import type { BlogArticleV2 } from "@/types/blog-v2";

export const BLOG_ARTICLES_V2: BlogArticleV2[] = [{ "slug": "10-pratiques-pour-developper-la-relation-de-confiance-dg-cio", "skip": false, "meta": { "title": "10 tips pour la relation DG/CIO", "h1": "10 tips pour la relation DG/CIO", "description": "10 pratiques pour développer la relation de confiance DG/CIO, du build au run, co-construites par la communauté des Pro de la Transfo.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b0e99207a150677e0173d4_TOP10%20relation%20DGCIO-min.jpg", "alt": "10 pratiques pour développer la relation de confiance DG/CIO" }, "author": { "name": "Pro. de la Transfo.", "category": "Gestion de projets", "publishedDate": "15/7/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b0e33b4f86cd68d63b49c4_pro.png" }, "publishedDate": "15/7/2023" }, "blocks": [{ "type": "paragraph", "text": "Avec la transformation numérique, les DSI sont les interlocuteurs privilégiés de la direction générale. Un moyen pour eux de se rapprocher des DG. Encore faut-il savoir cadrer et entretenir cette relation." }, { "type": "paragraph", "text": "Nous avons demandé aux &nbsp;\"<em>Pro de la Transfo</em>.\", une communauté de Décideurs et Doers de la transformation des entreprises; leurs astuces sur la façon de développer une relation de confiance avec les CEO." }, { "type": "paragraph", "text": "Objectif : co-créer des communs autour de la transfo. !" }, { "type": "paragraph", "text": "À partir de leurs retours d'expérience, nous avons co construit la liste de <strong>10 pratiques</strong> à considérer, de la plus simple à la plus avancée, <strong>du build au run</strong> !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64e4c2df9de7d724ff824a3e_pro.jpg", "alt": "22 juin 2023 - Workshop Pro de la Transfo", "caption": "12 pro. qui partagent durant une après-midi afin de créer des communs autour de la transfo. Travailler les relations avec les DG grâce au théâtre forum." }, { "type": "paragraph", "text": "Merci à" }, { "type": "list", "ordered": false, "items": ["Isabelle Leroux : Conseil en Transformation Organisation &amp; Digital", "Coralie Stevanazzi : Consultante Transformation", "Caroline Raveton : CIO &amp; consultante", "Elisabeth de Montety : PMO", "Sylvain Bourdette : CIO", "Clément Royer : CIO &amp; consultant", "Benito Diz : CIO", "Stéphane Creach : Consultant", "Simon Vacher : CPO", "Bertran Ruiz : CEO", "Thomas Poitau : CMO", "Jérôme Dard : Consultant"] }, { "type": "paragraph", "text": "Disclaimer&nbsp;: &nbsp;Ici pas de recettes \"magiques\". Juste des ingrédients, des postures et des tours de mains de Pro de la Transfo.&nbsp;Le management est un art !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64e4c4f2aa856ea74123335d_10%20TIPS%20CIO%20CEO-min.jpg", "alt": "10 pratiques pour développer la relation de confiance DG/CIO" }, { "type": "paragraph", "text": "-&gt;&nbsp;<a href=\"https://drive.google.com/file/d/1meC0KrcoqJ63ePRe2quXxgN_S-Aw-UEo/view?usp=drive_link\" target=\"_blank\">Lien vers version HD au format PDF imprimable</a>" }, { "type": "heading", "level": 2, "id": "transparence-en-continu-offrir-a-la-dg-la-capacite-de-co-piloter-la-transfo-de-son-organisation", "text": "Transparence en continu : offrir à la DG la capacité de co-piloter la transfo de son organisation" }, { "type": "paragraph", "text": "Avant même votre premier contact, quelles sont les astuces pragmatiques pour poser un futur cadre de coopération efficace ? Découvrez 5 pratiques sur ce \"cadrage\"." }, { "type": "heading", "level": 3, "id": "1-tout-se-joue-avant-daccepter-le-poste", "text": "1 : Tout se joue avant d'accepter le poste" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30c75a56b78aa3a31606e_1.jpg", "alt": "Tout se joue avant d'accepter le poste", "caption": "Un pacte CIO/DG" }, { "type": "paragraph", "text": "<strong>On s'accorde sur un pacte de gouvernance et fonctionnement précis.</strong> Plutôt qu'un échange sur des concepts flous et galvaudés \"on fera de l'agilité\" ^^... On pose un mode de fonctionnement, on formalise des engagements et redevabilités réciproques, &nbsp;et on s'assure que la direction est OK avec les changements culturels à venir. (Rituels, workflow des décisions clés, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">budgets</a>...) &nbsp;" }, { "type": "heading", "level": 3, "id": "2-prevoir-le-shadow-budget-une-reserve-tactique-pour-les-idees-parfois-geniales-de-son-dg", "text": "2 : Prévoir le \"shadow\" budget, une réserve tactique pour les idées (parfois ^^) géniales de son DG" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30ca1a584de1e8e187a76_2.jpg", "alt": "Prévoir le \"shadow\" budget", "caption": "Anticiper les nouvelles idées" }, { "type": "paragraph", "text": "<strong>Votre DG a une nouvelle idée !</strong> Souvent collectée le matin même dans les pages saumon du Figaro, Linkedin ou les Echos, ... CIO, ne rejetez pas tout en bloc. Prévoyez d'emblée chaque année une ligne budgétaire spéciale pour lancer quelques initiatives hors piste ! Visez les plus simples et les plus impactantes. En plus, vous n'êtes pas à l'abri d'un succès !" }, { "type": "heading", "level": 3, "id": "3-ne-jamais-presenter-seul-des-projets-transverses", "text": "3 : Ne jamais présenter seul des projets transverses !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30cce29770b358c42c250_3.jpg", "alt": "Pas de 1to1 sur les projets transverses", "caption": "Pas de 1to1 sur les projets transverses" }, { "type": "paragraph", "text": "<strong>Partager véritablement la responsabilité d'un projet ou d'un programme, c'est éviter les futures dissonances et désalignements.</strong> <br>Règle d'or : Pas de 1 on 1 sur les projets transverses. On partage les présentations en CODIR, on partage les points d'étape dédiés. Ex. vous pilotez la mise en prod de l'ERP finances, prévoyez de faire venir le CFO, 1/4 d'heure avant la fin de votre 1/1 avec la boss." }, { "type": "heading", "level": 3, "id": "4-faire-preuve-dempathie-comprendre-et-integrer-les-objectifs-de-la-dg", "text": "4 : Faire preuve d'empathie... comprendre et intégrer les objectifs de la DG" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30ceba56b78aa3a3199b9_4.jpg", "alt": "se mettre à la place de son DG", "caption": "Se mettre à la place de l'autre" }, { "type": "paragraph", "text": "<strong>La Direction Générale a aussi sa complexité aurait affirmé Lapalisse !</strong> Comprendre là ou on lui a demandé d'aller, ses enjeux tactiques et stratégiques communiqués ou non, sa feuille de route perso aussi, ce n'est pas de la flagornerie, c'est du bon sens de l'écoute et de l'efficacité. <br>Pour comprendre, il faut poser des questions : Quel niveau de pression du CA sur ce sujet ? Est-ce que tu as besoin d'un back-up sérieux sur ce sujet ? Exemple : \"On a une belle réussite sur ce pan du plan de transformation, veux-tu prendre la parole dans les médias\" ? Vous l'avez compris, se mettre à la place de l'autre est une posture clé. Après tout on est membre d'une équipe, et ensemble on va plus loin !" }, { "type": "heading", "level": 3, "id": "5-de-la-transparence-nait-la-confiance-partager-la-roadmap-dynamique-en-continu", "text": "5 : \"De la transparence naît la confiance\" Partager la roadmap dynamique en continu" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30e47650255351a621f73_5.jpg", "alt": "Transparence by design !", "caption": "Transparence by design !" }, { "type": "paragraph", "text": "<strong>Transparence by design !</strong> Offrir l'accès en continu aux avancées d'un plan, avec le bon niveau de granularité c'est la clé. Proposer le choix des armes : un lien permanent dans les favoris du navigateur, un PPT de synthèse à retrouver dans la boîte mail, une ligne Whatsapp d'urgence... <br>Reste à optimiser la mise à jour de votre <a href=\"https://www.airsaas.io/fr/gestion-de-projet/trois-innovations-et-tendances-qui-bousculent-la-gestion-de-portefeuille-de-projets\" target=\"_blank\">portefeuille de projets</a> avec vos chefs de projets et partenaires. Mais le jeu en vaut vraiment la chandelle. Foi d'éditeur de solution de gouvernance &nbsp;;)" }, { "type": "heading", "level": 2, "id": "optimiser-le-run-de-ses-rdv-avec-le-dg", "text": "Optimiser le \"run\" de ses RDV avec le DG" }, { "type": "paragraph", "text": "Le cadre est posé ? Désormais la <strong>phase d'exécution</strong> commence...on vous a préparé 5 autres pratiques pour muscler vos RDV !" }, { "type": "heading", "level": 3, "id": "6-preparer-un-1-on-1-comme-une-epreuve-sportive", "text": "6 : Préparer un 1 on 1 comme une épreuve sportive" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30d0a785a220d15e57949_6.jpg", "alt": "hygiène de champion avant chaque 1to1", "caption": "Hygiène de champion avant chaque 1to1" }, { "type": "paragraph", "text": "Içi pas de ring... Gardez les gants de boxe au vestiaire, mais <strong>adoptez une hygiène de champion avant chaque 1to1 !</strong> ça reste un basique validé. Voici <strong>notre check liste</strong> à afficher quelques part dans votre bureau :" }, { "type": "list", "ordered": false, "items": ["Bloquer 1h dans votre agenda avant chaque entretien", "S'assurer du timing prévu", "Assurer avec vos équipes la mise à jour de vos projets quelques jours en amont", "Lister les sujets et leurs attendus (1 seul objectif par sujet : informer, décider, alerter...)", "Prioriser l'ordre intelligemment et identifier les compromis possibles", "Rester toujours factuel et fonctionnel en préparant vos back-ups &nbsp;et antisèches", "Option Warrior : checker le RDV d'avant (un report tactique vaut mieux que de ne passer après un rendez-vous douloureux) &nbsp;"] }, { "type": "heading", "level": 3, "id": "7-gare-au-small-talk", "text": "7 : Gare au small talk !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30d32c0e1eef9d4e85d64_7.jpg", "alt": "small talk", "caption": "L'art de la petite conversation" }, { "type": "paragraph", "text": "<strong>Indispensable mais piégeux</strong>, le small talk, c'est à dire être capable d'engager la conversation, de tenir des discussions légères, de savoir parler de la pluie et du beau temps... peut prendre facilement 50% du temps ! Surtout avec un/e DG peu sachant/e sur vos sujets. Anticipez le sujet détendu du jour et venez avec les cafés, ça évitera le Rrrrrrrrhh Rrrrrrrhh du début de rendez-vous." }, { "type": "heading", "level": 3, "id": "8-si-ca-jargonne-tu-sonnes", "text": "8 : Si ça jargonne...tu sonnes !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30d70392df41d7b1702ab_8.jpg", "alt": "Parler français avec son DG !", "caption": "Si ça jargonne...tu sonnes !" }, { "type": "paragraph", "text": "<strong>La tech, ça jargonne sec</strong> ! Utile pour aller vite et créer un sentiment d'appartenance avec votre équipe...Cette \"habitude\" peut se retourner contre vous. Pédagogie, communication véritable, le 1to1 efficace n'accepte pas un mot de jargon au cours du RDV ! Vous parlez en user stories avec vos dev ? Faîtes de même avec les DG." }, { "type": "paragraph", "text": "Le top tip : offrir le <em>buzzer du jargon</em> avec la règle <strong>\"ça jargonne ? Tu sonnes !\"</strong> Pour les 3-4 premiers rendez-vous, ça devrait le faire. A tenter en CODIR aussi, d'autres confrères et consœurs aiment bien jargonner aussi." }, { "type": "heading", "level": 3, "id": "9-rendez-vous-catastrophe-apprendre-a-retourner-la-situation", "text": "9 : Rendez-vous catastrophe ? Apprendre à retourner la situation !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30dc811511103c2b1c071_9.jpg", "alt": "Renverser la situation à son avantage", "caption": "Retourner la situation" }, { "type": "paragraph", "text": "<strong>Quand c'est mal parti, c'est mal parti</strong>... voici des situations que les Pro. de la Transfo. ont vécu et leurs tactiques de contournement pour éviter le pourrissement de la situation :" }, { "type": "list", "ordered": false, "items": ["<strong>Un projet transverse monopolise la conversation : </strong>Reprogrammer un point avec les autres sponsors ou mieux, invitez au prochain COPROJ"] }, { "type": "list", "ordered": false, "items": ["<strong>Hors sujet manifeste : </strong> Accueillir le sujet, sans l'alimenter et utiliser le \"parking\", la mise au frigo, proposer une date précise (prochain 1to1, point ad hoc) pour apporter votre réponse. &nbsp;"] }, { "type": "list", "ordered": false, "items": ["<strong>Colère, mécontentement affirmé : </strong>Actez le point. Dépassionnez le sujet, et repartez sur des actions concrètes déjà mises en œuvre ou à valider pour retourner la situation."] }, { "type": "list", "ordered": false, "items": ["<strong>[option warrior] On vous dit comment faire : </strong>Valider le changement de rôle de votre interlocuteur, il devient chef de projet. On change de réunion, il faut réorganiser l'espace. Venez vous placer à ses côtés et prenez des notes, dessinez des schémas pour que la collaboration soit efficace. Vous avez un expert ^^, profitez-en !"] }, { "type": "heading", "level": 3, "id": "10-lafter-est-important-pour-conclure", "text": "10 : L'after est important pour conclure" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/64b30deea2de8e1ed6c4ae2e_10.jpg", "alt": "L'after du rdv", "caption": "Acter et capitaliser" }, { "type": "paragraph", "text": "L'important ce n'est pas la chute, c'est l'atterrissage ! .. <strong>Le 1on1 commence une fois qu'il est terminé ;)</strong> Envoyez vos quelques notes pour actions, marquant les décisions et idéalement, vous historisez dans un outil de pilotage (airsaas.io par exemple 🥰 ) Mais surtout, vous préparez déjà le prochain point :" }, { "type": "list", "ordered": false, "items": ["Fixer dans l'agenda les points importants à traiter", "Communiquer et répartir les \"to-do\" avec l'équipe", "Valider l'étape suivante et les points à traiter", "Noter quelque part les ressentis / réactions clés"] }, { "type": "insight-callout", "label": "À retenir", "html": "<ul><li>La discussion doit être constante et plaisante avec la direction générale ! Plus largement, le secret d'une transfo efficace réside à la fois dans la présence d'un outil simple dédié à la gouvernance (par exemple AirSaas !) ET dans la qualité de la relation CIO/DG/CODIR&nbsp;! Entre un COMEX/CODIR panier de crabes et/ou un COMEX/CODIR \"dream team\". Et à propos de Dream Team, merci aux membres de la communauté des Pro de la Transfo présents pour cette co création. # More to come !</li></ul>" }], "toc": [{ "label": "Transparence en continu : offrir à la DG la capacité de co-piloter la transfo de son organisation", "href": "#transparence-en-continu-offrir-a-la-dg-la-capacite-de-co-piloter-la-transfo-de-son-organisation", "level": 2 }, { "label": "Optimiser le \"run\" de ses RDV avec le DG", "href": "#optimiser-le-run-de-ses-rdv-avec-le-dg", "level": 2 }], "faq": [], "related": [] }, { "slug": "analyse-des-risques-projet", "skip": false, "meta": { "title": "Comment être pragmatique dans l'analyse des risques projet ?", "h1": "Comment être pragmatique dans l'analyse des risques projet ?", "description": "Après un bref rappel des modèles fondamentaux des risques dans la gestion de projet, nous regarderons pourquoi l'analyse de risques d'un projet est une usine à gaz et une perte de temps si elle est faite classiquement.", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "4/5/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea988524f164197ca07219_Project%20image%20(2)-min.jpg", "alt": "" }, "publishedDate": "4/5/2022" }, "blocks": [{ "type": "paragraph", "html": "Quelle est la dernière fois que vous avez vous dit à votre CODIR : \"<strong>Non on y va pas, c'est trop risqué !</strong>&nbsp;On est à N % de risques / On time / On cost / on quality&nbsp;<strong>!</strong>" }, { "type": "paragraph", "html": "Dans cet article nous allons&nbsp;<strong>nous intéresser à l'analyse des risques dans la&nbsp;</strong><a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a>&nbsp;<strong>et à ce qui n'est pas écrit dans le manuel du PMO</strong>&nbsp;projet... ! Après un bref rappel des modèles fondamentaux des risques dans la gestion de projet, nous regarderons&nbsp;<strong>pourquoi l'analyse de risques d'un projet est une usine à gaz</strong>&nbsp;et une perte de temps si elle est faite classiquement ? Nous proposerons&nbsp;<strong>de sortir de l'hypocrisie et de la subjectivité pour développer une pratique moderne, digitalisée et pragmatique !</strong>" }, { "type": "heading", "level": 2, "id": "pourquoi-est-ce-important-en-gestion-de-projet", "text": "Pourquoi est-ce important en gestion de projet ?" }, { "type": "heading", "level": 3, "id": "la-gestion-des-risques-na-peut-etre-jamais-ete-aussi-importante-quaujourdhui", "text": "La gestion des risques n'a peut-être jamais été aussi importante qu'aujourd'hui" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea95d57722a52f26e6f10d_usineagaz-analyse-risques-min.jpg", "alt": "Analyse de risques trop complexe", "caption": "Le principal risque de votre analyse des risques liés à votre projet...c'est sa complexité !" }, { "type": "paragraph", "html": "Un projet, c'est <strong>toujours un investissement</strong>&nbsp;; mieux vaut s'assurer qu'il sera possible de le mener efficacement. C'est dans cette étape qu'on va établir comment on envisage d'atteindre les objectifs du projet. On cherchera ici à savoir si le projet sera&nbsp;<strong>viable</strong>&nbsp;économiquement, s'il est effectivement&nbsp;<strong>réalisable</strong>&nbsp;(techniquement et dans les limites des coûts et délais possibles), et connaître les&nbsp;<strong>conséquences</strong>&nbsp;du projet sur son environnement." }, { "type": "paragraph", "html": "Quiconque a déjà eu à gérer un projet...ou un SI en période de pandémie, sait que l'analyse de risques est à la fois <strong>indispensable</strong> ET qu'elle <strong>ne suffit pas</strong>." }, { "type": "paragraph", "html": "L'expérience nous apprend en effet que&nbsp;<strong>rien ne se passe jamais comme prévu</strong>...et que si l'on n'y prend pas garde, il y a de grandes chances qu'on explose les délais, les <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">budgets</a>, et que la qualité attendue ne soit pas au rendez-vous." }, { "type": "paragraph", "html": "Ces difficultés, pour certaines, seront&nbsp;<strong>prévisibles,</strong>&nbsp;et vous pourrez les&nbsp;<strong>anticiper</strong>. Et c'est justement précisément le rôle de l'analyse de projet de vous éviter de vous retrouver dans ce genre de situation. Grâce à elle, vous aurez&nbsp;<strong>un arsenal&nbsp;à la fois proactif et réactif&nbsp;</strong>déjà prêt à l'emploi...et surtout en cas de crise inattendue,&nbsp;<strong>grâce à votre bonne gestion</strong>&nbsp;de projet vous pourrez&nbsp;<strong>consacrer votre énergie à ce qui n'était pas \"prévisible\"</strong>." }, { "type": "paragraph", "html": "La&nbsp;<strong>pandémie a rappelé à chacun que l'inattendu surgit toujours</strong>&nbsp;: \"Ce choc inattendu nous a rappelé que les prévisions sont régulièrement démenties. L'histoire est une succession d'évènements improbables qui s'enchaînent, s'affrontent et s'entremêlent pour donner naissance à un futur inimaginable quelques mois auparavant.\" (Yannick Roudaut auteur de Quand l'improbable surgit - Un autre futur revient dans la partie ! Ed. La Mer Salée Oct. 2020.)" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-risque-dans-un-projet", "text": "Qu'est ce qu'un risque dans un projet ?" }, { "type": "paragraph", "html": "Un risque, c'est un&nbsp;<strong>événement futur possible</strong>,&nbsp;<strong>identifiable</strong>&nbsp;et que nous pouvons&nbsp;<strong>quantifier en gestion de projet</strong>.&nbsp;" }, { "type": "paragraph", "html": "Le <strong>risque</strong> est <strong>inhérent</strong> à tout projet. Il peut provenir de la <strong>nature du projet</strong>, des <strong>budgets</strong> alloués, du degré de <strong>complexité</strong>, du besoin en <strong>ressource</strong>, etc." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea964251641d76be114ec4_risque-AirSaas.jpg", "alt": "Capture écran AirSaas - analyse de risques", "caption": "Penser autrement sa mise en mise en œuvre de la gestion des risques avec l'aide d'AirSaas" }, { "type": "paragraph", "html": "Une nuance très importante : <a href=\"https://norminfo.afnor.org/norme/fd-x50-117/management-de-projet-gestion-du-risque-management-des-risques-dun-projet/72873\" target=\"_blank\">la norme NFX50-117</a> (Management de projet – Gestion du risque – Management des risques projets)&nbsp;<strong>distingue imprévu, aléa, risque et problème.</strong>&nbsp;" }, { "type": "paragraph", "html": "L'un des <strong>risques de votre évaluation des risques</strong> potentiels de votre projet, c'est justement cette <strong>confusion</strong> et l'effet d'amalgame qui en découle." }, { "type": "heading", "level": 3, "id": "type-de-risques-projet-si-classiques-et-exemples-choisis", "text": "Type de risques projet SI \"classiques\" et exemples choisis :" }, { "type": "list", "ordered": false, "items": ["<strong>Fonctionnel</strong>&nbsp;: Le poids du spécifique dans le projet est trop important..."] }, { "type": "list", "ordered": false, "items": ["<strong>Technique</strong>&nbsp;: il y a un verrou technologique.. ne pas hésiter à faire un POC pour lever les risques identifiés."] }, { "type": "list", "ordered": false, "items": ["<strong>Organisationnel</strong>&nbsp;: Non tenue des engagements (planning, charges et coûts)"] }, { "type": "list", "ordered": false, "items": ["<strong>Roadmap</strong>&nbsp;: Petits projets et projets non prioritaires...révision de la RoadMap des projets entraînant un décalage ou un report du projet"] }, { "type": "list", "ordered": false, "items": ["<strong>Gestion de projet :</strong>&nbsp;Pas de positionnement de jalons clé par phase de planning.&nbsp;"] }, { "type": "list", "ordered": false, "items": ["<strong>Client interne</strong>&nbsp;: Faible implication de la MOA / des métiers dans la projet"] }, { "type": "list", "ordered": false, "items": ["<strong>Relation fournisseur &nbsp;:&nbsp;</strong>Communication difficile, faible réactivité de l'équipe prestataire, etc."] }, { "type": "list", "ordered": false, "items": ["<strong>SLA</strong>&nbsp;: Mauvaise appréciation du besoin de niveau de service comme la disponibilités ou les temps de réponse. =&gt; Vérifiez les affirmations des fournisseurs concernant les accords de niveau de service"] }, { "type": "list", "ordered": false, "items": ["<strong>Legal</strong>&nbsp;: changement de l'environnement juridique, etc... on touche ici parfois à des sujets très sensibles et bloquants..."] }, { "type": "list", "ordered": false, "items": ["<strong>Humain</strong>&nbsp;: les décisions ne sont pas prises&nbsp;ou bien on a besoin de gens hyper qualifiés...en pleine guerre des talents.. ou encore de personnes déjà (sur)occupées..."] }, { "type": "list", "ordered": false, "items": ["<strong>CyberRisque</strong>&nbsp;: En fonction de l'appétit pour le risque de votre organisation, votre programme de gestion des cyber-risques déterminera ensuite comment hiérarchiser et répondre à ces risques."] }, { "type": "list", "ordered": false, "items": ["<strong>Risques psychosociaux :</strong>&nbsp;les RPS recouvrent le stress, le harcèlement, la violence au travail et les incivilités. Un risque à transférer au RH."] }, { "type": "list", "ordered": false, "items": ["<strong>Financiers</strong>&nbsp;: le ticket minimum est trop élevé par exemple."] }, { "type": "list", "ordered": false, "items": ["<strong>Communication et management</strong>&nbsp;: trop d'absence des parties prenantes&nbsp;..."] }, { "type": "paragraph", "html": "etc.... Liste non exhaustive !" }, { "type": "paragraph", "html": "Pour chaque type de risques&nbsp;<strong>on identifiera donc : son type / les mot clés / une description / l'impact potentiel /et les actions conseillées</strong>&nbsp;dans un registre... (cf plus bas)." }, { "type": "heading", "level": 2, "id": "les-4-etapes-de-lanalyse-de-risques-projet", "text": "Les 4 étapes de l'analyse de risques projet" }, { "type": "paragraph", "html": "Le processus de gestion des risques se décompose en 4 étapes." }, { "type": "paragraph", "html": "Pour le PMBOK® : <strong>le management des risques</strong> est défini comme «&nbsp;<strong>le processus systématique </strong>d'identification, d'analyse et de réponse aux risques du projet&nbsp;»." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/627139655c1cad43e42f90f6_Analyse%20de%20risques.png", "alt": "Procress analyse de risques", "caption": "Simple, basique !" }, { "type": "list", "ordered": false, "items": ["Étape 1 : identifier les risques d'un projet", "Étape 2 : évaluer la probabilité et les conséquences des risques", "Étape 3 : proposer des actions pour chaque risque", "Étape 4 : Surveiller et rendre compte du suivi du risque"] }, { "type": "heading", "level": 3, "id": "etape-1-identifier-et-prioriser-les-risques-projet-dans-une-matrice-lisible", "text": "Étape 1 : Identifier (et prioriser) les risques projet dans une matrice ...lisible !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea96b2dc707584002170f3_Capture%20d%E2%80%99e%CC%81cran%202022-04-18%20a%CC%80%2014.54.28-min.png", "alt": "Matrice analyse de risques", "caption": "Exemple de registre de risques d'un plan d'assurance qualité DSI format excel...que plus personne n'a envie de lire..." }, { "type": "paragraph", "html": "L'identification des risques et leur traitchef ement doit se faire&nbsp;<strong>à la fois le plus tôt possible dans le projet ET tout au long du cycle de vie du projet</strong>, avec un accent particulier lors des jalons." }, { "type": "paragraph", "html": "Si certains risques sont trop grands —&gt; Faire un projet pour dé-risquer et ensuite valider ou non le projet.&nbsp; (cf. partie 3 ci-dessous)." }, { "type": "paragraph", "html": "<strong>Nota bene </strong>: Lorsqu'une démarche qualité est en place dans l'entreprise... ce processus sera utilement mené conjointement avec le responsable qualité lors des revues des directions entre autres." }, { "type": "paragraph", "html": "Ici après avoir (un peu) rempli le fichier Excel pour faire vos gammes... <strong>sortez du cadre !</strong>" }, { "type": "paragraph", "html": "Soyez créatifs,&nbsp;<strong>rendez tout d'abord votre analyse des risques lisible et surtout collaborative.</strong> Utilisez par exemple les \"j<strong>eux qui font le boulot</strong>\" inspiré de la culture Agile." }, { "type": "paragraph", "html": "Connaissez-vous <a href=\"https://www.reussirsesprojets.com/pre-mortem/\" target=\"_blank\">le \"Pre-Mortem\"</a> ? Ce jeu a été popularisé par Dave Gray, James Macanufo, Sunni Brown, les trois auteurs du best-seller Gamestorming - jouer pour innover (ed. diateino en 2014.)" }, { "type": "paragraph", "html": "Il s'agit d'<strong>anticiper toutes les raisons qui feraient que le projet, le produit, le service, l'entreprise… pourrait échouer,&nbsp;</strong>pour justement qu'elles n'arrivent pas." }, { "type": "paragraph", "html": "\"Si vous souhaitez donner un coup de balai à la grisaille qui règne dans vos bureaux, si tourner en rond ne vous fait pas rêver et que&nbsp;<strong>vous souhaitez que votre équipe progresse durablement</strong>, ce guide ludique est fait pour vous&nbsp;!\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea970812a1dbb18d5b6b6b_premortem-min.jpg", "alt": "Jeu agile pre mortem vs analyse de risques", "caption": "Premortem - Extrait du livre GameStorming - Ed Diateino" }, { "type": "paragraph", "html": "Un point important de cette approche&nbsp;collaborative&nbsp;: ne négligez jamais les avis minoritaires&nbsp;! La majorité n'a pas forcément raison quant il s'agit d'analyser les risques.&nbsp;" }, { "type": "heading", "level": 3, "id": "etape-2-evaluer-la-probabilite-et-les-consequences-des-risques", "text": "Étape 2 : Évaluer la probabilité et les conséquences des risques" }, { "type": "paragraph", "html": "Ce qu'on vous dit à l'école, en cours de gestion des risques : faites un&nbsp;<strong>profil quantitatif pour le risque projet</strong>&nbsp;notamment basé sur une moyenne de la probabilité, gravité et criticité !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea976f24f164c79ba0685b_Capture%20d%E2%80%99e%CC%81cran%202022-04-18%20a%CC%80%2023.56.37-min.png", "alt": "Matrice analyse de risques criticité impact probabilité", "caption": "Bienvenue en pleine subjectivité ! Chaque risque est noté...pondéré..." }, { "type": "paragraph", "html": "<strong>Ce qu'on apprend sur le terrain</strong> : avec ces évaluations c'est que ces<strong> matrices sont difficilement \"maintenables\"</strong>...et que l'appréciation quantitative nous fait<strong>&nbsp;entrer en pleine subjectivité !</strong>" }, { "type": "paragraph", "html": "Au-delà de toutes les bonnes pratiques et belles matrices quantitatives donc .... Faites <strong>confiance à la simplicité, aux process, à l'expérience et à votre intuition !</strong>" }, { "type": "paragraph", "html": "Le&nbsp;<strong>plan de reprise d'activité</strong>&nbsp;(PRA) et ou&nbsp;<strong>plan de continuité d'activité</strong>&nbsp;(PCA) ne vous vaccinera pas contre tout...mais ils constituent un \"<strong>Airbag risque</strong>\" intéressant." }, { "type": "paragraph", "html": "En termes d'expérience... au-delà de la vôtre, de celle de votre équipe on pourra s'appuyer sur la <strong>sagesse populaire</strong>...par exemple sur ce que les lois du temps nous ont appris...petite mise à jour :" }, { "type": "list", "ordered": false, "items": ["<strong>La loi de Murphy&nbsp;</strong>: \"rien ne se passe comme prévu\" - \"<strong>Anything that can go wrong, will go wrong</strong>\".", "Ou bien la&nbsp;<strong>loi de Hofstadter</strong>&nbsp;qui énonce que, \"<strong>quelle que soit la durée prévue pour un projet, il ne sera pas rendu dans le délai imparti.</strong>\""] }, { "type": "paragraph", "html": "Leçon à en tirer&nbsp;:&nbsp;<strong>le </strong><a href=\"https://www.airsaas.io/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\"><strong>chef de projet</strong></a><strong> et son équipe doivent estimer plus largement le temps nécessaire à la réalisation de leur projet</strong>. Partez du principe qu'il prendra inévitablement du retard. Un DSI avait coutume de nous asséner : <strong>\"Mettez des matelas dans les plannings\" </strong>!" }, { "type": "heading", "level": 3, "id": "etape-3-proposer-des-actions-pour-chaque-risque", "text": "Étape 3 : Proposer des actions pour chaque risque" }, { "type": "list", "ordered": false, "items": ["<strong>Accepter&nbsp;</strong>: tout est normal...on continue à superviser.", "<strong>Réduire</strong>&nbsp;: diminuer la probabilité d'occurrence et/ou la sévérité des impacts.", "<strong>Transférer</strong>: transférer la responsabilité d'un risque à une tierce partie qui supporterait les conséquences du problème", "<strong>Eviter&nbsp;</strong>: élimination totale de l'incertitude."] }, { "type": "paragraph", "html": "Au-delà des basiques et de l'anticipation ...l'action la plus importante de votre gestion de projet sera bien d'être capable de&nbsp;<strong>décider</strong>. Y compris&nbsp;<strong>de décider de ne pas lancer le projet</strong>. Sur ce point, rappelez-vous la formule inventée par Olivier Bas, vice président du groupe Havas :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6271380aa1458215745cb356_demidecision.jpeg", "alt": "1/2 décision = bordel au carré", "caption": "Source  conférence Olivier Bas - Titre d'un chapitre du livre \"Like ton job\" paru chez Dunod." }, { "type": "paragraph", "html": "Pour parvenir à cette<strong>&nbsp;gestion des risques prudente&nbsp;</strong>, il vous faudra avoir démontré que vous avez \"dé-risquer\" votre projet. Concrètement cela peut vouloir dire d'avoir lancé un projet spécifique sorte de prototype sans risque.‍" }, { "type": "heading", "level": 3, "id": "etape-4-surveiller-et-rendre-compte-du-suivi-du-risque", "text": "Étape 4 : Surveiller et rendre compte du suivi du risque" }, { "type": "paragraph", "html": "Une <strong>organisation</strong> doit se mettre en place <strong>pour communiquer sur la maîtrise des risques</strong>. C'est pourtant sur cette quatrième étape que la mise en œuvre semble aujourd'hui la plus hétérogène...!" }, { "type": "paragraph", "html": "De façon générale,<strong>&nbsp;le manque de transparence écrite peut conduire à de lourds échecs</strong>.&nbsp;" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea97c4f01323fc67c113f9_all-projects.jpg", "alt": "Capture écran Airsaas", "caption": "Penser autrement sa gestion des risques projet - capture d'écran menu AirSaas rapport flash" }, { "type": "paragraph", "html": "Bien utilisé, un <strong>outil de </strong><a href=\"https://www.airsaas.io/gestion-de-projet/le-pilotage-de-projet-en-2023\" target=\"_blank\"><strong>pilotage de projet</strong></a> permet <strong>d'aligner</strong> sur la valeur, la <strong>DSI</strong> et les équipes <strong>métiers</strong>, et <strong>top manager,</strong> en<strong> cassant les silos d'une organisation</strong> parfois trop lourde ou compartimentée au sein de chaque entreprise." }, { "type": "heading", "level": 2, "id": "comment-on-fait-evoluer-la-gestion-operationnelle-du-risque-en-cours-de-projet", "text": "Comment on fait évoluer la gestion opérationnelle du risque en cours de projet ?" }, { "type": "paragraph", "html": "Vous pouvez aussi être soudainement confrontés à de<strong>&nbsp;nouveaux risques ou voir des risques autrefois critiques perdre en intensité</strong>. Bref : surveillez régulièrement votre cartographie des risques. Ce <strong>processus</strong> de gestion des risques est <strong>itératif</strong>. Seulement... revenir sur la cartographie initiale pour une mise à jour est une charge importante. Comment s'y prendre pour ne pas y dépenser toute votre bande passante disponible ?" }, { "type": "heading", "level": 3, "id": "facon-de-faire", "text": "Façon de faire :" }, { "type": "list", "ordered": false, "items": ["Faire <strong>remonter les points d'attentions</strong> en <strong>continu</strong>", "Idem pour les <strong>décisions</strong>&nbsp;", "Mettre à jour les<strong> statuts de météo </strong>et leurs<strong> contextes opérationnels</strong>"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea983b0383f81f8e3fe463_execution.jpg", "alt": "Capture écran AirSaas flash report", "caption": "Exemple de rapport flash AirSaas consolidant les points d'attentions, décisions, statut météo ..." }, { "type": "heading", "level": 3, "id": "humain-les-indicateurs-qui-font-que-le-risque-devient-un-probleme", "text": "Humain : les indicateurs qui font que le risque devient un problème ..." }, { "type": "list", "ordered": false, "items": ["Si les<strong> décisions ne sont pas prises</strong>&nbsp;", "Si trop d'<strong>absence </strong>des <strong>parties prenantes</strong>&nbsp;", "<strong>Défiance</strong> dans la <strong>tenue du jalon</strong>&nbsp;", "Liste non limitative :)"] }, { "type": "heading", "level": 3, "id": "saas-des-risques-nouveaux-peu-familiers-et-souvent-mal-compris", "text": "SaaS... des risques nouveaux, peu familiers et souvent mal compris" }, { "type": "list", "ordered": false, "items": ["<strong>Faites confiance</strong> au fournisseur sur leur capacité de résilience et <strong>vérifiez !</strong>", "<strong>Testez vos plans de résilience</strong> pour vous assurer qu'ils fonctionnent et que chacun sait comment s'exécuter en cas de crise."] }, { "type": "heading", "level": 2, "id": "en-bref", "text": "En bref :" }, { "type": "list", "ordered": false, "items": ["C'est généralement le<strong>&nbsp;manque de transparence écrite</strong>&nbsp;en entreprise qui&nbsp;<strong>amène à des échecs projets </strong>&nbsp;;", "<strong>Tenir compte des risques&nbsp;</strong>et des contraintes du projet<strong>&nbsp;permettra de prendre des décisions radicales</strong>&nbsp;: on lance le projet ou non, on met éventuellement en œuvre des actions qui vont le rendre faisable pour une équipe.", "L'analyse des risques se <strong>fait en début de projet</strong>, à l'étape de l'étude de faisabilité, et lors des <strong>grands</strong>&nbsp;<strong>jalons</strong>&nbsp;du cycle projet. <br>‍"] }, { "type": "paragraph", "html": "Pour approfondir ce dernier axe clé, nous vous recommandons la lecture de l'article :<a href=\"/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\"> Le jalon projet : une technique pour séquencer vos projets intelligemment.</a>" }], "toc": [{ "label": "Pourquoi est-ce important en gestion de projet ?", "href": "#pourquoi-est-ce-important-en-gestion-de-projet", "level": 2 }, { "label": "Qu'est ce qu'un risque dans un projet ?", "href": "#quest-ce-quun-risque-dans-un-projet", "level": 2 }, { "label": "Les 4 étapes de l'analyse de risques projet", "href": "#les-4-etapes-de-lanalyse-de-risques-projet", "level": 2 }, { "label": "Comment on fait évoluer la gestion opérationnelle du risque en cours de projet ?", "href": "#comment-on-fait-evoluer-la-gestion-operationnelle-du-risque-en-cours-de-projet", "level": 2 }, { "label": "En bref :", "href": "#en-bref", "level": 2 }], "faq": [], "related": [] }, { "slug": "appel-doffres-et-evaluation-dune-solution-ppm-project-portfolio-management", "skip": true, "meta": { "title": "Appel d'offres et évaluation d'une solution PPM (Project Portfolio Management)", "h1": "Appel d'offres et évaluation d'une solution PPM (Project Portfolio Management)", "description": "Appel d'offres et évaluation d'une solution PPM (Project Portfolio Management)", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/667035cc119301d2f3a9ef4b_PPM-min%20(1).jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "17/6/2024", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "17/6/2024" }, "blocks": [], "toc": [{ "href": "#lessentiel-en-quelques-mots", "label": "L'essentiel en quelques mots…", "level": 2 }, { "href": "#sept-idees-recues-a-combattre-pour-reussir-vos-appels-doffre", "label": "Sept idées reçues💡 à combattre pour réussir vos appels d'offre", "level": 2 }, { "href": "#conclusions", "label": "Conclusions", "level": 2 }], "faq": [], "related": [], "reason": "extract emits 21k blocks (likely nested array spam) — needs manual cleanup" }, { "slug": "budget-previsionnel-projet", "skip": false, "meta": { "title": "Tout savoir sur le budget prévisionnel projet", "h1": "Tout savoir sur le budget prévisionnel projet", "description": "Découvrez les bonnes pratiques pour préparer le budget prévisionnel de votre projet : anticiper les dépenses, impliquer vos équipes et garder le cap.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37e7d9f36f78330171279_4.jpg", "alt": "" }, "author": { "name": "Simon Vacher", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e038501c4256317123910b_SV-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Pour vous différencier de vos concurrents, la gestion des ressources est primordiale dans la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> : en optimisant leur utilisation, vous ferez mieux avec les mêmes moyens !" }, { "type": "paragraph", "text": "Et le budget prévisionnel est un atout important de la gestion des ressources : il permet d'avoir une visibilité détaillée sur l'ensemble des recettes et des dépenses de votre projet. Grâce à lui, vous pouvez anticiper les obstacles que vous pourriez rencontrer et fixer un cap pour votre projet ! Bien sur le budget est partie intégrante de la fiche projet." }, { "type": "paragraph", "text": "Découvrez ici <strong>les bonnes pratiques pour préparer le budget prévisionnel de votre projet à venir</strong> - pas besoin d'être expert-comptable ou banquier pour le faire !" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-budget-previsionnel", "text": "Qu'est-ce qu'un budget prévisionnel ?" }, { "type": "paragraph", "text": "Faire un budget prévisionnel est indispensable lorsque l'on veut créer un projet : s'il peut servir à convaincre des supérieurs ou des investisseurs de l'intérêt de financer votre projet, il permettra dans tous les cas à toutes les parties impliquées dans le projet d'avoir une visibilité sur l'ensemble de sa réalisation." }, { "type": "paragraph", "text": "Le budget prévisionnel d'un projet, s'il est réaliste, décrit le plus précisément possible les dépenses ainsi que les recettes qui seront affiliées à votre projet. Une des astuces consiste à se baser sur des projets similaires menés par d'autres entreprises en faisant une étude de marché, afin que vos prévisions budgétaires collent au maximum aux dépenses et recettes futures." }, { "type": "paragraph", "text": "Bien entendu, si ce n'est pas la première année que vous menez ce type de projet, vous pouvez vous baser sur vos chiffres des années précédentes pour élaborer votre budget." }, { "type": "paragraph", "text": "Votre prévisionnel peut se faire sur un tableur Excel, ou bien sur un outil comptable dédié, qui permet de recenser vos prévisions sur une plateforme collaborative." }, { "type": "heading", "level": 2, "id": "pourquoi-etablir-un-budget-previsionnel-pour-un-projet", "text": "Pourquoi établir un budget prévisionnel pour un projet ?" }, { "type": "heading", "level": 3, "id": "anticiper-et-ajuster-votre-projet", "text": "Anticiper et ajuster votre projet" }, { "type": "paragraph", "text": "L'intérêt premier d'un <a href=\"https://www.legalstart.fr/fiches-pratiques/comptabilite-entreprise/comment-faire-budget-previsionnel/\" target=\"_blank\">budget prévisionnel</a> est d'essayer d'accroître votre visibilité sur le futur de votre projet - ou autrement dit, d'anticiper votre gestion de projet !" }, { "type": "paragraph", "text": "En effet, construire le prévisionnel financier de votre projet est l'une des meilleures solutions pour estimer sa faisabilité. Vous allez pouvoir calculer la marge de rentabilité que vous espérez atteindre (ou au moins l'équilibre budgétaire) et réaliser des ajustements sur votre stratégie si vous vous rendez compte que votre business plan ou votre plan de financement ne tiennent pas la route." }, { "type": "paragraph", "text": "Autre astuce : vous pouvez même réaliser plusieurs budgets prévisionnels qui représentent les différents scénarios que vous envisagez, et qui prennent en compte les imprévus que vous pouvez imaginer (problème d'approvisionnement, nouveaux concurrents qui changent le marché…)" }, { "type": "heading", "level": 3, "id": "garder-le-cap-durant-le-projet", "text": "Garder le cap durant le projet" }, { "type": "paragraph", "text": "Votre budget prévisionnel sera un outil redoutable d'aide à la décision au fur et à mesure de la réalisation du projet. En effet, votre budget vous permet de vérifier mois par mois que vous ne vous éloignez pas trop de votre stratégie initiale et que les décisions que vous avez prises ont bien eu l'impact que vous aviez prévu." }, { "type": "paragraph", "text": "Le budget prévisionnel est donc un outil de suivi de projet très efficace pour vérifier que vous collez bien à ce que vous aviez planifié : c'est un guide qui indique le cap que vous aviez prévu de prendre !" }, { "type": "heading", "level": 3, "id": "un-allie-de-poids-pour-votre-management", "text": "Un allié de poids pour votre management" }, { "type": "paragraph", "text": "Le budget prévisionnel de projet peut aussi être un levier intéressant pour manager vos équipes en tant que porteur de projet. Il peut, d'une part, servir à montrer à vos équipes que vos moyens ne sont pas illimités, ou qu'elles ont dépensé plus qu'il était prévu à l'origine, afin de les convaincre de faire attention." }, { "type": "paragraph", "text": "À l'inverse, élaborer un budget prévisionnel ambitieux aura un effet engageant important sur vos équipes. Elles se sentiront galvanisées de prendre part à un projet avec autant de moyens, ce qui accroîtra leur motivation." }, { "type": "paragraph", "text": "Le budget prévisionnel est donc un argument de poids pour appuyer vos décisions auprès de vos équipes." }, { "type": "heading", "level": 2, "id": "comment-preparer-un-budget-previsionnel", "text": "Comment préparer un budget prévisionnel ?" }, { "type": "heading", "level": 3, "id": "avoir-fait-linventaire-de-vos-ressources", "text": "Avoir fait l'inventaire de vos ressources" }, { "type": "paragraph", "text": "Un prérequis indispensable : pour réaliser un budget prévisionnel, vous devez lister l'ensemble des ressources à votre disposition. On parle ici des ressources matérielles, humaines, mais aussi du temps (nombre de jours) dont vous disposez pour mener à bien ce projet." }, { "type": "heading", "level": 3, "id": "decouper-vos-budgets-previsionnels", "text": "Découper vos budgets prévisionnels" }, { "type": "paragraph", "text": "Pour des projets de longue durée, il est préférable de calculer votre budget en le découpant de manière mensuelle. Plusieurs raisons à cela." }, { "type": "paragraph", "text": "Tout d'abord, il sera souvent plus simple de prévoir vos dépenses mensuelles plutôt qu'annuelles : les marges d'erreurs seront réduites !" }, { "type": "paragraph", "text": "Ensuite, une budgétisation mensuelle apportera une meilleure capacité d'anticipation : si vous vous forcez à budgétiser chaque mois, vous devrez alors être plus précis sur le temps que vous prévoyez pour faire chaque tâche." }, { "type": "paragraph", "text": "De plus, la mensualisation ne vous enlève rien. Nous ne vous apprenons rien si nous vous rappelons que pour établir votre budget annuel, vous n'aurez qu'à additionner le budget de chacun de vos 12 mois." }, { "type": "heading", "level": 3, "id": "impliquer-vos-collaborateurs-dans-la-confection-de-votre-budget", "text": "Impliquer vos collaborateurs dans la confection de votre budget" }, { "type": "paragraph", "text": "Si vous voulez prévoir efficacement vos dépenses et vos recettes, il est primordial d'impliquer les premiers concernés par ces dernières : vos collaborateurs. Il sera bien plus simple de réussir à anticiper les bons montants en les calculant avec ceux qui oeuvreront au quotidien sur le projet." }, { "type": "paragraph", "text": "Chacun de vos collaborateurs sera à même de vous donner une idée précise de l'importance des recettes et dépenses liées aux tâches dont il est responsable." }, { "type": "paragraph", "text": "Vous risquez d'obtenir un budget prévisionnel bien plus proche de la réalité en interrogeant vos collaborateurs sur leurs domaines de prédilection, qu'en confiant la réalisation de l'entièreté du budget à un consultant." }, { "type": "paragraph", "text": "De plus, vous obtiendrez un engagement d'autant plus important de la part de vos équipes si vous les avez impliquées dès la conception du budget du projet." }, { "type": "heading", "level": 3, "id": "prendre-garde-a-bien-evaluer-vos-depenses", "text": "Prendre garde à bien évaluer vos dépenses" }, { "type": "paragraph", "text": "Il est inutile de gonfler vos dépenses. Ne les surévaluez pas, ce n'est pas une bonne idée. Vous pouvez garder une très légère marge de sécurité si vous craignez de dépasser les montants que vous avez prévus, ou que les sommes sont vraiment dures à prévoir." }, { "type": "paragraph", "text": "Par contre, il est vivement conseillé de mettre de côté une réserve pour l'année sur votre plan de trésorerie afin de pouvoir faire face aux imprévus." }, { "type": "paragraph", "text": "De la même manière, évitez de sous-évaluer vos dépenses. Chiffrer un budget trop restreint pour les tâches que vous avez à accomplir obligera à une hiérarchisation entre les différentes tâches que vous aviez prévues, ce qui sera forcément source de tension dans vos équipes." }, { "type": "heading", "level": 3, "id": "eviter-autant-que-possible-de-sous-estimer-les-delais", "text": "Éviter autant que possible de sous-estimer les délais" }, { "type": "paragraph", "text": "Sous-estimer vos délais reviendra à faire travailler pendant plus longtemps que prévu vos équipes - et donc à exploser le budget prévisionnel du projet.<br><br>De nombreuses études ont montré qu'il était commun d'être trop optimiste lorsqu'on estime la durée de réalisation d'une tâche. Ainsi, interrogez vos collaborateurs sur le délai dont ils estiment avoir besoin pour accomplir leurs missions, et ajoutez une marge de sécurité par précaution (souvent entre 20 et 30% selon les collaborateurs)." }, { "type": "heading", "level": 3, "id": "un-budget-previsionnel-nest-pas-statique-faites-le-evoluer", "text": "Un budget prévisionnel n'est pas statique : faites-le évoluer !" }, { "type": "paragraph", "text": "Si, pour le confectionner en amont, vous êtes bien obligé d'essayer de prévoir le réel, il arrivera un moment où vos hypothèses se vérifieront ou s'infirmeront. Lorsque durant votre projet, vous obtenez davantage d'informations sur les dépenses et les recettes auxquelles vous allez faire face, servez-vous en pour retravailler votre budget prévisionnel !" }, { "type": "paragraph", "text": "Ainsi, il est conseillé de faire un bilan chaque mois sur vos dépenses et recettes effectives, et de les comparer à vos prévisions financières. Important : lorsque vous corrigez votre budget prévisionnel en cours d'année, n'oubliez pas de garder la version antérieure - cela évitera de perdre le cap, mais sera aussi très intéressant à revoir lorsque vous aurez bien avancé sur le projet." }, { "type": "paragraph", "text": "Pour aller plus loin, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">découvrez comment construire un budget de projet sans vous louper</a>." }, { "type": "paragraph", "text": "L'élaboration du budget prévisionnel de votre projet est terminée ? Vous pouvez désormais l'intégrer à votre <a href=\"https://www.airsaas.io/fr/gestion-de-projet/fiche-projet-exemple-et-methodologie\" target=\"_blank\">fiche projet</a>." }], "toc": [{ "label": "Qu'est-ce qu'un budget prévisionnel ?", "href": "#quest-ce-quun-budget-previsionnel", "level": 2 }, { "label": "Pourquoi établir un budget prévisionnel pour un projet ?", "href": "#pourquoi-etablir-un-budget-previsionnel-pour-un-projet", "level": 2 }, { "label": "Comment préparer un budget prévisionnel ?", "href": "#comment-preparer-un-budget-previsionnel", "level": 2 }], "faq": [], "related": [] }, { "slug": "budgetiser-un-projet-sans-se-louper", "skip": false, "meta": { "title": "Comment budgétiser un projet sans se louper", "h1": "Comment budgétiser un projet sans se louper", "description": "Découvrez comment budgétiser un projet sans se tromper : estimation par analogie, découpage en tranches, retour d'expérience du CIO d'Adeo et les 6 erreurs à éviter.", "publishedDate": "28/5/2022", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea9312dbd70fd37ca94f39_Project%20image%20(6)-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "28/5/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" } }, "blocks": [{ "type": "paragraph", "html": "Un DSI nous confiait récemment : \"<strong>le projet n'aurait jamais été accepté si l'on n'avait pas menti sur le budget !</strong>\" Que l'on soit d'accord ou pas, il est intéressant d'explorer les \"non-dits\" autour de l'argent dans la gestion de projet !" }, { "type": "paragraph", "html": "Reconnaissons le tout d'abord, l'équipe \"<strong>Chef de projet/PMO /DSI\" est confrontée à une injonction paradoxale</strong>.<strong> L'impossible défi </strong>de <strong>conjuguer</strong>, d'un côté la pression du marché et des métiers vers toujours <strong>plus d'innovation</strong>, de rapidité et <strong>d'agilité</strong>. Et de l'autre, des<strong> demandes d'estimations budgétaires </strong>précises d'une direction générale qui a besoin de valider les équations financières de l'entreprise !" }, { "type": "paragraph", "html": "Bien sûr, pour corser les choses, tout cela se réalise <strong>dans un contexte de guerre des talents IT et d'environnement de plus en plus VUCA</strong> (\"<em>Volatile, Uncertain, Complex, Ambiguous</em>\")." }, { "type": "paragraph", "html": "Alors comment sortir \"par le haut\" d'une situation ou <strong>53% des projets dépassent de 189% leurs prévisions budgétaires !</strong> ? (Source : Chaos report)." }, { "type": "paragraph", "html": "Dans cet article nous proposons de sortir (un peu) de la subjectivité générale en matière de budget dans la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a>, en mettant en avant <strong>des pratiques simples et pragmatiques !</strong> Découvrez le retour d'expérience du CIO d'Adéo et aussi un bref rappel des basiques pour vous permettre de budgéter votre prochain projet sans (trop) vous tromper." }, { "type": "heading", "level": 2, "id": "relever-le-defi-du-budget-avec-une-estimation-par-analogie", "text": "Relever le défi du budget avec une estimation \"par analogie\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea92284b368508405c566c_budget%20(2).jpg", "alt": "Construire un budget par analogie", "caption": "Copier intelligemment un budget projet quasi similaire pour sortir de l'approximation" }, { "type": "paragraph", "html": "Quand un chef de projet n'a jamais fait un type de projet, c'est compliqué d'établir une estimation ! Une des astuces consiste à se baser sur des données de projets quasi similaires afin que <strong>votre estimation colle au maximum aux dépenses et recettes futures</strong>." }, { "type": "paragraph", "html": "<strong>Demander à quelqu'un qui a déjà fait ce type de projet reste la façon la plus pragmatique de faire</strong>. Aller chercher l'expérience là où elle est… Site web, réseaux professionnels traditionnels et ou numériques. Pensez aux réseaux spécialisés comme les groupes Linkedin tels que celui d'Alliancy - DSI &amp; Transformation des organisations et/ou (autopromo), le club \"Pro de la Transfo\" d'AirSaas. Si vous avez plus de temps et d'argent à y consacrer, l'opportunité d'adhérer à un des réseaux traditionnels existant, vous permettra d'interagir au sein des cercles tels que l'ANDSI, le CIGREF, ou bien encore le Club Decision DSI, l'agora des DSI et CIO, le cercle des DSI d'ADN Ouest. L'offre est vaste." }, { "type": "paragraph", "html": "Si vous ne trouvez toujours pas votre réponse après quelques tentatives dans la sphère francophone...essayez donc les réseaux d'entraides entre DSI/PMO et CDIO anglophones. Par exemple <strong>le groupe Linkedin CIO Forum</strong>, ou bien la communauté en ligne d'IDG (TECH) talk propulsé par la revue CIO." }, { "type": "paragraph", "html": "L'objectif est de <strong>ne pas réinventer l'eau chaude</strong>, de <strong>rester concentré sur l'innovation !</strong> Sur ce point comme beaucoup d'autres la culture de l'informatique libre et de l'open source a ouvert la voie. Pas de complexes à avoir !" }, { "type": "quote", "text": "\"Good artists copy; great artists steal\"", "author": "Picasso (cité par Steve Jobs)" }, { "type": "heading", "level": 2, "id": "decoupez-le-budget-de-projet-en-tranches-credibles", "text": "Découpez le budget de projet en tranches crédibles !" }, { "type": "paragraph", "html": "Vous en êtes conscients, les plus <strong>grandes estimations budgétaires</strong> sont <strong>la plupart du temps les plus belles</strong> \"fakexcel\" news !" }, { "type": "paragraph", "html": "Paradoxalement, l'expérience nous apprend que <strong>plus le projet est gros et long moins ça sert à quelque chose de le budgétiser. </strong>Plus le taux d'erreur sera important en effet." }, { "type": "paragraph", "html": "Il est plus prudent d'estimer le budget par phase <strong>ou sur la base d'un projet qui a déjà été fait, refait et refait plusieurs fois (industrialisé).</strong>" }, { "type": "paragraph", "html": "Et oui, construire une estimation \"qui descend jusqu'au boulon de 12\" prend du temps !" }, { "type": "paragraph", "html": "<strong>Si c'est un projet trop gros</strong> : en termes de temps de nombre de personnes ou avec de forts risques techniques alors, il faut se l'avouer, <strong>il est quasi impossible de bien budgétiser un projet dans son ensemble</strong>. Il faudra découper le projet et budgéter phase après phase." }, { "type": "paragraph", "html": "‍<strong>Sinon, c'est un budget macro et ça peut être tout à fait suffisant !</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3eb2a796639885b0d2fba_graphic.png", "alt": "Ligne de performance vs temps", "caption": "Une ligne de performance inversement proportionnelle au temps passé sur le projet !" }, { "type": "heading", "level": 3, "id": "limites-des-estimations", "text": "Limites des \"estimations\"" }, { "type": "paragraph", "html": "\"Il faut cesser de faire <strong>des estimations projet !…Elles sont toutes foireuses\"</strong> d'après le spécialiste français et <strong>coach agile Frédéric</strong>." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea92cddc70758e1f21201d_fix-dessinateur-airsaas-budget-min-min.jpg", "alt": "Visuel FIX dessinateur - Estimation difficile, impossible ?", "caption": "L'exercice impossible du budget projet - Source : fix-dessinateur" }, { "type": "paragraph", "html": "La philosophie du \"<strong>No estimate</strong>\" est intéressante et fait de plus en plus parler d'elle dans les conférences de la communauté agile en particulier. Véritable \"mur porteur\" de l'industrie du développement logiciel, une estimation est en effet la pierre angulaire de nombreuses activités en gestion de projet : construction du budget, priorisation roadmap, prise de décisions, contractualisation…" }, { "type": "paragraph", "html": "Cela implique alors de <strong>trouver des alternatives à toutes ces activités projet… </strong>Donc de réinventer la gestion de projet, comment on priorise, comment on communique, comment on prend des décisions… Tout un programme !" }, { "type": "paragraph", "html": "<strong>L'utilisation de référentiel, type abaques de chiffrage pour établir des estimations budgétaires est une méthode</strong> qui, sur la base d'unités d'œuvre supposées êtres comparables aide à estimer un budget projet." }, { "type": "paragraph", "html": "Centrée sur les tâches productives \"pures\". Elle fait l'impasse sur les tâches liées au temps passé (meeting, points d'équipe) et les tâches liées aux travaux dits périphérique à la production (commercial, phase d'étude, de tests...)." }, { "type": "paragraph", "html": "<strong>Le propos ici n'est pas de déconstruire cette approche, mais de revaloriser l'expérience et le bon sens face à certains excès de rationalité.</strong>" }, { "type": "heading", "level": 2, "id": "retour-dexperience-du-cio-dadeo-leroy-merlin-etc", "text": "Retour d'expérience du CIO d'Adeo (Leroy Merlin, etc.)" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote><p>Au niveau budget, l'idée, c'est de fonctionner sur enveloppe fixe. Et moi, je cape l'investissement général, d'Adeo dans le digital, par rapport à la croissance de l'entreprise. On considère que ce ne sont pas des projets, donc ils n'ont pas de fin. Ce sont des produits. Quand on transforme la boîte en orientation product management, l'organisation financière doit aller avec.</p></blockquote><p><strong>Matthieu Grymonprez</strong> — CDO/CIO ADEO. Invité de l'épisode N°30 du Podcast CIO Révolution produit par AirSaas.</p>" }, { "type": "paragraph", "html": "Plutôt que de continuer à estimer des budgets trop longs autour de la notion de projet, Mathieu nous explique qu'<strong>il conserve sa capacité de projection dans une équation économique globale… Tout en organisant les budgets autour de la notion centrale de produit et de cycle agile</strong>. Donc chaque budget, ce sont des OPEX qui s'accumulent." }, { "type": "paragraph", "html": "<strong>L'innovation technologique comme culture d'entreprise. </strong>Décidément <strong>les entreprises \"orientée produit\" tirent l'innovation méthodologique </strong>vers le haut !" }, { "type": "heading", "level": 2, "id": "budgetiser-un-projet-les-6-erreurs-facilement-evitables", "text": "Budgétiser un projet : les 6 erreurs facilement évitables" }, { "type": "heading", "level": 3, "id": "1-sous-estimer-les-delais-et-les-couts-indirects-du-projet", "text": "1. Sous-estimer les délais et les coûts indirects du projet" }, { "type": "paragraph", "html": "<strong>Sous-estimer vos délais</strong> reviendra à <strong>faire travailler pendant plus longtemps que prévu vos ressources</strong>, et donc à \"exploser\" votre budget !" }, { "type": "paragraph", "html": "De nombreuses études ont montré qu'il était <strong>commun qu'un chef de projet soit trop optimiste lorsqu'il estime</strong> la durée de réalisation d'une tâche. Ainsi, <strong>interrogez vos collaborateurs sur le délai dont ils estiment avoir besoin </strong>pour accomplir leurs missions, et ajoutez une marge de sécurité par précaution (souvent entre 20 et 30% selon les collaborateurs)." }, { "type": "heading", "level": 3, "id": "2-vos-partenaires-sont-co-responsables-de-lestimation-impliquez-les", "text": "2. Vos partenaires sont co responsables de l'estimation : impliquez-les !" }, { "type": "paragraph", "html": "Si vous voulez prévoir efficacement vos dépenses et vos recettes, il est primordial d'impliquer les premiers concernés par ces dernières : vos partenaires. Il sera <strong>bien plus simple de réussir à anticiper les bons montants en les calculant avec ceux qui œuvreront au quotidien</strong> sur le projet." }, { "type": "paragraph", "html": "Chacun sera à même de vous donner une idée précise de l'importance des dépenses et des recettes liées aux tâches dont il est responsable au \"coût par coût\"." }, { "type": "paragraph", "html": "Avec ce <strong>dialogue vous risquez d'obtenir un </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/tout-savoir-sur-le-budget-previsionnel-projet\" target=\"_blank\"><strong>budget prévisionnel</strong></a><strong> bien plus proche de la réalité </strong>en interrogeant vos collaborateurs sur leurs domaines de prédilection, <strong>qu'en confiant la réalisation de l'entièreté du budget à un consultant</strong>." }, { "type": "heading", "level": 3, "id": "3-ne-pas-tenir-compte-de-ses-ressources", "text": "3. Ne pas tenir compte de ses ressources !" }, { "type": "paragraph", "html": "Faire l'inventaire de ses ressources est un prérequis indispensable pour réaliser un budget prévisionnel. Vous devez connaître l'ensemble des ressources à votre disposition. On parle ici des ressources matérielles, humaines, mais aussi du temps (nombre de jours) dont vous disposez pour mener à bien ce projet." }, { "type": "paragraph", "html": "L'une des <strong>principales causes d'échec budgétaire est due à une mauvaise planification de la disponibilité des ressources.</strong> Les vacances, la maladie, les mises à pied, les remplacements de ressources, travailler sur plusieurs projets en même temps ont toujours un impact sur le budget." }, { "type": "heading", "level": 3, "id": "4-un-budget-previsionnel-nest-pas-statique-faites-le-evoluer", "text": "4. Un budget prévisionnel n'est pas statique : faites-le évoluer !" }, { "type": "paragraph", "html": "Les coûts de gestion de projet ne sont pas gravés dans le marbre ! Mais évoluera avec le périmètre tout au long du cycle de vie du projet." }, { "type": "paragraph", "html": "Si pour le confectionner en amont, vous êtes bien obligé d'essayer de prévoir le réel, il arrivera un moment où vos hypothèses se vérifieront ou s'infirmeront. Lorsque durant votre projet, vous obtenez davantage d'informations sur les dépenses et les recettes auxquelles vous allez faire face, servez-vous en pour <strong>retravailler votre budget prévisionnel projet</strong> !" }, { "type": "paragraph", "html": "Ainsi, il est conseillé de <strong>faire un bilan chaque mois sur vos dépenses et recettes effectives</strong>, et de les comparer à vos prévisions." }, { "type": "paragraph", "html": "Important : lorsque vous corrigez votre budget prévisionnel, <strong>n'oubliez pas de garder la version antérieure</strong>, cela évitera de perdre le cap, mais sera aussi très intéressant à revoir lorsque vous aurez bien avancé sur le projet !" }, { "type": "heading", "level": 3, "id": "5-attention-au-double-run-de-vos-systemes", "text": "5. Attention au \"double run\" de vos systèmes !" }, { "type": "paragraph", "html": "<strong>Lorsqu'on budgète quelque chose qu'on remplace</strong> il peut y avoir une période ou les deux systèmes sont payés et souvent ça peut faire capoter financièrement le projet." }, { "type": "paragraph", "html": "Un acheteur nous racontait avoir découvert un budget projet ou les utilisateurs avaient demandé et obtenu de conserver l'ancienne appli pour un besoin d'archivage...pendant deux ans ! Et là c'est la triple peine : on garde les coûts d'infra, on garde les coûts de licence, et ceux de maintenance !" }, { "type": "paragraph", "html": "Avec une prévision budgétaire mieux anticipée on peut construire une application en local répondant au besoin de consultation d'archives." }, { "type": "paragraph", "html": "Attention également <strong>lorsqu'on budgète quelque chose qu'on remplace qui était en Capex par de l'Opex</strong> et là, c'est pire. Car on impacte le bilan comptable de l'entreprise !" }, { "type": "paragraph", "html": "Par ailleurs il faut avoir en tête que le coût du projet n'est pas uniquement une somme de dépenses internes mais qu'il y a des externalités." }, { "type": "list", "ordered": false, "items": ["Les coûts de gestion, de ressources humaines, dont les salaires ;", "les charges courantes de l'entreprise (électricité, etc.) ;", "les impôts et taxes ;", "les frais de communication et autres"] }, { "type": "paragraph", "html": "Attention ces coûts indirects seront partagés avec plusieurs projets notamment grâce à une <strong>clé de répartition</strong> !" }, { "type": "heading", "level": 3, "id": "6-lerreur-ultime-sous-traiter-cette-tache-au-controleur-de-gestion", "text": "6. L'erreur ultime : sous-traiter cette tâche au contrôleur de gestion :-)" }, { "type": "paragraph", "html": "Le support et le métier doivent s'entraider ! La lecture de la structure de coûts du budget du projet est un exercice complexe. <strong>Quelle que soit la taille de votre entreprise ne confiez pas ce dossier à quelqu'un qui n'est pas du métier. Faites-vous aider...Ne sous-traitez pas</strong>" }, { "type": "paragraph", "html": "Si vous ne voulez pas retrouver les codes analytiques de la compta dans votre budget projet retravailler toujours les choses sur votre outil." }, { "type": "paragraph", "html": "C'est un investissement conséquent. Mais fondamental pour budgétiser un projet de façon efficace." }, { "type": "heading", "level": 2, "id": "les-benefices-dun-budget-projet-reussi", "text": "Les bénéfices d'un budget projet réussi" }, { "type": "heading", "level": 3, "id": "le-budget-sert-a-rendre-le-projet-credible", "text": "Le budget sert à rendre le projet crédible" }, { "type": "paragraph", "html": "Commune une image, <strong>un bon budget vaut 1000 mots</strong>, car <strong>il démontrera à quel point une équipe de projet a pensé à tout.</strong>" }, { "type": "paragraph", "html": "Attention donc à ne pas oublier la base : un budget est un <strong>résumé des dépenses et des recettes anticipées.</strong> Il présente donc une estimation de l'ensemble des <strong>ressources nécessaires à l'atteinte d'objectifs sur une durée déterminée.</strong>" }, { "type": "paragraph", "html": "Pour gérer efficacement le budget d'un projet il est courant d'établir des indicateurs de performance clés (KPI). Les KPI vous aident à déterminer combien a été dépensé pour un projet, dans quelle mesure le budget réel du projet diffère de ce qui était prévu, etc." }, { "type": "paragraph", "html": "De manière classique enfin on fait attention à la différence entre le coût d'achat et les coûts récurrents (capex opex). On sépare les dépenses IT d'investissement et celles d'exploitation." }, { "type": "heading", "level": 3, "id": "le-budget-de-projet-sassimile-a-un-contrat-tacite", "text": "Le budget de projet s'assimile à un contrat tacite" }, { "type": "paragraph", "html": "Le budget de projet représente <strong>un engagement entre un manager de projet et sa hiérarchie et ou ses investisseurs</strong>, sur les résultats à atteindre et les moyens à mettre en œuvre. Un engagement vis-à-vis de son entreprise !" }, { "type": "paragraph", "html": "Faire un <strong>budget prévisionnel est indispensable lorsque l'on veut créer un projet </strong>: s'il peut servir à convaincre des supérieurs ou des investisseurs de l'intérêt de financer votre projet, il permettra dans tous les cas à toutes les parties impliquées dans le projet d'avoir une visibilité sur l'ensemble de sa réalisation. <a href=\"https://www.airsaas.io/fr/gestion-de-projet/cadrage-projet\" target=\"_blank\">Cadrage</a>, exécution, conduite du changement, communication, exploitation, etc." }, { "type": "heading", "level": 3, "id": "le-budget-est-un-media-il-vous-permet-de-tenir-les-parties-prenantes-informees", "text": "Le budget est un média : il vous permet de tenir les parties prenantes informées" }, { "type": "paragraph", "html": "S'il n'est pas possible de maintenir le budget actuel du projet, les parties prenantes doivent connaître la cause profonde de tout dépassement potentiel afin de prendre des décisions éclairées sur la poursuite. Des changements de portée sont probablement nécessaires. <strong>Le point important ici est que l'incertitude au sens large, comme une pandémie, est inévitable, laissant d'autres décisions liées au budget qui doivent être prises en temps opportun.</strong> Les parties prenantes telles que le client peuvent avoir besoin de décider si le moment ou les circonstances sont propices pour poursuivre, reporter ou arrêter complètement un projet." }, { "type": "heading", "level": 3, "id": "mieux-budgetiser-permet-danticiper-et-ajuster-son-projet", "text": "Mieux budgétiser permet d'anticiper et ajuster son projet" }, { "type": "paragraph", "html": "L'intérêt premier d'un budget prévisionnel est d'essayer d'<strong>accroître sa visibilité sur le futur</strong> de votre projet, ses ressources, autrement dit, d'anticiper !" }, { "type": "paragraph", "html": "En effet, construire le budget prévisionnel de son projet est l'une des <strong>meilleures solutions pour estimer sa faisabilité</strong>. Vous allez pouvoir calculer la marge que vous espérez atteindre (ou au moins l'équilibre budgétaire) et <strong>réaliser des ajustements sur votre stratégie </strong>si vous vous rendez compte que votre business plan ne tient pas la route." }, { "type": "paragraph", "html": "<strong>Astuces</strong> : vous pouvez même <strong>réaliser plusieurs budgets prévisionnels</strong> qui représentent les différents scénarios que vous envisagez, et qui prennent en compte les imprévus que vous pouvez imaginer (problème d'approvisionnement, nouveaux concurrents qui changent le marché, etc.)" }, { "type": "heading", "level": 3, "id": "le-budget-projet-mal-tenu-peut-destabiliser-ou-pas-toute-lentreprise", "text": "Le budget projet mal tenu peut déstabiliser, ou pas, toute l'entreprise" }, { "type": "paragraph", "html": "Au-delà du budget projet dépassé, l'impact éventuel des <strong>coûts de la non-livraison sur le business </strong>peut avoir un impact financier significatif. L'exemple emblématique est celui de la ville de Denver ou l'échec du logiciel de gestion de bagages du nouvel aéroport représenterait un coût de 1,1 million de dollars / jour." }, { "type": "paragraph", "html": "Si on prend un <strong>autre très gros projet par exemple comme l'interminable saga des EPR</strong>. Un nom devenu <strong>synonyme</strong> de retards à répétition et <strong>de gouffre financier.</strong> Disons le simplement oui c'est un budget projet raté : à ce jour il en est à 4x le budget estimé et 11 ans de dépassement de délais !" }, { "type": "paragraph", "html": "Bon, c'était le premier projet de ce type, c'est mission <strong>impossible de budgéter un chantier comme ça</strong>. Maintenant qu'ils l'ont fait une fois la prochaine itération sera beaucoup plus en ligne dans le prochain projet, plus précise pour la construction des six autres réacteurs prévus pour un coût total estimé entre 52 et 64 milliards d'euros !" }, { "type": "heading", "level": 2, "id": "resume", "text": "Résumé" }, { "type": "list", "ordered": false, "items": ["Petit projet ou gros projet ? <strong>On refuse de faire des budgets projets globaux</strong>, ça ne sert à rien !", "Besoin d'expérience de conseils ? Faites appel à un ami DSI/PMO/Chef de projet ou à un site web mais <strong>fonctionnez par analogie.</strong>", "Le projet remplace ou c'est nouveau ? Dans le premier cas <strong>attention à la durée de la phase de double exploitation.</strong>", "Le projet est long...<strong>modifiez le budget pendant toute la mise en œuvre du projet.</strong>"] }, { "type": "paragraph", "html": "Le budget prévisionnel est terminé ? Vous pouvez désormais l'intégrer à votre <a href=\"https://www.airsaas.io/gestion-de-projet/fiche-projet-exemple-et-methodologie\" target=\"_blank\">fiche projet</a>." }], "toc": [{ "label": "Relever le défi du budget avec une estimation \"par analogie\"", "href": "#relever-le-defi-du-budget-avec-une-estimation-par-analogie", "level": 2 }, { "label": "Découpez le budget de projet en tranches crédibles !", "href": "#decoupez-le-budget-de-projet-en-tranches-credibles", "level": 2 }, { "label": "Retour d'expérience du CIO d'Adeo (Leroy Merlin, etc.)", "href": "#retour-dexperience-du-cio-dadeo-leroy-merlin-etc", "level": 2 }, { "label": "Budgétiser un projet : les 6 erreurs facilement évitables", "href": "#budgetiser-un-projet-les-6-erreurs-facilement-evitables", "level": 2 }, { "label": "Les bénéfices d'un budget projet réussi", "href": "#les-benefices-dun-budget-projet-reussi", "level": 2 }, { "label": "Résumé", "href": "#resume", "level": 2 }], "faq": [], "related": [] }, { "slug": "cadrage-projet", "skip": false, "meta": { "title": "Comment faire un bon cadrage projet avec les métiers ?", "h1": "Comment faire un bon cadrage projet avec les métiers ?", "description": "Cadrez vos cadrages ! Une initialisation de projet réussi repose, entre autres, sur une vraie rencontre entre la connaissance métier, le sponsoring managérial et une expertise technologique.", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "16/5/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea93ec131e426ca619a033_Project%20image%20(5).jpg", "alt": "" }, "publishedDate": "16/5/2022" }, "blocks": [{ "type": "paragraph", "text": "Cadrez vos cadrages ! Une initialisation de projet réussi <strong>repose, entre autres, sur une vraie rencontre entre la connaissance métier, le sponsoring managérial et une expertise technologique.</strong> Néanmoins, et même si de nombreuses entreprises ont bien adressé cette question de l'absence de collaboration dès la note de cadrage, on assiste encore bien trop souvent en gestion de projet au maintien des silos en entreprise dès cet avant-projet !" }, { "type": "paragraph", "text": "Pourquoi en est-on arrivé à cet état de fait dans la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> ? Quelle est la composante clé d'un bon cadrage projet avec le métier à ne pas rater ? Comment font ceux qui innovent en termes de management de projet ?" }, { "type": "paragraph", "text": "Dans cet article vous découvrirez notamment des supers exemples de co-construction DSI/métiers inspirants (ne ratez pas les flashs design de la DSI de Ouigo !)&nbsp; Une façon hyper pragmatique et super efficace de traiter les feedbacks métiers et de gagner un maximum de temps dans l'exécution d'un projet. Avec ça fini les cadrages projets \"boiteux\"." }, { "type": "paragraph", "text": "À la fin de cet article vous repartirez en outre avec les <strong>étapes clés d'un cadrage collaboratif qui fonctionne</strong>, ainsi qu'une première <strong>liste de questions à poser pour dynamiser vos ateliers</strong>. Enfin nous ferons un court <strong>retour sur le rôle clé du BRM</strong> et une <strong>sélection d'exemples de cadrages agiles et participatifs</strong>." }, { "type": "paragraph", "text": "Bref, restez connectés ! On vous dit <strong>tout ce qu'il faut savoir sur l'art de</strong> <strong>cadrer votre projet… avec les métiers !</strong>" }, { "type": "heading", "level": 2, "id": "critique-de-lapproche-projet-moamoe", "text": "Critique de l'approche projet MOA/MOE" }, { "type": "paragraph", "text": "Pour comprendre la situation actuelle il est intéressant de porter un regard critique sur le \"legacy\" de l'approche MOE/MOA en gestion de projet. Oui, on a trop longtemps assisté à un jeu de « passe-plat » entre les business units. Chacun dans son \"pré carré\", ses objectifs." }, { "type": "paragraph", "text": "Pour poursuivre la métaphore culinaire, on pourrait même dire que <strong>les relations entre la cuisine (la DSI) et la salle de restaurant (les métiers) étaient clairement organisées en silos</strong>. Surtout pas de mélange entre nous ! Chacun ses projets, sa zone, avec au milieu, bien souvent, un serveur (chef de projet) pas très à l'aise pour piloter le tout. Et, en bout de chaîne, un client qui mangeait son plat froid ! Les uns attendant un cadrage de projet qui prenait beaucoup de temps, les autres des expressions de besoins mieux rédigées. <strong>Pas une franche réussite !</strong>" }, { "type": "heading", "level": 2, "id": "cadrage-dabord-une-co-construction", "text": "Cadrage ? D'abord, une co-construction !" }, { "type": "paragraph", "text": "Réussir un objectif cadrage d'un projet de transformation digitale, implique une <strong>démarche de co-construction d'équipe, une responsabilité partagée</strong>. En gestion de projet, l'objectif est bien d'éviter les silos et ce, dès les premières étapes de compréhension du besoin, de rédaction de la note de cadrage, en créant votre première équipe. Une sorte de MVP (Minimum Viable People), en somme." }, { "type": "paragraph", "text": "Celle-ci embarque à la fois le futur réalisateur de l'action la tech ! Le manager - aka Mr Sponsor - et un représentant du besoin, celui qui connaît le quotidien du business : le métier." }, { "type": "list", "ordered": false, "items": ["Le chef de projet, <strong>coordinateur général de cette \"micro entreprise\"</strong> sera chargé de cadrer le projet de façon collaborative.", "À ses côtés pour mener le cadrage, <strong>le représentant du métier, celui qui connaît le quotidien</strong> et les objectifs clés du projet, les attentes client.", "Cette co-construction s'appuie enfin sur le rôle clé de <strong>sponsor qui participe et anime une instance de conseil qui décide</strong> de la mise en place des processus et règles de contrôle proposés par les experts métier."] }, { "type": "paragraph", "text": "Selon la taille et la complexité organisationnelle de l'entreprise, cette micro structure va être plus ou moins évoluée. Le sponsoring pourra être mené par un ou plusieurs managers, etc." }, { "type": "paragraph", "text": "C'est cette manière de <strong>travailler en transverse dès le début</strong> qui va permettre aux collaborateurs de <strong>casser les silos</strong> et délivrer rapidement de nouveaux services, de <strong>privilégier l'intelligence collective à la première étape</strong>." }, { "type": "heading", "level": 2, "id": "cadrage-limportance-dun-autre-rapport-au-temps", "text": "Cadrage : l'importance d'un autre rapport au temps" }, { "type": "paragraph", "text": "Quel que soit le projet il faut quand même un peu de temps pour réfléchir à ce qu'on veut ! Que cela soit en termes de fonctionnalité, d'impact de changement..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea93667722a5a4e3e6dc2c_fix-chief-bullshit-officer-ed-diateino-min.jpg", "alt": "Dessin d'humour FX Dessinateur quick & dirty Slow & dirty", "caption": "Source fix dessinateur - Album Chief Bullshit officer ed. Diateino avril 2022" }, { "type": "quote", "text": "\"Le plus long dans les projets ce n'est pas la mise en place d'un système d'information. C'est plutôt la réflexion en amont du côté de l'entreprise et de ses métiers sur la question du comment est ce qu'ils veulent travailler…!\".", "author": "Isabelle André Perussi — DSI Ouigo et DG Squirrel (extrait de l'épisode 34 du Podcast CIO Révolution produit par AirSaas)." }, { "type": "paragraph", "text": "Face à la contrainte générale que représentent le raccourcissement des délais et la pénurie de compétences IT, <strong>privilégier un cadrage long sera un défi !</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/628219c1841ad01b695fcf8c_vik_illu-action-agile.png", "alt": "Dessin humour innovation", "caption": "La métaphore de la gestion du temps dans un projet - Source : vik-graphisme" }, { "type": "paragraph", "text": "Et, il faut se le dire <strong>: si l'équipe qui a le problème n'a même pas le temps de bien travailler sur celui-ci dès le début, il vaut mieux ne pas le faire !</strong> Les prochaines étapes prévues au planning ne risquent pas d'être meilleures en termes de réussite !" }, { "type": "quote", "text": "\"Durant nos réunions de métier / SI mensuelles, on négocie ! Si la direction concernée n'arrive pas à déléguer, à mettre des équipes c'est qu'il n'y a pas de valeur derrière ! Et si au bout d'un certain nombre de fois...il n'arrive pas à dégager du temps...des fois on se rend compte que le projet n'est pas la vraie priorité...alors on lance alors un autre projet !", "author": "Frédéric Navarro — DSI, Manager de Transition ESINFO (extrait de l'épisode 28 du Podcast CIO Révolution produit par AirSaas)." }, { "type": "heading", "level": 2, "id": "cadrage-projet-de-quoi-parle-t-on", "text": "Cadrage projet, de quoi parle-t-on ?" }, { "type": "paragraph", "text": "Faisons un arrêt sur images sur la définition même de l'étape de cadrage dans une gestion de projet." }, { "type": "heading", "level": 3, "id": "definition", "text": "Définition" }, { "type": "paragraph", "text": "<strong>Il s'agit bien d'une étape d'étude et d'analyse</strong> qui impacte la décision de lancer le projet, ou pas, selon son intérêt et sa faisabilité. En général une <a href=\"https://www.airsaas.io/fr/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\">note de cadrage</a> en résume les conclusions." }, { "type": "paragraph", "text": "Cette note de cadrage est le <strong>document synthétique qui permettra à chacun d'identifier en un coup d'œil les points principaux</strong> du cadrage de votre projet." }, { "type": "paragraph", "text": "Parmi les techniques basiques existantes on peut citer :" }, { "type": "paragraph", "text": "- La méthode SMART (pour Simple, Mesurable, Atteignable, Réaliste et Temporellement défini)" }, { "type": "paragraph", "text": "- La méthode \"CQQCOQP\" pour combien, quoi, qui, comment, où, quand et pourquoi ?" }, { "type": "paragraph", "text": "Chacun aura sa définition et sa propre méthode pour aboutir à une note de cadrage." }, { "type": "heading", "level": 3, "id": "la-note-de-cadrage-repond-a-trois-grandes-questions", "text": "La note de cadrage répond à trois grandes questions" }, { "type": "list", "ordered": true, "items": ["Description projet : gains attendus, livrables, etc.", "Contexte projet : périmètre, personnes impactées, origine de la demande, évolution réglementaire, plan de transformation de l'entreprise, conduite du changement, etc.", "Chiffres du projet ? Budget, durées, etc."] }, { "type": "paragraph", "text": "Les fiches de <strong>cadrage projet sont dynamiques et collaboratives</strong>. Les équipes IT/métier/sponsor peuvent itérer ensemble jusqu'à ce que le projet soit validé, dans un véritable cahier des charges complet qui guidera l'avancement du projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea93a555a4e608f0a66297_Creation-step1.jpg", "alt": "Capture écran AirSaas", "caption": "Sur AirSaas, nous guidons vos collaborateurs dans le remplissage des informations essentielles à une bonne note de cadrage." }, { "type": "heading", "level": 3, "id": "secrets-de-chef-de-projet-la-questiologie-ou-lart-de-poser-les-bonnes-questions", "text": "Secrets de chef de projet : la \"questiologie\" ou l'art de poser les bonnes questions !" }, { "type": "paragraph", "text": "Un cadrage complet, c'est une interrogation de la cible du besoin (la destination) ET une étape d'interrogation de la démarche (le chemin), en fonction du temps et des objectifs de chacun." }, { "type": "heading", "level": 4, "id": "questionner-la-cible-reelle-du-besoin-la-vraie-problematique", "text": "Questionner la cible réelle du besoin : la vraie problématique" }, { "type": "paragraph", "text": "Le principal écueil est de passer à côté du vrai sujet ! Il est utile de <strong>questionner et requestionner encore l'expression même de la problématique</strong>. D'aller chercher ce qui n'est pas écrit." }, { "type": "paragraph", "text": "Le cadrage est un vrai travail de mise en forme des pensées confuses grâce à un dialogue. Pour y parvenir, il est utile de <strong>croiser la donnée du métier avec celle de votre service client !</strong> Et de vos clients eux-mêmes bien sûr." }, { "type": "paragraph", "text": "Voici un <strong>exemple de questions ouvertes</strong>, à poser pour creuser le cadrage projet :" }, { "type": "list", "ordered": false, "items": ["Pourquoi ce problème n'a-t-il pas été résolu avant ?", "Comment a-t-il été contourné ?", "S'il est toujours là dans trois mois, quel impact ?", "Quel est le chemin le plus court qui a le plus d'impact ?"] }, { "type": "paragraph", "text": "Souvenez-vous : l'objectif est de dialoguer, afin d'élaborer avec un projet une solution innovante pour satisfaire des besoins précis et identifiés." }, { "type": "quote", "text": "\"Si j'avais une heure pour résoudre un problème, je passerais cinquante-cinq minutes à définir le problème et seulement cinq minutes à trouver la solution.\"", "author": "A. Einstein" }, { "type": "heading", "level": 4, "id": "questionner-les-solutions-un-besoin-1-000-facons-dy-repondre", "text": "Questionner les solutions : Un besoin ? 1 000 façons d'y répondre !" }, { "type": "paragraph", "text": "Un cadrage projet réussi permettra en effet de proposer plusieurs façons de répondre au problème identifié. Prenons un cas concret : la demande client au sein d'une entreprise \"je voudrais un ascenseur plus rapide\". Lors du premier cadrage on s'accorde tous pour la solution et créer le projet : planifier l'achat d'un nouvel ascenseur ! Lors du second cadrage, quelqu'un proposera de mettre une animation sympa et un nouvel écran pour faire attendre la personne intelligemment ! Problématique traitée. CQFD. :)" }, { "type": "quote", "text": "Si tu as besoin de quelque chose, appelle-moi, je te dirais comment t'en passer", "author": "Coluche" }, { "type": "heading", "level": 2, "id": "cadrage-dun-projet-allez-aussi-chercher-lexperience", "text": "Cadrage d'un projet : allez aussi chercher l'expérience !" }, { "type": "paragraph", "text": "Pensez à prendre tous les insights déjà donnés autour de ce problème" }, { "type": "list", "ordered": false, "items": ["Organiser la remontée des insights", "Toutes les semaines 2h de flash design pour travailler avec les métiers sur les insights et problèmes remontés."] }, { "type": "heading", "level": 3, "id": "organiser-la-remontee-des-insights", "text": "Organiser la remontée des \"insights\"" }, { "type": "list", "ordered": false, "items": ["Logguer tous les feedbacks en continu qui viennent du BRM ou du ticketing.<br>N'oublions pas que pour bien cadrer les projets il faut avoir une donnée claire, propre, structurée ! Le concept de garbage in / garbage out prend une nouvelle fois tout son sens."] }, { "type": "heading", "level": 3, "id": "retour-dexperience-le-flash-design", "text": "Retour d'expérience : Le \"flash design\"" }, { "type": "paragraph", "text": "Dans le cadre des interviews de notre Podcast CIO Révolution, <strong>Isabelle André Perussi,</strong> la DSI de Ouigo nous a parlé du \"flash design\" et on a adoré l'idée." }, { "type": "paragraph", "text": "Plutôt que de commencer à réfléchir au cadrage d'un besoin métier quand on a le temps de le traiter, elle nous explique qu'<strong>elle organise des sessions flash design de 2h dès que le métier émet son \"ticket\". 2h de brainstorming réunissant le métier et l'IT pour dégrossir le besoin</strong>, étudier les solutions SaaS \"miracles\" qui pourraient y répondre, et finalement se laisser du temps pour mûrir le besoin d'un véritable projet informatique interne. Tout ça intervenant bien en amont de la phase de cadrage. L'investissement est, il paraît, vite rentabilisé et beaucoup de frustrations projet vite désamorcées." }, { "type": "heading", "level": 2, "id": "brm-agilite-des-approches-complementaires-pour-votre-cadrage-avec-les-metiers", "text": "BRM, agilité, des approches complémentaires pour votre cadrage avec les métiers" }, { "type": "heading", "level": 3, "id": "brm-business-relationship-managemement", "text": "BRM : Business Relationship Managemement" }, { "type": "paragraph", "text": "Une pratique inspirée des référentiels de management des services informatiques ITIL : «Le BRM stimule, identifie, et façonne la demande des métiers en produits et services et s'assure que la valeur de ces produits et services est réalisée, optimisée et reconnue ». Un rôle qui favorise le renforcement de la relation DSI-métiers. <strong>Des gens dédiés,</strong> en fonction de la taille de l'entreprise, <strong>à la compréhension des besoins de l'entreprise en continu !</strong>" }, { "type": "paragraph", "text": "Sur ce rôle, découvrez ci-dessous le retour d'expérience du CDIO de Biogaran, Frédéric Riou :" }, { "type": "quote", "text": "Avec ce rôle de business partner, l'objectif, c'est d'être force de proposition, d'apporter des réponses aux problèmes posés, d'avoir un coup d'avance : on est tellement en connaissance du métier que le but, c'est d'apporter la solution avant même qu'un problème soit identifié.", "author": "Episode 29 podcast CIO Révolution." }, { "type": "heading", "level": 3, "id": "cadrages-agiles-des-approches-qui-engagent", "text": "Cadrages agiles : Des approches qui \"engagent\"" }, { "type": "paragraph", "text": "Avec la culture agile, on utilisera par exemple <strong>les jeux \"qui font le boulot\".</strong> Des ateliers ludiques pour arriver à une définition de la vision 360 du produit, d'un projet : vision, objectifs, storymap, roadmap, POC, etc." }, { "type": "paragraph", "text": "On peut en citer trois parmi de très nombreux :" }, { "type": "list", "ordered": false, "items": ["Le <a href=\"https://creativetech-fr.devoteam.com/2021/03/17/pre-mortem-se-projeter-dans-l-echec-du-produit-pour-mieux-l-eviter/\" target=\"_blank\">pre mortem</a> : élaborer un plan avant de commencer !", "Le product box : matérialiser physiquement les différentes visions sous forme de boîtes.", "Le catch-up d'un client en 15 minutes autour d'un café : vous saurez s'il faut creuser ou passer son chemin !"] }, { "type": "paragraph", "text": "Pour creuser cette approche, la lecture du livre <em>Gamestorming</em> publié aux éditions Diateino est vivement conseillée." }, { "type": "heading", "level": 2, "id": "a-retenir", "text": "À retenir" }, { "type": "insight-callout", "label": "À retenir", "html": "<ul><li>Évitez les silos dès la compréhension du besoin !</li><li>Les principales frictions proviennent du manque de compréhension du jeu de contrainte de la DSI et de la prise en compte des attentes des métiers. Dans votre <a href=\"/gestion-de-projet/comment-mettre-une-demarche-de-projet-dans-mon-entreprise\" target=\"_blank\">démarche de projet,</a> travailler d'emblée en coopération autour d'une plateforme commune améliore la compréhension de ce qui peut être fait et dans quel délai.</li><li>Cadrez vos cadrages ! C'est la phase à ne pas rater. C'est une question de ressource temps et d'investissement !</li></ul>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6282192f4608683b5bc4e5db_Sans%20titre%20(4).jpg", "alt": "Visuel illustration process cadrage métier", "caption": "Sur AirSaas, nous guidons les utilisateurs dans le remplissage des informations et objectifs essentielles de cadrage d'un projet." }], "toc": [{ "label": "Critique de l'approche projet MOA/MOE", "href": "#critique-de-lapproche-projet-moamoe", "level": 2 }, { "label": "Cadrage ? D'abord, une co-construction !", "href": "#cadrage-dabord-une-co-construction", "level": 2 }, { "label": "Cadrage : l'importance d'un autre rapport au temps", "href": "#cadrage-limportance-dun-autre-rapport-au-temps", "level": 2 }, { "label": "Cadrage projet, de quoi parle-t-on ?", "href": "#cadrage-projet-de-quoi-parle-t-on", "level": 2 }, { "label": "Cadrage d'un projet : allez aussi chercher l'expérience !", "href": "#cadrage-dun-projet-allez-aussi-chercher-lexperience", "level": 2 }, { "label": "BRM, agilité, des approches complémentaires pour votre cadrage avec les métiers", "href": "#brm-agilite-des-approches-complementaires-pour-votre-cadrage-avec-les-metiers", "level": 2 }, { "label": "À retenir", "href": "#a-retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "capacity-planning", "skip": false, "meta": { "title": "Le guide pour concevoir un Capacity Planning efficace", "h1": "Le guide pour concevoir un Capacity Planning efficace", "description": "Le guide pour concevoir un Capacity Planning efficace", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae4b88b03fcfdfe480103_Le%20guide%20pour%20concevoir.jpg", "alt": "" }, "author": { "category": "Gestion de projets" } }, "blocks": [{ "type": "paragraph", "text": "Combien de fois avez-vous dû réaffecter en urgence des ressources sur un projet prioritaire, au détriment d'un autre tout aussi stratégique ? &nbsp;<br>Combien de fois avez-vous eu du mal à justifier que vous ne pouviez pas lancer ces trois nouveaux projets tactiques ?<br>Combien de fois avez-vous senti la frustration de vos interlocuteurs face à vos explications, quand vous disiez \"on ne peut pas tout faire\" ?" }, { "type": "paragraph", "text": "Pour vous, DSI, PMO ou chef de projet, une mauvaise gestion des capacités entraîne des situations désagréables et des relations compliquées avec le reste de l'entreprise. Sans parler des équipes qui peuvent partir en burn out à force de courir derrières tous les lapins…" }, { "type": "paragraph", "text": "Pour l'entreprise c'est synonyme de gouffre financier. À mal gérer ses ressources, on gaspille énormément : retards et pertes financières… sans parler du stress de telles situations !" }, { "type": "paragraph", "text": "La solution ? Un Capacity Planning bien pensé, qui vous aide à éviter ces écueils en optimisant l'utilisation des ressources selon les priorités mouvantes de votre entreprise." }, { "type": "paragraph", "text": "Seulement, chez Airsaas, on sait combien il est facile de se perdre en chemin, et de finir par créer, soit une usine à gaz… soit rien du tout !" }, { "type": "paragraph", "text": "Pas de panique ! Ce guide vous donne <strong>toutes les clés pour construire un Capacity Planning efficace et maîtriser vos capacités de production</strong> : étapes à suivre, bonnes pratiques et outils." }, { "type": "heading", "level": 2, "id": "quest-ce-que-le-capacity-planning", "text": "Qu'est-ce que le Capacity Planning ?" }, { "type": "paragraph", "text": "Commencez votre plongée dans la méthode du Capacity Planning en vous penchant sur sa définition - histoire de commencer sur de bonnes bases !" }, { "type": "heading", "level": 3, "id": "une-definition-du-capacity-planning-claire-et-simple", "text": "Une définition du Capacity Planning claire et simple" }, { "type": "paragraph", "text": "Le Capacity Planning est une méthode permettant d'<strong>évaluer, de planifier et d'assurer une gestion des ressources optimale pour répondre aux besoins du portefeuille de projets</strong> / portefeuille d'initiatives d'une entreprise. Cette méthodologie prend en compte la gestion des ressources humaines et financières. On trouve également cette méthode sous les noms de gestion de la capacité, gestion capacitaire, ou plan capacitaire." }, { "type": "paragraph", "text": "Le but final d'un Capacity Planning est d<strong>'aligner la capacité disponible dans l'entreprise avec la demande prévue</strong>, en trouvant l'équilibre entre la stratégie de l'entreprise et ce qu'elle peut effectivement produire sur la période." }, { "type": "paragraph", "text": "Cette méthodologie permet ainsi de savoir quelle charge de travail attribuer aux équipes, et si davantage de ressources humaines sont nécessaires pour réaliser les projets." }, { "type": "paragraph", "text": "Attention à ne pas confondre le Capacity Planning avec une simple méthode de planification des ressources à court-terme, où on fait matcher la capacité de l'entreprise avec ses besoins actuels. Ici, on cherche à prévoir l'allocation des ressources sur un temps plus long, pour répondre à une demande à venir." }, { "type": "paragraph", "text": "<a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning-definition\" target=\"_blank\">Pour une définition du Capacity Planning plus creusée, c'est par ici que ça se passe</a>." }, { "type": "heading", "level": 3, "id": "la-difference-entre-capacity-planning-et-planification-de-la-demande", "text": "La différence entre Capacity Planning et planification de la demande" }, { "type": "paragraph", "text": "En tant que chef de projet, DSI ou PMO, il est fréquent de se mélanger les pinceaux entre différentes notions. Or, ici, il est important de comprendre les différences entre planification de la demande et Capacity Planning." }, { "type": "paragraph", "text": "D'un côté, <strong>le Capacity Planning</strong> permet de planifier les ressources nécessaires pour répondre à des besoins déjà identifiés (sur des projets en cours ou validés), et de vérifier si la charge de travail passe ou non auprès des équipes.<br>De l'autre, ce qu'on appelle généralement <strong>la planification de la demande</strong> (ou gestion de la demande) consiste à prévoir la demande future en projets qui arrivent dans le pipeline du portfolio." }, { "type": "paragraph", "text": "Ces deux notions présentent quelques différences :" }, { "type": "list", "ordered": false, "items": ["<strong>Elles ne suivent pas les mêmes objectifs</strong>. La gestion de la demande organise les différentes étapes de qualification, compréhension, priorisation. Et oui : il y a bien trop de \"demandes\" pour toutes les traiter en parallèle. Il faut donc organiser ce pipeline. De l'autre côté, le Capacity Planning se focalise sur la gestion des ressources pour répondre aux besoins actuels.", "<strong>Elles n'utilisent pas les mêmes données</strong>. Un plan capacitaire utilise la capacité existante de l'entreprise, tandis que la planification de la demande s'appuie sur une priorisation des demandes en projets ou en évolutions provenant des différents pôles de l'entreprise."] }, { "type": "paragraph", "text": "Cependant, malgré leurs différences, ces deux méthodes sont fondamentalement complémentaires. D'un côté, en planifiant la demande, vous répondez à la question \"Que devons-nous faire comme projets ?\". De l'autre, votre gestion de la capacité répond à la question &nbsp;\"Pouvons-nous faire ces projets ?\"." }, { "type": "paragraph", "text": "En somme, la gestion de la demande vous permet de canaliser les projets, pour lancer ceux qui peuvent vraiment être réalisés, plutôt que de vous lancer dans mille initiatives qui, même si elles sont bonnes, risquent bien de ne jamais aboutir." }, { "type": "paragraph", "text": "Chez Airsaas, nous recommandons toujours de planifier des réunions de gestion de la demande (ou request reviews) tous les quinze jours, pour récolter la demande. <br>Une bonne pratique est de créer des duos par domaine et solution - par exemple : Leader IT RH - Leader métier RH. Le Leader métier analyse les demandes et échange tous les 15 jours avec son Leader IT dédié, pour qualifier les demandes et orienter leur traitement : déjà traité, demande pas en accord avec les objectifs de l'organisation…" }, { "type": "paragraph", "text": "Pour aller plus loin <a href=\"https://www.airsaas.io/fr/podcast-cio-revolution/les-defis-techniques-et-humains-de-la-transition-didtgv-a-la-dsi-de-oui-go-isabelle-andre-perussi-e34\" target=\"_blank\">écoutez l'épisode de notre podcast où nous parlons du Flash Design avec Isabelle Perussy</a>." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c0254d7662945f0bda0459_culture-capacity-planning.png", "alt": "" }, { "type": "paragraph", "text": "Ainsi, <strong>à elles deux, ces méthodes permettent d'équilibrer les besoins et les ressources, et de maximiser l'efficacité opérationnelle </strong>de l'entreprise." }, { "type": "paragraph", "text": "Pour bien comprendre ces différences, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/planification-de-la-demande-capacity-planning\" target=\"_blank\">lisez notre article \"Planification de la demande et Capacity Planning : quelles différences ?\"</a>." }, { "type": "heading", "level": 2, "id": "les-7-benefices-dun-capacity-planning-bien-ficele", "text": "Les 7 bénéfices d'un Capacity Planning bien ficelé" }, { "type": "paragraph", "text": "Dans une organisation où les projets d'entreprise sont majoritairement transverses, le Capacity Planning devient un outil crucial. Combien de projets, qui portent pourtant tant de valeur pour l'entreprise, sont décalés mois après mois, faute d'une planification des ressources humaines transverse ?" }, { "type": "paragraph", "text": "Dans ce contexte, un capacitaire permet de prioriser de manière collective les projets à mener, en alignant tout le monde autour d'une dynamique positive." }, { "type": "paragraph", "text": "Ainsi, grâce à un Capacity Planning bien huilé, on observe :" }, { "type": "list", "ordered": false, "items": ["<strong>Une optimisation des ressources</strong>. Une meilleure allocation des ressources vous garantit que chaque projet dispose des compétences et des moyens nécessaires pour avancer efficacement, évitant ainsi le gaspillage et la surcharge.", "<strong>Des projets qui ont plus de chance de réussir</strong>. En anticipant les besoins en ressources, votre Capacity Planning limite les goulots d'étranglement et les blocages, et assure le respect des délais projet.", "<strong>Une amélioration de la relation entre les différents membres de la direction</strong>, grâce à &nbsp;un alignement stratégique amélioré. Les décisions d'allocation des ressources sont prises en fonction des priorités de l'entreprise, ce qui garantit une exécution en phase avec les objectifs stratégiques, et une meilleure communication entre les différentes parties prenantes. Vous pouvez enfin lancer (et finir !) ces projets non-stratégiques, souvent ignorés par la Direction, mais que les métiers attendent avec tant d'impatience.", "<strong>Une bonne préparation aux variations de la demande</strong>. Une vision claire des capacités permet d'anticiper les besoins en ressources supplémentaires et d'adapter la charge de travail en fonction des fluctuations d'activité.", "<strong>Une optimisation des coûts</strong>. En planifiant avec précision les budgets nécessaires à chaque projet et équipe, vous évitez les dépenses inutiles et améliorez votre retour sur investissement.", "<strong>Une amélioration de la productivité et de la satisfaction des parties prenantes</strong>. Une charge de travail équilibrée permet aux équipes d'être plus efficaces et de livrer des projets de qualité, tout en réduisant le stress et en favorisant l'engagement des collaborateurs."] }, { "type": "paragraph", "text": "En somme, la méthode du Capacity Planning, c'est moins de gaspillage de ressources, plus de projets qui arrivent au bout, et plus d'engagement de toutes vos parties prenantes." }, { "type": "paragraph", "text": "De quoi avoir envie de vous lancer, n'est-ce pas ?" }, { "type": "heading", "level": 2, "id": "les-etapes-pour-creer-votre-plan-capacitaire", "text": "Les étapes pour créer votre plan capacitaire" }, { "type": "paragraph", "text": "Ici, vous trouverez un résumé des différentes étapes pour créer votre propre Capacity Planning. Pour entrer dans le détail, n'hésitez pas à <a href=\"http://www.airsaas.io/fr/gestion-de-projet/plan-capacitaire\" target=\"_blank\">consulter notre article sur les 7 étapes pour créer votre plan capacitaire</a>." }, { "type": "heading", "level": 3, "id": "creer-des-groupes-de-competences-homogenes", "text": "Créer des groupes de compétences homogènes" }, { "type": "paragraph", "text": "Dans un premier temps, il convient de créer une organisation par équipe qui correspondent à des groupes de compétences homogènes. Par exemple IT Sécurité, IT data, IT infra, Finance ERP, Finance Corporate… cela va vous permettre de découper vos initiatives par groupe de compétence homogène ce qui est très pratique pour faire un capacitaire au trimestre." }, { "type": "heading", "level": 3, "id": "definir-votre-capacite-actuelle", "text": "Définir votre capacité actuelle" }, { "type": "paragraph", "text": "Ensuite, il va falloir, pour chaque groupe de compétences homogènes, <strong>définir le temps de run et le temps de build.</strong>" }, { "type": "paragraph", "text": "Attention à ce point : Il faut bien redéfinir collectivement le run et le build. Par exemple, il est dangereux de laisser les demandes d'évolutions dans le run : il vaut mieux les mettre dans le build. Le run pourrait être plutôt vu comme du support de premier ou second niveau. Tout ce qui crée de la valeur par la \"construction\" est du build - sinon, comment le valoriser ?" }, { "type": "heading", "level": 3, "id": "recolter-la-demande-sur-la-periode", "text": "Récolter la demande sur la période" }, { "type": "paragraph", "text": "Puis il s'agit d'<strong>identifier les projets prioritaires au vu des objectifs stratégiques de l'entreprise</strong>. Pour ce faire, vous pouvez vous appuyer sur les décisions prises par les différents métiers et la direction, mais aussi sur les données historiques de l'entreprise, et les tendances du marché." }, { "type": "heading", "level": 3, "id": "identifier-les-ecarts-entre-demande-et-capacite", "text": "Identifier les écarts entre demande et capacité" }, { "type": "paragraph", "text": "À cette étape, <strong>comparez de près la capacité actuelle des équipes avec la demande prévue</strong> sur la période. Vous pourrez ici identifier les goulots d'étranglement et les équipes qui disposent de plus de temps." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02619d9ea0f26bb542e01_capacitaire-equipes.png", "alt": "" }, { "type": "heading", "level": 3, "id": "equilibrer-capacite-et-demande", "text": "Équilibrer capacité et demande" }, { "type": "paragraph", "text": "Ici, vous rentrez dans le vif du sujet du Capacity Planning. Il s'agit de mettre en place des stratégies pour équilibrer la capacité et la demande." }, { "type": "paragraph", "text": "Pour ce faire, vous pouvez choisir de moduler la demande, en dépriorisant certains projets ou livrables à plus tard ou, a contrario, en priorisant d'autres projets." }, { "type": "paragraph", "text": "Mais souvent, il s'agira plutôt d'ajuster la capacité. Plusieurs leviers s'offrent ici à vous : recrutement de ressources humaines, formation à des compétences dont vous avez besoin, externalisation de certains livrables, mise en place de technologies en support…" }, { "type": "paragraph", "text": "Différentes stratégies d'ajustement de la capacité existent, dont :" }, { "type": "list", "ordered": false, "items": ["<strong>La stratégie \"Lead\"</strong>, qui consiste à augmenter la capacité pour anticiper des besoins en amont d'une hausse de la demande.", "<strong>La stratégie \"Lag\"</strong>, où vous augmentez la capacité seulement lorsque vous repérez un manque de capacité.", "<strong>La stratégie \"Match\"</strong>, qui combine les stratégies Lead et Lag, en augmentant petit à petit les ressources jusqu'à coller à la demande.", "<strong>La stratégie \"Adjust\"</strong>, où vous créez des scénarios à partir de la demande et des ressources, puis les comparez pour savoir dans quelles stratégies vous trouvez le plus de rentabilité et d'efficacité opérationnelle."] }, { "type": "paragraph", "text": "Nous vous recommandons d'appliquer la dernière stratégie, qui est la plus ROIste sans porter atteinte à la capacité de production de votre entreprise." }, { "type": "heading", "level": 3, "id": "implementer-votre-capacity-planning", "text": "Implémenter votre Capacity Planning" }, { "type": "paragraph", "text": "Désormais, mettez en place les actions identifiées à l'étape précédente. Implémentez également <strong>un outil qui permet de suivre l'évolution de la demande et de la capacité dans le temps</strong>, pour vous permettre d'ajuster le Capacity Planning au besoin." }, { "type": "paragraph", "text": "Bonne nouvelle : on vous dévoile plus d'informations sur le sujet dans la dernière partie de cet article !" }, { "type": "heading", "level": 3, "id": "suivre-et-ajuster-votre-planning-en-continu", "text": "Suivre et ajuster votre planning en continu" }, { "type": "paragraph", "text": "Une fois votre Capacity Planning créé, il s'agit de savoir s'il génère les résultats escomptés." }, { "type": "paragraph", "text": "Pour cela, suivez les métriques clés de performance permettant de savoir si votre plan capacitaire est efficace, comme :" }, { "type": "list", "ordered": false, "items": ["<strong>Le taux de réalisation des livrables prévus</strong>", "<strong>Le taux d'utilisation de la capacité</strong>", "<strong>Le taux d'achèvement des projets</strong> selon les budgets et les deadlines prévus", "<strong>Le taux d'interruption ou de retard</strong> lié à une mauvaise planification de la capacité", "<strong>Le niveau de satisfaction de vos différents parties prenantes</strong> (collaborateurs et clients) vis-à-vis de votre plan capacitaire"] }, { "type": "paragraph", "text": "Pensez aussi à rassembler régulièrement vos parties prenantes pour faire le point sur la demande ou les ressources - et reprenez ensuite chacune de ces étapes pour une bonne gestion de la capacité de production en continu." }, { "type": "heading", "level": 2, "id": "les-bonnes-pratiques-pour-reussir-votre-capacity-planning", "text": "Les bonnes pratiques pour réussir votre Capacity Planning" }, { "type": "paragraph", "text": "Les étapes précédentes vous donnent une bonne base méthodologique pour créer votre plan capacitaire. Découvrez désormais les bonnes pratiques pour créer un Capacity Planning qui vous permet réellement d'engager les équipes, et de les aligner avec les objectifs stratégiques de l'entreprise." }, { "type": "paragraph", "text": "Si besoin, ces clés de succès (et d'autres !) sont détaillées dans <a href=\"http://www.airsaas.io/fr/gestion-de-projet/planification-de-la-capacite\" target=\"_blank\">notre article sur les bonnes pratiques pour réussir votre planification de la capacité</a>." }, { "type": "heading", "level": 3, "id": "encourager-la-collaboration-inter-equipes", "text": "Encourager la collaboration inter-équipes" }, { "type": "paragraph", "text": "Un Capacity Planning est nécessairement politique - car après tout, prioriser, c'est forcément renoncer (même si ce n'est que provisoirement). Alors votre objectif premier doit être le suivant : faire en sorte que votre Capacity Planning aligne tout le monde autour de la stratégie de l'entreprise." }, { "type": "paragraph", "text": "Pour cela, passez par <strong>un moment collectif pour aligner toutes les parties prenantes</strong> (y compris la direction et les métiers) autour de cette vision, et des priorités qui en découlent en termes de livrables." }, { "type": "paragraph", "text": "Lors de ce moment collectif, chacun peut également repérer les risques et les dépendances entre les différents projets, et réfléchir à la capacité réelle que son équipe peut allouer à chaque projet." }, { "type": "paragraph", "text": "Pour creuser le sujet, découvrez deux méthodologies collaboratives de priorisation et d'organisation :" }, { "type": "list", "ordered": false, "items": ["<a href=\"https://www.airsaas.io/fr/quarter-plan\" target=\"_blank\">Le Quarter Plan</a>", "<a href=\"http://www.airsaas.io/fr/gestion-de-projet/pi-planning\" target=\"_blank\">Le PI Planning</a>"] }, { "type": "paragraph", "text": "Grâce à ces méthodes, vous évitez de disperser votre énergie en réunions en one-to-one, et capitalisez plutôt sur une grande réunion où tout le monde s'aligne. Que du bon !" }, { "type": "inline-cta", "label": "Réservez votre démo de 30 min", "href": "/fr/meetings-pages" }, { "type": "heading", "level": 3, "id": "mettre-en-place-un-capacitaire-sur-une-temporalite-longue", "text": "Mettre en place un capacitaire sur une temporalité longue" }, { "type": "paragraph", "text": "Déployez votre Capacity Planning sur <strong>une période plus longue que la semaine</strong>. Pourquoi ? Parce que cela vous permet d'obtenir un capacitaire approximativement juste plutôt que précisément faux." }, { "type": "paragraph", "text": "En effet, avec la fluctuation de la demande et de la capacité, un capacitaire à l'échelle d'une semaine devient vite faux, et doit être révisé non-stop." }, { "type": "paragraph", "text": "Avec un Capacity Planning à l'échelle d'un trimestre, d'un semestre ou d'un PI, vous vous alignez avec la réalité du travail que les équipes doivent fournir." }, { "type": "paragraph", "text": "Qui plus est, le fait d'organiser votre portfolio de projets sur une temporalité plus longue crée une pression positive. Les équipes font en sorte de finir leurs livrables avant la fin de la période, et de bien cadrer en amont les besoins qu'ils auront pour celle à venir." }, { "type": "paragraph", "text": "Sans compter le fait que vous supprimez bien des réunions inutiles : il suffit d'une réunion tous les mois, et non plus d'une (pénible) réunion hebdomadaire, pour que tout le monde puisse se focaliser sur \"le faire\" et non plus sur \"se réunir\"." }, { "type": "paragraph", "text": "Et bien entendu, cela ne vous empêche pas, ensuite, de décliner des agendas à la tâche et à l'échelle d'une semaine pour chaque équipe." }, { "type": "heading", "level": 3, "id": "estimer-le-temps-necessaire-au-livrable-plutot-qua-la-tache", "text": "Estimer le temps nécessaire au livrable plutôt qu'à la tâche" }, { "type": "paragraph", "text": "En établissant un Capacity Planning, il est fréquent de se perdre dans le détail des micro-tâches… qui, en fait, devraient relever de la gestion de projet de chaque équipe !" }, { "type": "paragraph", "text": "Pour éviter cela, adoptez une approche pragmatique, et concevez <strong>un capacitaire au livrable, et non à la tâche</strong>. Face à ce Capacity Planning, chaque chef de projet gère ensuite son propre découpage des tâches - et vous continuez à piloter votre portefeuille de projet de manière macro." }, { "type": "heading", "level": 3, "id": "penser-a-la-maille-de-lequipe-plutot-qua-la-personne", "text": "Penser à la maille de l'équipe plutôt qu'à la personne" }, { "type": "paragraph", "text": "À l'échelle d'une (petite) équipe, et sur une période plutôt courte, un Capacity Planning conçu à la maille des individus peut fonctionner. Mais si vous souhaitez définir un capacitaire à l'échelle de votre organisation, vous vous retrouverez rapidement à vous arracher les cheveux…" }, { "type": "paragraph", "text": "Privilégiez donc <strong>un capacitaire qui prend en compte la capacité par équipe, et non par individu</strong>. Cela vous permet de vous focaliser sur ce qui compte réellement dans le portfolio project management, à savoir : le build." }, { "type": "paragraph", "text": "Attention : par équipe, ici, on entend \"un rassemblement de compétences homogènes\". Par exemple, vous pouvez choisir de segmenter en plusieurs groupes de compétences l'équipe IT, en séparant l'IT Sécurité, l'IT Data et l'IT Intégration. Pour le pôle marketing, vous pouvez segmenter les ressources entre équipe marketing Content, équipe marketing CRM, et les autres marketeurs." }, { "type": "paragraph", "text": "Grâce à ce conseil, votre Capacity Planning devient plus souple, et permet à chacune des équipes d'adapter sa charge de travail au planning prévu." }, { "type": "heading", "level": 3, "id": "rester-flexible", "text": "Rester flexible" }, { "type": "paragraph", "text": "Prévoyez dans votre Capacity Planning <strong>des marges qui permettent de faire face aux imprévus</strong> que toute entreprise rencontre - parce qu'un projet ne se déroule presque jamais comme on le prévoit !" }, { "type": "paragraph", "text": "Adoptez donc une approche itérative, en convoquant régulièrement vos parties prenantes pour faire le point sur votre Capacity Planning. Là encore, c'est ce que permettent de faire les méthodes du Quarter Plan et du PI Planning, à adapter à votre organisation." }, { "type": "heading", "level": 2, "id": "quels-outils-pour-mettre-en-place-votre-capacity-planning", "text": "Quels outils pour mettre en place votre Capacity Planning ?" }, { "type": "paragraph", "text": "Si vous avez déjà mis en place un Capacity Planning, vous savez à quel point s'appuyer uniquement sur un tableau Excel peut rapidement devenir ingérable. Un bon pilotage nécessite un outil collaboratif, capable de s'adapter aux fluctuations de la demande et aux variations des ressources en temps réel." }, { "type": "paragraph", "text": "C'est précisément pour accompagner les DSI, PMO et chefs de projet dans la gestion de leur capacité de production que nous avons développé la fonctionnalité Capacity Planning d'Airsaas." }, { "type": "paragraph", "text": "Avec Airsaas, vous construisez une <strong>vue Capacitaire</strong> par équipe sur la période de votre choix : trimestre, semestre ou PI. Cette approche vous permet de vous concentrer sur le build réel de l'entreprise. Chaque équipe renseigne directement dans Airsaas les ressources disponibles pour contribuer aux projets en cours." }, { "type": "paragraph", "text": "Ensuite, il vous suffit de simuler différents scénarios pour ajuster l'allocation des ressources en fonction des priorités stratégiques. Grâce à la vue Capacitaire, vous identifiez instantanément les points de blocage et les besoins en ressources supplémentaires." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02737c3f7b9a4eb992582_capacitaire-airsaas.png", "alt": "" }, { "type": "paragraph", "text": "Ne perdez plus un temps précieux sur des suivis complexes et chronophages : adoptez un Capacity Planning efficace et pragmatique avec Airsaas !" }, { "type": "paragraph", "text": "Vous voilà armé de toutes les étapes et bonnes pratiques pour construire votre Capacity Planning. <a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">Demandez une démo Airsaas dès aujourd'hui</a>, et rendez cette tâche simple et collaborative, pour une gestion de la capacité vraiment alignée avec votre stratégie d'entreprise." }], "toc": [{ "label": "Qu'est-ce que le Capacity Planning ?", "href": "#quest-ce-que-le-capacity-planning", "level": 2 }, { "label": "Les 7 bénéfices d'un Capacity Planning bien ficelé", "href": "#les-7-benefices-dun-capacity-planning-bien-ficele", "level": 2 }, { "label": "Les étapes pour créer votre plan capacitaire", "href": "#les-etapes-pour-creer-votre-plan-capacitaire", "level": 2 }, { "label": "Les bonnes pratiques pour réussir votre Capacity Planning", "href": "#les-bonnes-pratiques-pour-reussir-votre-capacity-planning", "level": 2 }, { "label": "Quels outils pour mettre en place votre Capacity Planning ?", "href": "#quels-outils-pour-mettre-en-place-votre-capacity-planning", "level": 2 }], "faq": [], "related": [] }, { "slug": "capacity-planning-definition", "skip": false, "meta": { "title": "Capacity Planning : définition et principes de base", "h1": "Capacity Planning : définition et principes de base", "description": "Découvrez une définition claire du Capacity Planning ainsi que ses principes de base pour assurer une gestion de la capacité de vos ressources.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae454a72a221a5dbcbce7_Capacity%20planning.jpg", "alt": "" }, "author": { "category": "Gestion de projets" } }, "blocks": [{ "type": "paragraph", "text": "En tant que DSI ou PMO, vous jonglez au quotidien avec un large portefeuille de projets, dans lequel vous devez gérer à la fois les projets en cours, mais aussi les demandes entrantes." }, { "type": "paragraph", "text": "Seulement, vous avez beau planifier au maximum les ressources disponibles, prioriser les différents projets, aligner les équipes… la demande ne cesse d'affluer, et tout votre planning finit par partir à vau-l'eau." }, { "type": "paragraph", "text": "Et si l'une des réponses à ce défi quotidien tenait en deux mots : Capacity Planning ?" }, { "type": "paragraph", "text": "Dans cet article, découvrez <strong>une définition claire d'un Capacity Planning, ainsi que ses principes de base</strong> pour commencer à assurer une gestion de la capacité de vos ressources aux petits oignons." }, { "type": "heading", "level": 2, "id": "capacity-planning-definition-et-concepts-cles", "text": "Capacity Planning : définition et concepts clés" }, { "type": "paragraph", "text": "La définition d'un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning\" target=\"_blank\">Capacity Planning</a> est simple. Il s'agit d'<strong>une méthode pour évaluer, planifier et gérer les ressources nécessaires pour répondre aux besoins d'une organisation</strong>, sur une période de temps donnée à venir. En français, on parle aussi de gestion de la capacité, ou bien de gestion capacitaire." }, { "type": "paragraph", "text": "L'objectif principal du Capacity Planning est d'<strong>aligner la capacité disponible dans l'entreprise avec la demande récoltée</strong>. Grâce à cette démarche, vous priorisez vos projets de manière stratégique, en lançant les bonnes initiatives, au bon moment, et avec les bonnes ressources." }, { "type": "paragraph", "text": "Ainsi, avec un Capacity Planning bien ficelé, vous pouvez répondre à des questions comme :" }, { "type": "list", "ordered": false, "items": ["Pourrait-on faire plus de projets le prochain trimestre ?", "Doit-on recruter ?", "Quelle surcharge acceptons-nous d'avoir ?"] }, { "type": "paragraph", "text": "En ce sens, cette méthode est idéale pour les organisations qui doivent gérer un large portefeuille de projets, et qui doivent trouver <strong>l'équilibre entre la stratégie de l'entreprise et la réalité de ce qu'elle peut réaliser</strong> sur un temps donné. La bonne nouvelle : il est possible de faire un Capacity Planning pour n'importe quel secteur d'activité - informatique, retail, industrie…  ou n'importe quel type de projet : projet IT, projet de déménagement de siège, implémentation d'un nouveau processus RH…" }, { "type": "paragraph", "text": "Chez Airsaas, on se focalise généralement sur les ressources humaines - soit l'élément le plus complexe à gérer dans un plan capacitaire, à l'heure où la majorité des projets de transformation d'entreprise sont transverses." }, { "type": "heading", "level": 2, "id": "pourquoi-le-capacity-planning-est-il-interessant-pour-votre-entreprise", "text": "Pourquoi le Capacity Planning est-il intéressant pour votre entreprise ?" }, { "type": "heading", "level": 3, "id": "pour-optimiser-vos-ressources", "text": "Pour optimiser vos ressources" }, { "type": "paragraph", "text": "Grâce à un Capacity Planning, vous effectuez une meilleure affectation de vos ressources disponibles en fonction des priorités de l'entreprise, et évitez ainsi le gaspillage." }, { "type": "heading", "level": 3, "id": "pour-donner-plus-de-chances-a-vos-projets-de-reussir", "text": "Pour donner plus de chances à vos projets de réussir" }, { "type": "paragraph", "text": "Combien de projets avez-vous déjà dû abandonner, combien de projets glissent de mois en mois faute de ressources suffisantes, ou d'une bonne priorisation des initiatives ? Votre Capacity Planning vous permet d'obtenir une vision globale des ressources sur la période à venir, ce qui permet de limiter les retards sur vos projets." }, { "type": "heading", "level": 3, "id": "pour-vous-preparer-aux-variations-de-la-demande-ou-aux-imprevus", "text": "Pour vous préparer aux variations de la demande ou aux imprévus" }, { "type": "paragraph", "text": "En prévoyant les charges de travail des équipes, vous pouvez anticiper les goulots d'étranglements ou, a contrario, les besoins en recrutement ou en externalisation dont vous pourriez avoir besoin pour faire avancer vos projets." }, { "type": "heading", "level": 3, "id": "pour-un-meilleur-alignement-avec-la-strategie-de-lentreprise", "text": "Pour un meilleur alignement avec la stratégie de l'entreprise" }, { "type": "paragraph", "text": "Pour concevoir un Capacity Planning qui tient la route, vous devez nécessairement prioriser les ressources à attribuer aux différents projets. Cette méthodologie vous invite à prioriser l'avancement des projets en fonction des objectifs stratégiques de votre entreprise - votre direction va adorer !" }, { "type": "heading", "level": 3, "id": "pour-optimiser-vos-couts", "text": "Pour optimiser vos coûts" }, { "type": "paragraph", "text": "Votre Capacity Planning permet de prévoir quel budget doit être alloué à chaque projet ou chaque équipe, et donc, d'anticiper les coûts à prévoir. À vous une meilleure gestion budgétaire globale." }, { "type": "heading", "level": 3, "id": "pour-ameliorer-la-productivite-et-de-la-rentabilite-de-vos-equipes", "text": "Pour améliorer la productivité et de la rentabilité de vos équipes" }, { "type": "paragraph", "text": "Conséquence de tous les bénéfices précédents : mieux anticiper permet de mieux répartir les tâches et les livrables à réaliser, et donc, d'optimiser la productivité de chacun." }, { "type": "heading", "level": 3, "id": "pour-ameliorer-les-relations-entre-vos-parties-prenantes", "text": "Pour améliorer les relations entre vos parties prenantes" }, { "type": "paragraph", "text": "Grâce à votre Capacity Planning, toutes vos parties prenantes, depuis la direction jusqu'aux collaborateurs dans toutes les équipes, sont plus satisfaits de votre manière de gérer les projets." }, { "type": "paragraph", "text": "D'un côté, vous améliorez votre gestion des compétences, en attribuant les bonnes tâches aux bonnes ressources. Résultat : les équipes ne font plus face à une surcharge de travail, et sont plus valorisées selon leurs compétences réelles. De quoi faire fleurir votre satisfaction collaborateur." }, { "type": "paragraph", "text": "De l'autre côté (celui des clients finaux), vous livrez le produit ou le service attendu dans les meilleurs délais. Et vu qu'il est produit avec les meilleures ressources disponibles, sa qualité est optimale." }, { "type": "paragraph", "text": "Et côté équipes IT, fini le harcèlement régulier pour lancer ce projet, si important pour les métiers, que vous devez toujours remettre au lendemain faute d'avoir pu le prioriser dans la roadmap !" }, { "type": "paragraph", "text": "Vous connaissez désormais la définition du Capacity Planning, et ses bénéfices. Alors, par où commencer pour le déployer dans votre entreprise ?" }, { "type": "heading", "level": 2, "id": "les-principes-de-base-du-capacity-planning", "text": "Les principes de base du Capacity Planning" }, { "type": "heading", "level": 3, "id": "evaluer-la-capacite-actuelle", "text": "Évaluer la capacité actuelle" }, { "type": "paragraph", "text": "Tout d'abord, il vous faut repérer la capacité actuelle de votre entreprise en matière de compétences humaines, de bande passante à accorder aux projets." }, { "type": "paragraph", "text": "Cette étape vous demande d'avoir <strong>une vision précise de l'utilisation actuelle de ces ressources</strong>, sur les projets planifiés ou en cours, ainsi que sur le travail quotidien en dehors de ses projets." }, { "type": "paragraph", "text": "En faisant votre Capacity Planning, vous remarquerez rapidement que l'élément le plus complexe à gérer est l'estimation de la charge de travail disponible pour chaque individu, et donc, le temps qu'il pourra passer sur les projets." }, { "type": "paragraph", "text": "Quand vous analysez la bande passante de votre équipe, identifiez les tâches récurrentes de chacun et regroupez-les en blocs de temps dédiés, comme des demi-journées. Cette approche permet de concentrer l'effort et d'améliorer l'efficacité, plutôt que de simplement répartir les tâches au fil de l'eau, ou de gérer en pourcentage de disponibilité." }, { "type": "paragraph", "text": "À cette étape, vous pouvez également repérer les goulots d'étranglement déjà présents dans les projets, que le Capacity Planning permettra de solutionner." }, { "type": "heading", "level": 3, "id": "prevoir-la-demande-future", "text": "Prévoir la demande future" }, { "type": "paragraph", "text": "Dans un second temps, l'objectif est d'<strong>identifier les projets qui ont besoin de ressources à l'avenir</strong>, sur une période donnée, et d'estimer les ressources qui doivent y être dédiées." }, { "type": "paragraph", "text": "Pour ce faire, basez-vous sur la vision de la stratégie d'entreprise globale, des projets qui sont en cours de cadrage ou au stade de discussion. Cette vision guide la priorisation des projets dans votre portefeuille : c'est donc elle qui justifie que vous passiez en priorité telles ou telles ressources sur tel ou tel projet. On le sait :  c'est plus simple à dire qu'à faire, mais c'est l'objectif !" }, { "type": "paragraph", "text": "Les données historiques sur les projets passés sont souvent difficiles à obtenir (sauf si vous avez déjà mis Airsaas en place, bien sûr). Mais un point clé pour un bon Capacity Planning est d'analyser le rythme global de l'organisation et celui de chaque domaine spécifique – RH, finance, IT, opérations, etc." }, { "type": "paragraph", "text": "Chaque fonction a des cycles et des contraintes qui influencent directement le temps disponible pour les projets. Par exemple :" }, { "type": "list", "ordered": false, "items": ["<strong>RH</strong> : des périodes intenses lors des campagnes de recrutement ou des évaluations annuelles.", "<strong>Finance</strong> : une forte mobilisation en fin de trimestre et lors des clôtures comptables.", "<strong>IT</strong> : des pics d'activité lors des mises en production ou des audits de sécurité."] }, { "type": "paragraph", "text": "Si vous ne prenez pas en compte ces rythmes naturels, vous risquez d'attribuer des charges irréalistes aux équipes, entraînant des retards et une perte d'efficacité. En comprenant ces variations, vous pouvez mieux anticiper la disponibilité réelle et planifier les projets en conséquence." }, { "type": "paragraph", "text": "Pour creuser le sujet, rendez-vous sur <a href=\"https://www.airsaas.io/fr/gestion-de-projet/planification-de-la-demande-capacity-planning\" target=\"_blank\">notre article \"Planification de la demande et Capacity Planning : quelles différences ?\"</a>." }, { "type": "heading", "level": 3, "id": "aligner-capacite-et-demande", "text": "Aligner capacité et demande" }, { "type": "paragraph", "text": "À cette étape, vous arrivez dans le gros du Capacity Planning : vous devez <strong>aligner la capacité et la demande en fonction des objectifs stratégiques</strong> de votre organisation." }, { "type": "paragraph", "text": "Pour cela, vous disposez de plusieurs stratégies dans votre arsenal :" }, { "type": "list", "ordered": false, "items": ["<strong>Augmenter la capacité</strong>, en identifiant les ressources à venir ou nécessaires à rajouter. Prévoyez des recrutements en plus, ou bien pensez à faire monter en compétences certains collaborateurs sur un sujet dont vous pourriez avoir besoin dans la période à venir", "<strong>Ajuster la demande</strong>, en priorisant des projets dans le temps, en fonction de leur impact stratégique sur l'organisation.", "<strong>Ajuster la capacité et la demande sur-mesure</strong>, en fonction des projets prioritaires et des compétences à votre disposition."] }, { "type": "paragraph", "text": "Quoi qu'il en soit, dans le cadre d'un portefeuille de projet très large, soyez prêt : cet alignement entre capacité et demande va souvent nécessiter une négociation avec les métiers et la direction.  La bonne pratique : aligner tout le monde sur les priorités à établir, grâce à des méthodologies comme le <a href=\"http://www.airsaas.io/fr/gestion-de-projet/pi-planning\" target=\"_blank\">PI Planning</a> ou le <a href=\"https://www.airsaas.io/fr/quarter-plan\" target=\"_blank\">Quarter Plan</a>." }, { "type": "paragraph", "text": "Ces méthodes demandent de passer d'une planification sur un temps court (à la semaine ou au mois) à une projection sur un temps plus long, comme le trimestre, le semestre ou le Program Increment (PI). Ce faisant, vous vous assurez que vous créez un capacitaire adapté à l'échelle de votre organisation et à la transversalité de vos projets." }, { "type": "paragraph", "text": "Et rappelez-vous que tout l'art du Capacity Planning repose dans le fait de mettre en place une planification flexible ET synchrone, qui peut s'adapter aux changements organisationnels ou stratégiques. Un gros défi, mais dont le jeu en vaut la chandelle !" }, { "type": "paragraph", "text": "Pour aller plus loin, <a href=\"http://www.airsaas.io/fr/gestion-de-projet/plan-capacitaire\" target=\"_blank\">découvrez les étapes clés pour créer votre plan capacitaire</a>." }, { "type": "inline-cta", "label": "Réservez votre démo de 30 min", "href": "/fr/meetings-pages" }, { "type": "heading", "level": 3, "id": "suivre-et-ajuster-en-continu", "text": "Suivre et ajuster en continu" }, { "type": "paragraph", "text": "Une fois votre Capacity Planning établi, il ne s'agit pas de le laisser tel quel. Avec la variation de la demande, et les ressources disponibles qui fluctuent, votre capacitaire va nécessairement évoluer au cours du temps. D'où l'intérêt de le suivre et de l'ajuster de manière continue." }, { "type": "paragraph", "text": "Tout d'abord, utilisez des indicateurs clés de performance (KPI) pour évaluer l'efficacité du Capacity Planning, comme :" }, { "type": "list", "ordered": false, "items": ["<strong>Le taux d'avancement du Quarter Plan</strong>", "<strong>Le taux d'achèvement des projets</strong> dans les délais et budgets prévus", "<strong>Le taux d'interruption ou de retard</strong> sur les projets lié à une mauvaise planification de la capacité", "<strong>Le niveau de satisfaction des parties prenantes</strong> (collaborateurs et clients) vis-à-vis du Capacity Planning"] }, { "type": "paragraph", "text": "En parallèle, mettez en place des points de contrôle réguliers pour ajuster la gestion de la demande et le plan capacitaire au fil du temps." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c0254d7662945f0bda0459_culture-capacity-planning.png", "alt": "" }, { "type": "paragraph", "text": "Et pour un Capacity Planning couronné de succès, <a href=\"http://www.airsaas.io/fr/gestion-de-projet/planification-de-la-capacite\" target=\"_blank\">appliquez nos bonnes pratiques pour réussir votre planification de la capacité</a>." }, { "type": "heading", "level": 2, "id": "quels-outils-pour-faire-votre-capacity-planning", "text": "Quels outils pour faire votre Capacity Planning ?" }, { "type": "paragraph", "text": "Mettre en place un capacitaire est bien souvent une démarche lourde et chronophage. Bon nombre d'entreprises le font sur un tableur Excel, qu'il est généralement impossible de maintenir dans le temps par la suite." }, { "type": "paragraph", "text": "Alors faut-il totalement abandonner l'idée d'avoir un plan capacitaire vraiment efficace ?" }, { "type": "paragraph", "text": "Pas vraiment. Pour répondre à cette problématique, chez Airsaas, nous avons un parti pris : <strong>nous préférons avoir un capacitaire approximativement juste plutôt que précisément faux</strong>. Et c'est pour mettre en musique ce parti pris que nous avons développé une plateforme de Capacity Planning par équipe." }, { "type": "paragraph", "text": "Grâce à Airsaas :" }, { "type": "list", "ordered": false, "items": ["<strong>Vous estimez le temps nécessaire au livrable, et non à la tâche</strong>. L'estimation de la charge de travail se fait sous forme de t-shirt sizing, pour éviter de rentrer dans le détail micro- et donc, simplifier votre Capacity Planning.", "<strong>Vous anticipez les temps nécessaires et disponibles par équipe</strong>. Ainsi, vous évitez de vous projeter à l'échelle de la personne, et vous vous basez plutôt sur l'échelle de l'équipe, pour vous projeter réellement sur le build.", "<strong>Vous mettez en place d'un capacitaire au trimestre, au semestre, ou au PI</strong>. Cette méthodologie vous permet de vous aligner sur des échelles de temps qui représentent la réalité du travail à fournir - qui ne se fait souvent pas à l'échelle d'une semaine, mais plutôt sur un temps plus long."] }, { "type": "paragraph", "text": "Sur la plateforme Airsaas, la vue Capacitaire est simple et actionnable. Elle vous aide à savoir quelle est la capacité dans chaque équipe, quels livrables plombent l'avancement de vos projets, et quels sont vos besoins en ressources supplémentaires." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02737c3f7b9a4eb992582_capacitaire-airsaas.png", "alt": "" }, { "type": "paragraph", "text": "Résultat : vous mettez en place un capacitaire pragmatique, au niveau macro, qui permet de prioriser avec le Top Management les projets à lancer ou non. Ce qui ne vous empêche pas, en parallèle, une fois vos projets organisés dans le temps, de produire un capacitaire à la personne sur 2 à 3 mois maximum… que vous pourrez vraiment tenir !" }, { "type": "paragraph", "text": "De quoi prendre de meilleures décisions en termes de priorisation et de planification de la capacité." }, { "type": "paragraph", "text": "Intéressé par la solution Capacity Planning par équipes d'Airsaas ? <a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">Demandez une démo dès aujourd'hui</a>, et rationalisez votre gestion de portefeuille de projet tout en créant l'engagement dans vos équipes." }], "toc": [{ "label": "Capacity Planning : définition et concepts clés", "href": "#capacity-planning-definition-et-concepts-cles", "level": 2 }, { "label": "Pourquoi le Capacity Planning est-il intéressant pour votre entreprise ?", "href": "#pourquoi-le-capacity-planning-est-il-interessant-pour-votre-entreprise", "level": 2 }, { "label": "Les principes de base du Capacity Planning", "href": "#les-principes-de-base-du-capacity-planning", "level": 2 }, { "label": "Quels outils pour faire votre Capacity Planning ?", "href": "#quels-outils-pour-faire-votre-capacity-planning", "level": 2 }], "faq": [], "related": [] }, { "slug": "chef-de-projet-pmo", "skip": false, "meta": { "title": "La relation du PMO avec le chef de projet", "h1": "La relation du PMO avec le chef de projet", "description": "Focus sur les responsabilités du chef de projet et du PMO, et les liens qui existent entre ces deux acteurs de la transformation d'une entreprise.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6449317d4dfb52ce6009acca_La%20relation%20du%20PMO%20avec%20le%20chef%20de%20projet-min.jpg", "alt": "La relation du PMO avec le chef de projet" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "26/4/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "26/4/2023" }, "blocks": [{ "type": "paragraph", "text": "Le PMO dans une organisation exerce une fonction de structuration et d'assistance dans la réalisation des projets. Ses fonctions sont peu connues, rendant parfois compliquée la relation qu'il a avec le chef de projet." }, { "type": "paragraph", "text": "Cette méconnaissance de l'importance du PMO amène des fois à se poser des questions sur son utilité, déjà que le chef de projet est présent." }, { "type": "paragraph", "text": "Focus ici sur les responsabilités du chef de projet et du PMO, et les liens qui existent entre ces deux acteurs de la transformation d'une entreprise." }, { "type": "heading", "level": 2, "id": "qui-est-le-pmo", "text": "Qui est le PMO ?" }, { "type": "paragraph", "text": "L'adoption des <a href=\"https://blog-gestion-de-projet.com/gestion-de-projet/outils-methodes-gestion-projet/\">méthodologies de gestion de projet</a> a mis en lumière le rôle de Project Management Office. Au sein de l'entreprise, le PMO est la structure ou la personne chargée de coordonner les différents projets pour qu'ils soient en adéquation avec la stratégie de l'entreprise." }, { "type": "paragraph", "text": "Par exemple, lorsqu'une organisation désire réduire son empreinte carbone, elle s'appuiera sur une personne ou une structure en interne qui s'assurera que tous les projets initiés ou dirigés par l'organisation seront en concordance avec les exigences du programme écologique. Dans ce cas, le PMO facilitera le partage des ressources, des outils, des méthodes et des techniques afin de faire aligner les projets sur cet objectif spécifique de l'organisation." }, { "type": "paragraph", "text": "Il existe plusieurs types de PMO qui ont des rôles et des responsabilités différents." }, { "type": "paragraph", "text": "On peut retrouver dans une entreprise ou dans une organisation un EPMO. L'objectif de celui-ci est de faire aligner tous les programmes ou projets de l'entreprise avec les objectifs de ce dernier en mettant en place la bonne gouvernance. Dans l'exemple qu'on vient d'aborder, il a un rôle d'appui stratégique." }, { "type": "paragraph", "text": "Mais on peut également retrouver un PMO au sein d'un département ou d'un portefeuille. Concrètement, un département comme la logistique ou les approvisionnements peut disposer en son sein d'un PMO qui apportera son soutien aux services du département. Il sera donc le vecteur de l'entreprise pour faire passer les objectifs de cette dernière dans les projets que le département gère." }, { "type": "paragraph", "text": "Enfin, on peut retrouver le Project Management Office qui vient en soutien à l'équipe projet. Sur le projet, il accompagne directement le chef projet dans l'établissement de ses processus. C'est ainsi celui qui prend en charge la conformité des documents et process du projet." }, { "type": "heading", "level": 3, "id": "quel-est-le-role-du-pmo", "text": "Quel est le rôle du PMO ?" }, { "type": "paragraph", "text": "Le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/etre-pmo-en-2023-les-mutations-dun-metier\" target=\"_blank\">PMO</a> peut être positionné à divers niveaux hiérarchiques au sein de l'organisation. Pour autant, il dispose toujours d'une vision transversale des projets et des portefeuilles de l'entreprise ou de l'organisation et a une position stratégique en son sein." }, { "type": "paragraph", "text": "Dans le monde du travail, le rôle et les responsabilités du PMO sont peu vulgarisés. En conséquence, on perçoit mal l'utilité d'un PMO au sein de l'organisation." }, { "type": "paragraph", "text": "La mission du PMO est de garantir un alignement opérationnel et économique des projets avec les objectifs de l'entreprise ou de l'organisation. Il exerce une fonction de structuration et d'assistance dans la réalisation des différents projets." }, { "type": "paragraph", "text": "Sa position l'oblige aussi à coordonner les projets pour, s'il le faut, prioriser les uns sur les autres en accord avec les objectifs et les engagements présents et futurs de l'organisation. C'est également son devoir d'accompagner au mieux les équipes métiers pour qu'elles puissent satisfaire au mieux la vision de l'organisation." }, { "type": "paragraph", "text": "Enfin, par sa fonction de diffusion de la bonne gouvernance à travers la méthodologie de gestion de projets, il devient le garant de la ventilation des règles, modèles de documents, manuels de procédures, processus, etc." }, { "type": "heading", "level": 2, "id": "quelles-differences-entre-chef-de-projet-et-pmo", "text": "Quelles différences entre chef de projet et PMO ?" }, { "type": "paragraph", "text": "Vous l'aurez peut-être déjà compris : là où le PMO gère l'ensemble de la chefferie de projet de l'entreprise (en étant responsable des processus et des méthodologies mises en place), le chef de projet se charge d'organiser les différentes phases d'un projet (ou de plusieurs projets) en particulier." }, { "type": "paragraph", "text": "Dans la plupart des entreprises, il n'existe pas de lien de hiérarchique entre chef de projet et PMO. Cependant, on demande souvent au PMO d'avoir une vision macro du travail des différents chefs de projets de l'organisation. Il doit superviser et contrôler le portefeuille projet, gérer les budgets, et allouer les différentes ressources nécessaires pour que chaque chef de projet puisse se focaliser sur les aspects opérationnels de son rôle." }, { "type": "heading", "level": 2, "id": "pourquoi-se-doter-dun-pmo-en-presence-dun-chef-de-projet", "text": "Pourquoi se doter d'un PMO en présence d'un chef de projet ?" }, { "type": "paragraph", "text": "Le PMO est confronté à certains enjeux. L'un de ces enjeux est de parvenir à lever les obstacles et les oppositions qu'il rencontre en entreprise. Beaucoup sont persuadés que recruter un PMO alors que le chef de projet est déjà là est une dilapidation des ressources de l'organisation." }, { "type": "paragraph", "text": "Or, dans une organisation, il faut une personne ou une structure capable d'avoir le recul nécessaire et la vue d'ensemble qu'il faut pour aligner les projets à la stratégie de l'organisation. De plus, le PMO est le garant de la bonne gouvernance. En ce sens, il ventile les processus validés qui pourront garantir à tout le monde le bon fonctionnement des projets." }, { "type": "paragraph", "text": "Le PMO est aussi une plus-value dans la gestion de projet par sa capacité à apporter une meilleure maîtrise des délais et du budget. Il met ainsi en place des indicateurs clés de performance qu'il suit pour s'assurer de la bonne santé des projets. Parce qu'au niveau de l'organisation, selon les responsabilités qui lui sont attribuées, c'est lui le garant de la bonne marche des projets et de l'équilibre entre la qualité, les délais et les coûts." }, { "type": "paragraph", "text": "Bien souvent, le chef de projet n'a pas la vue d'ensemble du PMO, c'est pour cela que ce dernier doit être présent. Qui d'autre mieux que lui pourra faire le suivi des changements internes (fusions, réorganisations, acquisitions, initiatives stratégiques,…) et le suivi des nouvelles opportunités afin de connaître les meilleurs outils et processus ? Qui est plus habilité que le PMO pour traiter les demandes externes au projet et découvrir les besoins de nouvelles compétences ou de nouveaux processus ?" }, { "type": "paragraph", "text": "Par ailleurs, bien que le chef de projet soit présent, l'organisation peut décider d'établir un PMO. Plusieurs raisons peuvent être à la base de ce choix stratégique :" }, { "type": "list", "ordered": false, "items": ["Changement de process et besoin d'accompagnement du changement,", "Une nouvelle organisation interne,", "Une nouvelle gouvernance axée sur une communication claire et des responsabilités bien définies,", "Un établissement et une gestion du respect des normes,", "Une charge de travail des chefs de projet assez élevée entraînant un besoin d'accompagnement et de structuration sur la gestion des projets,", "Un examen et une gestion des risques,", "Une mise en place de nouveaux outils, de reportings réguliers ou de plannings complexes."] }, { "type": "paragraph", "text": "En résumé, les objectifs du PMO peuvent coïncider avec ceux d'un chef de projet. C'est notamment le cas lorsque les deux cherchent à bien mener les projets dans le respect des délais et des coûts impartis. C'est aussi le cas lorsqu'ils doivent remonter les KPI de suivi et le taux d'avancement ou encore leur obligation de respecter et d'intégrer les process." }, { "type": "paragraph", "text": "Toutefois, là où le chef de projet cherchera à suivre l'atteinte des objectifs de manière concrète sur le terrain, le PMO devra s'assurer que les projets suivent bien la stratégie de l'entreprise. Il se donne un peu plus de recul et joue un rôle d'harmonisation. Cela lui permet d'être le coach des chefs de projets pour être à leur côté et les aider." }, { "type": "paragraph", "text": "Et cela marche puisqu'une récente étude menée en France a démontré qu'avec un PMO, les projets reviennent moins chers, sont mieux alignés sur la stratégie de l'entreprise, réussissent plus souvent et plus rapidement. D'un autre côté, les clients sont plus satisfaits par la productivité, la gouvernance et la communication." }, { "type": "paragraph", "text": "Pour creuser le sujet, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pourquoi-mettre-en-place-un-pmo\" target=\"_blank\">rendez-vous sur notre article \"Pourquoi mettre en place un PMO ?\"</a>" }, { "type": "heading", "level": 2, "id": "quelles-interactions-entre-le-pmo-et-le-chef-de-projet", "text": "Quelles interactions entre le PMO et le chef de projet ?" }, { "type": "paragraph", "text": "Entre le PMO et les différents chefs de projet, doit exister une communication claire et permanente. Le PMO est censé être le chef d'orchestre. Il œuvre donc en synergie avec les chefs de projet pour contrôler la cohérence des projets et accompagner les chefs de projet dans le bon déroulement des projets." }, { "type": "paragraph", "text": "Le rôle du PMO n'est pas figé et peut varier d'une structure à une autre. Aussi, les interactions peuvent légèrement varier selon le type de PMO dont dispose l'organisation. Cette dernière peut également décider de faire évoluer son PMO en fonction de ses besoins." }, { "type": "paragraph", "text": "Pour aller plus loin, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-mettre-en-place-un-pmo\" target=\"_blank\">consultez nos bonnes pratiques sur comment mettre en place un PMO</a>." }, { "type": "heading", "level": 2, "id": "quels-softs-skills-pour-gerer-sa-relation-avec-le-chef-de-projet", "text": "Quels softs skills pour gérer sa relation avec le chef de projet ?" }, { "type": "paragraph", "text": "Au sein de l'organisation, le PMO a certaines responsabilités. C'est pour cela qu'un bon PMO doit développer certaines aptitudes bien précises afin de mener à bien sa mission :" }, { "type": "list", "ordered": false, "items": ["Une communication claire et efficace : pour éviter les confusions et les perceptions erronées qui peuvent coûter cher au projet,", "Une vision large : pour ne pas perdre de vue l'objectif du projet,", "Une organisation systématique : pour pouvoir structurer les informations et rester efficace,", "Une bonne maîtrise de soi : pour rester calme, prendre des décisions rationnelles sans se laisser submerger par les émotions ou les circonstances,", "Un esprit critique : afin d'analyser objectivement les informations reçues et les faits reportés,", "Une capacité à être factuel et à relever les incohérences à temps,", "Une bonne diplomatie pour gérer les conflits et désamorcer les situations compliquées en tête-à-tête,", "L'intuition : ce sixième sens permet d'être attentif et alerte face aux incohérences afin de prendre des décisions en se basant parfois sur son intime conviction,", "Le courage : nécessaire pour faire des choix cornéliens ou recadrer les collaborateurs si nécessaire."] }, { "type": "heading", "level": 2, "id": "conclusion", "text": "Conclusion" }, { "type": "paragraph", "text": "Il est désormais acquis que le PMO a un grand rôle à jouer dans l'implémentation de la méthodologie de gestion de projets au sein des organisations. Sa coordination des projets avec la stratégie de l'organisation est capitale." }, { "type": "paragraph", "text": "Même si ses fonctions sont encore peu connues si l'on effectue une petite comparaison avec les modèles anglo-saxons, la tendance va vers une généralisation du rôle du PMO dans les organisations." }, { "type": "paragraph", "text": "Cela augure d'une meilleure efficacité des projets et d'une meilleure satisfaction de toutes les parties prenantes. Mieux, cela permettra d'améliorer les relations entre le PMO et les chefs de projet ; deux postes aux compétences techniques similaires, mais qui ne sont nullement en concurrence." }], "toc": [{ "label": "Qui est le PMO ?", "href": "#qui-est-le-pmo", "level": 2 }, { "label": "Quelles différences entre chef de projet et PMO ?", "href": "#quelles-differences-entre-chef-de-projet-et-pmo", "level": 2 }, { "label": "Pourquoi se doter d'un PMO en présence d'un chef de projet ?", "href": "#pourquoi-se-doter-dun-pmo-en-presence-dun-chef-de-projet", "level": 2 }, { "label": "Quelles interactions entre le PMO et le chef de projet ?", "href": "#quelles-interactions-entre-le-pmo-et-le-chef-de-projet", "level": 2 }, { "label": "Quels softs skills pour gérer sa relation avec le chef de projet ?", "href": "#quels-softs-skills-pour-gerer-sa-relation-avec-le-chef-de-projet", "level": 2 }, { "label": "Conclusion", "href": "#conclusion", "level": 2 }], "related": [{ "label": "PMO (Project Management Office) : le guide complet pour comprendre et mettre en place ce rôle clé", "href": "/fr/gestion-de-projet/metier-pmo" }, { "label": "PI Planning : le guide complet pour aligner vos équipes IT et métiers", "href": "/fr/gestion-de-projet/pi-planning" }, { "label": "Management de portefeuille de projet : définition, méthodes et outils", "href": "/fr/gestion-de-projet/management-de-portefeuille-de-projet" }], "faq": [] }, { "slug": "chef-de-projet-transverse", "skip": false, "meta": { "title": "Comment être un bon chef de projet transverse ?", "h1": "Comment être un bon chef de projet transverse ?", "description": "Quels sont les enjeux et les difficultés du poste ? Comment rendre efficace le pilotage de projets transverses et la coordination des équipes sans liens hiérarchiques ?", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f389f9e54e0198db633d40_Project%20image%20(1).jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "21/4/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "21/4/2022" }, "blocks": [{ "type": "paragraph", "html": "Quels sont les enjeux et les difficultés du poste ? Comment <strong>rendre efficace le pilotage de projets </strong>transverses et la coordination des équipes <strong>sans liens hiérarchiques ?</strong> Découvrez les éléments clés qui vous permettront de<strong> faire bouger les lignes</strong> dans votre démarche de <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\">conduite de projet</a>.&nbsp;" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/625f1b2321d9e558691c7049_cdp-transverse-airsaaas-ok.jpg", "alt": "Salle de réunion", "caption": "Animer des temps collectifs : un rôle clé du chef de projet transverse" }, { "type": "heading", "level": 2, "id": "difficultes-et-enjeux-du-chef-de-projet-transverse", "text": "Difficultés et enjeux du chef de projet transverse" }, { "type": "paragraph", "html": "Le chef de projet (CDP) à la responsabilité de la gestion de projet et des opérations, nécessitant la constitution d'une équipe dédiée avec la participation de profils de différentes compétences n'évoluant pas dans les mêmes services et n'ayant <strong>pas de liens hiérarchiques entre eux</strong>, qu'ils soient internes ou externes à l'entreprise.&nbsp;" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f38892e8660c95f8577b49_difficult-cdp-transverse-min.jpg", "alt": "Illustration d'un chef de projet épuisé", "caption": "Chef de projet out of order :(" }, { "type": "heading", "level": 3, "id": "pas-de-lien-hierarchique-avec-lequipe", "text": "Pas de lien hiérarchique avec l'équipe" }, { "type": "paragraph", "html": "Ce point est souvent vu comme une difficulté, mais en réalité, c'est un facteur qui peut être très positif dans la gestion de projet. Cela permet de créer une <strong>dynamique de collaboration nouvelle</strong> basée sur la transparence et la responsabilisation de chacun." }, { "type": "paragraph", "html": "L'enjeu ici sera de :&nbsp;" }, { "type": "list", "ordered": true, "items": ["Rester dans le factuel et la transparence", "Fédérer l'équipe autour des enjeux du projet et de l'impact de sa réussite"] }, { "type": "paragraph", "html": "Pour cela, vous aurez besoin de<strong> profils moteurs</strong> et d'un <strong>sponsor impliqué et fédérateur</strong>." }, { "type": "heading", "level": 3, "id": "pas-dans-la-meme-equipe", "text": "Pas dans la même équipe" }, { "type": "paragraph", "html": "La première difficulté à ne pas être dans la même équipe est <strong>le manque de proximité</strong>. Ils ne partagent souvent pas les mêmes bureaux, ils peuvent parfois se retrouver sur des sites différents, ils n'ont pas toujours le même emploi du temps ou encore la même organisation. <strong>Alors comment faire ?&nbsp;</strong>" }, { "type": "heading", "level": 4, "id": "des-seances-de-travail-dediees", "text": "Des séances de travail dédiées" }, { "type": "paragraph", "html": "Il est primordial d'aménager du temps commun dédié à l'équipe pour avancer ensemble sur les différents sujets. Au delà <strong>d'un point hebdomadaire</strong> qui est indispensable, les différents membres de l'équipe doivent pouvoir s'aménager des sessions en groupe ou en sous-groupe pour les besoin des opérations." }, { "type": "heading", "level": 4, "id": "un-onboarding-des-superieurs-hierarchiques", "text": "Un onboarding des supérieurs hiérarchiques" }, { "type": "paragraph", "html": "Afin de pouvoir aménager du temps pour les membres de l'équipe, et ne pas mettre en conflit les tâches (notamment en charge) de leurs fonctions principales avec celles des opérations transverses, il est très<strong> important que le sponsor sensibilise et se mette d'accord avec les différents supérieurs des membres de l'équipe,</strong> pour faire en sorte que les ressources nécessaires soient aménagées. Le project manager et les supérieurs feront en sorte de se coordonner pour <strong>s'assurer que les actions de l'une des activités ne pénalisent pas celles de l'autre</strong>.&nbsp;" }, { "type": "heading", "level": 4, "id": "visibilite-transparence-et-outils-dedies", "text": "Visibilité, transparence et outils dédiés" }, { "type": "paragraph", "html": "Pour pallier ce manque de proximité, il est important que tous les membres de la task force puissent <strong>retrouver toutes les informations dont ils ont besoin</strong>, et ce, rapidement. Le CDP ou PMO fera donc en sorte que le travail de chacun soit accessible et communiqué, et les <strong>données soient centralisées, ordonnées et partagées.</strong> Dans l'idéal, il mettra en place un outil commun pour le suivi, qui favorise les échanges entre les membres, et qui soit accessible à tous. Cet outil doit également lui permettre d'assigner des tâches et <strong>offrir une vision globale de l'avancement</strong>." }, { "type": "paragraph", "html": "De plus, pour agir face à une organisation différente du travail de chacun, il sera important de mettre en place une<strong> organisation simple</strong>, cadrée en amont par le chef de projet en s'assurant qu'elle s'adapte et convient à tous, <strong>avec des outils ergonomiques et intuitifs.</strong>" }, { "type": "heading", "level": 3, "id": "les-parties-prenantes-ne-sont-pas-full-time-sur-le-projet", "text": "Les parties-prenantes ne sont pas full-time sur le projet" }, { "type": "paragraph", "html": "Il est difficile de piloter des opérations dans lesquelles les parties prenantes ne sont pas à plein temps. Hormis le temps (limité) quotidien et hebdomadaire des membres de l'équipe pouvant impacter la roadmap, les personnes en face n'ont <strong>pas que ce projet comme préoccupation quotidienne</strong>. Leurs missions principales respectives peuvent parfois être jugées comme prioritaires et générer du retard, de la perte d'informations ou clarté sur l'avancement.&nbsp;" }, { "type": "paragraph", "html": "Tout l'enjeu ici est de<strong> faciliter le travail de chacun</strong> en :" }, { "type": "list", "ordered": false, "items": ["Minimisant leur charge mentale&nbsp;", "Faisant en sorte <strong>que chacun définisse et s'engage sur ce qu'il peut réaliser</strong> et le temps imparti", "Conservant une communication précise et claire&nbsp;"] }, { "type": "heading", "level": 4, "id": "un-cadre-projet-clair-et-efficace", "text": "Un cadre projet clair et efficace" }, { "type": "paragraph", "html": "Il est donc ici particulièrement<strong> essentiel que le cadre et les étapes du projet soient parfaitement clairs</strong>. Chacun doit pouvoir <strong>savoir à tout moment où en est le projet</strong>, et ce qui reste à venir.&nbsp;" }, { "type": "paragraph", "html": "Le manager transversal est donc garant de la mise en place d'une <strong>structure simple</strong> au projet reprenant la vision globale, les jalons datés, et les différentes phases d'exécution (tout en faisant en sorte de découper les tâches avec des livrables clairs pour les membres de l'équipe).&nbsp;" }, { "type": "heading", "level": 4, "id": "ownership-et-engagement", "text": "Ownership et engagement" }, { "type": "paragraph", "html": "Avec l'absence de liens hiérarchiques il est important de voir les relations entre les collaborateurs comme un lien ressemblant plus à <strong>une relation de partenariat</strong>. Il est donc important pour chacun de prendre l'ownership des jalons qui lui seront assignés, de valider ces jalons avec le chef de projet transverse, ainsi que de s'engager sur l'exécution d'un livrable et une date de livraison." }, { "type": "paragraph", "html": "Le rôle du chef de projet est de s'assurer que la roadmap pourra être tenue dans un délai raisonnable, tout en challengeant les parties prenantes sur une éventuelle sous-dimensionnement ou sur-dimensionnement quant à la charge et les délais d'exécution.&nbsp;" }, { "type": "paragraph", "html": "N'hésitez pas à vous rapprocher de vos supérieurs hiérarchiques et du sponsor pour valider un cahier des charges et un plan de charge - l'important étant de toujours être transparent et clair dans l'état des lieux de la gestion de projet." }, { "type": "heading", "level": 3, "id": "les-aleas-du-timing", "text": "Les aléas du timing" }, { "type": "paragraph", "html": "Les aléas qui pourraient perturber le déroulement d'un projet voire même le mettre en danger sont nombreux. Ceci est particulièrement vrai quand il s'agit dans la gestion de projet transverse tant les <strong>facteurs d'imprévus sont importants</strong> et souvent en dehors du contrôle du chef de projet. Un collaborateur qui rencontre un aléa dans sa mission principale, l'indisponibilité matériel d'un composant du projet, un changement important et inattendu dans l'entreprise, peuvent mettre en péril toute la gestion de projets..." }, { "type": "heading", "level": 4, "id": "anticiper-cest-gagner", "text": "Anticiper c'est gagner !" }, { "type": "paragraph", "html": "Le chef de projet doit au maximum anticiper les facteurs bloquants que lui-même ou les membres de l'équipe projet pourraient rencontrer. Il doit être une ressource pour aider les parties prenantes en cas de problème pour la bonne conduite du projet." }, { "type": "paragraph", "html": "<strong>La capacité de gestion des imprévus et du risque</strong> est certainement l'une des qualités les plus importantes pour les chefs de projets. Ils interviennent souvent dans des projets vecteurs d'innovation et de changement et, à ce titre, ils doivent porter une attention particulière à l'analyse du contexte dans lequel le projet va évoluer, qu'il soit technique, humain ou financier. La <strong>capacité à identifier les problèmes</strong> pouvant survenir sur les éléments clés et mettre en place les bonnes actions correctives<strong> pour les \"dérisquer\"</strong> est déterminante. Comme par exemple prendre du temps dans la phase de cadrage pour :&nbsp;" }, { "type": "list", "ordered": false, "items": ["<strong>Anticiper les goulots d'étranglement</strong> et les facteurs bloquants sur les éléments critiques du projet", "<strong>Préparer des actions correctives</strong>", "<strong>Prendre une marge dans la roadmap </strong>pour les phases d'exécution et de prise de décisions"] }, { "type": "heading", "level": 2, "id": "les-7-outils-du-chef-de-projet-transversal", "text": "Les 7 outils du chef de projet transversal" }, { "type": "heading", "level": 3, "id": "lapproche-orientee-probleme", "text": "L'approche orientée problème" }, { "type": "paragraph", "html": "À l'instar de l'approche orientée solution, qui consiste à faire de la veille de solutions/méthodes/technologies nouvelles à mettre en place dans son entreprise (ce qui revient souvent à essayer de faire rentrer des ronds dans des carrés), l'approche orientée problème se veut plus pragmatique car elle permet de toujours avoir une réflexion<strong> ROIste </strong>sur le projet." }, { "type": "paragraph", "html": "On passera beaucoup plus de temps dans la première phase du projet à<strong> comprendre ce qui compose la problématique</strong>, à trouver des moyens pour mesurer son impact en termes de coût ou de manque à gagner pour l'entreprise." }, { "type": "paragraph", "html": "Cette approche va surtout va <strong>mettre en évidence les leviers d'actions</strong> qui deviendront les fonctionnalités clés de la solution, et permettre de garder un fil conducteur jusqu'au déploiement du projet en :&nbsp;" }, { "type": "list", "ordered": true, "items": ["Permettant de monitorer si les actions prises sur le projet vont répondre aux sous-ensembles de la problématique", "Conservant une vision financière, et donc, une meilleure gestion du budget", "Répondant aux aspects les plus critiques de la problématique rapidement&nbsp;", "Dimensionnant le bon périmètre de test et les bons KPIs", "Consolidant un ROI"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f388efe54e0173c06332f1_schema-cdp-transverse.jpg", "alt": "Schéma de l'approche orientée problème", "caption": "Schéma de l'approche orientée problème" }, { "type": "heading", "level": 3, "id": "la-donnee", "text": "La donnée" }, { "type": "paragraph", "html": "La valeur de la donnée n'étant plus à prouver, on mettra l'accent sur l'importance qu'elle a dans un projet transverse avec une approche orientée problème<strong>.&nbsp;</strong>" }, { "type": "paragraph", "html": "Ici c'est la donnée qui conditionne les actions et les décisions de toute l'équipe et les décisions en Go / No-Go de la direction - ce qui permet de rendre les échanges factuels et transparents.&nbsp;" }, { "type": "paragraph", "html": "Un bon chef de projet cherche à <strong>comprendre comment collecter, analyser et apporter les données pertinentes </strong>pour le projet.&nbsp;" }, { "type": "paragraph", "html": "Bien définie, elle lui sert comme outil d'auto-contrôle pour anticiper de futures actions correctives.&nbsp;" }, { "type": "heading", "level": 3, "id": "le-document-cadre-du-projet", "text": "Le document cadre du projet" }, { "type": "paragraph", "html": "Il s'agit certainement de <strong>la phase la plus importante pour le chef de projet</strong> et elle représente la majeure partie de la réussite d'un projet. Cette phase doit s'accompagner d'un document reprenant la synthèse de tous les éléments importants des opérations à lancer.&nbsp;" }, { "type": "paragraph", "html": "Voici un exemple de ce à quoi pourrait ressembler ce document :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3894ce3e5064579cdd482_625f1c9a23ed50380b8524fd_exemple-cadrage-projet-min.jpg", "alt": "Document de cadrage projet", "caption": "Exemple de document de cadrage projet" }, { "type": "paragraph", "html": "C'est un document qui doit être<strong> issu d'un travail collaboratif</strong> avec toutes les parties prenantes opérationnelles. Il permet de donner une vue globale et claire à tous et fige les engagements de chacun. Il permettra de faciliter les prises de décisions<strong> </strong>en comité de pilotage, et assurera la continuité des informations entre \"prévu et réalisé\" tout au long du projet.&nbsp;" }, { "type": "paragraph", "html": "Il servira de feuille de route au chef de projet transverse, lui permettra d'anticiper les facteurs bloquants, et de constater si le projet sort des rails." }, { "type": "heading", "level": 3, "id": "le-suivi-et-la-communication", "text": "Le suivi et la communication" }, { "type": "paragraph", "html": "Dans les projets transverses<strong> la communication est clé</strong> - il faut s'assurer que tout le monde a accès aux mêmes informations, il faut savoir jouer le rôle de médiateur parfois, et s'assurer que toutes les voies de communication sont ouvertes entre le chef de projet et les parties prenantes.&nbsp;" }, { "type": "paragraph", "html": "Il y a aussi parfois une \"évangélisation\" à réaliser pour être sûr de pouvoir embarquer dans la démarche tous ceux qui ont ou vont avoir un contact avec le projet." }, { "type": "heading", "level": 3, "id": "la-culture-du-feedback-et-louverture-a-lexterieur", "text": "La culture du feedback et l'ouverture à l'extérieur" }, { "type": "paragraph", "html": "\"Seul on va plus vite, à plusieurs on va plus loin.\" Un dicton qui résume bien l'importance de la culture du feedback et<strong> l'importance de s'entourer et s'ouvrir à des personnes extérieures </strong>au projet.&nbsp;" }, { "type": "paragraph", "html": "Que ce soit vers d'autres collègues, des écosystèmes d'innovation, des entreprises au marché ou fonctionnement similaire, dites-vous bien que si vous êtes confrontés à un problème, d'autres le sont peut-être aussi et ont déjà essayé de le résoudre. Qu'ils aient réussi ou échoué, ce sera une source d'apprentissage et d'informations importante.&nbsp;" }, { "type": "heading", "level": 3, "id": "le-moment-cle", "text": "Le moment clé" }, { "type": "paragraph", "html": "Le CDP à un rôle d'<strong>animation du comité de pilotage</strong>. Il doit s'assurer que tous les points importants de l'ordre du jour seront abordés. Pour cela il aura préparé en amont les intervenants, points et décisions clés à aborder pendant ce comité. Pour cela il peut s'aider de quelques points suivants." }, { "type": "heading", "level": 3, "id": "avoir-un-bon-sponsor", "text": "Avoir un bon sponsor" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f389bfff92d37295bf4743_cdp-transverse-airsaaas.jpg", "alt": "équipe", "caption": "L'esprit d'équipe se construit" }, { "type": "heading", "level": 4, "id": "cest-lui-qui-arrive-a-rebooster-la-team", "text": "C'est lui qui arrive à rebooster la team" }, { "type": "paragraph", "html": "Au-delà qu'il fait partie ou représente souvent la direction pour un groupe sans lien hiérarchique direct entre eux, il a un <strong>rôle déterminant dans la mobilisation des effectifs</strong> de l'équipe formée pour l'objectif, il transmet la vision et l'enjeu de la démarche ainsi que les bénéfices qui en découlent. Il permet aux collaborateurs de sortir de leur cadre habituel en leur confiant une mission nouvelle. Il permet aussi aux collaborateurs de partager et valoriser leurs idées en leur donnant les moyens de les mettre en action." }, { "type": "heading", "level": 4, "id": "il-donne-le-cap", "text": "Il donne le cap" }, { "type": "paragraph", "html": "Le sponsor va permettre et<strong> faciliter la mise en place de ces nouveaux projets</strong>, donner la ligne directrice et stratégique pour que le projet s'inscrive dans la vision et les enjeux de l'entreprise. À ce titre il sera <strong>un des arbitres clés de la démarche </strong>ainsi que pour la prise de décision et la défense du projet au Codir.&nbsp;" }, { "type": "heading", "level": 4, "id": "il-defend-le-projet-avec-le-chef-de-projet-transversal-au-comite-de-pilotage", "text": "Il défend le projet avec le chef de projet transversal au comité de pilotage" }, { "type": "paragraph", "html": "La posture du sponsor est déterminante. Son <strong>rôle est de suivre et challenger l'avancement des parties prenantes</strong>, <strong>d'arbitrer les décisions Go / No-Go</strong> (possiblement en consultation avec d'autres cadres du comité et/ou Codir) et de valider les prochaines étapes proposées. Il est important de lui fournir toutes les informations clés afin qu'il puisse faciliter le déroulement opérationnel voire même de le réorienter/recadrer si on s'éloigne de la vision et objectif initial." }, { "type": "paragraph", "html": "C'est le premier convaincu de la démarche et du projet, de ce fait, il défend avec le CDP le projet et sa direction aux parties prenantes et/ou autres membres de direction." }, { "type": "heading", "level": 2, "id": "les-competences-cles-dun-bon-directeur-de-projet-transverse", "text": "Les compétences clés d'un bon directeur de projet transverse" }, { "type": "paragraph", "html": "En résumé un bon chef de projet transversal doit avoir les compétences suivantes :" }, { "type": "list", "ordered": false, "items": ["Esprit d'équipe", "Communiquant", "Organisation et rigueur", "Pragmatisme", "Écoute et anticipation", "Appétence pour la gestion du risque", "Curiosité, dans une démarche d'apprentissage permanent", "Adepte de la culture du feedback et de recherche de retours d'expériences"] }, { "type": "paragraph", "html": "Pour approfondir cette démarche, nous vous conseillons la lecture de cet article clé <a href=\"http://gestion-de-projet/le-guide-du-mode-projet\"> Comment faire passer mon entreprise en mode projet ?</a>" }], "toc": [{ "label": "Difficultés et enjeux du chef de projet transverse", "href": "#difficultes-et-enjeux-du-chef-de-projet-transverse", "level": 2 }, { "label": "Les 7 outils du chef de projet transversal", "href": "#les-7-outils-du-chef-de-projet-transversal", "level": 2 }, { "label": "Les compétences clés d'un bon directeur de projet transverse", "href": "#les-competences-cles-dun-bon-directeur-de-projet-transverse", "level": 2 }], "faq": [], "related": [] }, { "slug": "comite-de-pilotage-definitions-et-incomprehensions", "skip": false, "meta": { "title": "Comité de pilotage : définition(s) et incompréhension(s)", "h1": "Comité de pilotage : définition(s) et incompréhension(s)", "description": "Revenir sur ce qui se joue derrière les mots ou expressions clés régulièrement utilisés en comité de pilotage d'un projet.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62bd74e32ad1dc0f5b32c5bd_copil-projet-defintion.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "30/6/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "30/6/2022" }, "blocks": [{ "type": "paragraph", "text": "Dans les entreprises <strong>tout le monde parle projet... mais personne ne parle de la même chose !</strong> Pire, on constate très souvent que les bases de la conduite de réunion de comité de pilotage ne sont pas maîtrisées. Idem pour les titres des missions, le nom des poste... Tout est galvaudé." }, { "type": "paragraph", "text": "Que vous soyez dirigeants, DSI, directeur de la transformation, PMO, BRM, responsable de BU, PO, scrum master, développeur, chef de projet senior ou débutant, dans les lignes qui suivent, on vous a concocté une \"antisèche\" conceptuelle. L'idée : revenir sur ce qui se joue derrière les mots ou expressions clés régulièrement utilisés en comité de pilotage d'un projet." }, { "type": "quote", "text": "Mal nommer les choses, c'est ajouter au malheur du monde.", "author": "Albert Camus" }, { "type": "paragraph", "text": "Pour faire court, deux problèmes sont à considérer dans le déroulement du projet : comprendre et être compris." }, { "type": "paragraph", "text": "Comprendre la portée réelle et symbolique de chaque mot-clé, pour comprendre de quoi on parle - et surtout <strong> </strong>saisir ce qui n'est pas dit. <br>Puis, <strong>être compris, par ses pairs</strong> au sein du projet, et/ou par les parties prenantes du comité de pilotage moins \"acculturées\" au fonctionnement d'un projet technique." }, { "type": "paragraph", "text": "On va démystifier 5 notions simples : celle de sponsor, de Copil, de jalons, de chef de projet, de key user et de reporting." }, { "type": "paragraph", "text": "Pour chaque terme, on va s'intéresser à la théorie et à la pratique, aux principales erreurs et/ou incompréhensions. Enfin, on illustrera les sujets avec les avis de \"Pros de La Transfo.\" interviewés lors du Podcast CIO Révolution produit par AirSaas. Objectif valeur !" }, { "type": "paragraph", "text": "Cet article fait partie de la série <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">Comité de pilotage ou Copil : Les bases</a> qui recense l'essentiel des éléments simples et pragmatiques à connaitre sur le comité de pilotage projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d1789d30123fdecb8a4aad_62ea8af8debf3e01b90bcaaa_cbo-airsaas-fxdessinateur.jpeg", "alt": "Chief bullshit officer FX Dessinateur" }, { "type": "heading", "level": 2, "id": "copil-5-expressions-cles-pour-mieux-se-comprendre", "text": "Copil : 5 expressions clés pour mieux se comprendre" }, { "type": "paragraph", "text": "Découvrez votre micro-kit de survie sémantique pour mieux se comprendre lors de votre prochain comité de pilotage." }, { "type": "heading", "level": 3, "id": "les-jalons-votre-meilleur-gps", "text": "Les jalons : votre meilleur GPS" }, { "type": "paragraph", "text": "Les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/jalon-projet\" target=\"_blank\">jalons du projet</a> sont semblables à des panneaux sur une route vous indiquant l'état d'avancement de votre trajet. Ils marquent la fin d'une étape et un point d'arrêt dans le processus de gestion de projet. Ils orientent le pilotage du Copil tel le GPS projet !" }, { "type": "paragraph", "text": "En pratique, ces jalons sont ce qui rythme les projets. Ils permettent d'aligner les équipes sur les objectifs, et de découper les projets en plusieurs étapes clés. Point trop n'en faut ! En donner trop, c'est rendre illisible le suivi efficace." }, { "type": "heading", "level": 4, "id": "l-incomprehension-courante-autour-des-jalons", "text": "L'incompréhension courante autour des jalons" }, { "type": "paragraph", "text": "On ne transforme pas une organisation en commençant par inviter les équipes à faire de la gestion de projet \"à la tache\". Le but est bien de structurer, communiquer et ensuite piloter un plan de transformation. Dans un pilotage du projet et un reporting, je partage l'état des jalons, pas des tâches !" }, { "type": "quote", "text": "S'il y a la possibilité de découper un projet, il ne faut pas hésiter à le découper au maximum de manière à avoir plusieurs petits problèmes plutôt qu'un immense problème très complexe à résoudre. Les petits problèmes solubles à court terme nécessitent un livrable intermédiaire permettant de valider, de réfuter, de réajuster les objectifs et les gains.", "author": "Thomas Vrignaud — CIO - CDO, Invité épisode 14 Podcast CIO Révolution" }, { "type": "heading", "level": 3, "id": "chef-de-projet-la-fin-du-heros-solitaire", "text": "Chef de projet : la fin du \"héros solitaire\"" }, { "type": "paragraph", "text": "En théorie, on présente fréquemment le chef de projet comme un Superman. Le pilote, <strong>chargé de mener le projet et de gérer son (bon) déroulement</strong>. D'animer une équipe transverse et éphémère. Le garant du respect du triangle \"Coûts-Qualité-Délai\" avec même une nouvelle passion : la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">gestion des risques</a>." }, { "type": "paragraph", "text": "En pratique, la majorité des projets ne se passent pas comme cela, <strong> </strong>car la coopération ne se décrète pas ! Les chefs de projet vont chercher à influencer, à s'aligner avec le sponsor et le métier. Les relations humaines sont primordiales dans ce travail et rendent l'exercice très subtil. En étant situé hors hiérarchie classique, ce rôle transversal de management de projet est doublement délicat." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d1789d30123fdecb8a4aaa_62ea8b39bbc7827476664599_chef-deprojet-min.jpeg", "alt": "Les assiettes tournantes ou la métaphore du chef de projet" }, { "type": "heading", "level": 4, "id": "deux-erreurs-et-incomprehensions-courantes-autour-du-chef-de-projet", "text": "Deux erreurs et incompréhensions courantes autour du chef de projet" }, { "type": "list", "ordered": false, "items": ["<strong>Confondre chef de projet et chefferie de projet.</strong> Le terme de \"chef\" induit en effet beaucoup trop un exercice du pouvoir solitaire et non collaboratif. Mais c'est bien un groupe, une \"chefferie\" formée par le trio chef de projet technique / chef de projet métier / sponsor projet qui est en responsabilité du pilotage. Le \"co-management\" est dans l'ADN de la transformation digitale !"] }, { "type": "list", "ordered": false, "items": ["<strong>Confondre projet et programme.</strong> C'est peut-être le syndrome le plus néfaste pour votre comité de pilotage. La perte d'énergie qui résulte de cette méprise est colossale. On ne pilote pas la construction de plusieurs maisons en se focalisant sur des détails ! Ne pas regarder son portefeuille par le haut vous lancera dans une noyade assurée."] }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote><p>Je crois beaucoup à la dualité du pilotage car avoir une direction qui n'est ni métier, ni DSI, permet de rester neutre et d'avoir un regard critique. Tout doit être dans l'explicite, les rôles doivent concrètement être définis à l'avance et la confiance doit régner.</p></blockquote><p><strong>Frédéric Riou</strong> — CIO - CDO, Invité épisode 29 Podcast CIO Révolution</p>" }, { "type": "heading", "level": 3, "id": "comite-de-pilotage-attention-aux-fuites-de-responsabilites", "text": "Comité de pilotage : attention aux fuites de responsabilités" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d1789e30123fdecb8a4ab7_62ea8b699d1225e5fdee5fd1_plan-action.jpeg", "alt": "Image d'illustration COPIL - Source JMB @CyberJMB" }, { "type": "paragraph", "text": "En théorie, le comité de pilotage serait <strong>une équipe dont </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-decider-en-copil\" target=\"_blank\"><strong>le rôle est de décider.</strong></a><strong> </strong>Un Copil désigne une réunion généralement constituée d'un membre de chaque métier impliqué dans le projet." }, { "type": "paragraph", "text": "En pratique, les sujets d'arbitrage remontés en comité de pilotage sont complexes, et le temps disponible y est limité. Qui plus est on a rarement toutes les directions représentées à chaque Copil. On assiste parfois à un désengagement progressif, voire à une véritable fuite de responsabilité très problématique !" }, { "type": "heading", "level": 4, "id": "deux-erreurs-et-incomprehensions-courantes", "text": "Deux erreurs et incompréhensions courantes" }, { "type": "list", "ordered": false, "items": ["<strong>Confondre Coproj et Copil</strong>"] }, { "type": "paragraph", "text": "COPROJ : Micro = Répartitions des tâches" }, { "type": "paragraph", "text": "COPIL : Macro = Arbitrages et décisions" }, { "type": "list", "ordered": false, "items": ["<strong>La \"séparation\" des responsabilités</strong>"] }, { "type": "paragraph", "text": "<strong>‍</strong>Si chaque organe de pilotage à son rôle et ses redevabilités dans le déroulement du projet<strong>,</strong> l'équipe de projet et le comité de pilotage sont tous deux responsables de la réussite." }, { "type": "paragraph", "text": "<strong>Fixez des normes élevées.</strong> Le comité de pilotage doit exiger des performances de l'équipe de projet tout en montrant simultanément où leur aide rendra cela possible. Exigez des informations claires, un dialogue ouvert, le respect des faits, ainsi que des attentes et des responsabilités écrites pour le comité de pilotage et l'équipe de projet." }, { "type": "heading", "level": 3, "id": "key-user-le-pire-et-le-meilleur-allie-de-la-conduite-du-changement", "text": "Key user : le pire et le meilleur allié de la conduite du changement" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d1789e30123fdecb8a4acb_62ea8bcc7722a50875e65b97_jack-nicholson-no-min.gif", "alt": "Gif Jack Nicholson NO", "caption": "Quand tu demandes à un \"volontaire\" d'être key user du Copil sur le gros projet ERP à venir" }, { "type": "paragraph", "text": "En théorie, <strong>l'utilisateur clé est le représentant des utilisateurs finaux.</strong> Il est l'un des mieux placé du comité de pilotage pour évaluer et innover sur la création de valeur apportée par un nouveau service." }, { "type": "paragraph", "text": "En pratique, cette fonction requiert un subtil mélange de bonne vision terrain <strong> </strong>et de capacité à prendre du recul <strong> </strong>pour identifier les contournements possibles." }, { "type": "heading", "level": 4, "id": "incomprehensions-et-erreurs-courantes-autour-du-key-user", "text": "Incompréhensions et erreurs courantes autour du key user" }, { "type": "list", "ordered": false, "items": ["<strong>L'utilisateur clé ne redescend pas l'information au groupe de personnes concernées.</strong>"] }, { "type": "paragraph", "text": "On parle de key user - mais l'acception conforme serait plutôt : \"groupe de key users et son représentant\" !" }, { "type": "paragraph", "text": "Il est primordial que celui-ci ait à la fois suffisamment de leadership pour décider en séance et suffisamment d'intelligence pour savoir quand il ne doit plus décider seul <strong> </strong>pour retourner communiquer et consulter sa \"base\", pour des décisions avec une dimension plus politique." }, { "type": "quote", "text": "La mise en place de comité de pilotage a aussi permis d'impliquer les Key Users de chaque métier, afin qu'ils puissent être le relais des bonnes pratiques transmises par la DSI : un rôle capital pour réussir à manager le changement !", "author": "Olivier Perrin — CIO, Invité épisode 17 Podcast CIO Révolution" }, { "type": "paragraph", "text": "Le rôle du métier est primordial, <strong> </strong>et c'est une vraie charge, une vraie mission. On n'attribue parfois pas suffisamment de temps, de formation et de rémunération pour valoriser et \"engager\" durablement ce rôle très stratégique dans la conduite de projet." }, { "type": "heading", "level": 3, "id": "reporting-du-flux-continu-sinon-rien", "text": "Reporting : du flux continu, sinon rien" }, { "type": "paragraph", "text": "En théorie, le PMO/chef de projet a comme rôle d'établir des <strong>tableaux de bord et </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\"><strong>reportings</strong></a> périodiques pour communiquer au comité de pilotage les grandes métriques relatives au projet. Idéalement, ils doivent être le plus synthétiques et visuels possible." }, { "type": "paragraph", "text": "En pratique, <strong> </strong>il y passe des heures, voire des jours. Et il n'y a rien de plus décourageant que d'être invité à travailler sur un Excel géant une fois par mois lorsque l'on n'est pas la personne ayant passé des dizaines d'heures à le créer." }, { "type": "paragraph", "text": "En résumé : l'usage d'une plateforme vous simplifiera la gouvernance (listing des décisions à prendre, vue Copil, etc.)" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d1789e30123fdecb8a4ac0_62bdfca88290d29985904cb5_report-flash.png", "alt": "Capture d'écran Flash Report sur la plateforme AirSaas", "caption": "Générez votre flash report en un clic et envoyez le de manière régulière aux différentes parties prenantes" }, { "type": "heading", "level": 4, "id": "la-meprise-courante-autour-du-reporting-en-copil-projet", "text": "La méprise courante autour du reporting en Copil projet" }, { "type": "paragraph", "text": "<strong>Confondre reporting et tableau de bord !</strong> Un reporting complet inclut à la fois un tableau de bord et le compte rendu, les faits marquants, etc. Des chiffres et des faits." }, { "type": "paragraph", "text": "<strong>Communiquer vers le comité de pilotage de façon continue favorise la transparence</strong> et la décision au sein des entreprises. Le comité de pilotage peut et doit avoir accès aux données du cadrage et de la mise en œuvre entre les réunions." }, { "type": "paragraph", "text": "L'utilisation de logiciels type PPM avec une interface suffisamment intuitive et un accès permanent permet de faciliter la collaboration entre les profils techniques et business." }, { "type": "quote", "text": "Le suivi de l'exécution du plan de la transformation s'est vite complexifié. Les équipes ont passé trop de temps à faire du reporting. On a manqué d'outils de suivi de l'exécution pour vraiment se focaliser sur l'impact de ce qu'on cherchait à faire. Nos MVP ne se sont pas traduits en minimum viable product mais en maximum viable product.", "author": "Patrick Valentin — CIO - CDO, Invité épisode 7 Podcast CIO Révolution" }, { "type": "paragraph", "text": "Bravo vous avez fait une mise à jour de ce qu'il faut bien saisir pour limiter la confusion. Une fois qu'on se comprend, cela ne sous-entend pas qu'on s'entend ! <strong> </strong>Il arrive en effet que les relations entre participants du comité soient tendues, voire agressives." }, { "type": "paragraph", "text": "Comment gérer les personnalités difficiles ? Comment réagir en cas d'agressivité ? On a été puiser dans notre vécu, analyser l'état de l'art de la documentation, on a interrogé nos amis Pros de la Transfo., pour vous proposer 7 astuces qui vous faciliteront la vie de bureau. C'est par ici : <a href=\"/gestion-de-projet/comment-gerer-lagressivite-dans-les-comites-de-pilotage\" target=\"_blank\">Comment gérer l'agressivité dans la réunion du comité de pilotage ?</a>" }], "toc": [{ "label": "Copil : 5 expressions clés pour mieux se comprendre", "href": "#copil-5-expressions-cles-pour-mieux-se-comprendre", "level": 2 }, { "label": "Les jalons : votre meilleur GPS", "href": "#les-jalons-votre-meilleur-gps", "level": 3 }], "faq": [], "related": [] }, { "slug": "comite-pilotage-projet", "skip": false, "meta": { "title": "Comité de pilotage projet : 5 astuces pour que tout se passe bien", "h1": "Comité de pilotage projet : 5 astuces pour que tout se passe bien", "description": "5 bonnes pratiques pour réussir votre comité de pilotage projet : astuces pragmatiques sur les dynamiques relationnelles, la préparation, la communication et la prise de décision.", "publishedDate": "1/6/2022", "author": { "name": "Jérôme Dard", "publishedDate": "1/6/2022", "category": "Gestion de projets", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea901f083f308b673091eb_copil-projet.jpg", "alt": "" } }, "blocks": [{ "type": "paragraph", "text": "<strong>Montre-moi ton comité de pilotage projet, je te dirai quel PMO ou chef de projet tu es</strong> !" }, { "type": "paragraph", "text": "Un proverbe chinois nous le rappelle : \"Le<strong> </strong>poisson pourrit toujours par la tête\". Oui : à l'origine des dysfonctionnements au sein d'une organisation, on trouve souvent ses dirigeants et managers." }, { "type": "paragraph", "text": "Réussir votre Copil projet, c'est réussir vos arbitrages et prises de décisions. C'est<strong> </strong>impliquer la gouvernance d'un projet, ceux qui détiennent le pouvoir sur les moyens, les délais, la qualité et la performance." }, { "type": "paragraph", "text": "Problème : les sujets remontés en comité de pilotage sont complexes. Le temps<strong> </strong>disponible<strong> </strong>y est<strong> </strong>limité et enfin, la concentration d'excès d'ego y est extrême !" }, { "type": "paragraph", "text": "Ajoutons qu'il y a parfois tellement de projets que le<strong> </strong>Codir ne peut alors pas participer à tous les Copil. Ce qui peut avoir pour conséquence un surplus de jeu \"politique\" interne, d'indécision." }, { "type": "paragraph", "text": "Comment, dans ce contexte,<strong> </strong>éviter ou déminer les pièges de l'effet groupe, et faire en sorte que le processus d'animation du comité de pilotage projet se passe le mieux possible ? On a interrogé nos amis DSI, PMO et chef de projets, on a puisé dans notre vécu, relu tous les articles, demandé à Google... pour sélectionner <strong>5 bonnes pratiques, qu'on aurait aimé connaître</strong>, avant notre premier Copil projet..." }, { "type": "paragraph", "text": "Ici, pas de conseils basiques - vous savez déjà qu'il faut faire un ordre du jour lors d'un comité de pilotage. On va s'intéresser à ce qui n'est pas écrit dans les manuels, avec un <strong>focus sur le pragmatisme et les dynamiques relationnelles</strong> d'un projet. Pour découvrir les fondamentaux on vous a préparé cet autre article à découvrir : <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">Comité de pilotage ou Copil : Les bases</a>&nbsp;" }, { "type": "heading", "level": 2, "id": "astuce-1-saccorder-pour-ne-pas-mettre-en-defaut-son-homologue-it-metier-en-copil", "text": "Astuce 1 : S'accorder pour ne pas mettre en défaut son homologue IT / Métier en Copil" }, { "type": "paragraph", "text": "Établissez en quelque sorte un \"<strong>contrat relationnel\"</strong> : ne jamais mettre son partenaire du tandem chef de projet métier / IT, en défaut devant le comité. Ce n'est pas le Copil d'une des parties, c'est le Copil du projet ! Faites en une sorte de <em>golden rule</em>\"" }, { "type": "paragraph", "text": "Cette astuce simple, si elle est utilisée à bon escient, ne garantira pas un projet idéal - mais juste des relations normales et en partie apaisées lors des moments de tensions." }, { "type": "paragraph", "text": "Il faut souligner que dans un contexte d'équipes de plus en plus auto-organisées et agiles dans les projets, le concept même de<strong> </strong>chef de projet unique semble de plus en plus anachronique, voire obsolète. Oui, vous êtes un groupe projet, une \"chefferie\" hybride. Précisons pour être complet, qu'<strong>au duo formé par le chef de projet IT et métier, il faut ajouter le sponsor.</strong> C'est ce trio qui doit animer le comité de pilotage<strong>.</strong>" }, { "type": "paragraph", "text": "Le chef de projet doit<strong> </strong>se phaser avant et après le comité de pilotage pour s'aligner sur les messages et objectifs parfois transverses." }, { "type": "paragraph", "text": "Pour bien ancrer cette pratique, on peut la comparer à celle qui se joue à l'échelle d'une famille. Prenons l'exemple d'un adolescent qui rencontrerait des problèmes de comportement au collège... Si l'un des parents, pour aller dans le sens de l'enfant, met en défaut les autres adultes co-responsables (parent et ou professeur), on commence alors à disfonctionner. Cette faille entre les trois partenaires de l'éducation peut être exploitée et donner lieu à des interprétations et débats sans fin ! L'analogie avec les projets vaut ce qu'elle vaut, mais elle dit bien l'importance du contrat relationnel, pour que chacun joue son rôle dans un cadre collectif, en co-responsabilité." }, { "type": "heading", "level": 2, "id": "astuce-2-aucune-information-ne-doit-etre-decouverte-pendant-le-comite-de-pilotage-projet", "text": "Astuce 2 : Aucune information ne doit être découverte pendant le comité de pilotage projet" }, { "type": "paragraph", "text": "<strong>Tous les documents; ordre du jour et annexes doivent être transmis, </strong>au moins une semaine; et idéalement 15 jours, avant le jour du comité de pilotage !" }, { "type": "paragraph", "text": "Attention : maîtriser cette astuce de base n'est pas si facile. Il s'agit ici de vous mettre (un peu) à la place des membres du comité de pilotage projet. Car oui, rappelons-le :<strong> </strong>envoyer un \"diapocument\", équivalent à un livre de 100 pages à lire,<strong> </strong>quelques jours seulement avant la réunion équivaut à faire vivre une expérience pénible à votre cible." }, { "type": "paragraph", "text": "Le principe conducteur : <strong>aucune information ou presque ne doit être découverte pendant le comité de pilotage.</strong>" }, { "type": "paragraph", "text": "De même <strong>le sponsor doit être tenu au courant des points critiques</strong> inclus dans l'ordre du jour. Sans pour autant lui faire relire tout le plan de communication, vous aurez préparé et validé les messages clés, décisions et solutions préconisées." }, { "type": "paragraph", "text": "Enfin, idéalement, certaines décisions du comité de pilotage projet seront prises avant la réunion entre le chef de projet IT/Métier et le sponsor. L'objectif serait d'avoir les validations des différents managers sur ces sujets. Tout est dans la préparation<strong>.</strong>" }, { "type": "heading", "level": 2, "id": "astuce-3-soyez-vagues-tres-precisement", "text": "Astuce 3 : Soyez vagues, très précisément !" }, { "type": "paragraph", "text": "Là, on est sur une astuce de pure rhétorique. Vous êtes le chef de projet IT/Métier ou PMO. Un des membres du comité de pilotage projet vous interpelle lors de la réunion. Si vous ne savez pas ce qui doit être fait, mais que vous ne voulez pas l'admettre, utilisez des phrases telles que&nbsp;: \"<em>Nous allons examiner ce problème et vous donner un retour d'ici mardi prochain, 15h00</em>\"." }, { "type": "paragraph", "text": "En technique de communication il est important, voire essentiel, \"<strong>d'accuser réception du message\" de l'émetteur</strong>. Vous vous assurerez de la sorte de ne plus y revenir, et éviterez un parasitisme latent." }, { "type": "paragraph", "text": "Notez-le sur le <em>parperboard</em> ou le support de la plateforme. Vous ne dites pas un mot de ce que vous allez faire, mais <strong>le délai exact crée une impression de certitude</strong>. Bien sûr, vous devez envoyer une mise à jour avant la date limite. Même s'il ne s'agit que d'un \"<em>désolé, nous avons dû reprioriser le sujet</em>\" avec un nouveau délai :-) vous serez perçu comme une personne très fiable, capable de respecter les délais et de communiquer clairement et à l'avance." }, { "type": "paragraph", "text": "C'est une astuce proche de celle consistant à accueillir et ranger les questions hors sujets au parking, pour garder le focus sur l'ordre du jour." }, { "type": "heading", "level": 3, "id": "variante-pour-garder-le-focus-la-zone-des-questions-frigosparking", "text": "Variante pour garder le focus : la zone des questions \"frigos/parking\"" }, { "type": "paragraph", "text": "On vous interpelle en pleine réunion sur une question non prévue ? <strong>Notez les sujets hors ordre du jour et mettez-les de côté</strong> pour discussion à une date ultérieure afin de<strong> </strong>vous assurer que l'ordre du jour principal est traité en priorité et de donner aux participants l'habitude de se concentrer et d'être conscients des tangentes, pour <strong>éviter les digressions</strong>." }, { "type": "paragraph", "text": "Cet usage à comme bénéfice de<strong> </strong>garder le comité de pilotage concentré sur l'ordre du jour indiqué. Deuxièmement, le frigo ou parking reconnaît et fait une place aux points importants soulevés par les différentes parties prenantes." }, { "type": "paragraph", "text": "Attention, la question doit être vraiment suivie. Ne faites pas semblant !" }, { "type": "heading", "level": 2, "id": "astuce-4-faites-la-promotion-des-accomplissements-et-succes", "text": "Astuce 4 : Faites la promotion des accomplissements et succès" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea8f7744e58a71d700438e_funny-celebrate-8-min.gif", "alt": "Illustration photo d'un des membres de l'équipe AirSaas" }, { "type": "paragraph", "text": "À l'inverse d'un comité de pilotage projet, ou parfois le principal driver est le suivi des risques, <strong>innovez et investissez dans le positif</strong> ! Une astuce simple : ritualiser, à chaque fois que l'avancement du projet le justifie des <em>Merci</em> <a href=\"https://emojipedia.org/folded-hands-light-skin-tone/\" target=\"_blank\"><strong>🙏🏻</strong></a><strong> </strong>et <em>bravo</em> ✌️!" }, { "type": "paragraph", "text": "<strong>Valorisez ce qui marche, ce qui a fonctionné, les équipes</strong>. C'est un objectif clé de votre plan de communication. Cela passera aussi par les chefs de projets qui postent sur les plateformes internes des succès, des sponsors qui \"likent\" et commentent." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3e8bf5a0566e058b267d8_Project%20page-min.jpg", "alt": "Capture écran plateforme AirSaas - partage succès", "caption": "Un management de projet qui célèbre chaque réussite des équipes" }, { "type": "paragraph", "text": "<strong>Utilisez chaque jalon projet comme un point succès. </strong>Récupérez via les plateformes dédiées la ou les captures d'écran des partages rédigés par d'autres que vous : c'est encore mieux quand c'est dit par quelqu'un d'autre que les PMO ou chefs de projet :-)" }, { "type": "paragraph", "text": "Le principe derrière cette pratique, est le suivant : \"ce que l'on regarde grandit\". Cette approche, théorisée par des consultants en management, est plus qu'une astuce : c'est une philosophie. Car concentrer l'attention d'un comité sur le positif valorisera non seulement le travail et les acteurs du projet impliqués, mais peut aussi contribuer à <strong>développer une culture centrée sur les points forts de l'organisation et de son management.</strong>" }, { "type": "paragraph", "text": "En résumé :<strong> </strong>mettez en avant toutes l'équipe de projet<strong>,</strong> notamment les équipes métiers.&nbsp;Sans oublier de rappeler les bénéfices clés pour les utilisateurs finaux - les clients de l'entreprise !" }, { "type": "heading", "level": 2, "id": "astuce-5-decidez-de-comment-decider", "text": "Astuce 5 : Décidez... de comment décider" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote><p>\"L'entreprise est une collectivité. Il faut accepter de se mettre en pack de rugby et de pousser dans le même sens ! Le temps qu'on prend à s'aligner ce n'est pas du temps perdu... il est important que chacun ait pu s'exprimer, et comprenne le choix et la décision qui a été prise.\"</p></blockquote><p><strong>Gilles de Richemond</strong><br>CEO Fairlyne | ex DSI du groupe Accor, extrait de l'épisode 40 du Podcast CIO Révolution produit par AirSaas.</p>" }, { "type": "quote", "text": "\"L'entreprise est une collectivité. Il faut accepter de se mettre en pack de rugby et de pousser dans le même sens ! Le temps qu'on prend à s'aligner ce n'est pas du temps perdu... il est important que chacun ait pu s'exprimer, et comprenne le choix et la décision qui a été prise.\"", "author": "Gilles de Richemond — CEO Fairlyne | ex DSI du groupe Accor, extrait de l'épisode 40 du Podcast CIO Révolution produit par AirSaas." }, { "type": "paragraph", "text": "<strong>Instaurer ou rappeler le processus de gouvernance</strong> est fondamental. C'est<strong> </strong>en quelque sorte l'algorithme du comité de pilotage d'un projet<strong>.</strong> S'assurer que chacun des membres du comité comprend les méthodes et phases nécessaires pour prendre des décisions est essentiel pour un management efficace." }, { "type": "paragraph", "text": "On rappelle ci-dessous l'équation popularisée par Olivier Bas, vice-président d'Havas, auteur, conférencier et enseignant :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/629798c204fc271575a21d21_demidecision.png", "alt": "1/2 décision bordel au carré", "caption": "Titre d'un chapitre du livre <a href=\"https://www.dunod.com/entreprise-et-economie/like-ton-job-comment-vivre-avec-bonheur-transformation-digitale\" target=\"_blank\"><em>Like ton job</em></a> paru chez Dunod." }, { "type": "paragraph", "text": "L'enjeu ce sont <strong>des décisions projets qui restent partagées et inclusives</strong>, et qui <strong>gagnent en rapidité ! </strong>" }, { "type": "paragraph", "text": "À la clé, une culture Copil entreprise radicalement différente de ce qui peut se faire ailleurs." }, { "type": "paragraph", "text": "Sans entrer dans tous les détails de la mise en œuvre (les avantages inconvénients de chacune feront l'objet d'un article dédié sur ce blog), rappelons que les principales méthodologies de décision dans le management des entreprises sont :" }, { "type": "list", "ordered": false, "items": ["<strong>La décision</strong> <strong>autocratique</strong> : j'ai décidé seul !", "<strong>La décision</strong> <strong>consultative</strong> : je vous ai écouté", "<strong>La décision par</strong> <strong>consensus</strong> : j'ai un accord général (tacite ou manifeste)", "<strong>La décision par</strong>&nbsp;<strong>consentement</strong> : j'ai une absence d'objection majeure."] }, { "type": "heading", "level": 2, "id": "astuce-bonus-affichez-la-checklist-du-role-et-des-redevabilites-du-comite-de-pilotage-projet", "text": "Astuce bonus : Affichez la checklist du rôle et des redevabilités du comité de pilotage projet" }, { "type": "paragraph", "text": "Au-delà des astuces, la pratique ultime ne consisterait-elle pas à garder bien en tête, et à rappeler au Copil si besoin, le cadre : les rôles et redevabilités générales du comité de pilotage dans le management de projet ?" }, { "type": "paragraph", "text": "Aux côtés du chef de projet, ses redevabilités sont :" }, { "type": "list", "ordered": false, "items": ["<strong>Prendre des décisions et faire des arbitrages</strong> vis-à-vis de la conduite de projet.", "<strong>Veiller au bon déroulement du projet</strong> et s'assurer qu'il est en accord avec les stratégies globales de l'entreprise.", "<strong>Évaluer la qualité et la santé du projet à chaque réunion</strong>. Si certains problèmes&nbsp; doivent être améliorés, les principaux intervenants peuvent les soulever pour les résoudre.", "<strong>Donner au chef de projet le pouvoir d'agir</strong> et d'utiliser les ressources de l'entreprise pour mener l'exécution, l'avancement du projet.", "<strong>Résoudre les conflits entre départements</strong>, les problèmes liés aux budgets et coûts, au planning, aux risques, à la gestion des ressources, à la qualité et à la portée.", "<strong>Surveiller les progrès du projet par rapport aux objectifs convenus</strong> et résoudre les problèmes qui ne permettent pas au projet de progresser à temps."] }, { "type": "paragraph", "text": "Avec cette sélection de 5 astuces + 1, vous êtes parés pour que votre comité de pilotage projet devienne un moment de décisions, un processus de management de projet plus efficace." }, { "type": "paragraph", "text": "Si toutefois vous êtes confrontés à un comité houleux et que rien ne va plus en terme de tensions entre deux participants, bonne nouvelle : le Blog Pro de la Transfo a pensé à vous. <a href=\"/gestion-de-projet/comment-gerer-lagressivite-dans-les-comites-de-pilotage\" target=\"_blank\">Découvrez comment gérer l'agressivité dans les comités de pilotage ?</a> Personnalités difficiles, réaction en cas d'agressivité ? Découvrez &nbsp;les 7 astuces sélectionnées pour vous faciliter la vie de bureau." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6297345614f7ff48d24fcc69_copil-projet-airsaas.jpg", "alt": "Illustration copil projet AirSaas", "caption": "Un Copil projet efficace se reposera sur un bon <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\">reporting projet</a>" }], "toc": [{ "label": "Astuce 1 : S'accorder pour ne pas mettre en défaut son homologue IT / Métier en Copil", "href": "#astuce-1-saccorder-pour-ne-pas-mettre-en-defaut-son-homologue-it-metier-en-copil", "level": 2 }, { "label": "Astuce 2 : Aucune information ne doit être découverte pendant le comité de pilotage projet", "href": "#astuce-2-aucune-information-ne-doit-etre-decouverte-pendant-le-comite-de-pilotage-projet", "level": 2 }, { "label": "Astuce 3 : Soyez vagues, très précisément !", "href": "#astuce-3-soyez-vagues-tres-precisement", "level": 2 }, { "label": "Astuce 4 : Faites la promotion des accomplissements et succès", "href": "#astuce-4-faites-la-promotion-des-accomplissements-et-succes", "level": 2 }, { "label": "Astuce 5 : Décidez... de comment décider", "href": "#astuce-5-decidez-de-comment-decider", "level": 2 }, { "label": "Astuce bonus : Affichez la checklist du rôle et des redevabilités du comité de pilotage projet", "href": "#astuce-bonus-affichez-la-checklist-du-role-et-des-redevabilites-du-comite-de-pilotage-projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-animer-un-bilan-projet-efficace", "skip": false, "meta": { "title": "Comment animer un bilan projet efficace", "h1": "Comment animer un bilan projet efficace", "description": "Qu'est-ce qu'un bilan projet ? Que doit-il inclure ? Pourquoi le réaliser ? Comment le réaliser efficacement ? Quelles sont les nouvelles tendances ? Et quelles sont les trames-types que vous pouvez utiliser ?", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37a042a9d959fb9575d1d_bilan-de-projet-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "20/4/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "20/4/2022" }, "blocks": [{ "type": "paragraph", "html": "En <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> on parle de bilan de projet, clôture, retrospective, débriefing, amélioration continue... appelez-le comme vous voulez.<strong> </strong>L'idée c'est de s'arrêter !<strong> </strong>S'arrêter de produire, pour réfléchir. Réfléchir avant d'agir à nouveau. Un rituel, avec à la clé un enjeu majeur : s'améliorer collectivement ! Mais au delà des intentions, 99% des DSI nous disent qu'au final, ils n'ont jamais le temps de faire leur bilan de projet." }, { "type": "paragraph", "html": "A l'image du kick-off, <strong>le bilan projet est un \"<em>must</em>\"</strong>. Traduisez : à partir d'une certaine taille d'entreprise, il s'agit d'un passage obligé dans la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/gestion-portefeuille-projets-vs-gestion-de-projet\" target=\"_blank\">gestion de portefeuille projet</a>. Si on veut faire chic, on peut dire que c'est une activité \"méta\" à haute valeur ajoutée<strong> </strong>dans la culture de votre organisation \"apprenante\". Si on veut appeler un chat un chat, il s'agit d'un investissement qui vaut le coup<strong> </strong>!" }, { "type": "paragraph", "html": "Mais alors qu'est-ce qu'un bilan projet ? Que doit-il inclure ? Pourquoi le réaliser ? Comment le réaliser efficacement ? Quelles sont les nouvelles tendances ? Et enfin : quelles sont les trames-types que vous pouvez utiliser ?" }, { "type": "paragraph", "html": "On fait le bilan du bilan : c'est parti !" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-bilan-projet", "text": "Qu'est-ce qu'un bilan projet ?" }, { "type": "paragraph", "html": "Dans le dictionnaire, la définition du mot bilan est la suivante : Bilan (de l'italien <em>bilancio</em>, balance) signifie « état de l'actif et du passif d'une entreprise » et, par extension, &nbsp;somme des aspects positifs et négatifs de quelque chose, résultat global." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c187768_624aece1459ce8e503a3444d_capture-AirSaas.png", "alt": "Illustration phases projet", "caption": "Vous êtes ici ! Le bilan a autant d'importance que le cadrage et l'exécution d'un projet" }, { "type": "paragraph", "html": "Dans<strong> </strong><a href=\"https://www.skills4all.com/pmbok-quest-ce-que-la-methodologie-pmbok/\" target=\"_blank\"><strong>le \"PMBok</strong>®</a>, <strong>\"</strong>l'Ancien Testament du chef de projet\", le processus de bilan est baptisé \"clôture\". Il a la même importance que les phases d'initialisation, de planification, d'exécution, de suivi et de contrôle. A ceci près qu'il s'agit de \"la fin du geste\". Et donc, de la fin du lien contractuel entre les parties prenantes." }, { "type": "paragraph", "html": "Cette phase contient : \"La réception de l'approbation du client, l'archivage des documents, la clôture des contrats, l'évaluation des enseignements tirés et la récompense des performances font tous partie du processus de clôture.\"" }, { "type": "paragraph", "html": "Un bilan de projet vise donc à faire le point pour aboutir à des propositions d'améliorations<strong> </strong>pour chacun des aspects du projet à prendre en compte pour les prochains \"chantiers\". On cherche bien sûr à identifier ce qui a donné de bons résultats et, ce qui en a donné<strong> </strong>de moins bons<strong>.</strong>" }, { "type": "paragraph", "html": "Responsable de projets digitaux, vous le savez : les études nous rappellent que les 3/4 des projets n'atteignent pas leurs objectifs (1) !" }, { "type": "heading", "level": 2, "id": "pourquoi-faire-un-bilan-projet", "text": "Pourquoi faire un bilan projet ?" }, { "type": "paragraph", "html": "La fin d'un projet est le bon moment pour :" }, { "type": "list", "ordered": false, "items": ["Ancrer des apprentissages forts", "Libérer la parole", "S'évaluer individuellement et collectivement", "Célébrer et remercier les parties prenantes", "Analyser", "S'améliorer", "Mettre à jour la documentation.", "Transmettre les clés du <a href=\"https://www.airsaas.io/gestion-de-projet/le-pilotage-de-projet-en-2023\" target=\"_blank\">pilotage</a> à une autre équipe en charge de l'exploitation", "Se reposer !", "Construire l'\"esprit d'équipe\""] }, { "type": "paragraph", "html": "La fin d'un projet n'est pas le bon moment pour :" }, { "type": "list", "ordered": false, "items": ["Régler ses comptes - vous n'êtes pas au tribunal !", "Créer un sous-projet dans le projet", "Se taire"] }, { "type": "paragraph", "html": "🚫Attention : sont souvent confondus le bilan projet et la <a href=\"https://www.airsaas.io/gestion-de-projet/la-revue-de-projet\" target=\"_blank\">revue de projet</a> ! Les revues de projet ont lieu à chaque fin de phase majeure et sont souvent planifiées dès le début du projet." }, { "type": "heading", "level": 3, "id": "les-5-mauvaises-raisons-pour-lesquelles-les-gens-ne-font-pas-de-bilan-projet", "text": "Les 5 (mauvaises) raisons pour lesquelles les gens ne font pas de bilan projet" }, { "type": "paragraph", "html": "<strong>Raison 1 : Je n'ai pas le temps</strong><br>Non : \"je ne veux pas prendre le temps\", ce n'est pas pareil." }, { "type": "paragraph", "html": "<strong>Raison 2 : L'équipe est en conflit larvé</strong><br>Oui - et c'est pour ça, dans la mesure du possible, qu'il faut libérer la parole. C'est dans ces moments-là que se construit l'esprit d'équipe." }, { "type": "paragraph", "html": "<strong>Raison 3 : Le projet plus personne ne veut en entendre parler, c'est un flop</strong><br>Si vous voulez poursuivre dans cette direction et enchainer les flops... ne changez rien !" }, { "type": "paragraph", "html": "<strong>Raison 4 : Je n'ai pas de budget</strong><br>Comment ça ? Vous avez un projet de transformation stratégique et vous n'avez pas de budget prévisionnel ?" }, { "type": "paragraph", "html": "<strong>Raison 5 : Ça ne sert à rien</strong><br>Si on a fait des débriefs en continu, ça ne sert en effet peut être à rien à chaud. Mais si l'on veut faire le bilan de la valeur à moyen terme, c'est une autre vision du projet qui se dévoile." }, { "type": "heading", "level": 2, "id": "que-doit-inclure-un-bilan-de-projet", "text": "Que doit inclure un bilan de projet ?" }, { "type": "paragraph", "html": "Le contenu type d'un bilan projet \"classique\" est le suivant&nbsp;:" }, { "type": "list", "ordered": false, "items": ["<strong>Le projet a-t-il atteint ses objectifs </strong>? Respect des&nbsp;coûts, des&nbsp;délais, du&nbsp;périmètre, de la&nbsp;qualité...", "Le&nbsp;<strong>déroulement</strong>&nbsp;du projet", "La&nbsp;<strong>coordination</strong>&nbsp;des équipes", "La&nbsp;<strong>satisfaction</strong>&nbsp;du client", "Le <strong>retour d'expérience</strong>"] }, { "type": "paragraph", "html": "Traditionnellement, les DSI se concentrent sur ce premier axe. 🚫 Erreur !" }, { "type": "paragraph", "html": "Comment améliorer ce processus en tenant compte de l'évolution du rôle de la DSI, devenu partenaire business stratégique à part entière ?" }, { "type": "heading", "level": 3, "id": "comment-innover-sur-le-bilan-de-projet-revue-des-nouvelles-tendances", "text": "Comment innover sur le bilan de projet ? Revue des nouvelles tendances" }, { "type": "paragraph", "html": "Avec l'accélération digitale<strong> </strong>et la globalisation de la culture agile et l'évolution de la place du DSI au sein des organisations, des nouvelles pratiques sont apparues. Les méthodes et le rituel de bilan aussi s'est transformé ! Revue de quelques exemples issus de constats terrains et interviews de DSI." }, { "type": "heading", "level": 5, "id": "deux-bilans-valent-mieux-quun", "text": "Deux bilans valent mieux qu'un" }, { "type": "paragraph", "html": "De façon générale, la valeur ajoutée et les gains escomptés d'un projet ne sont pas visibles dès la clôture et mise en production ! Il peut être pertinent d'un point de vue marketing de la DSI entre autres de créer ce temps de reporting et de consolidation des gains visés autour de la fameuse \"business value\"<strong>. </strong>Quelle est la valeur globale générée et quels ont été les gains effectifs du projets à 6 mois / 1 an ?" }, { "type": "paragraph", "html": "Autre exemple, simplement au niveau du vocabulaire : le terme de \"bilan projet\" à fait place aux \"retrospectives\". De la même façon que dans la culture de livraison des développements, les itérations courtes sont désormais plus en vogue, plus de retrospectives intermédiaires sont réalisées." }, { "type": "paragraph", "html": "De par son récent statut de business partner à part entière, la DSI, positionnée comme leader de transformation, adresse désormais les chantiers stratégiques. Les bilans projets ne sont plus opérés en silos, mais bel et bien en interdépendances. Il s'agit se <strong>proposer aux équipes une vision globale de la cathédrale à laquelle ils ont contribués. </strong><br>Au delà du contenu du projet, on cherchera donc à replacer le projet dans son contexte global ! A-t-il contribué à l'avancement d'un ou plusieurs grands chantier stratégiques de l'organisation ?" }, { "type": "paragraph", "html": "Outre les traditionnelles questions ouvertes type les + et les - sur différents axes, on constate de plus en plus que les bilans de projets ouvrent le dialogue sur des questions plus ciblées. Par exemple : \"Si vous deviez refaire ce projet, qu'auriez-vous &nbsp;aimé savoir dès le début ?\"." }, { "type": "paragraph", "html": "Quelque chose qui permette de structurer les \"<em>lessons learned</em>\", ce qui a été vécu, digéré et qui peut ensuite être diffusé : les comportements, au-delà des outils !" }, { "type": "paragraph", "html": "Enfin, <em>remote</em> oblige, le télétravail a favorisé la réalisation de bilans de projets à distance. Peut-on faire un bon bilans de projets à distance ? Les enjeux émotionnels, personnels et collectifs sont tels qu'il serait dommage de se priver de la dynamique et de l'énergie d'un moment de partage, de vie d'équipe \"en vrai\". C'est comme proposer de prendre un verre... en visio !" }, { "type": "paragraph", "html": "Néanmoins, si vous n'avez pas le choix, l'utilisation d'outils dédiés à ce type de processus peut faciliter votre bilan. On peut citer Klaxoon, Miro ou autre. Les éditeurs l'ont bien compris en proposant quelques templates de retros. Ceci dit, vous verrez à la fin de cet article qu'un simple modèle PowerPoint de 5 pages suffit à animer ce processus." }, { "type": "heading", "level": 2, "id": "comment-organiser-un-bilan-de-projet", "text": "Comment organiser un bilan de projet ?" }, { "type": "heading", "level": 3, "id": "un-prealable-deux-phases-et-trois-dimensions", "text": "Un préalable, deux phases et trois dimensions" }, { "type": "paragraph", "html": "Un prérequis \"primordial\" : réaliser votre bilan final de projet \"à froid\". En effet, si le débriefing à chaud est indispensable il n'est pas suffisant pour ancrer des apprentissages et changements culturels durables. <br><br>Deux phases clés à respecter dans le cadre de tout bilan de projet<strong> : <br></strong>Tout d'abord <strong>on libère la parole</strong> ! Pour y parvenir, il convient entre autres de poser un cadre sécurisant, en annonçant par exemple clairement les intentions et la portée du processus : à qui sera destiné le bilan ? Une fois le cadre posé, il peut être utile de proposer un \"<em>ice breaker</em>\". Une fois les conditions réunies, on réalise le bilan à proprement parler. En utilisant l'une des grilles agiles, Lean....peu importe. (Vous découvrirez à la fin de cet article 5 modèles pour cela).<br>Enfin, on peut aller vers la phase 2 : les solutions, le plan d'action. C'est souvent cette phase qui est négligée. D'expérience, on passe trop de temps sur la phase 1." }, { "type": "paragraph", "html": "Trois dimensions du bilan projet<strong> : l'individu, le collectif, et le corporate</strong>.<br>L'évaluation individuelle est réalisée par chaque individu de l'équipe C'est un pléonasme ? En fait, pas tant que ça ! On a trop tendance à évaluer les autres. \"Tu as fait ça ...tu aurais du...\" le fameux \"Tu qui tues\" ! Idéalement, c'est à chacun de \"s'auto-débriefer\". Si on prend le temps de réaliser un bilan projet de qualité, c'est le scénario idéal." }, { "type": "paragraph", "html": "<strong>La réussite de la dimension collective </strong>peut quand à elle être évaluée par tous. Avec une place particulière au PMO / <a href=\"https://www.airsaas.io/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\">chef de projet</a>, dont c'est la responsabilité d'animer le collectif. Pour cela, il peut préparer une série de questions ouvertes, par exemple \" Si tu devais refaire ce projet qu'est-ce que tu aurais aimé savoir dès le début ?\"&nbsp;" }, { "type": "paragraph", "html": "Enfin, il restera à <strong>évaluer la dynamique de l'entreprise</strong>. Le projet a été réalisé dans un contexte stratégique, au milieu d'enjeux corporate qu'il convient d'analyser et rappeler." }, { "type": "paragraph", "html": "Tips : pour les axes 2 et 3, proposez aux parties prenantes des \"TRIP\". Comprendre un Temps de Réflexion Individuel Préalable. 1 minute de réflexion en solo, avant toute mise en commun. Cela ne vous vaccinera pas contre l'effet de groupe, mais peut permettre une plus grande variété de réponses." }, { "type": "heading", "level": 2, "id": "qui-inviter-au-bilan", "text": "Qui inviter au bilan ?" }, { "type": "paragraph", "html": "Au minimum, ce processus se tiendra en présence de votre équipe complète. Celle qui a \"contribué\" activement . La bonne pratique est de convier les personnes ayant au moins contribué à 30 / 50% de leur temps." }, { "type": "list", "ordered": false, "items": ["Le Product Owner (maître d'ouvrage, ou un chef de projet fonctionnel, selon l'organisation de l'équipe)", "Tous les membres de l'équipe", "Un facilitateur \"coach d'organisation\""] }, { "type": "heading", "level": 2, "id": "les-7-habitudes-des-bilans-projets-efficaces", "text": "Les 7 habitudes des bilans projets efficaces" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c18776e_624af58e50a0a041af40ae0e_habitudesprojet.jpeg", "alt": "Conduite du changement", "caption": "Le pouvoir des habitudes...!" }, { "type": "list", "ordered": true, "items": ["<strong>Je programme, dès le lancement, le moment du bilan à plusieurs étapes du projet</strong>, par des évaluations intermédiaires et un bilan final.", "<strong>Je confie l'animation du processus de bilan à un spécialiste du coaching / facilitateur</strong>. Qui, idéalement, n'a pas eu de rôle actif dans le projet. L'objectif est de<strong> </strong>poser un cadre sécurisant<strong>. </strong>Plus facile à dire qu'à faire ! Un bilan de qualité implique en effet franchise&nbsp;et&nbsp;honnêteté&nbsp;de la part des participants - c'est peut être là le point de vigilance essentiel dans une rétrospective efficace.", "<strong>Je prends le temps ! On ne synthétise pas 1 an de projet en 1 heure</strong> ! En fonction de votre contexte et de la taille de l'organisation, on consacrera un temps \"adapté\", idéalement équivalent à la phase de pré-cadrage.", "<strong>Je réalise deux bilans</strong> : celui du premier axe, le tryptique \"coût-qualité-délais\", et un autre une fois les gains de la transformation business ancrés, celui de la valeur ajoutée métier. C'est celui ci qui est rarement réalisé ! Nous ne sommes plus dans le bilan à chaud des retros périodiques, mais bien dans un moment d'analyse à froid.", "<strong>J'utilise des outils visuels</strong> : le management visuel, le post-it, le Klaxoon... peu importe l'outil pourvu qu'on soit dans une démarche \"légère\". Tout sauf Excel ! L'expérience utilisateur/collaborateur encore et toujours. Oui : à ce stade nul besoin de sur-détailler : on cherche à obtenir une vision globale et synthétique.", "<strong>Je suis attentif à l'ambiance de travail à la \"décontraction\". </strong>On est aussi là pour \"relâcher la pression\" en passant un moment \"apprenant\" et convivial !", "<strong>Je prévois des gratifications concrètes. </strong>Des sucreries aux cadeaux goodies, en passant par un restaurant et en allant jusqu'à une prime, la palette est large pour ne pas seulement \"payer en mots\" !"] }, { "type": "heading", "level": 2, "id": "quelles-methodes-de-bilan-de-projet-dans-le-batiment-ou-chez-les-militaires", "text": "Quelles méthodes de bilan de projet dans le bâtiment, ou chez les militaires ?" }, { "type": "paragraph", "html": "Il n'y a pas que la tech dans la vie ! En dehors de l'industrie numérique, comment procède-t-on pour analyser les écarts entre le <a href=\"https://www.airsaas.io/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\">cadrage</a>, l'exécution et la livraison ?" }, { "type": "paragraph", "html": "Sans entrer dans tous les détails, nous avons sélectionné deux exemples de pratiques en terme de bilans de projets hors IT." }, { "type": "heading", "level": 3, "id": "les-bilans-projets-dans-le-batiment", "text": "Les bilans projets dans le bâtiment ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c187774_62f3793c03388a6e90911bec_bilan-projet-btp.jpeg", "alt": "bilans projets dans le bâtiment", "caption": "Des bilans projets en continu plutôt qu'à la fin quand c'est trop tard" }, { "type": "paragraph", "html": "\"On ne prend jamais le temps de faire un retour ! Ce qui est important c'est de réaliser des bilans hebdos. En fait, on se le dit tout le temps, en permanence et on formalise une fois par mois\"." }, { "type": "paragraph", "html": "\"Ce serait interminable de faire un bilan de projet sur une opération comme un immeuble avec 5 ans de projet, plus la garantie qui court après la livraison...\"" }, { "type": "paragraph", "html": "Lionel C. Directeur de programme immobilier au sein d'un promoteur national." }, { "type": "paragraph", "html": "Si ce témoignage n'est bien sur pas représentatif d'un secteur d'activité tout entier, il est néanmoins intéressant de se rendre compte que cette industrie du bâtiment, dite plus \"mature\" que l'IT, procède de cette façon, dans une culture du bilan de projet implicite et continue." }, { "type": "heading", "level": 3, "id": "le-bilan-de-projet-chez-les-militaires", "text": "Le bilan de projet chez les militaires" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c18777a_62f37931ab1b888fe60b4f8e_bilan-projet-armee.jpeg", "alt": "bilan de projet dans l'armée", "caption": "Pas de droit à l'erreur. Chaque mission donne lieu à un débriefing individuel et collectif." }, { "type": "paragraph", "html": "Retour d'expérience de Gilles Jurine. 15 ans de service actif dans l'Armée de l'Air. Gilles a assuré les fonctions de pilote de chasse, d'instructeur et de responsable formation au sein de l'École de l'Air de Salon de Provence. \"Le meilleur débriefing après une mission, c'est lorsqu'individuellement chacun s'auto-débriefe sur la mission. Versus un débriefing descendant\". Les 5 invariants de chaque mission sont : Préparation - Briefing- Réalisation de la mission - Débriefing - Rapport de mission. Le débriefing est dit \"à chaud\", et le rapport à froid\"" }, { "type": "heading", "level": 2, "id": "5-formats-types-de-bilan-deprojet", "text": "5 formats-types de bilan de projet" }, { "type": "heading", "level": 3, "id": "1-la-grille-tout-terrain-utile-pour-toute-taille-dequipe", "text": "1. La grille \"tout terrain\", utile pour toute taille d'équipe." }, { "type": "list", "ordered": false, "items": ["Ce qui a fonctionné ☑", "Ce qui serait à améliorer ↗", "Les mercis 🙏", "Les bonnes idées💡", "Et surtout, le plan d'action post retrospective ✅"] }, { "type": "heading", "level": 3, "id": "2-le-modele-mad-sad-glad", "text": "2. Le modèle \"Mad-Sad-Glad\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c187777_62f379b252988d6b8a412bd3_glad-sad-mad-AirSaas-min.jpeg", "alt": "MAD SAD GLAD bilan projet", "caption": "Mad-Sad-Glad : bilan de projet sur un axe plus \"émotionnel\"" }, { "type": "paragraph", "html": "Le <a href=\"https://www.neatro.io/modeles-retrospective/glad-sad-mad/\" target=\"_blank\">modèle Mad Sad Glad</a> est une technique de rétrospective agile. Cette technique se concentre sur le bien-être émotionnel de l'équipe de développement de projet. Ce faisant, cela contribue à améliorer le moral de l'équipe et à créer un environnement positif." }, { "type": "paragraph", "html": "Les icônes emoji sont utilisées pour visualiser les sentiments sur les pratiques agiles. Bien que la plupart des réunions rétrospectives se fassent selon une méthode traditionnelle de tableau blanc, cette présentation vous aidera à faire passer la réunion sur les médias numériques. Le modèle PowerPoint peut également être utilisé comme thème de diapositives Google pour les réunions virtuelles." }, { "type": "heading", "level": 3, "id": "3-le-modele-4l-liked-learned-lacked-and-longed-for", "text": "3. Le modèle 4L : Liked, Learned, Lacked, & Longed For" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c187771_62f379db349867e0d82eb3c4_4L.jpeg", "alt": "Bilan projet 4L", "caption": "le 4L : un modèle très complet pour une organisation \"apprenante\"" }, { "type": "paragraph", "html": "Avec cette grille type, il s'agit de formaliser, clarifier et cartographier ce que les équipes ont aimé, appris, manqué et souhaité - plus connu sous le nom de rétrospective 4L&nbsp;! Ce format de rétrospective populaire est apprécié des agilistes et scrum masters pour sa simplicité et sa capacité à aider les équipes à établir des objectifs à court et à long terme pour des améliorations futures." }, { "type": "heading", "level": 3, "id": "4-le-daki-drop-add-keep-improve", "text": "4. Le \"DAKI\" Drop, Add, Keep, Improve" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdd070adf047149c187780_624af2076027e9da2973f3a7_DAKI.png", "alt": "bilan projet DAKI", "caption": "Le modèle de rétrospective D.A.K.I" }, { "type": "paragraph", "html": "Notre préféré ! Un modèle \"capitalisable\"." }, { "type": "heading", "level": 3, "id": "5-le-starfish", "text": "5. Le Starfish" }, { "type": "paragraph", "html": "Le <a href=\"https://blog.myagilepartner.fr/index.php/2018/07/12/starfish-retrospective/\" target=\"_blank\">Starfish</a> est une technique de cartographie conceptuelle utilisée dans le processus de rétrospective de projet agile et scrum. Il donne un aperçu général pour estimer le succès global d'un projet. Cette présentation du diagramme rétrospectif fournit une illustration de la forme en étoile de mer en 5 étapes. La forme en étoile de mer, métaphore de la technique rétrospective, engagera un public et communiquera efficacement chaque idée. La rétrospective Starfish est un outil orienté vers l'action, conçu pour inciter les participants à créer des idées positives et exploitables. Au lieu de prendre des notes sur ce qui s'est bien passé ou non, cette méthode permet d'entrer dans des détails spécifiques. Il encourage une équipe à discuter d'idées qui génèrent de la valeur." }, { "type": "paragraph", "html": "Vous le voyez : la pratique du bilan de projet s'est elle aussi transformée - influencée par l'emergence des cultures lean, agiles, digitales et le développement des processus d'intelligence collective.<br>La méthode du bilan de projet est désormais réalisée en plusieurs fois, associe généralement plus de parties prenantes et mélange souvent plusieurs entités métiers." }, { "type": "paragraph", "html": "Si vous voulez approfondir cette notion clé, poursuivez votre lecture avec l'article suivant : \"<a href=\"https://www.airsaas.io/gestion-de-projet/la-revue-de-projet\" target=\"_blank\">La revue projet : un point d'étape pour tirer les leçons de vos erreurs</a><strong>.\"</strong>" }, { "type": "paragraph", "html": "Sources et références :" }, { "type": "paragraph", "html": "(1) Source : étude nord-américaine intitulée «&nbsp;Conduire le changement&nbsp;: Pourquoi les efforts de transformation échouent&nbsp;», publiée en 1995 dans&nbsp;<em>Harvard Business Review</em> - seuls 30% des changements organisationnels réussissent." }, { "type": "paragraph", "html": "(2) Le <em>Project Management Body of Knowledge</em> (<strong>PMBOK</strong>) est le guide du Project Management Institute définissant les champs de connaissance couvrant la gestion de projet, et recensant les bonnes pratiques professionnelles en la matière." }], "toc": [{ "href": "#quest-ce-quun-bilan-projet", "label": "Qu'est-ce qu'un bilan projet ?", "level": 2 }, { "href": "#pourquoi-faire-un-bilan-projet", "label": "Pourquoi faire un bilan projet ?", "level": 2 }, { "href": "#que-doit-inclure-un-bilan-de-projet", "label": "Que doit inclure un bilan de projet ?", "level": 2 }, { "href": "#comment-organiser-un-bilan-de-projet", "label": "Comment organiser un bilan de projet ?", "level": 2 }, { "href": "#qui-inviter-au-bilan", "label": "Qui inviter au bilan ?", "level": 2 }, { "href": "#les-7-habitudes-des-bilans-projets-efficaces", "label": "Les 7 habitudes des bilans projets efficaces", "level": 2 }, { "href": "#quelles-methodes-de-bilan-de-projet-dans-le-batiment-ou-chez-les-militaires", "label": "Quelles méthodes de bilan de projet dans le bâtiment, ou chez les militaires ?", "level": 2 }, { "href": "#5-formats-types-de-bilan-deprojet", "label": "5 formats-types de bilan de projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-animer-un-comite-de-pilotage", "skip": false, "meta": { "title": "Comment animer un comité de pilotage ?", "h1": "Comment animer un comité de pilotage ?", "description": "Réussir un comité de pilotage est un objectif atteignable pour tout chef de projet si la réunion et le chef de projet sont bien préparés.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea8ab124f16482759fdc57_animer-comite-pilotage.jpg", "alt": "" }, "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "4/7/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "publishedDate": "4/7/2022" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc989902f_62ea864fdf96d8a2b9c81fd7_animer-copil-min.jpeg", "alt": "animation copil" }, { "type": "paragraph", "html": "Réussir un comité de pilotage est un objectif atteignable pour tout chef de projet si la réunion et le chef de projet sont bien préparés." }, { "type": "paragraph", "html": "Tous les fondamentaux de cette démarche sont à retrouver dans notre article de référence : <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\">Comité de pilotage ou Copil : Les bases.</a>" }, { "type": "heading", "level": 2, "id": "les-deboires-a-eviter-pendant-un-comite-de-pilotage", "text": "Les déboires à éviter pendant un comité de pilotage" }, { "type": "heading", "level": 3, "id": "les-12-ou-non-decisions", "text": "Les 1/2 ou non-décisions" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67f39e7a769ea6a386d98f58_62c297e8577b6c8fcb6f4c2c_decision-copil-min.jpeg", "alt": " 1/2 ou non-décisions" }, { "type": "paragraph", "html": "Comme vu dans un précédent article : <strong>1/2 décision = bordel²</strong> et c'est certainement le KPI numéro 1 pour le chef de projet et le Copil. Toutes les décisions à prendre sur cette réunion ont-elles été prises ? Quel serait l'impact si elles n'étaient pas prises ou que partiellement ? Le chef de projet a-t-il apporté suffisamment d'informations nécessaires permettant la prise de toutes les décisions ?" }, { "type": "paragraph", "html": "Tandis que les deux dernières questions doivent se poser <strong>pendant la préparation du Copil, </strong>la première est <strong>un enjeu d'animation et de management</strong> de la réunion. Cet article doit permettre de mettre en lumière quelques points clés à utiliser pour s'assurer que vous en obteniez les livrables nécessaires et attendus" }, { "type": "heading", "level": 3, "id": "ne-pas-savoir-trancher-ou-toujours-chercher-le-consensus", "text": "Ne pas savoir trancher ou toujours chercher le consensus" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc9899018_62c2980cbf670d5c4ae2a238_copil-trancher-min.jpeg", "alt": "Trancher en copil" }, { "type": "paragraph", "html": "D'où l'importance pour le chef de projet, avec le support du sponsor, de bien expliquer les règles du jeu. Il se peut que dans nombre d'organisations le chef de projet soit une séniorité inférieure aux tops managers de l'entreprise présents dans cette réunion du comité. Pourtant, comme dans ses interactions avec des parties prenantes plus opérationnelles sans lien hiérarchique, il devra savoir faire bouger les lignes et savoir obtenir les éléments nécessaires à la bonne exécution du projet." }, { "type": "paragraph", "html": "N'oubliez pas que le chef de projet représente quelque part le sponsor. À ce titre, il représente également la volonté du sponsor que les sujets avancent. Il doit savoir recadrer la réunion, les évènements et personnalités qui pourraient perturber le déroulement du Copil." }, { "type": "paragraph", "html": "Il doit également savoir trancher et prendre des positions (en accord avec les axes stratégiques qu'il aura défini avec le sponsor) afin de mettre le projet dans la bonne direction, et aussi pour gagner en efficacité opérationnelle. Chercher à ce que tout le monde soit d'accord, tout le temps et en même temps, est le meilleur moyen de perdre un maximum de temps ou d'arriver à des impasses de non-décisions." }, { "type": "paragraph", "html": "Il ne s'agit pas de prendre des décisions autoritaires sans considérations pour les positions des autres parties prenantes. Il s'agit de donner un cadre dans lequel se concentrer en laissant de côté les éléments superflus au regard des informations en possession du sponsor et du chef de projet dans l'intérêt global de l'entreprise. Car à la fin, ce sont les deux personnes qui sont censés avoir la vision la plus précise sur le projet." }, { "type": "heading", "level": 3, "id": "les-tensions-frustrations-et-les-non-dit", "text": "Les tensions, frustrations et les non-dit" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc9899035_62f3bde387c5546b9f7930d2_Image%25201-min.jpeg", "alt": "Ne laissez pas la frustration s'installer", "caption": "Ne laissez pas la frustration s'installer" }, { "type": "paragraph", "html": "Le point précédent, comme d'autres (relations de pouvoir, conduite du changement...) peuvent générer des tensions et des frustrations parmi les parties prenantes du projet." }, { "type": "paragraph", "html": "Il est important de pouvoir désamorcer les tensions et les frustrations <strong>en dehors du comité de pilotage</strong>, de préférence avant, afin de <strong>garantir l'efficacité et la démarche positive du projet</strong>. On ne voudrait pas que certaines frustrations ou tensions génèrent du doute quant à la faisabilité ou à l'intérêt du projet pour de mauvaises raisons." }, { "type": "paragraph", "html": "Il s'agit <strong>d'identifier en amont qu'est-ce qui génère des tensions ou frustrations</strong> et pour qui afin de mettre en place les bonnes actions : cela peut-être une prise en considération du chef de projet des objections ou points d'attentions de certaines parties prenantes, de les traiter et si le désaccord persiste d'impliquer le sponsor dans sa résolution. Ce qui n'est pas toujours facile, mais <strong>une démarche transparente et sincère du chef de projet</strong> devrait suffire à ne pas le \"griller\" opérationnellement auprès des parties prenantes." }, { "type": "paragraph", "html": "<strong>Le plus critique pourrait être les non-dits</strong>, car ils peuvent avoir un impact fort sur les risques et problèmes pesant sur le projet. Le chef de projet doit savoir instaurer un climat de confiance et savoir faire participer ceux qui restent plus en retrait, soit par pression de ses pairs, soit parce qu'il n'ose pas devant les autres top managers ou tout simplement parce qu'il n'est pas assez impliqué. <strong>Sachez creuser quand vous ressentez qu'on ne vous dit pas tout</strong>." }, { "type": "heading", "level": 3, "id": "une-mauvaise-gestion-du-temps", "text": "Une mauvaise gestion du temps" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc9899038_62f3bf05eafac550e2658985_Image%25202-min.jpeg", "alt": "le respect du timing est essentiel", "caption": "Le respect du timing est essentiel" }, { "type": "paragraph", "html": "Ce facteur pouvant facilement être évité avec une bonne préparation et un bon time-keeper, est responsable de beaucoup de non-décisions et d'une mauvaise transmission de l'information. Il est donc important d'avoir prévu le temps nécessaire pour aborder tous les points clés (n'hésitez pas d'ailleurs à faire des <strong>dry run</strong> (filage) de votre présentation et interactions si vous avez des doutes sur le timing)." }, { "type": "paragraph", "html": "Il sera également important de faire un bon time-keeping et de savoir traiter les évènements chronophage pouvant survenir dans la réunion (monopolisation de la parole, digression, comportements.... - autant de points développés plus loin dans cet article)." }, { "type": "heading", "level": 2, "id": "arriver-prepare-au-comite-de-pilotage-du-projet", "text": "Arriver préparé au comité de pilotage du projet" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc989901b_62ea877fb102af4f6ce267be_prepa-copil-min.jpeg", "alt": "Préparation copil" }, { "type": "heading", "level": 3, "id": "des-objectifs-clairs-et-bien-definis-prepares-en-amont-avec-le-sponsor", "text": "Des objectifs clairs et bien définis, préparés en amont avec le sponsor" }, { "type": "paragraph", "html": "Le chef de projet doit s'assurer qu'à la fin du Copil tous les arbitrages, décisions et déblocages de points chauds soient traités en lien avec le rôle de ce type de réunion :" }, { "type": "list", "ordered": false, "items": ["<strong>Prendre des décisions et faire des arbitrages.</strong>", "<strong>Veiller au bon déroulement du projet</strong> et s'assurer qu'il est <strong>en accord avec les stratégies globales de l'entreprise.</strong>", "<strong>Évaluer la qualité et la santé du projet à chaque réunion</strong>. Si certains problèmes doivent être améliorés, les principaux intervenants peuvent les soulever pour les résoudre.", "<strong>Donner au chef de projet le pouvoir d'agir</strong> et d'utiliser les ressources de l'entreprise pour mener l'exécution, l'avancement du projet.", "<strong>Résoudre les conflits entre départements</strong>, les problèmes liés au coût, au temps, au risque, aux ressources, à la qualité et à la portée.", "<strong>Surveiller les progrès du projet par rapport aux objectifs convenus</strong> et <strong>résoudre les problèmes</strong> qui ne permettent pas au projet de progresser à temps."] }, { "type": "heading", "level": 3, "id": "un-support-de-presentation-efficace", "text": "Un support de présentation efficace" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc9899052_62f3bfd037dc739b7a64b6cd_copil-support-min-min.jpeg", "alt": "support copil" }, { "type": "paragraph", "html": "Bien utilisé et bien fait, c'est un outil redoutable pour driver la réunion autour des points essentiels, distiller toutes les informations clés, de manière organisée et synthétique, permettant la prise de décisions et les arbitrages pendant ce même Copil." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc989904f_62f3c0900b52a6345e13d483_screen%2520home%2520intro-min.jpeg", "alt": "Vue interface AirSaas", "caption": "AirSaas - Vue Kanban des projets" }, { "type": "heading", "level": 3, "id": "les-bons-participants", "text": "Les bons participants" }, { "type": "paragraph", "html": "Quels acteurs du projet et de l'entreprise rassembler dans la réunion du comité de pilotage du projet que vous allez animer ? Voici quelques points pour assurer une prise de décision et un bon déroulement de ce moment-clé." }, { "type": "list", "ordered": false, "items": ["Les participants doivent avoir une influence, une autorité, et disposer d'un pouvoir décisionnel dans leurs différents services et sur leurs ressources.", "Les éléments moteurs du projet en interne et les évangélistes doivent y être invités.", "Les intervenants externes de compétences et d'autorité pouvant apporter leur expertise sur le projet peuvent être intéressants à intégrer à la réunion."] }, { "type": "heading", "level": 3, "id": "connaitre-la-position-des-membres-du-comite", "text": "Connaître la position des membres du comité" }, { "type": "paragraph", "html": "Une des activités du chef de projet est de connaître tout au long du projet, la position et le parti pris des membres sur les différents sujets et les points de tension/objections, et il doit avoir une stratégie pour les désamorcer (en accord avec le sponsor)." }, { "type": "paragraph", "html": "Les points précédents ne sont qu'un rappel de quelques points clés sur le sujet, si vous voulez en savoir plus, retrouvez notre article dédié : <a href=\"#\">Comment bien préparer un comité de pilotage ?</a>" }, { "type": "heading", "level": 3, "id": "pas-besoin-de-tout-savoir-pour-tout-utiliser", "text": "Pas besoin de tout savoir pour tout utiliser" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc989903b_62f3c1360d180fea011579fd_Image%25203-min.jpeg", "alt": "Illustration utiliser infos copil" }, { "type": "list", "ordered": false, "items": ["<strong>Connaître ses chiffres</strong>. Le chef de projet doit connaître l'ensemble des chiffres clés à sa disposition, et doit avoir une stratégie claire pour obtenir les chiffres manquants. En revanche, quand il s'agit de détails très opérationnels et spécifiques, il peut être imprécis, mais surtout pas faux. Savoir s'entourer et impliquer ceux qui ont la connaissance attendue est primordial.", "<strong>Connaître l'étendue technique du projet et ses points de blocages/frictions/risques</strong>. Il doit savoir les comprendre, se les faire expliquer, mais surtout être capable de les restituer et les simplifier afin d'en faciliter la compréhension par tous."] }, { "type": "heading", "level": 2, "id": "comprendre-la-dynamique-interne-et-lutiliser-a-lavantage-du-projet", "text": "Comprendre la dynamique interne et l'utiliser à l'avantage du projet" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc989903e_62ea8802bbc78240c8662362_copil-dynamique-min.jpeg", "alt": "Jeu échec" }, { "type": "paragraph", "html": "Dans une entreprise, particulièrement au-delà d'une certaine taille, il y aura quasiment toujours des enjeux de politiques internes ou à caractère individuel. Des occasions pour certains de se mettre en avant ou de retarder/bloquer l'avancement du projet si celui-ci ne sert pas leurs intérêts ou celui de leurs missions principales." }, { "type": "paragraph", "html": "Connaître et comprendre l'impact du déroulement d'un projet sur les différentes parties prenantes permettra au chef de projet d'anticiper une des principales causes d'échecs : l'humain, la peur du changement, et les relations de pouvoir." }, { "type": "paragraph", "html": "Il revient donc au chef de projet de comprendre et d'analyser ces aspects au plus tôt dans le projet, afin de désamorcer ces risques - soit en mettant en place des stratégies de win-win, soit en actionnant le sponsor sur les aspects les plus bloquants afin qu'il remette l'intérêt global de l'entreprise au centre de la démarche." }, { "type": "paragraph", "html": "Ne pas prendre personnellement les réactions des éléments freins est pour le chef de projet une opportunité d'utiliser leurs objectifs personnels de manière positive, s'il arrive à les aligner avec l'intérêt du projet." }, { "type": "heading", "level": 2, "id": "communiquer-au-bon-niveau", "text": "Communiquer au bon niveau" }, { "type": "heading", "level": 3, "id": "connaissez-votre-audience", "text": "Connaissez votre audience" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc9899055_62f3c1a064f6eb72b7266143_Image%25204-min.jpeg", "alt": "Le bon message, le bon ton, le bon niveau de détail", "caption": "Le bon message, le bon ton, le bon niveau de détail" }, { "type": "paragraph", "html": "Il est évident que le chef de projet doit adapter son discours et le contenu du comité en fonction de son audience et de ce dont les membres ont besoin comme niveau et quantité d'information pour prendre des décisions." }, { "type": "paragraph", "html": "Sachant qu'il y a souvent des membres du Codir et/ou des top managers de l'entreprise dans le Copil, on privilégiera une présentation un peu plus \"high level\" en remettant le cadre du projet et la présentation au niveau des objectifs, enjeu et stratégie de l'entreprise. On évitera donc de trop rentrer dans les détails en donnant assez de contexte tout en allant droit au bout vers les arbitrages." }, { "type": "heading", "level": 3, "id": "ne-cristallisez-pas-sur-les-details-et-les-frustrations", "text": "Ne cristallisez pas sur les détails et les frustrations" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc989904c_62ea8874f01323dfddc058c6_details-copil-min.jpeg", "alt": "Illustration neige" }, { "type": "paragraph", "html": "La gestion des détails doit rester dans le champ d'action opérationnel. Le rôle du chef de projet et de bien les synthétiser pour mettre l'accent sur ce qui a bien fonctionné et sur les facteurs bloquants. Juste assez pour comprendre une problématique, ni plus ni moins." }, { "type": "paragraph", "html": "Les top managers et les membres du comité de direction sont là pour prendre des décisions dimensionnantes sur la direction du projet ou l'accès aux ressources, et comprendre pourquoi les arbitrages sont critiques." }, { "type": "paragraph", "html": "Donc sachez regrouper les détails et frustrations métiers derrière un plus gros enjeu et derrière un arbitrage plus important, afin que la gestion des détails en découle et soit évidente pour le chef de projet." }, { "type": "heading", "level": 3, "id": "ne-soyez-pas-trop-dans-la-technique", "text": "Ne soyez pas trop dans la technique" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc9899041_62ea88a8f0132360adc059f9_details-tech-copil-min.jpeg", "alt": "image Tech data centric" }, { "type": "paragraph", "html": "A moins que vous ayez envie de perdre une partie ou tout le monde en route et que les membres du comité de pilotage repartent avec plus de questions que de réponses, la bonne approche ici pour le chef de projet et de savoir vulgariser les aspects techniques pour aller à l'essentiel, tout en donnant suffisamment d'information pour ne pas donner l'impression que les informations ne sont pas fiables /abouties." }, { "type": "paragraph", "html": "Le chef de projet a le droit d'être imprécis sur certains aspects techniques, mais il n'a pas le droit d'être faux. Prendre des décisions sur des données ou informations fausses se retrouvera toujours en bout de chaîne comme un risque important ou une cause d'échec. Cette notion devrait s'étendre à tous les membres du Copil, et le chef de projet doit toujours croiser les informations de plusieurs sources avec expertise afin de pouvoir recadrer ou faire préciser les mauvaises interventions." }, { "type": "heading", "level": 3, "id": "sachez-lier-pour-votre-audience-loperationnel-a-la-strategie-big-picture", "text": "Sachez lier pour votre audience l'opérationnel à la stratégie \"big picture\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc9899106_62f3c2112e7c8d1f83911955_image%25205.jpeg", "alt": "To the moon !", "caption": "To the moon !" }, { "type": "paragraph", "html": "Pour bien animer un comité de pilotage, le project manager doit toujours se poser la question de quelle information et quel niveau d'information son audience à besoin, et à quel niveau les membres de son audience peuvent et ont l'habitude d'opérer. Et sans remettre les détails dans le contexte de l'enjeu stratégique ou de la vision macro, rien ne pourrait permettre à tous les membres de comprendre la pertinence pour eux de rentrer dans des détails d'exécution." }, { "type": "paragraph", "html": "Le project manager doit être force de proposition en matière de solutions qui s'intègrent dans la vision globale. Il doit être capable de participer, déclencher et prendre des positions pas seulement sur les aspects opérationnels, mais aussi dans des échanges plus \"high level\". Son rôle n'est pas d'arbitrer, mais de faire un cadrage, de faciliter et de mettre en position favorable les autres membres pour arbitrer." }, { "type": "heading", "level": 3, "id": "investissez-dans-le-positif", "text": "Investissez dans le positif !" }, { "type": "paragraph", "html": "Dans un comité de pilotage et même dans cet article, il est difficile de parler de gestion de projet sans parler de gestion des risques et facteurs bloquants. En revanche même si cela fait partie du jeu, votre comité de pilotage peut-être bien différent de ce qui se fait ailleurs si vous faites la promotion des accomplissements et des succès." }, { "type": "paragraph", "html": "Pensez à valoriser ce qui marche et ce qui a fonctionné, ritualisez les bravos et les mercis, c'est l'occasion de mettre en valeur les points forts de l'entreprise et encourager la bonne implication et les bonnes dynamiques et l'impact positif sur l'enjeu du projet et le résultat pour l'entreprise ainsi que pour les utilisateurs finaux. Cela donnera plus de vigueur et de sens à vos équipes projets, insufflera un bien meilleur état d'esprit et pérennisera l'engagement des parties prenantes." }, { "type": "heading", "level": 2, "id": "ne-pas-laisser-dobjections-sans-reponses", "text": "Ne pas laisser d'objections sans réponses" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc98990fd_62ea890cba10f58590f90f0b_feedback-copil-min.jpeg", "alt": "Traitement objections copil" }, { "type": "heading", "level": 3, "id": "connaitre-les-objections-a-lavance-et-sachez-reporter-a-plus-tard-la-reponse-aux-objections-secartant-de-lordre-du-jour", "text": "Connaître les objections à l'avance et sachez reporter à plus tard la réponse aux objections s'écartant de l'ordre du jour" }, { "type": "paragraph", "html": "Pour plus d'informations sur cette partie vous pouvez consulter l'article \"<a href=\"http://www.airsaas.io/fr/gestion-de-projet/preparer-comite-de-pilotage-d-un-projet\" target=\"_blank\">Comment préparer un comité de pilotage </a>?\" et \"<a href=\"#\">Copil projet, 5 astuces pour que tout se passe bien</a>\"." }, { "type": "heading", "level": 3, "id": "gerer-quand-la-reunion-derape", "text": "Gérer quand la réunion dérape" }, { "type": "paragraph", "html": "En cas de difficultés trop importantes (agressivité, refus d'avancer, tensions palpables) n'hésitez pas ! c'est le moment de faire une pause, d'analyser la situation et de prendre des actions correctives avec le sponsor." }, { "type": "heading", "level": 4, "id": "comment-gerer-les-personnes-negatives", "text": "Comment gérer les personnes négatives" }, { "type": "paragraph", "html": "Sans rentrer dans une liste trop exhaustive, on peut citer trois cas récurrents." }, { "type": "paragraph", "html": "Pour les personnes qui ont tendance à monopoliser la parole ou à digresser, n'hésitez pas à recadrer les propos en les recentrant sur les objectifs de la réunion et mettre l'accent sur le fait que vous avez entendu et que vous traiterez ces points ultérieurement. Si ce n'est pas suffisant, profitez d'un propos de cette personne pour donner la parole à un autre membre - de préférence un allié qui reviendra naturellement dans le cadre de la réunion." }, { "type": "paragraph", "html": "Pour les personnalités agressives ou opposantes en tout point, apaisez les débats en recentrant sur les éléments factuels et objectifs et proposez au plus récalcitrant de proposer des solutions à leur propre objections afin de remettre une démarche constructive." }, { "type": "paragraph", "html": "Si le seul objectif est de déstabiliser l'animateur ou la réunion et qu'ils ne souhaitent pas jouer le jeu en étant force de proposition, rappelez avec calme et bienveillance que celui qui ne fait pas partie de la solution fait donc partie du problème." }, { "type": "paragraph", "html": "Pour les personnes plus effacées qui pourraient donner lieu à des non-dits, il convient de les inciter à s'exprimer en mettant l'accent sur la valeur de leurs participations et leurs compétences." }, { "type": "heading", "level": 4, "id": "avoir-des-allies", "text": "Avoir des alliés" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc989905f_62f3c27224b1d51fbcc57f23_Image%25206-min.jpeg", "alt": "Cherchez du soutien", "caption": "Cherchez du soutien" }, { "type": "paragraph", "html": "L'animateur et/ou le chef de projet ne sera pas toujours dans la position idéale pour traiter toutes les objections ou gérer toutes les attitudes et comportements n'allant pas dans l'intérêt du projet. Pour cela il doit pouvoir s'appuyer sur d'autres membres plus légitimes dans certaines situations pour pouvoir prendre position et désamorcer des situations." }, { "type": "paragraph", "html": "En outre, le chef de projet doit avoir autour de lui dans l'équipe projet des éléments moteurs qui partagent la même vision et qui feront en sorte de pouvoir aider le projet. Plus le chef de projet aura le soutien de personnes influentes dans l'entreprise, plus il aura des leviers d'actions intéressants pour faire avancer le projet et ne pas se griller avec les membres opérationnels ou les métiers." }, { "type": "heading", "level": 2, "id": "si-vous-ne-faites-pas-partie-de-la-solution-vous-faites-partie-du-probleme", "text": "Si vous ne faites pas partie de la solution, vous faites partie du problème" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc9899102_62ea89db5bd878780e413c4f_copil-solution-pb-min.jpeg", "alt": "Résolution risques copil chef de projet" }, { "type": "paragraph", "html": "Et pour trouver des solutions encore faut-il qu'il y ait des problèmes et savoir bien les identifier." }, { "type": "paragraph", "html": "Si il y a bien un champ de compétences dans lequel le chef de projet devrait exceller, c'est bien dans l'identification et la résolution des risques et des problèmes. Les risques sont des problèmes en devenir et bien anticiper les problèmes clés est la compétence numéro 1 du chef de projet (soit \"lever les loups\")." }, { "type": "paragraph", "html": "Rien d'extraordinaire ou de \"cutting edge\" dans l'idée de mélanger \"chef de projet\" avec \"gestion des risques\" et \"problem solving\"" }, { "type": "paragraph", "html": "Le secret ici c'est d'adopter une approche la plus pragmatique possible en allant à l'essentiel. Plus le chef de projet écartera le superflue du projet, plus il limitera les facteurs de risques et les problèmes rencontrés. Soumettez chaque nouvel aspect/changement/fonction en plus dans votre projet avec une réflexion de risk/reward." }, { "type": "paragraph", "html": "Et si le chef de projet ne peut pas avoir de contrôle sur le risque/problème, alors il doit être proactif dans sa recherche de solution pour annuler la conséquence si le problème se manifeste et s'appuyer sur son sponsor ou sur le comité en cas de décisions difficiles à prendre." }, { "type": "paragraph", "html": "<strong>Quel rapport avec l'animation du comité de pilotage ? </strong>Car tous les problèmes ont tendance à se cristalliser pendant ces réunions, et le rôle du chef de projet n'est pas seulement de faire remonter les problèmes identifiés, mais il se doit d'être force de proposition et avoir des options et stratégies à soumettre au sponsor ou au comité de pilotage pour les résoudre." }, { "type": "heading", "level": 2, "id": "les-bonnes-pratiques-et-la-bonne-attitude-pour-animer-votre-comite-de-pilotage", "text": "Les bonnes pratiques et la bonne attitude pour animer votre comité de pilotage" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc9899029_62ea8a14bbc7822eed6635a0_copil-bestpractice-min.jpeg", "alt": "attitude copil" }, { "type": "heading", "level": 3, "id": "du-dynamisme", "text": "Du dynamisme" }, { "type": "paragraph", "html": "Avez-vous déjà été dans une réunion où vous avez l'impression qu'elle ne se termine jamais ? Où vous trouvez que c'est lent.. trop lent... et vous êtes déjà en train de penser à tout ce que vous auriez pu faire, faire avancer, si seulement vous n'étiez pas coincé dans cette réunion dans laquelle l'animateur vous endort avec des phrases à rallonge, alors que dès la moitié de la phrase vous aviez déjà compris où il voulait vous amener ? Ce n'est pas toujours qu'il aime s'écouter parler, mais peut-être est-ce parce qu'il ne communique pas efficacement et au bon niveau." }, { "type": "paragraph", "html": "Le chef de projet 2.0 ne doit pas être cette personne là. Il sait qu'il rassemble dans le Copil des tops managers de l'entreprise, somme toute, suffisamment bien câblés, et par ailleurs suffisamment occupés, pour que tout le monde apprécie qu'on aille droit au but, avec énergie et des phrases claires et concises. La préparation du <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comite-de-pilotage-definitions-et-incomprehensions\" target=\"_blank\">comité de pilotage</a> aidera le chef de projet à gagner de cette efficacité attendue et appréciée." }, { "type": "paragraph", "html": "<strong>Le niveau d'énergie du comité de pilotage dépendra du niveau d'énergie imprimé par l'animateur. </strong>Comme nous le savons aujourd'hui les émotions et attitudes sont contagieuses, et les membres du Copil se calqueront sur l'énergie de l'animateur. Et s'il est mou, alors la dynamique de la réunion sera molle est pesante, voire même déclenchera l'ennui et l'inattention. Un tel leadership n'est pas toujours facile, mais cela s'apprend ou s'acquiert avec un peu d'expérience et en adoptant les quelques astuces suivantes." }, { "type": "paragraph", "html": "Parmi ces astuces, notez que les contenus, sujets, et moments collaboratifs doivent s'enchainer de manière fluide et logique. Par ailleurs, n'hésitez pas à faire preuve d'originalité en optant par exemple pour des supports de présentation collaboratifs, ou en changeant de cadre, à l'instar de cette bonne vieille salle de réunion." }, { "type": "heading", "level": 3, "id": "une-gestion-du-temps-optimale", "text": "Une gestion du temps optimale" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e9669d963bc989905b_62ea8a49925c8b1ad30e9706_copil-gdt-min.jpeg", "alt": "Gestion temps copil" }, { "type": "heading", "level": 4, "id": "qui-est-le-bon-time-keeper", "text": "Qui est le bon time-keeper ?" }, { "type": "paragraph", "html": "Dans l'idéal il s'agit d'une autre personne que le chef de projet, ce qui lui permettra de se concentrer sur l'animation du comité de pilotage et de se libérer de cette charge mentale afin de se concentrer sur le contenu des échanges et sur le déroulement de la réunion." }, { "type": "paragraph", "html": "Cette autre personne doit être un élément moteur impliqué du projet et bien saisir tout l'enjeu de pouvoir aborder tous les points essentiels de l'ordre du jour. Un allié du chef de projet qui a de l'influence ou la sympathie des membres du comité de pilotage." }, { "type": "paragraph", "html": "Cela permettra d'ailleurs de faciliter l'animation du chef de projet si il n'est pas l'unique personne à devoir interrompre ou recadrer des participants." }, { "type": "heading", "level": 4, "id": "comment-bien-faire-respecter-le-temps-imparti", "text": "Comment bien faire respecter le temps imparti ?" }, { "type": "paragraph", "html": "En plus des éléments cités précédemment sur les dérapages et la monopolisation de la parole, il est conseillé de prendre une marge de manœuvre dans le temps prévu pendant la préparation afin d'absorber certains débordements, soyons clairs, un Copil c'est comme un projet même très bien préparé il peut toujours y avoir des imprévus, alors autant les prévoir et si tous les points ont été traités avant la fin de la réunion, personne n'aura de ressenti négatif sur le fait d'avoir été efficace, bien au contraire." }, { "type": "heading", "level": 3, "id": "noter-les-moments-et-actions-cles-ainsi-que-les-decisions", "text": "Noter les moments et actions clés ainsi que les décisions" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d866e8669d963bc989902c_62ea8a82700b63fab262f250_copil-moments-min.jpeg", "alt": "Prise de notes copil" }, { "type": "heading", "level": 4, "id": "definir-qui-prend-les-notes-et-dans-quel-format", "text": "Définir qui prend les notes et dans quel format" }, { "type": "paragraph", "html": "L'animateur peut difficilement animer le comité et prendre des notes en même temps. L'idéal est de trouver quelqu'un de rigoureux et promoteur du projet afin d'être sûr que les informations seront là. N'hésitez pas à lui fournir une trame pour la prise de note qui correspond au plan du compte rendu de la réunion utilisé dans votre entreprise." }, { "type": "heading", "level": 4, "id": "pourquoi-prendre-des-notes", "text": "Pourquoi prendre des notes ?" }, { "type": "paragraph", "html": "Il est important de prendre des notes pour montrer que l'avis et la participation de chacun a été prise en considération et également afin de formaliser les décisions qui ont été prises, les prochaines décisions à prendre ainsi que les prochaines étapes et qui doit les réaliser pour les prochains jalons du projet." }, { "type": "paragraph", "html": "Cela envoie un message de rigueur et d'efficacité et permet au chef de projet de bien dérouler les prochaines étapes, car le compte rendu joue aussi le rôle d'un contrat moral sur lequel s'appuyer." }, { "type": "paragraph", "html": "L'amélioration du processus d'animation de comité de pilotage est une pratique continue. Prochaine étape décrypter le process de décision de cette instance pour être au clair sur <a href=\"/gestion-de-projet/comment-decider-en-copil\">Comment décider en copil ?</a>" }], "toc": [{ "href": "#les-deboires-a-eviter-pendant-un-comite-de-pilotage", "label": "Les déboires à éviter pendant un comité de pilotage", "level": 2 }, { "href": "#arriver-prepare-au-comite-de-pilotage-du-projet", "label": "Arriver préparé au comité de pilotage du projet", "level": 2 }, { "href": "#comprendre-la-dynamique-interne-et-lutiliser-a-lavantage-du-projet", "label": "Comprendre la dynamique interne et l'utiliser à l'avantage du projet", "level": 2 }, { "href": "#communiquer-au-bon-niveau", "label": "Communiquer au bon niveau", "level": 2 }, { "href": "#ne-pas-laisser-dobjections-sans-reponses", "label": "Ne pas laisser d'objections sans réponses", "level": 2 }, { "href": "#si-vous-ne-faites-pas-partie-de-la-solution-vous-faites-partie-du-probleme", "label": "Si vous ne faites pas partie de la solution, vous faites partie du problème", "level": 2 }, { "href": "#les-bonnes-pratiques-et-la-bonne-attitude-pour-animer-votre-comite-de-pilotage", "label": "Les bonnes pratiques et la bonne attitude pour animer votre comité de pilotage", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-avoir-une-gestion-de-portefeuille-projet-pragmatique-en-2022", "skip": false, "meta": { "title": "Comment avoir une gestion de portefeuille projet pragmatique ?", "h1": "Comment avoir une gestion de portefeuille projet pragmatique ?", "description": "Comment avoir une gestion de portefeuille projet pragmatique en 2022 ? Découvrez les 6 leviers clés pour moderniser votre PPM : collaboration, reporting, sélection de projets, workflow et plus.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bcd89ab56aa1142c774d7_ppm-pragmatique-min.jpg", "alt": "Gestion de Projets" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "29/8/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "29/8/2022" }, "blocks": [{ "type": "paragraph", "html": "Il y aura toujours <strong>plus de projets que de ressources</strong> pour y travailler&nbsp;!" }, { "type": "paragraph", "html": "En tant que PMO/DSI/Directeur de transformation, il est une tâche qui vous tient sûrement à cœur si vous êtes passionné par votre métier : celle de la <strong>gestion des ressources et du portefeuille de projets</strong>." }, { "type": "paragraph", "html": "En <strong>2006</strong>, le Project Management Institute la définissait comme étant la <strong>gestion centralisée des processus</strong>, méthodes et technologies d'un ensemble de projets. Une activité permettant d'optimiser les arbitrages et leur planification, tout en évaluant le niveau de risque des projets et leur viabilité financière." }, { "type": "paragraph", "html": "🚫 <strong>STOP</strong> !" }, { "type": "paragraph", "html": "Oui, à l'époque des roadmap de SI à cinq ans, des logiques d'affrontement IT/métiers, une <strong>vision principalement financière</strong> du pilotage de portefeuille de projets a longtemps été la norme." }, { "type": "paragraph", "html": "Mais, à partir d'une certaine taille d'entreprise, d'un <strong>certain volume</strong> de projets transverses, de l'arrivée de changements internes ou externes rapides dans les organisations. <strong>Le \"sur contrôle\" ne fonctionne plus ! La gestion de portefeuille a besoin de</strong> passer <strong>d'une gestion parfois bureaucratique et trop centralisée à un management libéré, plus collaboratif et rapide pour gérer</strong> une démarche <strong>d'innovation et transformation qui délivre efficacement et en continu</strong>." }, { "type": "paragraph", "html": "Dans les lignes qui suivent on va s'intéresser <strong>à ce qui a changé et ce qui peut mieux fonctionner dans la gestion de portefeuille projets actuelle.</strong> On vous dit tout sur l'art et la manière de moderniser cette démarche. Pour <strong>investir en amont afin de moins subir en aval. Objectif : modernisation &amp; efficience !</strong>" }, { "type": "paragraph", "html": "Un dernier mot avant de commencer... par <strong>pragmatisme</strong>, qu'est-ce qu'on entend ? Pour résumer...c'est <strong>l'inverse de théorique</strong> ou abstrait ! Ce sont des pratiques venant <strong>du terrain,</strong> permettant de <strong>dépenser ses ressources intelligemment,</strong> avec une <strong>approche éprouvée</strong> qui puisse être réadaptée <strong>dans votre contexte</strong> d'innovation et transfo." }, { "type": "heading", "level": 2, "id": "ppm-la-fin-du-domaine-reserve", "text": "PPM : la fin du \"domaine réservé\"" }, { "type": "paragraph", "html": "Longtemps ce processus <strong>était le domaine d'un expert</strong> qui assumait la création et l'animation d'une feuille de route pour toute une entreprise !" }, { "type": "paragraph", "html": "Planification, exécution, reporting et analyses, gestion des demandes, des ressources, suivi et réalisation, des bénéfices...La démarche de PPM était parfois outillée avec une sorte <strong>d'ERP projet \"tout en un\" assez rigide</strong>, si ce n'était pas excel ou power point !" }, { "type": "paragraph", "html": "Ce processus de gestion de portefeuille <strong>répondait</strong> plus <strong>à un besoin de vision et de contrôle</strong> \"central\". Une vision orientée DAF en somme :-)" }, { "type": "paragraph", "html": "Le <strong>bilan</strong> de cette approche ? <strong>Le PPM était devenu un \"truc d'expert\"</strong>, un outil de gestion des ressources n'offrant pas assez de visibilité sur l'exécution de la feuille de route à toutes les parties prenantes impliquées dans la transformation de chaque entreprise." }, { "type": "paragraph", "html": "Disons-le simplement, cette gestion de portefeuille marchait, pour une partie de l'entreprise seulement...et dans le cadre d'une gestion de projets assez longue." }, { "type": "paragraph", "html": "Puis, la technologie est devenue le vecteur majeur de l'agilité et de l'innovation. <strong>La digitalisation est arrivée</strong>...et avec elle, un flux croissant de projets plus complexes, plus courts, plus transverses, qui ont tendu à <strong>rendre obsolète l'approche de planification centrale</strong>." }, { "type": "paragraph", "html": "De plus en plus d'outils saas spécialisés ont fait leur apparition, sur la gestion de tâches, le tracking de temps, la finance, etc. Ils ont clairement apporté <strong>une expérience utilisateurs meilleure</strong> que celle proposée par les logiciels ERP PPM tout en un." }, { "type": "paragraph", "html": "Les métiers se sont mis à utiliser massivement ces logiciels concurrents des outils ERP/PPM. Pour leur nette valeur ajoutée, allant même jusqu'à un \"shadow-it\" omniprésent et plus ou moins encadré." }, { "type": "paragraph", "html": "Oui, et au-delà de tel ou tel logiciel, le management de l'innovation et des portefeuilles de projets a changé sur de nombreux plans :" }, { "type": "list", "ordered": false, "items": ["La <strong>culture de la collaboration et de la transparence</strong> est devenue centrale&nbsp;! Versus, une focalisation sur la gestion des ressources et du plan de charge uniquement", "«&nbsp;L'adaptation&nbsp;» avec des itérations aux résultats rapides a remplacé la «&nbsp;sur anticipation&nbsp;»", "Le pilotage par la «&nbsp;valeur&nbsp;» a remplacé le pilotage «&nbsp;par le budget&nbsp;» uniquement", "Le <strong>coût de l'inaction</strong> / le \"Risk Of Ignoring\" est maintenant beaucoup plus <strong>reconnu</strong>.", "L'<strong>importance de la confiance et le besoin d'impliquer les collaborateurs</strong> est un enjeu partagé et compris.", "La <strong>décentralisation de l'IT au profit des métiers</strong> fait partie des tendances fortes"] }, { "type": "paragraph", "html": "Le diagnostic est en partie posé." }, { "type": "paragraph", "html": "Mais <strong>quels sont les leviers prioritaires à activer ? Comment faciliter la gestion initiale et continue</strong> d'un portefeuille de projets qui ne parte pas à la dérive en continu ? Comment aider l'organisation à prendre des décisions rapidement ? Faire en sorte que les équipes soient motivées ?" }, { "type": "paragraph", "html": "On a relu notre documentation, interrogé nos experts...et on vous propose de parcourir cette <strong>sélection de convictions</strong> !" }, { "type": "heading", "level": 2, "id": "six-leviers-pour-une-gestion-de-portefeuille-de-projets-pragmatique-en-2022", "text": "Six leviers pour une gestion de portefeuille de projets pragmatique en 2022" }, { "type": "heading", "level": 3, "id": "levier-1-maximiser-la-dimension-collaborative-versus-le-controle", "text": "Levier 1 : Maximiser la dimension collaborative versus le contrôle" }, { "type": "paragraph", "html": "Une gestion de portefeuille de projets qui avance, impliquera de <strong>créer et maintenir les conditions d'une culture de coopération, de transparence et de co-responsabilité forte</strong> entre toutes les équipes concernées." }, { "type": "paragraph", "html": "L'enjeu sera de <strong>passer d'une gestion centrée sur le contrôle du budget et des ressources à une gestion qui maximisera collaboration et engagement</strong> des parties prenantes." }, { "type": "paragraph", "html": "Voici quelques <strong>pratiques à considérer dans ce premier levier pour maximiser la collaboration</strong> et la confiance versus le contrôle :" }, { "type": "list", "ordered": false, "items": ["<strong>Proposer un espace collaboratif incorporé directement dans son outil PPM</strong>."] }, { "type": "paragraph", "html": "<strong>Grâce à une plateforme intégrant directement un espace collaboratif</strong>, on <strong>facilitera la libération de la parole.</strong> Vous pourrez consolider la remontée des points d'attentions, la remontée des décisions, des points de succès. Cela n'a peut-être l'air de rien ?. Mais cela peut <strong>vraiment simplifier son quotidien</strong> et celui de ses équipes !" }, { "type": "list", "ordered": false, "items": ["<strong>Utiliser la confiance dans les jalons</strong>... !"] }, { "type": "paragraph", "html": "Quand on devient PMO/DSI/Manager de portefeuille de projet IT, un des premiers écueils possibles est celui de <strong>tomber dans le micromanagement</strong>. De vouloir trop contrôler l'exécution du projet par les équipes." }, { "type": "paragraph", "html": "Pour vous aider à continuer à parier sur la confiance. Faites-vous aider par une plateforme." }, { "type": "paragraph", "html": "Avec AirSaas la notion de jalon (une <strong>étape clé à réussir dans le projet pour une date</strong>) comporte des attributs : le <strong>responsable, le poids et le degré de confiance.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bc84f15bab8397943a9cd_confiance-jalons.png", "alt": "Capture écran AirSaas de la fonction degré de confiance dans le jalon", "caption": "Degré de confiance dans le jalon : une innovation qui facilite la gestion du portefeuille" }, { "type": "paragraph", "html": "<strong>Pour suivre la progression de votre portefeuille vous pouvez</strong> regarder la progression de chacun des projets à travers la progression déclarée par le chef de projet affichée ensuite sur votre page portfolio en bas de chaque carte projet." }, { "type": "paragraph", "html": "Vous avez également la possibilité de suivre <strong>la progression des jalons</strong>. Grâce à un calcul automatique prenant en compte les jalons réalisés et leur poids." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bc8b60b11552aa775c820_suivi-jalons-airsaas.png", "alt": "Capture écran AirSaas - Suivi de progression projet", "caption": "Suivre l'exécution et le delivery du portefeuille avec les jalons pour limiter l'effet dérive en continu." }, { "type": "paragraph", "html": "Pour résumer ce premier levier, on ne résiste pas au plaisir de partager <strong>une citation qu'on adore.</strong> Celle de Ludovic Lajoie, issue d'un commentaire sur un post Linkedin AirSaas." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62eae08ccb335202a139b71a_gantt-rassure-equipe-assure.png", "alt": "Commentaire issu d'un post linkedin AirSaas." }, { "type": "paragraph", "html": "L'objectif est bien de <strong>dépasser les silos horizontaux</strong> : entre équipes et directions <strong>et les silos verticaux</strong> en termes de décisions." }, { "type": "paragraph", "html": "Oui...<strong>la coopération ne se décrète pas !</strong> Elle s'encourage, se facilite. On est bien sur des aspects culturels et humains qui prennent du temps." }, { "type": "heading", "level": 3, "id": "levier-2-une-autre-philosophie-du-reporting-pour-reduire-la-fatigue-cognitive", "text": "Levier 2 : Une autre philosophie du reporting pour réduire la fatigue cognitive !" }, { "type": "paragraph", "html": "Plus l'entreprise et son portefeuille de projets grandissent plus <strong>la capacité de garder un niveau de communication claire, cohérente, simple d'accès pour tout le monde est vital.</strong>" }, { "type": "paragraph", "html": "Que ce soit le directeur général qui ne comprend plus très bien ce que lui remontent les équipes, entre les membres du comité de direction qui ne parlent plus le même langage ou les équipes entre elles qui <strong>essayent de se synchroniser tant bien que mal.</strong>" }, { "type": "paragraph", "html": "Problème : L'information, <strong>les données du portefeuille sont disséminées</strong> dans le système d'information et les différents points d'avancements." }, { "type": "paragraph", "html": "Du coup <strong>la forme bloque le fond</strong> et tout rame." }, { "type": "paragraph", "html": "On pourrait penser que c'est accessoire, mais c'est en réalité <strong>l'un des éléments fondamentaux d'une prise de décision éclairée en haut lieu</strong>. La plupart du temps la décision est un arbitrage. Comment arbitrer entre A, B et C si on ne me présente pas une information comparable ?" }, { "type": "paragraph", "html": "On a bel et bien <strong>besoin d'uniformiser le reporting</strong>." }, { "type": "list", "ordered": false, "items": ["Uniformiser la forme, c'est dire ok : on va <strong>se faciliter la vie pour se comprendre</strong> quel que soit l'enjeu que nous affrontons. En passant ça <strong>réduit aussi la fatigue cognitive</strong> de tout le monde."] }, { "type": "list", "ordered": false, "items": ["Choisir un outil doté d'une <strong>interface suffisamment intuitive</strong> pour <strong>faciliter la collaboration entre les profils techniques et business</strong>.‍", "Si l'on souhaite en effet impliquer les collaborateurs d'une entreprise sur des sujets aussi techniques que ceux traités par la DSI, mieux vaut le faire sur une interface qui leur plaira ! Et qui les incitera à \"<strong>jardiner leurs données</strong>\" !", "Le second avantage est d'<strong>augmenter le taux d'adoption de ces PPM.</strong> Les collaborateurs ne mettront que quelques heures à se roder à l'utilisation de ces nouveaux logiciels plutôt que quelques jours. Ce qui peut être un levier très intéressant si l'objectif est de mobiliser rapidement."] }, { "type": "paragraph", "html": "Bonus : en <strong>simplifiant la collecte d'information</strong> et en <a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">automatisant le reporting, AirSaas</a> vous permettra d'<strong>avoir le temps d'aider les chefs de projets dans leurs enjeux</strong> et de faciliter la collaboration entre les équipes." }, { "type": "heading", "level": 3, "id": "levier-3-un-processus-de-selection-pour-choisir-les-vrais-projets-interessants-pour-lentreprise", "text": "Levier 3 : un processus de sélection, pour choisir les vrais projets intéressants pour l'entreprise" }, { "type": "paragraph", "html": "En préparant cet article, nous avons interrogé des pilotes de transformations en entreprises et des DSI. L'un d'entre eux, merci encore Frédéric :-) nous a confié son avis sur cette question de la gestion de portefeuille de projets pragmatique." }, { "type": "quote", "text": "Le pragmatisme ? C'est dépasser les intérêts&nbsp;! L'enjeu c'est de savoir comment tu peux choisir les vrais projets intéressants pour l'entreprise. Faire en sorte de \"passer du client roi à l'entreprise reine\". Pour dépasser les intérêts individuels, on peut adopter une approche collaborative, visuelle, et agile pour créer les conditions d'un dialogue, pour refaire du sens commun et engager les acteurs de l'entreprise à s'associer réellement sur les projets intéressant non pas pour chaque direction mais pour toute l'entreprise.", "author": "Frédéric Dufau-Joël — DSI pendant 20 ans - Coach interne La boîte à Outils Groupe SAMSE" }, { "type": "paragraph", "html": "Son retour d'expérience est passionnant. Dans son entreprise en partie agile et libérée, ils ont en quelque sorte : <strong>implémenté une limitation du travail en cours basée sur la discussion.</strong>" }, { "type": "paragraph", "html": "Tout l'enjeu est bien en amont. <strong>Choisir c'est avancer !</strong> Même si cela semble une évidence, à l'heure de l'hyper inflation de projets il semble plus qu'utile de se le rappeler !" }, { "type": "paragraph", "html": "En prime cela permettra à vos chefs de projets d'être moins pollués par des chantiers \"toxiques.\"<br>Cela rappellera aussi à certains <strong>un principe universel</strong> bien connu dans la tech et l'informatique : <strong>le GIGO pour Garbage IN - Garbage OUT !</strong>" }, { "type": "heading", "level": 3, "id": "levier-4-designer-votre-workflow-ppm-pour-simplifier-la-prise-dinitiatives-et-de-decisions", "text": "Levier 4 : Designer votre workflow PPM pour simplifier la prise d'initiatives et de décisions" }, { "type": "paragraph", "html": "80 % des projets n'ont pas besoin d'un planning de Gantt ! L'idée est bien d'investir dans la réflexion pour créer plusieurs workflows pour chaque type de portefeuilles de projets ! De ne pas verser dans <strong>le syndrome du canon pour la mouche</strong>." }, { "type": "paragraph", "html": "En s'inspirant par exemple du principe du \"T-shirt sizing agile\"...pour <strong>commencer par réfléchir sur les types de projets qui existent dans votre portefeuille de projets !</strong>" }, { "type": "paragraph", "html": "On a sélectionné <strong>trois exemples de découpages pragmatiques</strong> et inspirants." }, { "type": "heading", "level": 4, "id": "ppm-exemple-de-decoupage-1", "text": "PPM Exemple de découpage #1" }, { "type": "list", "ordered": true, "items": ["<strong>les projets IT déjà bien gérés</strong> dans Azure devops/<strong>Jira</strong>, etc.", "les projets importants / <strong>risqués ou il faut impliquer les métiers fortement</strong>", "l<strong>es projets plus petits</strong> ou l'implication des métiers est nécessaire mais ou il y a <strong>moins de risques.</strong>"] }, { "type": "paragraph", "html": "À partir ce simple découpage...vous pourrez appréhender une re définition de la gestion et des do's et dont' de votre portefeuille de projets par catégorie.&nbsp;" }, { "type": "paragraph", "html": "Ce qui est <strong>fondamental ce sera de bien concevoir un workflow associé à chaque découpage.</strong>" }, { "type": "paragraph", "html": "Quels sont critères qui font qu'un nouveau projet arrivant passe dans telle ou telle catégorie. Et pour chacune, quelle sera sa \"definition of done\" (DOD) ?" }, { "type": "paragraph", "html": "Puis une fois lancé, comment un projet passera-t-il d'une catégorie à l'autre. Quels seront les critères et processus associés à ce mouvement ?" }, { "type": "heading", "level": 4, "id": "ppm-exemple-de-decoupage-2-project-management-chez-axa", "text": "PPM Exemple de découpage #2 - Project Management chez AXA" }, { "type": "paragraph", "html": "Second exemple emprunté à la gestion de projet au sein d'Axa, l'utilisation d'<strong>une image simple celle des voies de péages d'une autoroute à projets</strong> associée à des workflows spécifiques :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bc95d443ce2604d58ca38_ppm-axa-peage.jpg", "alt": "Exemple de découpage PPM", "caption": "Exemple de découpage PPM en mode péage d'entrée sur l'autoroute. Vos projets classés dans un PPM pragmatique !" }, { "type": "list", "ordered": true, "items": ["Projets de la voie de gauche : Plus d'agilité vitesse, moins de validations", "Voie du milieu : projets tout-venant ! : Plus de volume, complexité moyenne", "Voie de droite / Projets poids lourds : Plus de sécurité, de moyens et de régulation, moins de vitesse"] }, { "type": "paragraph", "html": "Pour <strong>chacune de ces catégories</strong> au sein du <a href=\"https://www.airsaas.io/gestion-de-projet/gestion-de-portefeuille-projets-comment-selectionner-les-bons-projets\" target=\"_blank\">portefeuille de projets</a>, <strong>un protocole décisionnel et opérationnel spécifique</strong> a été conçu. On a également pensé les éventuels changements de files en cours de route." }, { "type": "paragraph", "html": "L'enjeu clé était de passer <strong>d'une gestion bureaucratique à un management \"adhocratique\".</strong>" }, { "type": "paragraph", "html": "L'adhocratie (du latin ad hoc : mis spécialement en place pour répondre à un besoin, et de kratos, pouvoir, autorité) se définit par Robert Waterman en 1990 dans « Adhocracy, The power to change » comme « toute forme d'organisation qui dépasse les frontières bureaucratiques habituelles pour saisir les opportunités, résoudre des problèmes, et obtenir des résultats» ." }, { "type": "heading", "level": 4, "id": "ppm-exemple-de-decoupage-3-frederic-navarro-dsi", "text": "PPM Exemple de découpage # 3 - Frédéric Navarro DSI" }, { "type": "paragraph", "html": "À la fois une <strong>méthode de classification</strong> et un <strong>processus pour contribuer à faciliter le travail</strong> entre les <strong>métiers et la DG</strong>." }, { "type": "paragraph", "html": "Mais surtout une approche pour <strong>générer de l'engagement autour de la feuille de route</strong>." }, { "type": "paragraph", "html": "Un <strong>dialogue continu</strong> avec l'ensemble des directions métiers pour catégoriser un projet à l'aide de <strong>quatre niveaux</strong> (stratégique, légal, de direction, de département) repriorisés chaque mois !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bcaa38382d0006ebfd1a9_decoupage-ppm.png", "alt": "Découpage PPM", "caption": "Exemple de découpage PPM - de gestion des ressources via Frédéric Navarro ep. 28 Podcast CIO Révolution" }, { "type": "quote", "text": "Sur la base d'une cinquantaine de projets, 3 ou 4 sont de niveau 1, considérés comme majeurs seront régulièrement évoqués par la DSI avec la direction. Cinq ou six seront de niveau 2 et ensuite chaque direction et/ou département va avoir un certain nombre de petites missions, petits sujets à traiter. En général, le processus de reclassification est quelque chose de rapide s'il est fait de cette manière.", "author": "Frédéric Navarro - DSI — Invité ep. 28 Podcast CIO Révolution" }, { "type": "paragraph", "html": "Ces démarches rappellent l'inspiration du <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-lean-portfolio-management-pour-aligner-en-continu-la-direction-generale-lit-et-les-metiers\" target=\"_blank\"><strong>lean portfolio management</strong></a> et de la <strong>philosophie agile</strong>, à l'échelle de l'entreprise. Frameworks parmi lesquels on peut citer le SAFe : pour Scaled Agile Framework. Celui-ci a été popularisé en 2011 par Dean Leffingwell. S'il est bien implémenté, celui-ci permet d'instaurer au sein d'une même entreprise allant de 50 à 150 personnes, pour créer un <strong>langage commun entre les différentes équipes</strong> concernées par le développement d'un produit." }, { "type": "heading", "level": 3, "id": "levier-5-savoir-arreter-un-projet-au-bon-moment", "text": "Levier 5 : Savoir arrêter un projet au bon moment" }, { "type": "insight-callout", "label": "Citation", "html": "Personne n'a jamais été promu pour avoir mis fin à un projet, ce qui est à l'origine d'un énorme gaspillage dans les entreprises. 🙂" }, { "type": "paragraph", "html": "Oui, et on mesure une gestion saine du portefeuille de projets à sa capacité à savoir arrêter un projet au bon moment !" }, { "type": "paragraph", "html": "La question du <strong>courage managérial et du leadership</strong> est centrale dans cet enjeu." }, { "type": "paragraph", "html": "Beaucoup d'événements internes ou externes influent en effet sur la vie du projet." }, { "type": "paragraph", "html": "Être dynamique et réactif au changement est primordial." }, { "type": "paragraph", "html": "À l'image d'un besoin en agilité, <strong>un projet peut être accéléré, mis en pause, voire même stoppé.</strong> Ceci n'est pas obligatoirement signe d'échec, et permet au contraire d'éviter le gaspillage d'énergie." }, { "type": "paragraph", "html": "À défaut d'être en capacité d'arrêter complètement un projet, une gestion pragmatique du portefeuille de projets peut passer par <strong>la liberté donnée aux collaborateurs d'aller choisir d'autres tâches / projets d'un backlog</strong> dès qu'un projet / une fonctionnalité est bloquée." }, { "type": "paragraph", "html": "On ne peut finir d'évoquer ce quatrième levier sans partager la référence du livre de Arne Roock, l'un des succès de librairie paru en 2012 : <strong>Stop starting, start finishing !</strong>" }, { "type": "paragraph", "html": "L'auteur y milite entre autres pour la limitation du travail en cours, le management visuel et développe l'approche du portfolio <a href=\"https://www.airsaas.io/fr/gestion-de-projet/la-methode-kanban-pour-optimiser-votre-suivi-de-projet\" target=\"_blank\">Kanban</a>." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bca678382d05d92bf7582_Stop%20starting%2C%20Start%20finishing-AirSaas.jpg", "alt": "Stop starting, Start finishing", "caption": "Expression tirée du titre du livre de Arne Roock paru en 2012" }, { "type": "paragraph", "html": "<strong>Stop starting, Start finishing</strong> : Cela signifie que vous ne pouvez pas terminer ce que vous n'avez pas commencé et que vous ne devriez jamais commencer ce que vous ne vous êtes pas engagé à terminer. Malheureusement, travailler sur de nombreux projets hautement prioritaires en même temps peut entraîner des problèmes importants et en particulier : l'inefficacité !" }, { "type": "heading", "level": 3, "id": "levier-6-permettre-a-chacun-de-voir-ce-dont-il-a-vraiment-besoin", "text": "Levier 6 : Permettre à chacun de voir ce dont il a (vraiment) besoin" }, { "type": "paragraph", "html": "Il y a <strong>plein de façons de voir l'information</strong> !" }, { "type": "paragraph", "html": "Et l'info est disséminée !" }, { "type": "paragraph", "html": "Si vous pilotez un flux d'initiatives impliquant plusieurs équipes, vous savez à quel point <strong>il est difficile d'y voir clair.</strong>" }, { "type": "paragraph", "html": "Il est fondamental de s'arrêter et <strong>s'accorder que l'on veut vraiment montrer dans ce portefeuille ?</strong> Est-ce en priorité les budgets, les états d'avancement, les météos&nbsp;?" }, { "type": "paragraph", "html": "Face au volume excessif d'information proposé on est vite dans le <strong>syndrome du sapin de noël.</strong> Un reporting surchargé, joli mais peu efficace pour décider !" }, { "type": "paragraph", "html": "Dans AirSaas, avec les smart view vous avez la possibilité de&nbsp;<strong>personnaliser la vue projet</strong>&nbsp;pour montrer exactement ce que vous souhaitez voir en un clin d'œil." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bca7d845cd4e868963881_8af25de4-9d29-4c17-aa7b-bddccb028477.png", "alt": "Capture d'écran AirSaas", "caption": "Vue PPM par statut." }, { "type": "paragraph", "html": "Une smart view comprend :&nbsp;" }, { "type": "list", "ordered": false, "items": ["Un <strong>filtre</strong> sélectionné", "Les <strong>attributs</strong> que vous souhaitez afficher (météo, importance, etc.)&nbsp;", "Une <strong>façon d'afficher</strong> les projets (kanban, liste ou timeline)&nbsp;", "La façon dont vous souhaitez grouper les projets (par programme, objectif, etc.)&nbsp;"] }, { "type": "paragraph", "html": "Et si vous êtes sur la timeline :&nbsp;" }, { "type": "list", "ordered": false, "items": ["La temporalité choisie (mois, quarter, etc.)&nbsp;"] }, { "type": "paragraph", "html": "L'important c'est de proposer non pas une vue du portefeuille, mais un nombre de vues et donc de <strong>critère de choix de priorisation quasi illimité</strong> !" }, { "type": "paragraph", "html": "Projets vitaux pour le CODIR, projets qui doivent être finis dans le quarter, etc." }, { "type": "paragraph", "html": "En complément des vues partagées, des <strong>vues privées permettront à chacun de mieux voir</strong> en fonction de ses propres critères." }, { "type": "heading", "level": 3, "id": "levier-bonus-revenir-a-la-semantique-au-sens", "text": "Levier bonus : revenir à la sémantique, au sens" }, { "type": "paragraph", "html": "Vous l'avez noté dans cet article nous avons abordé les notions de silos, de collaboration et de coopération. Il est parfois utile de revenir à la sémantique.&nbsp;Retour au sens qui a la vertu de bien faire comprendre les différents enjeux et degrés dans les modalités de travail :<br>" }, { "type": "list", "ordered": false, "items": ["nos organisations historiquement <strong>silotées</strong> : les équipes travaillent <strong>\"à côté\"</strong> des autres,", "puis on monte d'une marche et on <strong>collabore</strong> (co laborer) : les équipes travaillent \"<strong>avec</strong>\" les autres", "en enfin le \"Graal\" que nous recherchons tous : la <strong>coopération</strong> : les équipes \"font <strong>œuvre commune</strong>\" pour le bien commun général"] }, { "type": "paragraph", "html": "Merci à <strong>Isabelle Leroux,</strong> Consultante Transformation pour ce rappel sémantique et néanmoins pragmatique !" }, { "type": "paragraph", "html": "On est plus du tout dans le même état d'esprit ;) et c'est possible avec un soupçon de leadership à distiller dans le management à tous les étages... Augmentation du niveau de confiance et d'engagement sont à la clé." }, { "type": "heading", "level": 2, "id": "ppm-pragmatique-en-2022-a-retenir", "text": "PPM pragmatique en 2022 : À retenir" }, { "type": "list", "ordered": false, "items": ["<strong>Une gestion pragmatique du PPM permettra de mieux appréhender une partie des frustrations&nbsp;légitimes de chaque partie prenante</strong> et d'impliquer le top management en traitant des sujets qui sont fondamentaux&nbsp;: stratégie, dialogue et coopération entre les silos, répartition budgétaire.", "La démarche de PPM pragmatique implique un <strong>état d'esprit</strong> nouveau. On <strong>switch entre ancienne et nouvelle approches</strong> : Contrôle VS engagement ; Priorisation par la collaborativité VS data ; Simplicité VS complexité, Usage principal VS progiciel à tout faire ;", "Choisissez <strong>un outil qui porte une philosophie</strong> proche de celle que vous promouvez actuellement et avec une interface utilisateur ultra-simple !", "La <strong>transformation ne peut pas fonctionner sans l'engagement</strong> des gens.", "<strong>Investissez dans la réflexion</strong> sur votre framework et workflow de portefeuille projets adapté à votre contexte.", "Instaurez <strong>un processus de sélection de projet centré sur l'entreprise</strong> et ses collaborateurs <strong>versus le client roi</strong> !"] }, { "type": "paragraph", "html": "Vous avez <strong>toutes les clés pour vous moderniser votre démarche de PPM</strong> ? Pour finir le geste, nous vous proposons de poursuivre avec au menu la lecture de l'un des articles de \"Pro de la Transfo.\" : <a href=\"/gestion-de-projet/comment-mettre-une-demarche-de-projet-dans-mon-entreprise\" target=\"_blank\">Comment mettre une démarche projet dans mon entreprise.</a>" }], "toc": [{ "href": "#ppm-la-fin-du-domaine-reserve", "label": "PPM : la fin du \"domaine réservé\"", "level": 2 }, { "href": "#six-leviers-pour-une-gestion-de-portefeuille-de-projets-pragmatique-en-2022", "label": "Six leviers pour une gestion de portefeuille de projets pragmatique en 2022", "level": 2 }, { "href": "#ppm-pragmatique-en-2022-a-retenir", "label": "PPM pragmatique en 2022 : À retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-decider-en-copil", "skip": false, "meta": { "title": "Comment décider en Copil ?", "h1": "Comment décider en Copil ?", "description": "Comment prendre les bonnes décisions rapidement et avec un fort engagement de tous les membres du comité de pilotage ? Découvrez 5 modes de décision, 2 pièges à éviter et une checklist.", "publishedDate": "12/6/2022", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "12/6/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62a647e53ec20c14d109fd3a_Project%20image%20(8)-min.jpg", "alt": "" } }, "blocks": [{ "type": "paragraph", "html": "Ça vous arrive d'avoir des projets bloqués à cause de décisions qui ne sont pas prises ? Ou de vous demander pourquoi cette décision avait été prise ? On sait que dans les Copil, les décisions peuvent être parfois difficiles à prendre. On a tous en tête une personne qui monopolise la parole pendant dix minutes. Quelqu'un qui demande un détail précis qui nous empêche de parler du fond." }, { "type": "paragraph", "html": "Si vous êtes un fidèle lecteur de notre blog des \"Pros de la Transfo.\" vous connaissez l'équation \"<strong>1/2 décision = bordel au carré</strong>\". Formule écrite par Olivier Bas, vice-président d'Havas, auteur, conférencier et enseignant dans le livre <em>Like ton job</em>." }, { "type": "paragraph", "html": "<strong>Sans gouvernance claire, les projets sont lancés, arrêtés ou prolongés de manière irrationnelle.</strong> La DSI et la Direction de la Transformation sont au centre de cet enjeu." }, { "type": "paragraph", "html": "Oui : parmi toutes les responsabilités d'un comité de pilotage de projets, celle de prendre des décisions pertinentes est sans doute la plus difficile<strong>.</strong> <strong>Comment prendre les bonnes décisions rapidement et avec un fort engagement de tous</strong> les membres du comité ?" }, { "type": "paragraph", "html": "Dans les lignes qui suivent, nous apporterons un éclairage différent sur ce qui se joue dans ce type de réunion, ainsi que des astuces pour mieux gérer certaines situations de blocage." }, { "type": "paragraph", "html": "Préparez-vous à découvrir ou revisiter les avantages et inconvénients de cinq modes de prise de décisions possibles en Copil. Vous découvrirez aussi deux pièges à éviter et deux prérequis à respecter. Des retours d'expérience en gestion de projet qui peuvent vous aider à choisir le mode de choix le plus adapté en fonction de la décision à prendre. Pour peut-être retrouver le chemin d'un comité de pilotage utile et aussi décisif que possible !" }, { "type": "paragraph", "html": "Faciliter les décisions stratégiques<strong>.</strong> Une thématique que tout PMO ou directeur de projet devrait travailler dans la mise en place générale. Si ce n'est pas le cas, ça tombe bien : un rapide détour par l'article <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">Comité de pilotage ou Copil : Les bases</a> vous sera très utile." }, { "type": "heading", "level": 2, "id": "lorsque-decider-en-comite-de-pilotage-est-synonyme-derreur-focus-sur-deux-pieges-a-eviter", "text": "Lorsque décider en comité de pilotage est synonyme d'erreur : focus sur deux pièges à éviter" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f61_62ea8d9c7af19a1e39cc671e_decision-antoine-chereau-courrier-cadres.jpeg", "alt": "Dessin Antoine Chéreau - Courrier Cadres", "caption": "Toute ressemblance avec l'ordre du jour d'un de comité de pilotage projet serait purement fortuite. Source : Antoine Chéreau pour Courrier Cadres" }, { "type": "paragraph", "html": "Lionel M., ancien DSI de transition interrogé sur son retour d'expérience sur ces thématiques nous a confié :" }, { "type": "quote", "text": "J'ai plus d'expérience de non-décision que l'inverse ! Souvent, tu te réunis sans savoir quelles sont les décisions à prendre. Pire, tu sors parfois de Copil en te disant : on fait quoi finalement ? <b>Il y a un manque de concrétisation en actes, les choses ne sont pas assez clairement dites et écrites.</b> Et d'un Copil à l'autre, on ne sait plus qui a décidé de faire telle chose, qui a dit \"on y va\" ou pas, ni pourquoi.", "author": "Lionel M. — ex DSI de transition" }, { "type": "paragraph", "html": "On parle beaucoup d'intelligence collective, mais assez peu de son pendant : l'idiotie collective ! Car, c'est une conviction : il n'y a pas d'entre deux. Un peu comme pour la prise de poids. On prend ou on perd. Ici, on est collectivement intelligents ou bien idiots collectivement. Désolé." }, { "type": "heading", "level": 3, "id": "leffet-de-polarisation-collective-dans-les-decisions-augmente-les-risques", "text": "L'effet de polarisation collective dans les décisions augmente les risques" }, { "type": "paragraph", "html": "Le fait que l'être humain devienne un mouton est un phénomène vieux comme le monde. <strong>L'effet du groupe</strong> sur l'individu est ce que l'on appelle en psychologie, le conformisme : lorsque votre avis entre en conflit avec celui du groupe, vous avez tendance à conformer votre jugement à celui du groupe. Tout est normal." }, { "type": "paragraph", "html": "Outre le conformisme de la pensée de groupe, il existe un \"symptôme\" moins connu, mais critique en gestion de projet : celui de<strong> la polarisation collective.</strong> Il est démontré que les décisions de groupe peuvent conduire à des prises de risque plus élevées qu'en individuel. Le groupe a en effet tendance à prendre une option plus extrême que la moyenne des positions initiales de chacun. On parle alors d'un effet de polarisation." }, { "type": "paragraph", "html": "Il a ainsi été identifié comme étant à l'origine de l'échec de l'invasion ratée de la Baie des Cochons en 1961 à Cuba soutenu par les Etats-Unis, ou encore de l'explosion de la navette spatiale Challenger." }, { "type": "heading", "level": 3, "id": "le-hippo-un-danger-pour-le-comite-de-pilotage", "text": "Le \"HIPPO\" : un danger pour le comité de pilotage" }, { "type": "paragraph", "html": "En entreprise, et singulièrement dans les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comite-de-pilotage-definitions-et-incomprehensions\" target=\"_blank\">comités de pilotage projet</a>, de nombreuses variantes sont observées. L'une des plus navrante est appelée <strong>l'effet HIPPO, acronyme anglais signifiant <em>Highest Paid Person's Opinion</em>.</strong> Autrement dit : les opinions de la personne la plus hautement placée hiérarchiquement dans les membres du comité ont une tendance naturelle à être retenues." }, { "type": "paragraph", "html": "Une des astuces basiques pour tenter d'éviter ce biais en Copil peut consister à demander au plus grand \"chef à plume\" présent au comité de pilotage de parler en dernier à chaque tour de table. Mais l'expérience montre que, sur la durée, ça ne suffit pas - et souvent même, quand il ne parle pas, il s'exprime tout de même !" }, { "type": "paragraph", "html": "Rien de nouveau, de grave ou d'irrémédiable. Ceci étant, sachant cela, maintenant que nous nous sommes souvenus de cet effet de groupe et des principaux biais, nous n'avons plus d'excuses pour ne pas améliorer ce processus dans notre gestion de projet." }, { "type": "heading", "level": 2, "id": "acces-aux-donnees-et-definition-de-lautorite-projet-deux-prerequis-pour-mieux-decider", "text": "Accès aux données et définition de l'autorité projet : deux prérequis pour mieux décider" }, { "type": "quote", "text": "Le management est l'art de prendre des décisions à partir d'informations insuffisantes.", "author": "Roy Rowan" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f73_62a64a8979fb263a633db2f8_fxdessinateur.jpeg", "alt": "Chef de projet / PMO hésitant entre inno et comme d'habitude Source : FX Dessinateur.", "caption": "Chef de projet sortant d'un comité de pilotage. Crédit image : FX Dessinateur" }, { "type": "heading", "level": 3, "id": "et-si-vous-aviez-acces-a-toutes-les-decisions-a-prendre-et-a-lhistorique-cle-pendant-le-copil", "text": "Et si vous aviez accès à toutes les décisions à prendre et à l'historique clé pendant le Copil ?" }, { "type": "paragraph", "html": "Avant toute bonne pratique, la base de la base c'est de s'assurer que les enjeux attachés à la décision sont bien intégrés par les parties prenantes, le sponsor, le chef de projet IT et métier, et le management." }, { "type": "paragraph", "html": "Rien de pire que de devoir découvrir et analyser en séance les données, souvent complexes, d'un choix stratégique sur lequel se prononcer." }, { "type": "paragraph", "html": "Sur cette problématique découvrez le retour d'expérience de l'entreprise OCTO Tech :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f7b_62a64cc9b373dc2357f3d823_octo-tech-airsaas-min.jpeg", "alt": "Couverture Livre Ludovic Cinquin", "caption": "Ludovic Cinquin CEO d'OCTO Technology. Une des entreprises inspirée par la sociocratie 3.0" }, { "type": "quote", "text": "Il y a quelques sujets sur lesquels nous n'avons pas trouvé de mode de fonctionnement pérenne. Le premier est le relevé de décisions. Cela peut paraître anecdotique, mais nous sommes régulièrement confrontés au sujet. Même si, sur la plupart des instances, nous avons des comptes rendus dans lesquels débats, actions et décisions sont consignés, <b>il est fastidieux de les éplucher pour retrouver toutes les décisions qui ont été prises, surtout sur des sujets (et il y en a beaucoup) qui ont une périodicité annuelle.</b> Et <b>la motivation des décisions (qui est sans doute le sujet le plus important)</b> n'est pas non plus toujours clairement consignée. Un registre centralisé et accessible à tous serait sans doute une bonne idée, mais malgré quelques tentatives, nous n'avons pas réussi à ancrer cette habitude. \"Devenir une entreprise agile - Les leçons de 20 ans de transformation\"", "author": "Ludovic Cinquin" }, { "type": "paragraph", "html": "Développer une gouvernance agile et/ou efficace ne s'improvise pas seul. Les logiciels sont désormais nos alliés pour objectiver et faciliter les arbitrages. Les coachs d'organisation le disent : ces plateformes sont des <em>must have</em> !" }, { "type": "paragraph", "html": "Les responsables projet doivent en effet pouvoir<strong> faire remonter de manière simple, synthétique et précises les décisions à prendre</strong> pour faire avancer le projet.<br>Et les clients internes, sponsors, membres du comité de pilotage et ou comité de direction, etc. doivent pouvoir prendre des décisions dans les temps impartis pour ne pas retarder l'exécution et la conduite de projet." }, { "type": "paragraph", "html": "Et les clients internes, sponsors, membres du comité de pilotage et ou comité de direction, etc. doivent pouvoir prendre des décisions dans les temps impartis pour ne pas retarder l'exécution et la conduite de projet." }, { "type": "paragraph", "html": "Pour le management, il est souvent difficile d'avoir une vision claire de l'ensemble des décisions à prendre, et du contexte synthétique et précis. Et <em>a posteriori</em>, il est difficile d'avoir l'historique des décisions importantes (actées ou non) sur le projet. Difficile pour comprendre comment on en est arrivé là." }, { "type": "paragraph", "html": "<strong>L'usage d'une plateforme vous simplifiera la gouvernance</strong> (listing des décisions à prendre, vue Copil, etc.) Vous ne serez plus pris de court parce que vous n'avez pas la bonne information." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f78_62f3cfa6d36866127455552e_decisions.jpeg", "alt": "Filtrez les décisions qui vous concernent, celles qui sont les plus importantes, celles en retard, etc.", "caption": "Filtrez les décisions qui vous concernent, celles qui sont les plus importantes, celles en retard..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f7e_62f3d39529620b8fbe0487b7_desicion.jpeg", "alt": "Et surtout, en un clic, accéder à l'historique des échanges concernant une décision, son contexte.", "caption": "Et surtout, en un clic, accéder à l'historique des échanges concernant une décision, son contexte." }, { "type": "paragraph", "html": "Chaque décision a un statut (à l'étude / en cours / prise / plus d'actualité). Une fois créée, chaque décision a sa propre page sur laquelle vous pouvez poster, commenter, changer les attributs de la décision, et retrouver le projet associé." }, { "type": "quote", "text": "Un Kanban des décisions : ça change la vie !", "author": "PMO utilisateur de la plateforme AirSaas" }, { "type": "heading", "level": 3, "id": "definir-les-criteres-de-lautorite-dans-le-projet-pour-mener-a-bien-le-co-pilotage", "text": "Définir les critères de l'autorité dans le projet pour mener à bien le co-pilotage" }, { "type": "paragraph", "html": "Vous avez accès aux données. Top ! Le second prérequis consiste à fixer le cadre et les limites au pouvoir de chacune des équipes, instance et parties prenantes. \"Les bonnes clôtures font de bons voisins\"." }, { "type": "paragraph", "html": "De façon générale, les trois principales redevabilités d'un comité de pilotage sont de <strong>prendre des décisions et faire des arbitrages</strong>, de <strong>veiller au bon déroulement du projet</strong> et <strong>s'assurer qu'il est en accord avec les stratégies globales de l'entreprise.</strong> Pas de décider de tout ! Pourtant, on peut dire qu'on a parfois vu un Copil s'occuper de la couleur du site web au lieu de tenter de résoudre des conflits entre départements, ou de s'occuper de donner véritablement au chef de projet le pouvoir d'agir et d'utiliser les ressources de l'entreprise, par exemple." }, { "type": "paragraph", "html": "Pour déminer cette tendance naturelle du Copil à se mêler de ce qui ne le regarde pas, soyez attentif aux frontières de l'autorité dans le projet, du rôle, et des redevabilités de chaque instance. Comité de direction, Copil, chef de projet IT, sponsor, chef de projet métier... votre gouvernance projet mérite un design clair !" }, { "type": "paragraph", "html": "Concrètement l'idée est de <strong>charter les responsabilités</strong>. Aux côtés du RACI projet, vous pouvez par exemple établir des critères clés pour définir qui décide sur quoi<strong>.</strong> Un exemple : une ligne de flottaison budgétaire au-dessus de laquelle le comité de pilotage est consulté et décisionnaire. En dessous, la subsidiarité s'applique. Et surtout : une fois le principe posé, vous couvrirez les choix de vos collaborateurs quels qu'ils soient. Car rappelons-le : 8 fois sur 10, ce sera très bien ! La prise d'initiative sera vraiment encouragée." }, { "type": "heading", "level": 2, "id": "decider-de-comment-decider-5-modes-de-decision-pour-comite-de-pilotage", "text": "Décider de comment décider : 5 modes de décision pour comité de pilotage" }, { "type": "insight-callout", "label": "À retenir", "html": "Comme l'ont montré les résultats de nombreuses recherches, les individus acceptent et adhèrent aux décisions prises par le groupe (les autorités ou instances), même lorsque celles-ci leur sont défavorables, <b>s'ils croient en la « valeur du groupe »</b>. Autrement dit, s'ils pensent avoir affaire à des personnes honnêtes, intègres et compétentes. Cependant, <b>la confiance sociale n'est jamais totalement gagnée</b>. Elle <b>dépend</b>, entre autres, des informations concernant <b>la manière dont les groupes ont procédé pour aboutir à cette décision.</b><br>Groupe et décisions collectives de <b>Ewa Drozda-Senkowska, François Ric et Dominique Muller</b>." }, { "type": "paragraph", "html": "On a consolidé ci-dessous 5 approches, de la plus autoritaire et rapide à la plus lente et consensuelle. Tour d'horizon des différentes démarches de gouvernance d'un projet en entreprise." }, { "type": "heading", "level": 3, "id": "autoritaire-jai-decide", "text": "Autoritaire : \"j'ai décidé !\"" }, { "type": "list", "ordered": false, "items": ["Caractéristique : décision rapide fondée sur le principe des <em>domaines d'autorité</em>. Chaque membre de l'organisation a autorité sur certains aspects des activités. Il peut, ou pas, demander l'avis du comité et des parties prenantes avant de trancher.", "Avantages : rapidité. Le chef de projet a autorité sur une série de domaines.", "Inconvénient : On peut être une super locomotive pour le projet... mais sans wagon d'équipe accroché. Seul on va plus vite, à plusieurs on va plus loin, rappelle le dicton.", "Notre avis : vous l'avez lu plus haut, parfois l'effet groupe est toxique. Ce mode de gouvernance projets, s'il est utilisé à bon escient, peut se révéler le plus efficace, même s'il n'est pas le plus populaire lors de réunions."] }, { "type": "heading", "level": 3, "id": "consultatif-je-vous-ai-ecoute", "text": "Consultatif : \"je vous ai écouté\"" }, { "type": "list", "ordered": false, "items": ["Caractéristique : sollicitation d'avis auprès du groupe, par écrit et ou oral.", "Avantages : si la cohésion du groupe est bonne et que la parole est libérée, ce mode de décision éclaire le responsable d'un avis utile, confrontant, et bienveillant.", "Inconvénient : on peut être consulté et pas écouté. Les parties prenantes sont appelées à se prononcer sur des sujets complexes. Parfois, la rhétorique et la politique peuvent l'emporter. On constate de nombreux biais possibles (de polarisation, effet HIPPO, biais d'échantillon...).", "Notre avis : sans doute le plus utilisé en Copil et Codir. Ce processus fait la part belle aux égos de chacun tout au long du cycle de vie d'un projet."] }, { "type": "heading", "level": 3, "id": "majoritaire-a-vote", "text": "Majoritaire : \"à voté !\"" }, { "type": "list", "ordered": false, "items": ["Caractéristique : Vote à la majorité ou a l'unanimité.", "Avantages : une forme de démocratie projet.", "Inconvénient : un peu comme en politique, ce mode de scrutin peut générer des frustrations. Si une décision est prise à 51% de personnes pour, il y aura 49% de membres du groupe qui étaient contre et devront vivre avec la décision.", "Notre conseil : le vote est une pratique à mi-chemin entre les excès d'autorité et de consensus. Si les différents biais de l'effet de groupe sont évités, alors le vote peut se révéler une pratique moderne et engageante en réunion de comité."] }, { "type": "heading", "level": 3, "id": "consensus-apparent-quand-tout-le-monde-dit-oui", "text": "Consensus apparent : quand tout le monde dit « oui »" }, { "type": "list", "ordered": false, "items": ["Caractéristique : accord tacite ou manifeste. Un groupe arrive à choisir sans avoir recours au vote.", "Avantages : on discute longtemps, tous les points de vue sont respectés.", "Inconvénient : le processus le plus long et le plus difficile. Aller chercher chaque partie prenante, chaque membre du Copil, peut se révéler être une quête sans fin pour le chef de projet. Surtout : l'idée initiale est trop souvent modifiée, déformée. La mise en place de la décision du comité de pilotage devient contre productive par rapport à l'intention initiale.", "Notre avis : le moins conseillé des modes de décisions. En particulier parce que les différents amendements à l'idée initiale créent une distorsion."] }, { "type": "heading", "level": 3, "id": "consentement-quand-personne-ne-dit-non", "text": "Consentement : quand personne ne dit « non »" }, { "type": "list", "ordered": false, "items": ["Caractéristiques : On décide en s'assurant qu'une proposition ne recueille aucune objection sérieuse, plutôt que de chercher à contenter tout le monde et tomber dans le consensus mou. Le dicton le rappelle : \"mieux vaut du dur sûr que du mou flou !\"", "Avantages : on ne dévalorise pas l'idée du porteur de la demande en cherchant le consensus. Prise de décision agile par essence. Les egos y sont sous contrôle et un temps de parole permet à chacun de « questionner » et réagir.", "Limites : la principale est la bonne foi des participants. Attention également si trop de décisions de type « opérationnel » se font au consentement, cela peut se révéler chronophage et limiter l'autonomie des membres des équipes projet dans leurs rôles et domaine d'autorité.", "Notre conseil : tester le consentement idéalement avec un facilitateur la première fois. Les méthodes agiles et les gouvernances inspirées par l'entreprise libérée et l'holacratie utilisent depuis longtemps ce mode de décision."] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f70_62ea8e9cbbc782a229665dec_decision-methods-L-B-min.png", "alt": "Vue d'ensemble méthode de décisions", "caption": "Vue d'ensemble des méthodes de décisions pour équipe auto organisées - Source Jurgen appelo management 3.0" }, { "type": "heading", "level": 2, "id": "checklist-dune-prise-de-decision-durable-en-comite-de-pilotage", "text": "Checklist d'une prise de décision durable en comité de pilotage" }, { "type": "quote", "text": "Tips pour éviter le monopole de 10' d'une personne c'est le tour de parole sans être interrompu déjà. Après il faut être dans un COPIL autour de 10 membres... Sinon il faut prévoir un COPIL avec 2/3 décisions à prendre. Si la culture d'entreprise est très Top down et non collégiale, il convient d'avoir uniquement identifié le ou les 2 décideurs. Pour éviter l'effet, \"on n'a pas assez d'éléments, on ne peut pas décider\", il est nécessaire d'avoir envoyé les annexes de la prise de décision et d'avoir préparé (si décisions projets) un consensus ou les 2 alternatives. Et finalement, il faut surtout avoir précisé la ou les questions et ne pas passer à autre chose sans avoir la réponse.", "author": "Stéphan Boisson — Group Chief Digital & Information Officer · Comexposium" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d07a330577213943104f81_62ea8ef7dbd70fb664a922ef_airsaas-decision-copil-min.jpeg", "alt": "Aidez votre COPIL à décider !", "caption": "Votre comité de pilotage mérite un protocole décisionnel clair" }, { "type": "list", "ordered": true, "items": ["<strong>Examiner la problématique.</strong> Il n'y a choix que s'il y a une problématique qui offre plusieurs possibilités. On prépare plusieurs scénarios de choix, plusieurs options de projet. C'est à ce stade qu'on décidera du mode de décision le plus adapté en fonction des critères de temps et d'engagements visés.", "<strong>Évaluer les avantages et inconvénients</strong>, le rapport bénéfices valeur / risques (pour le projet pas pour soi !) de chacune des options. Voir clair dans toutes vos données permet de décider en \"pleine conscience\". S'assurer que chacun des membres du comité comprend les méthodes et étapes nécessaires pour prendre des décisions est essentiel pour un management efficace.", "<strong>Choisir</strong>. C'est l'étape clé, celle qui nous pousse vers une solution en renonçant aux autres. Plutôt que renoncer, acceptons que \"choisir, c'est avancer !\" Avancer en acceptant de ne pas tout avoir, sortir de la toute-puissance du Copil, prendre un risque et en assumer les conséquences. En ayant l'intime conviction que le choix que nous faisons est la meilleure des options offertes.", "<strong>Suivre l'exécution</strong>, la mise en œuvre. C'est l'étape où nous assumons réellement notre choix. Vous le savez : le Diable, et Dieu, sont dans les détails. Ce proverbe d'architecte américain est à graver sur toutes les pages de garde de vos PowerPoint.", "<strong>Et si vous n'avez pas décidé ?</strong> Acter les indécisions du Copil est tout aussi important. Consignez-le, en actant : \"Le Copil a décidé de ne pas décider. Le projet sera bloqué sur tel axe\". Un chef de projet le sait : \"Ce qui n'est pas écrit n'existe pas\"."] }, { "type": "paragraph", "html": "Le mot de la fin : <strong>ce qui crée le comportement, c'est le cadre !</strong> Agissez sur la gouvernance, une meilleure gestion de projet suivra." }, { "type": "paragraph", "html": "Vous avez maintenant toutes les cartes en main pour mieux gérer certaines situations d'indécisions. Pour aller plus loin et finir d'améliorer votre prochain Copil, on vous recommande la lecture de l'article suivant : <a href=\"/gestion-de-projet/comment-bien-preparer-un-comite-de-pilotage\" target=\"_blank\">Comment bien préparer un comité de pilotage ?</a> Car oui : tout est dans la préparation ! L'article à lire pour muscler votre préparation : définition des objectifs, interactions avec le sponsor, place des intérêts personnels, gestion des risques et des désaccords avant..." }, { "type": "quote", "text": "L'entreprise est une collectivité. Il faut accepter de se mettre en pack de rugby et de pousser dans le même sens ! Le temps qu'on prend à s'aligner ce n'est pas du temps perdu...il est important que chacun ait pu s'exprimer...Et comprenne le choix et la décision qui a été prise.", "author": "Gilles de Richemond — CEO Fairlyne | ex DSI du groupe Accor, extrait de l'épisode 40 du Podcast CIO Révolution produit par AirSaas." }], "toc": [{ "href": "#lorsque-decider-en-comite-de-pilotage-est-synonyme-derreur-focus-sur-deux-pieges-a-eviter", "label": "Lorsque décider en comité de pilotage est synonyme d'erreur : focus sur deux pièges à éviter", "level": 2 }, { "href": "#acces-aux-donnees-et-definition-de-lautorite-projet-deux-prerequis-pour-mieux-decider", "label": "Accès aux données et définition de l'autorité projet : deux prérequis pour mieux décider", "level": 2 }, { "href": "#decider-de-comment-decider-5-modes-de-decision-pour-comite-de-pilotage", "label": "Décider de comment décider : 5 modes de décision pour comité de pilotage", "level": 2 }, { "href": "#checklist-dune-prise-de-decision-durable-en-comite-de-pilotage", "label": "Checklist d'une prise de décision durable en comité de pilotage", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-elaborer-un-reporting-efficace", "skip": false, "meta": { "title": "Comment élaborer un reporting projet efficace ?", "h1": "Comment élaborer un reporting projet efficace ?", "description": "Outil de communication et d'analyse, le reporting projet a pour objectif de rendre compte de manière régulière de l'avancée d'un projet et de présenter les informations relatives à ce dernier de manière pertinente.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3819a0ae83ff1d7668d5e_6-2.jpg", "alt": "" }, "author": { "name": "Simon Vacher", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e038501c4256317123910b_SV-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Outil de communication et d'analyse,&nbsp;le reporting projet a pour objectif de rendre compte de manière régulière de l'avancée d'un projet et de présenter les informations relatives à ce dernier de manière pertinente. C'est un outil tourné vers l'action qui doit permettre à un <a href=\"/fr/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">comité de pilotage</a> de prendre des décisions judicieuses et rationnelles." }, { "type": "paragraph", "text": "Si vous êtes chef de projet, ou amené à faire de la gestion de projet manière régulière, vous savez qu'aujourd'hui l'information relative à un projet n'est plus une denrée rare. C'est son analyse, sa mise en forme et son interprétation qui sont les vrais enjeux d'un reporting bien construit, d'une <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> maîtrisée." }, { "type": "paragraph", "text": "Le reporting projet reste donc un exercice délicat : une surabondance d'informations et la multiplication des outils de reporting peuvent avoir une fâcheuse tendance à diluer l'information sans susciter l'intérêt des destinataires. &nbsp;En lisant cet article &nbsp;vous saurez à quoi sert vraiment un rapport de projet et comment améliorer la qualité de vos reportings pour les rendre vraiment efficaces intéressants pour tous les membres de votre équipe." }, { "type": "paragraph", "text": "Et en plus en cadeau vous pouvez télécharger (100% éditable sous format power point) notre modèle de<a href=\"/fr/solution/rapport-flash\" target=\"_blank\"> reporting projet ici.</a>" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-reporting-projet", "text": "Qu'est-ce qu'un reporting projet ?" }, { "type": "paragraph", "text": "Le reporting ou rapport de projet est désormais un élément bien installé dans la culture des entreprises : Product Manager, Product Owner, &nbsp;développeur ou manager, vous avez tous déjà reçu un reporting de projet dans votre boite e-mail ou via un outil collaboratif. Et vous êtes parfois amené à en élaborer certains." }, { "type": "paragraph", "text": "On pourrait définir un reporting comme une mise en scène d'informations et de données relatives à un projet, &nbsp;collectées à un instant T et présentées de manière suffisamment explicite pour que d'autres personnes puissent les exploiter et prendre des décisions." }, { "type": "heading", "level": 2, "id": "un-reporting-pour-quoi-faire", "text": "Un reporting, pour quoi faire ?" }, { "type": "paragraph", "text": "Le parti pris du reporting projet est qu'en s'appuyant sur des indicateurs de performances (appelés aussi KPIs pour Key Performance Indicators) , on peut mesurer et piloter la trajectoire d'un projet de manière efficace, ou à l'inverse se rendre compte de certains points de blocage." }, { "type": "paragraph", "text": "Dans tous les cas, un reporting de projet a pour finalité l'action, la planification des tâches et la prise de décision. Pour ce faire, les meilleurs rapports de projets ont tous un point en commun, ils permettent au lecteur de visualiser l'information en un clin d'œil pour que chacun à son niveau dans l'entreprise puisse faire les bons choix." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8395f5cd3d844d55773ce_62ea90d5e93adcb759569555_all-projects-min2.jpeg", "alt": "sommaire projet", "caption": "Sommaire projet" }, { "type": "heading", "level": 3, "id": "une-gestion-de-projet-tournee-vers-laction", "text": "Une gestion de projet tournée vers l'action" }, { "type": "paragraph", "text": "Le reporting est donc avant tout un outil d'aide à la décision, et pas du tout un outil de contrôle comme on le pense souvent. Il doit amener les parties prenantes à se poser des questions : \"Quelle suite à donner au projet?\", \"De quelles compétences avons-nous besoin &nbsp;?\", &nbsp;\"Pourquoi avons-nous pris du retard sur ce point précis ?\". \"Pourquoi le rythme de delivery est-il en train de baisser ?\". Ce sont toutes ces questions auxquelles les membres de l'équipe projet doivent pouvoir répondre si le reporting est pertinent." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8395f5cd3d844d55773c4_62ea983b0383f81f8e3fe463_execution.jpeg", "alt": "Décision à prendre", "caption": "Mettez en valeur les décisions à prendre" }, { "type": "heading", "level": 2, "id": "quels-types-dinformations-inclure-dans-votre-reporting", "text": "Quels types d'informations inclure dans votre reporting ?" }, { "type": "paragraph", "text": "Concevoir un rapport de projet est une de bonne idée, mais quelles informations allez-vous sélectionner, lesquelles allez-vous mettre plus en avant ? C'est sans doute le point le plus important abordé dans cet article, comment faire passer les bonnes informations, les bons messages aux bons interlocuteurs ?" }, { "type": "paragraph", "text": "Un reporting n'est pas un fourre-tout dans lequel s'amassent des données. Ce n'est pas à chacun de faire le tri mais à vous d'ordonner les informations pour donner une cohérence globale." }, { "type": "paragraph", "text": "Il faut donc faire directement le lien entre le choix des données présentes dans vos tableaux de bord et les besoins des différents destinataires. La première question à se poser n'est donc pas \"Quelles données inclure dans mon reporting?\" mais :" }, { "type": "paragraph", "text": "\"Qui va consulter ces indicateurs et qu'en attendent-ils ?\", \"Quels peuvent-être les solutions que mon rapport apporte par rapport aux problématiques soulevées la semaine dernière?\".... Et seulement ensuite : \"Quelles sont les informations clés dont j'ai besoin ?\"" }, { "type": "heading", "level": 2, "id": "differents-acteurs-differentes-demandes", "text": "Différents acteurs, différentes demandes" }, { "type": "heading", "level": 3, "id": "pour-le-top-management", "text": "Pour le top-management" }, { "type": "paragraph", "text": "Pour un CEO, &nbsp;un directeur financier &nbsp;et plus généralement le top management le temps est rare et &nbsp;précieux. Ils ont sûrement un portefeuille de projets bien rempli à gérer. Cette typologie de population a besoin de se faire rapidement une vue d'ensemble d'un projet pour prendre des décisions d'ordre macro." }, { "type": "heading", "level": 3, "id": "pour-les-equipes-metiers", "text": "Pour les équipes métiers" }, { "type": "paragraph", "text": "En revanche, une équipe opérationnelle - comme des développeurs ou des programmeurs par exemple - sera davantage attentive d'indicateurs d'efficacité et de productivité pour apprécier leur performance." }, { "type": "heading", "level": 3, "id": "pour-les-managers", "text": "Pour les managers" }, { "type": "paragraph", "text": "Enfin, un manager se servira du reporting projet comme d'un outil pour impliquer les parties prenantes du projet et rendre visible les enjeux et décisions à prendre du projet." }, { "type": "heading", "level": 2, "id": "comment-collecter-les-donnees-de-votre-reporting", "text": "Comment collecter les données de votre reporting ?" }, { "type": "paragraph", "text": "L'élaboration d'un reporting de projet peut vite devenir une tâche très chronophage si vous êtes mal organisé ou ne disposez pas des bons outils." }, { "type": "heading", "level": 3, "id": "les-bons-outils-de-collecte", "text": "Les bons outils de collecte" }, { "type": "paragraph", "text": "Une des clés pour gagner du temps et de savoir où et comment collecter les données dont vous avez besoin, et quels seront les indicateurs que vous allez mettre en avant." }, { "type": "paragraph", "text": "Un outil de reporting intégré (comme AirSaas), permet d'automatiser de manière intelligente la collecte des informations dont vous avez besoin pour élaborer votre reporting. Connecté aux outils collaboratifs que vous utilisez au quotidien, c'est sans doute la manière la plus sûre d'agréger rapidement les données et de leur donner du sens." }, { "type": "heading", "level": 3, "id": "la-bonne-frequence-de-reporting", "text": "La bonne fréquence de reporting" }, { "type": "paragraph", "text": "La fréquence d'envoi de votre reporting se fait selon deux critères : la période que vous souhaitez analyser et celle à laquelle vos interlocuteurs ont besoin de ce reporting." }, { "type": "paragraph", "text": "Assurez-vous donc également d'avoir accès de manière récurrente aux informations dont vous avez besoin afin d'éviter les \"trous dans la raquette\" au prochain envoi." }, { "type": "paragraph", "text": "Les meilleures équipes qui utilisent AirSaas envoient le rapport flash aux différentes parties prenantes une fois par semaine. (oui oui pas une fois tous les mois...!)" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8395f5cd3d844d55773e7_616fd320191fb9e48982f69c_Export-flash.jpeg", "alt": "export en un clic", "caption": "Export ppt en clic du rapport flash" }, { "type": "heading", "level": 2, "id": "adaptez-le-nombre-dindicateurs-a-votre-projet", "text": "Adaptez le nombre d'indicateurs à votre projet" }, { "type": "paragraph", "text": "En gestion de projet, un seul mot d'ordre, quel que soit le reporting que vous êtes en train d'élaborer : <strong>Soyez synthétique</strong> ! Un nombre réduit d'indicateurs ne signifie pas que votre reporting ne sera pas pertinent." }, { "type": "heading", "level": 3, "id": "less-is-good", "text": "Less is good !" }, { "type": "paragraph", "text": "Vous montrerez au contraire que vous avez pris le temps de choisir vos KPIs avec soin et que le projet vous tient à cœur. Le défaut de beaucoup de rapports c'est qu'ils ont tendance à vous noyer sous un flot d'informations inutiles, ne tombez pas dans le piège &nbsp;de la surabondance de data, c'est LE piège dans lequel nous sommes tous tombés au début." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c837cd73ec2f8efeab7d09_62f36ff388c0c330cc047df4_Project-progression-min.jpeg", "alt": "indicateur budget et effort projet", "caption": "Evolution du budget et du temps projets" }, { "type": "heading", "level": 3, "id": "le-bon-niveau-de-granularite", "text": "Le bon niveau de granularité" }, { "type": "paragraph", "text": "Un bon reporting présente des informations dont &nbsp;le niveau de granularité de l'information a été correctement choisi. Pensez à bien organiser vos indicateurs par ordre d'importance." }, { "type": "paragraph", "text": "Pour un rapport de projet envoyé à des populations très hétérogènes, l'élaboration d'un reporting de projet sous forme de synthèse avec accès à un reporting plus étoffé &nbsp;accessible facilement en cas de besoin est fortement conseillée." }, { "type": "heading", "level": 3, "id": "le-petit-truc-en-plus-qui-fait-toute-la-difference", "text": "Le petit truc en plus qui fait toute la différence" }, { "type": "paragraph", "text": "<em>Les spécialistes de la gestion de projet le savent, &nbsp;la vraie santé d'un projet se mesure aussi à l'aide des indicateurs qui se voient le moins, les indicateurs de performance cachés. Bien sûr, il est impossible de savoir ce qui se passe exactement dans la tête des membres d'une équipe, mais certains signes ne trompent pas : l'assiduité aux réunions, les retards récurrents de delivery, la multiplication des bugs fonctionnels, ou encore l'accumulation des erreurs d'inattention, sont tous des indicateurs de (bonne) santé d'un projet et du niveau d'implication.</em>" }, { "type": "heading", "level": 2, "id": "les-cles-dun-reporting-moderne-efficace-et-attrayant", "text": "Les clés d'un reporting moderne, efficace et attrayant" }, { "type": "paragraph", "text": "Avec tous les outils de présentation et de partage de l'information qui existent, les reportings de projet austères et peu lisibles n'ont plus lieu d'exister." }, { "type": "paragraph", "text": "La forme compte donc autant que le fond. Un reporting de projet efficace donne envie d'être lu, commenté et partagé. C'est avant tout un outil d'analyse et sa valeur ajoutée est de permettre de passer à l'action. Pour cela, plusieurs points sont à prendre en considération :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8395f5cd3d844d55773dc_62f3810bbb866a685862d6be_rapport%2520flash.jpeg", "alt": "Rapport flash intro", "caption": "La synthèse des fiches projets : le rapport flash" }, { "type": "heading", "level": 3, "id": "utilisez-les-formes-et-les-couleurs", "text": "Utilisez les formes et les couleurs :" }, { "type": "paragraph", "text": "N'ayez pas peur de faire appel à votre créativité pour attirer l'attention avec des couleurs afin de mettre en avant les informations et les évolutions les plus importantes. Réutilisez le même code couleur dans tous vos reportings pour habituer votre audience à votre méthode de travail." }, { "type": "heading", "level": 3, "id": "une-idee-un-graphique", "text": "Une idée = un graphique" }, { "type": "paragraph", "text": "En gestion de projet, &nbsp;les idées clés doivent absolument être illustrées de manière simple et percutante pour être mémorisées." }, { "type": "paragraph", "text": "Certains outils de suivi et de gestion de projet comme AirSaas proposent différentes manières de visualiser la data relative à votre activité pour que l'information circule plus rapidement au sein d'une entreprise. &nbsp;D'un rapport &nbsp;à l'autre les données se mettent à jour automatiquement pour vous faire gagner du temps." }, { "type": "heading", "level": 3, "id": "misez-sur-le-collaboratif-et-le-participatif", "text": "Misez sur le collaboratif et le participatif :" }, { "type": "paragraph", "text": "Le meilleur rapport de projet est celui sur lequel on passe le moins de temps possible mais qui met tout le monde d'accord." }, { "type": "paragraph", "text": "En impliquant les parties prenantes dans le suivi de &nbsp;projet vous bénéficiez d'un double avantage : des données actualisées sur lesquels les acteurs concernés s'engagent, et la mise en place d'un processus collaboratif au sein duquel tout le monde apporte sa pierre à l'édifice. Faites appel à l'intelligence collective !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8395f5cd3d844d55773c1_62f3813287c55408057635a9_Success-post-min.jpeg", "alt": "Partagez vos succès projet !", "caption": "Partagez vos succès projet, ne les gardez pas pour vous ;-)" }, { "type": "heading", "level": 2, "id": "quels-outils-utiliser-en-gestion-de-projet", "text": "Quels outils utiliser en gestion de projet ?" }, { "type": "paragraph", "text": "L'utilisation d'outils intégrés permet de passer très peu de temps sur le reporting de projet et de se concentrer sur la valeur ajoutée des tâches à accomplir. Et oui il n'est pas \"normal\" de passer 3 jours par mois à faire du power point..." }, { "type": "paragraph", "text": "D'ailleurs on parle davantage de suivi de projet puisque les données sont mises à jour et consultables à tout moment, de manière visuelle et explicite &nbsp;par tous les membres de l'équipe. Avec ce genre d'outils, le niveau des collaborateurs augmente et l'équipe a vraiment les moyens de se concentrer sur sa vraie mission." }, { "type": "paragraph", "text": "<strong>Parmi les outils généralement utilisés en gestion de projet, on retrouve notamment : </strong>" }, { "type": "paragraph", "text": "- La todo sur papier, et oui &nbsp;! Ça marche très bien sur des projets ou est seul et que tout dépend d'une seule personne .. En voie de disparition :-)" }, { "type": "paragraph", "text": "- Microsoft Excel - c'est le plus utilisé mais aussi le plus statique et le plus difficile à mettre à jour. &nbsp;Mais bon ..!" }, { "type": "paragraph", "text": "- Monday, Asana, Wrike en saas, ou d'autres solutions en open source qui se focalise sur la gestion des tâches." }, { "type": "paragraph", "text": "Ce sont bien des outils de gestion projet, mais pas de pilotage projet. Les outils de gestion de projet sont centrés sur les tâches et les diagrammes de gantt." }, { "type": "paragraph", "text": "AirSaas, l'outil de pilotage de projet est centré sur les décisions et le reporting." }, { "type": "paragraph", "text": "Bien utilisé, un outil de pilotage de projet permet d'aligner la DSI et les équipes métiers, le top management sur les mêmes objectifs et une meilleure communication en cassant les silos d'une organisation parfois trop lourde ou compartimentée." }, { "type": "paragraph", "text": "Avec un outil commun sur lequel mettre en commun des données chiffrées de vos projets, il est ensuite plus facile de construire une vision commune et d'avancer dans la même direction, avec une même <a href=\"/gestion-de-projet/comment-mettre-une-demarche-de-projet-dans-mon-entreprise\" target=\"_blank\">démarche de projet</a>." }], "toc": [{ "label": "Qu'est-ce qu'un reporting projet ?", "href": "#quest-ce-quun-reporting-projet", "level": 2 }, { "label": "Un reporting, pour quoi faire ?", "href": "#un-reporting-pour-quoi-faire", "level": 2 }, { "label": "Quels types d'informations inclure dans votre reporting ?", "href": "#quels-types-dinformations-inclure-dans-votre-reporting", "level": 2 }, { "label": "Différents acteurs, différentes demandes", "href": "#differents-acteurs-differentes-demandes", "level": 2 }, { "label": "Comment collecter les données de votre reporting ?", "href": "#comment-collecter-les-donnees-de-votre-reporting", "level": 2 }, { "label": "Adaptez le nombre d'indicateurs à votre projet", "href": "#adaptez-le-nombre-dindicateurs-a-votre-projet", "level": 2 }, { "label": "Les clés d'un reporting moderne, efficace et attrayant", "href": "#les-cles-dun-reporting-moderne-efficace-et-attrayant", "level": 2 }, { "label": "Quels outils utiliser en gestion de projet ?", "href": "#quels-outils-utiliser-en-gestion-de-projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-faire-un-bon-point-davancement-projet", "skip": false, "meta": { "title": "Comment faire un bon point d'avancement projet ?", "h1": "Comment faire un bon point d'avancement projet ?", "description": "Découvrez les ingrédients d'un point d'avancement moderne, transparent et efficace : 12 bonnes pratiques et retours d'expériences de PMO/DSI pour faire avancer votre projet.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea918a9bacb825b5c1c869_avancement-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "28/5/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "28/5/2022" }, "blocks": [{ "type": "paragraph", "html": "\"Le projet ne marche pas ! On communiquera sur l'avancement quand ce sera OK.\" Voici ce qu'on entend encore trop souvent dans les couloirs. Et c'est surtout ce qu'il faut continuer à faire pour être bien certain de passer à côté du sujet." }, { "type": "paragraph", "html": "Dans les lignes qui suivent, vous découvrirez <strong>les ingrédients d'un point d'avancement moderne, transparent et efficace</strong> (et donc des méthodes pour réussir votre <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a>)." }, { "type": "paragraph", "html": "Musclez votre suivi de l'avancement : c'est bien le message clé. Cela peut sembler simpliste comme levier de succès, et néanmoins, la bonne tenue de ces points peut faire toute la différence entre le succès et l'échec du projet. Bonne nouvelle : ça n'a pas besoin d'être compliqué !" }, { "type": "paragraph", "html": "Quelles sont les erreurs courantes et points de vigilance à surveiller ? Comment animer ce processus pour en faire à la fois un rituel simple et engageant ? Nous avons regroupé et commenté 12 bonnes pratiques et retours d'expériences de PMO/DSI. En synthèse, on va voir comment vous aider à faire avancer votre projet efficacement." }, { "type": "heading", "level": 2, "id": "les-pieges-a-eviter-pour-les-points-davancement", "text": "Les pièges à éviter pour les points d'avancement" }, { "type": "paragraph", "html": "<strong>Chaque projet nécessite des synchronisations régulières</strong> où les parties prenantes se réunissent pour discuter des objectifs, de la qualité, des jalons, des tâches et de l'avancement des travaux." }, { "type": "paragraph", "html": "Outre la fonction de reporting auprès des différentes instances concernées, bien animé, ce point d'avancement remplira également un rôle d'alignement des équipes impliquées." }, { "type": "heading", "level": 3, "id": "le-manque-dinformation-de-contexte", "text": "Le manque d'information de contexte" }, { "type": "paragraph", "html": "Disposer d'une information de progression isolée de son contexte ne permet pas aux parties prenantes du projet de s'orienter, et donc de décider avec discernement dans la complexité." }, { "type": "paragraph", "html": "Un rappel, pour être efficace <strong>les trois ingrédients d'un point d'avancement de projet</strong> sont :" }, { "type": "paragraph", "html": "1️⃣ Le rappel rapide du <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-faire-un-bon-cadrage-projet-avec-les-metiers\" target=\"_blank\">cadrage</a> (pourquoi on le fait ? sur quel périmètre ? etc.)" }, { "type": "paragraph", "html": "2️⃣ L'état des lieux de l'avancement (progression, point d'attention, décisions à prendre, etc.)" }, { "type": "paragraph", "html": "3️⃣ Et le rappel temporel (qu'est-ce qui nous attend ?)" }, { "type": "paragraph", "html": "La <strong>bonne collecte et transmission de ces informations</strong> sont l'une des clés de la réussite de ce processus. Grâce au rappel du contexte et de la timeline, on favorise la capacité à s'orienter pour chacun. On a effet besoin de disposer à la fois à de tous les ingrédients ci-dessus, mais également du contexte de ces données, pour saisir le niveau de progression réel du projet." }, { "type": "heading", "level": 3, "id": "labsence-de-concision", "text": "L'absence de concision" }, { "type": "paragraph", "html": "On est là pour un seul objectif : <strong>formaliser un état avancement, pas en débattre.</strong> Pensez au triage aux urgences. Pas d'opération dans le couloir s'il vous plaît !" }, { "type": "heading", "level": 3, "id": "limprecision", "text": "L'imprécision" }, { "type": "paragraph", "html": "On constate trop régulièrement des <strong>projets</strong> d'envergures qui ne sont pas planifiés et documentés en détail. L'attribution d'une action, des jalons et tâches du projet est parfois arbitraire, ce qui en rend le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\">suivi du projet</a> difficile." }, { "type": "paragraph", "html": "Chaque chef de projet a en général sa propre méthode de rapport de point d'avancement. Dans une grande équipe, <strong>ce manque d'uniformité crée de la confusion auprès des managers,</strong> qui ne bénéficient pas de trames de travail identiques." }, { "type": "paragraph", "html": "De nombreux grands chantiers n'utilisent pas de véritable outil de gestion de projet pour un suivi efficace." }, { "type": "heading", "level": 3, "id": "la-fuite-de-responsabilite-devenue-discipline-olympique-en-gestion-de-projet", "text": "La \"fuite de responsabilité\", devenue discipline olympique en gestion de projet" }, { "type": "paragraph", "html": "Les points d'avancement projet sont des moments de vérité par rapport à la projection initiale, à l'atteinte des résultats, et rendent visible la bonne coopération de chacun - ou pas ! Les tensions y sont légitimes et fréquentes." }, { "type": "paragraph", "html": "Les collaborateurs sont en effet potentiellement appelés à rendre des comptes et à s'engager sur un objectif et des nouveaux résultats clés. <strong>Obtenir un engagement individuel et collectif</strong> durable est un défi moderne pour tout chef de projet transverse parfois confronté à de la mauvaise volonté, voire de la mauvaise foi." }, { "type": "paragraph", "html": "Néanmoins, la tendance à la généralisation de l'usage de plateformes de collaboration projet a rendu plus visible le désengagement éventuel de certains. Dans ce contexte, votre rôle est de rappeler le cadre, les rôles et redevabilités de chacun." }, { "type": "paragraph", "html": "Si vous constatez qu'une situation de ce type survient fréquemment, échangez tout d'abord avec l'intéressé sur la base d'observations concrètes. Faites lui part de vos besoins généraux dans votre rôle, puis formulez une demande claire. Écoutez bien les réponses, les besoins exprimés. En cas de blocage avéré, formalisez le litige. Un appel au sponsor sera peut-être nécessaire. Un rappel : la coopération, ça ne se décrète pas !" }, { "type": "paragraph", "html": "Sans juger cette tendance à une forme de désengagement observée dans de nombreuses grandes entreprises, dans votre rôle de chef de projet, il vous faut néanmoins en tenir compte pour rester dans une forme de discernement." }, { "type": "heading", "level": 3, "id": "lexces-de-reunions", "text": "L'excès de réunions" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d17c7bae68096320d1af97_6290e971028f0364f784b346_1646379000029.jpeg", "alt": "Reunion inutiles", "caption": "Dites stop à l'abus de réunion \"informationnelles\"" }, { "type": "paragraph", "html": "<strong>Ne vous réunissez que lorsqu'il n'y a pas d'autre moyen pratique d'atteindre vos objectifs dans un projet</strong>." }, { "type": "paragraph", "html": "Au-delà de l'intérêt \"social\" pour une équipe, qui peut être traité dans un autre espace que celui du point d'avancement projet, il n'est pas toujours justifiable de réunir physiquement des personnes simplement pour partager leur statut ou fournir des informations sur des tâches." }, { "type": "paragraph", "html": "Dans un sens ou dans l'autre, surveillez la fréquence des réunions dans un projet. Leur abus ou leur absence peut nuire à la productivité." }, { "type": "heading", "level": 2, "id": "12-pratiques-pour-garder-les-points-davancement-sur-la-bonne-voie", "text": "12 pratiques pour garder les points d'avancement sur la bonne voie" }, { "type": "heading", "level": 3, "id": "faites-en-un-sujet-dequipe", "text": "Faites-en un sujet d'équipe" }, { "type": "paragraph", "html": "Ce sont les collaborateurs et leurs bonnes relations qui font avancer et qui transforment, au-delà du suivi des tâches et des outils mis en place." }, { "type": "paragraph", "html": "L'enjeu est bel et bien de diffuser et faire vivre une culture de co-responsabilité : l'esprit d'équipe, en somme. Pour y parvenir, allez jusqu'à modifier la définition de la grille d'évaluation et de rémunération s'il le faut. Objectivez le fait qu'on évalue aussi la coopération dans la relation du groupe projet. <strong>#TeamSpirit</strong>" }, { "type": "heading", "level": 3, "id": "utilisez-la-technologie-pour-piloter-par-la-decision", "text": "Utilisez la technologie pour piloter par la décision" }, { "type": "paragraph", "html": "Ne soyez plus pris de court parce que vous n'avez pas la bonne information. En utilisant le bon outil, vous aurez accès à toutes les décisions à prendre et historiques clés." }, { "type": "paragraph", "html": "Avec Airsaas, on a créé une plateforme pour vous simplifier la gouvernance (listing des décisions à prendre, vue Copil, etc.)" }, { "type": "paragraph", "html": "Les métiers et l'IT sont parfois en tension. Pour faire avancer les sujets sereinement une solution pragmatique est de proposer une vue consolidée via une plateforme, un workflow partagé permettant de rassembler les parties prenantes autour d'un même outil, compréhensible de tous. Le dashboard : c'est autour de cette vue que vous allez vous réunir toutes les X semaines pour faire un point d'avancement ! #CollaboratifByDesign" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44bd5_62ea90660383f80c7a3f8b33_Project-page-feed-min.jpeg", "alt": "Capture écran appli AirSaas", "caption": "Reporting régulier, remontée des décisions prises, problèmes rencontrés et des succès pour engager les équipes et avancer sereinement." }, { "type": "heading", "level": 3, "id": "automatisez-en-utilisant-des-outils-de-reporting-pour-communiquer-lavancement-du-projet", "text": "Automatisez, en utilisant des outils de reporting pour communiquer l'avancement du projet" }, { "type": "paragraph", "html": "Météo, progression, point d'attention, décisions à prendre... Vous avez saisi toutes ces informations ? Plutôt que de rédiger un rapport, automatisez l'envoi d'un e-mail au format court et précis, une fois par semaine pour ne pas noyer sous l'information. #WeeklyEmails" }, { "type": "heading", "level": 3, "id": "synchronisez-en-interconnectant-vos-outils-pour-eviter-les-doubles-saisies-des-points-davancement", "text": "Synchronisez, en interconnectant vos outils pour éviter les doubles saisies des points d'avancement" }, { "type": "paragraph", "html": "Rappelez-vous comment on faisait avant : \"Je copie/colle le détail du projet depuis la feuille de cadrage, récupère les efforts restants sur Jira, envoie un message sur Teams pour avoir l'état d'avancement, jalons...\" STOP !" }, { "type": "paragraph", "html": "Créez les projets sur AirSaas, définissez les priorités en comité de pilotage, et recevez toutes les informations d'avancement directement sur vos canaux de communication synchronisés, comme Microsoft Teams." }, { "type": "paragraph", "html": "AirSaas se connecte aux outils les plus populaires du marché (Jira, Azure devOps, Asana...) pour faire remonter les informations essentielles à un pilotage macro de vos activités. #SmartSync" }, { "type": "heading", "level": 3, "id": "dites-stop-a-linfoxication-et-merci-aux-jalons", "text": "Dites stop à l'infoxication et merci aux jalons" }, { "type": "paragraph", "html": "Menez des examens formels des progrès par rapport au plan à des points critiques définis dans le plan de projet lorsque des étapes importantes sont terminées. Lors des jalons." }, { "type": "paragraph", "html": "Ne noyez pas vos équipes et interlocuteurs sous un diagramme de Gantt de suivi d'avancement des tâches. #ThinkJalon" }, { "type": "heading", "level": 3, "id": "etablissez-de-bons-objectifs", "text": "Établissez de bons objectifs" }, { "type": "heading", "level": 4, "id": "on-ne-reussit-que-par-rapport-aux-objectifs-fixes", "text": "On ne réussit que par rapport aux objectifs fixés" }, { "type": "paragraph", "html": "Vous ne pouvez pas suivre un avancement de ce que vous n'avez pas établi ! Les bons objectifs sont réalistes, clairs et mesurables. Quel que soit votre choix de méthode (OKR, SMART, SMAC...), rédigez une esquisse des objectifs de votre projet, puis examinez-les pour voir s'ils répondent aux exigences." }, { "type": "paragraph", "html": "Attention cependant : pas la peine de tout mesurer. Tout n'est pas KPIsable ou ROIsable." }, { "type": "insight-callout", "label": "À retenir", "html": "À retenir : aucun projet ne démarre si les objectifs ne sont pas clairement établis ! #KPI" }, { "type": "heading", "level": 3, "id": "rendez-votre-projet-visuel", "text": "Rendez votre projet visuel" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d17c7bae68096320d1afb2_6291d51b32a5ceca64de856a_avancement-visual-management-min.jpeg", "alt": "Exemple d'affiche projet montrant le cheminement projet", "caption": "Montrez le cheminement d'un projet en dessinant une montagne pour traiter les projets et missions à atteindre en plusieurs étapes" }, { "type": "heading", "level": 4, "id": "de-lascaux-a-instagram-le-pouvoir-des-images-est-une-constante", "text": "De Lascaux à Instagram : le pouvoir des images est une constante" }, { "type": "paragraph", "html": "75 % des neurorécepteurs du cerveau sont dédiés au traitement de l'information visuelle et spatiale. Source : Dan Roam, <em>Convaincre en deux coups de crayon</em>" }, { "type": "paragraph", "html": "L'agile, le lean, le design ont cette souche commune : <strong>rendre un objectif, un procédé et un résultat plus visible, plus clair.</strong>" }, { "type": "paragraph", "html": "Et en gestion de projet, les solutions sont nombreuses : <a href=\"http://www.airsaas.io/fr/gestion-de-projet/kanban-gestion-de-projet\" target=\"_blank\">Kanban</a>, affiche projet, mindmapping, plateforme avec une interface visuelle au top... Vous pouvez tenir au courant vos collègues des mises à jour de l'état d'avancement grâce à un management visuel attractif et efficace. Par exemple, grâce à l'attribut météo projet." }, { "type": "insight-callout", "label": "À retenir", "html": "À retenir : il est très motivant pour une équipe de visualiser les objectifs et KPI qu'elle a contribué à établir ainsi que les progrès réalisés (ou non) vers ces objectifs. #SimplifierPourAmplifier" }, { "type": "heading", "level": 3, "id": "adaptez-le-point-davancement-projet-a-vos-differentes-cibles", "text": "Adaptez le point d'avancement projet à vos différentes cibles" }, { "type": "paragraph", "html": "Les Directions Générales ayant compris que les cycles de trois ans de projet ne marchent plus et qu'il va falloir prioriser en continu. Elles cherchent de plus en plus à comprendre la réalité de l'avancement des travaux dans la conduite de projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8395f5cd3d844d55773d1_62ea90d5e93adcb759569555_all-projects-min2.jpeg", "alt": "Capture écran appli AirSaas montrant les modèles de présentation différents par cible", "caption": "Une seule mise à jour de votre avancement projet, différentes vues pour chaque typologie de reporting" }, { "type": "paragraph", "html": "En utilisant une plateforme dédiée, une seule saisie de la progression sera nécessaire. Et plusieurs filtres plus tard, vos mises à jour et les différents états d'avancement pré-enregistrés dans le menu seront prêts à être démultipliés aux différents lecteurs, sous forme de flash report, par exemple. #ProduceOnceDisplayEverywhere" }, { "type": "paragraph", "html": "Exemple d'usage en reporting :" }, { "type": "list", "ordered": false, "items": ["<strong>Sur Teams, pour une communication des points d'avancement du projet \"larges\"</strong> auprès de l'ensemble des personnes qui seront concernées par les résultats du projet.", "<strong>Pour l'équipe projet, l'envoi de façon régulière à l'ensemble des parties prenantes</strong> d'un <a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">rapport flash</a> au format PowerPoint grâce à un outil dédié comme AirSaas."] }, { "type": "heading", "level": 3, "id": "concentrez-vous-sur-les-faits-observables", "text": "Concentrez-vous sur les faits observables" }, { "type": "paragraph", "html": "Lors des échanges sur la progression des différents sujets, factualisez ! Demandez à chaque personne d'<strong>étayer ses opinions par des faits, en les illustrant avec un exemple concret</strong>." }, { "type": "paragraph", "html": "L'objectif est de garder une équipe concentrée sur la prise de bonnes décisions fondées sur des faits. Et n'oubliez pas de rester souple." }, { "type": "quote", "text": "Si les faits ne correspondent pas à la théorie, changez les faits.", "author": "A. Einstein" }, { "type": "heading", "level": 3, "id": "donnez-des-reperes-temporels-clairs", "text": "Donnez des repères temporels clairs" }, { "type": "paragraph", "html": "Proposer un avancement projet implique de zoomer et dé-zoomer en permanence sur les données, de <strong>faciliter l'orientation de chacun dans la transformation en cours</strong>. Problème : quand on a beaucoup de chantiers le rapport devient très vite illisible." }, { "type": "paragraph", "html": "Dessinez les chemins critiques du projet pour définir une feuille de route adaptée et cohérente. Elle vous permettra de donner de la visibilité sur les échéances et les actions en cours, passées et à venir, ainsi qu'à monitorer l'état de santé de l'avancement du projet. Le chemin vers chaque objectif et vers le résultat final." }, { "type": "heading", "level": 4, "id": "une-ligne-de-temps-qui-permet", "text": "Une ligne de temps qui permet :" }, { "type": "list", "ordered": false, "items": ["De grouper les items du rapport par météo, risque, objectif, statut et importance", "De naviguer dans le temps de l'avancement du projet (un peu à la Google Maps)"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d17c7bae68096320d1afac_62ea9133dc70751b9f21198e_timeline-min.jpeg", "alt": "Capture écran appli AirSaas montrant la time line du portefeuille projet", "caption": "Une ligne de temps, pour une vision temporelle claire : indispensable" }, { "type": "heading", "level": 3, "id": "un-type-de-projet-un-type-de-suivi", "text": "Un type de projet = un type de suivi" }, { "type": "paragraph", "html": "Micro-projet, projet transverse, d'entreprise, \"POC\", projet bac à sable, stratégique, légal, de direction, de département... On se mélange les post-it ! Et surtout : on risque le syndrome du canon pour la mouche, c'est-à-dire sortir l'artillerie lourde de votre management de projet pour rien." }, { "type": "paragraph", "html": "Sans perdre de vue les fondamentaux d'un point d'avancement de projet : une mise à jour sur la progression. Il est important que le chef de projet adapte son action, ses outils, au type de projet suivi." }, { "type": "paragraph", "html": "Sur ce thème, découvrez par exemple la définition / classification de Frédéric Navarro, quatre fois DSI et aujourd'hui directeur de projet indépendant au sein d'ESINFO. Extrait de l'épisode 28 de CIO Révolution, le Podcast produit par AirSaas :" }, { "type": "quote", "text": "\"On a instauré un dialogue mensuel métier au cours duquel chacun comprend le vocabulaire et les enjeux de chacun. Un dialogue ou chacun accepte de se remettre en cause. Et, au bout de 6 mois, on a une vraie vision de chaque département dans son rythme pour avancer, et chacun s'engage\".", "author": "Frédéric Navarro — DSI, Manager de Transition ESINFO (extrait de l'épisode 28 du Podcast CIO Révolution produit par AirSaas)" }, { "type": "paragraph", "html": "Dans un <strong>dialogue constant avec l'ensemble des directions métiers</strong>, il a catégorisé chaque projet à l'aide de 4 différents niveaux (projet stratégique, légal, de direction, de département). En fonction de l'avancement de chaque typologie, l'ensemble est repriorisé pour des points d'avancement spécifiques chaque mois." }, { "type": "paragraph", "html": "Besoins, différentes étapes d'avancements, ressources, compétences demandées... le projet est alors présenté sous tous ces aspects. Les différents départements métiers interviennent au fur et à mesure afin de discuter des responsabilités qu'elles auraient dans le cadre de ce projet ainsi que de ses disponibilités." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d17c7bae68096320d1af9e_6291bcaa799a82696652be4a_design-projet-min.jpeg", "alt": "Illustration d'une pratique de DSI - pyramide projets", "caption": "Ces quatre niveaux constituent une base de classement, mais ce n'est en rien ce qui permet de scorer les différents projets et leur avancement" }, { "type": "paragraph", "html": "Sur la base d'une cinquantaine de chantiers menés par la DSI, trois ou quatre sont de niveau 1, considérés comme majeurs, seront régulièrement évoqués par la DSI avec la Direction. Cinq ou six seront de niveau 2, et ensuite chaque direction et/ou département va avoir un certain nombre de petites missions, de petits sujets à traiter. En général, le processus de définition / reclassification est quelque chose de rapide s'il est fait de cette manière." }, { "type": "heading", "level": 2, "id": "a-retenir", "text": "À retenir" }, { "type": "insight-callout", "label": "À retenir", "html": "<ul><li>Les <strong>trois ingrédients indispensables</strong> d'un processus de point d'avancement de projet efficace sont <strong>la fréquence continue, la standardisation et l'adaptation à vos typologies</strong> des personnes.</li><li>Avoir un trop beau planning de Gantt, envoyer un trop long email, produire le rapport PowerPoint le plus design du CAC40 ne suffit pas ? Ce sont <strong>les collaborateurs et leurs bonnes relations qui font avancer les projets et qui transforment l'entreprise !</strong></li><li>Un bon point d'avancement remplit un <strong>rôle d'alignement des équipes.</strong></li></ul>" }, { "type": "paragraph", "html": "Vos points d'avancement de projet sont sur la bonne voie ? C'est le moment de revisiter un classique, et de mettre à jour votre vision de l'<a href=\"/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">analyse des risques projet.</a>" }], "toc": [{ "href": "#les-pieges-a-eviter-pour-les-points-davancement", "label": "Les pièges à éviter pour les points d'avancement", "level": 2 }, { "href": "#12-pratiques-pour-garder-les-points-davancement-sur-la-bonne-voie", "label": "12 pratiques pour garder les points d'avancement sur la bonne voie", "level": 2 }, { "href": "#a-retenir", "label": "À retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-gerer-lagressivite-dans-les-comites-de-pilotage", "skip": false, "meta": { "title": "Comment gérer l'agressivité dans les réunions de pilotage ?", "h1": "Comment gérer l'agressivité dans les réunions de pilotage ?", "description": "Comment gérer l'agressivité dans les comités de pilotage ? 7 conseils pour recadrer les comportements agressifs, maintenir le calme et préserver le collectif.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ac094db1450036c1fb3e6a_copil-projet-agreessivite-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "17/6/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "17/6/2022" }, "blocks": [{ "type": "paragraph", "text": "On a tous en tête un email violent, une personne qui fait peur aux autres membres de la réunion de pilotage. Celle qui ne laisse pas les autres finir leur idée, leur coupe la parole sans arrêt. Quelqu'un qui hausse la voix, crie, tape éventuellement du poing sur la table ou quitte le Copil en claquant la porte ! Et avouons-le : le contexte de pandémie et confinement n'a pas arrangé la situation." }, { "type": "paragraph", "text": "Bienheureux ceux qui lors de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-animer-un-comite-de-pilotage\" target=\"_blank\">l'animation d'un comité de pilotage</a> n'ont jamais été perturbés par un ou plusieurs membres. Agressifs, faux experts, adeptes du mutisme... Mais <strong>comment réagir face au manque de respect ?</strong> Y a-t-il des façons de recadrer une personnalité difficile ? Qui doit intervenir ? Comment agir et stopper habilement les comportements à risques avant qu'il ne soit trop tard ? Qu'est-ce que veut dire travailler sur le climat dans les comités de pilotage ? Enfin, comment évaluer ce qui est un comportement hors-jeu sanctionnable ? Ce qui ne l'est pas ?" }, { "type": "paragraph", "text": "En creux : comment gérer sa propre agressivité, pour garder son \"self-control\", son \"anger management\" ? On vous dit l'essentiel de ce qu'il faut connaître sur l'agressivité, on vous a préparé le kit de survie en milieu hostile. Vous repartirez avec une sélection des 7 astuces à mobiliser lorsque cela se produit." }, { "type": "paragraph", "text": "Cet article fait partie d'un dossier <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">Comité de pilotage ou Copil : Les bases</a> qui reprend l'essentiel à savoir sur le comité de pilotage projet - des éléments simples et pragmatiques." }, { "type": "heading", "level": 2, "id": "reperer-les-types-dagression-en-reunion-de-pilotage-lesquelles-sanctionner-ou-non", "text": "Repérer les types \"d'agression\" en réunion de pilotage : lesquelles sanctionner ou non ?" }, { "type": "paragraph", "text": "Rappelons que l'agressivité est une réaction à une émotion de colère et/ou de frustration. Elle peut être une conséquence de la peur, du manque d'assurance, de l'envie, de la jalousie, du fait que l'on ne sache pas comment agir dans ce comité projet..." }, { "type": "paragraph", "text": "Avant tout, la première chose à faire est de savoir identifier ce qui est du registre de la loi et ce qui ne l'est pas. Que ce soit en tant qu'animateur du processus de Copil, de chef de projet ou de participant, votre responsabilité est de savoir reconnaître ce qui est du domaine de l'acceptable, et ou du non négociable. Nul n'est censé ignorer la loi, même dans la gestion de projet !" }, { "type": "heading", "level": 3, "id": "deux-stades-de-comportement-agressif-pour-deux-reactions", "text": "Deux stades de comportement agressif pour deux réactions" }, { "type": "list", "ordered": true, "items": ["L'agression \"<strong>hors la loi</strong>\" : je sanctionne !", "L'agresseur <strong>irrespectueux, juste à la limite de la violence</strong> : je recadre et \"on\" re négocie les règles."] }, { "type": "paragraph", "text": "<strong>Premier cas : aucune question à se poser, on sanctionne.</strong>" }, { "type": "paragraph", "text": "Une agressivité qui dépasse la limite. L'agression physique, l'agression verbale violente... L'objectif ici n'est pas de composer ou négocier. Mais bel et bien de mettre les gens en sécurité. En entreprise comme ailleurs aucune des parties-prenantes n'est censé ignorer la loi." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d085ca2ae5522f08c87248_62ac0853a465af801fa657af_agression-redflag-arisaas.jpeg", "alt": "Red flag en cas d'agressivité hors cadre", "caption": "Colère, frustration : rien ne justifie l'agressivité \"ouverte\" qui s'en prend aux personnes." }, { "type": "paragraph", "text": "Sur ce point, il est important de <strong>faire la différence entre des erreurs</strong>, une agressivité par exemple liée à un excès d'émotion, <strong>et des fautes</strong>. Par exemple un comportement \"volontaire\" qui met en \"danger\" l'intégrité d'un autre individu et le collectif. La réaction à adopter est avant tout d'arrêter le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comite-de-pilotage-definitions-et-incomprehensions\" target=\"_blank\">comité de pilotage</a> si besoin. Pour protéger les personnes. Pour ensuite formaliser le conflit, factualiser, laisser une trace écrite de ce qui vient de se produire." }, { "type": "paragraph", "text": "Ici, votre responsabilité individuelle ou en tant que cadre est de ne pas fermer les yeux. L'organisation \"doit\" sanctionner un comportement. Montrer qu'il y a une conséquence, qu'il n'y a pas d'impunité. En un mot à faire preuve de courage managérial." }, { "type": "paragraph", "text": "Dans le second stade de comportement agressif, on retrouve le profil plus classique de <strong>l'agressif, impoli, irrespectueux qui exerce à la limite du carton rouge.</strong> Exemple : il hausse la voix, crie, se lève, lance une phrase à \"l'emporte-pièce\" pour attaquer personnellement certains membres de la réunion de pilotage, voire tout le Copil ! Il s'en prend aux personnes, pas à ce qu'elles font. Idem : <strong>ici un recadrage et une remédiation sur les règles sont à prévoir</strong>. En cas d'irrespect ou d'agression verbale, rappelez de manière ciblée les règles de discussion convenues pour les réunions de pilotage. Demandez aux participants de s'y tenir et d'éviter un comportement agressif pendant tout l'avancement du projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d085ca2ae5522f08c8724b_62ac0a4a136f69945f3ddd76_copil-tension-airsaaas.jpeg", "alt": "agressivité dans les copil", "caption": "Problème d'agressivité : réagissez." }, { "type": "paragraph", "text": "Dans ce même type, on reconnaît moins facilement <strong>le passif agressif occasionnel.</strong> Celui qui ignore même qu'il est agressif. C'est un membre du Copil qui ne laisse pas les autres finir leur idée, leur coupe la parole sans arrêt. Quelqu'un qui réagit par des commentaires subjectifs, notamment par des attitudes et un langage non verbal explicite, voire des soupirs type \"Pff\"... Bref : un irrespect, une agressivité contenue, mais clairement présente. Nous verrons ci-dessous dans les 10 astuces comment réagir face à l'agressivité de ce type." }, { "type": "paragraph", "text": "D'emblée, s'il n'y avait qu'une chose à retenir : vous aurez à mener un recadrage individuel et une négociation collective sur les règles de base de votre réunion de pilotage collective." }, { "type": "heading", "level": 2, "id": "7-conseils-pour-gerer-lagressivite-dans-les-comites-de-pilotage", "text": "7 conseils pour gérer l'agressivité dans les comités de pilotage" }, { "type": "heading", "level": 3, "id": "ignorer-empirer-prenez-le-comportement-agressif-au-serieux-et-ne-pas-le-minimiser", "text": "Ignorer = empirer - Prenez le comportement agressif au sérieux et ne pas le minimiser" }, { "type": "paragraph", "text": "<strong>L'agressif est une personne qui attaque et cherche la confrontation.</strong> Il n'attend de vous qu'une seule chose : que vous répliquiez de manière agressive. Au contraire, gardez votre calme et laissez-le s'exprimer jusqu'à retrouver son propre calme et sa capacité d'écoute, sans quoi vous ne réussirez pas à vous faire entendre." }, { "type": "paragraph", "text": "<strong>Empêchez l'interlocuteur irrespectueux de monopoliser le débat</strong>, favorisez l'esprit collectif, base du mode projet. Notez les opinions exprimées à l'aide de mots-clés par exemple. Montrez que vous prenez au sérieux l'opinion du membre du comité. Demandez-lui et à l'équipe de projet d'associer d'autres mots-clés afin de récapituler cette opinion." }, { "type": "paragraph", "text": "<strong>N'ignorez pas : au contraire, requestionnez son opinion</strong> : \"Comment parviens-tu à cette conclusion ?\" \"Pour quelle raison emploies-tu ce ton ?\". Recentrez ses interventions sur l'objet de la présentation." }, { "type": "heading", "level": 3, "id": "maintenez-un-langage-non-verbal-decontracte-et-refletez-lagressivite", "text": "Maintenez un langage non verbal \"décontracté\" et reflétez l'agressivité" }, { "type": "paragraph", "text": "<strong>Ne vous laissez pas emporter par vos émotions</strong>. Choisissez vos réactions. Une pratique basique : concentrez-vous pendant un instant en toute conscience sur votre respiration. L'œil lointain." }, { "type": "paragraph", "text": "\"Ne paraissez jamais étonné\" serait un peu la règle d'or. Pensez au film <em>Itinéraire d'un enfant gâté</em> et à la scène culte où Jean-Paul Belmondo entraîne Richard Anconina à l'art oratoire. Plus facile à dire qu'à faire. Attention : l'idée est de rester vous-même, d'utiliser un langage non verbal décontracté et détaché. Entraînez-vous pour trouver votre \"poker face\", pas ce sourire crispé :-) ! C'est votre vrai sourire, l'humour qui va faire le travail." }, { "type": "paragraph", "text": "Souvent les gens ne se rendent pas compte de leur agressivité. Une des astuces qui fonctionne : reprendre la même phrase que votre agresseur avec une autre intonation." }, { "type": "heading", "level": 3, "id": "ne-vous-sentez-pas-oblige-de-repondre-a-toutes-les-agressions-verbales", "text": "Ne vous sentez pas obligé de répondre à toutes les agressions verbales" }, { "type": "paragraph", "text": "<strong>Utilisez le silence comme outil d'apaisement</strong>. Si vous souhaitez répondre, choisissez vos batailles pour contre-attaquer par surprise. Mieux vaut une riposte qui touche que cinq contre-attaques molles !" }, { "type": "paragraph", "text": "Si on vous coupe la parole, n'hésitez pas à répondre avec une phrase simple et calme. Du type \"Oui, j'aimerais beaucoup entendre ton avis là-dessus, et je termine ce que j'ai à dire pour te laisser réagir.\" Notez le \"Oui et\" à la place du \"Non, mais...\"." }, { "type": "paragraph", "text": "Dans la mesure du possible, <strong>n'en faites pas une affaire personnelle.</strong> Essayez même de vous désensibiliser, en général les agresseurs s'en prennent à tout le monde. Malgré les apparences vous n'êtes pas forcément visé !" }, { "type": "heading", "level": 3, "id": "reagir-face-au-manque-de-respect-appuyez-sur-pause", "text": "Réagir face au manque de respect : appuyez sur \"pause\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d085ca2ae5522f08c87250_62ea8cd54a841502f0c253da_exemple-irrespect.jpeg", "alt": "Photo Gérald Darmanin Appoline de Malherbe", "caption": "L'exemple emblématique d'un \"clash\" entre le ministre de l'intérieur et une journaliste" }, { "type": "paragraph", "text": "Vous avez peut être vu passer cet échange où, confronté aux derniers chiffres de l'insécurité, le ministre de l'Intérieur Gérald Darmanin a jugé l'analyse de la journaliste \"un peu populiste\" et n'a pas hésité à la prendre de haut. \"Est-ce que vous me laissez parler, madame? Votre présentation est très rapide et un peu populiste. (...) Non mais ne vous vexez pas, calmez-vous, madame, ça va bien se passer\", lance-t-il alors sur un ton condescendant." }, { "type": "paragraph", "text": "\"Je vous demande pardon?\", réagit Apolline de Malherbe, outrée. \"Ça va bien se passer\", répète Gérald Darmanin. La journaliste reprend et souligne \"Gérald Darmanin, attendez, comment vous me parlez?\" s'indigne-t-elle. \"Je trouve ça sidérant votre manière de répondre. Ce n'est pas une réponse, c'est presque une offense\", souligne-t-elle. \"Ne vous vexez pas, je réponds comme vous m'agressez\", tente de répliquer le ministre." }, { "type": "paragraph", "text": "Au moment ou l'interview sort du cadre habituel de la joute oratoire pour devenir une attaque irrespectueuse, la réaction de la journaliste est un modèle du genre. Elle met ses bras en croix en disant tout simplement \"Pause on arrête de jouer\" sur un ton calme et déterminé. En esquivant une question de fond, l'interlocuteur a créé une seconde polémique." }, { "type": "paragraph", "text": "Un rappel : ce n'est jamais une bonne idée de dire à quelqu'un : \"calme-toi\". En conduite de projet, en gouvernance, ou dans la vie de tous les jours !" }, { "type": "heading", "level": 3, "id": "art-du-feedback-cnv-soyez-au-niveau-sur-les-fondamentaux-de-la-communication", "text": "Art du feedback, CNV : soyez au niveau sur les fondamentaux de la communication" }, { "type": "paragraph", "text": "Mieux vaut prévenir que guérir. N'hésitez pas à effectuer une piqûre de rappel bien utile des trois méthodes de communication bienveillante / non violentes (OSCAR, DESC et OSBD) pour transformer vos messages difficiles en feedbacks constructifs et efficaces ! Y compris dans un email." }, { "type": "paragraph", "text": "Une image vaut mille mots. Pour cette remise à niveau, rien de mieux que le <em>Sketchnote</em> (magistral) créé par Maxence Walbrou, coach, facilitateur et illustrateur." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d085ca2ae5522f08c87254_62ea8d33891af0954c51eb7d_feedback-bloculus.jpeg", "alt": "Illustration Maxence Walbrou", "caption": "Source illustration Maxence Walbrou - Blog bloculus.com article \"Sauvez des vies faites des feedbacks\"" }, { "type": "heading", "level": 3, "id": "travaillez-sur-le-climat-avant-pendant-et-apres-les-reunions-de-pilotage", "text": "Travaillez sur le climat avant, pendant et après les réunions de pilotage" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d085ca2ae5522f08c87257_62ac0b5088d4191c9d445bcf_copli-regulation-airsaas.jpeg", "alt": "Travail sur le climat", "caption": "" }, { "type": "paragraph", "text": "En cas de signaux faibles d'agressivité à répétition, le travail de prévention peut encore être réalisé. Il peut s'agir par exemple de <strong>se mettre d'accord sur des règles de fonctionnement</strong> - sorte de \"code d'honneur\" collectif avant les comités. On négocie ensemble les règles relatives à la communication, l'écoute active, l'usage des smartphones, l'emploi du \"Je\" versus le \"On\". Et encore, à limiter le \"tu qui tue\". Bref : on négocie et on en parle des besoins de chacun." }, { "type": "paragraph", "text": "Vous pouvez aussi décider d'alléger le portefeuille projet ! Définissez clairement ce qui est vital et concentrez la réunion de pilotage dessus - de toute façon vous n'aurez pas le temps de faire autre chose." }, { "type": "paragraph", "text": "<strong>Un des secrets est de respecter les temps d'inclusion.</strong> Ces moments type \"ice breaker\", ou météo personnelle, sont là pour créer un climat propice aux échanges constructifs, pour libérer la parole. Ne faites pas l'impasse sur ces moments plus légers. Alterner temps forts et temps morts est une bonne façon de faire baisser la (sur-) tension inutile; et éviter toute violence." }, { "type": "paragraph", "text": "<strong>Enfin sachez interrompre un Copil avant que la colère ne l'emporte !</strong> Si les émotions ne redescendent toujours pas, interrompez la réunion de pilotage. Faites une pause de dix minutes qui permettra à chacun de se calmer. Profitez de la pause pour prendre le collaborateur en tête à tête et pour discuter au calme de son comportement agressif." }, { "type": "paragraph", "text": "À froid, après le Copil, n'hésitez pas à revenir vers le membre qui a eu un comportement agressif pour prendre un rendez-vous informel afin d'entendre ce qui n'a pas été dit." }, { "type": "heading", "level": 3, "id": "savoir-demander-de-laide-quand-lagressivite-est-devenue-ingerable-dans-le-projet", "text": "Savoir demander de l'aide quand l'agressivité est devenue ingérable dans le projet" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d085ca2ae5522f08c87244_62ac0bfaa1fafbde9f0e15ca_help-airsaas-copil-projet.jpeg", "alt": "Tuche HELP en copil", "caption": "Face à des situations dysfonctionnelles, signalez et transmettez la gestion a des experts" }, { "type": "paragraph", "text": "Vous n'êtes pas seuls ! <strong>Un signalement très factuel est à transmettre par écrit auprès de votre hiérarchie</strong> et des Ressources Humaines. Plusieurs solutions sont envisageables collectivement si la situation a dégénéré. Récemment par exemple une médiation a été menée au sein d'une DSI ou avait lieu une croissance forte et une fusion / réorganisation interminable. Ces contextes cumulés généraient de grandes difficultés et une violence ouverte dans les échanges." }, { "type": "paragraph", "text": "Autre exemple de solution possible : un travail de baromètre social peut utilement être mené. Mais n'oubliez pas que la prévention des risques psychosociaux est un métier !" }, { "type": "paragraph", "text": "Pour aller plus loin, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comite-pilotage-projet\" target=\"_blank\">consultez nos 5 astuces pour que tout se passe bien en comité de pilotage projet</a>." }, { "type": "heading", "level": 2, "id": "le-mot-de-la-fin-vigilance-et-prevention-pour-eviter-tout-exces-dagressivite", "text": "Le mot de la fin : vigilance et prévention pour éviter tout excès d'agressivité" }, { "type": "paragraph", "text": "En management de projet comme dans toute chose, c'est l'excès qui est toxique. Un peu d'agressivité est tolérable. Il ne faut pas dramatiser. Il faut le souligner également : quand c'est passionnel, cela veut également dire qu'il y a de l'engagement ! <strong>Savoir opposer ses désaccords, même vertement, peut parfois être très bénéfique.</strong> Restons simplement vigilants sur les comportements excessifs et intraitables sur toute violence illégale." }, { "type": "paragraph", "text": "Vous avez lu les 7 astuces pour décrypter et parer plus sereinement les éventuels futurs comportements agressifs en réunion de pilotage. Le décryptage et le déminage de comportements limites vous ont intéressé ? Poursuivez sur le thème de la prévention avec la lecture de l'article <a href=\"/gestion-de-projet/comment-bien-preparer-un-comite-de-pilotage\" target=\"_blank\">Comment bien préparer un comité de pilotage ?</a>" }], "toc": [{ "label": "Repérer les types \"d'agression\" en réunion de pilotage : lesquelles sanctionner ou non ?", "href": "#reperer-les-types-dagression-en-reunion-de-pilotage-lesquelles-sanctionner-ou-non", "level": 2 }, { "label": "7 conseils pour gérer l'agressivité dans les comités de pilotage", "href": "#7-conseils-pour-gerer-lagressivite-dans-les-comites-de-pilotage", "level": 2 }, { "label": "Le mot de la fin : vigilance et prévention pour éviter tout excès d'agressivité", "href": "#le-mot-de-la-fin-vigilance-et-prevention-pour-eviter-tout-exces-dagressivite", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-mettre-en-place-un-comite-de-pilotage", "skip": false, "meta": { "title": "Comment mettre en place un comité de pilotage ?", "h1": "Comment mettre en place un comité de pilotage ?", "description": "Comment mettre en place un comité de pilotage ? Découvrez les rôles, membres, bonnes pratiques et outils pour créer un Copil efficace et durable.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea67d4156de885e5b58180_comment-mettre-en-place-comite-pilotage.jpg", "alt": "" }, "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "4/7/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "publishedDate": "4/7/2022" }, "blocks": [{ "type": "heading", "level": 2, "id": "pourquoi-faire-un-copil", "text": "Pourquoi faire un Copil ?" }, { "type": "paragraph", "html": "Un projet fonctionne toujours à deux niveau, il part d'un enjeu pour l'entreprise et d'un objectif issu d'une vision stratégique, il implique de ce fait des cadre supérieur de l'entreprise mais également des acteurs qui le mettront en œuvre dans une phase plus opérationnelle, on y retrouvera souvent des services métiers, des compétences spécifiques (internes ou externes) et des fonctions support. Les cadres supérieurs et le sponsor s'assurent de la direction stratégique du projet et de la mise à disposition des ressources et conditions nécessaires à son exécution. Ensuite les autres membres du projet s'affaire à exécuter et réaliser opérationnellement le projet." }, { "type": "paragraph", "html": "Problème : Le projet peut échouer assez rapidement par manque de vision stratégique, jeux de pouvoir et politique interne, mauvaise allocation des ressources, mauvaise gestion des tensions et des problèmes inhérents à tout projet qui même si planifié parfaitement comportera presque toujours des imprévus. Et l'équipe des opérations ne sera pas toujours en mesure ou à la bonne position dans l'entreprise pour résoudre ces problèmes et prendre les bonnes décisions." }, { "type": "paragraph", "html": "D'où l'importance de la mise en place d'un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comite-de-pilotage-definitions-et-incomprehensions\" target=\"_blank\">comité de pilotage projet</a> afin d'arbitrer et prendre les décisions stratégiques pour sa réussite, ainsi que de donner les moyens et rassembler les facteurs qui donneront toutes ses chances au projet d'aboutir." }, { "type": "paragraph", "html": "Le succès ou l'échec d'un projet dépend très souvent des actions menées par celui-ci. Bonne nouvelle, vous pourrez approfondir les fondamentaux dans notre article de référence : <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">Comité de pilotage ou Copil : Les bases.</a>" }, { "type": "heading", "level": 2, "id": "quelle-est-la-difference-entre-un-comite-de-direction-codir-un-comite-de-pilotage-copil-et-un-comite-de-projet-coproj", "text": "Quelle est la différence entre un comité de direction CODIR, un comité de pilotage Copil et un comité de projet COPROJ ?" }, { "type": "list", "ordered": false, "items": ["Le Codir : Par définition le comité de direction rassemble tous les cadres dirigeants de l'entreprise, cela favorise une gestion horizontale des préoccupations clés et actions stratégiques pour l'entreprise. Il peut survenir par exemple pour la gestion de crise ou encore répondre aux enjeux stratégiques majeurs.", "Le Coproj : Le comité de projet à une vocation très opérationnelle : suivi des tâches et actions en cours, résolution opérationnelle de problématiques selon les arbitrages et décisions stratégique (prise en Copil), coordination et accompagnement des équipes dans les opérations et les difficultés opérationnelles.", "Le Copil : Le comité de pilotage quant à lui est destiné principalement à s'assurer de l'avancement du projet en accord avec les objectifs prédéfini et stratégique pour l'entreprise, il est composés de cadres de l'entreprise qui permettront de faire les arbitrages difficiles mais aussi de donner accès aux ressources et aux conditions qui permettront à la réussite du projet."] }, { "type": "heading", "level": 2, "id": "quel-est-le-role-dun-comite-de-pilotage", "text": "Quel est le rôle d'un comité de pilotage ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea652fda8fd01771298726_role%20copil-min-min.jpg", "alt": "rôle copil" }, { "type": "list", "ordered": false, "items": ["<strong>Donner la direction stratégique, impliquer et mobiliser les parties prenantes</strong>", "<strong>Prendre des décisions et faire des arbitrages.</strong>", "<strong>Veiller au bon déroulement du projet</strong> et s'assurer qu'il est <strong>en accord avec les stratégies globales de l'entreprise.</strong>", "<strong>Évaluer la qualité et la santé du projet à chaque réunion</strong>. Si certains problèmes  doivent être améliorés, les principaux intervenants peuvent les soulever pour les résoudre.", "<strong>Donner au chef de projet le pouvoir d'agir</strong> et d'utiliser les ressources de l'entreprise pour mener l'exécution, l'avancement du projet.", "<strong>Résoudre les conflits entre départements</strong>, les problèmes liés au coût, au temps, au risque, aux ressources, à la qualité et à la portée.", "<strong>Surveiller les progrès du projet par rapport aux objectifs convenus</strong> et <strong>résoudre les problèmes</strong> qui ne permettent pas au projet de progresser à temps."] }, { "type": "heading", "level": 2, "id": "quelles-sont-les-personnes-qui-constituent-un-comite-de-pilotage", "text": "Quelles sont les personnes qui constituent un comité de pilotage ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea6596ba10f500b5f74b47_casting%20copil-min.jpg", "alt": "casting copil" }, { "type": "paragraph", "html": "Si vous souhaitez faire un Copil réellement efficace et qui dénote avec ce qui peut se faire habituellement, la sélection des membres du comité est critique et peut changer complètement la dynamique et l'issue d'un projet." }, { "type": "paragraph", "html": "En membres clés que l'on retrouve habituellement on aura :" }, { "type": "paragraph", "html": "<strong>Le sponsor du projet</strong> : Généralement faisant partie du Codir / Comex, Il donne la direction stratégique au projet, il fait en sorte de pouvoir donner les ressources et conditions nécessaires au chef de projet afin qu'il puisse correctement coordonner l'exécution du projet. Il sera chargé également de trancher dans les arbitrages et décisions difficiles." }, { "type": "paragraph", "html": "<strong>Le chef de projet</strong> : C'est le chef d'orchestre du projet, le bras armé du sponsor, ils travaillent tandem afin de s'assurer du bon déroulement du projet, il est soutenu par le sponsor au sein du comité et il est également les yeux et les oreilles du sponsor." }, { "type": "paragraph", "html": "C'est là où vous avez la possibilité de <strong>ne pas faire comme les autres</strong> : Là où <strong>la plupart n'implique les représentant des métiers</strong> et/ou fonctions support <strong>que plus tard ou ponctuellement</strong>, l'astuce ici est de pouvoir <strong>intégrer tous les représentants des parties prenantes clés dans la vie du projet le plus tôt possible</strong>. En effet, beaucoup de projets ont échoué au moment ou le \"dossier\" tombe sur le bureau, c'est-à-dire, seulement quand on attend des actions opérationnelles de leurs part et c'est souvent là que les problèmes critiques arrivent en interne avec <strong>des causes d'échecs quasi immédiat</strong> rendant la suite du projet vraiment difficile voire qui donne lieu à un No Go." }, { "type": "paragraph", "html": "On privilégiera le fait de <strong>les impliquer au plus tôt</strong> afin de pouvoir prendre en compte leurs points d'attention et <strong>fluidifier le futur opérationnel du projet</strong>." }, { "type": "paragraph", "html": "L'autre particularité sera de nommer <strong>un porteur de projet côté métier</strong>, ce qui permettra de bien impliquer le ou les services clés et d'évangéliser le projet pour les équipes en interne qui sont pour le moment extérieures au projet. Cela permettra au chef de projet de piloter la mise en œuvre tout en travaillant et en aidant le porteur de projet à <strong>bien identifier l'alignement entre le problème à résoudre et la mise en place de solution.</strong>" }, { "type": "heading", "level": 3, "id": "qui-sont-les-bons-membres-dun-comite-de-pilotage", "text": "Qui sont les bons membres d'un comité de pilotage ?" }, { "type": "paragraph", "html": "On privilégiera au maximum <strong>les éléments moteurs</strong> de la démarche, qui ont envie de <strong>faire bouger les lignes</strong> et qui ont un attrait pour le projet, on limitera donc les personnalités sceptiques ou hostiles à l'idée du projet ou de sa façon de le mener à bien." }, { "type": "paragraph", "html": "On souhaitera pouvoir rassembler les personnes dans l'entreprise <strong>qui possèdent les ressources et l'influence nécessaire </strong>pour la réalisation du projet" }, { "type": "heading", "level": 3, "id": "qui-dautre-peut-participer-au-comite-de-pilotage", "text": "Qui d'autre peut participer au comité de pilotage ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2e4ff9ad8bb435b1f364f_guest%20copil-min.jpeg", "alt": "Invité mystère copil" }, { "type": "paragraph", "html": "On peut parfois faire appel à <strong>des personnalités extérieures</strong> à l'entreprise afin de <strong>donner du peps à la vision ou à l'exécution du projet</strong>, ou encore faire appel à des experts qui permettront de clarifier certains sujets et/ou à <strong>éliminer certains biais cognitifs</strong> potentiellement bloquants de certaines parties prenantes." }, { "type": "paragraph", "html": "Il peut être intéressant également pour la direction de l'entreprise ou le sponsor d'impliquer d'autres membres d'autres services ou d'autres filiales ponctuellement afin de les sensibiliser à la démarche si ils veulent la reproduire dans le futur ailleurs sur un autre projet, ou dans une <strong>dynamique d'harmonisation des projets internes</strong> pour <strong>éviter les doublons de projet</strong> ou de solutions à mettre en place." }, { "type": "heading", "level": 2, "id": "desamorcer-les-enjeux-de-politique-interne-au-profit-des-interets-superieurs-de-lentreprise", "text": "Désamorcer les enjeux de politique interne au profit des intérêts supérieurs de l'entreprise" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea65e11bc460440167d3e7_copil%20politique-min.jpg", "alt": "Jeu politique COPIL" }, { "type": "heading", "level": 3, "id": "le-role-du-sponsor-dans-le-copil", "text": "Le rôle du sponsor dans le Copil" }, { "type": "paragraph", "html": "Dans le comité de pilotage le sponsor est garant de plusieurs choses :" }, { "type": "paragraph", "html": "Il donne <strong>la ligne stratégique</strong>, challenge <strong>l'avancement</strong> et joue un rôle clé dans <strong>les arbitrages</strong>. Aussi, il facilitera le travail du chef de projet, en suggérant des idées en lien avec <strong>la stratégie d'entreprise</strong> mais aussi en assurant <strong>la gestion des conflits</strong> dans le cas ou le management transverse ne serait pas suffisant, il a le dernier mot, <strong>il est capable de trancher</strong> en cas de décisions en ballotage et soumettre ou donner des actions correctives durant le Copil." }, { "type": "paragraph", "html": "Il est garant de l'intérêt de l'entreprise dans le projet et sera <strong>valoriser le bon état d'esprit</strong> ainsi que les actions qui vont dans le sens du projet." }, { "type": "heading", "level": 3, "id": "placer-les-interets-du-projet-au-dessus-des-enjeux-personnels", "text": "Placer les intérêts du projet au-dessus des enjeux personnels" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2e52c41058e5e79931f2b_conflit%20interet%20copil-min.png", "alt": "Conflit copil" }, { "type": "paragraph", "html": "Un grosse partie des projets touchent souvent plusieurs services et plusieurs compétences métiers, aussi les actions d'un projet peuvent s'additionner pour certains avec leurs activités principales, c'est le cas des projets transverses, à ce titre il n'est pas évident pour tout le monde que les actions d'un projet transverses sont tout aussi importantes pour l'entreprise que les actions de leurs missions principales." }, { "type": "paragraph", "html": "Aussi il est important de <strong>fixer les règles et le cadre dès le départ</strong> sur l'investissement attendu ainsi que de comment les décisions seront prises et quel est <strong>le rôle attendu de chaque participant.</strong>" }, { "type": "paragraph", "html": "Quant à ceux qui penseraient à la jouer perso, voyant le projet comme une opportunité pour obtenir quelque chose par ailleurs ou simplement pour briller, sachez <strong>ne valoriser que les actions qui font directement avancer le projet</strong> et celles qui <strong>favorisent le team spirit.</strong>" }, { "type": "paragraph", "html": "Instaurer un climat de confiance ainsi que de valoriser les membres du projet dans leur capacité à mener le groupe vers la réussite du projet." }, { "type": "paragraph", "html": "Pour creuser le sujet, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-gerer-lagressivite-dans-les-comites-de-pilotage\" target=\"_blank\">découvrez comment gérer l'agressivité dans les comités de pilotage</a>." }, { "type": "heading", "level": 2, "id": "comment-creer-un-comite-de-pilotage-efficace-dans-la-duree", "text": "Comment créer un comité de pilotage efficace dans la durée ?" }, { "type": "heading", "level": 3, "id": "droit-au-but", "text": "Droit au but" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea6652dbd70f0628a74f0d_mur%20escalade%20copil-min.jpg", "alt": "Un mur d'escalade analogie copil" }, { "type": "paragraph", "html": "<strong>Chercher le chemin le plus efficace et qualitatif</strong> vers l'atteinte des objectifs du comité de pilotage, peu de monde prend du plaisir ou gagne en efficacité dans les réunions dîtes \"réunionites\"," }, { "type": "paragraph", "html": "Plus vous aurez dans votre comité de pilotage des membres occupés, plus ils apprécieront <strong>les Copil efficaces</strong> qui vont droit au but. Pour cela il faut se concentrer sur un ordre du jour et <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-modele-de-presentation-pour-votre-comite-de-pilotage\" target=\"_blank\">une <strong>présentation synthétique</strong></a> possible en se restreignant simplement aux <strong>informations nécessaires pour prendre des décisions</strong>. Il peut être très efficace de catégoriser les points de l'ordre du jour par ordre de priorité et d'impact sur le projet." }, { "type": "paragraph", "html": "Pour rappel, tout vos support doivent se contenter de remplir les objectif du rôle du comité de pilotage cité précédemment. Vous retrouverez plus d'informations sur ce point dans l'article : Comment bien préparer son comité de pilotage" }, { "type": "heading", "level": 3, "id": "informations-et-outils-necessaires-du-copil", "text": "Informations et outils nécessaires du Copil" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea66be4b3685f0605aa81b_tooling%20copil-min-min.jpg", "alt": "Outils pilotage projet" }, { "type": "list", "ordered": false, "items": ["<strong>Décisions du derniers comité de pilotage</strong>", "<strong>Performance</strong> : Planning projet VS avancement réel / Budget prévu VS dépenses à date", "Les prochains gros <strong>Jalons et enjeux</strong>", "<strong>Tableau de bord</strong> (vue d'ensemble), suivi de l'avancement du projet et des KPIs", "<strong>Risques et points d'attention</strong>", "<strong>Les décisions à prendre</strong>", "Questions", "Prochaines étapes", "Dates et Jalons du prochain Copil<br>Faites attention à ne pas utiliser de support de présentation qui rentre trop dans le détails comme les outils de gestion de projet, au risque de perdre bon nombre de collaborateurs pendant la réunion et <strong>si vous souhaitez gagner du temps sans passer des heures à refaire un powerpoint pour chaque comité de pilotage </strong>et donner de la visibilité sur les éléments essentiels pour un Copil : <a href=\"https://www.airsaas.io/fr\" target=\"_blank\">L'outil AirSaas</a> a spécialement été conçu pour résoudre ces problèmes-là."] }, { "type": "heading", "level": 3, "id": "intervenants-ponctuels-et-investissement-dans-le-positif", "text": "Intervenants ponctuels et investissement dans le positif" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea671cda8fd09a5e29987d_copil%20positif-min.jpg", "alt": "copil Psychologie positive projets" }, { "type": "paragraph", "html": "Il n'y a pas de règles indiquant qu'un comité de pilotage doit se tenir dans la même salle de réunion avec forcément les mêmes personnes, le chef de projet doit avoir le contrôle sur les invitations du comité afin d'être sûr qu'il n'y aura pas de présence contre-productive, ceci étant dit rien ne l'empêche d<strong>'inviter une personnalité</strong> choisi pour une compétences ou parcours spécifique qui pourrait redonner <strong>un bon élan au projet</strong>. <strong>Variez également de lieux</strong>, particulièrement si cela à un lien avec le projet et que ça permette de <strong>sortir les collaborateurs de leurs quotidiens.</strong>" }, { "type": "paragraph", "html": "<strong>Une autre culture Copil est possible</strong> que d'aborder essentiellement que des risques et des facteurs bloquants. Valoriser le travail accompli et utiliser la réalisation de Jalons du projet comme points à célébrer. Trop se concentrer sur les problèmes peut avoir comme conséquences de finir par en créer et il est très important de savoir se concentrer aussi sur ce qui s'est bien passé." }, { "type": "heading", "level": 3, "id": "conserver-la-valeur-du-copil", "text": "Conserver la valeur du Copil" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea6776af559208fa104fdb_value%20copil-min.jpg", "alt": "Pilotage par la valeur" }, { "type": "paragraph", "html": "Vous conserverez la valeur de cette instance si vous conservez <strong>son efficacité et son utilité</strong>. Ne conservez pas un Copil parce que la réunion est calée depuis longtemps si vous n'avez rien de significatif à arbitrer ou d'avancement significatif à montrer. Si vous avez la bonne fréquence de ces réunions, ce problème ne devrait pas se manifester, mais si c'est le cas il vaudra toujours mieux d'écourter ou de reporter une réunion, plutôt que de chercher à étoffer son contenu." }, { "type": "paragraph", "html": "Le chef de projet doit rendre cet exercice facile pour les participants et s'assurer qu'il conserve un intérêt pour ses membres et pérenniser cette instance." }, { "type": "heading", "level": 3, "id": "ce-a-quoi-un-copil-ne-sert-pas", "text": "Ce à quoi un Copil ne sert pas" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2e5e70d244742b247497d_useful%20copil-min.jpeg", "alt": "Utilité copil" }, { "type": "list", "ordered": false, "items": ["A simplement informé ou <strong>à but strictement descendant</strong>, selon vos choix de management, il sera plus efficace qu'il soit inclusif et collaboratif", "<strong>A une mise à mort</strong> : Ce n'est pas l'endroit pour descendre le travail ou la mauvaise implication d'un ou de plusieurs collaborateurs. Certains pourraient penser que cela pourrait servir d'exemple et faire rentrer tout le monde dans le rang. Mais sachez ne pas laver votre linge sale en public. Instaurer une dynamique de groupe positive est préférable pour le bien du projet. Privilégiez les rdv individuels pour exprimer si les attentes du projet diffèrent avec les actions de certains collaborateurs.", "<strong>Entrer dans trop de détails techniques</strong>, particulièrement si c'est pour expliquer tout ce que vous avez fait, c'est important de valoriser son travail et le travail de tous, mais rentrer dans un processus de justification imprime rarement une très bonne dynamique."] }, { "type": "paragraph", "html": "Vous avez mis en place votre copil ? Découvrez <a href=\"/gestion-de-projet/comment-animer-un-comite-de-pilotage\" target=\"_blank\">Comment animer un comité de pilotage ?</a>" }], "toc": [{ "label": "Pourquoi faire un Copil ?", "href": "#pourquoi-faire-un-copil", "level": 2 }, { "label": "Quelle est la différence entre un comité de direction CODIR, un comité de pilotage Copil et un comité de projet COPROJ ?", "href": "#quelle-est-la-difference-entre-un-comite-de-direction-codir-un-comite-de-pilotage-copil-et-un-comite-de-projet-coproj", "level": 2 }, { "label": "Quel est le rôle d'un comité de pilotage ?", "href": "#quel-est-le-role-dun-comite-de-pilotage", "level": 2 }, { "label": "Quelles sont les personnes qui constituent un comité de pilotage ?", "href": "#quelles-sont-les-personnes-qui-constituent-un-comite-de-pilotage", "level": 2 }, { "label": "Désamorcer les enjeux de politique interne au profit des intérêts supérieurs de l'entreprise", "href": "#desamorcer-les-enjeux-de-politique-interne-au-profit-des-interets-superieurs-de-lentreprise", "level": 2 }, { "label": "Comment créer un comité de pilotage efficace dans la durée ?", "href": "#comment-creer-un-comite-de-pilotage-efficace-dans-la-duree", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-mettre-en-place-un-pmo", "skip": false, "meta": { "title": "Comment mettre en place un PMO ?", "h1": "Comment mettre en place un PMO ?", "description": "Comment mettre en place un PMO ? Découvrez les étapes clés, le profil idéal, les difficultés à anticiper et les bonnes pratiques pour réussir la mise en place d'un Project Management Office.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8ed73ba2092e1215ffbd6_PMO-min.jpg", "alt": "" }, "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "25/2/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "publishedDate": "25/2/2023" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8e7db537877c35f464429_mise%20en%20place%20PMO.jpg", "alt": "project management office - bureau des projets", "caption": "Bienvenue dans le pragmatic project management office  - bureau des projets" }, { "type": "heading", "level": 2, "id": "quand-se-pose-la-question-de-la-mise-en-place-dun-pmo", "text": "Quand se pose la question de la mise en place d'un PMO ?" }, { "type": "paragraph", "html": "À partir de quand se lancer ? C'est une question qu'on nous pose très souvent. En effet, ce rôle est devenu de plus en plus important pour les entreprises afin de faire face à l'accélération de l'innovation et l'explosion des projets transverses." }, { "type": "paragraph", "html": "Il semble cependant que les mêmes freins reviennent quand on se pose la question de la mise en place d'un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/metier-pmo\" target=\"_blank\">PMO</a>. L'entreprise est-elle suffisamment grande pour justifier la création de ce type de poste ? Est-on assez structuré en interne pour le mettre en place ?" }, { "type": "paragraph", "html": "La <strong>taille de l'entreprise</strong> est <strong>moins importante que le nombre de projets ainsi que l'investissement qu'ils représentent</strong>. Moins l'effectif est important avec un grand nombre de projets, plus l'implication en mode \"best effort\" des équipes est importante." }, { "type": "paragraph", "html": "Avec des collaborateurs qui prennent le rôle de chef de projet en plus de leurs fonctions habituelles, rôle pour lequel, si ce n'est pas leur cœur de métier, on peut s'attendre à une efficacité plus faible et de nombreux projets deviennent très difficiles à mener à bien." }, { "type": "paragraph", "html": "Dans de nombreux cas, l'échec des projets peut coûter bien plus cher que l'embauche d'un PMO." }, { "type": "paragraph", "html": "La question de la structuration de l'entreprise devrait être prise à l'envers ici. Le rôle d'un PMO est d'aider à structurer une démarche et une culture visant la montée en compétences de tous les collaborateurs sur les projets et ainsi améliorer la réussite de ces projets, en participant également à une meilleure efficacité pour les collaborateurs." }, { "type": "paragraph", "html": "Il peut donc être un élément important dans la structuration d'une entreprise pour faire face à une montée en charge sur l'activité cœur de métier. C'est toujours mieux que de mettre une majorité de projets en stand-by ou en échec chronique." }, { "type": "heading", "level": 3, "id": "trois-criteres-pour-decider-du-recrutement-dun-pmo", "text": "Trois critères pour décider du recrutement d'un PMO ?" }, { "type": "list", "ordered": true, "items": ["Premier critère, purement ROIste, dans les ratios généralement constatés, le bon moment pour mettre en place un PMO est quand la somme des projets transverses ou de transformation atteint 400K€ à 500K€. Provisionner 15% à 20% de la valeur de son <a href=\"https://www.airsaas.io/fr/gestion-de-projet/gestion-portefeuille-projets-vs-gestion-de-projet\" target=\"_blank\">portefeuille projet</a> dans la mise en place d'un PMO semble être une bonne pratique pour sécuriser les investissements actuels mais aussi améliorer l'efficience des futurs investissements.", "Quand les projets dérapent ! Second contexte à prendre en compte pour passer le cap. Quand votre projet ERP glisse depuis 18 mois…c'est le signe qu'il vous manque de \"l'huile\". Recruter ou s'adjoindre les services d'un PMO externe permettra en outre d'économiser du temps passé par les collaborateurs clés sur les projets et ainsi mieux gérer leurs activités cœur de métier.", "Enfin, troisième critère plus subjectif, <strong>quand le DG à l'impression que ça rame</strong> ! C'est le signe qu'il va falloir piloter un peu plus ce sujet-là. Ne pas s'installer dans le manque d'efficience, transparence et de confiance."] }, { "type": "paragraph", "html": "Besoin de creuser le sujet ? <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pourquoi-mettre-en-place-un-pmo\" target=\"_blank\">Rendez-vous sur notre article \"Pourquoi mettre en place un PMO ?\"</a>" }, { "type": "heading", "level": 2, "id": "que-faut-il-mettre-en-place-avant-larrivee-dun-pmo", "text": "Que faut-il mettre en place avant l'arrivée d'un PMO ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8e5e1685d831215c93dac_c4981d32-6f42-4256-b0ee-ff5eb8256e62.png", "alt": "PMO Les clés d'une mise en œuvre réussie", "caption": "Les clés d'une mise en œuvre réussie" }, { "type": "paragraph", "html": "Avant l'arrivée d'un PMO, il est important de mettre en place les éléments suivants :" }, { "type": "list", "ordered": true, "items": ["Identifier les besoins de l'entreprise en termes de gestion de projet et déterminer comment un PMO peut aider à les satisfaire.", "Définir le rôle et les responsabilités du PMO, ainsi que les ressources dont il aura besoin pour remplir ses fonctions. (N'hésitez pas à faire évoluer cette vision en prenant conseil à l'extérieur ou en fonction des éléments apportés sur la table par les candidats)", "Choisir un responsable pour le PMO qui lui donnera les moyens de réussir, en lui fournissant notamment les ressources nécessaires et lui permettant d'ouvrir les bonnes portes et d'avoir la bonne influence dans l'entreprise.", "Communiquer sur le PMO auprès de tous les membres de l'entreprise, afin de les sensibiliser à son rôle et à ses responsabilités, et de leur fournir les informations nécessaires pour travailler en collaboration avec lui."] }, { "type": "paragraph", "html": "En mettant en place ces éléments avant l'arrivée du PMO, vous vous assurez que le PMO dispose des moyens minimums nécessaires pour remplir ses fonctions et que tous les membres de l'entreprise sont informés de son rôle et de ses responsabilités. Cela vous permettra également de réduire les problèmes potentiels qui pourraient survenir au cours du processus de mise en place du PMO." }, { "type": "paragraph", "html": "Attention les quatre points ci-dessus constituent la base …Mais <strong>ça ne suffira pas</strong> pour une prise de fonction de PMO efficace !" }, { "type": "paragraph", "html": "À travers nos échanges avec les DSI, Directions générales, sponsors… Nous avons acquis la conviction qu'il y a trois prérequis supplémentaires." }, { "type": "list", "ordered": true, "items": ["<strong>Le PMO est rattaché à la Direction</strong>. Oui c'est un rôle stratégique !", "<strong>Le PMO est positionné comme un facilitateur</strong> versus un contrôleur qui \"enm….e\" tout le monde. il doit donner envie et fédérer !", "On donne (vraiment) au PMO <strong>les capacités, la permission de challenger les sponsors et décideurs</strong>…Vous tuez ce rôle si le PMO se fait rembarrer à chaque remontée."] }, { "type": "heading", "level": 2, "id": "quel-profil-rechercher", "text": "Quel profil rechercher ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8eba04e476a361c88ba79_profil-pmo.jpg", "alt": "Profil type PMO", "caption": "Chefs de projets ou PMO ?" }, { "type": "paragraph", "html": "Pour trouver le profil idéal pour un poste de PMO, il est important de rechercher quelqu'un qui a :" }, { "type": "list", "ordered": false, "items": ["Une solide expérience en gestion de projet transverse et/ou de transformation", "Des compétences en communication et en collaboration, pour travailler efficacement avec les différents membres de l'équipe de projet et gérer les relations avec les différents intervenants.", "Des compétences en organisation et en planification, pour organiser les différents projets entre eux et aider à les gérer pour qu'ils soient menés à bien dans les délais impartis.", "Des compétences en gestion des risques et en résolution de problèmes, pour identifier et gérer les risques qui peuvent survenir au cours d'un projet et trouver des solutions pour les résoudre.", "Une connaissance approfondie des outils et des technologies de gestion de projet, pour consolider sa démarche afin de mieux gérer les projets de l'entreprise.", "<strong>Le plus : </strong>Un candidat avec une très bonne culture des projets de transformation, une bonne vision des enjeux et solutions basées sur des retours d'expérience et proche d'un réseau d'acteurs sur ces thèmes afin de rester à jour sur les évolutions des enjeux autour de la transformation d'entreprise."] }, { "type": "paragraph", "html": "On attend également que le PMO fasse le lien entre les chefs de projets et les métiers avec l'exécutif et le top management. Pour cela vous aurez besoin d'un profil capable d'évoluer dans les deux sphères, son rôle étant d'aider et de faciliter, il doit comprendre les besoins et avoir les prérequis techniques pour supporter les équipes et les services dans leur rôle d'exécution mais également avec une forte appétence et compréhension business pour communiquer au bon niveau avec le Codir / Comex." }, { "type": "paragraph", "html": "<strong>Les compétences projet, c'est le minimum, la base !</strong> Vous l'avez compris le rôle de PMO contrôleur à l'ancienne ne fonctionnera pas avec juste le service minimum, <strong>on recherche un profil type capitaine d'équipe</strong> vs un \"chefaillon\". On cherche quelqu'un de pédagogue, il doit <strong>donner envie et fédérer !</strong>" }, { "type": "paragraph", "html": "La situation optimale c'est quand vous avez un PMO qui est monté en interne et qui est coaché par quelqu'un d'externe le cas échéant. Il aura la légitimité et des tips pour trouver sa posture." }, { "type": "heading", "level": 2, "id": "a-quelles-difficultes-faut-il-sattendre-au-debut", "text": "À quelles difficultés faut-il s'attendre au début ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8ebbced7c97e69c7bae23_pmo%20start.jpg", "alt": "Les débuts en tant que PMO", "caption": "Bienvenue dans les portefeuilles de projets" }, { "type": "paragraph", "html": "Lors de la mise en place d'un PMO, il est possible de rencontrer les difficultés suivantes :" }, { "type": "list", "ordered": true, "items": ["Résistance au changement : il est possible que certains membres de l'entreprise soient réticents à l'idée de travailler avec un PMO et qu'ils aient du mal à s'adapter aux nouvelles méthodes de travail.", "Manque d'outils adaptés : \"pour qui possède un marteau tout ressemble à un clou\".", "Problèmes de communication : il est possible que les différents membres de l'entreprise ne soient pas sur la même longueur d'onde en ce qui concerne les objectifs et les responsabilités du PMO, ce qui peut entraîner des malentendus et des difficultés à travailler en collaboration.", "Manque de soutien : il est possible que le PMO ne bénéficie pas du soutien nécessaire de la part de la direction, ce qui peut limiter son efficacité et sa capacité à remplir ses fonctions de manière adéquate.", "Le manque d'exemplarité : si votre Codir ne donne pas l'exemple pas la peine d'attendre des métiers, PMO et chef de projet de compenser…Par un phénomène de mimétisme hiérarchique, chacun s'adaptera à la \"norme\", bonne et mauvaise ^^"] }, { "type": "paragraph", "html": "Pour éviter ces difficultés, il est important de planifier soigneusement la mise en place du PMO et de communiquer clairement avec tous les membres de l'entreprise pour leur expliquer le rôle et les responsabilités du PMO, ainsi que les avantages qu'il peut apporter à l'entreprise." }, { "type": "heading", "level": 2, "id": "quelle-est-sa-meilleure-position-pour-agir", "text": "Quelle est sa meilleure position pour agir ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8ebe10df711c3525a20fd_impact%20-%20pmo.jpg", "alt": "Posture de PMO", "caption": "Une feuille de route seule ne suffit pas" }, { "type": "paragraph", "html": "Il y a plusieurs éléments à considérer pour identifier la position dans laquelle intégrer le PMO dans l'objectif d'en obtenir le meilleur résultat :" }, { "type": "heading", "level": 3, "id": "lentite-avec-la-plus-grande-maturite-projet-dans-lentreprise", "text": "L'entité avec la plus grande maturité projet dans l'entreprise :" }, { "type": "paragraph", "html": "L'objectif est pour le PMO d'être dans une position où il va pouvoir agir assez rapidement. Il aura besoin de concentrer son énergie dans le développement ou la restructuration des opérations projets et de la gouvernance et pouvoir s'imprégner de la direction stratégique donnée à ses actions par le top management. S'il passe trop de temps à mettre à niveau ou à convertir l'équipe dans laquelle il travaille, son énergie et ses résultats risquent fortement d'en pâtir." }, { "type": "paragraph", "html": "L'idéal ici est que le PMO puisse évoluer dans l'entité de l'entreprise la plus mature en conduite de projet et qui partage la vision de la structuration à venir." }, { "type": "heading", "level": 3, "id": "entite-dinfluence-et-de-bienveillance", "text": "Entité d'influence et de bienveillance :" }, { "type": "paragraph", "html": "L'autre aspect, presque plus important que le point précédent, sera que le PMO puisse agir et avoir le soutien depuis l'entité qui à la dimension la plus transverse dans l'entreprise, et qui est la plus appréciée par les collaborateurs de l'entreprise et les autres services. S'il est rattaché à des personnalités qui ont de l'influence et qui sont appréciés alors cela facilitera la diffusion d'une nouvelle culture et évitera les freins rencontrés par le PMO, ainsi que les potentielles guerres d'ego dans les services." }, { "type": "heading", "level": 3, "id": "proximite-avec-le-codircomex", "text": "Proximité avec le Codir/Comex" }, { "type": "paragraph", "html": "Enfin, un des rôles clés du PMO est de pouvoir obtenir des décisions rapides pour les projets, de la part des membres du Codir/Comex, il doit être en mesure de leur transmettre toutes les informations nécessaires permettant la prise de ces décisions. Pour ce faire, il doit avoir une position proche de ces instances de décisions, comme avoir un N+1 membre du directoire." }, { "type": "paragraph", "html": "Le bénéfice secondaire, et qu'étant rattaché à un membre de direction, cela anticipera également les potentiels freins projet liés à l'ego et la volonté de certains collaborateurs de vouloir briller aux dépens de l'objectif des projets ou de vouloir asseoir une quelconque autorité toxique." }, { "type": "heading", "level": 2, "id": "comment-communiquer-et-mettre-le-pmo-dans-de-bonnes-conditions", "text": "Comment communiquer et mettre le PMO dans de bonnes conditions ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8ebf5302f85bde7130001_communication-airsaas.jpg", "alt": "Communiquer sur le rôle de PMO", "caption": "Avoir ou pas un plan de communication" }, { "type": "paragraph", "html": "Pour communiquer efficacement sur le PMO et le mettre dans de bonnes conditions, voici quelques conseils :" }, { "type": "list", "ordered": true, "items": ["Communiquez clairement sur le rôle et les responsabilités du PMO auprès de tous les membres de l'entreprise. Expliquez en quoi le PMO peut les aider dans leur travail et comment ils peuvent travailler en collaboration avec lui.", "Faites une présentation du PMO lors d'une réunion de kick off pour informer tous les membres de l'entreprise des nouvelles méthodes de travail qui seront mises en place et leur expliquer comment elles vont leur faciliter la vie.", "Donnez au PMO les outils lui permettant de bien travailler, de bien communiquer et interagir avec les parties prenantes pour qu'il puisse remplir ses fonctions de manière efficace. Cela peut inclure des outils de gouvernance projet, des logiciels, ou tout autre type de ressource qui lui sera utile."] }, { "type": "heading", "level": 2, "id": "comment-organiser-ou-reorganiser-la-gouvernance-des-projets", "text": "Comment organiser ou réorganiser la gouvernance des projets ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8ec094e476ab27e893b84_gouvernance%20projet.jpg", "alt": "Gouvernance projet / PMO", "caption": "Les étapes clés d'une gouvernance" }, { "type": "paragraph", "html": "La gouvernance des projets est un sujet qui peut être délicat, surtout quand elle est réorganisée à la suite de l'arrivée d'un PMO. On souhaite mettre en place une gouvernance efficace et adaptée qui facilitera la conduite des projets, le suivi global et la prise de décision, pas à déclencher des guerres d'ego ou d'amplifier la résistance aux changements." }, { "type": "paragraph", "html": "Pour organiser ou réorganiser la gouvernance des projets dans l'entreprise, pas la peine de sortir major du project management institute :" }, { "type": "list", "ordered": true, "items": ["Assurez-vous du fait que la stratégie de l'organisation existe bien et qu'elle est partagée ! Donner du sens : Il ne suffit pas d'un plan stratégique tous les 5 ans, il faut le faire vivre !", "Ensuite, descendez d'un niveau jusqu'aux grands programmes identifiés. Le sont-ils ? Car oui…avant même de vouloir améliorer la gouvernance il faut vérifier que chacun sait \"où on va collectivement ?\"", "Ensuite, mettez-vous d'accord sur des cycles de priorisation au regard des cycles budgétaires en place.", "Enfin, revenez aux fondamentaux humains. Une bonne gouvernance projet restera toujours d'avoir un sponsor, un chef de projet, un référent métier vraiment disponible. Sans oublier la création de nouveaux rituels clés de synchronisation et communications, réguliers et respectés !"] }, { "type": "paragraph", "html": "Après seulement, la question des outils sera la dernière clé. Oui, l'assistance à la gouvernance est un \"must have\". Et oui, chaque outil embarque avec lui une philosophie. Favoriser un management par l'engagement, les jalons et les décisions. <strong>Airsaas</strong> a été spécialement conçu dans ce sens." }, { "type": "heading", "level": 2, "id": "ne-sous-estimez-pas-limportance-des-quick-wins", "text": "Ne sous-estimez pas l'importance des \"quick wins\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f8ec7d14d852f41c6b2de3_quick%20win.jpg", "alt": "Quick wins PMO", "caption": "La gestion de projets est un art !" }, { "type": "paragraph", "html": "Les quick-wins sont des actions rapides et faciles à mettre en place qui permettent d'obtenir rapidement des résultats positifs et visibles. Ils sont indispensables lorsqu'on crée un nouveau poste, particulièrement de PMO, qui est souvent un rôle plus méconnu (quand il est nouveau) et source de résistance au changement quand mal onboardé dans l'entreprise. Les quick-wins permettent de montrer rapidement sa valeur ajoutée et de créer de la confiance et de l'engagement sur son action auprès de ses collègues et de la direction." }, { "type": "paragraph", "html": "Il est important de trouver des quick-wins qui sont en lien avec les objectifs de l'entreprise et qui peuvent être réalisées rapidement, sans nécessiter des ressources importantes. Cela peut être, par exemple, la mise en place de processus de travail plus efficaces, la résolution de problèmes qui ont été identifiés comme des freins à la performance des projets." }, { "type": "paragraph", "html": "Il ne faut bien évidemment pas se concentrer que sur les quick-wins dans les premiers temps de prise de poste, il faudra en parallèle qu'il mène des actions de fond pour mettre en place la démarche projet et les projets stratégiques dont les résultats ne seront visibles qu'à plus moyens termes." }, { "type": "paragraph", "html": "En revanche, soutenir le PMO dans la résolution de quick-wins permettra de donner du crédit et du poids à son action et ainsi faciliter la confiance et l'engagement des collaborateurs dans la démarche." }], "toc": [{ "label": "Quand se pose la question de la mise en place d'un PMO ?", "href": "#quand-se-pose-la-question-de-la-mise-en-place-dun-pmo", "level": 2 }, { "label": "Que faut-il mettre en place avant l'arrivée d'un PMO ?", "href": "#que-faut-il-mettre-en-place-avant-larrivee-dun-pmo", "level": 2 }, { "label": "Quel profil rechercher ?", "href": "#quel-profil-rechercher", "level": 2 }, { "label": "À quelles difficultés faut-il s'attendre au début ?", "href": "#a-quelles-difficultes-faut-il-sattendre-au-debut", "level": 2 }, { "label": "Quelle est sa meilleure position pour agir ?", "href": "#quelle-est-sa-meilleure-position-pour-agir", "level": 2 }, { "label": "Comment communiquer et mettre le PMO dans de bonnes conditions ?", "href": "#comment-communiquer-et-mettre-le-pmo-dans-de-bonnes-conditions", "level": 2 }, { "label": "Comment organiser ou réorganiser la gouvernance des projets ?", "href": "#comment-organiser-ou-reorganiser-la-gouvernance-des-projets", "level": 2 }, { "label": "Ne sous-estimez pas l'importance des \"quick wins\"", "href": "#ne-sous-estimez-pas-limportance-des-quick-wins", "level": 2 }], "faq": [], "related": [] }, { "slug": "comment-mettre-une-bonne-meteo-projet", "skip": false, "meta": { "title": "Comment faire une météo projet claire et compréhensible ?", "h1": "Comment faire une météo projet claire et compréhensible ?", "description": "Comment mettre en place une météo projet pertinente ? Usages fondamentaux, bonnes pratiques, erreurs courantes et pièges à éviter pour faire de cet indicateur un levier d'efficacité.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f36d0c33f545261135cd82_meteo-projet-airsaas-min.jpg", "alt": "Météo projet AirSaas" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "13/4/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "13/4/2022" }, "toc": [{ "label": "Qu'est ce qu'une météo projet ?", "href": "#quest-ce-quune-meteo-projet", "level": 2 }, { "label": "La météo projet, levier de performance insoupçonné", "href": "#la-meteo-projet-levier-de-performance-insoupconne", "level": 2 }, { "label": "Quatre problèmes courants avec la météo projet !", "href": "#quatre-problemes-courants-avec-la-meteo-projet", "level": 2 }, { "label": "Quatre alternatives visuelles à la météo pour vos états de santé projet :", "href": "#quatre-alternatives-visuelles-a-la-meteo-pour-vos-etats-de-sante-projet", "level": 2 }], "blocks": [{ "type": "paragraph", "html": "Oui ! Cette approche est à la fois suffisamment porteuse, pour libérer la parole de la plupart des personnes impliquées et simple, pour <strong>rendre lisible l'état de santé du portefeuille projet</strong>. Bien exécutée elle <strong>rend accessible rapidement les informations</strong> clés à connaitre derrière les différents changement de statuts...et facilitera votre <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet.</a>" }, { "type": "paragraph", "html": "On vous dit tout pour faire de cette pratique <strong>un levier d'efficacité</strong> de votre gestion de projet : usages fondamentaux et bonnes pratiques, comment <strong>mettre en place une météo projet pertinente ?&nbsp;Quels sont les erreurs courantes et pièges à éviter ?</strong>" }, { "type": "heading", "level": 2, "id": "quest-ce-quune-meteo-projet", "text": "Qu'est ce qu'une météo projet ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b15_6247101b95f4a4562cfa3fd0_27379b47-3c96-4060-b561-4b071f5ad3db.png", "alt": "Capture écran AirSaas - météo", "caption": "Trois états de météo projet type" }, { "type": "paragraph", "html": "La météo projet est un <strong>modèle visuel simple</strong>, qui utilise la métaphore du temps qu'il fait pour communiquer sur l'état de santé d'un projet. C'est même le <strong>premier indicateur de la santé d'un projet !</strong>" }, { "type": "paragraph", "html": "Intimement liés au processus d'amélioration continue, le <strong>suivi</strong> et l'<strong>analyse</strong> des indicateurs fournissent un retour, des informations essentielles aux équipes." }, { "type": "paragraph", "text": "Mais attention...pas n'importe comment !" }, { "type": "paragraph", "text": "A minima, cet indicateur de reporting doit être :" }, { "type": "list", "ordered": false, "items": ["<strong>Compréhensible par tous</strong>&nbsp;: idéalement, sa définition sera le fruit d'un travail collaboratif de l'équipe", "<strong>Ciblé</strong>&nbsp;: les besoins de partage d'informations auxquels ils répond doivent être clairement définis", "<strong>Partagé</strong>&nbsp;pour que tout le monde aille dans la même direction, vers un seul et même but"] }, { "type": "paragraph", "text": "Par exemple, voici trois indicateurs type d'une météo simple et leur signification :" }, { "type": "heading", "level": 4, "id": "soleil-le-projet-progresse-comme-prevu", "text": "☀️ Soleil : Le projet progresse comme prévu..." }, { "type": "paragraph", "html": "Tous les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/jalon-projet\" target=\"_blank\">jalons projets</a> sont sur la bonne voie. Aucune action nécessaire. Bravo :)" }, { "type": "heading", "level": 4, "id": "pluie-cest-complique", "text": "🌧️ Pluie : c'est compliqué" }, { "type": "paragraph", "text": "Un ou plusieurs jalons majeurs sont en retard, mais la livraison finale n'est pas impactée." }, { "type": "paragraph", "text": "Le comité de projet devrait être notifié utilisant un point de synchronisation déjà prévu avec le sponsor." }, { "type": "heading", "level": 4, "id": "orage-cest-bloque", "text": "⚡ Orage : c'est bloqué" }, { "type": "paragraph", "text": "Un ou plusieurs jalons majeurs sont en retard et la livraison finale est impactée." }, { "type": "paragraph", "text": "Le sujet devrait être remonté immédiatement au sponsor de projet et au comité de projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b71_62f36c15e3e50656f7ccc017_flash-report-min.jpeg", "alt": "Interface AirSaas (flash report)", "caption": "Vue du flash report projet généré depuis la plateforme AirSaas" }, { "type": "heading", "level": 3, "id": "les-trois-benefices-de-la-meteo-projets", "text": "Les trois \"bénéfices\" de la météo projets :" }, { "type": "heading", "level": 4, "id": "synthetiser-letat-davancement-dun-projet", "text": "👉 Synthétiser l'état d'avancement d'un projet" }, { "type": "paragraph", "html": "Agrémenter les tableaux de synthèse d'indicateurs permet de <strong>simplifier la lecture des données </strong>et de rendre compte rapidement de la situation globale...et du contexte." }, { "type": "heading", "level": 4, "id": "mettre-en-evidence-levolution", "text": "👉 Mettre en évidence l'évolution" }, { "type": "paragraph", "text": "En relisant le bulletin météo précédent et en donnant à voir des changements. On permet aux parties prenantes de saisir les \"dynamiques\" vécues au sein des collectifs." }, { "type": "heading", "level": 4, "id": "creer-la-parole", "text": "👉 \"Créer la parole\"" }, { "type": "paragraph", "html": "Au sens propre \"provocare\". On pense trop souvent que c'est acquis. Au contraire. Ces informations visuelles permettent d'aborder le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\">reporting projet</a> d'une manière plus légère." }, { "type": "heading", "level": 2, "id": "la-meteo-projet-levier-de-performance-insoupconne", "text": "La météo projet, levier de performance insoupçonné" }, { "type": "paragraph", "html": "La météo projet offre une véritable <strong>cartographie des activités en cours et des éventuels signaux faibles, symptômes ou syndromes de dysfonctionnements </strong>de votre système. !" }, { "type": "heading", "level": 4, "id": "signaux-faibles-quelques-nuages-et-averses", "text": "Signaux faibles : quelques nuages et averses ?" }, { "type": "paragraph", "html": "Des précipitations...c'est normal. <strong>Aucun projet ne se passe comme prévu</strong>...c'est dommage mais c'est la règle des 5 C (\"C'est con mais c'est comme ça\" ;-)!" }, { "type": "heading", "level": 4, "id": "symptomes-pluie-tres-frequentes", "text": "Symptômes : pluie très fréquentes ?" }, { "type": "paragraph", "html": "Aïe ...l'équipe n'a pas vu le soleil depuis longtemps...<strong>Attention</strong>, d'une part au moral des troupes et d'autre part<strong> aux causes réelles de cette mauvaise conjoncture répétée.</strong> Un <strong>travail d'analyse des causes</strong> sur les problématiques rencontrées peut (devrait) utilement être mené." }, { "type": "heading", "level": 4, "id": "syndromes-la-foudre-est-tombee-plusieurs-fois", "text": "Syndromes : la foudre est tombée plusieurs fois ?" }, { "type": "paragraph", "html": "Il est presque trop tard...<strong>la mauvaise santé est chronique</strong>. Les causes structurelles de cette mauvaise santé sont désormais \"enkystées\"..." }, { "type": "paragraph", "html": "En vous<strong> concentrant sur les signaux faibles et / ou symptômes fréquents</strong>, c'est à dire les sujets compliqués voire bloquants, vous pourrez déterminer avec précision où concentrer les ressources pour optimiser votre gestion de projet. <strong>Mesurer c'est piloter !</strong>" }, { "type": "paragraph", "html": "Finalement cet indicateur est un <strong>outil de reporting visuel </strong>assez<strong> proche des outils de management visuel </strong>issues des méthodes de production <strong>du lean management. Celui qu'on regarde le plus !</strong>" }, { "type": "heading", "level": 2, "id": "quatre-problemes-courants-avec-la-meteo-projet", "text": "Quatre problèmes courants avec la météo projet !" }, { "type": "paragraph", "text": "Oui ! Un indicateur aussi simple que la météo projet peut être \"perverti\". Rappelez vous que même le plus simple des outils, lorsqu'il est utilisé à l'envers est contre productif ! voire dangereux." }, { "type": "heading", "level": 3, "id": "1-pas-assez-de-nuances-on-a-seulement-trois-indicateurs", "text": "1. Pas assez de nuances...on a seulement trois indicateurs !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b18_62471c06b22b5c1d964df38a_3typeou4meteo-projet.png", "alt": "3 statuts météo", "caption": "Avec un 4e statut on dépassera plus facilement le côté \"tous les projets ont la moyenne\"..." }, { "type": "paragraph", "text": "Quand il y a seulement trois statuts de météo projets...on a naturellement tendance à mettre celui du milieu..." }, { "type": "paragraph", "text": "Cela n'apporte plus la clarté dans la lisibilité attendue..." }, { "type": "paragraph", "html": "Avoir <strong>quatre critères de météo vous apportera de la nuance</strong>, de la finesse. Comme le dit le dicton....\"Il vaut mieux du \"dur sur\" que du \"mou flou\" ! :-)" }, { "type": "heading", "level": 4, "id": "par-exemple-4-indicateurs-type", "text": "Par exemple, 4 indicateurs type :" }, { "type": "list", "ordered": true, "items": ["Bloqué,", "compliqué,", "se complique", "et normal !"] }, { "type": "heading", "level": 3, "id": "2-pas-de-methodologie-tout-le-monde-le-fait-a-sa-sauce", "text": "2. Pas de méthodologie ....tout le monde le fait à sa sauce !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b1b_62471caf99cf8d3b8d73c53b_methodologie-meteo-projet-airsaas.png", "alt": "methodo projet", "caption": "Culture projet partagée au sein d'une seule plateforme fait gagner du temps !" }, { "type": "paragraph", "html": "Focalisé sur des usages avancés....on oublie souvent ce point de méthode basique en gestion de projet....<strong>Se mettre d'accord </strong>avec toutes les parties prenantes sur <strong>ce qui fait passer d'un statut météo projet à un autre. </strong>C'est fondamental." }, { "type": "heading", "level": 3, "id": "3-pas-de-contexte-vous-ne-savez-pas-pourquoi-un-changement-de-statut-a-eu-lieu", "text": "3. Pas de contexte...vous ne savez pas pourquoi un changement de statut a eu lieu !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b74_62f36c9e9f36f7095f1667ca_projet-bloque-airsaas-min.jpeg", "alt": "accès détail météo", "caption": "En un clic sur \"Voir le détail\", retrouver l'explication de pourquoi votre projet est bloqué depuis deux semaines !" }, { "type": "paragraph", "html": "☀️ Connaitre la météo et le risque d'un projet c'est bien, <strong>savoir pourquoi il est dans cette état c'est encore mieux. </strong>En un clic sur \"Voir le détail\", retrouver l'explication de pourquoi votre projet est bloqué depuis deux semaines !" }, { "type": "paragraph", "html": "On à besoin que<strong> l'information du changement de statut soit compréhensible par tous.</strong> Pour y parvenir votre météo projet peut être \"auto-portante\"." }, { "type": "paragraph", "text": "C'est à dire toujours accompagnée d'un message, du contexte précis, accessible en 1 clic ! Quelqu'un qui arrivera sur le projet...comprendra le pourquoi du comment !" }, { "type": "heading", "level": 3, "id": "4-pas-dintegrite-on-prefere-masquer-les-problemes", "text": "4. Pas d'intégrité....On préfère masquer les problèmes !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b1e_624720794a08ba53b659f9da_integrite-projet-airsaas.png", "alt": "Autruche projet", "caption": "Le statut météo ne devrait pas être utilisé pour cacher des problèmes" }, { "type": "paragraph", "html": "L'efficacité de cet outil repose sur l'intégrité du chef de projet et l'exactitude de la météo type assignée. Une <strong>météo inopportune peut mener à éviter d'affronter un problème et en supporter l'échec en fin de projet</strong>. Son but est de démontrer du progrès et de préciser quand l'intervention du comité de projet est nécessaire." }, { "type": "paragraph", "html": "Donc,<strong> le statut météo ne devrait pas être utilisé pour cacher des problèmes. </strong>C'est plutôt une façon de <strong>rechercher du support et des conseils du sponsor et des parties prenantes</strong>. Utilisez une définition de statut commune pour communiquer." }, { "type": "heading", "level": 2, "id": "quatre-alternatives-visuelles-a-la-meteo-pour-vos-etats-de-sante-projet", "text": "Quatre alternatives visuelles à la météo pour vos états de santé projet :" }, { "type": "heading", "level": 3, "id": "1-le-barometre-projet", "text": "1. Le baromètre projet" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b21_62472194d78d1f3a817b9536_barometre-coupe.png", "alt": "baromètre", "caption": "Simple, basique :) ici avec 5 nuances...peut-être une de trop..." }, { "type": "paragraph", "text": "ici avec 5 nuances...peut-être une de trop...?" }, { "type": "heading", "level": 3, "id": "2-le-diagnostic-abcdefg", "text": "2.Le diagnostic \"ABCDEFG\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b24_6247220c3a3f572a4a0f8d28_variante-meteo.jpeg", "alt": "Diagnostic projet", "caption": "On retrouve avec ce modèle le côté diagnostic thermique qui parle à tous..." }, { "type": "paragraph", "text": "Comme dans cet exemple vous pouvez facilement le \"customiser\" en modifiant les libellés des titres correspondants aux classes A,B..." }, { "type": "heading", "level": 3, "id": "3-le-systeme-vor-ou-rag", "text": "3. Le système \"VOR\" ou \"RAG\" \"RAG\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c834bb13f435c278a49b27_624722515658efae7b76f4e0_RAG.png", "alt": "RAG status", "caption": "Il est inspiré des méthodes du Lean management...le classique système trois couleurs. !" }, { "type": "paragraph", "text": "VOR pour \"Vert Orange Rouge\"." }, { "type": "paragraph", "text": "En anglais on parle du \"RAG\" status. Pour Red Amber et Green Status." }, { "type": "heading", "level": 3, "id": "4-les-emojis-smiley", "text": "4. Les emojis smiley" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/624720e1228bef7e471abbb5_Sans%2520titre%2520(4).png", "alt": "smiley projet", "caption": "Ou comment ajouter une touche \"émotionnelle\" aux couleurs." }, { "type": "paragraph", "text": "Combiné à la couleur....ils fonctionnent bien. Idem on y ajoutera un 4e smiley pour apporter la nuance recherchée." }, { "type": "paragraph", "html": "En résumé, la météo est un <strong>outil de gouvernance et de communication</strong>. Au même titre que les indicateurs d'avancement, de jalons, et de livrables c'est un indicateur clé de l'exécution du \"chantier\". Mais contrairement aux autres c'est le \"premier\" à renseigner sur l'état de santé ! Pour compléter cet article, la lecture recommandée est \"<a href=\"https://www.airsaas.io/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\">Comment élaborer un reporting efficace</a>\"." }], "faq": [], "related": [] }, { "slug": "comment-reussir-un-projet-transverse", "skip": false, "meta": { "title": "Comment réussir un projet transverse ?", "h1": "Comment réussir un projet transverse ?", "description": "Toutes les clés de succès de votre prochain projet transverse. Des conseils pragmatiques et concrets pour mener votre projet au succès !", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3863233f545341936e65e_Project%20image-min2.jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "20/4/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "20/4/2022" }, "blocks": [{ "type": "paragraph", "text": "Tout n'est pas un problème d'organisation. On ne réussit pas un projet transverse parce qu'on gère bien un diagramme de Gantt. La méthodologie reste importante, mais l'enjeu de la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> concerne avant tout l'humain et l'équipe au centre du projet." }, { "type": "paragraph", "text": "Cet article vous dévoile <strong>toutes les clés de succès de votre prochain projet transverse</strong>. Des conseils pragmatiques et concrets pour mener votre projet au succès !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba67_62f3848c7d5e7f5d099078a7_projet-transverse-airsaas.jpeg", "alt": "Projet transverse", "caption": "Projets transverses : un moteur pour la transformation" }, { "type": "heading", "level": 2, "id": "comment-fonctionner-en-mode-projet-transverse-et-casser-les-silos-de-lentreprise", "text": "Comment fonctionner en mode projet transverse et casser les silos de l'entreprise ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba49_62f384e964eac22620049490_Involved%20members.jpeg", "alt": "Capture écran AirSaas équipes projet", "caption": "Choisir la dream team de votre projet" }, { "type": "heading", "level": 3, "id": "role-du-sponsor", "text": "Rôle du sponsor" }, { "type": "paragraph", "text": "Le sponsor, souvent membre de la Direction, doit avoir assez d'influence auprès des autres membres de la Direction Générale et dans l'entreprise afin de pouvoir <strong>faciliter la création de projet transverse</strong> et avoir la possibilité de mettre les moyens nécessaires en place pour sa réussite - notamment en aménageant du temps et de la disponibilité aux acteurs clés. Il doit avoir la volonté de faire bouger les lignes et il est <strong>l'un des premiers promoteurs de la démarche</strong> et du changement de point de vue quant à l'intérêt de sortir d'un fonctionnement classique des services." }, { "type": "paragraph", "text": "Il donne la ligne stratégique, challenge l'avancement et joue un rôle clé dans les arbitrages. Aussi, il facilitera le travail du chef de projet, en défendant le projet en comité de direction, en suggérant des idées en lien avec la stratégie d'entreprise. Il pourra également participer à la gestion des conflits dans le cas ou le management transverse ne serait pas suffisant." }, { "type": "heading", "level": 3, "id": "construction-de-lequipe-transverse-task-force", "text": "Construction de l'équipe transverse (task force)" }, { "type": "paragraph", "text": "Il est fortement recommandé d'i<strong>mpliquer toutes les personnes qui auront un lien avec le projet le plus tôt possible</strong>. Pour cela, vous pouvez mettre en place un comité spécifique, que ce soit un comité de pilotage ou d'innovation. Mais ici, nous parlerons de l'équipe, qui prendra l'essentiel des actions opérationnelles du projet. Vous rechercherez le plus possible à trouver les attributs suivants dans votre équipe transverse." }, { "type": "heading", "level": 4, "id": "des-competences-aiguisees", "text": "Des compétences aiguisées" }, { "type": "paragraph", "text": "Que ce soit dans l'aspect technique d'un profil, ou la connaissance accrue d'un environnement métier, vous chercherez à <strong>embarquer dans l'équipe des spécialistes</strong> dans les compétences recherchées avec si possible de l'influence. Cela permettra notamment d'évangéliser la démarche au sein d'autres collaborateurs de l'entreprise." }, { "type": "heading", "level": 4, "id": "des-elements-moteurs", "text": "Des éléments moteurs" }, { "type": "paragraph", "text": "En première ligne dans la réalisation des objectifs, les membres de l'équipe d'un projet transverse doivent-être moteurs dans la conduite du changement. Ils sont <strong>les premiers acteurs de ce processus</strong>, souvent nouveau. De ce fait, on voudra éviter au maximum les freins et les facteurs bloquants liés à l'humain, en composant l'équipe de profils partageant un état d'esprit positif quant au lancement du projet transverse. De quoi motiver toutes les parties prenantes de l'organisation impliquées dans votre projet transverse !" }, { "type": "heading", "level": 3, "id": "quest-ce-que-travailler-en-transversalite", "text": "Qu'est ce que travailler en transversalité ?" }, { "type": "paragraph", "text": "Travailler en transversalité, c'est avant tout travailler <strong>sans liens hiérarchiques</strong>, avec des personnes ne travaillant souvent pas dans le même service avec qui il est difficile de partager du temps." }, { "type": "list", "ordered": false, "items": ["<strong>Une gestion de projet tournée vers la transparence.</strong> Particulièrement en absence de liens hiérarchiques, une forte confiance entre les différents acteurs du projet est indispensable. Le chef de projet transverse doit mettre en place une dynamique dans laquelle il n'y a aucun intérêt pour personne à la rétention d'information. Lui et le sponsor doivent être vigilant dans le cas contraire.", "<strong>Du temps de travail dédié.</strong> Même si les acteurs ne travaillent pas dans le même service, il doivent pouvoir aménager du temps de travail en équipe afin d'être plus efficace et d'éviter l'inertie liée à la distance et aux activités habituelles de leurs missions respectives."] }, { "type": "heading", "level": 2, "id": "les-prerequis-pour-une-gestion-de-projet-transversal-reussie", "text": "Les prérequis pour une gestion de projet transversal réussie" }, { "type": "paragraph", "text": "En plus des éléments cités plus haut, on retrouve des éléments qu'il faut avoir bien en place avant le début opérationnel." }, { "type": "heading", "level": 3, "id": "un-bon-alignement-avec-la-strategie-dentreprise", "text": "Un bon alignement avec la stratégie d'entreprise" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba3b_62f38527d36866c52a51a46e_Projet_Goal%20-%20Desc%20-%20Gains.jpeg", "alt": "Capture écran AirSaas - Projets transverses" }, { "type": "paragraph", "text": "L'une des règles d'or à suivre pour le chef de projet comme guideline, c'est <strong>l'alignement de son projet avec la stratégie d'entreprise.</strong> Même si cela parait n'être que du bon sens, il peut être difficile, selon les étapes et aléas au cours d'un projet transverse, de savoir si l'on s'inscrit bien toujours dans la vision et la stratégie de l'entreprise. En cas de doute, se tourner vers le sponsor et faire toujours en sorte qu'il ait les bonnes informations." }, { "type": "heading", "level": 3, "id": "un-probleme-dur-avec-fort-impact-sur-lentreprise", "text": "Un problème \"DUR\" avec fort impact sur l'entreprise" }, { "type": "paragraph", "text": "Dans les bonnes pratiques des projets transverses réussis, on retrouve en tête de liste l'importance de <strong>la problématique que le projet doit résoudre</strong>. Il permet de caractériser si l'objectif que l'on veut remplir a du sens, et s'il apporte une réelle valeur." }, { "type": "paragraph", "text": "Le bon traitement d'un problématique par un projet transverse présente d'autres avantages comme :" }, { "type": "list", "ordered": false, "items": ["Permettre de chiffrer l'impact d'un problème", "Bien définir les fonctionnalités d'un service", "Définir un budget", "Permettre de valoriser les solutions misent en place et calculer un ROI"] }, { "type": "paragraph", "text": "Cette problématique doit-être <strong>DUR : Douloureuse, Urgente et Reconnue</strong>" }, { "type": "paragraph", "text": "Il sera bien mieux de passer du temps à bien comprendre le problème et le qualifier de DUR avant de lancer les opérations, que de se rendre compte au final que le projet ou la solution n'apporte pas assez de valeur, et que l'équation économique n'est pas favorable." }, { "type": "heading", "level": 3, "id": "un-budget-bien-ficele", "text": "Un budget bien ficelé" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba2d_62f3854b03388a842791920e_Projet_Budget.jpeg", "alt": "Attributs projets cadrage" }, { "type": "paragraph", "text": "Tout comme ne pas avoir bien défini une problématique (et son impact) peut être dès le début une cause d'échec d'un projet transverse, ne pas avoir de budget précis alloué en est une autre. Mettre une équipe en place et instaurer des changements dans le fonctionnement de l'entreprise peut être très néfaste pour la continuité de ce genre de démarche. En effet, si après plusieurs mois de travail on se rend compte qu'on ne souhaite pas ou que l'on a pas le budget nécessaire pour amener le projet à son terme, c'est la catastrophe assurée. D'où l'importance de définir un budget et surtout de <strong>chiffrer une problématique pour prioriser les plans d'investissement.</strong>" }, { "type": "heading", "level": 2, "id": "les-elements-cles-dexecution-pour-reussir-vos-projets-transverses", "text": "Les éléments clés d'exécution pour réussir vos projets transverses" }, { "type": "heading", "level": 3, "id": "1-rationaliser", "text": "1 : Rationaliser" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba35_625ef188cd49e0ffbe307008_projet-transverse-pragmatic.jpeg", "alt": "Illustration sur le pragmatisme", "caption": "We ❤️ pragmatisme !" }, { "type": "heading", "level": 4, "id": "a-chaque-problematique-sa-solution-pragmatique", "text": "À chaque problématique sa solution pragmatique" }, { "type": "paragraph", "text": "Après avoir abordé l'importance d'un problème bien défini, il lui faut maintenant <strong>sa solution pragmatique</strong>. En effet, on a naturellement tendance à vouloir mettre en place une solution complète pour tout résoudre dès lors qu'on visualise mentalement la solution parfaite. Or, il s'avère que les solutions idéales sur le papier (quand on est en dehors de son coeur de métier) ne seront pas réalisables, car trop longues et trop coûteuses à mettre en place - particulièrement quand on recherche \"l'effet waouh\" avant tout." }, { "type": "paragraph", "text": "Cherchez à répondre à 80% du problème - mais le mieux, le plus rapide et le moins cher possible. Pour cela, le travail sur le problème et les fonctionnalités clés pourra vous aider." }, { "type": "heading", "level": 4, "id": "prioriser-les-fonctionnalites-cles-et-les-evolutions-de-versions", "text": "Prioriser les fonctionnalités clés et les évolutions de versions" }, { "type": "paragraph", "text": "Quand on attaque un problème, une des solutions très efficace est de <strong>re-découper la problématique en plusieurs sous-problèmes</strong> qui la composent. Hiérarchiser ces sous-problèmes en fonction de l'impact/ des conséquences qu'ils génèrent, et enfin se poser la question : \"Pourquoi ce sous-problème n'est pas encore résolu ?\". La réponse à cette question sera votre levier d'action, et vous permettra de définir une fonctionnalité de votre solution permettant de le résoudre." }, { "type": "paragraph", "text": "L'idée ici est de <strong>vous concentrer sur les sous-problèmes les plus importants</strong> et de composer votre solution principale là-dessus. Vous pourrez toujours prévoir une solution évolutive avec la mise en place de nouvelles fonctionnalités plus tard au cours du projet transverse, pour compléter la résolution de la problématique globale." }, { "type": "heading", "level": 4, "id": "adopter-une-vision-long-terme-et-une-approche-roiste", "text": "Adopter une vision long terme et une approche ROIste" }, { "type": "paragraph", "text": "Il arrive souvent que, dans les premières phases d'un projet transverse, motivé par l'envie de montrer de la valeur et des \"quick wins\", on perde de vue la vision globale et long terme du projet. Il ne faut donc <strong>pas oublier que l'objectif principal est de résoudre la problématique sur le long terme.</strong> Les premières phases de votre management de projet doivent essentiellement servir à alimenter cet aspect là." }, { "type": "paragraph", "text": "Pour cela, <strong>garder une approche ROIste de vos actions</strong> et de ce qu'il restera à mettre en place est déterminant pour la validation permanente de vos recommandations et de la solution finale." }, { "type": "heading", "level": 3, "id": "2-derisquer", "text": "2 : Dérisquer" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba5b_62f38581df91453b9c1e0b2f_antenne-derisquer-airsaas.jpeg", "alt": "Photo en hauteur", "caption": "Un risque de vertige, ça se pilote aussi." }, { "type": "heading", "level": 4, "id": "selectionner-les-bons-partenaires-audit", "text": "Sélectionner les bons partenaires - audit" }, { "type": "paragraph", "text": "On peut souvent être tenté de partir avec une solution ou un partenaire extérieur qui provoque un \"effet waouh\", car elle séduira certainement les collaborateurs et valorisera l'image de votre projet. Mais assurez-vous de la capacité d'exécution de vos partenaires dans le cadre de votre projet. On préfèrera une solution peut-être moins sexy mais qui marche, et des partenaires qui délivrent." }, { "type": "paragraph", "text": "Pour cela, n'hésitez pas à faire un audit approfondi de la solution ou du partenaire externe, afin de vous assurer que la solution fonctionnera et aura la capacité d'être maintenue dans le temps." }, { "type": "heading", "level": 4, "id": "lancer-une-phase-de-test-des-hypotheses-a-valider-et-les-bon-kpis", "text": "Lancer une phase de test - des hypothèses à valider et les bon KPIs" }, { "type": "paragraph", "text": "Afin de dérisquer votre projet transverse sur le long terme, il est toujours conseillé de mettre votre solution en phase de test. Pour cela, il est important de mettre en situation et de monitorer les fonctionnalités clés, un périmètre représentatif du projet long terme, de l'environnement et contraintes de la solution." }, { "type": "paragraph", "text": "Pour cela, en partant des fonctionnalités clés que vous aurez définies grâce aux sous-problèmes de votre problématique, identifiez des hypothèses auxquelles vous aurez à répondre pour vous assurer que les fonctionnalités clés permettent de résoudre le problème et que la solution sera maintenable dans son environnement. Une fois ces hypothèses définies, trouvez <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\" target=\"_blank\">les bons KPIs à mettre en place</a> pour mesurer si oui ou non vous pourrez répondre aux hypothèses pendant la phase de test." }, { "type": "heading", "level": 4, "id": "creer-une-roadmap-et-un-cahier-des-charges", "text": "Créer une roadmap et un cahier des charges" }, { "type": "paragraph", "text": "Particulièrement dans un projet transverse, il vous sera très utile afin de rythmer les actions et de mettre tout le monde d'accord, d'entériner tous les aspects du projet dans un cahier des charges validé par toutes les parties prenantes. Pour cela, pensez à bien intégrer chacun des acteurs dans l'élaboration du document pour les parties qui les concernent. Ensuite, dessinez les chemins critiques du projet pour définir une roadmap adaptée et cohérente. Elle vous permettra de donner de la visibilité aux actions en cours, passées et à venir, ainsi qu'à monitorer l'état de santé de l'avancement." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba1f_62f385c7349867ec6d2f324e_Projet_Copil-milestones.jpeg", "alt": "timeline jalons projet", "caption": "Une vision temporelle claire" }, { "type": "heading", "level": 4, "id": "decouper-les-livrables-et-raccourcir-les-deadlines", "text": "Découper les livrables et raccourcir les deadlines" }, { "type": "paragraph", "text": "Un autre aspect de phases opérationnelles efficaces est de découper la taille des livrables ainsi que la fréquence de restitution, afin de limiter la charge mentale des collaborateurs (surtout s'ils sont sur plusieurs missions en parallèle) et avoir un suivi plus fin des dérives de planning pour prendre les bonnes actions correctives." }, { "type": "paragraph", "text": "Cela permettra aussi de rythmer le projet et les échanges, ainsi que de valoriser le travail et l'avancement de chacun." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba4d_6270f93b2b96c44ac22b5d82_Projet%20-%20deliverable.jpeg", "alt": "Capture écran AirSaas - Projets transverses" }, { "type": "heading", "level": 4, "id": "mettre-en-place-un-suivi-de-projet-a-la-semaine-rapport-flash", "text": "Mettre en place un suivi de projet à la semaine - rapport flash" }, { "type": "paragraph", "text": "L'un des leviers pour rythmer les projets transverses et rendre l'avancement plus efficace est d'instaurer un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\">suivi de projet</a> hebdomadaire du projet entre les membres de la task force et des externes plus opérationnels. Pour cela, mettre en place un rapport flash est une très bonne action pour suivre l'avancement, et permettre à tout le monde de garder une vision 360° du projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d18534c2d61f36e304ba29_62f38608523cfa1f14842cbe_Projet_kanban-report%20flash.jpeg", "alt": "Capture écran AirSaas - portfolio Projets" }, { "type": "heading", "level": 4, "id": "fonctionner-en-circuit-de-decision-court-comite-de-pilotage", "text": "Fonctionner en circuit de décision court - comité de pilotage" }, { "type": "paragraph", "text": "Dans la continuité de l'efficacité opérationnelle pour les projets transverses, et afin de se prémunir de l'inertie liée aux organisations complexes dans l'entreprise, pendant la création de l'équipe du projet, on mettre aussi en place un circuit de décision court avec un sponsor et quelques décideurs clés (au besoin) : un comité de pilotage tous les 30 ou 45 jours, afin d'y présenter l'avancement et les arbitrages nécessaires à l'avancement." }, { "type": "paragraph", "text": "Pour approfondir nous vous conseillons la lecture de l'article suivant : <a href=\"/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\">Comment être un bon chef de projet transverse ?</a>" }], "toc": [{ "label": "Comment fonctionner en mode projet transverse et casser les silos de l'entreprise ?", "href": "#comment-fonctionner-en-mode-projet-transverse-et-casser-les-silos-de-lentreprise", "level": 2 }, { "label": "Les prérequis pour une gestion de projet transversal réussie", "href": "#les-prerequis-pour-une-gestion-de-projet-transversal-reussie", "level": 2 }, { "label": "Les éléments clés d'exécution pour réussir vos projets transverses", "href": "#les-elements-cles-dexecution-pour-reussir-vos-projets-transverses", "level": 2 }], "faq": [], "related": [] }, { "slug": "copil-projet-ou-comite-de-pilotage-projet-les-bases", "skip": false, "meta": { "title": "Copil projet : les bases à connaître sur le bout des doigts", "h1": "Copil projet : les bases à connaître sur le bout des doigts", "description": "Le comité de pilotage (ou Copil projet) est une instance indispensable dans la transformation d'une entreprise. Explorons son fonctionnement, ses missions et les bonnes pratiques.", "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "12/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f36f8e87c554788d75644b_Project%20image.jpg", "alt": "" }, "publishedDate": "12/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Le comité de pilotage (ou Copil projet) est une instance indispensable dans la transformation d'une entreprise. C'est lui qui fait le <strong> </strong>lien entre le Codir et les équipes qui mettent en place les projets. Il décrit un groupe de personnes dont la fonction est de prendre des décisions et de veiller à l'atteinte d'un objectif au sein d'une entreprise." }, { "type": "paragraph", "text": "Explorons ici en détail son fonctionnement et le rôle qu'il joue dans le processus de gestion globale du projet. Ce sera aussi l'occasion de faire émerger les bonnes pratiques et donner à tous les chefs de projet des conseils utiles pour que vos Copil projet deviennent de vrais moments de décision." }, { "type": "heading", "level": 2, "id": "copil-projet-une-definition", "text": "Copil projet : une définition" }, { "type": "paragraph", "text": "Le comité de pilotage est un groupe de personnes - dont fait partie le chef de projet - chargées de <strong>veiller au bon fonctionnement d'un projet dans une entreprise</strong>. Pour améliorer le suivi d'un projet<strong> </strong>sur le plan de l'observation et des<strong> </strong>choix à effectuer, il se constitue généralement d'une équipe transversale au projet. Le comité de pilotage est généralement constitué d'un membre de chaque catégorie de rôle." }, { "type": "paragraph", "text": "Le comité de projet prend la forme concrète de réunions réalisées au service de la gestion de projet pour en garantir le bon déroulement et le succès final : avancée des travaux, réalisation des objectifs, le respect des délais, de la qualité ou des contraintes budgétaires…" }, { "type": "paragraph", "text": "Ce comité peut s'appuyer sur l'analyse de métriques issues des activités du projet afin de <strong>prendre des décisions concrètes</strong>." }, { "type": "heading", "level": 2, "id": "pourquoi-a-t-on-besoin-dun-comite-de-pilotage", "text": "Pourquoi a-t-on besoin d'un comité de pilotage ?" }, { "type": "paragraph", "text": "Le comité de pilotage (ou Copil) projet a pour objectif de mettre de l'huile dans les rouages du fonctionnement d'un projet. C'est une instance<strong> </strong>décisionnelle qui permet au client et au prestataire/partenaire (interne ou externe) d'avancer sur le même chemin, d'être alignés sur les objectifs et les tâches à réaliser." }, { "type": "paragraph", "text": "Un Copil s'organise principalement sur des projets complexes, dans lesquels beaucoup d'intervenants et d'interlocuteurs sont impliqués et/ou quand ceux-ci sont liés par de forts liens d'interdépendance." }, { "type": "paragraph", "text": "Un comité de pilotage projet permet aussi de réduire les risques d'échec en suivant de près l'avancement du projet et en partageant la charge décisionnelle entre tous les acteurs." }, { "type": "paragraph", "text": "L'enjeu principal du comité de pilotage est de prendre des décisions sur les ou les projets en cours. Le Copil projet n'est PAS<strong> </strong>une instance de<strong> </strong>partage d'informations ! Dans toutes les entreprises, la réunion du comité doit avoir comme objectif de décider, de faire des choix sur les sujets \"chauds\" ou importants qui impactent le déroulement du ou des projets et leur mise en œuvre." }, { "type": "heading", "level": 2, "id": "quelles-sont-les-missions-du-comite-de-pilotage-projet", "text": "Quelles sont les missions du comité de pilotage projet ?" }, { "type": "paragraph", "text": "Définition des objectifs, suivi de l'état d'avancement ou prises de décisions finales : le Copil intervient à toutes les étapes du projet. Cette instance a vraiment pour rôle la prise en charge de toutes les décisions relatives au projet. Au menu des réunions de Copil, des choix sont faits aussi bien sur les dates-clés du projet, l'allocation du budget ou sur les négociations contractuelles avec les fournisseurs et prestataires." }, { "type": "paragraph", "text": "Récapitulons les missions-clés du Copil projet :" }, { "type": "list", "ordered": false, "items": ["<strong>Suivre la progression du projet</strong> par rapport aux grandes étapes du planning et des échéances", "<strong>Arbitrer sur les sujets bloquants</strong> et impactant le déroulement du projet", "<strong>Affecter les ressources nécessaires à la progression du projet</strong> : il remonte au comité stratégique (s'il existe) les problèmes qui ne sont pas de leur ressort, ainsi que les décisions majeures", "Dans les entreprises à taille réduite, le comité de pilotage peut également <strong>réaliser les arbitrages </strong>concernant les orientations stratégiques", "<strong>Faire le point sur l'avancée des livrables</strong> prévus", "<strong>Suivre la consommation du</strong> <strong>budget</strong> défini initialement et remonter des alertes de surconsommation", "<strong>Monitorer les risques</strong>, leur probabilité de réalisation, et anticiper des solutions"] }, { "type": "heading", "level": 2, "id": "quelle-est-la-composition-du-comite-de-pilotage", "text": "Quelle est la composition du comité de pilotage ?" }, { "type": "paragraph", "text": "Les membres du comité de projet sont des dirigeants, des managers ainsi que les équipes métiers<strong> </strong>concernées par le projet. Le sponsor du projet fait partie intégrante de ce groupe." }, { "type": "heading", "level": 3, "id": "copil-ou-comite-de-direction", "text": "Copil ou Comité de direction ?" }, { "type": "paragraph", "text": "En fonction de la taille de l'entreprise, la constitution du Copil projet peut changer. L'élément clé et primordial est que le Copil puisse décider. Si, pour X raisons, la décision pouvait être remise en cause par une personne tierce ou un autre groupe de décision, alors c'est fini : le Copil ne sert à rien." }, { "type": "paragraph", "text": "Pour les PME, le Copil est constitué du Codir et de manière ponctuelle (par projet) du chef du projet + du sponsor du projet." }, { "type": "paragraph", "text": "Dans les grandes entreprises, la difficulté réside dans le fait qu'il y a tellement de projets que le Codir ne peut pas participer à tous les Copil projet. C'est là que les problèmes arrivent : le Copil peut ne pas avoir le dernier mot, et cela rajoute donc beaucoup de politique." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83571cd095964a46feaef_62f36d8564f6eb762b228b61_CoDir%2520Copil.jpeg", "alt": "Schéma Codir Copil", "caption": "Schéma lien Codir / Copil" }, { "type": "heading", "level": 3, "id": "qui-detient-vraiment-le-pouvoir", "text": "Qui détient vraiment le pouvoir ?" }, { "type": "paragraph", "text": "En gestion de projet, il existe souvent une grande confusion entre exécution du projet et détention du pouvoir." }, { "type": "paragraph", "text": "Attention donc : en tant que chef de projet dans la gestion de projets transverses, vous ne pouvez pas arbitrer seul<strong> </strong>et prendre des décisions sur les moyens à mettre en œuvre en priorité ou des délais qui dépassent le cadre de la mission. Pour que des décisions soient prises, il faut présenter régulièrement des reportings<strong> </strong>et mettre en lumière des informations clés au comité de pilotage." }, { "type": "heading", "level": 3, "id": "le-paradoxe-du-chef-de-projet", "text": "Le paradoxe du chef de projet" }, { "type": "paragraph", "text": "La majorité du temps, les projets échouent car il y a un désalignement entre les équipes / personnes impliquées. Notre avis (non consensuel) : alors que le chef de projet passe son temps à regarder les taches à faire et rappeler à l'ordre les personnes en retard, il devrait faire preuve de leadership, et créer les conditions d'un alignement en continu. Mais ça sera l'affaire d'un autre article..." }, { "type": "heading", "level": 3, "id": "une-equipe-dont-le-role-est-de-decider", "text": "Une équipe dont le rôle est de décider" }, { "type": "paragraph", "text": "L'équipe du comité de pilotage est comme <strong>un</strong><strong> système d'aide à la navigation</strong> qui prendrait <em>in fine</em> les décisions sur la direction à prendre. Les membres du Copil projet sont un relais de pouvoir essentiel dans l'entreprise." }, { "type": "paragraph", "text": "L'équipe projet est formée en début de projet par le<strong> </strong>sponsor, en collaboration étroite avec le chef de projet. Il faut absolument que les<strong> </strong>experts métiers<strong> </strong>susceptibles de participer à la prise de décision soient dans l'équipe." }, { "type": "paragraph", "text": "Concrètement, les membres du Copil sont à piocher dans la typologie d'acteurs suivante :" }, { "type": "list", "ordered": false, "items": ["Sponsor", "Directeur du projet (qui peut également être le sponsor)", "Chef de projet", "Représentant métier en fonction des besoins", "Groupe de \"key users\""] }, { "type": "heading", "level": 2, "id": "les-erreurs-frequentes-a-eviter", "text": "Les erreurs fréquentes à éviter" }, { "type": "heading", "level": 3, "id": "1-confondre-copil-et-coproj", "text": "1 / Confondre Copil et Coproj" }, { "type": "paragraph", "text": "Un comité de projet (Copro ou Coproj) est une réunion organisée par les chefs de projet. Ils sont au courant de toutes les facettes du projet et des enjeux. C'est un point d'étape destiné à faire émerger des points d'arbitrages<strong> </strong>à soumettre au Copil si besoin." }, { "type": "paragraph", "text": "Le Coproj est donc une réunion, le plus souvent hebdomadaire, qui réunit un chef de projet client et un chef de projet chez le prestataire si les projets font appel à de l'aide extérieure. Les opérationnels concernés peuvent ainsi<strong> </strong>coordonner le projet, et s'assurer qu'il avance dans la bonne direction. C'est l'occasion de remonter d'éventuelles problématiques ou retards, mais aussi et surtout de trouver une<strong> </strong>solution pour organiser la suite des événements." }, { "type": "paragraph", "text": "On confond parfois le Coproj avec le premier Copil : un premier comité de pilotage, aussi appelé « <em>kick-off meeting</em> », a généralement lieu avant le démarrage du projet. Ensuite, il peut intervenir lors des étapes clés du projet (fin de phase de cadrage, avant la mise en production…) pour<strong> </strong>valider<strong> </strong>les prises de décision." }, { "type": "paragraph", "text": "Coproj : Micro = Répartitions des tâches" }, { "type": "paragraph", "text": "Copil : Macro = Arbitrages et décisions" }, { "type": "heading", "level": 3, "id": "2-ne-pas-savoir-exactement-ce-qui-se-passe-dans-un-codir", "text": "2/ Ne pas savoir exactement ce qui se passe dans un Codir" }, { "type": "paragraph", "text": "Le comité de direction rassemble des personnes qui ont une autorité de décision dans l'entreprise. On l'appelle aussi \"équipe de direction\" ou \"comité exécutif\"." }, { "type": "paragraph", "text": "Les membres du comité de direction se réunissent de façon ponctuelle pour évaluer les projets en cours dans les différents départements de l'entreprise. Ils proposent une vision stratégique pour l'entreprise. Ils entourent ainsi le chef d'entreprise et lui apportent leurs soutien. Ils donnent des avis et des recommandations : le comité de direction est donc une manière de prendre des décisions en commun, qui se veulent être les meilleures pour l'entreprise." }, { "type": "paragraph", "text": "Le Codir parle projet lors des Copil Projets mais se retrouve aussi pour parler finance, stratégie, fusion / acquisition, RH..." }, { "type": "heading", "level": 2, "id": "comment-se-prepare-une-reunion-de-copil-projet", "text": "Comment se prépare une réunion de Copil projet?" }, { "type": "paragraph", "text": "Le chef de projet définit les points à aborder et charge à lui d'intégrer les travaux des parties prenantes concernées ou des groupes de travail constitués pour la résolution d'un problème précis. Aucune information ne doit être découverte pendant le comité de pilotage. <strong>L'agenda</strong> de la réunion doit être bien défini dans un premier temps, puis doit inclure les points essentiels, avant d'être <strong>envoyé</strong> aux participants <strong>48 heures avant </strong>la réunion." }, { "type": "heading", "level": 3, "id": "tout-se-fait-en-amont", "text": "Tout se fait en amont" }, { "type": "paragraph", "text": "Tout doit être envoyé en amont, au moins<strong> une semaine</strong> à l'avance, aux personnes qui assistent aux réunions. Des documents utiles à la bonne compréhension du projet peuvent également être envoyés par le chef de projet." }, { "type": "paragraph", "text": "Le sponsor doit être au courant de tout, et surtout des sujets critiques qui seront inclus dans la présentation. Idéalement, certaines décisions seront prises avant la réunion entre le chef de projet et sponsor. L'objectif serait d'avoir les <strong>validations</strong> des différents <strong>managers</strong> sur ces sujets." }, { "type": "heading", "level": 3, "id": "un-peu-de-politique", "text": "Un peu de politique" }, { "type": "paragraph", "text": "Le chef de projet doit travailler en amont, avec les participants des comités susceptibles de s'opposer à certaines décisions pour essayer de <strong>désamorcer </strong>la situation et de comprendre de quoi il en retourne exactement. Le chef de projet est donc un négociateur ou en tout cas il doit le devenir. De son tact politique dépend l'avancée du projet. Il doit apaiser les tensions et remettre le projet sur les rails plus souvent qu'à son tour. Le but du jeu est d'éviter au maximum les conflits ouverts entre parties prenantes. Les équipes métiers risquent alors de se désengager des comités de pilotage et aucune des autres instances projet ne pourra débloquer la situation." }, { "type": "heading", "level": 3, "id": "deroulement-des-reunions", "text": "Déroulement des réunions" }, { "type": "paragraph", "text": "L'objectif des réunions est d'obtenir un<strong> </strong>point d'avancement sur le projet. Le principal intérêt des réunions est de maintenir des échanges continus entre les différentes équipes techniques et fonctionnelles. Le chef de projet ou directeur de projet anime le Copil. Il présente l'état d'avancement du projet à l'aide de tableaux de bord et d'un <strong>reporting</strong> précis et <strong>synthétique</strong>. Les points sensibles doivent absolument être abordés. Le sponsor donne son accord aux décisions qui sont prises." }, { "type": "paragraph", "text": "Les réunions ont lieu le plus souvent une fois par mois. Parfois on met en place une fréquence trimestrielle. La durée d'un Copil est de 1h30 à 2 heures max." }, { "type": "heading", "level": 3, "id": "documents-utilises", "text": "Documents utilisés" }, { "type": "paragraph", "text": "Les deux documents principalement utilisés sont l<strong>'ordre du jour</strong> et le <strong>compte rendu.</strong>" }, { "type": "paragraph", "text": "L'ordre du jour : analyse du planning, des risques, des actions en cours, des décisions prises et des décisions à prendre, etc. Toutes ces informations sont consignées dans l'ordre du jour communiqué aux participants en amont." }, { "type": "paragraph", "text": "Le compte rendu : Un compte rendu s'impose, qui est à envoyer dans les 24 heures par le chef de projet à tous les participants. Les différentes décisions y seront tracées, documentées. Il sera ajouté par la suite aux documents du projet." }, { "type": "heading", "level": 2, "id": "reussir-son-copil-les-top-tips-pour-ne-pas-se-planter", "text": "Réussir son Copil : les \"top-tips\" pour ne pas se planter" }, { "type": "heading", "level": 3, "id": "1-copil-codir-limportant-cest-de-decider", "text": "1 - Copil - Codir - L'important c'est de décider !" }, { "type": "paragraph", "text": "Dans certaines organisations le Codir englobe le Copil. Peu importe. Si vous êtes chef de projet, assurez-vous que des<strong> décisions soient prises</strong> pour vos projets." }, { "type": "heading", "level": 3, "id": "2-course-de-fond-vs-sprint", "text": "2 - Course de fond vs Sprint" }, { "type": "paragraph", "text": "Le Copil n'est pas une réunion. C'est une suite de réunions. Le Copil s'inscrit dans la durée avec une fréquence à respecter. L'idéal c'est qu'il ait lieu tous les mois au minimum, sinon on perd le fil et on ne force pas à prendre les bonnes décisions. Le projet s'enlise et c'est l'échec. Lorsque vous<strong> planifiez</strong> votre premier Copil, envoyez des invitations à toutes les personnes concernées pour les <strong>six mois à venir</strong>." }, { "type": "heading", "level": 3, "id": "3-exiger-la-presence-de-toutes-les-personnes-concernees", "text": "3 - Exiger la présence de toutes les personnes concernées" }, { "type": "paragraph", "text": "Tous les <strong>décisionnaires</strong> doivent absolument être <strong>présents</strong> à chaque Copil. Notre conseil : gérer la participation des membres du Copil en amont des réunions. Une absence annoncée ou constatée signifie souvent que la personne est en désaccord avec le projet ou qu'elle ne sent pas assez considérée au sein du projet. Dans tous les cas une absence peut nuire à la productivité du projet voire même à l'ambiance de la réunion." }, { "type": "heading", "level": 3, "id": "4-un-format-unique", "text": "4 - Un format unique" }, { "type": "paragraph", "text": "Une fois qu'un format a été adopté par toutes parties prenantes et qu'il a montré son efficacité, n'en changez pas. La <strong>régularité</strong> permet de se focaliser sur le fond et d'oublier la forme. Mieux vaut passer du temps sur la mise en forme de votre présentation en amont du premier Copil, choisir les bons indicateurs et les codes couleurs pour ensuite figer ce canevas qui servira de base à tous les Copil. Ainsi vous serez plus performants dans le traitement des sujets importants et/ou urgent." }, { "type": "heading", "level": 3, "id": "5-time-keeper", "text": "5 - Time Keeper" }, { "type": "paragraph", "text": "Pour certains, le temps c'est de l'argent, pour d'autres c'est juste une question de respect du temps des autres et d'efficacité. Une réunion de Copil qui dure 3 heures ne serait pas productive et il y a fort à parier qu'à la prochaine réunion le taux de participation soit en baisse significative. Pour remédier à cette problématique d'horaire nommez un \"time-keeper\" - un maître du temps - qui doit absolument être une personne qui n'est PAS l'organisateur du Copil afin d'éviter toute maladresse." }, { "type": "paragraph", "text": "Si on se dit 10 mn par \"point\" important, alors c'est 10 mn. le time-keeper a le droit, et doit mettre fin à une discussion afin que le meeting \"avance\". C'est le<strong> garant</strong> d'une certaine <strong>discipline</strong> qui à la longue sera sûrement <strong>appréciée</strong> par la plupart des <strong>membres</strong>." }, { "type": "heading", "level": 3, "id": "6-menager-les-frustrations", "text": "6 - Ménager les frustrations" }, { "type": "paragraph", "text": "Un Copil n'est pas un règlement de compte en public. Si quelque chose cloche, <strong>faites-en part</strong> à la personne concernée bien<strong> en amont</strong>. Ou si elle est manifestement en cause dans un blocage important sur le projet, faites lui part de votre intention de partager cette information pendant la réunion. L'<strong>effet de surprise</strong> n'est <strong>pas</strong> l'effet <strong>recherché </strong>pendant un Copil." }, { "type": "heading", "level": 3, "id": "7-reporting-en-continu", "text": "7 - Reporting en continu" }, { "type": "paragraph", "text": "Le meilleur moyen de ne pas prendre les acteurs du Copil au dépourvu, c'est de <strong>communiquer en continu</strong> sur l'avancée du projet. <a href=\"/fr/solution/rapport-flash\" target=\"_blank\">Envoyez des informations et des reportings actualisés </a>(de nombreux outils sont disponibles) a pour effet de faire réagir les personnes concernées au fur et à mesure qu'elles se sentent concernées. Ainsi, en créant de petits séismes par le biais d'un reporting hebdomadaire, vous serez capable d'anticiper une fronde ou une révolte qui commence à gronder !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83571cd095964a46fead7_62f36e8814709349636af67d_Copil.jpeg", "alt": "Suivi exécution projet", "caption": "Suivi exécution projet" }, { "type": "heading", "level": 3, "id": "8-linvite-surprise-la-fausse-bonne-idee", "text": "8 - L'invité surprise = la fausse bonne idée" }, { "type": "paragraph", "text": "C'est justement la pire chose que vous puissiez faire : convier un \"invité surprise\" de manière ponctuelle au Copil. Il n'est peut-être pas au courant du mode de fonctionnement de la réunion et va probablement poser des questions dont la prise en compte et les réponses ont été apportées il y a plusieurs jours voire plusieurs semaines. Un invité ponctuel est comme un cheveu sur la soupe, c'est un élément <strong>perturbateur</strong> dont la valeur ajoutée est toute relative. Si c'est un expert alors pourquoi ne pas lui demander de rédiger une note de recommandation sur un sujet précis et l'envoyer aux personnes concernées en amont de la réunion ?" }, { "type": "paragraph", "text": "Pour rappel, le comité de pilotage n'est pas une arène dans laquelle chacun apporte ses informations et arguments. C'est un moment où les décisions sont prises. Et l'invité extérieur n'a pas le droit de vote !" }, { "type": "heading", "level": 3, "id": "9-encore-un-peu-de-politique", "text": "9 - (encore) un peu de politique" }, { "type": "paragraph", "text": "Si la présence d'un expert métier est nécessaire ou souhaitable alors n'hésitez pas une seconde et invitez-le(s) à la réunion ! Ce serait une maladresse que de demander à une personne tierce de parler au nom du métier, vous risqueriez de perdre en crédibilité très rapidement. Les experts métier doivent être valorisés lorsque c'est possible et associés aux décisions qui sont prises. Vous contribuez ainsi à la création d'un <strong>climat</strong> sain et, en tant que chef de projet vous méritez le respect qui vous est dû." }, { "type": "heading", "level": 3, "id": "10-si-la-decision-nest-pas-prise", "text": "10 - Si la décision n'est pas prise" }, { "type": "paragraph", "text": "Si dans le temps imparti la décision n'est pas prise ou pire si une 1/2 décision (= bordelx2) est prise alors faites-le remarquer :" }, { "type": "paragraph", "text": "<em>\"L'objectif du Copil sur ce projet était de prendre une décision sur ce projet. Nous n'avons pas réussi à statuer. Le projet est donc mis en stand-by et prendra du retard à partir d'aujourd'hui.\"</em>" }, { "type": "paragraph", "text": "Ce qui n'est pas écrit n'existant pas : Mettre cette phrase dans le compte rendu permettra au moment du bilan de mettre chacun face à ses <strong>responsabilités</strong>." }, { "type": "heading", "level": 3, "id": "11-pause-dejeuner", "text": "11 - Pause-déjeuner" }, { "type": "paragraph", "text": "Si le \"time-keeper\" a le droit de mettre fin à certaines discussions, il y en a certaines qui méritent pourtant d'être poursuivies en OFF dans l'intérêt du projet. Un bon conseil : organisez vos réunions Copil de 10h à midi. D'une part vous êtes sûr de terminer à l'heure parce que tout le monde a faim ! D'autre part, des échanges informels et non chronométrés peuvent avoir lieu en toute décontraction pendant le déjeuner. C'est une manière de détendre l'atmosphère. L'abus d'alcool est dangereux pour la santé." }, { "type": "heading", "level": 2, "id": "sponsor-jalons-chef-de-projet-key-user-reporting-comite-de-pilotage-definitions-et-incomprehensions", "text": "Sponsor, jalons, chef de projet, key user, reporting, comité de pilotage : définition(s) et incompréhension(s)" }, { "type": "paragraph", "text": "Pour le dire simplement la question c'est la scalabiliy de l'agilité... 😂" }, { "type": "paragraph", "text": "Même si tous les métiers ont leurs codes...Dans la tech. ça jargonne sec !<br><br>Si vous voulez vraiment inclure les parties prenantes de vos projets dans un environnement clair et faciliter le développement d'une <strong>culture</strong> de transformation commune...sans avoir à former vos équipes pendant des jours....testez AirSaas !" }, { "type": "paragraph", "text": "Car oui dans les entreprises tout le monde parle projets...mais personne ne parle de la même chose !" }, { "type": "paragraph", "text": "Prenons l'exemple des jalons...L'erreur courante est d'en donner trop, de rendre illisible un suivi efficace<strong>.</strong>" }, { "type": "paragraph", "text": "Un rappel fondamental : dans un pilotage et reporting, je partage l'état des jalons, pas des tâches !<br>Car, oui on ne transforme pas une organisation en commençant par inviter les équipes à faire de la gestion de projets \"à la tache\". Le but est bien de structurer, communiquer et ensuite piloter un plan de transformation.<br>On vous a concocté une \"antisèche\" réussite sur 5 mots courants de la gestion de projet, qui pourtant sont souvent mal compris. Sponsor, jalons, chef de projet, key user, reporting, comité de pilotage." }, { "type": "paragraph", "text": "En revisitant ce qui se joue derrière les mots ou expressions clés régulièrement utilisés en comité de pilotage d'un projet, on revient au sens, au processus...Et si finalement la clé n'était pas là...mieux se comprendre." }, { "type": "paragraph", "text": "Car rappelons-le, un REX ce n'est pas seulement un chien ! :-). <a href=\"/gestion-de-projet/comite-de-pilotage-definitions-et-incomprehensions\" target=\"_blank\">Comité de pilotage : définition(s) et incompréhension(s)</a>" }, { "type": "heading", "level": 2, "id": "tout-est-dans-la-preparation-ce-quil-faut-faire-avant-le-comite", "text": "Tout est dans la préparation ! Ce qu'il faut faire avant le comité" }, { "type": "paragraph", "text": "Un Copil ne doit pas être votre énième réunion hebdo ou mensuelle. Ni un groupe de travail vu comme un atelier collaboratif pour co-construire..., il ne doit pas permettre de répondre à des questions opérationnelles ou métiers..." }, { "type": "paragraph", "text": "Tout ceci a déjà été traité en <strong>amont</strong> en plus petit groupe. Et le chef de projet, ainsi que le sponsor doivent avoir une idée très claire de ce qu'ils attendent de chaque session de comité de pilotage projet." }, { "type": "paragraph", "text": "Grâce à tout un travail de préparation, le chef de projet peut notamment connaître toutes les objections des membres et préparer avec le sponsor le bon plan d'action." }, { "type": "paragraph", "text": "Définition des objectifs, interactions avec le sponsor, place des intérêts personnels, gestion des désaccords avants, astuce du formulaire anonyme, points de vigilance parties prenantes. Tout pour muscler votre préparation." }, { "type": "paragraph", "text": "Dans cet article <a href=\"/gestion-de-projet/comment-bien-preparer-un-comite-de-pilotage\" target=\"_blank\">Comment bien préparer un comité de pilotage ?</a> L'accent est mis sur l'humain et les relations humaines. Elles sont tellement souvent à l'origine de défaillances projets qu'elles représentent des points d'attention majeurs dans la gestion de projet." }, { "type": "heading", "level": 2, "id": "le-copil-commence-ce-quil-faut-faire-pour-lanimer-avec-efficacite", "text": "Le Copil commence ? Ce qu'il faut faire pour l'animer avec efficacité !" }, { "type": "paragraph", "text": "Le comité a été préparé avec le maximum d'anticipation...C'est le jour \"J\", l'heure \"H\" ...et vous avez déjà relevé quelques imprévus...une absence d'un des membres, un support mal ficelé... Vous sentez que vous n'êtes pas en pleine possession de vos moyens." }, { "type": "paragraph", "text": "Oui et sous <strong>stress</strong> nos comportements changent !" }, { "type": "paragraph", "text": "Quels sont les déboires à éviter, comment avoir une bonne gestion du temps, des tensions, quel est le support de présentation optimal...Comment gérer le dérapage, les enjeux politiques, quel juste niveau de détails communiquer. Toutes ces questions sont légitimes. En passant en revue notre <strong>check liste </strong>vous vous éviterez des sur tensions inutiles." }, { "type": "paragraph", "text": "Si la réunion et le chef de projet sont bien préparés, réussir un comité de pilotage est un objectif atteignable ! Lisez cet article pour savoir <a href=\"/gestion-de-projet/comment-animer-un-comite-de-pilotage\" target=\"_blank\">Comment animer un comité de pilotage ?</a>" }, { "type": "heading", "level": 2, "id": "le-copil-rame-comment-ameliorer-le-processus-de-decision", "text": "Le Copil rame ? Comment améliorer le processus de décision ?" }, { "type": "paragraph", "text": "Nous l'avons vu plus haut, ce comité est une <strong>équipe</strong> dont le rôle est de décider !" }, { "type": "paragraph", "text": "Dans une entreprise les décisions c'est l'élément central qui bloque ou débloque une situation." }, { "type": "paragraph", "text": "MAIS" }, { "type": "paragraph", "text": "Personne, aucune entreprise, ne pilote par la décision." }, { "type": "list", "ordered": false, "items": ["Aucune manière claire de prendre une décision hormis en meeting - - Pas d'historique", "Pas de transparence sur les décisions,", "Pas de possibilité pour un chef de projet de remonter facilement une décision à prendre."] }, { "type": "paragraph", "text": "Plus le processus de décision est clair, transparent, facilement \"utilisable\" plus la capacité de l'entreprise à agir est forte. Sinon ça rame !" }, { "type": "paragraph", "text": "La décision devrait être aussi <strong>simple</strong> qu'une API." }, { "type": "paragraph", "text": "Sans prise de décision efficace, les projets sont lancés, stoppés ou prolongés de manière <strong>irrationnelle</strong>. On a tous en tête une personne qui monopolise la parole pendant 10 minutes. Quelqu'un qui demande un détail précis qui nous empêche de parler du fond… Découvrez des astuces pour mieux gérer ces situations-là, et enfin savoir <a href=\"/gestion-de-projet/comment-decider-en-copil\" target=\"_blank\">Comment décider en Copil ?</a>" }, { "type": "heading", "level": 2, "id": "comment-mettre-en-place-un-comite-de-pilotage-efficace", "text": "Comment mettre en place un comité de pilotage efficace ?" }, { "type": "paragraph", "text": "On l'a vu plus haut, le comité de pilotage a pour objectif de mettre de l'huile dans les rouages du fonctionnement d'un projet. Mais comment mettre de l'huile dans le fonctionnement de cet organe lui-même ?" }, { "type": "paragraph", "text": "Quels sont les points de vigilance clés sur l'implication des membres, comment désamorcer les tensions, éviter trop de jeux politiques, garder une efficacité dans la durée, quels sont les outils les plus utiles… Si vous vous demandez <a href=\"/gestion-de-projet/comment-mettre-en-place-un-comite-de-pilotage\" target=\"_blank\">Comment mettre en place un comité de pilotage ?</a> Lisez notre article de référence sur cette page." }, { "type": "heading", "level": 2, "id": "comment-gerer-lagressivite-dans-les-comites-de-pilotage", "text": "Comment gérer l'agressivité dans les comités de pilotage ?" }, { "type": "paragraph", "text": "Comment repérer et gérer les personnalités difficiles dans vos entreprises et réunions de comités de pilotage ? C'est un des enjeux les plus critiques dans toute assemblée celui qui conditionne les conditions de travail. Il existe deux types de comportements agressifs...Un peu comme les premiers secours, notre responsabilité collective est avant tout d'être en capacité de repérer les types \"d'agression\" : celle qu'il faut <strong>sanctionner</strong> et celles sur lesquelles <strong>remédier</strong> !" }, { "type": "paragraph", "text": "Dans la seconde catégorie on retrouve le profil plus classique de l'agressif, impoli, irrespectueux qui exerce à la limite du <strong>carton rouge.</strong> Exemple : il hausse la voix, crie, se lève, lance une phrase à \"l'emporte-pièce\" pour attaquer personnellement certains membres, voire tous/ ! Il s'en prend aux personnes versus ce qu'elles font." }, { "type": "paragraph", "text": "Attention à la prise en compte ...Ignorer = empirer." }, { "type": "paragraph", "text": "Idem,<strong> </strong>ici un recadrage et une<strong> remédiation</strong> sur les règles sont à prévoir. En cas d'irrespect ou d'agression verbale, rappelez de manière ciblée les règles de discussion convenues pour les Copil. Demandez aux participants de s'y tenir et d'éviter un comportement agressif." }, { "type": "paragraph", "text": "<a href=\"/gestion-de-projet/comment-gerer-lagressivite-dans-les-comites-de-pilotage\" target=\"_blank\">Comment gérer l'agressivité dans les comités de pilotage ?</a> Comment réagir en cas d'agressivité ? Découvrez les 7 astuces sélectionnées pour vous faciliter la vie de bureau." }, { "type": "heading", "level": 2, "id": "copil-5-astuces-pour-que-tout-se-passe-bien", "text": "Copil : 5 astuces pour que tout se passe bien" }, { "type": "paragraph", "text": "Félicitations ! La mise à jour s'est bien passée ! Vous avez lu un dossier complet sur cette page. Vous connaissez maintenant les bases du Comité de pilotage, ses outils, ses opérations, toute l'importance dans le déroulement du projet d'une bonne exécution de ce processus au sein de votre entreprise." }, { "type": "paragraph", "text": "Au-delà des fondamentaux, on vous a préparé sur une autre page 5 astuces premium pour aller plus loin. Des pratiques pragmatiques et activables : découvrez par exemple le contrat relationnel IT/Métier/Sponsor. Vous serez également séduits par un tips \"pépite\" de pure réthorique avec la méthode des réponses vagues &amp; précises à utiliser si vous êtes pris en défaut, etc. Voici notre sélection, forcément subjective, de 5 pratiques, qu'on aurait aimé découvrir, avant notre premier comité :-) <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">Copil projet : 5 astuces pour que tout se passe bien.</a>" }], "toc": [{ "href": "#copil-projet-une-definition", "label": "Copil projet : une définition", "level": 2 }, { "href": "#pourquoi-a-t-on-besoin-dun-comite-de-pilotage", "label": "Pourquoi a-t-on besoin d'un comité de pilotage ?", "level": 2 }, { "href": "#quelles-sont-les-missions-du-comite-de-pilotage-projet", "label": "Quelles sont les missions du comité de pilotage projet ?", "level": 2 }, { "href": "#quelle-est-la-composition-du-comite-de-pilotage", "label": "Quelle est la composition du comité de pilotage ?", "level": 2 }, { "href": "#les-erreurs-frequentes-a-eviter", "label": "Les erreurs fréquentes à éviter", "level": 2 }, { "href": "#comment-se-prepare-une-reunion-de-copil-projet", "label": "Comment se prépare une réunion de Copil projet?", "level": 2 }, { "href": "#reussir-son-copil-les-top-tips-pour-ne-pas-se-planter", "label": "Réussir son Copil : les \"top-tips\" pour ne pas se planter", "level": 2 }, { "href": "#sponsor-jalons-chef-de-projet-key-user-reporting-comite-de-pilotage-definitions-et-incomprehensions", "label": "Sponsor, jalons, chef de projet, key user, reporting, comité de pilotage : définition(s) et incompréhension(s)", "level": 2 }, { "href": "#tout-est-dans-la-preparation-ce-quil-faut-faire-avant-le-comite", "label": "Tout est dans la préparation ! Ce qu'il faut faire avant le comité", "level": 2 }, { "href": "#le-copil-commence-ce-quil-faut-faire-pour-lanimer-avec-efficacite", "label": "Le Copil commence ? Ce qu'il faut faire pour l'animer avec efficacité !", "level": 2 }, { "href": "#le-copil-rame-comment-ameliorer-le-processus-de-decision", "label": "Le Copil rame ? Comment améliorer le processus de décision ?", "level": 2 }, { "href": "#comment-mettre-en-place-un-comite-de-pilotage-efficace", "label": "Comment mettre en place un comité de pilotage efficace ?", "level": 2 }, { "href": "#comment-gerer-lagressivite-dans-les-comites-de-pilotage", "label": "Comment gérer l'agressivité dans les comités de pilotage ?", "level": 2 }, { "href": "#copil-5-astuces-pour-que-tout-se-passe-bien", "label": "Copil : 5 astuces pour que tout se passe bien", "level": 2 }], "faq": [], "related": [] }, { "slug": "demarche-de-projet", "skip": false, "meta": { "title": "Comment instaurer une démarche de projet dans mon entreprise ?", "h1": "Comment instaurer une démarche de projet dans mon entreprise ?", "description": "Comment mettre en place une démarche projet pragmatique et standardisée ? Découvrez pourquoi et comment développer une culture projet efficace dans votre entreprise.", "publishedDate": "4/5/2022", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "4/5/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea955c7a189107aaa7cb8f_Project%20image%20(3)-min.jpg", "alt": "" } }, "blocks": [{ "type": "paragraph", "html": "La <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\">conduite de projet</a> <strong>aussi est un métier en transformation !</strong> Accélération digitale, multiplication des projets transverses et environnement \"VICA\" (volatile incertain complexe et ambigu) rendent la maîtrise de cet art toujours plus exigeant." }, { "type": "paragraph", "html": "Dans cet article nous explorerons en détail <strong>pourquoi et comment mettre en place une démarche projet pragmatique et (un peu) standardisée</strong>. L'occasion de déconstruire quelques préjugés sur la méthode et de vous aider à <strong>développer votre culture projet efficace</strong> 🔥 !" }, { "type": "heading", "level": 2, "id": "rapide-rappel-des-fondamentaux", "text": "Rapide rappel des fondamentaux" }, { "type": "paragraph", "html": "Un projet est un ensemble d'actions que nous souhaitons entreprendre, pour atteindre un but... Un mot qui vient du latin \"projectum de projicere\", littéralement « <strong>jeter quelque chose vers l'avant</strong> » !" }, { "type": "paragraph", "html": "Au delà de la définition et des outils, ce sont bien <strong>les questions clés de l'exercice du pouvoir et de la réalisation de la transformation</strong> de l'entreprise qui sont en jeu." }, { "type": "heading", "level": 2, "id": "les-etapes-types-dune-demarche-de-projet", "text": "Les étapes-types d'une démarche de projet" }, { "type": "paragraph", "html": "Quelle que soit votre méthode de gestion de projet, une démarche de projet respecte a priori des étapes et utilise des outils !" }, { "type": "list", "ordered": false, "items": ["<a href=\"https://www.airsaas.io/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\"><strong>Cadrage</strong></a> général des objectifs, étapes et des besoins, avec le métier ;", "Choix des <strong>méthodologies</strong> de livraison, des exigences, des outils, de l'équipe et de la gouvernance projet ;", "<strong>Planification</strong> macro / jalons / plan de communication ;", "<strong>Exécution</strong> et respect du triptyque \"coût-qualité-délais\" ;", "<strong>Tests et recette ;</strong>", "<strong>Livraison ;</strong>", "<a href=\"https://www.airsaas.io/gestion-de-projet/comment-animer-un-bilan-projet-efficace\" target=\"_blank\"><strong>Bilan proje</strong>t</a> et amélioration ;"] }, { "type": "paragraph", "html": "Derrière ce tableau des étapes \"académique\" et idéal... quelle réalité ?" }, { "type": "heading", "level": 3, "id": "le-constat-general", "text": "‍Le constat général :" }, { "type": "list", "ordered": false, "items": ["Quasiment toutes les entreprises ont une <strong>culture projet hétérogène</strong> et les <a href=\"https://www.airsaas.io/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\"><strong>chefs de projets</strong></a> ont également des <strong>niveaux très variables</strong> ;", "<strong>La DSI a longtemps été en pointe sur ces questions,</strong> et les <strong>métiers pas trop \"matures\"</strong> sur la gestion de projet ;", "On <strong>semble s'être collectivement habitué à ce que les chantiers IT soient en retard</strong>, plus cher et/ou \"hors sujets\" ;", "N'importe quel outil de CRM offre une bonne vision globale de la performance commerciale avec des reportings variés... <strong>la performance opérationnelle des projets de transformation d'entreprise est quant à elle très difficile à visualiser et partager</strong>...", "On remarque enfin, fréquemment, l'<strong>absence d'amélioration continue ou de bilan projet</strong>"] }, { "type": "paragraph", "html": "En synthèse : le projet, <strong>tout le monde connait...mais, généralement, personne ne met la même définition et réalisation derrière.</strong>" }, { "type": "heading", "level": 2, "id": "trois-raisons-pour-lesquelles-mettre-en-place-une-vraie-demarche-de-projet-dans-mon-entreprise", "text": "Trois raisons pour lesquelles mettre en place une (vraie) démarche de projet dans mon entreprise !" }, { "type": "heading", "level": 3, "id": "pour-que-ca-avance-et-vraiment", "text": "💪Pour que ça avance, et vraiment !" }, { "type": "paragraph", "html": "L'emergence de plus en plus de projets transverses, rassemblant des business unit différentes <strong>a rendu indispensable le recours à des équipes pluridisciplinaires</strong>, \"hors silos\". Cette coordination est, a priori, plus facile si on regroupe des gens dans une phase de temps et de moyens définis. <strong>L'avancement de vos projets et, a fortiori, l'efficience de votre transformation en dépend.</strong>" }, { "type": "heading", "level": 3, "id": "pour-sortir-des-fausses-priorisations", "text": "🚥 Pour sortir des fausses priorisations !" }, { "type": "paragraph", "html": "L'accélération digitale a pour corollaire une <strong>augmentation du flux d'initiatives</strong>. Extra !...sauf si on ne définit pas <strong>un périmètre clair d'initiatives et d'exécution</strong>. Les objectifs sont bien de concentrer et prioriser les efforts ! On risque sinon de verser non pas dans l'agilité...mais dans l'agitation et la fausse <strong>priorisation.</strong>" }, { "type": "paragraph", "html": "Délivrer avec méthode...! se fixer des échéances, des objectifs par étapes, permet d'être efficace ! <strong>Choisir...C'est avancer !</strong>" }, { "type": "heading", "level": 3, "id": "pour-suivre-ou-se-depense-votre-argent-et-votre-temps", "text": "💸 Pour suivre ou se dépense votre argent et votre temps... !" }, { "type": "paragraph", "html": "<strong>Si on traite les questions en flux continu,</strong> type \"run\", ....comme fait-on pour évaluer les résultats, le <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">budget</a> et la valeur ajoutée crée ?" }, { "type": "paragraph", "html": "Les étapes ou jalons des projets permettent de proposer régulièrement une vue précise de ce qu'on fait, et de ce qu'on ne fait pas, de <strong>piloter par la valeur !</strong>" }, { "type": "heading", "level": 2, "id": "comment-sy-prendre-pour-piloter-efficacement-une-demarche-de-projet", "text": "Comment s'y prendre pour piloter efficacement une démarche de projet ?" }, { "type": "heading", "level": 3, "id": "changer-dangle-de-vue", "text": "👀 Changer d'angle de vue" }, { "type": "paragraph", "html": "L'héritage d'années de pratique avec des référentiels d'outils de gestion de projets type \"à la tâche\" ont conditionné notre vision de la réalisation en liste des tâches, planning et ressources, ...puis portefeuille." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3e25f74114711c9400b1a_demarche.jpg", "alt": "Pyramide démarche projet", "caption": "8 chances sur 10 de \"subir\" une transformation inefficace" }, { "type": "paragraph", "html": "⚠️ Non ! On ne transforme pas une organisation en commençant <strong>par forcer les équipes à faire de la gestion de projet \"à la tâche\"</strong>, le but est bien bien de structurer, communiquer et ensuite piloter un plan de transformation." }, { "type": "heading", "level": 3, "id": "standardiser-plusieurs-demarches", "text": "↔️ Standardiser plusieurs démarches" }, { "type": "paragraph", "html": "Attention au syndrome du \"canon pour la mouche\". Tous les projets n'ont pas la même définition...les mêmes contraintes et besoins en terme de méthodes de réalisation. On en distinguera trois grands types et leur démarches associées." }, { "type": "list", "ordered": false, "items": ["les projets IT qui sont déjà bien gérés dans Azure devops/Jira, etc.", "les projets importants / risqués ou il faut impliquer les métiers fortement", "et les projets plus petits ou l'implication des métiers est nécessaire mais ou il y a moins de risques."] }, { "type": "paragraph", "html": "A partir ce ce simple découpage...vous pourrez appréhender une re définition des do's et dont' de la gestion de projet par catégorie, avec un outil compagnon comme AirSaas.&nbsp;" }, { "type": "heading", "level": 3, "id": "creer-et-vendre-un-plan-de-transformation-dabord", "text": "🏡 Créer et vendre un plan de transformation d'abord..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62714920747026c0d398526b_transformation.jpeg", "alt": "Une vision claire qui fera \"sens\" pour tous !", "caption": "Une vision claire qui fera \"sens\" pour tous !" }, { "type": "paragraph", "html": "De façon schématique, les grandes phases d'une approche de projet (efficace) sont :" }, { "type": "list", "ordered": true, "items": ["Je <strong>vends un </strong><a href=\"https://www.appvizer.fr/magazine/operations/ppm/plan-de-transformation\" target=\"_blank\"><strong>plan de transformation</strong></a>, qui donne du sens...pour tout le monde !", "Je <strong>canalise mon objectif initial</strong>, sur des projets à \"courte portée\" !", "Je <strong>\"caste\" la premières équipe projet</strong>, avec des individus et directions qui se connaissent... et s'apprécient.", "Dans mon <a href=\"https://www.airsaas.io/gestion-de-projet/le-pilotage-de-projet-en-2023\" target=\"_blank\">pilotage du projet</a> et reporting, <strong>je partage des </strong><a href=\"https://www.airsaas.io/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\"><strong>jalons</strong></a><strong> pas des tâches</strong> !", "Je <strong>valorise vraiment cette équipe : les contributeurs</strong>, key users, responsable métiers..."] }, { "type": "paragraph", "html": "Dans le détail :" }, { "type": "heading", "level": 4, "id": "je-vends-un-plan-de-transformation-qui-donne-du-sens", "text": "Je vends un plan de transformation qui donne du sens !" }, { "type": "paragraph", "html": "Simplifions-nous la tâche en entrant par le \"haut du portefeuille\" ! Le plus important c'est bien d'<strong>avoir une vision globale de ce qu'on veut faire,</strong> pour prioriser <strong>avant même de dire comment on exécutera !</strong> Car oui il faut le répéter <strong>ça ne sert à rien de des mettre des tâches dans des projets qu'on ne va pas faire</strong> !" }, { "type": "heading", "level": 4, "id": "je-calibre-mon-objectif-initial-sur-23-projets-a-courte-portee-pour-avoir-des-succes", "text": "Je calibre mon objectif initial sur 2/3 projets à \"courte portée\" pour avoir des succès !" }, { "type": "paragraph", "html": "Par exemple sur un rythme de 3-6 ou 9 mois maximum...vos premiers \"bébés projet\" ne seront ni des prématurés, type quick-win\"- ni de futurs Tanguys, type chantier ERP à perpétuité !" }, { "type": "heading", "level": 4, "id": "je-caste-les-premieres-equipes-projets-avec-des-individus-et-directions-qui-se-connaissent-et-sapprecient", "text": "Je \"caste\" les premières équipes projets avec des individus et directions qui se connaissent et s'apprécient..." }, { "type": "paragraph", "html": "On pense bien trop souvent que c'est la gestion des tâches qui fait réussir. Ce qui créé la réussite du projet... c'est l'équipe ! Après chacun a ses bonnes pratiques... la DSI peut aller chercher une direction avec qui ça se passe déjà bien... pour engranger des succès modèles. On appelle cela la stratégie de la tache d'huile !" }, { "type": "heading", "level": 4, "id": "dans-mon-pilotage-et-reporting-je-partage-letat-du-projet-des-jalons-pas-des-taches", "text": "Dans mon pilotage et reporting, je partage l'état du projet des jalons, pas des tâches !" }, { "type": "paragraph", "html": "Je met à jour les éléments clés : décisions à prendre, points d'attentions, jalons pour communiquer à tout le top management l'état du projet ;" }, { "type": "paragraph", "html": "J'intègre les autres directions à AirSaas pour faire en sorte d'avoir une communication globale unifiée, et une <strong>vision des projets et initiatives transformantes toujours</strong> à jour." }, { "type": "paragraph", "html": "J'envoie les rapport flash a un public large, aux parties prenantes une fois par semaine. (oui oui pas une fois tous les mois...!)" }, { "type": "heading", "level": 4, "id": "je-valorise-vraiment-les-contributeurs-key-users-responsable-metiers", "text": "Je valorise vraiment les contributeurs, key users, responsable métiers..." }, { "type": "paragraph", "html": "Les fondamentaux restent les fondamentaux : un sponsor qui joue son rôle, des métiers bien impliqué dans le cadrage...un comité de pilotage....les bons outils...une direction de la transformation qui valorise vraiment ses contributeurs avec une attention au triangle \"Ambiance-sens-salaire\" !" }, { "type": "paragraph", "html": "En synthèse, pour une re définition de votre gestion de projet...nous vous révélons l'une des <strong>équations de l'algorithme d'efficacité projet</strong> d'AirSaas :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62e93ed52c6694604fd3abc2_airsaas-nl-1-min.jpeg", "alt": "Equation démarche Projet ROI", "caption": "Equipe + Comité de pilotage + rapport flash + priorisation = efficacité projet ² !" }, { "type": "heading", "level": 2, "id": "gestion-de-projet-de-transformation-les-elements-cles", "text": "⛰️ Gestion de projet de transformation : les éléments clés !" }, { "type": "paragraph", "html": "Au delà des outils donc, la démarche ce sont des méthodes et des étapes clés." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62714b94e7e643ce851a39a2_matrice-knoster-projet-airsaas.jpg", "alt": "Matrice de Knoster", "caption": "Matrice de Knoster pour une démarche de projet de changement." }, { "type": "list", "ordered": false, "items": ["<strong>Sans vision</strong>, on crée de la <strong>confusion</strong>.", "<strong>Sans savoir-faire</strong>, on engendre la <strong>peur</strong>.", "<strong>Sans bénéfice au changement</strong>, on renforce la <strong>résistance.</strong>", "<strong>Sans ressources</strong>, on génère de la <strong>frustration</strong>.", "<strong>Sans plan d'actions</strong> structuré et suivi, on génère de la <strong>pagaille</strong>"] }, { "type": "heading", "level": 2, "id": "demarche-projet-les-7-erreurs", "text": "🤦‍♂️ Démarche projet : les 7 erreurs !" }, { "type": "list", "ordered": true, "items": ["<strong>Confondre outils et démarche</strong> projet : la démarche elle, inclura l'humain !", "<strong>Croire que le plus beau diagramme de Gantt ou Asana vous protège de l'échec</strong> ! it's the team, stupid !", "<strong>Confondre démarche de projet et programme :</strong> la valeur ajoutée doit être visualisée globalement.", "<strong>Ne pas</strong> (du tout) <strong>tenir compte des résistances au changement</strong> dans un projet : <em>« Les gens ne détestent pas le changement. Il détestent juste la manière dont vous essayez de les faire changer » </em>M. Kanazawa", "<strong>Confondre agilité et agitation</strong> : l'important c'est l'efficacité !", "<strong>Donnez la priorité à... trop de priorités</strong> ! un peu comme un croisement avec des feux oranges clignotants partout !", "<strong>Choisir les mauvais outils</strong> : \"quand on a qu'un marteau tout ressemble à un clou\" !"] }, { "type": "heading", "level": 2, "id": "les-points-cles-a-retenir", "text": "Les points-clés à retenir" }, { "type": "list", "ordered": false, "items": ["<strong>Disons le clairement :</strong> 80 % des projets ne nécessiteront pas de Gantt ou de priorisation à la tâche !", "En <strong>visualisant le portefeuille, c'est-à-dire un ensemble de projets ordonné et piloté par la valeur</strong> entre les métiers et la DSI, il deviendra <strong>plus facile de gérer une partie des frustrations</strong> et d'impliquer le Top Management en traitant des sujets qui sont fondamentaux : stratégie, dialogue et coopération entre les silos, répartition budgétaire..", "Créer les conditions d'une démarche de projet efficace demande un <strong>travail d'acculturation et une montée en compétences sur les pratiques et la philosophie pas seulement agile... mais \"pragmatique\" !</strong> Ne pensez pas uniquement management de projet, mais également conduite du changement et leadership."] }, { "type": "paragraph", "html": "Une fois les fondamentaux généraux de la démarche établis, le prochain challenge sera de passer en mode projet dans le détail. La lecture de cet article devrait vous y aider : <a href=\"/fr/gestion-de-projet/le-guide-du-mode-projet\" target=\"_blank\">Comment faire passer mon entreprise en mode projet</a> ?" }], "toc": [{ "label": "Rapide rappel des fondamentaux", "href": "#rapide-rappel-des-fondamentaux", "level": 2 }, { "label": "Les étapes-types d'une démarche de projet", "href": "#les-etapes-types-dune-demarche-de-projet", "level": 2 }, { "label": "Trois raisons pour lesquelles mettre en place une (vraie) démarche de projet dans mon entreprise !", "href": "#trois-raisons-pour-lesquelles-mettre-en-place-une-vraie-demarche-de-projet-dans-mon-entreprise", "level": 2 }, { "label": "Comment s'y prendre pour piloter efficacement une démarche de projet ?", "href": "#comment-sy-prendre-pour-piloter-efficacement-une-demarche-de-projet", "level": 2 }, { "label": "⛰️ Gestion de projet de transformation : les éléments clés !", "href": "#gestion-de-projet-de-transformation-les-elements-cles", "level": 2 }, { "label": "🤦‍♂️ Démarche projet : les 7 erreurs !", "href": "#demarche-projet-les-7-erreurs", "level": 2 }, { "label": "Les points-clés à retenir", "href": "#les-points-cles-a-retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "fiche-projet-exemple-et-methodologie", "skip": false, "meta": { "title": "Fiche projet : méthodologie & exemple", "h1": "Fiche projet : méthodologie & exemple", "description": "Une fiche de projet est un outil essentiel car elle définit avec précision toute l'organisation du projet. Méthodologie et exemple de fiche projet.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f38451b9b831262a2710ed_3.jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "10/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "10/10/2021" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44be5_62f382435a05664617ad8c2e_6269623ae08e865e4c48f096_Project-page-setup%25252Bexecution-min.jpeg", "alt": "Cadrage et exécution projet", "caption": "Cadrage et exécution projet" }, { "type": "paragraph", "html": "Une fiche de projet est un outil essentiel car elle <strong>définit</strong> avec précision<strong> toute l'organisation</strong> du projet ou d'une partie de ce dernier. C'est un livrable important car le chef de projet doit y lister toutes les phases, les étapes et les actions qui devront être accomplies dans la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet.</a> Lorsque vous passez en revue vos projets vous pouvez envoyer un <a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">rapport flash</a> qui centralise les fiches projets actualisées aux différentes parties prenantes." }, { "type": "inline-cta", "label": "Télécharger ⇣", "href": "https://hubs.ly/Q02NlZ8Q0" }, { "type": "heading", "level": 2, "id": "quest-ce-quune-fiche-de-projet-ou-plan-projet", "text": "Qu'est-ce qu'une fiche de projet ou plan projet ?" }, { "type": "paragraph", "html": "C'est un peu la recette du projet. Certains diront \"<strong>la carte d'identité du ou des projets sur lesquels vous travaillez. </strong>Sans organisation ni planification, les équipes prennent des risques inutiles et mettent en danger l'atteinte des résultats. Les fiches projet sont des livrables dans lesquels figurent tous les \"ingrédients\" nécessaires. Elles servent à <strong>rendre les projets compréhensibles </strong>par toutes les <strong>parties prenantes</strong> et à mettre en avant les enjeux principaux. La fiche projet ne fait<strong> pas office de contrat</strong> mais <strong>apporte de la transparence</strong> entre un prestataire et son client, ou entre les parties prenantes au sein d'une même entreprise." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c16_62f3825c13ce5e53bf3f66b1_6269623ae08e86360848f068_Deal-min.jpeg", "alt": "une équipe soudée" }, { "type": "heading", "level": 3, "id": "quelles-sont-les-questions-auxquelles-repond-la-fiche-de-projet", "text": "Quelles sont les questions auxquelles répond la fiche de projet ?" }, { "type": "paragraph", "html": "Des informations essentielles doivent figurer dans vos fiches projet. Elles doivent permettre de répondre à certaines questions clé :" }, { "type": "list", "ordered": false, "items": ["Quels sont les <strong>objectifs principaux</strong> du projet ?", "<strong>Qui est le donneur d'ordre</strong> / qui exécute ? / avec le soutien de qui ?", "Comment sera organisée la gestion de projet ?", "Quelle est la <strong>fréquence d'envoi des livrables</strong> ?", "De quelles <strong>ressources</strong> dispose-t-on ?", "Quels sont <strong>les risques</strong> et<strong> les contraintes</strong> liées au projet ?"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44bfb_62f382b5e38c6d1d9b1fc7d1_6269623ae08e86ba4548f07e_Creation-Gain.jpeg", "alt": "gain projet", "caption": "Gain projet" }, { "type": "heading", "level": 3, "id": "un-document-de-pilotage-des-activites-liees-a-un-projet", "text": "Un document de pilotage des activités liées à un projet" }, { "type": "paragraph", "html": "La fiche projet est donc un véritable <strong>outil de gestion</strong> de vos projets. Elle <strong>centralise</strong> en un lieu unique toutes <strong>les informations utiles</strong> à son<strong> bon déroulement</strong> et en précise le contexte." }, { "type": "paragraph", "html": "C'est en quelque sorte un<strong> résumé simplifié du projet</strong> qui permet d'en piloter les grands axes. En un clin d'œil, grâce aux fiches, sans effectuer une recherche trop poussée, tous les intervenants ont une vision claire du projet." }, { "type": "paragraph", "html": "Au sein d'un projet, les fiches sont des<strong> outils d'échange et de</strong> partage consultables à n'importe quel moment avec votre équipe, que vous travaillez tous sur le même site ou à distance." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44bd5_62ea90660383f80c7a3f8b33_Project-page-feed-min.jpeg", "alt": "Piloter l'exécution projet", "caption": "Piloter l'exécution projet" }, { "type": "heading", "level": 2, "id": "qui-redige-les-fiches-de-projet", "text": "Qui rédige les fiches de projet ?" }, { "type": "paragraph", "html": "C'est souvent <strong>le chef de projet</strong> qui va s'atteler à la description du projet et proposer une <strong>première version</strong>. De nombreux formats sont possibles. Certains utilisent le programme informatique Word tout simplement." }, { "type": "paragraph", "html": "Selon le contexte, un programme comme Microsoft Word permet de rédiger des fiches de projets de manière simple en suivant un modèle prédéfini. Mais attention, cet outil a ses limites. En effet, une fiche projet rédigé sur <strong>Word</strong> à <strong>l'inconvénient</strong> de ne <strong>pas pouvoir être mise à jour de manière collaborative</strong>." }, { "type": "paragraph", "html": "Dans tous les cas, le chef de projet aura besoin du soutien des autres parties prenantes pour bien rédiger sa fiche, et ne passer trop de temps en phase de recherche." }, { "type": "heading", "level": 4, "id": "voici-un-exemple-de-fiche-de-description-projet", "text": "Voici un exemple de fiche de description projet :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c0b_62f3836213ce5e009d3f6ac1_6269623ae08e86cf3348f06b_setup.jpeg", "alt": "Modèle de rapport flash", "caption": "Modèle de rapport flash" }, { "type": "heading", "level": 3, "id": "les-inconvenients-dune-fiche-descriptive-de-projet-statique", "text": "Les inconvénients d'une fiche descriptive de projet statique" }, { "type": "paragraph", "html": "Attention, car en utilisant Word pour vos fiches projet, vous aurez également tendance à utiliser toujours le même modèle de document, alors que chacun le sait <strong>chaque projet est différent</strong> : dans son déroulement, son objectif global ou dans les actions à mener au jour le jour. Dans la pratique, une fois votre fiche projet rédigée et envoyée, une seule version sera disponible et il sera difficile d'y faire un ajout ou de préciser certains points dans la mesure où le document n'est pas disponible en ligne." }, { "type": "heading", "level": 3, "id": "dautres-modeles-de-fiche-existent", "text": "D'autres modèles de fiche existent" }, { "type": "paragraph", "html": "Des outils de gestion de projet proposent <strong>d'autres façons de rédiger des fiches projets</strong>. En allant directement <strong>chercher l'information dans votre système IT</strong> ou vos outils de reporting, la rédaction de vos fiches est facilitée et vous pouvez choisir entre différentes versions." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c27_62f370f834986741dc2e6b30_Project-metrics.jpeg", "alt": "Fiche cadrage projet", "caption": "Fiche cadrage projet" }, { "type": "heading", "level": 3, "id": "plusieurs-fiches-en-fonction-des-projets", "text": "Plusieurs fiches en fonction des projets" }, { "type": "paragraph", "html": "<strong>Tous les projets sont différents </strong>et la fiche doit <strong>s'adapter au contexte</strong> aussi bien qu'aux enjeux. Par conséquent la description de chaque projet est unique. Il est donc souhaitable de <strong>disposer de plusieurs modèles </strong>de fiche projet. Bien sûr ces différentes versions pourront être <strong>réutilisées par la suite pour gagner du temps</strong> sur un prochain projet." }, { "type": "paragraph", "html": "Les types de fiche projet les plus courants sont les suivantes :" }, { "type": "list", "ordered": false, "items": ["<strong>Pré-projet</strong>. Avant de valider un projet, il est parfois nécessaire de <strong>demander des validations en interne</strong>. Une fiche de pré-projet est parfois nécessaire.", "<strong>Projet interne</strong> : cette fiche est souvent plus concise que pour un projet classique parce qu'elle <strong>s'adresse à des interlocuteurs qui sont des collègues.</strong> Ils sont déjà au courant du projet et la fiche doit aller droit au but."] }, { "type": "list", "ordered": false, "items": ["<strong>Multi-projets</strong>. Il arrive que certains projets fassent partie d'une <strong>stratégie globale de déploiement</strong>. C'est souvent le cas dans les projets de développement de produits numériques. Une seule et même fiche peut donc <strong>regrouper plusieurs fiches</strong>. On utilisera le même genre de modèle que pour un projet classique."] }, { "type": "list", "ordered": false, "items": ["<strong>Micro-projet</strong> : Parfois, un projet n'implique que très peu de personnes et ne demande pas une gestion compliquée ni la mobilisation de ressources conséquentes. Un <strong>document très succinct</strong> peut alors suffire."] }, { "type": "inline-cta", "label": "Télécharger ⇣", "href": "https://hubs.ly/Q02NlZ8Q0" }, { "type": "heading", "level": 2, "id": "quest-ce-quune-fiche-projet-reussie", "text": "Qu'est-ce qu'une fiche projet réussie ?" }, { "type": "paragraph", "html": "La fiche projet <strong>conditionne le futur du projet et ses bons résultats</strong>. Il n'y a pas de recette miracle mais plusieurs actions sont à réaliser pour être certains de n'oublier aucunes tâches ni aucune étape dans votre fiche projet." }, { "type": "heading", "level": 3, "id": "un-travail-de-recherche-minutieux", "text": "Un travail de recherche minutieux" }, { "type": "paragraph", "html": "La phase de recherche est un point d'attention crucial. Tel un journaliste ou un enquêteur, le project manager doit rassembler toutes les informations liées au projet, avant de commencer à rédiger sa fiche. <strong>Mettez-vous dans la peau de quelqu'un qui prend le projet en cours de route </strong>et qui n'y connaît rien. Listez bien tous les points importants, toutes les activités et les étapes nécessaires à la réalisation du projet. Une fiche est un document pratique et en phase avec les objectifs à atteindre." }, { "type": "heading", "level": 3, "id": "se-poser-les-bonnes-questions", "text": "Se poser les bonnes questions" }, { "type": "paragraph", "html": "De quelles <strong>informations</strong> a-t-on besoin que votre <strong>fiche soit utile et permette d'interagir avec les autres parties prenantes</strong>. Pensez à toutes les questions que l'on pourrait vous poser dans les réunions. Tous les participants ne maîtrisent pas forcément votre domaine d'expertise. À vous d'être explicite en réunion." }, { "type": "heading", "level": 3, "id": "soyez-synthetique", "text": "Soyez synthétique" }, { "type": "paragraph", "html": "<strong>Obligez-vous à décrire votre projet en une phrase et une seule.</strong> Cette étape est fondamentale et démontrera votre esprit de synthèse auprès du sponsor et des autres intervenants dont vous recherchez le soutien au sein de ce projet. Votre fiche doit tenir en une page et une seule. Forcez-vous à réaliser un travail de simplification à chaque fois que cela est possible." }, { "type": "heading", "level": 3, "id": "noubliez-personne-dans-votre-fiche", "text": "N'oubliez personne dans votre fiche" }, { "type": "paragraph", "html": "C'est l'<strong>erreur classique</strong>. Les fiches doivent <strong>absolument faire référence à tous les acteurs impliqués</strong>. Vous avez besoin du soutien de tout le monde et votre fiche doit impliquer tout le monde. Faites également figurer les coordonnées de chaque acteur, client ou prestataire pour les joindre plus facilement." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44bf4_62f37cc85606d84d53b0f203_People-involve-min.jpeg", "alt": "Photo De Personnes S'appuyant Sur Une Table En Bois", "caption": "Mettez en valeur les personnes impliquées dans le projet" }, { "type": "heading", "level": 3, "id": "faites-figurer-les-informations-cles-selon-un-plan-defini", "text": "Faites figurer les informations clés selon un plan défini" }, { "type": "paragraph", "html": "Quels sont les objectifs ? Combien ça coûte ? Quels sont les délais ? (quelle est la date de livraison) Quels sont les risques ? Quels sont les points d'attention et quelle action est à mener en priorité ? <strong>Ne répondez pas à ces questions à la légère</strong>. S'il vous manque des informations, contactez le service concerné en amont et <strong>vérifiez vos hypothèses</strong>. Lorsque vous aurez réuni tous les éléments, alors vous pourrez commencer votre travail." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c1c_62f3840e50d801373d5a7fbd_6269623ae08e8662ea48f0a0_Pinned-messages.jpeg", "alt": "Points projets", "caption": "Les points clefs du projets" }, { "type": "heading", "level": 3, "id": "soyez-realiste-dans-la-redaction-de-votre-fiche", "text": "Soyez réaliste dans la rédaction de votre fiche" }, { "type": "paragraph", "html": "Une fiche doit être au service du projet, lui apporter une notion de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/cadrage-projet\" target=\"_blank\">cadrage</a>, en <strong>décrire les étapes clé mais sans enjoliver la situation.</strong> En promettant trop en rédigeant votre fiche projet, vous risquez de mettre certaines personnes en porte à faux et ce ne serait pas leur rendre service. Au bout du compte, en tant que leader sur ce projet, vous avez un <strong>devoir de transparence </strong>vis-à-vis des membres de l'équipe et des prestataires <strong>lors de la conception des fiches.</strong>" }, { "type": "heading", "level": 2, "id": "comment-bien-presenter-votre-projet", "text": "Comment bien présenter votre projet ?" }, { "type": "paragraph", "html": "La fiche projet n'est que l<strong>a première étape du projet</strong>. Vous avez à présent toutes les cartes en main pour présenter votre projet et le rendre explicite pour le reste des parties-prenantes." }, { "type": "heading", "level": 3, "id": "ne-pas-sisoler", "text": "Ne pas s'isoler" }, { "type": "paragraph", "html": "C'est une mission qui a l'air simple en apparence mais en réalité peut s'avérer délicate. Vous êtes parfois pris dans un jeu politique qui nuit au projet.<strong> Ne vous isolez pas dans une posture dirigiste</strong> qui peut paraître confortable au début." }, { "type": "heading", "level": 3, "id": "communiquer-anticiper", "text": "Communiquer, anticiper" }, { "type": "paragraph", "html": "Au contraire, le <strong>bon chef de projet est un communicant </strong>et il sait aussi anticiper. Grâce à des échanges fréquents, il se forge une perception toujours plus fine du projet dans toutes ses dimensions afin de l'intégrer du mieux possible. Percevoir les <strong>impacts du projet sur les plans organisationnels, technologiques et culturels </strong>est une des règles du succès." }, { "type": "heading", "level": 3, "id": "vendre-son-projet-avant-tout", "text": "Vendre son projet avant tout !" }, { "type": "paragraph", "html": "Un bon <strong>projet</strong> doit quand même <strong>se vendre, même en interne</strong>. Le bon <strong>chef de projet </strong>est aussi un \"<strong>expert en marketing</strong>\". Bien sûr il faut prendre soin d'étudier avec les responsables concernés leur vision propre du projet. Mais il s'agit aussi de <strong>présenter</strong> les enjeux <strong>sous leurs plus beaux atours</strong>. C'est le seul moyen d'établir les alliances nécessaires à la réussite. Sur ce point, lisez l'article sur comment réussir <a href=\"/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">un plan de communication projet.</a>" }, { "type": "inline-cta", "label": "Télécharger ⇣", "href": "https://hubs.ly/Q02NlZ8Q0" }], "toc": [{ "label": "Qu'est-ce qu'une fiche de projet ou plan projet ?", "href": "#quest-ce-quune-fiche-de-projet-ou-plan-projet", "level": 2 }, { "label": "Qui rédige les fiches de projet ?", "href": "#qui-redige-les-fiches-de-projet", "level": 2 }, { "label": "Qu'est-ce qu'une fiche projet réussie ?", "href": "#quest-ce-quune-fiche-projet-reussie", "level": 2 }, { "label": "Comment bien présenter votre projet ?", "href": "#comment-bien-presenter-votre-projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "gestion-de-portefeuille-projet-pme", "skip": false, "meta": { "title": "Pourquoi développer une gestion de portefeuille projets dans une PME ?", "h1": "Pourquoi développer une gestion de portefeuille projets dans une PME ?", "description": "Les PME ont les mêmes attentes au niveau de la transformation numérique que les ETI et grands groupes. Découvrez pourquoi la gestion de portefeuille projets n'est pas réservée aux grandes entreprises.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6336a8d7e6b26823ad7b3746_PPM-PME-AirSaas-min.jpg", "alt": "Gestion de Projets" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "30/9/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "30/9/2022" }, "blocks": [{ "type": "paragraph", "text": "Les PME ont les mêmes attentes au niveau de la transformation numérique que les ETI et grands groupes, à la différence près que leurs ressources et budgets sont moindres, et que les compétences en interne sont parfois moins identifiées ou dédiées.&nbsp;" }, { "type": "paragraph", "text": "L'accélération digitale est là, et il est aujourd'hui vital de s'outiller pour piloter et surfer sur cette vague avec autre chose qu'un tableur Excel et une présentation PowerPoint !" }, { "type": "paragraph", "text": "Une démarche de standardisation du pilotage projet, assistée par une plateforme peut se révéler judicieuse." }, { "type": "paragraph", "text": "<a href=\"https://www.oberlo.fr/blog/petites-entreprises-en-france\" target=\"_blank\">D'après l'INSEE</a>, en 2022 les PME représentaient 3,8 % des entreprises en France, soit environ 144 400 PME en tout. Les grandes entreprises et entreprises de taille intermédiaire ne constituant que 0,2 % des entreprises en France, soit 7 600 entreprises au total." }, { "type": "paragraph", "text": "Les PME constituent bien le <strong>cœur du tissu économique</strong> Français." }, { "type": "paragraph", "text": "Et bonne nouvelle : <strong>la gestion de portefeuille de projets n'est pas réservée aux ETI et grands comptes !</strong>" }, { "type": "heading", "level": 2, "id": "gestion-de-portefeuille-de-projets-definition-et-usages", "text": "Gestion de portefeuille de projets : définition et usages" }, { "type": "paragraph", "text": "Le portfolio management, que l'on retrouve aussi sous les dénominations « <a href=\"https://www.airsaas.io/fr/gestion-de-projet/project-portfolio-management\" target=\"_blank\">Project Portfolio Management</a> » ou « gestion de portefeuille de projets est défini par Wikipédia comme \"<em>la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage</em>\"." }, { "type": "paragraph", "text": "Alors que la gestion de projet s'attache à « bien faire les projets » - domaine de l'opérationnel -, la gestion de portefeuille de projets vise à « <strong>faire les bons projets</strong> » - domaine du décisionnel." }, { "type": "quote", "text": "Il faut revenir aux fondamentaux : il faut se questionner sur le business, sur les contraintes métiers, où est-ce qu'il est nécessaire d'avoir de la souplesse, etc. Pour réussir à bien lister l'ensemble des attentes, et classifier ces attentes, les prioriser, afin d'y voir clair.", "author": "Laurent Béliot — DSI en temps partagé - episode 24 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "La <strong>couverture fonctionnelle des plateformes logicielles</strong> associées aux pratiques de portefeuilles de projets est plus ou moins large selon les éditeurs, elle peut inclure :" }, { "type": "list", "ordered": false, "items": ["La gestion du <strong>temps</strong>", "La gestion des <strong>ressources</strong>", "La gestion de <strong>projet</strong>", "La gestion <strong>budgétaire</strong>", "La gestion des <strong>décisions</strong>", "La gestion du <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\"><strong>reporting</strong></a> unifié", "La gestion du <strong>portefeuille de projets</strong>", "La gestion des <strong>demandes entrantes</strong>", "La gestion de la <strong>collaboration</strong>"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdc3b9c48984919821f939_63369b34e6da8e7c4a685496_PPM-Airsaas-min.jpeg", "alt": "couverture fonctionnelle type des outils PPM", "caption": "Couverture fonctionnelle / produits des solutions de gestion de portefeuille projet" }, { "type": "paragraph", "text": "A l'image des ERP des années 2000/2010, certaines solutions sont très, voire trop larges... Même si les promesses du \"tout en 1\" sont tentantes. Attention à l'adoption et à la conduite du changement dans votre déploiement. La multiplication des fonctionnalités, la densité du menu du logiciel, est paradoxalement un signe de futurs problèmes <strong></strong>dans leur utilisation en entreprise." }, { "type": "paragraph", "text": "Dans les lignes qui suivent, on vous en dit plus sur le contenu et on partage <strong>une stratégie pragmatique pour implémenter une solution de gestion de portefeuille de projets efficacement dans votre PME</strong>." }, { "type": "heading", "level": 2, "id": "gestion-dun-portefeuille-de-projet-dans-une-pme-quels-benefices-et-pour-qui", "text": "Gestion d'un portefeuille de projet dans une PME : quels bénéfices, et pour qui ?" }, { "type": "paragraph", "text": "<strong>Combler le gap entre vision et exécution</strong>. Et suivre toutes vos initiatives au même endroit C'est la promesse des démarches et outils de gestion du portefeuille de projets !" }, { "type": "quote", "text": "Quand on est dans une PME, on est à mi-chemin entre le besoin d'opérationnel et le besoin de stratégie. Il faut être capable de faire le grand écart quotidiennement.", "author": "Pierre Raschi — Directeur général - Référence DSI - Episode 8 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "Avec une plateforme comme AirSaas au sein de votre entreprise vous pourrez bénéficier de cinq avantages clés :" }, { "type": "list", "ordered": true, "items": ["<a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-faire-un-bon-cadrage-projet-avec-les-metiers\" target=\"_blank\"><strong>Cadrages projets</strong></a><strong> collaboratifs</strong> et uniformes", "<strong>Reportings</strong> décisionnels <strong>automatiques</strong>", "<strong>Focalisation</strong> sur la <strong>prise de décision</strong>, les points d'attentions", "<strong>Pilotage</strong> par les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\"><strong>jalons</strong></a>", "<a href=\"https://www.airsaas.io/gestion-de-projet/comment-animer-un-bilan-projet-efficace\" target=\"_blank\"><strong>Bilan projet</strong></a> dans une seule plateforme."] }, { "type": "paragraph", "text": "L'accélération de la transition digitale a en effet pour conséquence une <strong>augmentation du flux d'initiatives et projets</strong>." }, { "type": "paragraph", "text": "Suivre vos \"chantiers\" et le management de projet avec un tableur Excel n'est plus une option !" }, { "type": "paragraph", "text": "Pour suivre vos investissements, vos objectifs stratégiques, une gestion de portefeuilles de projets moderne peut vous aider à définir un périmètre clair d'initiatives ET d'exécution." }, { "type": "quote", "text": "Si on ne fait pas cet exercice de priorisation en fonction du payback, on peut se retrouver à dépenser pas mal d'argent en transformation digitale pour des projets qui ont un impact business faible sur l'entreprise. L'idée, c'est d'avoir une remontée des projets par direction et ensuite les prioriser en fonction du payback que ça peut représenter pour l'entreprise.", "author": "Alexis de Nervaux — CIO & CDO - episode 48 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "Les objectifs sont bien de <strong>concentrer et prioriser les efforts</strong> ! On risque sinon de verser, non pas dans l'agilité des processus, mais dans l'agitation et la non-priorisation." }, { "type": "paragraph", "text": "Les outils modernes de Portfolio Project Management sont donc situés à la fois au niveau stratégique et opérationnel dans votre organisation." }, { "type": "paragraph", "text": "C'est précisément sur ces deux axes que la mise en place d'un outil de gestion du portefeuille projets vous apportera de la valeur ajoutée <strong></strong>et des bénéfices, directs et indirects :" }, { "type": "list", "ordered": false, "items": ["<strong>Plus de transparence</strong> dans le fonctionnement", "<strong>Un cadre clair</strong> et unique pour suivre l'avancement des initiatives", "<strong>Une capitalisation sur les projets menés</strong>, de leur cadrage à leur exécution, jusqu'au bilan projet", "Un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/la-methode-kanban-pour-optimiser-votre-suivi-de-projet\" target=\"_blank\"><strong>Kanban</strong></a><strong> des décisions</strong> à prendre contribuant à une nouvelle efficience de votre gouvernance de la transformation de votre organisation", "<strong>La diffusion d'une culture projet forte</strong>, sans effort, dans toute l'entreprise", "Enfin, <strong>plus de plaisir dans l'utilisation</strong> : finissez-en aujourd'hui avec votre Excel à 1200 colonnes !"] }, { "type": "paragraph", "text": "C'est peut-être pour vous, managers et dirigeants de PME, que le pragmatisme est le plus important <strong></strong>! Inutile de lire un des énièmes livres blancs : lancez-vous." }, { "type": "heading", "level": 2, "id": "la-demarche-portefeuille-projets-dans-les-pme-un-levier-dengagement-et-de-business", "text": "La démarche portefeuille projets dans les PME : un levier d'engagement et de business" }, { "type": "paragraph", "text": "Le premier facteur d'échec évoqué pour les projets transverses qui n'apportent pas les résultats escomptés est le manque d'alignement et de communication entre l'IT, les métiers et le Codir." }, { "type": "insight-callout", "label": "À retenir", "html": "Pour le dire en deux mots : <strong>sans transparence, pas d'engagement.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66cdc3b9c48984919821f944_63369dd475a0b2e1ed0c9e56_silos-entreprise-airsaas.jpeg", "alt": "Silos en entreprise", "caption": "Ensemble de silos organisationnels, le nombre n'est pas représentatif :)" }, { "type": "paragraph", "text": "C'est de ce constat et par la volonté d<strong>e</strong> vouloir aider les ETI et PME à réussir à travailler en \"cross silos\" horizontaux (DSI - métiers), mais aussi en \"cross silos\" verticaux (chef de projets - PMO - direction), qu'AirSaas s'est développé." }, { "type": "quote", "text": "Un point indispensable dans la transfo, c'est la communication. On ne communique jamais assez. En tout cas de façon assez ciblée et efficace. La transformation c'est quelque chose qui peut faire peur aux personnes. Si on ne communique pas, les projets peuvent être perçus comme un risque : \"Ouhlala, on va remplacer mon job\". C'est clé dans la réussite et l'adoption des changements. Quand on communique en continu sur des sujets, chacun a le loisir de réagir. Cela instaure un dialogue qui est très sain pour la réussite de changements structurants comme ceux qu'on est en train de faire.", "author": "Alexia Schmitt — CIO - Episode 22 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "Vous avez une stratégie d'entreprise ? C'est tout ce dont vous avez besoin pour commencer avec AirSaas !" }, { "type": "paragraph", "text": "Trois axes de travail seront alors à adresser pour amener un fonctionnement plus coopératif de votre gestions de projets. Qui génère de la performance versus un fonctionnement type \"sur contrôle\" pour éviter la dérive des activités." }, { "type": "heading", "level": 3, "id": "renforcer-le-sens-la-vision", "text": "Renforcer le sens, la vision" }, { "type": "paragraph", "text": "Ayez un bon storytelling des programmes de transformation / axes stratégiques. Par exemple : \"le programme d'excellence commerciale 2022 (projet CRM, projet analyse comportementale, projet analyse prédictive, projet site web...) doit nous amener à rentrer dans le top 3 européen\". Sinon; au bout de quelques mois, les projets n'auront plus de sens, et le manque de motivation des équipes peut vite se faire ressentir." }, { "type": "heading", "level": 3, "id": "redefinir-les-roles-et-redevabilites-des-ressources-humaines", "text": "Redéfinir les rôles et redevabilités des ressources humaines" }, { "type": "paragraph", "text": "C'est quoi un sponsor ? Un chef de projet ? Un référent métier ? Quels sont les droits et devoirs de chacun dans la gestion de projets ? Sans règle du jeu, personne ne sera responsable de rien." }, { "type": "heading", "level": 3, "id": "faire-evoluer-les-rituels-et-la-communication-sur-le-suivi-de-projet", "text": "Faire évoluer les rituels et la communication sur le suivi de projet" }, { "type": "paragraph", "text": "Par exemple :" }, { "type": "list", "ordered": false, "items": ["Tous les mardis, réunion chef de projet + référent métier de 5 minutes par projet : décisions à prendre, points d'attention", "Tous les vendredis, envoi du <a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">rapport flash</a> à l'ensemble des parties-prenantes", "Tous les mois, Copil sur les enjeux du mois prochain, et alignement sur le temps métiers disponible"] }, { "type": "paragraph", "text": "Avec cette démarche stratégique et un logiciel de gestion de portefeuille projet moderne, vous serez plus à même d'évaluer les projets qui contribuent à votre stratégie ET qui permettent d'obtenir les objectifs et résultats visés de façon engageante et coopérative." }, { "type": "heading", "level": 2, "id": "la-digitalisation-de-la-demarche-de-portefeuille-de-projets-de-pme-pour-innover-malgre-des-ressources-limitees", "text": "La digitalisation de la démarche de portefeuille de projets de PME pour innover malgré des ressources limitées" }, { "type": "paragraph", "text": "La gestion de portefeuille de projets : une démarche réservée aux grandes entreprises ? Certainement pas ! Au contraire, les PME peuvent parfois mieux tirer leur épingle du jeu. Pourquoi ? Parce qu'elles ont intrinsèquement plus d'agilité et parfois, disons-le, de motivation, qu'au sein d'une ETI ou d'un grand groupe." }, { "type": "paragraph", "text": "Oui : le <strong>cycle de décision d'une PME</strong> est, en général, différent d'une ETI ou d'un grand groupe. La plupart des silos organisationnels ne sont pas encore \"enkystés\"." }, { "type": "quote", "text": "Le premier conseil que je pourrais donner à un dirigeant de PME, c'est d'identifier ses axes de valeurs. Comment peut-on créer de la valeur grâce au digital ?", "author": "Pierre Raschi — Directeur Général - Référence DSI - Episode 8 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "Vous n'avez pas de ressources ou de compétences disponibles pour travailler sur la transformation ? Tant mieux. On peut tout à fait créer une culture projet forte en s'appuyant sur des outils et une démarche. Les plateformes constitueront une assistance précieuse au pilotage." }, { "type": "paragraph", "text": "Le parallèle avec le vélo à assistance électrique est tout indiqué ! Oui : même dans un environnement contraint par le manque de temps et ressources, ajouter un moteur à votre pilotage projet est possible." }, { "type": "paragraph", "text": "En complément de votre \"outillage\", le pilotage demeure un enjeu majeur. Une autre piste possible sera de recourir a un PMO/CDIO/DSI en temps partagé." }, { "type": "quote", "text": "Les PME ont deux choix. Elles peuvent recruter un DSI costaud, taillé pour le poste mais qui va s'ennuyer car il n'y a pas assez de projets à piloter. Le second, c'est de faire appel à un responsable informatique, plus jeune, que l'on va faire grandir avec la société, mais lorsqu'ils deviennent DSI, ils sont beaucoup trop dans l'opérationnel. Notre objectif, c'est de proposer un troisième choix, d'accompagner ces DSI, pendant un ou deux jours par semaine.", "author": "Pierre Raschi — Directeur Général - Référence DSI - Episode 8 Podcast CIO Révolution by AirSaas" }, { "type": "heading", "level": 2, "id": "conclusions-and-recommandations", "text": "Conclusions & recommandations" }, { "type": "heading", "level": 3, "id": "pme-10-criteres-cles-pour-choisir-votre-outil-ppm", "text": "PME : 10 critères clés pour choisir votre outil PPM" }, { "type": "heading", "level": 4, "id": "1-le-design-de-linterface", "text": "1. Le design de l'interface" }, { "type": "paragraph", "text": "Pour une vraie adoption <strong></strong>par les utilisateurs au quotidien, c'est le critère numéro 1 ! Optez pour une <strong>solution \"light\"</strong> <strong>versus</strong> le progiciel \"tout en 1\" type ERP projet \"obèse\"." }, { "type": "heading", "level": 4, "id": "2-les-fonctionnalites-cles-innovantes", "text": "2. Les fonctionnalités clés innovantes" }, { "type": "paragraph", "text": "Si votre besoin est de commencer rapidement, fuyez aujourd'hui les solutions aux couvertures fonctionnelles trop larges. Visez le \"B.A-BA\" du PPM et des automatisations-clés. Avec, par exemple, la fonction de reporting en un clic et standardisé." }, { "type": "heading", "level": 4, "id": "3-la-dimension-collaborative-de-la-solution", "text": "3. La dimension collaborative de la solution" }, { "type": "paragraph", "text": "Au cours du cycle de vie du projet, <strong></strong>comment sont pensées les interactions entre les acteurs transverses ? Les logiciels qui sortent du lot incluent en particulier le renforcement du collaboratif en synchrone et asynchrone." }, { "type": "heading", "level": 4, "id": "4-la-vision-la-philosophie-derriere-loutil", "text": "4. La vision, la philosophie, derrière l'outil" }, { "type": "paragraph", "text": "L'évolution des méthodes vers toujours plus d'hybride entre agilité et cycle en V nécessitera une approche souple du canevas méthodologique proposé. Aujourd'hui, tout est projet, de 3 jours à 3 ans..." }, { "type": "heading", "level": 4, "id": "5-louverture-de-la-solution", "text": "5. L'ouverture de la solution" }, { "type": "paragraph", "text": "Ne perdez plus de temps en re-saisie de données. Les PPM modernes sont conçus comme de véritables \"hubs\" permettant à un ensemble d'applications déjà existantes dans votre organisation de communiquer entre elles. Que ce soit avec vos outils de gestion de projet (Wrike, Jira, Asana, Trello) ou avec vos outils de communication (Teams, par exemple), Airsaas rassemble vos données projets dans un tableau de bord." }, { "type": "heading", "level": 4, "id": "6-la-conformite-rgpd-et-cloud-act", "text": "6. La conformité RGPD et Cloud Act" }, { "type": "paragraph", "text": "Ce point n'est pas anecdotique en gestion de projets. Et trop souvent oublié dans les phases d'avant-vente." }, { "type": "heading", "level": 4, "id": "7-la-capacite-de-reversibilite", "text": "7. La capacité de réversibilité" }, { "type": "paragraph", "text": "Elle peut être coûteuse, voire impossible. Ce point n'est pas anecdotique, et trop souvent oublié également. Notre conseil : interrogez les éditeurs sur leurs pratiques et faites un test de \"rollback\" (export de données) avant de signer le contrat." }, { "type": "heading", "level": 4, "id": "8-la-securite", "text": "8. La sécurité" }, { "type": "paragraph", "text": "Un check par votre RSSI peut permettre de vous assurer que tout est ok pour identifier et protéger l'accès à des données stratégiques. Chiffrez si possible les données pour vous apporter un peu plus de sérénité." }, { "type": "heading", "level": 4, "id": "9-le-prix-de-tous-les-types-de-licences-et-du-set-up-pack", "text": "9. Le prix de tous les types de licences et du set up pack" }, { "type": "paragraph", "text": "Pas seulement le prix facial des licences utilisateurs actifs, mais également le prix des licences pour les profils secondaires, type ambassadeurs métiers." }, { "type": "heading", "level": 4, "id": "10-lediteur-et-la-communaute-dutilisateurs", "text": "10. L'éditeur et la communauté d'utilisateurs" }, { "type": "paragraph", "text": "Last but not least des 10 critères : les hommes derrière l'outil. <strong></strong>Quel support, quels conseils et quelles relations l'éditeur vous propose-t-il avant, pendant et après la vente ? Propose-t-il une communauté d'utilisateurs ? Quelle vision du marché porte-t-il ? Quelle communication fournit-il sur sa roadmap ?" }, { "type": "heading", "level": 3, "id": "ppm-les-prerequis-et-astuces-pour-se-lancer-dans-une-pme", "text": "PPM : Les prérequis et astuces pour se lancer dans une PME" }, { "type": "list", "ordered": false, "items": ["<strong>Identifiez et sélectionnez quelques plateformes</strong> PPM, pas seulement via les plateformes type Capterra : elles ont des angles morts. Demandez à votre réseau aussi !", "<strong>Shortlistez</strong> 2 à 3 outils,", "<strong>Contactez les éditeurs</strong> pour un RFI (Request for Information)", "<strong>Etablissez vos critères prioritaires</strong> parmi ceux proposés et votre contexte organisationnel", "<strong>Demandez aux éditeurs des contacts intégrateurs internes ou externes</strong> : évitez autant que possible d'y aller seul sans accompagnement par un facilitateur général.", "<strong>Créez un groupe pilote composé de chef de projets</strong> / <strong>métiers / sponsor</strong> avec qui cela se passe déjà bien, et qui ont envie de changer de <a href=\"https://www.airsaas.io/gestion-de-projet/comment-mettre-une-demarche-de-projet-dans-mon-entreprise\" target=\"_blank\">démarche projet</a>.", "Privilégiez sur ce type de mise en œuvre démarche progressive pour commencer, avec une tactique d'implémentation positive, sur un petit nombre de projets pour faire \"tache d'huile\" sur une future utilisation générale.", "Fixez vous des limites ! Réaliser une transition culturelle et de gouvernance est un challenge qui en vaut la peine... mais au bon rythme !"] }, { "type": "paragraph", "text": "Vous l'avez compris : le développement <strong></strong>de portefeuilles de projets en PME peut faciliter vos différentes transitions <strong></strong>digitales, environnementales et organisationnelles. Pour un meilleur alignement stratégique, plus d'efficacité... et de plaisir aussi !" }], "toc": [{ "href": "#gestion-de-portefeuille-de-projets-definition-et-usages", "label": "Gestion de portefeuille de projets : définition et usages", "level": 2 }, { "href": "#gestion-dun-portefeuille-de-projet-dans-une-pme-quels-benefices-et-pour-qui", "label": "Gestion d'un portefeuille de projet dans une PME : quels bénéfices, et pour qui ?", "level": 2 }, { "href": "#la-demarche-portefeuille-projets-dans-les-pme-un-levier-dengagement-et-de-business", "label": "La démarche portefeuille projets dans les PME : un levier d'engagement et de business", "level": 2 }, { "href": "#la-digitalisation-de-la-demarche-de-portefeuille-de-projets-de-pme-pour-innover-malgre-des-ressources-limitees", "label": "La digitalisation de la démarche de portefeuille de projets de PME pour innover malgré des ressources limitées", "level": 2 }, { "href": "#conclusions-and-recommandations", "label": "Conclusions & recommandations", "level": 2 }], "related": [{ "href": "/fr/gestion-de-projet/metier-pmo", "label": "PMO (Project Management Office) : le guide complet pour comprendre et mettre en place ce rôle clé" }, { "href": "/fr/gestion-de-projet/pi-planning", "label": "PI Planning : le guide complet pour aligner vos équipes IT et métiers" }, { "href": "/fr/gestion-de-projet/management-de-portefeuille-de-projet", "label": "Management de portefeuille de projet : définition, méthodes et outils" }], "faq": [] }, { "slug": "gestion-portefeuille-projets-vs-gestion-de-projet", "skip": false, "meta": { "title": "Management de portefeuille de projet : définition, méthodes et outils", "h1": "Management de portefeuille de projet : définition, méthodes et outils", "description": "Gestion de portefeuille de projets (PPM) : définition, méthodes de priorisation, KPIs essentiels et guide pour déployer une démarche efficace.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6995db9e00db2afd8d4d5013_Gestion%20de%20portefeuille%20de%20projets.jpg", "alt": "Gestion de portefeuille de projets" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "1/2/2026", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "1/2/2026" }, "blocks": [{ "type": "heading", "level": 2, "id": "quest-ce-que-la-gestion-de-portefeuille-de-projets", "text": "Qu'est-ce que la gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "La <strong>gestion de portefeuille de projets</strong> (GPP), aussi appelée <strong>Project Portfolio Management</strong> (PPM), est une discipline stratégique qui consiste à sélectionner, prioriser et piloter l'ensemble des projets d'une organisation pour maximiser la création de valeur." }, { "type": "paragraph", "html": "Contrairement à la gestion de projet, qui vise à \"<strong>bien faire les projets</strong>\" (domaine opérationnel), la gestion de portefeuille de projets cherche à \"<strong>faire les bons projets</strong>\" (domaine décisionnel)." }, { "type": "paragraph", "html": "Le Project Management Institute (PMI) la définit comme <em>la gestion centralisée des processus, méthodes et technologies d'un ensemble de projets, permettant d'optimiser les arbitrages et leur planification, tout en évaluant le niveau de risque et la viabilité financière des projets</em>." }, { "type": "paragraph", "html": "Concrètement, un <strong>portefeuille de projets</strong> regroupe l'ensemble des projets, programmes et opérations d'une entreprise. À l'image d'un portefeuille boursier, il s'agit de décider où investir son budget, ses ressources et son temps pour obtenir le meilleur retour sur investissement." }, { "type": "paragraph", "html": "Le PPM fonctionne comme un <strong>entonnoir stratégique</strong> : à l'entrée, un flux massif d'idées provenant de la stratégie, des clients ou de la réglementation ; à la sortie, une sélection rigoureuse d'initiatives coordonnées et exécutables. Sans ce filtre, l'organisation s'épuise à tout mener de front et condamne ses projets à des résultats médiocres." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699732d4dfc0c2f0d4d8feb0_Entonnoir%20strate%CC%81gique%20PPM%20FR.jpg", "alt": "Entonnoir stratégique de la gestion de portefeuille de projets — de l'idée à l'exécution" }, { "type": "paragraph", "html": "Ce que la gestion de portefeuille de projets permet" }, { "type": "list", "ordered": false, "items": ["Assurer l'<strong>alignement stratégique</strong> entre les projets et la vision de l'entreprise", "<strong>Prioriser</strong> les initiatives à plus forte valeur ajoutée", "<strong>Optimiser l'allocation des ressources</strong> (humaines, financières, matérielles) entre les projets", "<strong>Anticiper les risques</strong> de déséquilibre entre capacité et demande", "Offrir une <strong>visibilité consolidée</strong> aux instances de décision (Comité de pilotage, Direction Générale)", "<strong>Arrêter ou reporter</strong> les projets qui n'apportent plus de valeur"] }, { "type": "heading", "level": 3, "id": "la-capacite-par-equipe-la-contrainte-au-coeur-du-portefeuille", "text": "La capacité par équipe : la contrainte au cœur du portefeuille" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets repose sur une vérité que beaucoup d'organisations refusent de regarder en face : <strong>la capacité des équipes est finie</strong>. Et c'est cette contrainte — pas les matrices de scoring, pas les pourcentages d'avancement — qui doit structurer toutes les décisions." }, { "type": "paragraph", "html": "Concrètement, la capacité se mesure <strong>par équipe</strong> et <strong>au trimestre</strong>. C'est l'échelle du <strong>Quarter Plan</strong> : chaque équipe (infra, développement, data, sécurité…) dispose d'un nombre de jours-homme réels sur le trimestre à venir, une fois déduites les absences, la maintenance, le run et les imprévus. Cette capacité trimestrielle est le vrai budget de votre portefeuille — bien plus structurant que le budget financier." }, { "type": "table", "headers": ["", "Gestion des ressources", "Planification de la capacité"], "rows": [["Horizon", "Court terme (semaine/sprint)", "Trimestriel (Quarter Plan)"], ["Maille", "Individu par individu", "Équipe par équipe"], ["Question clé", "\"Qui travaille sur quoi cette semaine ?\"", "\"Cette équipe peut-elle absorber ce projet ce trimestre ?\""], ["Usage", "Optimiser l'affectation au quotidien", "Décider quels projets entrent dans le portefeuille — et lesquels attendent"]] }, { "type": "insight-callout", "html": "⚠️ <strong>Méfions-nous des mots creux.</strong> Les termes \"prioriser\" et \"piloter\" sont parmi les plus galvaudés du vocabulaire projet. Dire qu'un portefeuille est \"priorisé\", c'est souvent ne rien dire du tout si aucune contrainte de capacité n'a été confrontée aux engagements. De même, \"piloter\" un portefeuille via un <strong>pourcentage d'avancement</strong> est trompeur : un projet peut afficher 70 % d'avancement et être à des mois de livrer le moindre délivrable exploitable. Le pourcentage d'avancement mesure la consommation de charge, rarement la proximité d'un résultat tangible. La vraie question n'est jamais \"où en est-on ?\", mais <strong>\"qu'est-ce qu'on va livrer ce trimestre, et est-ce que l'équipe a la bande passante pour le faire ?\"</strong>", "label": "Attention" }, { "type": "paragraph", "html": "La planification de la capacité est le garde-fou stratégique de votre portefeuille : sans elle, vous validez des projets que vos équipes ne pourront jamais absorber." }, { "type": "insight-callout", "html": "💡 <strong>Le saviez-vous ?</strong> Selon une étude du PMI, 70 % des projets ont tendance à échouer. La première cause ? Un changement dans les priorisations de l'entreprise (39 %), suivi d'une modification des objectifs du projet (37 %). La gestion de portefeuille de projets existe précisément pour anticiper et piloter ces arbitrages plutôt que de les subir.", "label": "Le saviez-vous" }, { "type": "heading", "level": 2, "id": "portefeuille-de-projets-vs-programme-vs-projet-quelles-differences", "text": "Portefeuille de projets vs programme vs projet : quelles différences ?" }, { "type": "paragraph", "html": "La confusion entre ces trois concepts est fréquente. Voici ce qui les distingue." }, { "type": "heading", "level": 3, "id": "le-projet", "text": "Le projet" }, { "type": "paragraph", "html": "Un <strong>projet</strong> est une initiative temporaire visant à produire un livrable unique. Il a un début, une fin, un budget et des objectifs SMART (Spécifiques, Mesurables, Atteignables, Réalistes, Temporels). La gestion de projet se concentre sur la livraison réussie de cette initiative." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> Déployer un nouvel outil CRM pour l'équipe commerciale." }, { "type": "heading", "level": 3, "id": "le-programme", "text": "Le programme" }, { "type": "paragraph", "html": "Un <strong>programme</strong> est un ensemble de projets interdépendants qui partagent des objectifs communs. Les projets au sein d'un programme sont liés : ils contribuent collectivement à un résultat stratégique." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> Le programme \"Transformation digitale de la relation client\" qui regroupe le projet CRM, le projet refonte du site web et le projet mise en place d'un chatbot." }, { "type": "heading", "level": 3, "id": "le-portefeuille-de-projets", "text": "Le portefeuille de projets" }, { "type": "paragraph", "html": "Un <strong>portefeuille de projets</strong> n'est pas un niveau hiérarchique au-dessus du programme. C'est une <strong>lentille</strong> — une façon de regarder un groupement de projets sous un angle donné, pour prendre des décisions adaptées à ce périmètre." }, { "type": "paragraph", "html": "En pratique, une même organisation manipule plusieurs portefeuilles simultanément : le portefeuille de l'<strong>équipe IT infrastructure</strong>, celui de l'<strong>équipe applicative métier</strong>, le portefeuille des <strong>projets vitaux</strong>, celui des projets de <strong>conformité réglementaire</strong>, ou encore le portefeuille global vu par la Direction Générale. Chaque vue répond à une question différente : \"Mon équipe est-elle en surcharge ?\", \"Nos projets vitaux avancent-ils ?\", \"Sommes-nous alignés avec la stratégie ?\"." }, { "type": "paragraph", "html": "C'est ce qui rend la gestion de portefeuille de projets si puissante : elle n'impose pas un cadre unique, mais offre la possibilité de <strong>filtrer, regrouper et comparer les projets</strong> selon les besoins de chaque partie prenante — équipe, direction métier, DSI ou Comité de direction." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> La DSI pilote un portefeuille global, mais chaque équipe (infra, dev, data) dispose de sa propre vue portefeuille avec ses contraintes de capacité. Le Comité de direction, lui, regarde le portefeuille par axe stratégique." }, { "type": "heading", "level": 3, "id": "tableau-comparatif", "text": "Tableau comparatif" }, { "type": "table", "headers": ["Critère", "Projet", "Programme", "Portefeuille"], "rows": [["Nature", "Une initiative temporaire avec un livrable", "Un ensemble de projets liés par un objectif commun", "Une vue sur un groupement de projets, filtrée par équipe, thématique ou axe stratégique"], ["Objectif", "Livrer un résultat concret dans les délais", "Atteindre un bénéfice stratégique commun", "Décider quoi faire, quoi arrêter, quoi reporter — en fonction de la capacité réelle"], ["Niveau de décision", "Opérationnel", "Tactique", "Stratégique"], ["Contrainte centrale", "Le triangle coût/délai/périmètre", "La coordination entre projets interdépendants", "La capacité des équipes — le nombre de projets sera toujours supérieur à ce qu'on peut absorber"], ["Pilote", "Chef de projet", "Directeur de programme", "PMO / DSI / Direction Générale"], ["Question clé", "\"Le livrable sera-t-il prêt ?\"", "\"Les projets produisent-ils le bénéfice attendu ?\"", "\"Les bonnes équipes travaillent-elles sur les bons sujets, au bon moment ?\""]] }, { "type": "insight-callout", "html": "📌 <strong>À retenir :</strong> Le portefeuille n'est pas \"au-dessus\" du projet et du programme dans une pyramide. C'est une <strong>grille de lecture</strong> qui permet de comparer, arbitrer et allouer les ressources entre des projets qui se disputent la même capacité. Il peut exister autant de vues portefeuille que de besoins de décision dans l'organisation.", "label": "À retenir" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699733200e76e85e0aaa049e_Le%20portefeuille%20comme%20lentille%20%E2%80%94%20vues%20multiples%20FR.jpg", "alt": "Le portefeuille de projets comme lentille — vues multiples par équipe, stratégie et priorité" }, { "type": "heading", "level": 2, "id": "pourquoi-mettre-en-place-une-gestion-de-portefeuille-de-projets", "text": "Pourquoi mettre en place une gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "Dans la plupart des entreprises, le nombre de projets dépasse largement la capacité à les réaliser. C'est une loi universelle de la transformation : la demande sera toujours supérieure à l'offre de ressources disponibles." }, { "type": "paragraph", "html": "Les chiffres le confirment : selon l'IBM Institute for Business Value, les organisations leaders en gestion de portefeuille de projets affichent une <strong>performance de revenus 46 % plus prévisible</strong> que leurs concurrentes moins matures. L'excellence en PPM n'est pas un luxe organisationnel — c'est un avantage concurrentiel mesurable." }, { "type": "paragraph", "html": "Sans gestion de portefeuille de projets, les organisations subissent un phénomène bien connu : <strong>l'urgence chasse l'urgence</strong>. Les équipes fonctionnent en \"best effort\", les arbitrages se font au fil de l'eau (ou au \"fait du prince\"), et personne n'a de visibilité sur ce qui est réellement prioritaire." }, { "type": "heading", "level": 3, "id": "les-6-benefices-concrets-dune-demarche-de-gestion-de-portefeuille-de-projets", "text": "Les 6 bénéfices concrets d'une démarche de gestion de portefeuille de projets" }, { "type": "paragraph", "html": "<strong>1. Alignement stratégique</strong>" }, { "type": "paragraph", "html": "La GPP garantit que chaque projet contribue à la stratégie de l'entreprise. Fini les projets \"orphelins\" qui consomment des ressources sans créer de valeur mesurable. Chaque euro investi est tracé jusqu'à un objectif stratégique. Une vérité trop souvent ignorée : <strong>succès technique ≠ succès business</strong>. Une exécution parfaite d'un projet sans alignement stratégique reste un gaspillage de ressources." }, { "type": "paragraph", "html": "<strong>2. Priorisation objective et transparente</strong>" }, { "type": "paragraph", "html": "En rendant visible la règle du jeu et l'ensemble des sujets en revue de portefeuille, la démarche instaure une relation de confiance et de transparence entre la DSI, les métiers et la direction générale. Les décisions de priorisation sont fondées sur des <strong>données probantes</strong>, pas sur le rapport de force politique ou la voix la plus forte en comité de direction." }, { "type": "paragraph", "html": "<strong>3. Optimisation de la capacité — la vraie valeur ajoutée</strong>" }, { "type": "paragraph", "html": "C'est ici que la gestion de portefeuille de projets prend tout son sens. La capacité ne se mesure pas à l'échelle de l'organisation entière — elle se mesure <strong>équipe par équipe, trimestre par trimestre</strong>. L'approche du <strong>Quarter Plan</strong> consiste à confronter, chaque trimestre, les engagements projet à la bande passante réelle de chaque équipe. Les organisations qui maîtrisent cette planification augmentent de <strong>68 % leurs chances de livrer leurs projets à temps</strong>. Le secret : identifier les goulots sur les compétences critiques (architectes IT, experts métiers, ingénieurs spécialisés) et accepter de reporter ce qui ne rentre pas dans le trimestre. Résultat : moins de surcharge, moins de retards en cascade, des engagements crédibles." }, { "type": "paragraph", "html": "<strong>4. Gestion proactive des risques</strong>" }, { "type": "paragraph", "html": "En ayant une vue consolidée du portefeuille, les risques sont identifiés à l'échelle de l'organisation, pas uniquement projet par projet. Un risque sur un projet structurant peut impacter tout le portefeuille : la GPP permet de l'anticiper." }, { "type": "paragraph", "html": "<strong>5. Meilleure communication avec les parties prenantes</strong>" }, { "type": "paragraph", "html": "Le reporting consolidé du portefeuille (tableau de bord, rapport flash, revue de portefeuille) offre aux dirigeants les données nécessaires pour prendre des décisions éclairées, sans avoir à plonger dans le détail de chaque projet." }, { "type": "paragraph", "html": "<strong>6. Agilité décisionnelle</strong>" }, { "type": "paragraph", "html": "Les roadmaps de SI à 3-5 ans figées appartiennent au passé. Avec une GPP moderne, la priorisation se fait en continu, à un rythme adapté aux changements de contexte de l'entreprise. Les données terrain remontent en temps réel, permettant des réajustements rapides." }, { "type": "quote", "text": "🏢 <strong>Idée reçue :</strong> \"La gestion de portefeuille de projets est réservée aux grandes entreprises.\" <strong>Faux.</strong> Les PME et ETI peuvent parfois en tirer encore plus de bénéfices, car elles ont plus d'agilité et la capacité de mettre en œuvre la démarche plus rapidement. L'enjeu est d'adapter le niveau de formalisme à la taille de l'organisation." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6997336f720e4b07874d2db7_6%20be%CC%81ne%CC%81fices%20du%20PPM%20en%20chiffres%20FR.jpg", "alt": "Statistiques clés de la gestion de portefeuille de projets — IBM, PMI" }, { "type": "heading", "level": 2, "id": "les-7-etapes-pour-deployer-une-gestion-de-portefeuille-de-projets-efficace", "text": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699733e0185a65bc475aebde_Les%207%20e%CC%81tapes%20du%20de%CC%81ploiement%20PPM%20FR.jpg", "alt": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace" }, { "type": "heading", "level": 3, "id": "etape-1-definir-les-objectifs-strategiques", "text": "Étape 1 — Définir les objectifs stratégiques" }, { "type": "paragraph", "html": "Tout commence par la boussole. Sans clarté sur la stratégie, votre portefeuille ne sera qu'un inventaire de projets sans cohérence." }, { "type": "paragraph", "html": "Trois actions concrètes pour cette étape :" }, { "type": "list", "ordered": false, "items": ["Formaliser la vision à 2-3 ans avec la Direction Générale", "Identifier les axes stratégiques prioritaires (croissance, efficacité, conformité, innovation...)", "Traduire ces axes en <strong>critères de sélection mesurables</strong> pour les projets"] }, { "type": "heading", "level": 3, "id": "etape-2-recenser-et-categoriser-tous-les-projets-intake", "text": "Étape 2 — Recenser et catégoriser tous les projets (Intake)" }, { "type": "paragraph", "html": "Créez un inventaire exhaustif de toutes les initiatives en cours et à venir : projets validés, projets en attente, idées en gestation. Centralisez toutes les demandes — qu'elles soient stratégiques, réglementaires, issues des métiers ou des clients — dans un processus unique d'<strong>intake</strong> (capture). C'est le meilleur moyen d'éliminer les redondances et d'identifier les opportunités de mutualisation." }, { "type": "paragraph", "html": "Chaque projet doit être documenté avec une fiche standardisée comprenant au minimum : objectif, sponsor, budget estimé, ressources nécessaires, échéance et contribution stratégique." }, { "type": "paragraph", "html": "Catégorisez ensuite vos projets par type (transformation, run, réglementaire, innovation...) et par programme si applicable." }, { "type": "heading", "level": 3, "id": "etape-3-evaluer-et-prioriser-les-projets", "text": "Étape 3 — Évaluer et prioriser les projets" }, { "type": "paragraph", "html": "C'est le cœur de la démarche. Appliquez vos critères de sélection pour noter et classer chaque projet. Les méthodes de priorisation sont détaillées dans la section suivante, mais l'essentiel est d'avoir une approche <strong>multicritère</strong> qui combine valeur business, faisabilité, risques et alignement stratégique." }, { "type": "heading", "level": 3, "id": "etape-4-aligner-la-capacite-avec-la-demande-quarter-plan", "text": "Étape 4 — Aligner la capacité avec la demande (Quarter Plan)" }, { "type": "paragraph", "html": "C'est l'étape la plus décisive — et la plus souvent bâclée. Pour chaque <strong>équipe</strong>, évaluez sa capacité réelle sur le <strong>trimestre à venir</strong> : jours-homme disponibles, une fois déduites les absences, le run, la maintenance et la marge d'imprévu. Puis confrontez cette capacité aux engagements projet." }, { "type": "paragraph", "html": "C'est souvent le moment de vérité : ce qui semblait prioritaire peut se révéler irréaliste si l'équipe concernée est déjà saturée. L'exercice doit être concret : non pas \"a-t-on les moyens au global ?\", mais <strong>\"l'équipe Data peut-elle absorber ce projet en Q2, ou faut-il le décaler en Q3 ?\"</strong>" }, { "type": "paragraph", "html": "L'objectif n'est pas de tout planifier au jour près. C'est de s'assurer que les engagements sont crédibles. Mieux vaut 5 projets livrés ce trimestre que 15 projets \"en cours\" dont aucun ne délivre de résultat tangible. Attention au piège du pourcentage d'avancement : un projet à \"60 %\" ne signifie pas qu'il est proche de livrer quoi que ce soit d'exploitable — c'est souvent juste un ratio de charge consommée." }, { "type": "heading", "level": 3, "id": "etape-5-definir-la-gouvernance-et-les-rituels", "text": "Étape 5 — Définir la gouvernance et les rituels" }, { "type": "paragraph", "html": "Mettez en place les instances de décision et les rituels récurrents qui feront vivre votre portefeuille :" }, { "type": "list", "ordered": false, "items": ["<strong>Revue de portefeuille mensuelle</strong> : arbitrages, décisions Go/No-Go, réallocation de ressources", "<strong>Comité de pilotage</strong> : validation des orientations stratégiques et des investissements majeurs", "<strong>Reporting hebdomadaire</strong> (rapport flash) : état d'avancement consolidé envoyé aux parties prenantes", "<strong>Point projet hebdomadaire</strong> : 5 minutes par projet entre chef de projet et référent métier"] }, { "type": "paragraph", "html": "Le PMI distingue trois types de PMO (Bureau de Gestion de Projets), selon le niveau de contrôle exercé :" }, { "type": "table", "headers": ["Type de PMO", "Rôle", "Niveau de contrôle"], "rows": [["Support", "Fournit modèles, outils et bonnes pratiques", "Faible — les équipes restent autonomes"], ["Contrôle", "Exige la conformité aux méthodologies via des audits", "Modéré — cadre structurant"], ["Directif", "Gère directement les projets et affecte les chefs de projet", "Élevé — pilotage centralisé"]] }, { "type": "paragraph", "html": "Le choix du type de PMO dépend de la maturité de votre organisation et de votre culture managériale. La tendance actuelle est au PMO \"facilitateur\" (entre Support et Contrôle), qui structure sans bureaucratiser. Plus largement, le succès en 2026 exige une <strong>métamorphose du PMO</strong> : il doit évoluer d'un rôle de support administratif vers celui de <strong>partenaire stratégique</strong>. Le pilotage stratégique ne consiste pas à surveiller des calendriers, mais à garantir que chaque euro et chaque heure investis servent la croissance de l'entreprise." }, { "type": "paragraph", "html": "Sans rituels réguliers, votre portefeuille deviendra vite obsolète. C'est la fréquence et la discipline de ces rituels qui créent la valeur." }, { "type": "heading", "level": 3, "id": "etape-6-outiller-la-demarche", "text": "Étape 6 — Outiller la démarche" }, { "type": "paragraph", "html": "Suivre un portefeuille de projets dans Excel n'est plus viable au-delà de 10 projets. Un <strong>outil PPM</strong> (Project Portfolio Management) dédié permet de centraliser les informations, automatiser le reporting et offrir une visibilité en temps réel à toutes les parties prenantes." }, { "type": "paragraph", "html": "Les critères clés pour choisir votre outil PPM sont détaillés dans la section dédiée ci-dessous." }, { "type": "heading", "level": 3, "id": "etape-7-piloter-en-continu-et-ameliorer", "text": "Étape 7 — Piloter en continu et améliorer" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets n'est pas un exercice ponctuel, c'est un processus continu. À chaque revue de portefeuille, posez-vous trois questions :" }, { "type": "list", "ordered": true, "items": ["Les projets en cours sont-ils toujours alignés avec la stratégie ?", "Faut-il ajouter, reporter ou arrêter des projets ?", "La capacité est-elle toujours suffisante pour tenir les engagements ?"] }, { "type": "quote", "text": "🎯 <strong>Conseil pragmatique :</strong> Ne cherchez pas la perfection au démarrage. Commencez avec un périmètre restreint (10-15 projets clés), des rituels simples et un outil adapté. Faites \"tache d'huile\" ensuite. La maturité se construit progressivement, comme un sachet de thé qui infuse." }, { "type": "heading", "level": 2, "id": "les-methodes-de-priorisation-dun-portefeuille-de-projets", "text": "Les méthodes de priorisation d'un portefeuille de projets" }, { "type": "paragraph", "html": "La priorisation est l'exercice le plus complexe et le plus politique de la gestion de portefeuille de projets. Voici les méthodes les plus utilisées." }, { "type": "heading", "level": 3, "id": "le-scoring-multicritere", "text": "Le scoring multicritère" }, { "type": "paragraph", "html": "Chaque projet est évalué sur une grille de critères pondérés. Les critères se répartissent généralement en trois familles :" }, { "type": "list", "ordered": false, "items": ["<strong>Critères financiers</strong> : Valeur Actuelle Nette (VAN), Retour sur Investissement (ROI), période de remboursement (payback)", "<strong>Critères stratégiques</strong> : Alignement avec les objectifs annuels, impact client, différenciation concurrentielle", "<strong>Critères opérationnels</strong> : Faisabilité technique, probabilité de réussite, urgence réglementaire, disponibilité des ressources"] }, { "type": "paragraph", "html": "Chaque critère reçoit un score (par exemple de 1 à 5) et un poids relatif. Le score pondéré total permet de classer les projets objectivement et d'établir une <strong>ligne de démarcation</strong> (cut-line) : les projets au-dessus passent, ceux en dessous sont reportés ou abandonnés. L'application de la cut-line est l'acte de management ultime : une fois que les ressources sont consommées par les projets les mieux notés, tout ce qui se trouve en dessous de la ligne doit être reporté ou annulé, sans exception. C'est la seule méthode pour garantir que les initiatives à fort impact reçoivent l'oxygène nécessaire à leur réussite — et pour protéger le portefeuille des \"projets de cœur\" (pet projects) dépourvus de valeur réelle." }, { "type": "paragraph", "html": "<strong>Avantage :</strong> Transparence, reproductibilité, facilité d'explication aux parties prenantes. <strong>Limite :</strong> La qualité du scoring dépend de la qualité des données d'entrée. Comme le souligne Robert Cooper, expert en gestion de portefeuille : <em>« La sophistication des méthodes financières dépasse souvent la qualité des données. Les méthodes purement comptables produisent parfois les résultats les plus médiocres si elles ne sont pas complétées par un jugement stratégique. »</em>" }, { "type": "heading", "level": 3, "id": "la-matrice-valeur-effort-et-risque-rendement", "text": "La matrice valeur / effort (et risque / rendement)" }, { "type": "paragraph", "html": "Cette approche simple et visuelle positionne chaque projet sur deux axes : la valeur attendue (impact business) et l'effort nécessaire (coût, complexité, durée). Les projets à forte valeur et faible effort (les \"quick wins\") sont prioritaires." }, { "type": "paragraph", "html": "Une variante couramment utilisée est la <strong>matrice risque-rendement</strong>, qui permet d'équilibrer le portefeuille entre quatre quadrants : les \"Quick Wins\" (faible risque, haut rendement), les projets stratégiques (haut risque, haut rendement), les projets d'optimisation (faible risque, faible rendement) et les projets à éviter (haut risque, faible rendement)." }, { "type": "paragraph", "html": "<strong>Avantage :</strong> Visuel, rapide à mettre en place, excellent pour les ateliers de priorisation. <strong>Limite :</strong> Réducteur pour les projets complexes à impact long terme" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/69975dc546f627807d618489_Matrice%20Valeur%20-Effort%20FR.png", "alt": "Matrice de priorisation valeur-effort pour le portefeuille de projets" }, { "type": "heading", "level": 3, "id": "la-methode-moscow", "text": "La méthode MoSCoW" }, { "type": "paragraph", "html": "Classez les projets en quatre catégories : <strong>Must have</strong> (vital), <strong>Should have</strong> (important), <strong>Could have</strong> (souhaitable), <strong>Won't have</strong> (pas maintenant). Cette méthode issue du monde agile est particulièrement adaptée quand il faut trancher rapidement." }, { "type": "heading", "level": 3, "id": "le-modele-wsjf-weighted-shortest-job-first", "text": "Le modèle WSJF (Weighted Shortest Job First)" }, { "type": "paragraph", "html": "Issu du framework SAFe, le WSJF priorise en divisant la valeur (<strong>coût du retard</strong> — Cost of Delay) par la taille de l'effort. Le coût du retard combine trois composantes : la valeur business/utilisateur, la criticité temporelle (fenêtre d'opportunité) et la réduction de risque ou l'opportunité d'apprentissage. Les projets à fort coût du retard et de petite taille passent en premier. C'est la méthode la plus utilisée dans les organisations ayant adopté l'agilité à l'échelle." }, { "type": "heading", "level": 3, "id": "la-methode-rice", "text": "La méthode RICE" }, { "type": "paragraph", "html": "RICE est un modèle de scoring rapide qui évalue chaque projet selon 4 dimensions : <strong>Reach</strong> (portée/nombre de personnes impactées), <strong>Impact</strong> (degré d'impact par personne), <strong>Confidence</strong> (niveau de confiance dans les estimations) et <strong>Effort</strong> (charge de travail nécessaire). Le score RICE = (Reach × Impact × Confidence) / Effort. Les projets avec le score le plus élevé sont priorisés." }, { "type": "heading", "level": 3, "id": "la-priorisation-par-le-lean-portfolio-management", "text": "La priorisation par le Lean Portfolio Management" }, { "type": "paragraph", "html": "Le <strong>Lean Portfolio Management</strong> (LPM) va plus loin en intégrant la priorisation dans un flux continu, aligné sur les objectifs stratégiques (OKR ou Epics stratégiques). La capacité est allouée par \"flux de valeur\" plutôt que par projet, ce qui permet une plus grande agilité dans les arbitrages." }, { "type": "table", "headers": ["Caractéristique", "PPM traditionnelle", "Lean Portfolio Management"], "rows": [["Financement", "Basé sur des projets spécifiques", "Basé sur les chaînes de valeur (Value Streams)"], ["Planification", "Cycle annuel rigide", "Glissante, itérative, ajustée chaque trimestre"], ["Gouvernance", "Contrôle centralisé (Top-down)", "Décisions décentralisées avec garde-fous"], ["Focus", "Administration de projets individuels", "Performance économique globale du portefeuille"]] }, { "type": "paragraph", "html": "Le passage au LPM marque la fin de la planification annuelle rigide, souvent obsolète dès le premier trimestre. On ne finance plus des projets isolés (approche \"Fire and Forget\"), mais des chaînes de valeur continues. Cette agilité est sécurisée par trois <strong>garde-fous</strong> (Guardrails) :" }, { "type": "list", "ordered": true, "items": ["<strong>Investissement par horizon</strong> : Équilibre entre maintenance du patrimoine existant, gains immédiats (quick wins) et innovation de rupture.", "<strong>Allocation de capacité</strong> : Arbitrage strict entre le développement de nouvelles fonctionnalités et la réduction de la dette technique.", "<strong>Indicateurs basés sur les résultats</strong> : Utilisation de KPIs liés aux résultats réels (Outcomes) plutôt qu'au simple avancement des tâches (Outputs)."] }, { "type": "heading", "level": 3, "id": "lanalyse-de-simulation-what-if", "text": "L'analyse de simulation « What-If »" }, { "type": "paragraph", "html": "L'analyse de scénarios est un levier puissant pour s'extraire de la gestion de crise permanente et troquer l'intuition contre l'<strong>analyse d'impact prédictive</strong>. Une simulation rigoureuse repose sur trois étapes :" }, { "type": "list", "ordered": true, "items": ["<strong>Identification des variables</strong> : Isoler les leviers critiques — budgets, disponibilité des compétences clés, <strong>coût du retard</strong> (Cost of Delay), dépendances inter-projets.", "<strong>Modélisation de scénarios</strong> : Construire des trajectoires optimiste, pessimiste et \"plus probable\" pour tester la résilience du portefeuille.", "<strong>Évaluation de l'impact</strong> : Mesurer précisément la dérive potentielle sur les délais, les coûts et la charge de travail globale."] }, { "type": "paragraph", "html": "Par exemple : simuler l'ajout d'un projet urgent pour mesurer le décalage sur les dates de livraison des initiatives en cours, ou évaluer l'impact d'une réduction budgétaire de 15 % sur la composition du portefeuille. Les outils PPM modernes intègrent ces capacités de simulation pour éclairer les décisions d'arbitrage en comité de pilotage — mettant fin au règne de \"la voix la plus forte\" en comité de direction." }, { "type": "quote", "text": "⚡ <strong>Bonne pratique AirSaaS :</strong> Les portefeuilles priorisés à 2-3 ans figés, c'était avant. Aujourd'hui, la priorisation en continu est la pratique courante. Un sondage AirSaas (2022) montre que la majorité des DSI repriorisent leur portefeuille au minimum chaque trimestre, et souvent chaque mois." }, { "type": "heading", "level": 2, "id": "les-kpis-essentiels-du-pilotage-de-portefeuille", "text": "Les KPIs essentiels du pilotage de portefeuille" }, { "type": "paragraph", "html": "Piloter un portefeuille de projets sans indicateurs, c'est conduire sans tableau de bord. Voici les KPIs incontournables, organisés en 4 catégories." }, { "type": "heading", "level": 3, "id": "kpis-dalignement-strategique", "text": "KPIs d'alignement stratégique" }, { "type": "list", "ordered": false, "items": ["<strong>% de projets alignés avec les axes stratégiques</strong> : Chaque projet doit être rattaché à un objectif. Un portefeuille sain affiche 80 à 100 % d'alignement.", "<strong>Répartition budgétaire par axe stratégique</strong> : Visualiser si les investissements sont cohérents avec les priorités déclarées.", "<strong>Bénéfices réalisés</strong> : Valeur réelle constatée post-clôture, comparée aux bénéfices attendus lors de la sélection."] }, { "type": "heading", "level": 3, "id": "kpis-de-capacite-et-ressources", "text": "KPIs de capacité et ressources" }, { "type": "list", "ordered": false, "items": ["<strong>Taux d'utilisation des ressources</strong> : Temps productif vs temps total disponible. Au-delà de 80 %, le risque de surcharge est élevé.", "<strong>Ratio demande vs capacité</strong> : Combien de projets sont en attente faute de bande passante ?", "<strong>Productivité par ressource</strong> : Tâches ou jalons accomplis par période, pour identifier les écarts de performance.", "<strong>Churn de l'équipe</strong> : Rotation du personnel en cours de projet — un indicateur avancé de problèmes de management ou de surcharge."] }, { "type": "heading", "level": 3, "id": "kpis-de-performance-operationnelle", "text": "KPIs de performance opérationnelle" }, { "type": "list", "ordered": false, "items": ["<strong>% de projets \"au vert\" / \"à risque\" / \"en alerte\"</strong> : Le triptyque météo classique, indispensable pour une revue de portefeuille efficace.", "<strong>Taux de respect des jalons</strong> : Les jalons clés sont-ils atteints dans les délais ?", "<strong>Variance budgétaire</strong> : Écart entre coûts prévus et coûts réels — un signal d'alerte précoce.", "<strong>Nombre de demandes de changement</strong> : Indicateur de la stabilité du périmètre. Un nombre élevé signale un cadrage initial insuffisant.", "<strong>Indice de santé du projet</strong> : Score composite combinant coût, délai et risque en un seul indicateur.", "<strong>Conformité</strong> : Adhérence aux processus, méthodologies et réglementations en vigueur."] }, { "type": "heading", "level": 3, "id": "kpis-de-valeur-et-resultats", "text": "KPIs de valeur et résultats" }, { "type": "list", "ordered": false, "items": ["<strong>ROI des projets livrés</strong> : Le portefeuille crée-t-il réellement la valeur financière attendue ?", "<strong>Délai de livraison (Time to Market)</strong> : Combien de temps entre la décision de lancer un projet et la première livraison de valeur ?", "<strong>Taux d'annulation</strong> : Capacité de l'organisation à arrêter les projets non rentables — un signe de maturité, pas d'échec.", "<strong>Satisfaction des parties prenantes</strong> : Enquêtes de satisfaction auprès des sponsors, métiers et équipes projet.", "<strong>Gestion des risques</strong> : Ratio risques mitigés vs risques identifiés — mesure l'efficacité de l'anticipation."] }, { "type": "quote", "text": "📊 <strong>Conseil :</strong> Ne multipliez pas les indicateurs. 5 à 8 KPIs bien choisis et mis à jour régulièrement valent mieux que 18 indicateurs jamais consultés. Sélectionnez ceux qui correspondent à votre niveau de maturité et enrichissez progressivement. L'enjeu est que votre tableau de bord de portefeuille raconte une histoire claire en 30 secondes." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699734d9e8f99e6b413126ef_Page%20Portfolio%20FR.png", "alt": "Tableau de bord de gestion de portefeuille de projets — interface AirSaas" }, { "type": "heading", "level": 2, "id": "comment-choisir-son-outil-ppm", "text": "Comment choisir son outil PPM ?" }, { "type": "paragraph", "html": "Le marché des outils de gestion de portefeuille de projets a considérablement évolué. Fini les usines à gaz ERP/PPM des années 2010. Les solutions modernes misent sur la simplicité, la collaboration et l'automatisation." }, { "type": "heading", "level": 3, "id": "les-criteres-essentiels-dun-bon-outil-ppm", "text": "Les critères essentiels d'un bon outil PPM" }, { "type": "paragraph", "html": "<strong>Simplicité d'adoption</strong> : L'outil doit être utilisable par les chefs de projet, les métiers ET la direction, sans formation complexe. Si personne ne l'utilise, il ne sert à rien." }, { "type": "paragraph", "html": "<strong>Vue portefeuille consolidée</strong> : Tableaux de bord visuels avec filtres (par programme, par axe stratégique, par météo projet, par responsable). La vue macro est la raison d'être de l'outil." }, { "type": "paragraph", "html": "<strong>Reporting automatisé</strong> : Génération automatique de rapports flash (PPT, PDF, URL) pour le Comité de pilotage, sans passer 4 jours à compiler des données manuellement." }, { "type": "paragraph", "html": "<strong>Gestion des rituels</strong> : L'outil doit structurer vos revues de portefeuille, vos points projet et vos Copil avec des workflows adaptés." }, { "type": "paragraph", "html": "<strong>Intégration avec l'écosystème existant</strong> : Connexion native avec les outils de gestion de tâches (Jira, Asana, Monday, Azure DevOps) pour faire remonter les données opérationnelles sans double saisie." }, { "type": "paragraph", "html": "<strong>Collaboration temps réel</strong> : Toutes les parties prenantes (DSI, métiers, direction) contribuent sur la même plateforme. Plus de \"je ne savais pas\"." }, { "type": "heading", "level": 3, "id": "ce-quun-outil-ppm-ne-resout-pas", "text": "Ce qu'un outil PPM ne résout pas" }, { "type": "paragraph", "html": "Un outil, aussi bon soit-il, ne peut pas compenser une gouvernance floue, des objectifs stratégiques non définis ou un management indécis. L'outil est un catalyseur : il amplifie les bonnes pratiques, mais ne les crée pas." }, { "type": "quote", "text": "🚀 <strong>AirSaaS</strong> est l'outil de gestion de portefeuille de projets conçu pour les DSI, PMO et directeurs de transformation qui veulent allier simplicité et efficacité. Tableau de bord visuel, rapport flash automatique, intégrations natives et collaboration temps réel. <a href=\"/fr/solution/management-de-portefeuille-projet\">Découvrir AirSaas→</a>" }, { "type": "heading", "level": 2, "id": "les-erreurs-a-eviter-en-gestion-de-portefeuille-de-projets", "text": "Les erreurs à éviter en gestion de portefeuille de projets" }, { "type": "paragraph", "html": "Après des centaines d'échanges avec des DSI, PMO et directeurs de transformation, voici les erreurs les plus fréquentes que nous observons." }, { "type": "heading", "level": 3, "id": "erreur-n1-confondre-gestion-de-portefeuille-et-gestion-de-projet", "text": "Erreur n°1 — Confondre gestion de portefeuille et gestion de projet" }, { "type": "paragraph", "html": "Le portefeuille ne sert pas à micro-manager les tâches de chaque projet. Il sert à prendre des décisions stratégiques : quels projets lancer, arrêter, accélérer ou reporter. Mélanger les niveaux crée de la confusion et alourdit la gouvernance." }, { "type": "heading", "level": 3, "id": "erreur-n2-ne-pas-oser-arreter-un-projet", "text": "Erreur n°2 — Ne pas oser arrêter un projet" }, { "type": "paragraph", "html": "Un portefeuille qui ne \"tue\" jamais de projet est un portefeuille malade. Si un projet ne crée plus de valeur, a vu son contexte changer ou mobilise des ressources critiques, il faut savoir le stopper. C'est un signe de maturité, pas d'échec." }, { "type": "heading", "level": 3, "id": "erreur-n3-sous-estimer-la-gestion-de-la-capacite", "text": "Erreur n°3 — Sous-estimer la gestion de la capacité" }, { "type": "paragraph", "html": "Valider 20 projets quand on a la capacité d'en mener 8 correctement, c'est la recette de l'échec collectif. Et la capacité ne se gère pas \"au global\" — elle se gère <strong>équipe par équipe, trimestre par trimestre</strong>. Une organisation peut avoir du budget disponible et des ressources \"sur le papier\", mais si l'équipe Data est saturée au Q2, aucun projet Data ne délivrera. L'incapacité chronique à dire \"non\" est le symptôme le plus répandu des organisations immatures en PPM. La gestion de portefeuille de projets impose de confronter la demande à la réalité de la capacité de chaque équipe — et d'assumer les arbitrages qui en découlent." }, { "type": "heading", "level": 3, "id": "erreur-n4-se-fier-au-pourcentage-davancement", "text": "Erreur n°4 — Se fier au pourcentage d'avancement" }, { "type": "paragraph", "html": "Le % d'avancement est l'un des indicateurs les plus trompeurs du pilotage de portefeuille. Un projet affiché à 70 % peut être à des mois de livrer le moindre délivrable exploitable. Ce chiffre mesure le plus souvent la <strong>consommation de charge</strong> (combien de jours ont été passés) et non la <strong>proximité d'un résultat tangible</strong>. Les organisations matures en PPM remplacent le % d'avancement par des indicateurs concrets : jalons atteints, délivrables acceptés, fonctionnalités livrées en production. La question à poser en revue de portefeuille n'est jamais \"à combien de % en est-on ?\", mais <strong>\"qu'est-ce qui sera livré et utilisable à la fin du trimestre ?\"</strong>" }, { "type": "heading", "level": 3, "id": "erreur-n5-un-reporting-heterogene-et-chronophage", "text": "Erreur n°5 — Un reporting hétérogène et chronophage" }, { "type": "paragraph", "html": "Si chaque chef de projet produit son reporting dans un format différent, à une fréquence aléatoire, le Comité de pilotage ne pourra jamais avoir une vision claire du portefeuille. Standardisez le format, automatisez la collecte, fixez un rythme régulier." }, { "type": "heading", "level": 3, "id": "erreur-n6-lancer-la-demarche-sans-sponsorship", "text": "Erreur n°6 — Lancer la démarche sans sponsorship" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets touche aux budgets, aux priorités et parfois aux jeux de pouvoir. Sans sponsor au niveau Direction Générale ou DSI, la démarche s'essouffle dès les premiers arbitrages difficiles." }, { "type": "heading", "level": 3, "id": "erreur-n7-vouloir-tout-faire-dun-coup", "text": "Erreur n°7 — Vouloir tout faire d'un coup" }, { "type": "paragraph", "html": "Privilégiez une approche progressive : démarrez sur un périmètre limité, avec des rituels simples et un petit nombre de projets pilotes. Montrez les premiers résultats, puis étendez. L'adoption se fait par la preuve, pas par le décret." }, { "type": "heading", "level": 2, "id": "faq-gestion-de-portefeuille-de-projets", "text": "FAQ — Gestion de portefeuille de projets" }, { "type": "heading", "level": 3, "id": "quest-ce-quun-portefeuille-de-projets", "text": "Qu'est-ce qu'un portefeuille de projets ?" }, { "type": "paragraph", "html": "Un portefeuille de projets est l'ensemble des projets, programmes et opérations d'une organisation, gérés collectivement pour atteindre les objectifs stratégiques. Wikipédia le définit comme <em>\"la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage\"</em> (Fernez-Walch, 2004)." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-gestion-de-portefeuille-de-projets-et-gestion-multi-projets", "text": "Quelle est la différence entre gestion de portefeuille de projets et gestion multi-projets ?" }, { "type": "paragraph", "html": "La <strong>gestion multi-projets</strong> est opérationnelle : elle vise à gérer efficacement plusieurs projets en parallèle (planning, ressources, dépendances). La <strong>gestion de portefeuille</strong> est stratégique : elle décide quels projets lancer et dans quel ordre, en fonction de leur contribution à la stratégie. En résumé, le multi-projet s'occupe du \"comment\", le portefeuille s'occupe du \"quoi\"." }, { "type": "heading", "level": 3, "id": "qui-est-responsable-de-la-gestion-du-portefeuille-de-projets", "text": "Qui est responsable de la gestion du portefeuille de projets ?" }, { "type": "paragraph", "html": "En général, c'est le <strong>PMO</strong> (Project Management Office), le <strong>DSI</strong> ou le <strong>Directeur de transformation</strong> qui pilote la gestion de portefeuille. Mais les décisions d'arbitrage impliquent la Direction Générale et les directions métiers. La gestion de portefeuille de projets est par nature transverse et collaborative." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-un-outil-ppm-et-un-outil-de-gestion-de-projet", "text": "Quelle est la différence entre un outil PPM et un outil de gestion de projet ?" }, { "type": "paragraph", "html": "Un <strong>outil de gestion de projet</strong> (Jira, Asana, Monday, Trello) permet de gérer les tâches, le planning et les ressources d'un projet individuel. Un <strong>outil PPM</strong> permet de piloter l'ensemble du portefeuille : vue consolidée, arbitrages, reporting stratégique, alignement avec les objectifs. Les deux sont complémentaires et doivent idéalement être connectés." }, { "type": "heading", "level": 3, "id": "la-gestion-de-portefeuille-de-projets-est-elle-adaptee-aux-pme", "text": "La gestion de portefeuille de projets est-elle adaptée aux PME ?" }, { "type": "paragraph", "html": "Absolument. La taille de l'entreprise ne détermine pas le besoin, c'est le nombre de projets en concurrence pour les mêmes ressources qui compte. Dès qu'une PME gère plus de 5-10 projets transverses en parallèle, une démarche de portefeuille — même légère — apporte une valeur considérable. Les PME ont d'ailleurs souvent plus d'agilité pour la mettre en œuvre." }, { "type": "heading", "level": 3, "id": "a-quelle-frequence-faut-il-reprioriser-son-portefeuille-de-projets", "text": "À quelle fréquence faut-il reprioriser son portefeuille de projets ?" }, { "type": "paragraph", "html": "La priorisation en continu est devenue la pratique dominante. La plupart des organisations matures réalisent une revue de portefeuille formelle chaque mois, avec des points d'arbitrage ponctuels si le contexte l'exige. Les roadmaps figées à 2-3 ans ont laissé place à un pilotage agile et adaptatif." }, { "type": "heading", "level": 3, "id": "quels-sont-les-principaux-frameworks-pour-la-gestion-de-portefeuille-de-projets", "text": "Quels sont les principaux frameworks pour la gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "Les frameworks les plus reconnus sont : le <strong>Standard for Portfolio Management du PMI</strong>, <strong>MoP (Management of Portfolios)</strong> de AXELOS, le <strong>Lean Portfolio Management (LPM)</strong> du framework SAFe, et les approches inspirées du <strong>OKR</strong> (Objectives and Key Results). Le choix dépend de la culture et de la maturité de votre organisation." }, { "type": "heading", "level": 2, "id": "pour-aller-plus-loin", "text": "Pour aller plus loin" }, { "type": "list", "ordered": false, "items": ["<a href=\"/fr/gestion-de-projet/lean-portfolio-management\">Lean Portfolio Management : aligner direction générale, IT et métiers</a>", "<a href=\"/fr/solution/revue-de-portefeuille\">Revue de portefeuille : bonnes pratiques et guide complet</a>", "<a href=\"/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet\">Les 10 erreurs à ne pas commettre dans la mise en place d'un portefeuille projet</a>", "<a href=\"/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme\">Gestion de portefeuille de projets en PME : bénéfices et bonnes pratiques</a>", "<a href=\"/fr/guide/cahier-des-charges-logiciel-ppm\">Outil PPM : le cahier des charges pour bien choisir</a>", "<a href=\"/fr/solution/management-de-portefeuille-projet\">Découvrir AirSaaS, l'outil PPM des DSI et PMO</a>"] }], "toc": [{ "href": "#pour-aller-plus-loin", "label": "Pour aller plus loin", "level": 2 }, { "href": "#portefeuille-de-projets-vs-programme-vs-projet-quelles-differences", "label": "Portefeuille de projets vs programme vs projet : quelles différences ?", "level": 2 }, { "href": "#pourquoi-mettre-en-place-une-gestion-de-portefeuille-de-projets", "label": "Pourquoi mettre en place une gestion de portefeuille de projets ?", "level": 2 }, { "href": "#les-7-etapes-pour-deployer-une-gestion-de-portefeuille-de-projets-efficace", "label": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace", "level": 2 }, { "href": "#les-methodes-de-priorisation-dun-portefeuille-de-projets", "label": "Les méthodes de priorisation d'un portefeuille de projets", "level": 2 }, { "href": "#les-kpis-essentiels-du-pilotage-de-portefeuille", "label": "Les KPIs essentiels du pilotage de portefeuille", "level": 2 }, { "href": "#comment-choisir-son-outil-ppm", "label": "Comment choisir son outil PPM ?", "level": 2 }, { "href": "#les-erreurs-a-eviter-en-gestion-de-portefeuille-de-projets", "label": "Les erreurs à éviter en gestion de portefeuille de projets", "level": 2 }, { "href": "#faq-gestion-de-portefeuille-de-projets", "label": "FAQ — Gestion de portefeuille de projets", "level": 2 }], "faq": [{ "question": "Qu'est-ce qu'un portefeuille de projets ?", "answer": "Un portefeuille de projets est l'ensemble des projets, programmes et opérations d'une organisation, gérés collectivement pour atteindre les objectifs stratégiques. Wikipédia le définit comme \"la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage\" (Fernez-Walch, 2004)." }, { "question": "Quelle est la différence entre gestion de portefeuille de projets et gestion multi-projets ?", "answer": "La gestion multi-projets est opérationnelle : elle vise à gérer efficacement plusieurs projets en parallèle (planning, ressources, dépendances). La gestion de portefeuille est stratégique : elle décide quels projets lancer et dans quel ordre, en fonction de leur contribution à la stratégie. En résumé, le multi-projet s'occupe du \"comment\", le portefeuille s'occupe du \"quoi\"." }, { "question": "Qui est responsable de la gestion du portefeuille de projets ?", "answer": "En général, c'est le PMO (Project Management Office), le DSI ou le Directeur de transformation qui pilote la gestion de portefeuille. Mais les décisions d'arbitrage impliquent la Direction Générale et les directions métiers. La gestion de portefeuille de projets est par nature transverse et collaborative." }, { "question": "Quelle est la différence entre un outil PPM et un outil de gestion de projet ?", "answer": "Un outil de gestion de projet (Jira, Asana, Monday, Trello) permet de gérer les tâches, le planning et les ressources d'un projet individuel. Un outil PPM permet de piloter l'ensemble du portefeuille : vue consolidée, arbitrages, reporting stratégique, alignement avec les objectifs. Les deux sont complémentaires et doivent idéalement être connectés." }, { "question": "La gestion de portefeuille de projets est-elle adaptée aux PME ?", "answer": "Absolument. La taille de l'entreprise ne détermine pas le besoin, c'est le nombre de projets en concurrence pour les mêmes ressources qui compte. Dès qu'une PME gère plus de 5-10 projets transverses en parallèle, une démarche de portefeuille — même légère — apporte une valeur considérable. Les PME ont d'ailleurs souvent plus d'agilité pour la mettre en œuvre." }, { "question": "À quelle fréquence faut-il reprioriser son portefeuille de projets ?", "answer": "La priorisation en continu est devenue la pratique dominante. La plupart des organisations matures réalisent une revue de portefeuille formelle chaque mois, avec des points d'arbitrage ponctuels si le contexte l'exige. Les roadmaps figées à 2-3 ans ont laissé place à un pilotage agile et adaptatif." }, { "question": "Quels sont les principaux frameworks pour la gestion de portefeuille de projets ?", "answer": "Les frameworks les plus reconnus sont : le Standard for Portfolio Management du PMI, MoP (Management of Portfolios) de AXELOS, le Lean Portfolio Management (LPM) du framework SAFe, et les approches inspirées du OKR (Objectives and Key Results). Le choix dépend de la culture et de la maturité de votre organisation." }], "related": [{ "href": "/fr/gestion-de-projet/lean-portfolio-management", "label": "Lean Portfolio Management : aligner direction générale, IT et métiers" }, { "href": "/fr/solution/revue-de-portefeuille", "label": "Revue de portefeuille : bonnes pratiques et guide complet" }, { "href": "/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet", "label": "Les 10 erreurs à ne pas commettre dans la mise en place d'un portefeuille projet" }, { "href": "/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme", "label": "Gestion de portefeuille de projets en PME : bénéfices et bonnes pratiques" }, { "href": "/fr/guide/cahier-des-charges-logiciel-ppm", "label": "Outil PPM : le cahier des charges pour bien choisir" }, { "href": "/fr/solution/management-de-portefeuille-projet", "label": "Découvrir AirSaaS, l'outil PPM des DSI et PMO" }] }, { "slug": "jalon-projet", "skip": false, "meta": { "title": "Le jalon projet : une technique pour séquencer vos projets intelligemment", "h1": "Le jalon projet : une technique pour séquencer vos projets intelligemment", "description": "Le jalon projet est un outil de gestion de projet particulièrement efficace pour séquencer en différentes phases. Grâce aux jalons, vous boostez la motivation de vos équipes et améliorez la transparence sur l'état d'avancement de votre projet.", "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37e4813ce5efbe93f3a36_Project%20image2.jpg", "alt": "" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Le suivi de projet est une étape primordiale pour maximiser vos chances de réussite : même si vous avez planifié le déroulement de votre projet, il faut absolument que vous puissiez contrôler la trajectoire<strong> </strong>que vous prenez pendant son exécution. Le jalon projet est un<strong> outil de gestion de projet particulièrement efficace</strong>&nbsp;pour séquencer&nbsp;en différentes phases. Grâce aux jalons, vous boostez la motivation de vos équipes et améliorez la transparence sur l'état d'avancement de votre projet.&nbsp;" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea947e12a1db65655b1059_Projet-timeline-min.jpeg", "alt": "Timeline des jalons projets", "caption": "Timeline des jalons projets - barre de progression" }, { "type": "heading", "level": 2, "id": "quest-ce-que-quun-jalon-projet", "text": "Qu'est-ce que qu'un jalon projet ?" }, { "type": "paragraph", "text": "Le jalon (en anglais \"milestone\") marque la fin d'une étape et un point d'arrêt dans le processus de gestion de projet.&nbsp;" }, { "type": "paragraph", "text": "Le jalon est souvent associé à un<strong> évènement important</strong> comme la signature<strong> </strong>d'un gros contrat, la mise sur le marché d'un produit, où le lancement d'une campagne publicitaire. C'est en tout cas la<strong> fin d'une étape</strong> <strong>et le début</strong> <strong>d'une</strong> <strong>autre</strong> dans le cycle de vie d'un projet." }, { "type": "paragraph", "text": "C'est donc l'occasion pour une équipe de<strong> faire le bilan</strong> sur l'ensemble de l'exécution de l'étape précédente, avant de passer à la suivante d'un projet.&nbsp;" }, { "type": "paragraph", "text": "D'ailleurs le jalon marque un passage définitif à la prochaine étape : une fois validé, il n'y a normalement pas de retour en arrière dans le planning du projet." }, { "type": "paragraph", "text": "Autre chose : les jalons n'ont pas vraiment<strong> </strong>de durée ou alors cette dernière est nulle, il s'agit plutôt d'un marqueur qui identifie la fin d'une étape et le début d'une autre.&nbsp;" }, { "type": "paragraph", "text": "En résumé, les jalons sont semblables à des bornes, des panneaux sur une route vous indiquant l'état d'avancement de votre gestion de projets.&nbsp;" }, { "type": "heading", "level": 2, "id": "section", "text": "‍" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37d7a5606d8e8fab0fb3e_Project-Milestones-.jpg", "alt": "project milestones", "caption": "Mise à jour des jalons d'un projet dans le logiciel de gestion de portefeuille projet Airsaas" }, { "type": "heading", "level": 2, "id": "pourquoi-faire-des-jalons-projets", "text": "Pourquoi faire des jalons projets ?" }, { "type": "paragraph", "text": "Les jalons projets ont trois objectifs principaux :&nbsp;" }, { "type": "list", "ordered": false, "items": ["<strong>Revenir sur l'exécution</strong> de la phase passée : tirer les leçons des erreurs commises, valoriser ce qui a fonctionné, et adapter la planification de la phase suivante en fonction.&nbsp;"] }, { "type": "list", "ordered": false, "items": ["<strong>Contrôler</strong> <strong>les différents livrables</strong> : vérifier qu'ils sont tous en conformité avec ce qui avait été déterminé lors de la planification du projet.&nbsp;"] }, { "type": "list", "ordered": false, "items": ["<strong>Valider le lancement de la phase suivante</strong> : avec potentiellement, des réajustements en fonction des enseignements tirés de la phase précédente.&nbsp;&nbsp;"] }, { "type": "paragraph", "text": "Mais les jalons sont aussi des <strong>leviers </strong>importants pour <strong>motiver votre équipe</strong> et optimiser l'exécution du projet :&nbsp;" }, { "type": "list", "ordered": false, "items": ["Ils évitent<strong> </strong>que <strong>les objectifs fixés semblent irréalisables</strong>. En effet, lorsque l'objectif visé est trop grand, il peut décourager vos collaborateurs qui ne savent alors pas par où commencer. Ainsi, en décomposant vos objectifs en jalons, vous augmentez l'implication de vos collaborateurs et donc les chances de réussite du déroulement du projet.&nbsp;"] }, { "type": "list", "ordered": false, "items": ["Les jalons d'un projet permettent aussi d'<strong>éviter </strong><a href=\"https://blog-gestion-de-projet.com/effet-tunnel/\" target=\"_blank\"><strong>l'effet tunnel</strong></a>. Cause principale de l'échec des projets, l'effet tunnel représente le moment où il n'est plus possible de savoir où en est l'avancement du travail de chaque membre de l'équipe. En jalonnant son projet, on crée des points qui servent de repère de navigation au chef de projet et à l'ensemble de l'équipe, à échéances fixes."] }, { "type": "list", "ordered": false, "items": ["Les jalons sont aussi de bons leviers pour <a href=\"https://www.airsaas.io/fr/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\"><strong>réussir</strong> <strong>votre</strong> <strong>communication</strong></a><strong> avec l'ensemble des parties prenantes</strong> de votre projet. Le nombre de jalons validés étant un bon indicateur de l'état d'avancement du projet, en particulier pour des personnes qui ne travaillent pas dessus au quotidien."] }, { "type": "heading", "level": 2, "id": "comment-faire-les-jalons-de-son-projet", "text": "Comment faire les jalons de son projet ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/632322f549e4a73d386e2eff_plante-de-jalons-projet-airsaas.png", "alt": "Dessin de ", "caption": "L'art délicat du \"planté de jalons\" dans les projets !" }, { "type": "heading", "level": 2, "id": "trouver-le-bon-nombre-de-jalons", "text": "Trouver le bon nombre de jalons ‍" }, { "type": "paragraph", "text": "Quel est le nombre idéal<strong> </strong>de jalons d'un projet ? <strong>Ni trop, ni pas assez ! </strong>Pas la peine de demander à Wikipédia ! Pour faire simple : tout dépend des caractéristiques de votre projet ou de votre produit, il n'y a pas de nombre optimal de jalons.&nbsp;" }, { "type": "paragraph", "text": "Si vous décidez d'un nombre trop important de jalons, vous êtes sûrement en train de <strong>confondre tâche et jalon</strong>. Les jalons permettent de partager une vue temporelle macro avec l'ensemble des parties prenantes. Si vous allez dans les tâches (micro) vous allez démotiver les personnes du projet car elles ne se sentiront pas concernés." }, { "type": "paragraph", "text": "À l'inverse, si vous ne jalonnez pas suffisamment votre projet, vous allez au-devant d'un gros problème : l'effet tunnel. Vous pouvez ne pas vous rendre compte qu'une partie de vos collaborateurs dévient du plan initial et vous augmentez notamment vos risques d'être dans le pire des scénarios...&nbsp;Arriver à la fin de l'échéancier du projet en étant à côté de la plaque.." }, { "type": "paragraph", "text": "De nombreuses équipes impliquent tous leurs membres lors du choix des jalons du projet :&nbsp; c'est aussi un bon<strong> levier pour</strong> <strong>engager et</strong> <strong>responsabiliser</strong> chacun de vos collaborateurs. Il arrive aussi que vous ne puissiez pas choisir tous les jalons de votre projet : des conditions spécifiques peuvent être imposées par le client final, notamment lorsque vous devez lui livrer des livrables importants.&nbsp;" }, { "type": "heading", "level": 3, "id": "penser-a-assortir-une-echeance-pour-chaque-jalon", "text": "Penser à assortir une échéance pour chaque jalon ‍" }, { "type": "paragraph", "text": "Comme précisé précédemment, les jalons ne durent pas dans le temps, mais sont les <strong>marqueurs</strong> d'un changement de phase dans votre projet. Vous devez donc décider d'une date pour votre jalon, et cette dernière ne doit pas correspondre à la durée d'exécution de la tâche, mais plutôt à <strong>sa date de lancement ou de réalisation.</strong>&nbsp;" }, { "type": "paragraph", "text": "Par exemple, dans le cas où l'un de vos jalons est attaché à un livrable, son échéance sera la date de rendu au client plutôt que le temps que vous prévoyez pour le réaliser.&nbsp;&nbsp;" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37dc701f8f1eb37e7cf56_Copil-Milestones.jpg", "alt": "illustration copil milestones", "caption": "Exemple de suivi jalons - point événement déroulement projet" }, { "type": "heading", "level": 3, "id": "des-exemples-de-choix-de-jalons", "text": "Des exemples de choix de jalons ‍" }, { "type": "paragraph", "text": "À la question qu'est-ce qu'un jalon ? Il n'existe pas de réponse universelle, voici une sélection de jalon événement à titre d'exemple d'un projet :" }, { "type": "list", "ordered": false, "items": ["Assigner un jalon <strong>à chaque tâche critique </strong>: les tâches à identifier comme critiques sont celles qui doivent être réalisées sous peine de ralentir ou même de bloquer l'ensemble du projet. Si vous souhaitez maximiser vos chances d'éviter les goulots d'étranglement, n'hésitez pas à mettre en lumière ces<strong> tâches critiques</strong> en les identifiant comme jalons auprès de votre équipe.&nbsp;"] }, { "type": "list", "ordered": false, "items": ["Assigner un jalon à <strong>chaque évènement majeur</strong> de votre projet : réunissez-vous avec votre équipe pour décider de ce que vous considérez comme des évènements majeurs de la planification, au regard des objectifs de votre projet ou produit."] }, { "type": "list", "ordered": false, "items": ["Assigner un jalon à la<strong> réalisation d'un objectif clé</strong> : vous pouvez aussi décider de jalonner votre projet par le prisme de vos résultats. Pensez alors à prendre suffisamment de temps pour penser intelligemment le chiffrage de vos objectifs, autrement, vous risquez de vous retrouver avec des jalons trop réguliers, où à l'inverse trop éloignés dans le temps.&nbsp;"] }, { "type": "heading", "level": 3, "id": "utiliser-la-confiance-dans-le-jalon-projet", "text": "Utiliser la confiance dans le jalon projet" }, { "type": "paragraph", "text": "Avec AirSaas la notion de jalon comporte des éléments d'attributs : le <strong>responsable, le poids et le degré de confiance.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/630bc84f15bab8397943a9cd_confiance-jalons.png", "alt": "Fonction de modification du degré de confiance dans le jalon ", "caption": "Les chefs de projet peuvent utiliser AirSaas et sa fonction de modification du degré de confiance dans le jalon" }, { "type": "paragraph", "text": "Le degré de confiance dans le jalon d'un projet est l'ne des <strong>nouveautés</strong> qui <strong>facilite</strong> le <strong>suivi</strong> des points." }, { "type": "paragraph", "text": "Vous avez par exemple la possibilité de suivre votre objectif de<strong> progression des jalons</strong>, grâce à un calcul automatique prenant en compte les jalons réalisés et leur poids." }, { "type": "paragraph", "text": "Suivre le travail avec les informations liées aux jalons peut contribuer à<strong> limiter l'effet dérive en continu.</strong>" }, { "type": "heading", "level": 2, "id": "piloter-par-les-jalons-vs-piloter-a-la-tache", "text": "Piloter par les jalons VS piloter à la tâche" }, { "type": "paragraph", "text": "Dans toutes les organisations les directions et les responsables veulent maîtriser le risque de dérapage d'un projet. Dans ce cadre-là elles essayent de mettre en place une gestion de tâche qui se matérialise par le fameux Gantt.&nbsp;" }, { "type": "paragraph", "text": "Malheureusement, la majorité des organisations n'arrivent pas à faire une mise en place ce type de gestion de projet pour la plupart des projets de l'entreprise car :" }, { "type": "list", "ordered": false, "items": ["La <strong>culture projet</strong> est <strong>trop hétérogène</strong> dans l'entreprise", "Il n'y a <strong>pas assez de formation </strong>pour les chefs de projets", "Les responsables métiers impliqués ne sont <strong>pas formés aux découpages</strong> de leurs missions en tâches", "La majorité des projets ne sont <strong>pas des projets qui ont été déjà été faits,</strong> du coup il est très difficile de découper précisément le projet en différentes missions et d'effectuer un gestion des tâches.", "La <strong>communication</strong> entre les équipes n'est <strong>pas authentique</strong> et il y a beaucoup trop de non-dits."] }, { "type": "paragraph", "text": "Cela crée beaucoup de frustration pour tous les acteurs." }, { "type": "paragraph", "text": "Une<strong> alternative au contrôle</strong> des tâches et aux&nbsp;diagrammes de Gantt&nbsp;est le <strong>pilotage par les jalons</strong>.&nbsp; Sur ce point découvrez l'article<a href=\"/gestion-de-projet/le-diagramme-de-gantt-comment-sen-servir\" target=\"_blank\"> : Le diagramme de Gantt : comment s'en servir ?</a>" }], "toc": [{ "label": "Qu'est-ce que qu'un jalon projet ?", "href": "#quest-ce-que-quun-jalon-projet", "level": 2 }, { "label": "Pourquoi faire des jalons projets ?", "href": "#pourquoi-faire-des-jalons-projets", "level": 2 }, { "label": "Comment faire les jalons de son projet ?", "href": "#comment-faire-les-jalons-de-son-projet", "level": 2 }, { "label": "Trouver le bon nombre de jalons", "href": "#trouver-le-bon-nombre-de-jalons", "level": 2 }, { "label": "Piloter par les jalons VS piloter à la tâche", "href": "#piloter-par-les-jalons-vs-piloter-a-la-tache", "level": 2 }], "faq": [], "related": [] }, { "slug": "kanban-gestion-de-projet", "skip": false, "meta": { "title": "Kanban & gestion de projet : la méthode pour optimiser votre suivi de projet", "h1": "Kanban & gestion de projet : la méthode pour optimiser votre suivi de projet", "description": "Découvrez comment utiliser concrètement le Kanban dans votre gestion de projet pour optimiser votre suivi de projet.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f38d15e3e50634f2ce01e8_1-3-min.jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\">suivi de projet</a> peut parfois se faire avec des outils qui offrent une visibilité globale (comme le diagramme de Gantt par exemple), mais il arrive aussi que vous souhaitiez rentrer davantage dans le détail." }, { "type": "paragraph", "text": "Le Kanban est l'un des meilleurs pour cela, et en plus, c'est un excellent support de communication pour vos réunions d'équipe !" }, { "type": "paragraph", "text": "Découvrez ici comment utiliser concrètement le Kanban dans votre gestion de projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8393b38147e34dd835bab_62f37ed0147093c2a56b9627_Project-kanban-min.jpeg", "alt": "Kanban des projets : le dashboard", "caption": "Kanban des projets" }, { "type": "heading", "level": 2, "id": "quest-ce-que-cest-que-la-methode-kanban", "text": "Qu'est-ce que c'est que la méthode Kanban ?" }, { "type": "paragraph", "text": "Le Kanban est un outil qui provient de la méthode du \"lean facturing\". L'objectif premier des systèmes Kanban était donc de permettre d'assurer une production en flux tendu et de parvenir à respecter un équilibre entre la production et la demande." }, { "type": "paragraph", "text": "Le nom Kanban vient du japonais : il signifie étiquette. Plus précisément, il s'agissait de l'étiquette qui servait à indiquer à un poste de production s'il devait continuer à produire où plutôt s'arrêter. L'objectif était de limiter le surplus de pièce par rapport aux demandes clients et donc de limiter le gaspillage, notamment lorsqu'un défaut sur une série de pièces avait été détecté." }, { "type": "paragraph", "text": "Désormais, le Kanban est beaucoup utilisé comme d'une des méthodologies phares de la gestion de projet agile - mais son usage ne s'arrête pas qu'aux projets informatiques. Tout chef de projet, quel que soit son domaine, peut utiliser cet outil de suivi d'avancement du projet très fonctionnel et collaboratif." }, { "type": "paragraph", "text": "La méthode Kanban se base sur un système de cartes synthétiques qui permettent à chaque membre de l'équipe de savoir :" }, { "type": "list", "ordered": false, "items": ["Quelles sont les tâches à réaliser", "Quand elles doivent être réalisées", "Ce qui a déjà été réalisé"] }, { "type": "paragraph", "text": "Le Kanban est donc l'outil parfait pour rappeler chacune des tâches dont doit se charger une équipe et permettre à chacun des membres de coordonner leurs efforts en vue de maximiser leur productivité." }, { "type": "paragraph", "text": "C'est aussi un outil visuellement intéressant : en un coup d'œil, chacun peut disposer de l'organisation des tâches de l'équipe à un moment T. Le Kanban optimise donc <a href=\"https://www.airsaas.io/fr/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">la communication</a> et la bonne circulation des informations relatives aux tâches à exécuter dans vos équipes." }, { "type": "paragraph", "text": "Pour simplifier encore davantage la visibilité, les Kanbans sont généralement divisés en trois parties différentes :" }, { "type": "list", "ordered": false, "items": ["Les tâches \"à réaliser\"", "Les tâches \"en cours\"", "Les tâches \"réalisées\""] }, { "type": "paragraph", "text": "Souvent, chacun de ces statuts est représenté par un code couleur afin que chacun puisse savoir ce qu'il doit faire et ce qui est fait en quelques secondes seulement." }, { "type": "paragraph", "text": "Le tableau Kanban comporte parfois un espace où chaque membre de l'équipe, et même parfois les clients, peut proposer des idées sur le projet. Ces idées peuvent ainsi être reprises par l'équipe et intégrée au projet si elles sont jugées pertinentes." }, { "type": "paragraph", "text": "Pour résumer, le Kanban est communément considéré comme un outil de gestion de projets bien plus efficace que les tableaux traditionnels et les \"to-do list\", et l'adopter et l'utiliser au quotidien amène de nombreux bénéfices." }, { "type": "heading", "level": 2, "id": "pourquoi-utiliser-un-kanban-dans-la-gestion-de-projet", "text": "Pourquoi utiliser un Kanban dans la gestion de projet ?" }, { "type": "paragraph", "text": "L'utilisation d'un Kanban dans la gestion de projet a de nombreux avantages qui devraient vous convaincre d'adopter cet outil." }, { "type": "paragraph", "text": "En voici quelques-uns." }, { "type": "list", "ordered": false, "items": ["<strong>Une réduction des délais et des coûts</strong> : grâce à une meilleure communication et une priorisation des tâches à effectuer plus effective.", "<strong>Une meilleure visibilité sur l'exécution du projet</strong> : vous pouvez suivre l'état d'avancement de chacune des tâches en quelques secondes.", "<strong>Une plus grande la flexibilité de votre équipe</strong> : avoir une visibilité fine sur les tâches que chacun doit réaliser permet de parvenir à changer de cap plus facilement lorsqu'un évènement inattendu survient - par exemple lorsque le besoin de votre client évolue.", "<strong>Des goulots d'étranglement évités</strong> : comme chacun sait ce que les autres ont à faire et dans quels délais, les risques de se retrouver bloqué par une tâche non finie par l'un de ses collègues sont considérablement réduits.", "<strong>Un outil pour la collaboration corrective</strong> : les membres de l'équipe sont incités à communiquer pour résoudre les problèmes dès qu'ils apparaissent.", "<strong>Une meilleure qualité</strong> : la méthode de gestion de projet par Kanban aide à obtenir un niveau de qualité constant, et ce, de manière collective.", "<strong>Une simplification de la démarche d'amélioration continue</strong> : la faculté de visualiser la façon de travailler de votre équipe facilement permet de réfléchir constamment à des axes d'amélioration.", "<strong>Plus de souplesse dans l'exécution</strong> : les changements de priorités, du responsable d'une tâche donnée ou un simple décalage des délais dans le temps sont facilités.", "<strong>Un management visuel</strong> : chacun des membres de votre équipe dispose du même niveau d'information (l'état d'avancement, les contraintes, les difficultés de chacun…). En leur offrant une vision globale de l'exécution, vous intégrez complètement votre équipe au projet, et vos collaborateurs se sentent d'autant plus impliqués.", "<strong>Une méthode instinctive</strong> : la méthode Kanban est simple d'utilisation et donc rapide à mettre en place. De plus, les bénéfices sont presque immédiats.", "<strong>Un coup de boost pour la motivation de vos équipes</strong> : une des raisons principales de la démotivation d'une équipe est de devoir gérer une tâche qui leur paraît trop grande, insurmontable. La méthode Kanban est idéale pour découper tout projet en un ensemble de petites tâches réalisables. Cette astuce reconnue vous permet de motiver vos collaborateurs, a fortiori si chaque tâche est assignée à un responsable.", "<strong>Un bon support de réunion</strong> : le tableau Kanban est un support de présentation pour vos réunions avec vos équipes. Il est particulièrement utile pour les points quotidiens de début de journée."] }, { "type": "heading", "level": 2, "id": "kanban-physique-vs-kanban-digital", "text": "Kanban physique -vs- Kanban digital" }, { "type": "paragraph", "text": "Les tableaux Kanban peuvent être utilisés sous leur forme numérique ou physique, et chacune d'elles possède des avantages. En voici quelques-uns pour vous aider à faire votre choix." }, { "type": "heading", "level": 3, "id": "les-avantages-du-kanban-physique", "text": "Les avantages du Kanban physique" }, { "type": "paragraph", "text": "Certaines équipes (notamment des développeurs informatiques) choisissent de mettre en place un Kanban physique dans les locaux de l'entreprise, pour encourager les collaborateurs pendant leurs sprints agiles. Ce format présente quelques avantages :" }, { "type": "paragraph", "text": "<strong>Une visibilité continue</strong> : un tableau physique est \"toujours allumé\" et permet donc à chacun d'avoir sous le nez ce qu'il reste à faire." }, { "type": "paragraph", "text": "<strong>Engager vos équipes</strong> : un tableau physique est coloré, apporte une touche sympathique à vos bureaux et a un impact sur l'implication de vos équipes." }, { "type": "paragraph", "text": "<strong>Encourage à la communication</strong> : le tableau physique offre un lieu de conversation et de réflexion tout trouvé. Vos collaborateurs pourront échanger avec le tableau comme support." }, { "type": "heading", "level": 3, "id": "les-avantages-du-kanban-digital", "text": "Les avantages du Kanban digital" }, { "type": "paragraph", "text": "<strong>Plus simple à maintenir ordonné</strong> : oubliez les écritures illisibles et les post-it qui se décollent." }, { "type": "paragraph", "text": "<strong>Traçabilité dans le temps</strong> : aucun post-it n'est jeté sans avoir été archivé et vous avez une visibilité sur l'ensemble des tâches tout au long de l'exécution de votre projet." }, { "type": "paragraph", "text": "<strong>Accessibilité</strong> : tout le monde peut avoir accès au tableau, en même temps, et peu importe où il se trouve. C'est particulièrement pratique lorsque vous collaborez avec des freelances ou des collaborateurs à distance." }, { "type": "paragraph", "text": "<strong>Changement en temps réel</strong> : chaque membre de votre équipe voit les informations actualisées sur son tableau, sans délai, ni avoir besoin de les briefer pour les prévenir." }, { "type": "paragraph", "text": "<strong>Information centralisée</strong> : toutes les informations utiles à une tâche peuvent être incorporées dans le tableau facilement (fichiers joints, description longue, etc…)" }, { "type": "paragraph", "text": "<strong>Sécurisation accrue</strong> : vous ne perdez pas de post-it, et les applications permettent souvent des processus d'authentification garantissant la protection d'informations confidentielles." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8393b38147e34dd835bc4_62f38c84eafac57e7d6349cc_Presentation-mode-.jpeg", "alt": "Vue projet", "caption": "Passez du Kanban à la fiche projet en un clic" }, { "type": "heading", "level": 2, "id": "le-kanban-comme-support-de-communication-intermediaire", "text": "Le Kanban comme support de communication intermédiaire" }, { "type": "paragraph", "text": "Le Kanban est donc une méthode efficace pour impliquer vos collaborateurs et assurer un suivi détaillé de l'exécution de votre projet. Il est cependant important de comprendre que le Kanban est, selon les situations, parfois trop détaillé, et parfois pas assez." }, { "type": "paragraph", "text": "Par exemple, si vous faites une <a href=\"https://www.airsaas.io/fr/gestion-de-projet/la-revue-de-projet\" target=\"_blank\"><strong>revue de projet</strong></a> pour valider le passage à la phase suivante de votre projet, alors le Kanban vous servira de tremplin à vos discussions — vous devrez forcément rentrer davantage dans le détail au cours de vos échanges, mais c'est un bon support pour débattre." }, { "type": "paragraph", "text": "À l'inverse, si vous souhaitez qu'une personne qui ne connait pas votre projet puisse en comprendre les grandes lignes très rapidement, il se peut que le Kanban soit un support de communication un peu trop précis pour lui. Orientez-le plutôt vers la <a href=\"/fr/gestion-de-projet/fiche-projet-exemple-et-methodologie\" target=\"_blank\"><strong>fiche projet</strong></a>, qui est un contenu plus synthétique et donc idéal pour les personnes extérieures au projet." }, { "type": "paragraph", "text": "Si vous avez maintenant compris les limites du Kanban, alors vous pourrez en tirer son plein potentiel en l'utilisant dans les situations les plus appropriées !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8393b38147e34dd835ba5_62f38cb287c554817f76d1fe_Export-flash-min.jpeg", "alt": "export de la fiche projet", "caption": "Exportez votre fiche projet en un clic" }], "toc": [{ "label": "Qu'est-ce que c'est que la méthode Kanban ?", "href": "#quest-ce-que-cest-que-la-methode-kanban", "level": 2 }, { "label": "Pourquoi utiliser un Kanban dans la gestion de projet ?", "href": "#pourquoi-utiliser-un-kanban-dans-la-gestion-de-projet", "level": 2 }, { "label": "Kanban physique -vs- Kanban digital", "href": "#kanban-physique-vs-kanban-digital", "level": 2 }, { "label": "Le Kanban comme support de communication intermédiaire", "href": "#le-kanban-comme-support-de-communication-intermediaire", "level": 2 }], "faq": [], "related": [] }, { "slug": "kpi-gestion-de-projet", "skip": false, "meta": { "title": "Guide complet : les KPI dans la gestion de projet", "h1": "Guide complet : les KPI dans la gestion de projet", "description": "Les KPI de gestion de projet sont essentiels pour objectiver votre suivi de projet en chiffrant vos performances. Découvrez comment les utiliser efficacement.", "publishedDate": "8/10/2021", "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f38aa9d36866227251e8a0_1-2-min.jpg", "alt": "" } }, "blocks": [{ "type": "paragraph", "text": "Pour augmenter vos chances de réussite, il est essentiel d'assurer un suivi tout au long de l'exécution de votre projet. Le suivi de projet vise à contrôler que le déroulement de votre projet se passe bien comme vous l'aviez prévu et permet de réajuster votre stratégie en cas de besoin.<br>" }, { "type": "paragraph", "text": "Dans cette tâche, les KPI de gestion de projet sont essentiels : ce sont grâce à eux que vous pourrez objectiver votre suivi de projet chiffrant vos performances ! Ils doivent apparaitre dans <a href=\"/fr/solution/rapport-flash\" target=\"_blank\">le reporting projet</a> que vous envoyez aux différentes parties prenantes à intervalle régulier." }, { "type": "heading", "level": 2, "id": "les-kpi-quest-ce-que-cest", "text": "Les KPI : Qu'est-ce que c'est ?" }, { "type": "paragraph", "text": "Les KPI (Key Performance Indicators) ou indicateurs clés de performance sont utilisés pour évaluer les performances de vos projets.<br>‍<br>Ces indicateurs chiffrés vous permettent de bien sûr de connaitre votre état d'avancement sur vos objectifs, mais ils vous donnent surtout la possibilité de repérer les aspects de votre projet sur lesquels vous avez des difficultés, ainsi que ceux sur lesquels vous obtenez de bons résultats !<br><br>Les KPI permettent souvent de se rendre compte des points qu'il faut optimiser pour améliorer l'exécution d'un projet. Ce sont les garde-fous stratégiques de la gestion de projet !<br><br>Les KPI sont donc d'une grande aide dans le pilotage de projet : ils vous donnent un aperçu immédiat de l'état de votre projet à un instant T !" }, { "type": "paragraph", "text": "Et les informations données par les KPI vous aideront à prendre vos décisions : si les KPI sont bons, ne faites rien, s'ils indiquent que vous sous-performez, prenez des mesures correctives !" }, { "type": "paragraph", "text": "S'il existe des KPI qui sont communément utilisés par de nombreuses entreprises, l'idéal reste quand même de les personnaliser à vos équipes et votre projet." }, { "type": "paragraph", "text": "<strong>Une typologie des indicateurs a été dressée :</strong>" }, { "type": "list", "ordered": false, "items": ["<strong>les indicateurs de coûts</strong> : pour vérifier que vous ne dépassez pas les limites budgétaires de votre projet"] }, { "type": "list", "ordered": false, "items": ["<strong>les indicateurs de délais :</strong> pour s'assurer que vous respectez les délais prévus pour votre projet et éviter les retards"] }, { "type": "list", "ordered": false, "items": ["<strong>les indicateurs de qualité :</strong> pour contrôler la qualité du travail de votre équipe tout au long du projet"] }, { "type": "list", "ordered": false, "items": ["<strong>les indicateurs d'efficacité :</strong> pour suivre la gestion du projet, et vérifier que vos ressources (budgétaires, humaines, temporelles) sont utilisées de manière optimale !"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c837cd73ec2f8efeab7d0e_62f36ff388c0c330cc047df4_Project-progression-min.jpeg", "alt": "KPI kezako ?" }, { "type": "heading", "level": 2, "id": "pourquoi-utiliser-des-kpi", "text": "Pourquoi utiliser des KPI ?" }, { "type": "paragraph", "text": "Quiconque a déjà eu à gérer un projet sait que si l'on n'y prend pas garde, il y a de grandes chances qu'on dépasse les délais, qu'on explose les budgets, et que la qualité attendue ne soit pas au rendez-vous." }, { "type": "paragraph", "text": "Et c'est justement précisément le rôle des KPI de vous éviter de vous retrouver dans ce genre de situation. Grâce à eux, vous saurez continuellement où vous en êtes dans la réalisation de votre projet, sur chacun des aspects cités au-dessus, mais aussi sur tous ceux que vous voulez contrôler !" }, { "type": "paragraph", "text": "Libre à vous de créer vos propres KPI en fonction de vos besoins." }, { "type": "paragraph", "text": "Si l'on voulait illustrer l'intérêt des KPI, on pourrait comparer la gestion de projet au pilotage d'une fusée." }, { "type": "list", "ordered": false, "items": ["Comme votre projet, le vol d'une fusée est divisé en plusieurs phases (propulsée, balistique…) et le pilote doit savoir exactement quel est le moment idéal pour changer de phase !", "Comme pour votre projet, le pilote doit contrôler la trajectoire et la vitesse de sa fusée : ni trop lente, ni trop rapide, juste dans les temps !", "Comme pour votre projet, il est essentiel de connaître en temps réel la quantité de carburant restante pour éviter les mauvaises surprises !", "Comme pour votre projet, de nombreux voyants sont nécessaires pour veiller au bon fonctionnement de la fusée et éviter le crash !"] }, { "type": "paragraph", "text": "Pour résumer : prendriez-vous le risque de faire décoller une fusée sans aucun voyant lumineux ni indicateur ? Eh bien il serait (au moins) aussi suicidaire de se lancer dans le pilotage de votre projet, tout en souhaitant atteindre une exécution et une rentabilité optimales, sans l'aide d'indicateurs de performances !" }, { "type": "heading", "level": 2, "id": "comment-utiliser-des-kpi-pour-la-gestion-de-projet", "text": "Comment utiliser des KPI pour la gestion de projet ?" }, { "type": "heading", "level": 3, "id": "des-criteres-a-respecter-dans-leur-elaboration", "text": "Des critères à respecter dans leur élaboration" }, { "type": "paragraph", "text": "Si vous voulez que vos KPI soient efficaces et vous aider à piloter vos projets, vous devez respecter plusieurs critères. Un bon indicateur doit :" }, { "type": "list", "ordered": false, "items": ["être relié à un objectif particulier", "être mesurable tout au long du projet", "être défini dans le temps, sur une période donnée", "être assez simple pour que toutes les parties prenantes puissent le comprendre", "être orienté pour la prise de décision", "si possible être personnalisé aux besoins de votre équipe / projet"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c27_62f370f834986741dc2e6b30_Project-metrics.jpeg", "alt": "KPI critères" }, { "type": "heading", "level": 3, "id": "un-code-couleur-pour-faciliter-la-visibilite", "text": "Un code couleur pour faciliter la visibilité" }, { "type": "paragraph", "text": "Certaines personnes aiment utiliser un code couleur avec leur indicateur clé. Le code couleur le plus courant est :" }, { "type": "list", "ordered": false, "items": ["KPI vert : très bien, il faut continuer les actions qui vous ont permis d'atteindre ces résultats.", "KPI orange : à surveiller, est susceptible de s'améliorer comme de se détériorer.", "KPI rouge : il y a un problème, il faut absolument prendre des mesures pour corriger le tir."] }, { "type": "paragraph", "text": "L'intérêt d'un tel code est de faciliter la visibilité sur l'ensemble des aspects du projet que vous mesurez grâce à vos KPI. De cette manière, il devient encore plus facile de débattre de la priorisation des efforts avec votre équipe : en un coup d'oeil, chacun sait quels aspects du projet se portent bien, lesquels sont à surveiller et quels sont ceux qu'il faut absolument repenser." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c837cd73ec2f8efeab7cfd_62ea947e12a1db65655b1059_Projet-timeline-min.jpeg", "alt": "KPI code couleur" }, { "type": "heading", "level": 3, "id": "des-precautions-a-prendre-pour-mettre-en-place-des-kpi", "text": "Des précautions à prendre pour mettre en place des KPI" }, { "type": "paragraph", "text": "Lorsque vous déployez des KPI dans le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\">suivi de votre projet</a>, vous devez prendre quelques précautions afin de vous assurer de l'efficacité de vos KPI." }, { "type": "paragraph", "text": "<strong>Des précautions organisationnelles : </strong>Vous devez sélectionner les KPI en fonction des objectifs que vous avez discutés et fixé avec votre équipe projet. L'adoption des KPI sera simplifiée si chacun des membres de votre équipe comprend leur intérêt." }, { "type": "paragraph", "text": "Ensuite, vous devez assigner la responsabilité de chaque objectif aux personnes compétentes et définir les processus pour contrôler leur évolution dans le temps. Les responsabilités de chacun doivent être claires pour éviter les tensions au fur et à mesure de l'évolution du projet et des KPI." }, { "type": "paragraph", "text": "<strong>Des précautions techniques : </strong>il vous faudra adapter votre infrastructure de gestion de projet à vos KPI : votre manière de rédiger vos rapports et les logiciels que vous utilisez doivent être paramétrés pour permettre d'obtenir toutes les informations nécessaires à vos KPI. Ces changements peuvent prendre du temps, mais aussi perturber votre équipe projet : pensez à les briefer en amont sur l'intérêt de bousculer leurs habitudes au profit des KPI." }, { "type": "paragraph", "text": "<strong>Des précautions culturelles : </strong>Travailler avec des KPI a de nombreuses conséquences sur la manière de travailler de votre équipe : la responsabilisation, le suivi des performances de chacun ou encore le contrôle du respect des objectifs. L'idéal est de parvenir à avoir une discussion ouverte avec vos collaborateurs en amont de la mise en place des KPI : le concept leur plait-il ? En comprennent-ils l'utilité ? Ont-ils des appréhensions ?" }, { "type": "paragraph", "text": "Il est vraiment préférable de discuter dans le détail de tout ce qu'implique l'utilisation des KPI avec votre équipe projet, plutôt que de découvrir durant l'exécution que certains n'étaient pas prêt à changer leurs habitudes !" }, { "type": "paragraph", "text": "Il existe plusieurs astuces pour mettre vos collaborateurs en confiance :" }, { "type": "list", "ordered": false, "items": ["construisez vos KPI avec eux", "demandez-leur de vous confier leurs craintes", "organisez des retours d'expérience"] }, { "type": "heading", "level": 2, "id": "quels-sont-les-kpi-les-plus-utilises-les-kpi-de-couts", "text": "Quels sont les KPI les plus utilisés ? Les KPI de coûts" }, { "type": "list", "ordered": false, "items": ["<strong>KPI de coût réel</strong> : il représente le coût réel total du projet. Vous l'obtenez en additionnant toutes les dépenses", "<strong>KPI des coûts non planifiés</strong> : toutes les dépenses que vous n'aviez pas prévues initialement", "<strong>KPI des coûts de retards :</strong> vous pouvez ainsi chiffrer ce que vous coûtent vos retards.", "<strong>KPI de l'écart de coût du projet</strong> : la différence entre coût prévu du projet et son coût réel"] }, { "type": "heading", "level": 3, "id": "les-kpi-de-delais", "text": "Les KPI de délais" }, { "type": "list", "ordered": false, "items": ["<strong>KPI de taux de retard</strong> : le pourcentage des retards par rapport aux délais que vous aviez prévus", "<strong>KPI des durées de tâches</strong> : pour connaître le temps moyen nécessaire à la réalisation de toutes vos tâches"] }, { "type": "list", "ordered": false, "items": ["<strong>KPI d'écart de durée</strong> : comparer le temps que vous avez passé sur une tâche à celui que vous aviez initialement prévu", "<strong>KPI d'écart de délai</strong> : pour savoir si vous êtes en retard ou en avance sur le délai d'exécution global que vous aviez prévu pour le projet"] }, { "type": "heading", "level": 3, "id": "les-kpi-de-qualite", "text": "Les KPI de qualité" }, { "type": "list", "ordered": false, "items": ["<strong>KPI de satisfaction du client</strong> : il existe différentes manières de le mesurer - enquêtes de satisfaction, questionnaires, fidélisation des clients…", "<strong>KPI des plaintes du client</strong> : un des indicateurs-clés de performance sur le nombre de retours"] }, { "type": "heading", "level": 3, "id": "les-kpi-defficacite-et-davancement-du-projet", "text": "Les KPI d'efficacité et d'avancement du projet" }, { "type": "list", "ordered": false, "items": ["<strong>Le KPI du taux d'avancement</strong> : comparez le nombre de tâches accomplies à celui des tâches que vous aviez prévues pour connaitre le taux de progression de votre projet.", "<strong>Le KPI de l'efficience du temps passé sur le projet</strong> : comparez le nombre d'heures que vous avez passées sur le projet à celui que vous aviez prévu pour savoir si votre équipe est efficace."] }, { "type": "heading", "level": 2, "id": "le-tableau-de-bord-de-gestion-de-projet-et-les-kpi", "text": "Le tableau de bord de gestion de projet et les KPI" }, { "type": "paragraph", "text": "La plupart du temps, les KPI que vous allez créer seront réunis dans <a href=\"/fr/solution/tableau-de-bord-gestion-de-projet\" target=\"_blank\"><strong>un tableau de bord de gestion de projet</strong></a> : ce sont des outils simplifiant le pilotage des projets." }, { "type": "paragraph", "text": "Les tableaux de bord de gestion de projet permettent de faire une mesure de la performance de votre activité de manière constante afin d'optimiser vos processus de gestion de projets. De cette manière, vous pourrez utiliser les KPI de manière optimale et mettre toutes les chances de votre côté pour mener à bien vos projets." }], "toc": [{ "label": "Les KPI : Qu'est-ce que c'est ?", "href": "#les-kpi-quest-ce-que-cest", "level": 2 }, { "label": "Pourquoi utiliser des KPI ?", "href": "#pourquoi-utiliser-des-kpi", "level": 2 }, { "label": "Comment utiliser des KPI pour la gestion de projet ?", "href": "#comment-utiliser-des-kpi-pour-la-gestion-de-projet", "level": 2 }, { "label": "Quels sont les KPI les plus utilisés ? Les KPI de coûts", "href": "#quels-sont-les-kpi-les-plus-utilises-les-kpi-de-couts", "level": 2 }, { "label": "Le tableau de bord de gestion de projet et les KPI", "href": "#le-tableau-de-bord-de-gestion-de-projet-et-les-kpi", "level": 2 }], "faq": [], "related": [] }, { "slug": "la-revolution-numerique-au-sein-du-secteur-de-lindustrie-industrie-4-0", "skip": false, "meta": { "title": "La révolution numérique au sein du secteur de l'industrie : Industrie 4.0", "h1": "La révolution numérique au sein du secteur de l'industrie : Industrie 4.0", "description": "La révolution numérique au sein du secteur de l'industrie : Industrie 4.0", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f39029eb74964f0b9f547b_Project%20image%20copy-min.jpg", "alt": "" }, "author": { "category": "Gestion de projets" } }, "toc": [{ "label": "La supply chain débute avec les fournisseurs : comment la DSI accompagne le changement vers l'industrie 4.0?", "href": "#la-supply-chain-debute-avec-les-fournisseurs-comment-la-dsi-accompagne-le-changement-vers-lindustrie-40", "level": 2 }, { "label": "30 ans pour optimiser la supply chain : un processus long et fastidieux", "href": "#30-ans-pour-optimiser-la-supply-chain-un-processus-long-et-fastidieux", "level": 2 }, { "label": "Le défi de construire sa propre chaîne de production dans l'industrie 4.0", "href": "#le-defi-de-construire-sa-propre-chaine-de-production-dans-lindustrie-40", "level": 2 }, { "label": "Le best of breed tend à s'imposer face au modèle monolithe", "href": "#le-best-of-breed-tend-a-simposer-face-au-modele-monolithe", "level": 2 }, { "label": "Quand le marketing et l'IT travaille ensemble pour concevoir une solution", "href": "#quand-le-marketing-et-lit-travaille-ensemble-pour-concevoir-une-solution", "level": 2 }, { "label": "La maintenance connectée pour prévenir les pannes machines dans les lignes de production", "href": "#la-maintenance-connectee-pour-prevenir-les-pannes-machines-dans-les-lignes-de-production", "level": 2 }, { "label": "L'enjeu cybersécurité dans l'industrie 4.0 : comment rebondir après avoir subi une attaque massive ?", "href": "#lenjeu-cybersecurite-dans-lindustrie-40-comment-rebondir-apres-avoir-subi-une-attaque-massive", "level": 2 }, { "label": "Hypercroissance : d'une PME à une ETI industrielle", "href": "#hypercroissance-dune-pme-a-une-eti-industrielle", "level": 2 }], "blocks": [{ "type": "heading", "level": 2, "id": "la-supply-chain-debute-avec-les-fournisseurs-comment-la-dsi-accompagne-le-changement-vers-lindustrie-40", "text": "La supply chain débute avec les fournisseurs : comment la DSI accompagne le changement vers l'industrie 4.0?" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"Au vu de notre positionnement dans la chaîne de valeur, la DSI est clairement au centre de la relation de l'entreprise avec les fournisseurs et les clients pour résoudre leurs problèmes, améliorer les processus, et leur offrir une expérience simplifiée.\" - Olivier Fiquet dans l'épisode \"Quantifier et qualifier la performance de la supply chain grâce à l'IT\"</blockquote>" }, { "type": "quote", "text": "\"Au vu de notre positionnement dans la chaîne de valeur, la DSI est clairement au centre de la relation de l'entreprise avec les fournisseurs et les clients pour résoudre leurs problèmes, améliorer les processus, et leur offrir une expérience simplifiée.\"", "author": "Olivier Fiquet dans l'épisode \"Quantifier et qualifier la performance de la supply chain grâce à l'IT\"" }, { "type": "paragraph", "html": "Avec la pandémie de Covid-19 et la Guerre en Ukraine, la tension au sein de la supply chain est monté d'un cran, que ce soit du côté des fournisseurs. Dans ce premier podcast, Olivier Fiquet revient sur la relation qu'il entretient, en tant que DSI, avec ses fournisseurs. L'entreprise pour laquelle il travaille est en étroite relation avec des milliers de fournisseurs qui ont des maturités technologiques très différentes. Si certaines ont d'ores et déjà enclenché leur transformation, ce n'est pas forcément le cas pour d'autres qui ont besoin d'être accompagnées. Découvrons quelles techniques Olivier Fiquet qu'il a mise en œuvre pour réduire au maximum <a href=\"https://www.airsaas.io/podcast-cio-revolution/quantifier-et-qualifier-la-performance-de-la-supply-chain-grace-a-lit-olivier-fiquet\" target=\"_blank\">la tension de la supply chain</a>." }, { "type": "paragraph", "html": "Face au manque de référentiel et de maturité de ce premier maillon de la supply chain, il est intéressant de voir que la DSI d'un groupe a la volonté d'aider ses fournisseurs à faire des choix technologiques ou à utiliser de bonnes plateformes. Pour tenir les promesses clients en termes de coûts et de délais, Olivier Fiquet et ses équipes souhaitent obtenir <strong>le plus d'informations possibles autour de la réception des matières premières</strong>. Sans avoir une supply chain numérisée, cela n'est pas possible." }, { "type": "paragraph", "html": "À titre d'exemple, Olivier Fiquet présente son projet : avec l'aide de ses équipes, celui-ci a mis en place un outil spécifique et adapté pour ses fournisseurs. Cette solution a pour but de relancer ces derniers à l'aide de notifications et de mails afin qu'ils puissent envoyer à temps toutes les informations nécessaires quant à l'arrivée des matières premières. Grâce à l'envoi d'une notification au bon moment, les fournisseurs sont informés et peuvent tenir les délais." }, { "type": "paragraph", "html": "En parallèle, <strong>l'enjeu au niveau de la donnée est très important</strong>. Par moments, les métiers ou les fournisseurs n'obtiennent pas les données nécessaires à temps ce qui brise la supply chain. Dans d'autres situations, elle se retrouve avec un très grand nombre d'informations pas forcément structurées. La difficulté réside dans la sélection et la classification de la donnée, de bien comprendre ce qui est de l'ordre de l'urgent ou de l'important pour que la supply chain soit performante. La relation entre les métiers et les fournisseurs est un pilier pour le passage vers <a href=\"https://www.airsaas.io/fr/secteur/industrie-transformation-digitale\" target=\"_blank\">l'industrie 4.0</a>" }, { "type": "heading", "level": 2, "id": "30-ans-pour-optimiser-la-supply-chain-un-processus-long-et-fastidieux", "text": "30 ans pour optimiser la supply chain : un processus long et fastidieux" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"Pendant des années, nous avons travaillé sur l'infra-logistique de nos lignes de fabrication afin de la simplifier, de l'optimiser, notamment grâce à l'arrivée de l'automatisation et des machines. [...] Le système industriel que l'entreprise possède aujourd'hui est l'aboutissement de projets ayant commencé il y a plus de 25 ans.\" Daniel Freyd dans l'épisode \"La DSI au centre de chaque étape de la supply chain\"</blockquote>" }, { "type": "quote", "text": "\"Pendant des années, nous avons travaillé sur l'infra-logistique de nos lignes de fabrication afin de la simplifier, de l'optimiser, notamment grâce à l'arrivée de l'automatisation et des machines. [...] Le système industriel que l'entreprise possède aujourd'hui est l'aboutissement de projets ayant commencé il y a plus de 25 ans.\"", "author": "Daniel Freyd dans l'épisode \"La DSI au centre de chaque étape de la supply chain\"" }, { "type": "paragraph", "html": "Daniel Freyd revient sur les trente années où son entreprise a été en constante transformation. Depuis son arrivée, il y maintenant vingt ans, il a énormément travaillé, lui et toutes ses équipes afin de faire évoluer la <a href=\"https://www.airsaas.io/podcast-cio-revolution/la-dsi-au-centre-de-chaque-etape-de-la-supply-chain-daniel-freyd\" target=\"_blank\">supply chain</a>. De la modélisation de l'aménagement des pièces à vivre, jusqu'à la pose des meubles, chaque maillon de la supply chain a été accompagné par la DSI :" }, { "type": "list", "ordered": false, "items": ["<strong>Enregistrement de la commande en magasin</strong> : un concepteur-vendeur discute avec le client de l'ensemble des produits que ces derniers souhaitent acheter.", "Envoi de la commande aux fournisseurs : la DSI envoie de manière automatiser des prévisions sur la quantité de matières premières souhaitée par l'entreprise.", "<strong>Établissement du capacité planning et du capacity machine</strong> : avec plusieurs milliers de meubles envoyés chaque jour, des outils mis au point par la DSI permettent de vérifier l'ensemble des disponibilités au niveau de la main-d'œuvre, des outils de construction, des lieux de construction, etc. Le tout en respectant à la lettre la demande des clients.", "<strong>La maintenance des machines</strong> : la DSI a pour objectif d'éviter les pannes insoutenables (une panne de plus de deux heures a des conséquences lourdes sur le business).", "<strong>Fabrication des meubles et contrôle qualité</strong> : des outils ont été conçus en interne (grâce à l'IA et à la vision par ordinateur) afin de contrôler chaque meuble au plus vite.", "<strong>Envoi, livraison et pose</strong> : la DSI intervient une dernière fois avec ses partenaires logistiques qu'elle accompagne également."] }, { "type": "paragraph", "html": "De plus, selon les périodes de l'année, la supply chain et la chaîne de production sont plus ou moins sollicitées. Avec les autres directions métiers, la DSI prend le temps de trouver des solutions, que ce soit au niveau des ressources humaines (recrutement des opérateurs, formation adaptée, gestion de la main-d'œuvre, etc.), mais aussi au niveau des fournisseurs (prendre également en compte leur calendrier) et de la data (prise de commande, confirmation, suivi)." }, { "type": "paragraph", "html": "On voit clairement toute la difficulté et les nombreux paramètres qu'a dû prendre en compte l'entreprise afin d'optimiser la supply chain. Il est impressionnant de voir à quel point que le système d'information est imbriqué dans l'ensemble des étapes de la supply chain pour apporter un maximum d'informations." }, { "type": "heading", "level": 2, "id": "le-defi-de-construire-sa-propre-chaine-de-production-dans-lindustrie-40", "text": "Le défi de construire sa propre chaîne de production dans l'industrie 4.0" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"A Fuji Electric France, on a conçu nous même notre chaîne de production, qui est différente de la maison mère située au Japon. C'est un véritable succès collectif car des bancs techniques ont été conçus il y a maintenant vingt ans et continuent de fonctionner aujourd'hui.\" Pierre Duriez dans l'épisode \"Une DSI indépendante des choix de la société mère : l'exemple de Fuji Electric\"</blockquote>" }, { "type": "quote", "text": "\"A Fuji Electric France, on a conçu nous même notre chaîne de production, qui est différente de la maison mère située au Japon. C'est un véritable succès collectif car des bancs techniques ont été conçus il y a maintenant vingt ans et continuent de fonctionner aujourd'hui.\"", "author": "Pierre Duriez dans l'épisode \"Une DSI indépendante des choix de la société mère : l'exemple de Fuji Electric\"" }, { "type": "paragraph", "html": "Le DSI de Fuji Electric France, Pierre Duriez, nous explique comment sa filiale a réussi à se détacher de la <a href=\"https://www.airsaas.io/podcast-cio-revolution/une-dsi-independante-des-choix-de-la-societe-mere-lexemple-de-fuji-electric-pierre-duriez\" target=\"_blank\">chaîne de production</a> de la société mère en mettant en place sa propre chaîne de production. La branche française de cette entreprise a décidé de faire appel à la DSI pour y parvenir. Les équipes de Pierre Duriez ont porté le lead dans la structuration de l'équipe projet :" }, { "type": "paragraph", "html": "Premièrement, il y a eu <strong>un travail autour de l'utilisation de briques pouvant communiquer les unes avec les autres</strong>. L'objectif est d'apporter une aide aux différents business units travaillant dans la chaîne de production dans leurs tâches du quotidien. Pour choisir ces solutions, la DSI est passée par une <a href=\"https://www.airsaas.io/fr/innovation-veille-technologique\" target=\"_blank\">veille technologique</a> active, s'appuyant sur de vraies expériences et pas uniquement sur les présentations que peuvent faire les éditeurs. Ils ont notamment testé plusieurs solutions afin de les comparer grâce à des proof of concept et sont allés au contact d'entreprises qui exploitaient des solutions qui les intéressaient. Au lieu d'avoir une solution tout-en-un beaucoup plus complexe à manipuler, il se trouve avec un \"SI en légo\" dont les briques sont connectées entre elles." }, { "type": "paragraph", "html": "Deuxièmement, il s'est intéressé à <strong>la collaboration qui existe entre les différentes entités et ces différentes briques métiers</strong>. Dans les deux collaborations, l'enjeu principal est le transfert (envoi et réception) de la data et de l'information. En travaillant autour des flux de données, la DSI a fait en sorte que chaque entité puisse avoir facilement accès aux données qui la concernent. En maîtrisant la donnée, l'entreprise a aussi la possibilité de tracer l'ensemble des faits et gestes de chaque maillon de la chaîne de production. Cela permet d'avoir accès à des reportings ou des tableaux de bords détaillés et donc, de favoriser la prise de décision pour améliorer la performance de la chaîne." }, { "type": "paragraph", "html": "Troisièmement, la DSI s'est penchée sur la question suivante : <strong>comment prioriser les projets d'amélioration en continu ?</strong> Selon l'importance des projets, ces derniers sont priorisés selon le temps passé à leur réalisation. La projection à très court terme est imposée pour les tâches du quotidien ou pour les problèmes qu'il faut très vite résoudre. La projection sur le moyen terme permet de se laisser un peu plus de temps pour améliorer ou renouveler l'existant. Enfin, la projection sur le long terme permet de lancer des projets structurants (nouvelles fonctionnalités, nouvelles briques, etc.)." }, { "type": "heading", "level": 2, "id": "le-best-of-breed-tend-a-simposer-face-au-modele-monolithe", "text": "Le best of breed tend à s'imposer face au modèle monolithe" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"Il y a un très fort besoin d'agilité dans cette entreprise. Il peut exister des périodes creuses où on ne va pas spécialement avoir besoin de nous, mais à tout moment, un projet peut très vite arriver. [...] Maintenant, est-ce que pour le bien de l'entreprise, il faut aller vers du monolithe ou peaufiner, aller plus en profondeur dans le modèle best of breed ?\" - Serge Maurey dans l'épisode \"Le modèle best of breed contre le modèle monolithe pour un maximum d'agilité\"</blockquote>" }, { "type": "quote", "text": "\"Il y a un très fort besoin d'agilité dans cette entreprise. Il peut exister des périodes creuses où on ne va pas spécialement avoir besoin de nous, mais à tout moment, un projet peut très vite arriver. [...] Maintenant, est-ce que pour le bien de l'entreprise, il faut aller vers du monolithe ou peaufiner, aller plus en profondeur dans le modèle best of breed ?\"", "author": "Serge Maurey dans l'épisode \"Le modèle best of breed contre le modèle monolithe pour un maximum d'agilité\"" }, { "type": "paragraph", "html": "DSI du groupe CMR, Serge Maurey s'est longtemps posé la même question : doit-il travailler pour structurer son SI en un seul bloc ou bien que celui-ci est composé de nombreuses briques technologiques ? Plutôt que d'adopter une suite logicielle \"tout-en-un\" provenant d'un seul éditeur, il se questionne autour des briques qu'il peut utiliser autour d'un ERP centralisé." }, { "type": "paragraph", "html": "Revenons sur l'exemple présenté par Serge Maurey : à son arrivée au sein de cette entreprise, le DSI de la firme s'appuyait sur un ERP central gérant une bonne partie des besoins métiers mais pas tous. En plus de cela, certaines solutions périphériques à cet ERP étaient déjà utilisées par les métiers. En prenant le temps d'analyser son socle SI, Serge Maurey a pris en compte que le SI était déjà sous la forme d'un modèle <a href=\"https://www.airsaas.io/podcast-cio-revolution/le-modele-best-of-breed-contre-le-modele-monolithe-pour-un-maximum-dagilite-serge-maurey\" target=\"_blank\">best of breed</a>. Il a impliqué ses équipes afin de le parfaire." }, { "type": "paragraph", "html": "Deux changements significatifs permettant la mise en place d'un modèle best of breed plus prononcé, remettant en question le périmètre de l'ERP :" }, { "type": "list", "ordered": false, "items": ["De plus en plus de <strong>solutions SaaS</strong>, spécifiques à certains besoins, sont développées. Ces outils sont très intéressants pour les métiers car ils tentent de répondre à leurs attentes globales et possèdent de très bonnes API.", "<strong>Les outils d'intégration d'API</strong> se sont également améliorés, ce qui permet d'intégrer toutes les solutions souhaitées bien plus facilement qu'avant. Il est plus facile d'interconnecter les solutions SaaS et gérer la synchronisation."] }, { "type": "paragraph", "html": "Ainsi, on voit que la mise en place d'un modèle monolithe tend à disparaître au profit du modèle best of breed. La véritable interrogation étant de définir le champ d'action de l'ERP et de savoir si l'on propose de plus en plus de briques pour les directions métiers. Cette question semble guider les DSI pour qu'une entreprise industrielle tende vers l'industrie 4.0" }, { "type": "heading", "level": 2, "id": "quand-le-marketing-et-lit-travaille-ensemble-pour-concevoir-une-solution", "text": "Quand le marketing et l'IT travaille ensemble pour concevoir une solution" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"On a tout fait pour que Thibault (directeur du marketing) n'ait pas l'étiquette du Product Owner alors qu'il n'avait pas les compétences nécéssaires pour l'être, même si ironiquement, il l'a indirectement été : c'est lui qui porte le métier, qui sait ce qui se passe sur le terrain et qui a donc tranché quand il fallait prendre des décisions importantes.\" Jean-Stève Hadjistavrou accompagné de Thibault Cognon dans l'épisode \"Quand la DSI et le marketing s'allient pour créer un service dans l'industrie\"</blockquote>" }, { "type": "quote", "text": "\"On a tout fait pour que Thibault (directeur du marketing) n'ait pas l'étiquette du Product Owner alors qu'il n'avait pas les compétences nécéssaires pour l'être, même si ironiquement, il l'a indirectement été : c'est lui qui porte le métier, qui sait ce qui se passe sur le terrain et qui a donc tranché quand il fallait prendre des décisions importantes.\"", "author": "Jean-Stève Hadjistavrou accompagné de Thibault Cognon dans l'épisode \"Quand la DSI et le marketing s'allient pour créer un service dans l'industrie\"" }, { "type": "paragraph", "html": "Voici un exemple concret de transformation vers une industrie 4.0 : quand le métier et la DSI s'associent et collaborent pour concevoir un service ensemble, pour ses clients. C'est le cas de l'entreprise Sames Kremlin avec la direction marketing &amp; innovation de Thibault Cognon. Ce dernier a sollicité la direction des systèmes d'information de Jean-Stève Hadjistavrou afin d'automatiser le pilotage des robots industriels." }, { "type": "paragraph", "html": "Le double objectif de ce projet est le suivant : <strong>remédier au manque d'effectif qualifié</strong> et éviter de perdre du temps dans <strong>la formation de nouveaux opérateurs</strong>. Ainsi, en travaillant main dans la main, <a href=\"https://www.airsaas.io/podcast-cio-revolution/quand-la-dsi-et-le-marketing-sallient-pour-creer-un-service-dans-lindustrie-\" target=\"_blank\">le marketing et la DSI</a> travaillent pour le business." }, { "type": "paragraph", "html": "Dans le cadre de cette relation, chaque direction a apporté sa pierre à l'édifice et a accompagné l'autre afin que chacun puisse mettre ses compétences au profit du projet. Le marketing a apporté un maximum d'information à la DSI afin de faciliter son travail en étant présent dans les usines. Cette présence a permis à la direction marketing de prendre les décisions quant à l'avancement du projet. D'un autre côté, la DSI s'est focalisée sur tout l'aspect technologique du projet. Les deux entités ont fait équipe en se posant toujours la même question : qu'est-ce que nous souhaitons obtenir à la fin ?" }, { "type": "paragraph", "html": "Les deux entités ont posé ensemble les contraintes techniques et juridiques liées au projet afin d'avancer en connaissance de cause. Le fait d'associer la DSI et la direction métier afin d'atteindre un même but a permis de faire naître un nouveau service client." }, { "type": "heading", "level": 2, "id": "la-maintenance-connectee-pour-prevenir-les-pannes-machines-dans-les-lignes-de-production", "text": "La maintenance connectée pour prévenir les pannes machines dans les lignes de production" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"La maintenance prédictive, l'idée, c'est d'arriver à anticiper des pannes de machines dans les lignes de production, de manière à éviter un arrêt brutal. Ainsi, il est possible de réparer la machine pour que la panne ne se produise jamais. C'est mon tout nouveau défi.\" Alexis de Nervaux dans l'épisode \"La maintenance prédictive dans l'industrie 4.0\"</blockquote>" }, { "type": "quote", "text": "\"La maintenance prédictive, l'idée, c'est d'arriver à anticiper des pannes de machines dans les lignes de production, de manière à éviter un arrêt brutal. Ainsi, il est possible de réparer la machine pour que la panne ne se produise jamais. C'est mon tout nouveau défi.\"", "author": "Alexis de Nervaux dans l'épisode \"La maintenance prédictive dans l'industrie 4.0\"" }, { "type": "paragraph", "html": "Alexis de Nervaux, déjà intervenu dans le cadre du podcast CIO Révolution (ep.16 - \"Avoir la double casquette CIO &amp; CDO\") revient dans cette saison dédié à la révolution numérique dans l'industrie. Celui-ci évoque l'un de ses derniers projets qu'il a en tête depuis maintenant plusieurs mois. Ce projet s'appuie sur le constant suivant : éviter la moindre panne machine provoquant des retards dans la production. Par effet boule de neige, les délais ne sont pas respectés, ce qui peut affecter l'image de marque." }, { "type": "paragraph", "html": "La <a href=\"https://www.airsaas.io/podcast-cio-revolution/la-maintenance-predictive-dans-lindustrie-alexis-de-nervaux\" target=\"_blank\">maintenance connectée</a> consiste à <strong>anticiper les défaillances machines</strong>. En allant au-devant d'une panne ou d'un dysfonctionnement, il est possible d'engager les réparations nécessaires afin qu'elles ne produisent jamais. Bien choisies, les solutions de maintenance connectée constitue une véritable aide pour la prise de décision dans des situations critiques. Bien entendu, pour que cela puisse fonctionner, il faut que la solution choisie soit la plus performante possible, alors même que le parc de machine est très hétérogène. Alexis de Nervaux s'est lancé dans un processus strict de sélection :" }, { "type": "list", "ordered": false, "items": ["Première étape : <strong>analyser le marché des solutions de maintenance connectée</strong> pour comprendre leur fonctionnement, comprendre les différentes techniques et méthodes utilisées, faire une liste des fonctionnalités, voir comment elles peuvent être mises en place à petite, moyenne ou grande échelle, voir si ces solutions sont faciles d'utilisation, etc.", "Seconde étape : <strong>choisir un petit panel de solutions à tester au sein d'une usine</strong> choisie au préalable, c'est le projet \"smart maintenance\". En choisissant une seule usine (en l'occurrence une où les pannes peuvent être fréquentes), Alexis de Nervaux a testé trois solutions différentes. Il a pu se rendre rapidement compte que la première ne convenait absolument pas, que la seconde n'était pas adaptée aux besoins de l'entreprise, et que la troisième était celle qu'il allait privilégier sur le long terme.", "Troisième étape : tenter d'<strong>établir un périmètre plus important</strong> pour déployer la solution à plus grand échelle en identifiant les usines pour lesquelles, la maintenance prédictive serait la plus performante."] }, { "type": "paragraph", "html": "Ironiquement, puisque ces tests-là sont concluants tout en apportant un éclairage sur cette technologie aux usines et aux opérateurs, certaines usines ont voulu s'emparer de ce projet beaucoup plus rapidement que ce qu'avait prévu Alexis de Nervaux. Par moments, il est difficile d'impliquer les métiers dans certains projets, mais quand ces projets fonctionnent et ont de l'intérêt pour les métiers, ces derniers prennent le temps de s'y intéresser. Parfois, il peut y avoir un emballement dans le déploiement de la solution, les métiers voulant absolument acquérir l'outil. C'est à la DSI de freiner le jeu et de faire en sorte que le déploiement se passe pour le mieux." }, { "type": "paragraph", "html": "La maintenance connectée et plus largement les outils d'intelligence artificielle ou liées à l'internet des objets sont des exemples concrets prouvant que l'innovation peut aider les entreprises à se transformer." }, { "type": "heading", "level": 2, "id": "lenjeu-cybersecurite-dans-lindustrie-40-comment-rebondir-apres-avoir-subi-une-attaque-massive", "text": "L'enjeu cybersécurité dans l'industrie 4.0 : comment rebondir après avoir subi une attaque massive ?" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"On est passé d'une société qui avait l'habitude de mettre gérer son budget au cas par cas, qui n'a pas pour habitude de consacrer une grosse partie de son chiffre d'affaire à l'IT, vers une entreprise qui a un positionnement quasi digital, dans lequel le budget IT est bien supérieur et tourné vers d'autres sujets comme la sécurité.\" - Sylvain Coquio dans l'épisode \"La cybersécurité dans le monde de l'industrie\"</blockquote>" }, { "type": "quote", "text": "\"On est passé d'une société qui avait l'habitude de mettre gérer son budget au cas par cas, qui n'a pas pour habitude de consacrer une grosse partie de son chiffre d'affaire à l'IT, vers une entreprise qui a un positionnement quasi digital, dans lequel le budget IT est bien supérieur et tourné vers d'autres sujets comme la sécurité.\"", "author": "Sylvain Coquio dans l'épisode \"La cybersécurité dans le monde de l'industrie\"" }, { "type": "paragraph", "html": "Le 21 février 2021, l'entreprise Manutan subit de plein fouet le ransomware DoppelPaymer. Sylvain Coquio, DSI du groupe Manutan est revenu sur la manière dont l'entreprise a rebondi après avoir subi une telle attaque. Après une longue restructuration au niveau de sa <a href=\"https://www.airsaas.io/podcast-cio-revolution/la-cybersecurite-dans-le-monde-de-lindustrie-sylvain-coquio\" target=\"_blank\">cybersécurité</a>, Manutan a su se relever et rebondir en s'appuyant sur quatre piliers fondamentaux :" }, { "type": "list", "ordered": false, "items": ["<strong>La concrète refonte du SI.</strong> Dès que celui-ci a été attaque, l'ensemble de l'entreprise ne fonctionnait plus. Toute l'entreprise s'est aperçue de l'importance du système d'information. Dans le cadre où le système d'information d'une entreprise est obsolète, vieillissant et pas ordonnée, il y a de grandes chances que celui-ci soit très vulnérable et une proie facile pour les hackeurs. Le legacy constitue une porte d'entrée mal verrouillée pour ces personnes malveillantes. Sylvain Coquio s'est donc attelé à reprendre en main le legacy et à proposer de nouvelles solutions indépendantes les unes des autres.", "<strong>Le recrutement de nouvelles compétences.</strong> Lors de chaque trimestre, Sylvain Coquio fait le point en faisant appel à des spécialistes de la cybersécurité afin de comprendre, connaître et assimiler les tendances et nouveaux risques que les entreprises peuvent encourir. De plus, une nouvelle direction a été créée : la direction Marketing Business Technology (MBT), présente au Comex dans le but de créer une synergie entre les équipes marketing, les équipes d'expérience client, l'e-commerce, la data, le master data management et l'IT.", "<strong>Le changement du paradigme budgétaire.</strong> L'entreprise a progressivement augmenté son budget IT afin de se tourner vers un positionnement plus digital. Cela génère d'immenses attentes, notamment auprès des directions métiers qui sont impatientes d'obtenir de nouvelles composantes. Sylvain Coquio doit aller jongler entre les projets sur le long terme (comme la refonte de la SI), la proposition de solutions sur le court terme pour assouvir les besoins des business units.", "<strong>La sensibilisation des collaborateurs.</strong> Manutan a lancé de grandes campagnes de formation afin de sensibiliser chaque employé autour des gestes et des notions basiques pour éviter tout nouveau risque d'attaque. Chaque nouvelle recrue passe par cette formation obligatoire et doit répondre à un test validant les acquis qu'il doit maîtriser. Si l'évaluation n'est pas réussie, celui-ci doit suivre à nouveau la formation."] }, { "type": "paragraph", "html": "Grâce à un travail concret mené autour de ces quatre piliers, Manutan a réussi à se relever après avoir subi une attaque de grande envergure. Involontairement, cette cyberattaque a également prouvé que toutes les entités de l'entreprise étaient capable de collaborer et de se serrer les coudes pour résoudre des problèmes tout en transformant l'entreprise. La cybersécurité est un enjeu primordial pour l'industrie 4.0." }, { "type": "heading", "level": 2, "id": "hypercroissance-dune-pme-a-une-eti-industrielle", "text": "Hypercroissance : d'une PME à une ETI industrielle" }, { "type": "insight-callout", "label": "Citation", "html": "<blockquote>\"Pour moi, lorsqu'une entreprise comme une PME devient une ETI, c'est à ce moment-là qu'elle se rend compte qu'elle n'a plus que jamais besoin de la DSI. [...] Aujourd'hui, nos principaux clients sont d'immenses groupes. Ils demandent logiquement à ce qu'on ait des interconnexions avec eux du même niveau que les leurs. Pour être capable de se mettre à niveau, on est obligé de surperformer.\" Emmanuel Artigue dans l'épisode \"Les enjeux SI d'une PME qui se transforme en ETI\"</blockquote>" }, { "type": "quote", "text": "\"Pour moi, lorsqu'une entreprise comme une PME devient une ETI, c'est à ce moment-là qu'elle se rend compte qu'elle n'a plus que jamais besoin de la DSI. [...] Aujourd'hui, nos principaux clients sont d'immenses groupes. Ils demandent logiquement à ce qu'on ait des interconnexions avec eux du même niveau que les leurs. Pour être capable de se mettre à niveau, on est obligé de surperformer.\"", "author": "Emmanuel Artigue dans l'épisode \"Les enjeux SI d'une PME qui se transforme en ETI\"" }, { "type": "paragraph", "html": "Dans ce dernier podcast, Emmanuel Artigue, DSI de Toupret, évoque les enjeux SI d'une PME qui se mue en ETI. Il s'agit d'un moment clé de la vie d'une entreprise où l'IT a totalement son rôle à jouer. Grâce à son déploiement à l'international, l'entreprise est en croissance constante depuis près de 20 ans et a réussi à franchir le seuil des 250 collaborateurs depuis peu." }, { "type": "paragraph", "html": "La direction IT d'Emmanuel Artigue tente d'accompagner les filiales de l'entreprise dans leur stratégie de transformation tout en gérant leur hypercroissance. Ces filiales sont semi-intégrées : si certaines d'entre elles ont pris le parti d'intégrer l'ERP de la maison mère, d'autres ont fait le choix d'être indépendantes de par leur taille ou de par la spécificité du marché dans lequel elles sont. Pour essayer de \"lutter\" contre l'élargissement du shadow IT, Emmanuel Artigue a préféré <strong>s'adapter, vivre avec, et accompagner</strong> ces entités afin de leur fournir un maximum d'agilité." }, { "type": "paragraph", "html": "Afin d'accélérer la transformation de l'entreprise, il a été obligé <strong>d'externaliser certaines compétences</strong>, afin de passer de 90 % des compétences en interne à un équilibre parfait entre compétences externes et interne. À terme, il souhaite que près de deux tiers des compétences soient externalisés afin que les équipes en interne puissent se focaliser sur des projets structurants et en lien avec la croissance de l'entreprise." }, { "type": "paragraph", "html": "Pour Emmanuel Artigue, le DSI accompagne ce passage de <a href=\"https://www.airsaas.io/podcast-cio-revolution/les-enjeux-si-dune-pme-qui-se-transforme-en-eti-emmanuel-artigue\" target=\"_blank\">PME à ETI</a> grâce <strong>aux multiples casquettes</strong> du rôle qu'il endosse. Il concilie les profils du technologue (en tant que spécialiste de l'IT), du stratège (celui qui va continuellement se demander comment l'IT va apporter à l'entreprise) et de l'opérationnel (pour faire en sorte faire évoluer la culture d'entreprise vers la transformation). C'est avec un DSI pilotant la transformation grâce aux différentes casquettes qu'il possède que les entreprises transitent vers l'industrie 4.0." }], "faq": [], "related": [] }, { "slug": "la-revue-de-projet", "skip": false, "meta": { "title": "La revue de projet : un point d'étape pour tirer les leçons de vos erreurs", "h1": "La revue de projet : un point d'étape pour tirer les leçons de vos erreurs ", "description": "La revue de projet est un point d'étape essentiel pour impliquer vos collaborateurs, booster la collaboration et apprendre de vos erreurs de conduite de projet.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3712bd6406519fcf1cc3e_2.jpg", "alt": "" }, "author": { "name": "Simon Vacher", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e038501c4256317123910b_SV-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Dans vos processus de suivi de projet, il arrivera que vous passiez des étapes clés (auxquelles vous aurez potentiellement assorti des jalons projets)." }, { "type": "paragraph", "text": "Il est alors recommandé d'organiser des revues projet : des réunions pour impliquer vos collaborateurs, booster la collaboration et apprendre de vos erreurs de <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c837cd73ec2f8efeab7cfd_62ea947e12a1db65655b1059_Projet-timeline-min.jpeg", "alt": "Le calendrier et les jalons pendant une revue de projet", "caption": "Calendrier / roadmap et jalons" }, { "type": "heading", "level": 2, "id": "a-quoi-sert-une-revue-de-projet-quest-ce-quune-revue-de-projet", "text": "À quoi sert une revue de projet ? Qu'est-ce qu'une revue de projet ?" }, { "type": "paragraph", "text": "Le premier et principal objectif d'une revue projet est de <strong>réunir l'ensemble des acteurs d'un projet</strong> afin de faire le point sur l'avancée du projet, et de valider les livrables qui y sont associés. " }, { "type": "paragraph", "text": "En plus de l'objectif officiel, cette est un outil de management de projet idéal pour favoriser la cohésion de votre équipe : discussion autour de la vision de chacun, partage des informations, échange d'expertises, développement de l'intelligence collective, etc… " }, { "type": "paragraph", "text": "La revue projet est <strong>l'un des ingrédients principaux d'une équipe projet soudée</strong>, efficace et engagée et donc l'un des leviers pour augmenter les chances de réussite de votre projet ! " }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c837cd73ec2f8efeab7d09_62f36ff388c0c330cc047df4_Project-progression-min.jpeg", "alt": "Airsaas vous aide à gérer vos revues de projets" }, { "type": "heading", "level": 3, "id": "revue-de-projet-et-jalon", "text": "Revue de projet et jalon" }, { "type": "paragraph", "text": "Lors de la planification d'un projet, on le construit autour de différentes étapes clés qui rythment son exécution. Et ces étapes d'un projet sont généralement représentées par <a href=\"https://www.airsaas.io/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\">des jalons</a> : en validant un jalon, on atteste qu'une des phases du projet a été exécutée et qu'il est possible de passer à la suivante ! " }, { "type": "paragraph", "text": "C'est donc au cours de la revue projet que l'on décide formellement de la validation d'un jalon et donc de l'avancée potentielle du projet à la phase d'après. " }, { "type": "paragraph", "text": "Les revues de projet ont donc lieu à chaque fin de phase majeure et sont souvent planifiées dès le début par le chef de projet. Les décisions prises en revue de projet sont généralement irrévocables et servent d'appui pour la suite de l'exécution du projet. " }, { "type": "heading", "level": 2, "id": "quels-sont-les-differents-types-de-revue-de-projet", "text": "Quels sont les différents types de revue de projet ?" }, { "type": "paragraph", "text": "Certains types de revue sont spécifiquement orientés sur l'un des aspects du projet. " }, { "type": "paragraph", "text": "On retrouve souvent : " }, { "type": "list", "ordered": false, "items": ["<strong>La revue de projet budgétaire</strong> : elle est centrée sur le contrôle des dépenses et des recettes. Elle fait partie de la <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">gestion budgétaire</a> et permet de suivre les écarts de budgets, de formuler de nouvelles prévisions ou encore de procéder à des réajustements. "] }, { "type": "list", "ordered": false, "items": ["<strong>La revue des phases de sprint</strong> : la revue de projet permet de clore les phases de sprint dans le cadre de projets \"agiles\". Il est ainsi possible d'évaluer ce qui a été exécuté, de réajuster ses décisions, et de valider le passage au sprint suivant. "] }, { "type": "list", "ordered": false, "items": ["<strong>La revue de fabrication d'un produit :</strong> elle permet, lorsqu'un projet est axé autour d'un produit, de valider toutes les étapes autour de la fabrication de ce dernier, et de préparer la suite de son développement. ."] }, { "type": "heading", "level": 2, "id": "a-quoi-sert-une-revue-de-projet", "text": "À quoi sert une revue de projet ? " }, { "type": "paragraph", "text": "Les revues de projet ont des objectifs et bénéfices multiples." }, { "type": "paragraph", "text": "Elles servent notamment à : " }, { "type": "list", "ordered": false, "items": ["Assurer le <strong>suivi du projet général,</strong> du déroulement du projet"] }, { "type": "list", "ordered": false, "items": ["<strong>Vérifier</strong> que tous les objectifs d'une phase ont été atteints "] }, { "type": "list", "ordered": false, "items": ["<strong>Contrôler</strong> le respect des échéances et délais "] }, { "type": "list", "ordered": false, "items": ["Donner une <strong>vision unique</strong>, claire et transparente du projet à toutes les parties prenantes du projet "] }, { "type": "list", "ordered": false, "items": ["<strong>Discuter des problèmes</strong> que chacun a rencontrés dans ses dossiers afin de trouver collectivement des solutions"] }, { "type": "list", "ordered": false, "items": ["<strong>Débattre</strong> de réajustements potentiels "] }, { "type": "list", "ordered": false, "items": ["<strong>Prendre des décisions</strong> sur la suite du projet "] }, { "type": "list", "ordered": false, "items": ["<strong>Renforcer la <a href=\"https://www.collock.com/2020/08/25/comment-renforcer-cohesion-equipe-nouveau-projet/\" target=\"_blank\">cohésion</a> de l'équipe</strong> "] }, { "type": "list", "ordered": false, "items": ["<strong>Créer des habitudes</strong> collaboratives entre les membres de l'équipe"] }, { "type": "heading", "level": 2, "id": "quand-devez-vous-organiser-votre-revue-de-projet", "text": "Quand devez-vous organiser votre revue de projet ?" }, { "type": "paragraph", "text": "La réponse est simple : organisez ce type de réunion à la fin de chaque étape majeure du projet. Pour le dire autrement : vous devez réunir vos parties prenantes dans une revue de projet au passage d'un jalon - l'objectif étant de savoir si tout est prêt pour passer à l'étape suivante de l'avancement du projet." }, { "type": "heading", "level": 2, "id": "qui-inviter-a-la-revue-de-projet", "text": "Qui inviter à la revue de projet ?" }, { "type": "paragraph", "text": "Tous les décisionnaires du projet doivent être présents à une revue de projet pour qu'elle soit efficace, et que les décisions qui régissent la suite du projet soient prises sur le moment même. Invitez-y donc les responsables des métiers impliqués, mais aussi vos sponsors, ainsi que les responsables de certains livrables si nécessaire (pour répondre à des questions techniques éventuelles)." }, { "type": "paragraph", "text": "Mais attention à ne pas tomber dans l'écueil de vouloir inviter tous les acteurs du projet ! Seuls les participants dont la présence est essentielle pour faire avancer le projet doivent être invités - faute de quoi, votre revue risque de devenir peu efficace." }, { "type": "heading", "level": 2, "id": "comment-faire-une-bonne-revue-de-projet", "text": "Comment faire une bonne revue de projet ?" }, { "type": "heading", "level": 3, "id": "des-precautions-a-prendre-en-amont-et-en-aval", "text": "Des précautions à prendre en amont et en aval" }, { "type": "paragraph", "text": "<strong>En amont :</strong>" }, { "type": "paragraph", "text": "Comme pour les autres types de réunion, le temps alloué à ce processus n'est pas illimité. Il faut donc impérativement prendre le temps de la préparer en amont, afin que le temps prévu soit utilisé de manière optimale et que la revue soit productive." }, { "type": "paragraph", "text": "Plusieurs étapes sont donc nécessaires : définir un ordre du jour, un lieu, la liste des parties prenantes, mais aussi créer les supports visuels nécessaires à la revue." }, { "type": "paragraph", "text": "Dans l'idéal, il est conseillé que le chef de projet transmette en amont du rendez-vous ou <a href=\"https://www.airsaas.io/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">comité de pilotage</a> toutes les informations relatives à la revue de projet à chacun des participants : ainsi tout le monde sait déjà précisément ce qui va être discuté sur le dossier." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8380767e281be1d4a267a_62f3705b50d8018cf3599412_Attention-point.jpeg", "alt": "illustration de l'outil Airsaas", "caption": "Tout pour faciliter les réunions de l'équipe projet" }, { "type": "paragraph", "text": "<strong>En aval :</strong>" }, { "type": "list", "ordered": false, "items": ["<strong>Rédiger un compte rendu</strong> : il est primordial d'envoyer un résumé de ce qui a été discuté à l'ensemble des parties impactées par la revue de projet"] }, { "type": "list", "ordered": false, "items": ["<strong>Écrire</strong> noir sur blanc <strong>les conclusions</strong> : vous devez formaliser toutes les décisions prises, ainsi que les nouvelles tâches à mener par l'équipe à la prochaine étape"] }, { "type": "list", "ordered": false, "items": ["<strong>Assurer un suivi</strong> : mettre en place des routines de contrôle des actions décidées durant la revue."] }, { "type": "paragraph", "text": "Ces différentes étapes vous permettront de <strong>piloter, responsabiliser et d'impliquer tous les membres de votre équipe</strong> sur le projet, et de vous assurer que ce qui a été décidé en revue de projet soit bien appliqué !  " }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8380767e281be1d4a266d_62f3708b0d180f44e5121377_post-report.jpeg", "alt": "illustration de l'outil Airsaas" }, { "type": "heading", "level": 2, "id": "quelques-astuces-pour-une-revue-de-projet-efficace", "text": "Quelques astuces pour une revue de projet efficace" }, { "type": "heading", "level": 3, "id": "eviter-de-rentrer-trop-dans-les-details", "text": "Éviter de rentrer trop dans les détails" }, { "type": "paragraph", "text": "Le temps à votre disposition n'est pas infini, ne le gâchez pas ! D'autant plus que vous risquez de perdre l'attention de votre auditoire si vous commencez à entrer dans des détails qui échappent à ceux qui ne travaillent pas avec vous quotidiennement." }, { "type": "heading", "level": 3, "id": "prenez-le-temps-de-mettre-en-avant-vos-reussites", "text": "Prenez le temps de mettre en avant vos réussites" }, { "type": "paragraph", "text": "Il y a toutes les chances pour que des difficultés et des imprévus soient survenus lors de l'exécution de la phase de votre projet que vous cherchez à valider. Cependant, les revues de projet ne doivent pas miner le moral des troupes, il faut mieux citer les problèmes principaux auxquels vous avez dû faire face, mais aussi mettre en avant vos réussites et féliciter ceux qui en sont responsables. " }, { "type": "heading", "level": 3, "id": "faites-le-lien-entre-le-passe-et-le-futur-de-votre-projet", "text": "Faites le lien entre le passé et le futur de votre projet" }, { "type": "paragraph", "text": "Vous devez évidemment faire le point sur la phase du projet que vous venez d'exécuter, en tirer les enseignements importants, et discuter de ce qui aurait pu être optimisé. Mais il faut absolument que vous preniez le temps de discuter du prochain jalon durant la revue de projet. Chaque collaborateur doit sortir galvanisé par la prochaine phase qui l'attend, comprendre pourquoi elle est essentielle au projet et quelles sont les tâches dont il sera responsable !" }, { "type": "heading", "level": 3, "id": "utilisez-le-pouvoir-des-retrospectives", "text": "Utilisez le pouvoir des rétrospectives " }, { "type": "paragraph", "text": "Utilisez les rétros pour identifier les forces et les faiblesses d'une étape et améliorer les futurs travaux. Discutez des différentes techniques rétrospectives, telles que la méthode « commencer, arrêter, continuer » ou la méthode « \"glad, sad, mad », et comment elles peuvent aider les équipes à réfléchir sur ce qui s'est bien passé et sur ce qui doit être amélioré." }, { "type": "heading", "level": 3, "id": "tirer-parti-des-outils-interconnectes", "text": "Tirer parti des outils interconnectés" }, { "type": "paragraph", "text": "Les outils comme AirSaas lorsqu'ils sont connectés à Jira ou Asana, aideront le DSI / PMO et chef de projet à suivre un état d'avancement de façon macro et à identifier les domaines qui nécessitent une attention particulière. Fournissez des conseils sur l'utilisation combinée de ces outils, tels que la configuration de tableaux de bord ou l'utilisation de l'automatisation pour rationaliser les flux de travail." }, { "type": "heading", "level": 3, "id": "developpez-une-culture-damelioration-continue", "text": "Développez une culture d'amélioration continue" }, { "type": "paragraph", "text": "Discuter de la manière de favoriser une culture d'amélioration continue au sein d'une organisation. Cela peut inclure des stratégies comme encourager les commentaires des membres de l'équipe, célébrer les succès et être ouvert aux nouvelles idées. Partagez des exemples de la façon dont cette culture peut mener à suivre un avancement de manière plus efficace." }, { "type": "heading", "level": 3, "id": "evitez-les-pieges-courants", "text": "Évitez les pièges courants" }, { "type": "paragraph", "text": "Offrez un aperçu des pièges courants de la gestion de projet et comment les éviter. Par exemple, discutez des risques de dérive de la portée, du manque d'implication des parties prenantes ou d'une mauvaise communication, et fournissez des conseils sur la façon d'atténuer ces risques." }, { "type": "heading", "level": 2, "id": "revue-de-projet-et-kpi-de-gestion-de-projet", "text": "Revue de projet et KPI de gestion de projet " }, { "type": "paragraph", "text": "La revue de projet est l'un des éléments les plus efficaces pour permettre à toutes les parties prenantes de faire le point sur l'avancée du sujet. Dans ce contexte, il peut vraiment être intéressant de vous servir de <strong>KPI de gestion de projet </strong>: ils seront la base de tous vos débats, et vous permettront d'objectiver vos performances pour être plus pertinents dans vos analyses.<br><br>Utiliser les KPI de gestion de projet durant vos revues de projet vous aidera à être certain d'être passé à la phase suivante du projet, sans avoir loupé aucune des leçons que vous deviez tirer de vos difficultés." }, { "type": "paragraph", "text": "Sur ce sujet, la <strong>lecture suivante conseillée</strong> est celle de l'article <a href=\"/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\"><strong>le jalon projet : une technique pour séquencer vos projets intelligemment.</strong></a>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c27_62f370f834986741dc2e6b30_Project-metrics.jpeg", "alt": "Suivi et gestion des ressources et du projet dans Airsaas" }], "toc": [{ "label": "À quoi sert une revue de projet ? Qu'est-ce qu'une revue de projet ?", "href": "#a-quoi-sert-une-revue-de-projet-quest-ce-quune-revue-de-projet", "level": 2 }, { "label": "Quels sont les différents types de revue de projet ?", "href": "#quels-sont-les-differents-types-de-revue-de-projet", "level": 2 }, { "label": "À quoi sert une revue de projet ? ", "href": "#a-quoi-sert-une-revue-de-projet", "level": 2 }, { "label": "Quand devez-vous organiser votre revue de projet ?", "href": "#quand-devez-vous-organiser-votre-revue-de-projet", "level": 2 }, { "label": "Qui inviter à la revue de projet ?", "href": "#qui-inviter-a-la-revue-de-projet", "level": 2 }, { "label": "Comment faire une bonne revue de projet ?", "href": "#comment-faire-une-bonne-revue-de-projet", "level": 2 }, { "label": "Quelques astuces pour une revue de projet efficace", "href": "#quelques-astuces-pour-une-revue-de-projet-efficace", "level": 2 }, { "label": "Revue de projet et KPI de gestion de projet ", "href": "#revue-de-projet-et-kpi-de-gestion-de-projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "le-diagramme-de-gantt-comment-sen-servir", "skip": false, "meta": { "title": "Le diagramme de Gantt : comment s'en servir ?", "h1": "Le diagramme de Gantt : comment s'en servir ?", "description": "Le diagramme de Gantt est l'un des outils les plus utilisés pour simplifier le suivi de projet. Focus sur cet outil de gestion de projet, ses bénéfices et la méthode pour créer le vôtre.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37f2a1470938aca6b9824_5-2.jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "7/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "7/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Le diagramme de Gantt est l'un des outils les plus utilisés pour simplifier le suivi de projet. Sa simplicité visuelle permet à chacun de visualiser en un instant l'ensemble des tâches à accomplir et les délais assortis. C'est un des \"musts have\" de la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet.</a>" }, { "type": "paragraph", "text": "Focus ici sur cet outil de gestion de projet, ses bénéfices et la méthode pour créer le vôtre." }, { "type": "heading", "level": 2, "id": "quest-ce-quun-diagramme-de-gantt-pour-la-gestion-de-projet", "text": "Qu'est-ce qu'un diagramme de Gantt pour la gestion de projet ?" }, { "type": "paragraph", "text": "L'origine du nom de ce diagramme provient de son créateur : Henry Gantt. Il a mis au point son outil au début du XXème siècle avec un objectif en tête : optimiser l'organisation du travail en atelier. Si au début le diagramme de Gantt est bien plus efficace pour organiser les petits projets, il sera perfectionné par Morgan Walker et James Kelley et leur méthode CPM (<em>Critical Path Method</em>). Il deviendra alors apte à améliorer la planification et l'exécution de projets de bien plus grande envergure." }, { "type": "paragraph", "text": "Le diagramme de Gantt est aujourd'hui considéré comme l'un des meilleurs outils pour organiser et planifier les tâches nécessaires à l'exécution de projets." }, { "type": "paragraph", "text": "Son principe est simple :" }, { "type": "list", "ordered": false, "items": ["On retrouve en ordonnée la liste des tâches à réaliser", "Et en abscisse les unités de temps"] }, { "type": "paragraph", "text": "Le diagramme de Gantt permet donc au chef de projet d'avoir une visibilité globale de l'ensemble des tâches et des délais qui leur sont assorties. Plus le rectangle qui représente la tâche est long, plus le temps qu'on aura dédié à l'exécution de cette tâche est important." }, { "type": "paragraph", "text": "Les tâches peuvent être connectées entre elles : dans ce cas là, on sait que l'une ne peut pas commencer tant que la première n'est pas terminée. Le diagramme de Gantt est donc l'une des manières d'éviter de se retrouver face à un goulot d'étranglement et de prendre du retard sur les délais planifiés." }, { "type": "paragraph", "text": "Grâce à sa simplicité visuelle, le diagramme de Gantt permet à chacun, qu'il connaisse bien le projet ou pas du tout, de saisir en un coup d'œil les différentes activités à réaliser pour mener à bien le projet, ainsi que leur organisation dans le temps." }, { "type": "heading", "level": 2, "id": "pourquoi-en-faire-un", "text": "Pourquoi en faire un ?" }, { "type": "paragraph", "text": "Utiliser un diagramme de Gantt pour la gestion de projet présente de nombreux avantage, en voici quelques-uns :" }, { "type": "list", "ordered": false, "items": ["Il offre une visibilité précise sur la chronologie d'un projet : chaque collaborateur peut voir à tout moment quelles sont les tâches à effectuer et sous quels délais. Le diagramme de Gantt peut d'ailleurs être un soutien du planning projet.", "Structurer toute sorte de projets complexes : le diagramme de Gantt est un outil universel. Il est utilisable pour tous les domaines d'activité puisque tous les projets sont découpés en tâches, assorties de délais et bien souvent de jalons. Et le diagramme vous permet de simplifier la vision qu'ont vos collaborateurs du projet : il distingue les étapes et éclaire toute l'équipe sur le chemin qu'elle doit emprunter.", "Respecter les délais : le diagramme de Gantt est un outil très efficace pour estimer les délais de réalisation de vos tâches, et donc la charge de travail à y affecter. Vous pouvez ainsi gérer au mieux vos ressources temporelles et humaines en les affectant au bon endroit, et planifier intelligemment l'échéancier du projet.", "Prioriser les différentes tâches : les projets peuvent comporter des dizaines de tâches différentes à mener. Il devient alors compliqué d'y voir clair : quelle tâche faut-il absolument effectuer maintenant ? Laquelle peut attendre ? Le diagramme de Gantt appliqué à la gestion de projet vous permet de repérer les chemins critiques en quelques secondes, et vous aide donc à organiser vos efforts pour optimiser votre efficacité !"] }, { "type": "heading", "level": 2, "id": "comment-creer-un-diagramme-de-gantt", "text": "Comment créer un diagramme de Gantt ?" }, { "type": "paragraph", "text": "Plusieurs méthodologies existent - en voici une en 5 étapes." }, { "type": "heading", "level": 3, "id": "1-listez-toutes-vos-taches", "text": "1 ) Listez toutes vos tâches" }, { "type": "paragraph", "text": "Réunissez toutes les parties prenantes de votre projet et demandez-leur de lister l'ensemble des tâches qu'ils doivent réaliser : vous obtiendrez la totalité des tâches qui doivent être effectuées pour réaliser votre projet." }, { "type": "paragraph", "text": "N'hésitez pas à assortir chacune de ses tâches de ses sous-tâches, qui peuvent elles-mêmes être subdivisées en actions (sous la forme de \"bullet points\" par exemple)." }, { "type": "paragraph", "text": "L'objectif est de ne rien oublier : plus votre diagramme sera exhaustif, plus vos chances de tenir vos délais seront grandes. Placez ensuite l'ensemble de ces tâches, sous-tâches et actions (si c'est nécessaire) sur la gauche de diagramme." }, { "type": "heading", "level": 3, "id": "2-affectez-vos-ressources-a-chaque-tache", "text": "2) Affectez vos ressources à chaque tâche" }, { "type": "paragraph", "text": "Vous devez ensuite affecter chacune de vos ressources (budgétaire, humaines, etc…) à vos tâches et sous-tâches. Par exemple vous devez déterminer quelle quantité de travail fournira chacune de vos équipes sur les différentes tâches que vous avez listées." }, { "type": "paragraph", "text": "Et vous pouvez aussi rentrer un peu plus dans le détail, en affectant la charge de travail de chacun de vos collaborateurs sur des sous tâches ou même des actions." }, { "type": "heading", "level": 3, "id": "3-planifiez-dans-le-temps", "text": "3) Planifiez dans le temps" }, { "type": "paragraph", "text": "Lorsque vous avez listé toutes vos tâches et effectué la gestion des ressources de votre projet, il vous faudra les organiser chronologiquement. L'objectif est ici de trouver l'ordre de réalisation idéal de vos différentes tâches." }, { "type": "paragraph", "text": "Pour chacune d'entre elles, décidez donc d'une date de début, et de fin. Prenez le temps d'évaluer correctement le temps nécessaire à l'exécution de chacune de ces tâches." }, { "type": "heading", "level": 3, "id": "4-connectez-vos-taches-entre-elles", "text": "4) Connectez vos tâches entre elles" }, { "type": "paragraph", "text": "L'idée ici est d'éviter de vous retrouver coincé dans votre management de projet parce que la réalisation d'une tâche conditionnait le début de l'exécution d'une autre. Et justement : en liant deux tâches entre elles, vous pourrez visualiser à tout moment que l'une est dépendante de l'autre dans le chemin critique du diagramme." }, { "type": "paragraph", "text": "Pensez à différencier plusieurs types de connexions différentes :" }, { "type": "list", "ordered": false, "items": ["Parfois une tâche ne peut pas être commencée avant qu'une autre ne soit finie", "Mais il arrive aussi que le début d'une tâche soit conditionné par le début d'une autre", "Il peut aussi arriver que les connexions soient multiples : par exemple, quand la réalisation de plusieurs tâches est nécessaire à l'exécution d'une autre"] }, { "type": "insight-callout", "label": "À noter", "html": "À noter qu'une tâche peut avoir plusieurs tâches antérieures obligatoires. Dans ce cas, il faut que ces tâches soient toutes terminées pour entamer la suivante. Inversement, une tâche peut avoir plusieurs tâches postérieures. Dans ce cas, la fin de cette tâche conditionne le début des autres." }, { "type": "heading", "level": 3, "id": "5-integrez-des-jalons", "text": "5) Intégrez des jalons" }, { "type": "paragraph", "text": "Les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/jalon-projet\" target=\"_blank\">jalons projet</a> correspondent aux étapes clés de votre projet. En les définissant et en anticipant les échéances importances, vous augmentez votre visibilité sur l'exécution de votre projet. En les intégrant à votre diagramme de Gantt pour la gestion de projet, vous pourrez visualiser en un coup d'oeil les différentes phases et grandes étapes de votre projet." }, { "type": "heading", "level": 2, "id": "gantt-ou-kanban", "text": "Gantt ou Kanban ?" }, { "type": "paragraph", "text": "Le diagramme de Gantt vous donne une visibilité globale sur l'ensemble des tâches que vous devez accomplir ainsi que les dates auxquelles vous devez les avoir réalisées. <a href=\"http://www.airsaas.io/fr/gestion-de-projet/kanban-gestion-de-projet\" target=\"_blank\">Le <strong>Kanban</strong></a> lui, vous permettra d'entrer davantage dans le détail de la réalisation de votre projet." }, { "type": "paragraph", "text": "La méthode Kanban offre donc différents avantages complémentaires au diagramme de Gantt : vous pouvez suivre l'état d'avancement de chaque tâche, impliquez vos collaborateurs et vous en servir comme support pour vos réunions. Coupler ces deux outils de planification peut donc être un atout pour votre projet !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c8393b38147e34dd835bab_62f37ed0147093c2a56b9627_Project-kanban-min.jpeg", "alt": "Vue kanban projet", "caption": "Vue kanban d'un projet" }, { "type": "paragraph", "text": "Après Gantt, (re)découvrez <a href=\"/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\">le jalon projet</a> : une technique pour séquencer vos projets intelligemment." }], "toc": [{ "label": "Qu'est-ce qu'un diagramme de Gantt pour la gestion de projet ?", "href": "#quest-ce-quun-diagramme-de-gantt-pour-la-gestion-de-projet", "level": 2 }, { "label": "Pourquoi en faire un ?", "href": "#pourquoi-en-faire-un", "level": 2 }, { "label": "Comment créer un diagramme de Gantt ?", "href": "#comment-creer-un-diagramme-de-gantt", "level": 2 }, { "label": "Gantt ou Kanban ?", "href": "#gantt-ou-kanban", "level": 2 }], "faq": [], "related": [] }, { "slug": "le-grand-guide-de-la-conduite-de-projet", "skip": false, "meta": { "title": "Le grand guide de la conduite de projet", "h1": "Le grand guide de la conduite de projet", "description": "Vous êtes DSI/CIO, Directeur des études, Chef de projet senior, PMO et souhaitez réfléchir à la meilleure façon de mettre en place une culture projet pour réussir votre transformation ?", "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "10/5/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea94cb5bd878297241d8d0_Project%20image%20(4)-min.jpg", "alt": "" }, "publishedDate": "10/5/2022" }, "toc": [{ "label": "Comment mettre en place une démarche de projet dans votre entreprise ?", "href": "#comment-mettre-en-place-une-demarche-de-projet-dans-votre-entreprise", "level": 2 }, { "label": "Comment faire un bon cadrage projet ?", "href": "#comment-faire-un-bon-cadrage-projet", "level": 2 }, { "label": "Comment budgétiser un projet ?", "href": "#comment-budgetiser-un-projet", "level": 2 }, { "label": "Comment organiser votre conduite de projet ?", "href": "#comment-organiser-votre-conduite-de-projet", "level": 2 }, { "label": "4 réunions pour assurer le pilotage de vos projets au quotidien", "href": "#4-reunions-pour-assurer-le-pilotage-de-vos-projets-au-quotidien", "level": 2 }, { "label": "Plan de communication projet : comment éviter l'échec ?", "href": "#plan-de-communication-projet-comment-eviter-lechec", "level": 2 }, { "label": "Comment élaborer un reporting projet efficace ?", "href": "#comment-elaborer-un-reporting-projet-efficace", "level": 2 }, { "label": "Tout savoir sur la fiche projet", "href": "#tout-savoir-sur-la-fiche-projet", "level": 2 }, { "label": "Le pilotage de projet moderne", "href": "#le-pilotage-de-projet-moderne", "level": 2 }], "blocks": [{ "type": "paragraph", "html": "Vous êtes DSI/CIO, Directeur des études, Chef de projet senior, PMO et souhaitez&nbsp;réfléchir à la meilleure façon de mettre en place une culture projet pour réussir votre transformation&nbsp;? D'optimiser votre management de projet ? Vous êtes au bon endroit !" }, { "type": "paragraph", "html": "Après avoir lancé avec succès le podcast CIO Révolution, nous voulons&nbsp;créer la communauté des Pros de la Transfo.<strong>&nbsp;</strong>pour diffuser un savoir caché : \"Le COMMENT réussir à se transformer ?\" Dans ce cadre, nous vous proposons un dossier grand format, contenant une sélection d'articles pleins d'<strong>astuces opérationnelles pour aider les personnes à challenger leurs organisations de manière pragmatique et efficiente.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62796cd16c490f28ef313472_management-projet.jpeg", "alt": "Pro de la Transfo avec AirSaas.io", "caption": "Tout pour devenir un \"Pro de la Transfo\"." }, { "type": "heading", "level": 2, "id": "comment-mettre-en-place-une-demarche-de-projet-dans-votre-entreprise", "text": "Comment mettre en place une démarche de projet dans votre entreprise ?" }, { "type": "paragraph", "html": "Savoir taper un texte sur Word fait-il de nous un bon écrivain ? Non ! De la même manière, maîtriser un outil de GP, ou un diagramme de Gantt ne fera jamais de nous un champion du management de projet." }, { "type": "paragraph", "html": "Partage des responsabilités, parallélisation des tâches, reporting, analyse des risques...Le concept de démarche de projet traite de la manière de piloter, de l'art de se servir des outils et enfin de la meilleure approche pour coordonner l'action<strong>.</strong>" }, { "type": "paragraph", "html": "Une définition académique nous rappelle qu'un projet recouvre \"l'ensemble des actions menées par une équipe de travail pendant une période prédéfinie pour réaliser ou modifier un produit ou un service afin de répondre au besoin de l'entreprise ou d'un client.\"" }, { "type": "paragraph", "html": "Problème : le projet, tout le monde connaît, mais, généralement, personne ne met la même définition et démarche de réalisation derrière<strong>.</strong>" }, { "type": "paragraph", "html": "Très éloignée de l'organisation classique à laquelle les entreprises sont habituées, cette démarche implique de <strong>bien prendre en compte les typologies de projets</strong> : micros, stratégiques, multiprojets, transverses, internes...&nbsp;Bref : de vraiment partir d'une typologie claire pour cerner les trois grands types de démarche de cadrage / exécution." }, { "type": "paragraph", "html": "<strong>Standardiser votre démarche rendra votre culture de livraison plus efficace </strong>et répondra&nbsp;également&nbsp;au besoin d'uniformité du reporting<strong>&nbsp;</strong>dans l'entreprise." }, { "type": "paragraph", "html": "Plus qu'une méthode universelle on s'intéressera ici à un ensemble, à plusieurs étapes à ne pas rater pour déjouer les pièges de la conduite de projet." }, { "type": "paragraph", "html": "Pour en savoir davantage, suivez le guide : lisez cet article : \"<a href=\"/gestion-de-projet/comment-mettre-une-demarche-de-projet-dans-mon-entreprise\" target=\"_blank\">Comment mettre une démarche de projet dans mon entreprise</a>\"." }, { "type": "heading", "level": 3, "id": "comment-reussir-un-projet-transverse", "text": "Comment réussir un projet transverse ?" }, { "type": "paragraph", "html": "Coopérer dans un projet transversal, c'est <strong>casser les silos de l'entreprise</strong>. Cela ne s'improvise pas. Un projet de transformation implique en effet de nombreux acteurs et processus qui sont, généralement, issus de services différents. Pas facile d'être efficace et présent sur tous les fronts !" }, { "type": "paragraph", "html": "Dans ce contexte, il faudra réinventer le management de projet, pour travailler en transversalité<strong>.</strong>" }, { "type": "paragraph", "html": "Il y a trois grands prérequis à connaître" }, { "type": "list", "ordered": true, "items": ["Un alignement avec la stratégie d'entreprise", "La problématique doit être \"DUR\" : Douloureuse, Urgente et Reconnue", "Un budget précis alloué"] }, { "type": "paragraph", "html": "Nous allons vous faire changer de regard sur la façon de (vraiment) collaborer<strong> </strong>sans lien hiérarchique - mais pas sans encadrement !" }, { "type": "paragraph", "html": "Construction de l'équipe transverse, rationalisation, méthode pour dérisquer : on vous dit tout sur les éléments clés d'une bonne exécution en management de projet dans l'article :&nbsp;<a href=\"/gestion-de-projet/comment-reussir-un-projet-transverse\" target=\"_blank\">Comment réussir un projet transverse ?</a>" }, { "type": "heading", "level": 2, "id": "comment-faire-un-bon-cadrage-projet", "text": "Comment faire un bon cadrage projet ?" }, { "type": "paragraph", "html": "Peu importe votre entreprise, sa taille, et son secteur d'activité... 80% des retards sur les projets IT sont dus à un mauvais cadrage !" }, { "type": "paragraph", "html": "On va s'intéresser au&nbsp;<strong>contenu de la note de cadrage dans le management de projet</strong>. En quelque sorte une&nbsp;version préparatoire du cahier des charges, y compris sur les aspects techniques." }, { "type": "paragraph", "html": "La note est utilisée pour optimiser la future exécution de vos projets. Pour accompagner les équipes de gestion de projet à se poser les bonnes questions (problème à résoudre, gains attendus, objectifs / programmes auxquels il contribue, critères et fonctionnalités indispensables, effort / budget que suis-je prêt à investir, etc.). Réaliser ce cadrage de façon collaborative avec le métier ou l'IT sur des canevas projets standardisés est une très bonne pratique. C'est le prix à payer pour se préparer à conduire un projet efficace !" }, { "type": "paragraph", "html": "Découvrez&nbsp;<a href=\"/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\">comment faire un bon cadrage projet&nbsp;</a>dans cet article." }, { "type": "heading", "level": 3, "id": "comment-mener-lanalyse-des-risques-projet", "text": "Comment mener l'analyse des risques projet ?" }, { "type": "paragraph", "html": "L'expérience nous apprend que&nbsp;rien ne se passe jamais comme prévu en gestion de projet. Et que, si l'on n'y prend pas garde, il y a de grandes chances qu'on \"explose\" les délais, les budgets - et qu'en prime, la qualité attendue ne soit pas au rendez-vous ! Plus que des aléas et imprévus, l'objectif est bien de réduire les accidents avec une vraie prise en compte et maîtrise en continu du risque." }, { "type": "paragraph", "html": "Dans la gestion de projet classique,<strong>&nbsp;</strong>la pratique courante consiste à identifier, évaluer et prévenir (ou atténuer) les risques d'un projet susceptibles d'avoir un impact sur les résultats souhaités. Dans la réalité, cette pratique est souvent une action réalisée \"une fois pour toutes\", au moment du lancement - et, à défaut d'une vraie maîtrise, avait souvent tendance à ressembler à une usine à gaz Excel." }, { "type": "paragraph", "html": "Pourtant, <strong>la gestion des risques n'a peut-être jamais été aussi importante qu'aujourd'hui</strong>. Au-delà de la maîtrise d'un objectif initial et du célèbre ensemble \"coût-qualité-délai\", comment fait-on vivre l'analyse des risques&nbsp;tout au long du projet<strong>&nbsp;</strong>?&nbsp;Une analyse des risques projet vous aidera à multiplier vos chances de réussite. On vous dit tout sur le pourquoi et le comment la mettre en œuvre et surtout comment ne pas transformer ce processus vital, en usine à gaz \"mortelle\" !" }, { "type": "paragraph", "html": "Vous aimez les risques ? Lisez l'article le plus à jour sur&nbsp;<a href=\"/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">l'analyse des risques projet</a>&nbsp;!" }, { "type": "heading", "level": 3, "id": "tout-savoir-sur-la-note-de-cadrage-projet", "text": "Tout savoir sur la note de cadrage projet" }, { "type": "paragraph", "html": "Le chef de projet n'a&nbsp;pas pour seule mission&nbsp;d'assurer le suivi de l'exécution. Il est aussi impliqué dans les&nbsp;phases amont&nbsp;et de&nbsp;définition&nbsp;des actions projet." }, { "type": "paragraph", "html": "Et à ce stade, notre meilleur conseil pourrait être de vous proposer de retarder le plaisir de lancer un chantier pour en<strong> </strong>vérifier la viabilité<strong>.</strong> Pour vérifier qu'il possède le minimum de qualités nécessaires pour parvenir à son terme." }, { "type": "paragraph", "html": "C'est l'objet de la note de cadrage. Afin de pouvoir l'aborder dans les meilleures dispositions&nbsp;il devra, dans un&nbsp;<strong>document unique</strong>, rassembler&nbsp;<strong>toutes les informations clés&nbsp;issues des</strong>&nbsp;<strong>analyses techniques préalables</strong>&nbsp;au lancement. Un document qui lui permettra de&nbsp;définir le \"scope\"&nbsp;et les objectifs de son projet et d'en&nbsp;partager les informations essentielles&nbsp;avec toutes les personnes qui seront&nbsp;impliquées dans son déroulement<strong>.</strong>" }, { "type": "paragraph", "html": "C'est le premier \"média\" précis qui sera évalué par vos parties prenantes. Un élément fondamental de votre management de projet." }, { "type": "paragraph", "html": "Ce document de synthèse s'appelle une note de cadrage. Elle présentera le&nbsp;contexte&nbsp;du projet, les&nbsp;objectifs&nbsp;à atteindre,&nbsp;l'organisation générale... Bref, tout ce qui sera nécessaire pour&nbsp;bien&nbsp;cadrer le projet et<strong>&nbsp;sécuriser&nbsp;sa&nbsp;réalisation</strong>." }, { "type": "paragraph", "html": "Découvrez les contenus incontournables à faire figurer dans une note de cadrage<strong> : </strong><a href=\"/gestion-de-projet/la-revue-de-projet\" target=\"_blank\">Tout savoir sur la note de cadrage projet.</a>" }, { "type": "heading", "level": 2, "id": "comment-budgetiser-un-projet", "text": "Comment budgétiser un projet ?" }, { "type": "paragraph", "html": "Si, après plusieurs mois de travail, on se rend compte que l'on n'a pas le budget nécessaire pour amener le projet à son terme, ça fait mauvais genre... C'est pourtant l'une des causes d'échec projet les plus courantes !" }, { "type": "paragraph", "html": "D'où l'importance<strong> </strong>de savoir définir un budget et surtout de <strong>chiffrer une problématique pour prioriser les plans d'investissement.</strong>" }, { "type": "paragraph", "html": "On peut citer par exemple le piège classique d'un budget 100% \"build\" qui fait l'impasse sur les coûts liés à l'exploitation et la maintenance du RUN. Ou encore celui du budget statique jamais réévalué. Ou encore le grand classique : celui du budget parfait - qui omet la réserve de trésorerie afin de pouvoir faire face aux imprévus.&nbsp; Dans les grands programmes immobiliers du secteur du bâtiment, ce sont près de 30% des coûts qui sont ainsi provisionnés pour les aléas liés aux délais et malfaçons." }, { "type": "paragraph", "html": "Dans l'article \"Comment budgétiser un projet ?\", nous vous livrons nos meilleurs conseils pour faire mieux avec les mêmes moyens afin de soigner votre porte-monnaie. Et pourquoi pas permettre au comité de pilotage d'attribuer des augmentations méritées !" }, { "type": "paragraph", "html": "Vous êtes à un clic de <a href=\"/gestion-de-projet/tout-savoir-sur-le-budget-previsionnel-projet\" target=\"_blank\">tout savoir sur le budget prévisionnel projet.</a>" }, { "type": "heading", "level": 3, "id": "budgetiser-un-projet-sans-se-louper", "text": "Budgétiser un projet sans se louper" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6295e341854a1bf807e32d15_airsaas-budget-min.jpg", "alt": "Les estimations de délai et coût projet seraient toutes fausses !", "caption": "Les estimations de délai et coût projet seraient toutes fausses !" }, { "type": "paragraph", "html": "Le budget est le <strong>média clé dans votre démarche de projet</strong>. Au-delà de permettre d'avoir une visibilité détaillée sur l'ensemble de recettes et des dépenses de votre projet. Grâce à lui, vous pouvez anticiper les obstacles que vous pourriez rencontrer et fixer un cap !" }, { "type": "paragraph", "html": "Vous pensez maîtriser les bases du budget prévisionnel ?" }, { "type": "paragraph", "html": "Pourtant&nbsp;53% des projets dépassent de 189% leurs prévisions budgétaires !" }, { "type": "paragraph", "html": "<strong>‍</strong>Améliorez votre vision avec la découverte de&nbsp;stratégies de mise en œuvre empiriques &amp; pragmatiques. Méthode par&nbsp;analogie, méthode par&nbsp;découpage en phase, méthode du no estimate, approche<strong>&nbsp;</strong>budget produit vs approche budget projet&nbsp;? Erreurs courantes et retour d'expérience de&nbsp;Matthieu Grymonprez, CDO/CIO Adeo Groupe&nbsp;(Leroy Merlin, etc.)" }, { "type": "paragraph", "html": "Dans l'article \"<a href=\"/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">Budgétiser un projet sans se louper\",</a> on fera tout pour réconcilier la tech et la finance au service de la transformation des entreprises." }, { "type": "heading", "level": 2, "id": "comment-organiser-votre-conduite-de-projet", "text": "Comment organiser votre conduite de projet ?" }, { "type": "heading", "level": 3, "id": "le-jalon-projet-une-technique-pour-sequencer-vos-projets-intelligemment", "text": "Le jalon projet : une technique pour séquencer vos projets intelligemment" }, { "type": "paragraph", "html": "Nous partageons une conviction : &nbsp;<strong>le pilotage stratégique des projets ne doit/peut pas se faire par la tâche, mais par le jalon !</strong>" }, { "type": "paragraph", "html": "Les jalons donnent du rythme aux projets, ils permettent un meilleur alignement des équipes sur les objectifs et un découpage des projets en plusieurs étapes clés." }, { "type": "paragraph", "html": "Et surtout, ils constituent une alternative au contrôle des tâches micro-management et au planning de Gantt !" }, { "type": "paragraph", "html": "Encore faut-il être en mesure d'en faire une bonne définition. De choisir les bons mots-clés du jalon." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea947e12a1db65655b1059_Projet-timeline-min.jpeg", "alt": "Capture écran AirSaas", "caption": "Vue d'une timeline des jalons avec les étapes d'un projet sur AirSaas" }, { "type": "paragraph", "html": "Sur AirSaas vous pouvez, ajouter des jalons de projets et les déclarer comme \"faits\". Ils apparaissent sur la timeline et deviennent rouges lorsque vous êtes en retard." }, { "type": "paragraph", "html": "Pour en savoir plus, parcourez cet article de référence sur ce sujet : votre vie va changer ! <a href=\"/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\">Le jalon projet : une technique pour séquencer vos projets intelligemment.</a>" }, { "type": "heading", "level": 3, "id": "le-macro-planning-pourquoi-et-comment-sen-servir", "text": "Le macro planning : pourquoi et comment s'en servir ?" }, { "type": "paragraph", "html": "Votre conduite de projet nécessitera rapidement un planning à communiquer à tous les interlocuteurs. L'équipe projet peut vous aider à réaliser cette première photo, sorte de tableau de bord initial qui clarifie un objectif." }, { "type": "paragraph", "html": "Le macroplanning précise comment vous envisagez&nbsp;<strong>la projection de votre projet dans le temps.&nbsp;</strong>On parlera également de «&nbsp;roadmap projet&nbsp;».<strong>&nbsp;</strong>Réalisé dès la phase d'initialisation, alors qu'il n'existe pas encore de cahier des charges ce document détaillera les tâches à réaliser et les étapes clés. Vous indiquerez également quelles phases vont se conduire&nbsp;en parallèle, quelles autres devront&nbsp;se succéder<strong>.&nbsp;</strong>Véritable \"vue hélicoptère\" du futur chantier, cet outil accompagne logiquement le document de cadrage projet." }, { "type": "paragraph", "html": "Pour en savoir plus, lire l'article : <a href=\"/gestion-de-projet/le-macro-planning-pourquoi-et-comment-sen-servir\" target=\"_blank\">Le macro planning : pourquoi et comment s'en servir ?</a>" }, { "type": "heading", "level": 3, "id": "le-diagramme-de-gantt-comment-sen-servir", "text": "Le diagramme de Gantt : Comment s'en servir ?" }, { "type": "paragraph", "html": "Gantt et son cousin le CPM (<a href=\"https://www.projectmanager.com/guides/critical-path-method\" target=\"_blank\">Critical Path Method</a>, apparu dans les années 50) sont des méthodes utilisées pour simplifier le suivi de projet. Le diagramme de Gantt est une base incontournable pour qui veut parler management de projet." }, { "type": "paragraph", "html": "Grâce à sa simplicité, le diagramme de Gantt permet de <strong>saisir en un coup d'œil les différentes activités à réaliser </strong>pour exécuter le projet, ainsi que leur organisation dans le temps." }, { "type": "paragraph", "html": "Il est intéressant de revenir un instant sur l'origine de cet outil." }, { "type": "paragraph", "html": "Flashback en 1917 !" }, { "type": "paragraph", "html": "Henry Laurence Gantt était un ingénieur, disciple de Taylor. Il a eu la responsabilité d'optimiser la production d'un atelier. Plusieurs stades de fabrication coexistaient. Il a constaté que certaines opérations dépendaient de la réalisation d'autres, tissant ainsi entre elles un réseau de dépendance. Il en déduisit que certaines opérations pouvaient être menées en parallèle, et que d'autres pouvaient se succéder." }, { "type": "paragraph", "html": "Dans le but d'optimiser le temps de fabrication en utilisant cette possibilité de travail en parallèle, il développa un système de représentation graphique des activités sur une échelle de temps : le diagramme à barres. Chaque tâche à réaliser est représentée par une barre d'une longueur proportionnelle à sa durée estimée." }, { "type": "paragraph", "html": "Son apport clé ? <strong>Un affichage graphique</strong>, sorte de média,<strong> </strong>outil de communication entre les acteurs du processus." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ec3a061eb10c236fdb7bd5_gantt-airsaas.jpg", "alt": "Gantt", "caption": "Il y a une ligne par tâche. Les dépendances se traduisent par la position des barres les unes par rapport aux autres." }, { "type": "paragraph", "html": "On représente les informations visuellement :" }, { "type": "list", "ordered": false, "items": ["En ordonnées la liste des tâches à réaliser", "En abscisses les unités de temps"] }, { "type": "paragraph", "html": "Le diagramme de Gantt est donc l'une des manières d'éviter de se retrouver face à un goulot d'étranglement et de prendre du retard sur les délais planifiés." }, { "type": "paragraph", "html": "Que vous soyez ou non un chef de projet aguerri, nous vous conseillons une petite mise à jour, pour découvrir pourquoi et comment utiliser et<strong> </strong>dépasser les limites du diagramme de Gantt, près d'un siècle après sa création !<strong> </strong>Quelles sont les alternatives au contrôle des tâches et au micro)management ? Comment le<strong> </strong>jalon peut-il au contraire vous aider à séquencer vos projets intelligemment ?" }, { "type": "paragraph", "html": "On vous dit tout dans l'article de référence : \"<a href=\"/gestion-de-projet/le-diagramme-de-gantt-comment-sen-servir\" target=\"_blank\">Le diagramme de Gantt : comment s'en servir ?</a>\"" }, { "type": "heading", "level": 3, "id": "comment-mettre-une-meteo-projet-pertinente", "text": "Comment mettre une \"météo projet\" pertinente ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6247101b95f4a4562cfa3fd0_27379b47-3c96-4060-b561-4b071f5ad3db.png", "alt": "Capture écran fonction météo projet AirSaas", "caption": "Des solutions pour rendre lisible votre communication" }, { "type": "paragraph", "html": "La météo projet utilise la métaphore du temps qu'il fait pour communiquer sur le statut de ce dernier. C'est même le <strong>premier indicateur de la santé d'un projet !</strong>" }, { "type": "paragraph", "html": "Intimement liés au processus d'amélioration continue, le suivi et l'analyse des indicateurs fournissent des informations essentielles aux équipes." }, { "type": "paragraph", "html": "Souvent moqué pour son côté simpliste, le processus de la météo est pourtant&nbsp;un levier<strong>&nbsp;</strong>insoupçonné pour un management efficace." }, { "type": "paragraph", "html": "Pour être pertinent, idéalement, cet indicateur de reporting doit être :" }, { "type": "list", "ordered": false, "items": ["<strong>Compréhensible par tous</strong>&nbsp;: idéalement, sa définition sera le fruit du travail collaboratif de l'équipe", "<strong>Ciblé</strong>&nbsp;: les besoins de partage d'informations auxquels il répond doivent être clairement définis", "<strong>Partagé</strong>&nbsp;pour que tout le monde aille dans la même direction, vers un seul et même but"] }, { "type": "paragraph", "html": "Oui. Conduire un projet nous fait passer par des \"montagnes russes\" émotionnelles<strong>. </strong>Utiliser un <strong>langage visuel simple </strong>permettra de faire passer des<strong> messages clairs au management. </strong>Parmi tous les outils de suivi c'est votre meilleur allié<strong>.&nbsp;</strong>" }, { "type": "paragraph", "html": "Redécouvrez un outil puissant pour rendre lisible votre communication : <a href=\"https://www.airsaas.io/gestion-de-projet/comment-mettre-une-bonne-meteo-projet\" target=\"_blank\">Comment faire une météo projet claire et compréhensible ?</a>" }, { "type": "heading", "level": 3, "id": "le-tableau-de-bord-de-gestion-de-projet-moderne", "text": "Le tableau de bord de gestion de projet moderne" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62e2bc4ebe46394cfc95ba59_ppm%20airsaas-min.jpg", "alt": "Tableau de bord de gestion de projet avec AirSaas", "caption": "Visualiser en un coup d'œil votre portefeuille projet sous la forme d'une roadmap n'a jamais été aussi simple" }, { "type": "paragraph", "html": "L'accélération digitale a rendu obsolète de nombreuses démarches et les tableaux de bord de gestion de projet<strong> </strong>liés. Absence de prise en compte de la collaboration. Non-intégration avec les outils existants. Granularité des données inadaptée. Interfaces utilisateurs pas au niveau. Pourtant, la réussite des chantiers digitaux devient une condition<em> sine qua non</em> à la compétitivité des organisations&nbsp;!" }, { "type": "paragraph", "html": "Paradoxe : n'importe quel outil de<em> data warehouse</em> ou de CRM offre une bonne vision globale de la performance commerciale avec des reportings variés, tandis que la performance opérationnelle des programmes de transformation d'entreprise est quant à elle très difficile à visualiser et partager." }, { "type": "paragraph", "html": "Comment<strong> penser votre tableau de bord au regard des caractéristiques propres de votre entreprise</strong> ? Comment co-construire celui-ci les avec des responsables métiers impliqués&nbsp;?" }, { "type": "paragraph", "html": "Pour passer au XXIe siècle, découvrez&nbsp;<a href=\"https://airsaas.io/fr/solution/tableau-de-bord-gestion-de-projet\" target=\"_blank\">le tableau&nbsp;de bord de gestion de projet&nbsp;moderne</a>&nbsp;que vos équipes attendaient !" }, { "type": "heading", "level": 2, "id": "4-reunions-pour-assurer-le-pilotage-de-vos-projets-au-quotidien", "text": "4 réunions pour assurer le pilotage de vos projets au quotidien" }, { "type": "heading", "level": 3, "id": "le-suivi-de-projet-pour-garder-vos-parties-prenantes-alignees", "text": "Le suivi de projet pour garder vos parties prenantes alignées" }, { "type": "paragraph", "html": "<strong>Pas de bonne exécution de stratégie sans l'adhésion </strong>de vos parties prenantes !" }, { "type": "paragraph", "html": "Un rappel : le suivi de projet a pour but de contrôler la bonne exécution selon le planning<strong> </strong>établi, la qualité attendue et que les ressources humaines, matérielles et financières soient bien employées. Cela reste un outil de contrôle et de validation." }, { "type": "paragraph", "html": "Rappelons également que le projet va se situer à l'intérieur d'un faisceau de trois contraintes : les délais, la qualité, les coûts. Toute dérive un peu importante va le faire immanquablement \"buter\" sur l'une au moins de ces contraintes." }, { "type": "paragraph", "html": "Prenons l'exemple de la contrainte de délais : un retard survient sur une tâche du chemin critique. Or la contrainte de délais est impérative : pour tenir les délais, ou bien on maintient la qualité prévue mais à un coût plus élevé (on fait intervenir des renforts dans l'équipe, qu'il faut former, on fait appel à plus de sous-traitance...), ou bien on reste dans l'enveloppe de coûts prévue, mais en acceptant de transiger sur certains aspects de la qualité. C'est le genre de situation devant laquelle on va se trouver." }, { "type": "paragraph", "html": "Pour pouvoir prendre en connaissance de cause ce genre de décisions, il faut que plusieurs facteurs soient réunis :" }, { "type": "list", "ordered": false, "items": ["<strong>Être capable de repérer les dérapages </strong>: cela va être le rôle des tableaux de bord et des tableaux de suivi, ainsi que tout le dispositif d'information et d'alerte mis en place", "<strong>Être capable d'analyser les causes réelles du problème</strong> pour établir un diagnostic fiable", "<strong>Établir un plan d'action</strong>, c'est-à-dire trouver des solutions adéquates et prendre des décisions - décisions dépendant du chef de projet dans un premier temps, appel au sponsor, dans le cas ou les décisions n'entrent pas dans son périmètre de responsabilités, appel au comité de pilotage dans les cas les plus impactants."] }, { "type": "paragraph", "html": "C'est l'objet des méthodes et outils de suivi de projet." }, { "type": "paragraph", "html": "Quant à elles, les parties prenantes sont des personnes qui ont un intérêt quelconque dans le résultat de votre projet<strong>. </strong>Soit parce qu'elles vont l'impacter ou être impactées par lui.<strong> </strong>Et figurez-vous qu'il y en a toujours plus qu'on ne pense !<strong> </strong>Cette notion quelque peu vague recouvre des réalités bien différentes." }, { "type": "paragraph", "html": "Reconnaissons-le : le suivi de projet s'occupe généralement peu, ou mal, des parties prenantes.<strong> </strong>L'arrivée de nouvelles générations d'outils de PPM et plateformes connectées aux différents outils a changé la donne." }, { "type": "paragraph", "html": "Dans cet article on a choisi de mettre en avant&nbsp;<strong>5 leviers à considérer pour entretenir une relation gagnante/gagnant</strong>&nbsp;et garder vos parties prenantes alignées." }, { "type": "paragraph", "html": "Usage des plateformes, place de la communication, conduite de changement, importance des rituels, bonnes pratiques de DSI, usage de la matrice de positionnement des acteurs sur l'axe pouvoir/intérêt. L'article à lire pour mettre vos relations dans une bonne direction : <a href=\"/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\">Le suivi de projet pour garder aligné les parties prenantes.</a>" }, { "type": "heading", "level": 3, "id": "comment-faire-un-bon-point-davancement-projet", "text": "Comment faire un bon point d'avancement projet ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ec3d3f6529ce6e29bf8a4b_point-avancement-projet_Pros%20de%20la%20Transfo.jpg", "alt": "Comment faire un bon point d'avancement", "caption": "Réussir à (bien) mener des points d'avancement projet n'est pas un sujet à prendre à la légère." }, { "type": "paragraph", "html": "Quelle fréquence choisir, quelle présentation standard utiliser, comment adapter votre reporting à chaque typologie de personnes, de lecteurs ?" }, { "type": "paragraph", "html": "Les 3 leviers d'un processus de suivi d'avancement efficace sont :" }, { "type": "list", "ordered": false, "items": ["<strong>Une fréquence continue</strong>", "<strong>Une standardisation</strong>", "<strong>Une adaptation des formats </strong>aux types<strong> </strong>de projets et aux personnes destinataires"] }, { "type": "paragraph", "html": "Sur ce dernier point, un rappel s'impose : <strong>1 type de projet = 1 type de point d'avancement.</strong>" }, { "type": "paragraph", "html": "Problème : comme tout est projet (microprojet, projet transverse, d'entreprise, \"POC\", projet bac à sable, stratégique, légal, de direction, de département...) il y a de quoi s'y perdre." }, { "type": "paragraph", "html": "En ne typant pas on risque l'effet \"canon pour la mouche\". C'est-à-dire sortir l'artillerie lourde de votre gestion de projet pour rien." }, { "type": "paragraph", "html": "Les fondamentaux et usages avancés<strong> </strong>de ce processus sont à notre portée. Importance des outils visuels, usage des plateformes, rôle du sponsor, automatisation, synchronisation avec vos autres outils..." }, { "type": "paragraph", "html": "On a sélectionné 12 pratiques et / ou retours d'expériences de PMO/DSI. On fait le point sur <a href=\"/gestion-de-projet/comment-faire-un-bon-point-davancement-projet\" target=\"_blank\">comment faire un bon point d'avancement projet.</a>" }, { "type": "heading", "level": 3, "id": "la-revue-de-projet-un-point-detape-pour-tirer-les-lecons-de-vos-erreurs", "text": "La revue de projet : un point d'étape pour tirer les leçons de vos erreurs" }, { "type": "paragraph", "html": "Les revues de projet interviennent<strong> à chaque fin de phase majeure </strong>et sont souvent planifiées dès le début du projet<strong>.</strong> Qu'elles portent sur des aspects techniques, produits, délais, ou de phase de sprint,<strong> </strong>les décisions prises en revue de projet servent de base pour la suite de l'exécution<strong> </strong>du projet." }, { "type": "paragraph", "html": "C'est <strong>l'un des ingrédients principaux d'une équipe projet soudée</strong>. Un moment où l'on décide collectivement de la validation d'un jalon, des actions." }, { "type": "paragraph", "html": "Durant vos revues de projet l'utilisation des KPI de gestion de projet vous aidera à être certain d'être passé à la phase suivante du projet, sans avoir loupé aucune des leçons que vous deviez tirer de vos difficultés." }, { "type": "paragraph", "html": "Découvrez l'article de référence<strong> </strong>sur le sujet : <a href=\"/gestion-de-projet/la-revue-de-projet\" target=\"_blank\">La revue de projet : un point d'étape pour tirer les leçons de vos erreurs</a>" }, { "type": "heading", "level": 3, "id": "bilan-projet-exemple-et-methodologie", "text": "\"Bilan projet\" exemple et méthodologie" }, { "type": "paragraph", "html": "Le bilan a autant d'importance que le périmétrage et l'exécution d'un projet.&nbsp;Cette étape clé&nbsp;marquera la fin de votre pilotage actif, du lien contractuel. Réussir le bilan projet, c'est aussi soigner votre sortie, votre image !" }, { "type": "paragraph", "html": "Qu'est-ce qu'un bilan projet ? Comment l'animer efficacement ? Que doit-il inclure ? Pourquoi le réaliser ? Quelles sont les nouvelles tendances ? Quelles sont les 7 bonnes habitudes des bilans projets efficaces ? Comment fait-on des bilans de projet dans d'autres secteurs d'activité ? Et enfin, y a-t-il des trames types que l'on peut utiliser ?" }, { "type": "paragraph", "html": "Toutes ces questions et aussi leurs réponses sont au menu de l'article : <a href=\"/gestion-de-projet/comment-animer-un-bilan-projet-efficace\" target=\"_blank\">Comment animer un bilan projet efficace ?</a>" }, { "type": "heading", "level": 2, "id": "plan-de-communication-projet-comment-eviter-lechec", "text": "Plan de communication projet : comment éviter l'échec ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62470cb5afa4ec63a0ac6fa0_Matrice%20%20communication%20projet%20AirSaas.png", "alt": "Carte mémoire Plan de communication", "caption": "Mindmap \"Carte mémoire\" de votre plan de communication projet" }, { "type": "paragraph", "html": "99 % des échecs projets sont liés à un mauvais plan de communication ! (statistique invérifiable du Totally Subjective Institute :)" }, { "type": "paragraph", "html": "Le plan de communication est la déclinaison opérationnelle et structurée des actions de communication d'un projet. : \"<strong>qui dit quoi, à qui, pourquoi, quand, où ? par quel moyen et avec quel effet ?</strong>\"." }, { "type": "paragraph", "html": "Pour le construire, vous pouvez utiliser une méthode en 7 étapes, basée sur la <a href=\"https://www.e-marketing.fr/Definitions-Glossaire/Modele-Lasswell-242443.htm\" target=\"_blank\">matrice de Lasswel</a>." }, { "type": "paragraph", "html": "Disons-le clairement :<strong> </strong>l'équipe projet doit se responsabiliser pour communiquer. Il est plus que fondamental de bien&nbsp;organiser la remontée de toutes les informations, points d'attention et décisions prises. C'est<strong>&nbsp;</strong>le manque de transparence dans la communication écrite&nbsp;qui est&nbsp;responsable de nombreux échecs." }, { "type": "paragraph", "html": "Il faut rappeler que <strong>\"</strong>penser\" sa communication, y investir le \"juste temps<strong>\"</strong> vous permettra d'aligner vos parties prenantes de leur faire vivre une expérience positive et de gagner du temps sur l'opérationnel. Oui<strong> </strong>: le design du plan de communication est clé pour l'avancement du projet." }, { "type": "paragraph", "html": "Découvrez comment générer un support de \"communication en un clic\". On vous a aussi préparé cinq hacks pour construire un plan de communication projet \"du XXIe siècle\". Et enfin les Do's &amp; Don't&nbsp;d'<a href=\"/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">un plan de communication projet.</a>" }, { "type": "heading", "level": 2, "id": "comment-elaborer-un-reporting-projet-efficace", "text": "Comment élaborer un reporting projet efficace ?" }, { "type": "paragraph", "html": "L'importance du reporting dans l'efficience des projets de transformation est fondamentale. C'est avec un reporting qualitatif - versus quantitatif- envoyé à une forte fréquence que les&nbsp;PMO&nbsp;arrivent à mieux fédérer toute l'entreprise autour des projets transverses. Le problème ? Le reporting prend beaucoup, beaucoup trop de temps." }, { "type": "paragraph", "html": "Pourtant, utilisé avec une bonne méthodologie, le reporting projet est un outil tourné vers l'action. ! Il aidera chaque lecteur, quelle que soit son implication ou son rôle dans la construction du futur produit ou service à décider, avec discernement, en pleine responsabilité." }, { "type": "paragraph", "html": "Véritable&nbsp;mise en scène d'informations<strong>&nbsp;</strong>et de données relatives à un projet, son analyse, sa mise en forme et son interprétation sont devenues les vrais enjeux d'un pilotage efficace. Avec un outil commun<strong> </strong>sur lequel partager des données chiffrées de vos projets, il sera plus facile de construire une vision commune et d'avancer dans la même direction." }, { "type": "paragraph", "html": "Collecte, fréquence, nombre d'indicateurs, forme, outils, petits trucs en plus qui font toute la différence...<strong> </strong><a href=\"/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\">Comment élaborer un reporting projet efficace ?</a>" }, { "type": "heading", "level": 3, "id": "le-flash-report-ou-rapport-flash", "text": "Le \"Flash Report\" ou rapport flash" }, { "type": "paragraph", "html": "Les rapports flash sont décisifs dans votre management de projets. Ils facilitent vos processus de<strong> </strong>décisions et permettent une meilleure exécution." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62bdfca88290d29985904cb5_report-flash.png", "alt": "Capture écran AirSaas Flash report", "caption": "Document bref qui fournit une vision synthétique des projets sur une période" }, { "type": "paragraph", "html": "Le rapport flash&nbsp;d'AirSaas est composé de deux diapositives : l'une rappelle toutes les informations de cadrage, tandis que l'autre comporte toutes les informations nécessaires à la bonne exécution du projet." }, { "type": "paragraph", "html": "Un bon rapport flash est un<strong> récapitulatif synthétique sur l'avancée des différents projets en cours</strong>. Il a pour objectif de tenir à jour les parties prenantes. Le rapport flash de la solution AirSaas comporte des diapositives d'introduction (rappel du planning, métriques du dashboard report, timeline, etc.) et, pour chaque projet, deux slides contenant les informations suivantes :&nbsp;" }, { "type": "list", "ordered": false, "items": ["Un récapitulatif sur le contexte", "Les \"metrics\" d'avancée des projets", "Les données sur le ressenti des équipes"] }, { "type": "paragraph", "html": "Support de communication \"optimal\"&nbsp;les \"rapports flash\"&nbsp;sont cruciaux pour une meilleure implication des parties prenantes de l'entreprise et par conséquent pour la réussite de votre conduite de projet. Ils viennent&nbsp;compléter un bon pilotage et suivi de planning<strong>.</strong>" }, { "type": "paragraph", "html": "<a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">Flash report ou rapport flash - Télécharger notre modèle PPT</a>" }, { "type": "heading", "level": 2, "id": "tout-savoir-sur-la-fiche-projet", "text": "Tout savoir sur la fiche projet" }, { "type": "paragraph", "html": "\"Carte d'identité\" de votre projet, cette fiche contient les informations essentielles pour une première définition du périmètre et de la réalisation : objectifs, donneur d'ordre, exécution, soutiens, organisation, fréquences d'envois des livrables, ressources, risques..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6177e7e9dc718e71bbf0fa55_Project-metrics.jpg", "alt": "Exemple de fiche projet AirSaas", "caption": "Exemple de fiche projet" }, { "type": "paragraph", "html": "Une fiche de projet est <strong>un </strong><strong>outil essentiel </strong><strong>car elle</strong> <strong>contient toute l'organisation du projet</strong> ou d'une partie de ce dernier. C'est un livrable fondamental car le chef de projet y liste toutes les phases, les étapes et les actions qui devront être accomplies dans la conduite de projet." }, { "type": "paragraph", "html": "Point de vigilance :<strong> </strong>tous les projets sont différents !<strong> </strong>Il n'existe toujours pas de \"one size fits all\" ! Votre fiche doit donc s'adapter aux contextes aussi bien qu'aux enjeux." }, { "type": "paragraph", "html": "Les modèles de fiche projet les plus courants sont les suivantes :" }, { "type": "list", "ordered": false, "items": ["<strong>Pré-projet</strong>, avant de valider un projet", "<strong>Projet interne</strong>, pour des interlocuteurs qui sont des collègues", "<strong>Multi-projets</strong> : une seule et même fiche peut donc regrouper plusieurs fiches", "<strong>Micro-projet</strong> : un document très succinct peut suffire"] }, { "type": "paragraph", "html": "Mais qui la rédige ? Qui la valide ? Quelle différence en fonction du type : préprojet, multiprojet, microprojet, projet interne ? Et enfin existe-t-il un modèle à adapter ? Ne réinventez pas la roue et télécharger notre modèle de fiche projet. Bonne nouvelle : on vous a préparé cette <a href=\"/gestion-de-projet/fiche-projet-exemple-et-methodologie\" target=\"_blank\">fiche projet méthodologie (exemple)</a>." }, { "type": "heading", "level": 2, "id": "le-pilotage-de-projet-moderne", "text": "Le pilotage de projet moderne" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ecb3de8a9935c1ef2d5f6d_airsaas-spacex-Le%20tableau%C2%A0de%20bord%20de%20gestion%20de%20projet%C2%A0moderne-min.jpg", "alt": "Tableau de bord non mimimaliste" }, { "type": "paragraph", "html": "Pandémie, Grande Démission, prolifération de sujets, management transverse, travail hybride, IA, no code... Vous l'avez bien noté : on ne pilote plus un projet comme en 1917, lorsque. Henry Laurence Gantt a inventé un modèle pour optimiser le travail d'un atelier de fabrication." }, { "type": "paragraph", "html": "Ce monde VICA (Volatile incertain complexe et Ambigu) est arrivé !" }, { "type": "paragraph", "html": "En face de ce nouveau contexte, un pilotage nouveau a émergé :" }, { "type": "list", "ordered": false, "items": ["Pilotage par les jalons", "Centralisation des décisions", "Reporting en un clic", "Nouvelles gouvernances dans les chefferies de projet/Copil", "Méthodes collaboratives", "Gestion de projet hybride..."] }, { "type": "paragraph", "html": "Quelles croyances doit-on revisiter pour moins subir et échouer dans les livraisons de projet ? Que faut-il ajouter pour garder du plaisir et de l'efficience dans la démarche ? Y a-t-il des nouvelles tendances à surveiller pour suivre et anticiper les évolutions du pilotage de projet?" }, { "type": "paragraph", "html": "<a href=\"https://airsaas.io/\" target=\"_blank\">Le pilotage de projet moderne</a> : l<strong>'article à lire pour enlever le frein à main de votre conduite de projet</strong> et le limiteur de vitesse de transformation de l'entreprise !" }], "faq": [], "related": [] }, { "slug": "le-guide-du-mode-projet", "skip": false, "meta": { "title": "Comment faire passer mon entreprise en mode projet ?", "h1": "Comment faire passer mon entreprise en mode projet ?", "description": "Passer en mode projet suppose d'aller encore plus loin en repensant toute votre organisation : de la définition du projet commun, à sa communication, à la structuration des équipes et de leur chef !", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f376d2d6406549eff2092b_1-min%20(1).jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Passer en mode projet suppose d'aller encore plus loin en repensant toute votre organisation : de la définition du projet commun, à sa communication, à la structuration des équipes et de leur chef !" }, { "type": "paragraph", "text": "Découvrez ici les bonnes raisons et les clés pour adopter ce mode de travail." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13bc_62f3742013ce5e8e913ebdd3_Project-page-feed.jpeg", "alt": "Communication projet", "caption": "Centralisez la communication projet dans le cadre du travail en mode projet" }, { "type": "heading", "level": 2, "id": "quest-ce-que-cest-le-mode-projet", "text": "Qu'est-ce que c'est, le mode projet ?" }, { "type": "paragraph", "text": "Le fonctionnement en mode projet peut être décrit par <strong>trois caractéristiques principales</strong> :" }, { "type": "list", "ordered": false, "items": ["Une organisation autour d'un <strong>livrable commun</strong>", "Une équipe <strong>pluridisciplinaire</strong>", "Chapeautée par un <strong>chef d'orchestre</strong> : le <a href=\"https://www.airsaas.io/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\">chef de projet</a>"] }, { "type": "heading", "level": 3, "id": "une-organisation-autour-dun-projet-commun", "text": "Une organisation autour d'un projet commun" }, { "type": "paragraph", "text": "Toute l'équipe et la méthodologie mise en place doivent être pensées autour du projet<strong>,</strong> que ce soit au niveau du budget, des délais affectés à chaque tâche ou encore des méthodes de travail choisies. Toute l'organisation doit être centrée sur un objectif précis : la réalisation optimale du projet." }, { "type": "paragraph", "text": "Un des principaux défis du mode projet consiste à <strong>mettre en place une collaboration efficace</strong> entre toutes les personnes impliquées dans le projet, en prenant notamment en compte les missions que chacun à réaliser en parallèle." }, { "type": "paragraph", "text": "L'équipe idéale pour réaliser un projet est composée de personnes avec des profils différents : leurs compétences, qualifications et expertises doivent être complémentaires et couvrir l'ensemble du spectre du projet." }, { "type": "paragraph", "text": "Le choix de l'équipe est donc une des étapes les plus importantes pour parvenir à réellement travailler en mode projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13ca_62f374757aa393210a62307e_People-involve.jpeg", "alt": "Equipes impliquées en mode projet", "caption": "L'équipe projet" }, { "type": "heading", "level": 3, "id": "une-transversalite-des-equipes", "text": "Une transversalité des équipes" }, { "type": "paragraph", "text": "Afin de parvenir à recruter tous les profils nécessaires à l'accomplissement du projet, les équipes qui travaillent en mode projet proviennent généralement de services différents. Elles peuvent habituellement travailler dans des services différents au sein d'une même entreprise." }, { "type": "paragraph", "text": "Si cette transversalité des équipes est pratique pour composer l'équipe idéale, elle entraîne aussi des conséquences sur plusieurs aspects de votre organisation :" }, { "type": "list", "ordered": false, "items": ["<strong>Tout le monde n'a pas la même maturité méthodologique</strong>. Votre méthodologie de travail doit donc être pensée en prenant en compte les différences entre chacun des membres de votre équipe (habitude propre à son service, à la culture de son entreprise, outil différent…).", "<strong>Le management l'équipe</strong> : il doit lui aussi être adapté à la diversité des profils ainsi qu'aux spécificités du projet mené. Le chef de projet n'est pas le \"chef\" des personnes mais le leader du projet. Il est responsable du travail des autres.", "Les personnes venant de différents horizons ou services, il faut être très clair sur le temps disponible de chacun et ce tout le long du projet. Cadrer une \"enveloppe temps\"."] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13b1_62f374dfe3e506143bcd1b6a_Team-involve.jpeg", "alt": "Equipes impliquées", "caption": "Les équipes impliquées dans le projet" }, { "type": "paragraph", "text": "Enfin, pour <strong>souder les membres de votre équipe</strong> malgré leurs différences, il sera primordial de structurer votre équipe autour de l'intérêt commun que chacun d'entre eux partage. Il faudra penser à communiquer en continu sur l'impact que ce projet peut avoir sur l'entreprise et les clients." }, { "type": "heading", "level": 3, "id": "une-equipe-chapeautee-par-un-chef-de-projet", "text": "Une équipe chapeautée par un chef de projet" }, { "type": "paragraph", "text": "Pour solidariser votre équipe autour du projet, il est indispensable de nommer un chef de projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13c1_62f375b65a05665b12ad0e61_intro-project.jpeg", "alt": "Le chef de projet", "caption": "Le responsable projet" }, { "type": "paragraph", "text": "Son rôle sera d'assurer la réalisation du projet à travers différentes fonctions :" }, { "type": "list", "ordered": false, "items": ["<strong>Il répartit les tâches</strong> entre les membres de l'équipe en fonction des compétences de chacun", "<strong>Il fixe les délais</strong> assignés à chaque tâche et s'assure qu'ils sont tenus", "<strong>Il anime les réunions</strong> d'équipes et accompagne chacun des collaborateurs", "<strong>Il assure un suivi global</strong> de l'ensemble du projet et reporte avec un outil de gestion", "<strong>Il mobilise les sponsors</strong> du projet lorsque c'est nécessaire", "<strong>Il veille à ce que les décisions soient prises</strong> par les bonnes personnes dans les bons délais"] }, { "type": "paragraph", "text": "Le <a href=\"https://www.reussirsesprojets.com/qualites-chef-de-projet/\" target=\"_blank\">chef de projet</a> doit donc être <strong>doté d'une personnalité forte</strong>, afin de parvenir à s'imposer auprès de son équipe lorsque c'est nécessaire, de la remobiliser en cas de baisse de régime et plus largement de leur <strong>partager sa vision du chemin</strong> vers l'objectif commun : la réalisation optimale du projet !" }, { "type": "heading", "level": 2, "id": "pourquoi-travailler-en-mode-projet", "text": "Pourquoi travailler en mode projet ?" }, { "type": "paragraph", "text": "Si l'on parvient à créer une symbiose entre les différents membres de l'équipe et les compétences qu'ils apportent, alors travailler en mode projet présente de nombreux avantages." }, { "type": "list", "ordered": false, "items": ["On <strong>brise l'organisation pyramidale</strong> classique et les frictions qu'elle génère", "On <strong>brise les silos</strong> entre services, ce qui améliore la coordination des collaborateurs", "On <strong>obtient une vision précise</strong> des tâches qui composent le projet ainsi que des délais assignés", "La <strong>communication</strong> entre les membres de l'équipe est optimisée et le <strong>partage d'informations simplifié</strong>", "On <strong>responsabilise les collaborateurs</strong>, ce qui stimule leur motivation, leur intelligence collective ainsi que leurs facultés à innover", "La <strong>charge de travail est mieux répartie</strong> entre les membres de l'équipe, mais aussi dans le temps", "La <strong>cohésion de votre équipe est renforcée</strong>, ce qui développe la coopération et la confiance que se portent les collaborateurs"] }, { "type": "paragraph", "text": "Tous ces avantages que présente le mode projet amènent deux conséquences sur la réalisation de vos projets. Tout d'abord, <strong>vous pouvez entreprendre des projets complexes</strong> : tous ces avantages permettent à vos équipes de réaliser des projets impossibles à exécuter sans ce mode particulier d'organisation. Ensuite, vos projets sont menés plus rapidement, coûtent généralement moins cher, et sont de meilleure qualité." }, { "type": "paragraph", "text": "Cependant, il y a un prix à payer : mettre en place le mode projet est complexe et requiert d'y passer du temps. En effet, si les collaborateurs recrutés ne sont pas suffisamment disponibles, que le budget alloué n'est pas en accord avec les objectifs, ou que vous ne parvenez pas à rassembler autour d'un objectif commun les profils hétérogènes que vous avez choisis, alors il y a toutes les chances pour que votre projet échoue." }, { "type": "paragraph", "text": "Heureusement, il existe des bonnes pratiques pour parvenir à travailler en mode projet." }, { "type": "heading", "level": 2, "id": "comment-travailler-en-mode-projet", "text": "Comment travailler en mode projet ?" }, { "type": "heading", "level": 3, "id": "constituer-son-equipe-projet", "text": "Constituer son équipe projet" }, { "type": "paragraph", "text": "La première étape est de <strong>réunir les bonnes personnes</strong> autour de votre projet. Vous devez vous poser plusieurs questions :" }, { "type": "list", "ordered": false, "items": ["Quelles sont les qualités et compétences nécessaires à la réalisation de mon projet ?", "Les profils que je recrute sont-ils complémentaires et aptes à travailler ensemble ?", "Les collaborateurs ont-ils suffisamment de disponibilités pour accomplir leurs tâches ?", "Sont-ils suffisamment concernés par le projet sur lesquels ils devront travailler ?"] }, { "type": "paragraph", "text": "Une fois l'équipe projet constituée, il faut alors assigner les rôles et les responsabilités à chacun des membres du groupe." }, { "type": "paragraph", "text": "Cette étape permet de responsabiliser chaque collaborateur sur les tâches qui lui sont attribuées, et d'optimiser la coopération dans la mesure où chacun a son champ de compétence bien délimité." }, { "type": "paragraph", "text": "Après l'équipe, il faut trouver le chef de projet idéal !" }, { "type": "heading", "level": 3, "id": "trouver-le-chef-de-projet-adapte", "text": "Trouver le chef de projet adapté" }, { "type": "paragraph", "text": "Il vous faut parvenir à trouver le profil qui parviendra à manager votre équipe." }, { "type": "paragraph", "text": "Il sera <strong>garant de la bonne exécution</strong> du projet tout au long de sa réalisation : répartition des tâches, planification, coordination des intervenants ainsi que du management du groupe." }, { "type": "paragraph", "text": "En terme de soft skills : il doit être capable de fédérer, de rassembler, mais aussi de faire respecter ses décisions - d'autant plus qu'il arrive qu'il n'ait pas de supériorité hiérarchique forte par rapport aux autres collaborateurs." }, { "type": "paragraph", "text": "Le chef de projet doit donc posséder des compétences managériales, relationnelles et communicationnelles fortes pour parvenir à orchestrer et piloter le mode projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13ae_62f3762a13ce5e51323ed323_Creation-responsable.jpeg", "alt": "L'adéquation entre le chef de projet et le projet", "caption": "Le bon chef de projet pour le bon projet" }, { "type": "heading", "level": 2, "id": "definir-le-projet-linteret-dun-cahier-des-charges-du-projet", "text": "Définir le projet : l'intérêt d'un cahier des charges du projet" }, { "type": "paragraph", "text": "Même s'il n'existe pas de modèle universel applicable, il est indispensable de <strong>définir clairement les limites de votre projet</strong>. Sans cela, le chef de projet et son équipe n'auront pas suffisamment d'informations pour assurer la réalisation de leurs objectifs.<br><br>Il y a donc une liste d'éléments (non exhaustive) à définir en amont du projet :" }, { "type": "list", "ordered": false, "items": ["Le <strong>contexte</strong> et les <strong>enjeux</strong> du projet", "Les <strong>objectifs</strong> à atteindre", "Le <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\"><strong>budget</strong> alloué</a>", "Une estimation de la charge initiale maximale", "Les outils et méthodes envisagées", "Les <strong>ressources</strong> humaines disponibles", "Les <strong>risques</strong> potentiels", "Les <strong>délais</strong> à respecter dans le planning du projet", "La place du projet par rapport à un ensemble d'autres chantiers"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13b9_62f3767188c0c35f4604ba8a_Project-info.jpeg", "alt": "note de cadrage", "caption": "Note de cadrage" }, { "type": "paragraph", "text": "Ces contenus serviront tout autant pour le choix de la composition de votre équipe que pour assurer la gestion du projet tout au long de sa réalisation." }, { "type": "paragraph", "text": "Ces informations doivent être inscrites dans un cahier des charges : ce sera le document commun qui centralisera tous ces éléments pour l'ensemble des parties prenantes du projet." }, { "type": "paragraph", "text": "<strong>Coucher ces éléments sur le papier</strong> <strong>facilite</strong> <strong>la coopération</strong> : cela évite tout malentendu ou chevauchement sur les tâches attribuées et ainsi réduit les frictions potentielles dans votre équipe." }, { "type": "paragraph", "text": "Le cahier des charges peut être basé sur la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\">note de cadrage</a> rédigée en amont du projet et a tout intérêt à être complété durant l'exécution du projet." }, { "type": "heading", "level": 3, "id": "sensibiliser-au-mode-projet", "text": "Sensibiliser au mode projet" }, { "type": "paragraph", "text": "Si le mode projet présente de nombreux avantages, il faut tout de même rappeler qu'il est très éloigné des méthodes et de l'organisation traditionnelle à laquelle vos collaborateurs sont habitués." }, { "type": "paragraph", "text": "Et comme tout changement de pratique, la question du passage au mode projet ne manquera pas de provoquer des réactions de la part de l'équipe que vous souhaitez constituer. Les réactions potentielles vont de l'indifférence à l'appréhension, en passant par l'enthousiasme. L'important est d'<strong>éviter de provoquer un rejet total.</strong>" }, { "type": "paragraph", "text": "Pas de recette miracle : la façon dont vous vous y prendrez dépendra de votre personnalité, mais Il est surtout primordial que vous preniez le temps de sensibiliser vos collaborateurs au nouveau fonctionnement qui les attend.<br><br>Pas de panique pour autant ! Si vous leur présentez les avantages du mode projet et que vous les rassurez sur leurs interrogations, il y a toutes les chances pour que vous parveniez à les convaincre de se lancer. Pour vous faciliter le mode projet nous avons regroupé 10 bonnes pratiques ci-dessous." }, { "type": "heading", "level": 2, "id": "aide-memoire-10-bonnes-pratiques-du-mode-projet", "text": "Aide-mémoire : 10 bonnes pratiques du mode projet" }, { "type": "heading", "level": 3, "id": "definissez-les-objectifs-et-contenus-de-votre-projet-clarifier", "text": "Définissez les objectifs et contenus de votre projet #clarifier" }, { "type": "paragraph", "text": "On ne réussit que par rapport aux objectifs. C'est la base. Et cependant, dans la vraie vie avant de démarrer un projet, on oublie parfois de <strong>définir clairement les objectifs et aussi ceux que l'on ne poursuivra pas !</strong> Cela vous aidera à vous concentrer sur ce que vous voulez accomplir, votre terrain de jeu, et à vous assurer que tout le monde travaille vers les mêmes objectifs, dans le même but. Cela implique un cahier des charges précis et également donc, de dire ce que le projet ne fera pas, sa portée réelle." }, { "type": "heading", "level": 3, "id": "creez-avec-les-metiers-un-plan-de-projet-cooperer", "text": "Créez (avec les métiers) un plan de projet #coopérer" }, { "type": "paragraph", "text": "Un <strong>plan de projet co créé avec les métiers et partagé avec les parties prenantes</strong> doit inclure des échéanciers, <a href=\"https://www.airsaas.io/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\">des jalons</a>, des budgets, des ressources et des risques. Étant donné qu'une partie de vos ressources critiques est constituée par vos partenaires métiers. Il devrait également inclure une répartition des tâches et des responsabilités, afin que chacun sache ce qu'il doit faire sur la feuille de route et l'engagement que cela représentera. Le travail collaboratif entre les différents acteurs est la clé du management de projet." }, { "type": "heading", "level": 3, "id": "attribuez-des-roles-et-des-responsabilites-vraiment-claires-aux-acteurs-du-projet-informer", "text": "Attribuez des rôles et des responsabilités (vraiment) claires aux acteurs du projet : #informer" }, { "type": "paragraph", "text": "Tel le chef d'orchestre, assurez-vous que <strong>chacun connaît et comprend sa place et son rôle</strong> et ses responsabilités dans le projet. Cela aidera à s'assurer que les tâches sont terminées à temps et selon les exigences requises le rôle et par cette approche de la gestion de projets qui bouscule le management et les hiérarchies établies dans les entreprises." }, { "type": "heading", "level": 3, "id": "utilisez-des-outils-de-gestion-de-projet-outiller", "text": "Utilisez des outils de gestion de projet #outiller" }, { "type": "paragraph", "text": "Il existe de nombreux outils de gestion de projet disponibles qui peuvent vous aider à suivre les progrès, à gérer les tâches et à collaborer avec les membres de l'équipe. Un outil de gestion embarque avec lui une philosophie, une façon de travailler. Par exemple, partager un diagramme de Gantt, une charge, pour votre gestion de projets peut se révéler contreproductif si vous cherchez à convaincre et à adopter une bonne communication." }, { "type": "heading", "level": 3, "id": "communiquez-regulierement-impacter", "text": "Communiquez régulièrement #impacter" }, { "type": "paragraph", "text": "<strong>Une communication régulière</strong> est essentielle lorsque l'on travaille sur un projet. Cela permet de s'assurer que tout le monde est sur la même longueur d'onde et que tout problème, question ou préoccupation est traité rapidement." }, { "type": "paragraph", "text": "Sur ce thème et ces activités, il existe des méthodes, en particulier le <a href=\"https://www.e-marketing.fr/Definitions-Glossaire/Modele-Lasswell-242443.htm\" target=\"_blank\">modèle de Laswell</a> : \"Qui dit quoi, à qui, au travers de quel médium, avec quel résultat ?\"." }, { "type": "heading", "level": 3, "id": "surveillez-les-progres-evaluer", "text": "Surveillez les progrès #évaluer" }, { "type": "paragraph", "text": "Vous devez suivre l'évolution du projet, l'atteinte des objectifs pour vous assurer qu'il reste sur la bonne voie. Des <strong>rapports d'avancement réguliers</strong> et des mises à jour de statut peuvent vous aider à identifier rapidement les problèmes et à prendre des mesures correctives si nécessaire." }, { "type": "heading", "level": 3, "id": "restez-flexible-assouplir", "text": "Restez flexible : #assouplir" }, { "type": "paragraph", "text": "Un scénario, mais de la souplesse ! Les projets peuvent changer, et vous devez être prêt à vous adapter si les choses ne se déroulent pas comme prévu. <strong>Être flexible et ouvert aux nouvelles idées</strong> peut vous aider à surmonter les obstacles qui pourraient survenir dans votre management de projets. Devenez yogi projet ! Vive la souplesse." }, { "type": "heading", "level": 3, "id": "gerez-les-risques-derisquer", "text": "Gérez les risques #dérisquer" }, { "type": "paragraph", "text": "Chaque projet comporte des risques. Sans entrer dans une usine à gaz Excel, vous devez vous y préparer. <a href=\"https://www.airsaas.io/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">Identifiez les risques</a> potentiels dès le début et mettez en place des plans pour les atténuer." }, { "type": "heading", "level": 3, "id": "celebrez-toutes-les-reussites-ritualiser", "text": "Célébrez toutes les réussites #ritualiser" }, { "type": "paragraph", "text": "Lorsqu'un projet est terminé ou même un jalon majeur, avec succès ou non, prenez le temps de <strong>célébrer avec votre équipe le positif, de dire merci</strong> ! Chacun sa façon de le faire - mais reconnaître le travail acharné de chaque collaborateur et les efforts accomplis aidera à remonter le moral et à garder tout le monde motivé." }, { "type": "heading", "level": 3, "id": "apprenez-vraiment-de-vos-experiences-capitaliser", "text": "Apprenez (vraiment) de vos expériences #capitaliser" }, { "type": "paragraph", "text": "Après avoir terminé un projet, <strong>prenez le temps de réfléchir à la manière dont vous avez travaillé.</strong> Ce qui a bien fonctionné et à ce qui n'a pas fonctionné. Les agilistes ont intégré ces activités de rétro depuis longtemps. Ces pratiques vous aideront à améliorer votre efficacité et vos processus et manières de faire, et à assurer que les projets futurs soient encore plus réussis. Quel que soit le type de méthode adoptée, le plus important, c'est de capitaliser." }, { "type": "paragraph", "text": "En conclusion : pour profiter de tous les avantages du mode projet, vous allez devoir prendre le temps de penser votre projet, de trouver le chef de projet adéquat, de constituer une équipe complémentaire, et de convaincre cette dernière de vous suivre dans cette aventure !" }, { "type": "paragraph", "text": "Bonne chance !" }, { "type": "heading", "level": 2, "id": "mode-projet-et-note-de-cadrage", "text": "Mode projet et note de cadrage" }, { "type": "paragraph", "text": "Dans le cadre du fonctionnement du mode projet de nombreuses équipes utilisent <strong>la note de cadrage comme outil en soutien au mode projet</strong> : la note de cadrage est un document synthétique qui récapitule l'ensemble des points clés de votre projet.<br><br>Il peut donc être très intéressant d'adapter l'utilisation de la note de cadrage au mode projet. Rappelez tous les points essentiels à vos équipes, pour simplifier leur adaptation et simplifier la collaboration autour de votre but commun : la réalisation du projet ! Pour en savoir plus sur le sujet, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\">rendez-vous sur notre article sur la note de cadrage projet</a>." }], "toc": [{ "label": "Qu'est-ce que c'est, le mode projet ?", "href": "#quest-ce-que-cest-le-mode-projet", "level": 2 }, { "label": "Pourquoi travailler en mode projet ?", "href": "#pourquoi-travailler-en-mode-projet", "level": 2 }, { "label": "Comment travailler en mode projet ?", "href": "#comment-travailler-en-mode-projet", "level": 2 }, { "label": "Définir le projet : l'intérêt d'un cahier des charges du projet", "href": "#definir-le-projet-linteret-dun-cahier-des-charges-du-projet", "level": 2 }, { "label": "Aide-mémoire : 10 bonnes pratiques du mode projet", "href": "#aide-memoire-10-bonnes-pratiques-du-mode-projet", "level": 2 }, { "label": "Mode projet et note de cadrage", "href": "#mode-projet-et-note-de-cadrage", "level": 2 }], "faq": [], "related": [] }, { "slug": "le-modele-de-presentation-pour-votre-comite-de-pilotage", "skip": false, "meta": { "title": "Modèle de présentation pour votre comité de pilotage (exemple)", "h1": "Modèle de présentation pour votre comité de pilotage (exemple)", "description": "Modèle de présentation pour votre comité de pilotage (exemple)", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f38b8e5a0566faf0addbf5_Project%20image3-min.jpg", "alt": "" }, "author": { "name": "Bertran Ruiz", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e0385c210a2b1948e800a6_BR-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c839fd0fe2df1b55666847_62f38b13e3e506199ecdeb2b_Presentation-min.jpeg", "alt": "Présentation copil en live", "caption": "Comment faciliter la prise de décision ?" }, { "type": "paragraph", "html": "En tant que chef de projet, il est une tâche qui vous tient sûrement à cœur si vous êtes passionné par votre métier : celle de la présentation de l'avancée du projet en <a href=\"/fr/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">comité de pilotage</a>." }, { "type": "paragraph", "html": "La réunion du \"Copil\", comme on dit souvent en abrégé, qui a lieu une fois par mois environ, est une occasion en or pour partager les dernières avancées du projet auprès des parties prenantes et mettre en avant votre équipe." }, { "type": "paragraph", "html": "Un bon chef de projet sait que l'anticipation et la préparation sont des valeurs essentielles qui mennent au succès et à la réussite d'un Copil." }, { "type": "inline-cta", "label": "Télécharger ⇣", "href": "https://hubs.ly/Q02Nl-VT0" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-comite-de-pilotage", "text": "Qu'est-ce qu'un comité de pilotage ?" }, { "type": "paragraph", "html": "Quand le pilotage d'un projet présente de forts enjeux, un niveau de technicité complexe, ou un nombre de personnes impliquées important, la création d'un comité de pilotage pour assurer un bon management de projet devient la priorité numéro 1 du chef de projet." }, { "type": "heading", "level": 3, "id": "une-simple-reunion-de-suivi-de-projet", "text": "Une simple réunion de suivi de projet ?" }, { "type": "paragraph", "html": "Une réunion de comité de pilotage est bien plus qu'une simple réunion entre les instances décisionnaires et opérationnelles chargées de l'exécution du projet. Dans le management de projets transverses la place du chef de projet n'est pas celle du manager. Ce dernier ne peut donc pas arbitrer les priorités de moyens, de délais ou de qualité qui ne sont pas de son ressort." }, { "type": "heading", "level": 3, "id": "un-relais-de-pouvoir-dans-les-entreprises", "text": "Un relais de pouvoir dans les entreprises" }, { "type": "paragraph", "html": "Le comité de pilotage (ou Copil) est donc une composante de la réussite d'un projet. C'est un relais de pouvoir essentiel dont le rôle est d'assurer le suivi d'un projet, analyser son avancement et de prendre des décisions finales en fin de réunion." }, { "type": "paragraph", "html": "Le comité de pilotage devra s'assurer que le processus de décision permet de répondre aux enjeux auxquels s'attaque l'équipe en place et qu'elle pourra y répondre dans les délais impartis." }, { "type": "heading", "level": 3, "id": "comment-sont-formes-les-comites-de-pilotage", "text": "Comment sont formés les comités de pilotage ?" }, { "type": "paragraph", "html": "Le Copil est donc formé en début de projet par le sponsor en collaboration avec le chef de projet. Dans la pratique les membres du comité de pilotage sont des décideurs (actionnaire, business angel, manager...) capables de rendre les arbitrages nécessaires à la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite du projet</a> ainsi que des experts métiers qui ont l'expérience concrète du projet et le vivent au quotidien." }, { "type": "heading", "level": 3, "id": "le-role-exact-des-reunions-des-comites-de-pilotage", "text": "Le rôle exact des réunions des comités de pilotage" }, { "type": "paragraph", "html": "C'est un outil ultra-efficace de prise de décision collégiale pour donner un nouvel élan à vos projets à forts enjeux et traiter un dossier \"brûlant\" mais dont il faut trouver la clé pour atteindre les objectifs fixés. À noter que le sponsor et le management doivent être mis au courant de l'agenda du Copil bien à l'avance. Ils ne doivent pas découvrir le contenu des dossiers en cours pendant les réunions." }, { "type": "paragraph", "html": "Le sponsor est l'allié du chef de projet au sein du comité de pilotage. Sur un projet, il doit détenir assez d'informations en amont pour être en mesure de prodiguer des conseils aux équipes, quelque soit la phase dans laquelle se trouve le projet." }, { "type": "paragraph", "html": "Les rôles sont bien définis, chacun des acteurs a le sien :" }, { "type": "list", "ordered": false, "items": ["le sponsor vend le projet : et oui il faut mobiliser en continu !", "les membres des comités de pilotage ont donné leur avis et leurs conseils", "le chef de projet devra exécuter les décisions prises"] }, { "type": "heading", "level": 3, "id": "quel-est-lenjeu-principal-du-comite-de-pilotage", "text": "Quel est l'enjeu principal du comité de pilotage ?" }, { "type": "paragraph", "html": "Sur un projet, l'animation du comité de pilotage devient donc la tactique essentielle pour impliquer ceux qui détiennent le pouvoir sur les moyens, les délais, la qualité/la performance. Ce genre de réunion de travail dure généralement 1 à 2 heures au cours desquelles de nombreuses décisions doivent être prises." }, { "type": "list", "ordered": false, "items": ["Quelle direction veut-on donner au projet ?", "Quels sont les éléments dont nous disposons pour prendre une ou plusieurs décisions ?"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c839fd0fe2df1b5566685a_6172b44c4f771fdbcc3951c0_Decision-Kanvan.jpeg", "alt": "Dashboard décision", "caption": "Dashboard des décisions" }, { "type": "heading", "level": 2, "id": "le-deroulement-dun-comite-de-pilotage-projet", "text": "Le déroulement d'un comité de pilotage projet" }, { "type": "paragraph", "html": "Ce type de réunion ne se tient pas au hasard. Des membres de la direction seront présents et c'est aussi l'occasion de vous mettre en valeur personnellement en tant que chef de projet. Le comité de pilotage est un exercice imposé avec ses rituels ses enjeux et ses objectifs." }, { "type": "heading", "level": 3, "id": "deux-etapes-principales-au-sein-dune-meme-presentation", "text": "Deux étapes principales au sein d'une même présentation :" }, { "type": "paragraph", "html": "- L'ordre du jour : analyse des actions en cours, des décisions prises et des décisions à prendre. Ces informations doivent parvenir aux différents acteurs en amont des réunions." }, { "type": "paragraph", "html": "- Le compte rendu du comité de pilotage : qui consigne les décisions prises pendant les réunions. Il est envoyé par le chef de projet." }, { "type": "heading", "level": 2, "id": "nos-conseils-pour-reussir-ses-reunions-de-comite-de-pilotage", "text": "Nos conseils pour réussir ses réunions de comité de pilotage" }, { "type": "paragraph", "html": "L'expérience montre que les parties prenantes sont autant attentives au fond qu'à la forme. C'est pour cela que le support utilisé est très important." }, { "type": "paragraph", "html": "Les <a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">outils de reporting</a> et de mesure de la performance sont très utiles, mais quand vient le moment de préparer la réunion du comité de pilotage vous devez être attentif à quelques points de première importance :" }, { "type": "list", "ordered": false, "items": ["Préparez-vous bien : connaître ses chiffres, avoir en tête les étapes importantes du projet, mais aussi les enjeux politiques et stratégiques relatifs au projet."] }, { "type": "list", "ordered": false, "items": ["Restez synthétique : \"Droit au but\" doit être votre devise. Le comité de pilotage est là pour prendre des décisions pas pour écouter vos louanges ou vos plaintes. Si problème il y a, abordez-le directement en début de réunion et sans détour"] }, { "type": "list", "ordered": false, "items": ["Choisissez le bon support de présentation : Pour que le pilotage de vos projets soit une réussite, la forme compte autant que le fond. Il existe de nombreux modèles de présentation, à vous de choisir celui qui vous convient le mieux ou qui sera le plus parlant pour les comités auprès desquels vous allez devoir présenter l'avancée des opérations. Vos tableaux de bord doivent être concis et inciter à l'action. L'utilisation des couleurs est vivement recommandée."] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c839fd0fe2df1b5566683c_6172b482ccc5f50aab186460_Projet-timeline.jpeg", "alt": "Timeline projet", "caption": "Les jalons d'un projet" }, { "type": "list", "ordered": false, "items": ["Choisissez le bon niveau de communication : Un manager ne veut pas et ne doit pas rentrer dans le détail pour prendre une décision stratégique sur des projets. Pendant la semaine vous interagissez avec des opérationnels, dans les comités de pilotage vous vous adressez à des décisionnaires pressés par le temps. Utilisez le même langage que vos interlocuteurs, le mimétisme aide à faire passer les messages."] }, { "type": "heading", "level": 3, "id": "soyez-lambassadeur-de-votre-projet", "text": "Soyez l'ambassadeur de votre projet !" }, { "type": "paragraph", "html": "Les accomplissements de l'équipe projet doivent absolument être mis en avant lors de ce type de réunions. Un projet qui est un succès c'est un projet dont toutes les parties prenantes ont l'impression que les choses avancent vite et bien." }, { "type": "paragraph", "html": "Il y a donc un objectif de performance auquel les membres du comité seront attentifs. N'hésitez pas à mettre en avant tous les acteurs qui travaillent sur le projet, notamment les équipes métiers." }, { "type": "paragraph", "html": "Dans un projet il y a toujours certains \"oubliés\" ; le chef de projet est aussi là pour embarquer tous les membres de son équipe vers le même objectif." }], "toc": [{ "label": "Qu'est-ce qu'un comité de pilotage ?", "href": "#quest-ce-quun-comite-de-pilotage", "level": 2 }, { "label": "Le déroulement d'un comité de pilotage projet", "href": "#le-deroulement-dun-comite-de-pilotage-projet", "level": 2 }, { "label": "Nos conseils pour réussir ses réunions de comité de pilotage", "href": "#nos-conseils-pour-reussir-ses-reunions-de-comite-de-pilotage", "level": 2 }], "faq": [], "related": [] }, { "slug": "le-portefeuille-projets-pour-faire-grandir-les-collaborateurs-et-lorganisation", "skip": false, "meta": { "title": "Le portefeuille projets pour faire grandir les collaborateurs et l'organisation", "h1": "Le portefeuille projets pour faire grandir les collaborateurs et l'organisation", "description": "Ma boîte n'est pas assez mature en gestion de projet pour aller vers une gestion de Portefeuille projets. Découvrez les arguments pour et contre, et un retour d'expérience PMO.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/644fbfa227c55147fd413a16_PPM%20vs%20PM%20(1)-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "1/5/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "1/5/2023" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/644f9604c5625d462c6f386f_maturite%CC%81%20(4)-min.jpg", "alt": "Ma boîte est elle trop immature en gestion de projet ?", "caption": "Dsi / project management office en plein atelier de prise de décision stratégique ^^" }, { "type": "paragraph", "html": "<em>\"Ma boîte n'est pas assez mature en gestion de projet pour aller vers une gestion de Portefeuille projets.\"</em>" }, { "type": "paragraph", "html": "C'est la phrase que nous entendons le plus souvent lors des démonstrations d'AirSaas." }, { "type": "paragraph", "html": "Pour rappel, AirSaas rentre dans la catégorie des PPM (Portfolio Project Management) mais on préfère se définir comme un <strong>outil de gouvernance projet</strong>. -&gt; cf. notre grand guide : \"<a href=\"/gestion-de-projet/portfolio-project-management-le-top-10-des-bonnes-pratiques\">Portfolio project management le top 10 des bonnes pratiques</a>\"." }, { "type": "paragraph", "html": "Dans cet article nous vous proposons de <strong>revenir sur les arguments</strong> les plus courants en faveur d'un immobilisme sur les processus de gouvernance et de les confronter aux arguments d'un éditeur engagé en faveur de l'implémentation d'un outil de gouvernance moderne !&nbsp; <br>Vous allez <strong>entendre le procureur et l'avocat !</strong> À vous de vous faire votre jugement à la fin. ^^" }, { "type": "paragraph", "html": "Nous partagerons aussi un retour d'expérience sur la mise en œuvre de la fonction PMO - Bureau des projets dans une structure à faible maturité projet." }, { "type": "paragraph", "html": "Bonne lecture.<br>" }, { "type": "heading", "level": 2, "id": "cinq-niveaux-de-maturite-en-gestion-de-projet-pour-une-entreprise", "text": "Cinq niveaux de maturité en gestion de projet pour une entreprise :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/644fc127c077ef35e77aa01c_maturite%CC%81-projet.jpg", "alt": "Les 5 stades de maturité en gestion de projet", "caption": "Toutes les entreprises ont une solution de transformation et innovation à leur portée" }, { "type": "list", "ordered": true, "items": ["<strong>Niveau initial</strong> : À ce niveau, l'entreprise n'a <strong>pas encore de processus de gestion de projet formalisés</strong>. Les projets sont gérés de manière ad hoc, sans objectifs, normes ni procédures établies.", "<strong>Niveau de base</strong> : À ce niveau, l'entreprise a établi des processus de gestion de projet de base, mais ils ne sont <strong>pas encore uniformément appliqués</strong> dans toute l'entreprise. La gestion de projet est encore considérée comme une activité secondaire.", "<strong>Niveau intermédiaire</strong> : À ce niveau, l'entreprise a des processus de gestion de projet solides et uniformément appliqués dans toute l'entreprise. La gestion de projet est considérée comme une activité clé et est <strong>intégrée à la stratégie globale</strong> de l'entreprise.", "<strong>Niveau avancé</strong> : À ce niveau, l'entreprise a établi <strong>une culture de gestion de projet</strong> forte, et la gestion de projet est considérée comme une compétence clé pour les employés. L'entreprise utilise des méthodes de gestion de projet avancées et le rôle de <strong>PMO est considéré comme stratégique.</strong> Elle est en mesure de gérer des projets complexes et à grande échelle.", "<strong>Niveau de pointe (aka Ninja !)</strong> : À ce niveau, l'entreprise a atteint l'excellence en matière de gestion de projet et utilise des méthodes et des outils de pointe. La gestion de projet est intégrée dans tous les processus de l'entreprise, et elle est <strong>considérée comme un avantage concurrentiel.</strong>"] }, { "type": "paragraph", "html": "Bien sûr, lorsqu'on évoque la culture <strong>on est en pleine subjectivité</strong>.&nbsp; Il est important de noter que chaque entreprise a son propre rythme et sa propre trajectoire de développement en matière de gestion de projet, et que l'atteinte de chaque niveau de maturité peut prendre du temps.<br>" }, { "type": "heading", "level": 2, "id": "les-arguments-contre-une-demarche-de-portefeuilles-de-projets-dans-une-organisation-pas-assez-mature-en-gestion-de-projets", "text": "Les arguments contre une démarche de portefeuilles de projets dans une organisation pas assez \"mature\" en gestion de projets" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/644fc077bf2fa10ad799c90e_entreprise-maturite%CC%81-projet-PPM-min(1).jpg", "alt": "Les arguments contre une démarche de portefeuilles de projet", "caption": "Durée, prix, clients, logiciel, DSI, mise en œuvre, fonctions, enjeux, rh, marketing, tout peut être prétexte à ne pas changer de solution" }, { "type": "paragraph", "html": "Voici une sélection des 7 arguments qui pourraient être avancés contre le passage au portfolio project management (PPM) dans une entreprise qui n'est pas assez mature en gestion de projet :" }, { "type": "list", "ordered": true, "items": ["<strong>Coûts élevés</strong> : Le passage au PPM peut impliquer des coûts élevés, notamment en termes de formation des équipes, d'acquisition de nouveaux outils et de mise en place de processus plus complexes.", "<strong>Résistance au changement</strong> : Les équipes pourraient résister au changement et avoir du mal à s'adapter à une nouvelle approche de gestion de projet.", "<strong>Complexité accrue</strong> : Le PPM peut être perçu comme trop complexe et difficile à mettre en place, surtout si l'entreprise n'a pas encore une culture de gestion de projet solide.", "<strong>Temps de mise en place</strong> : La mise en place du PPM peut prendre du temps, ce qui pourrait retarder les projets en cours.", "<strong>Adaptabilité</strong> : Le PPM peut ne pas être adapté à tous les types de projets et certaines entreprises pourraient avoir besoin d'une approche plus flexible.", "<strong>Perte de contrôle</strong> : Les équipes pourraient avoir l'impression de perdre le contrôle sur leurs projets, car la gestion est centralisée à un niveau plus élevé.", "<strong>Nécessité de changements organisationnels</strong> : Le PPM peut nécessiter des changements organisationnels importants pour être efficace, ce qui peut être difficile à mettre en place dans une entreprise qui n'est pas suffisamment mature en gestion de projet."] }, { "type": "paragraph", "html": "Il est important de prendre en compte ces contre-arguments <strong>avant de décider de passer au portefeuille de projets</strong>. Il est possible que certains d'entre eux soient plus pertinents pour votre entreprise que d'autres." }, { "type": "heading", "level": 2, "id": "les-arguments-pour-une-demarche-de-portefeuilles-de-projet-dans-une-organisation-pas-assez-mature-en-gestion-de-projet", "text": "Les arguments pour une démarche de portefeuilles de projet dans une organisation pas assez \"mature\" en gestion de projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/644fc03714d787c0576e61f8_maturite%CC%81-PPM-min.jpg", "alt": "Les contres arguments pour une démarche de Portefeuille project management dans une organisation pas assez mature en gestion de projet.", "caption": "Quelle valeur ? Quel outil ?" }, { "type": "list", "ordered": true, "items": ["<strong>Coûts élevés</strong> : Oui, si on compare un outil d'alignement de gouvernance à un logiciel collaboratif...c'est sûr. Sauf qu'en l'occurrence <strong>on touche à l'OS de votre boîte</strong> ! Et bien que la mise en place du PPM puisse impliquer des coûts initiaux, les avantages à long terme peuvent largement justifier ces investissements, notamment en termes d'amélioration de la performance, de réduction des coûts, de fidélisation des talents et d'<strong>alignement stratégique</strong> !", "<strong>Résistance au changement</strong> : surtout, <strong>ne pas parler de changement</strong> ! Il est vrai que le changement peut être difficile à accepter pour certaines équipes, mais une communication claire et une formation adéquate peuvent aider à réduire la résistance et faciliter l'adaptation à la nouvelle approche de gouvernance. Changer, c'est exister demain ! Demandez à Kodak et BlackBerry !&nbsp; (Sur ce point, on vous reccomande de jetter un clic sur la matrice de Knoster pour un changement réussi. cf le Blog Pro de la Transfo - article Pilotage de projet ce qui a changé en 2023).", "<strong>Complexité accrue</strong> : Bien que le PPM puisse sembler complexe au premier abord, Au contraire <strong>prendre de la hauteur est un processus 100% naturel</strong>. Ce qui est complexe c'est de gérer les projets de façon micro ! Et, une fois le set up et les trois premières semaines passées, lorsque l'outil, les process et rôles sont en place, la gestion de projet peut elle aussi se simplifier, <strong>devenir plus efficace</strong> et être moins sujette à des erreurs et des retards.<br>", "<strong>Temps de mise en place</strong> : Bien que la mise en place du PPM puisse prendre du temps (compter 1 à 2 mois en moyenne), cela peut aider à établir une base solide pour une gestion de projet plus efficace et plus efficiente à long terme. <strong>Le fait d'y voir plus clair sur l'ensemble du processus et d'automatiser le reporting</strong> aux instances dirigeantes, permettra in fine de <strong>dépolluer vos chefs de projets</strong> avec certains chantiers toxiques et de leur <strong>dégager du temps</strong> de bande passante.<br>", "<strong>Adaptabilité</strong> : Bien que le PPM puisse ne pas être adapté à tous les types de projets, il peut être modulable pour s'adapter à différentes situations et contextes. On le répète, ce n'est <strong>pas réservé aux start-up, ETI et grands groupes</strong>, à partir du moment où vous êtes sur un marché et que vous <strong>faites des projets transverses, vous êtes concernés</strong> !&nbsp;Quelque soit vos secteurs, tout le monde est concerné !", "<strong>Perte de contrôle</strong> : là, on touche un point sensible !&nbsp; Oui, en craquant les silos horizontaux et verticaux, certains chefs de projets <strong>\"barons\" vont perdre une partie de leur pouvoir</strong> au profit d'une <strong>activité mieux partagée</strong> avec les parties prenantes experts métiers, key users, directions générales et sponsors. Et bien que la gestion de projet soit centralisée à un niveau plus élevé, cela aidera à assurer une meilleure visibilité, une meilleure affectation des ressources et une meilleure coordination des projets, ce qui peut en fin de compte améliorer le contrôle et la gouvernance des projets.&nbsp;", "<strong>Nécessité de changements organisationnels :</strong> Bien que le PPM puisse nécessiter des changements organisationnels importants, cela peut aider à aligner la gestion de projet sur la stratégie globale de l'entreprise et à améliorer la communication et la prise de décisions à tous les niveaux. Adopter une démarche de portefeuille de projets &nbsp;et l'un des logiciels compagnon est un pari. <strong>Le pari de faire grandir les collaborateurs et l'organisation.&nbsp;</strong><br>"] }, { "type": "heading", "level": 2, "id": "retour-dexperience-sur-la-mise-en-place-de-la-fonction-pmo-bureau-des-projets-dans-une-structure-a-faible-maturite-projet", "text": "Retour d'expérience sur la mise en place de la fonction PMO - Bureau des projets dans une structure à faible maturité projet" }, { "type": "paragraph", "html": "Mettre en place une fonction PMO et un portfolio project management : par quoi commencer ? Comment passer du \"niveau de base\" au \"niveau intermédiaire\" de maturité ?" }, { "type": "paragraph", "html": "Constance VIVIER, PMO, et membre de la communauté Pro de la Transfo,&nbsp; nous partage ici un bref retour d'expérience, plus d'un an après, de la mise en place d'un bureau des projets." }, { "type": "list", "ordered": true, "items": ["<strong>Adopter un langage commun</strong>"] }, { "type": "paragraph", "html": "Tout d'abord, il vous faudra <strong>poser le socle</strong> : créer ou formaliser un langage projet commun à toute l'entreprise, que ce soit le nom et l'objectif des livrables projets, des phases projets et des instances de gouvernance… Ce sera une bonne idée si vous co-construisez ce cycle de vie projet avec quelques personnes expérimentées. Pour le partager ensuite à l'ensemble de la communauté projets, la mise en place d'ateliers participatifs (sur le modèle de la Fresque du Climat où les participants re-construisaient le cycle projet et ses livrables, en étant guidés par le PMO) en a conquis plus d'un pour son côté ludique et qui \"décomplexifie\" le sujet. Ces \"Fresques\" sont aussi une façon de répondre aux interrogations des chefs de projets et de commencer à insuffler une nouvelle façon d'envisager les choses, en introduisant la gestion de PPM et la nécessaire priorisation des projets." }, { "type": "list", "ordered": true, "items": ["<strong>Instaurer des rituels</strong>"] }, { "type": "paragraph", "html": "Le rôle du PMO doit s'instaurer progressivement et il peut s'incarner notamment par la mise en place de rituels, que ce soit des COPIL et/ou des points bilatéraux avec les chefs de projets. Il est important d'instaurer une fréquence ajustée aux besoins, mais suivie : cela donne le \"tempo\" à la communauté projet… qui peut d'ailleurs être restreinte dans un premier temps, puis s'agrandir de façon progressive en lien avec la maturité projet de l'entreprise. Tous ces rituels doivent être accompagnés du même objectif : apporter de la valeur, autrement le Chef de projet y viendra à reculons et le verra comme une simple perte de temps." }, { "type": "list", "ordered": true, "items": ["<strong>Formaliser les processus</strong>"] }, { "type": "paragraph", "html": "Une fois ce socle établi, je me suis appuyée sur la démarche de management des processus de l'entreprise. J'ai formalisé et partagé le processus du pilotage du portefeuille de projets, afin de faire prendre connaissance aux parties prenantes du pourquoi, du comment, et du RACI de la mise en place du management de portefeuille projets, des différentes catégories de projets définies et leurs impacts (notamment en termes de reporting et gouvernance)." }, { "type": "paragraph", "html": "Après le processus, on enchaîne avec la rédaction et le partage de procédures, qui servent à éclairer des points bloquants pour l'ensemble de la communauté projets. Le rôle du PMO est parfaitement mis en lumière quand des façons de travailler sont clarifiées et que des problèmes sont résolus !" }, { "type": "list", "ordered": true, "items": ["<strong>Normaliser les méthodes projets</strong>"] }, { "type": "paragraph", "html": "Sur la base de \"le PMO propose, les chefs de projets disposent\" (pour commencer),&nbsp; le PMO met à disposition de la communauté des modèles de livrables projets, à la fois pour faire gagner du temps aux chefs de projets, et pour faire monter en compétence l'ensemble du groupe, harmoniser les pratiques. Sur ce point des modèles de livrables, ne pas hésiter à faire du test&amp;learn, et à co-construire avec des chefs de projets que vous savez déjà bien outillés sur l'un ou l'autre des pans de la gestion de projet. De même, pour normaliser les méthodes projets et le processus de PPM, <strong>outillez-vous.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/644fbfd427c55157dd41691c_maturite%CC%81%20(3)-min.jpg", "alt": "", "caption": "Principes actifs à l'œuvre" }, { "type": "paragraph", "html": "À la manière d'un sachet de thé dans de l'eau chaude, vous <strong>infusez progressivement dans l'entreprise la culture projet</strong>, de la gestion de projet au PPM, vers l'excellence opérationnelle. Prochaine étape ? Laisser infuser, ajouter un peu de lait et remuer pour atteindre le niveau avancé…<br>" }, { "type": "heading", "level": 2, "id": "le-verdict-nattendez-pas-que-votre-entreprise-soit-mature-en-gestion-de-projet-pour-lancer-une-demarche-de-gestion-de-portefeuille-sinon-elle-ne-le-sera-jamais", "text": "Le verdict : n'attendez pas que votre entreprise soit \"mature\" en gestion de projet pour lancer une démarche de gestion de portefeuille, sinon elle ne le sera jamais !" }, { "type": "paragraph", "html": "Oui, en matière de transformations et d'innovation managériale la structure agit sur la culture...et réciproquement.&nbsp;" }, { "type": "paragraph", "html": "En résumé, <strong>les processus de gouvernance et d'exécution sont différents ET complémentaires. Votre</strong> transformation mérite une démarche efficace !" }, { "type": "paragraph", "html": "Bien sûr, si rien n'est \"noir ou blanc\" en matière de conseils et de relations humaines. Il y a néanmoins des fondamentaux ! La performance, le gain de parts de marché, la coopération et les processus de décisions, d'investissement, de portefeuilles de projets ne <strong>sont pas réservés aux ETI</strong> !&nbsp;" }, { "type": "paragraph", "html": "Investir dans le but implémenter un bureau des projets / assorti de solutions type de gouvernance type PPM - PMO as a service est un effort qui permettra de <strong>structurer et amplifier une démarche déjà en place</strong> naturellement.&nbsp; Vos équipes pourront y voir clair en un coup d'œil, dégager un temps précieux &nbsp;sur leur plan de charge pour se focaliser sur ce qui compte : <strong>les relations et la bonne coopération transverse !&nbsp;Faites vos choix ^^</strong>" }, { "type": "paragraph", "html": "Et pour creuser ce point clé, rendez-vous sur l'article \"<a href=\"/gestion-de-projet/le-lean-portfolio-management-pour-aligner-en-continu-la-direction-generale-lit-et-les-metiers\">Le Lean Portfolio Management pour aligner en continu la direction générale, l'IT et les métiers\"<strong>.</strong></a><br><br>" }], "toc": [{ "label": "Cinq niveaux de maturité en gestion de projet pour une entreprise :", "href": "#cinq-niveaux-de-maturite-en-gestion-de-projet-pour-une-entreprise", "level": 2 }, { "label": "Les arguments contre une démarche de portefeuilles de projets dans une organisation pas assez \"mature\" en gestion de projets", "href": "#les-arguments-contre-une-demarche-de-portefeuilles-de-projets-dans-une-organisation-pas-assez-mature-en-gestion-de-projets", "level": 2 }, { "label": "Les arguments pour une démarche de portefeuilles de projet dans une organisation pas assez \"mature\" en gestion de projet.", "href": "#les-arguments-pour-une-demarche-de-portefeuilles-de-projet-dans-une-organisation-pas-assez-mature-en-gestion-de-projet", "level": 2 }, { "label": "Retour d'expérience sur la mise en place de la fonction PMO - Bureau des projets dans une structure à faible maturité projet", "href": "#retour-dexperience-sur-la-mise-en-place-de-la-fonction-pmo-bureau-des-projets-dans-une-structure-a-faible-maturite-projet", "level": 2 }, { "label": "Le verdict : n'attendez pas que votre entreprise soit \"mature\" en gestion de projet pour lancer une démarche de gestion de portefeuille, sinon elle ne le sera jamais !", "href": "#le-verdict-nattendez-pas-que-votre-entreprise-soit-mature-en-gestion-de-projet-pour-lancer-une-demarche-de-gestion-de-portefeuille-sinon-elle-ne-le-sera-jamais", "level": 2 }], "faq": [], "related": [] }, { "slug": "le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes", "skip": false, "meta": { "title": "Suivi de projet : comment bien aligner les parties prenantes de vos projets ?", "h1": "Suivi de projet : comment bien aligner les parties prenantes de vos projets ?", "description": "Pas de bonne exécution de stratégie sans l'adhésion de vos parties prenantes ! Découvrez 5 leviers modernes pour maintenir l'alignement des parties prenantes avec efficacité.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea64583733b4c641cca17c_suivi-projet-alignement-parties-prenantes-min.jpeg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "7/7/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "7/7/2022" }, "blocks": [{ "type": "paragraph", "text": "Pas de <strong>bonne exécution</strong> de stratégie sans l'adhésion de vos parties prenantes !" }, { "type": "paragraph", "text": "On va s'intéresser à des <strong>méthodes efficaces en gestion de projet moderne</strong> qui permettront à une équipe projet d'influencer positivement ses parties prenantes - et ce de façon durable !" }, { "type": "paragraph", "text": "D'ailleurs, peut-être êtes-vous en train de vous demander : « Mais pourquoi donc m'intéresserais-je à cet angle mort de la gestion de projet » ? Parce que <strong>l'alignement de vos parties prenantes est une ressource critique</strong> ! Parce que votre projet mérite à chacune des étapes l'engagement constant fort de vos parties prenantes. <br><br>Oui : le budget et les efforts consentis par les membres de l'équipe très impliqués dans les tâches ont besoin du support et de l'alignement de personnes plus éloignées mais concernées, et ce de façon durable. Pour un avancement efficace l'enjeu est de conserver un bon niveau d'énergie, d'engagement autour de l'équipe de projet. Un véritable défi si on n'applique pas de solutions et méthodes de travail modernes." }, { "type": "paragraph", "text": "<strong>Focus ici sur le concept de suivi de projet</strong>, et cinq leviers pour moderniser cette démarche au sein de votre organisation." }, { "type": "heading", "level": 2, "id": "rappel-quest-ce-quun-suivi-de-projet", "text": "Rappel : qu'est-ce qu'un suivi de projet ?" }, { "type": "paragraph", "text": "Un rappel formation si vous arrivez de la planète « je ne connais pas les projets » : <strong>le <a href=\"https://blog-gestion-de-projet.com/gestion-de-projet/controle-suivi-de-projet/\" target=\"_blank\">suivi de projet</a> a pour but de contrôler la bonne exécution</strong> selon le planning établi, la qualité attendue et que les ressources humaines, matérielles et financières sont bien respectées, ainsi que le statut des jalons. C'est un outil de contrôle et de validation. Il sert les objectifs du projet - vous avez donc de bonnes raisons de vous y attarder un instant." }, { "type": "paragraph", "text": "Quant à elles, les parties prenantes, sont des personnes qui ont un intérêt quelconque dans le résultat de votre projet. Les personnes qui vont impacter ou être impactés dans la durée par le projet. Il y en a toujours plus qu'on ne pense ! Cette notion quelque peu vague recouvre des réalités bien différentes. Quand c'est flou, il y a un loup. À vous d'apporter de la précision. C'est un adage bien connu en gestion de projet !" }, { "type": "paragraph", "text": "Pour creuser le sujet, consulter notre <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">grand guide de la conduite de projet</a>." }, { "type": "heading", "level": 2, "id": "le-suivi-de-projet-traditionnel-soccupe-peu-ou-mal-des-parties-prenantes", "text": "Le suivi de projet traditionnel s'occupe peu (ou mal) des parties prenantes" }, { "type": "list", "ordered": false, "items": ["On est témoin depuis des années de projets qui, soit négligent leurs parties prenantes, soit à l'opposé sont écrasés par le poids de leurs parties prenantes.", "Le <strong>processus de gestion de projet</strong> lui-même est l'objet d'écarts types énormes entre des organisations à forte culture projet, uniformisée et outillée, et celles plus informelles pseudo « agiles », voire toxiques pour une entreprise.", "Il existe un « fossé informationnel » entre les managers de projet, la DG, l'équipe, et les parties prenantes internes et externes. Facteur aggravant : quand l'information parvient jusqu'aux parties prenantes, elle l'est rarement dans un vocabulaire inclusif, en français dans le texte. Car oui ça jargonne sec au sein de la tech ! Essayons de parler la même langue entre acteurs pour atteindre les mêmes objectifs.", "Enfin, autour des projets eux-mêmes, il y a une tendance générale au désengagement dans les grandes entreprises."] }, { "type": "heading", "level": 3, "id": "la-matrice-pouvoirinteret-des-parties-prenantes-est-elle-encore-adaptee", "text": "La matrice Pouvoir/Intérêt des parties prenantes est-elle encore adaptée ?" }, { "type": "paragraph", "text": "Parlons de la <em>stakeholder map</em>, cette méthode de cartographie des parties prenantes qui est enseignée dans les formations en gestion de projet. On nous apprend l'importance d'un plan de gestion pour situer les différents acteurs clés sur une matrice pouvoir d'influence / intérêt. C'est sans aucun doute une bonne base de réflexion pour formaliser votre stratégie, et n'oublier aucunes parties prenantes. Il y en a toujours plus qu'on ne pense ! Attention : chaque projet doit inclure tout le monde : fournisseurs et sous-traitants sont aussi des parties prenantes." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea63e4dc7075f6681ede9d_15acb6f3-77e2-429c-b54a-459a7ef33c96-min.png", "alt": "Matrice impact parties prenantes", "caption": "Matrice impact / parties prenantes" }, { "type": "paragraph", "text": "Néanmoins, si on schématise volontairement, cette approche du plan projet sous-entend de focaliser son attention et sa communication sur les parties prenantes clés. Quelque part, c'est ne pas avoir compris l'évolution culturelle liée à la digitalisation des organisations. Une évolution qui a permis <strong>plus d'horizontalité dans les rapports en entreprise</strong>. Tout le monde compte. N'importe quel collaborateur doit pouvoir interagir sur le suivi d'avancement du projet à travers des moyens de communication variés." }, { "type": "quote", "text": "🎙 « Un point indispensable dans la transfo., ce sont les aspects de communication. On ne communique jamais assez. En tout cas de façon assez ciblée et efficace. La transformation c'est quelque chose qui peut faire peur aux personnes. Si on ne communique pas, les projets peuvent être perçus comme un risque. »", "author": "Alexia Schmitt, Directrice de la Transformation et des Systèmes d'Information Centrimex — épisode 22 du Podcast CIO Révolution by AirSaas" }, { "type": "heading", "level": 3, "id": "suivi-de-projet-larrivee-des-plateformes-change-la-donne", "text": "Suivi de projet : l'arrivée des plateformes change la donne" }, { "type": "paragraph", "text": "<strong>Fini le pilotage par email ou un blog projet !</strong> On a maintenant une gestion de projet augmentée. Rappelez-vous l'exemple de l'automobile, et des premiers régulateurs et limiteurs de vitesse. Ils se généralisent aujourd'hui ! Dans le suivi de projet, une modernisation des processus est en route. Ne doutons pas de ces mises à jour en cours. Et choisissons le meilleur assistant, la meilleure aide pour tous les membres de l'équipe." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c29a3937b20e00d9499c6c_tdb-airsaas.png", "alt": "Capture écran AirSaas", "caption": "Rejoignez les équipes projet / parties prenantes qui réussissent" }, { "type": "heading", "level": 2, "id": "5-leviers-modernes-pour-maintenir-lalignement-des-parties-prenantes-avec-efficacite", "text": "5 leviers (modernes) pour maintenir l'alignement des parties prenantes avec efficacité" }, { "type": "paragraph", "text": "L'alignement ça ne se décrète pas...ça se construit pas à pas dans la sincérité et le respect mutuel. Chaque partie prenante peut ou pas faire le choix de s'aligner malgré les difficultés rencontrées - ou à cause d'elles. Pour nous faciliter la vie et trouver des pistes de solutions on a listé 5 leviers d'action. Découvrez ici notre sélection." }, { "type": "list", "ordered": true, "items": ["Établissez le « pourquoi » clair de chacun", "Instaurez des rituels", "Fixez la transparence à 100 %", "Redonnez une direction claire ou tout le monde sera perdu !", "Surprenez vos parties prenantes !"] }, { "type": "heading", "level": 3, "id": "1-etablissez-le-pourquoi-clair-de-chaque-partie-prenante", "text": "1. Etablissez le \"pourquoi ?\" clair, de chaque partie prenante" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c6a5d78fedcc2b88c831b2_cercle-or-startwhy-airsaas.png", "alt": "Le cercle d'or commencez par le pourquoi", "caption": "Le cercle d'or commencez par le pourquoi" }, { "type": "paragraph", "text": "Dès le cadrage du plan projet, vos premières consultations serviront à <strong>identifier le « pourquoi » clair de vos parties prenantes</strong>. Pourquoi veulent-elles être impliquées dans le projet ! Qu'est-ce qu'elles en attendent à titre personnel ?" }, { "type": "paragraph", "text": "Grâce à cette étape vous comprendrez clairement ce qui est fondamental pour eux, leur « mission »." }, { "type": "paragraph", "text": "Attention : de façon globale, ils sont sans doute OK avec les objectifs du projet. Creusez ! Car dans le détail ils peuvent vous dire « non je n'aime pas vraiment ça ». Tout est normal. Ce qui est fondamental à ce stade, c'est de formaliser l'accord. Tous les chefs de projet le savent : ce qui n'est pas écrit n'existe pas. Cela fait partie des contraintes du métier. « <strong>Factualisez » et établissez ensemble, dans un accord collectif, les indicateurs à suivre tout au long du projet.</strong>" }, { "type": "paragraph", "text": "Enfin rappelons-le : après la discussion avec les dirigeants, pour une bonne mise en œuvre, menez cette démarche à tous les étages, et continuez avec toutes les parties prenantes de la transformation, pour réellement aligner l'ensemble de vos planètes de transfo. digitale." }, { "type": "paragraph", "text": "Le travail de cartographie matrice pouvoir/intérêt décrit ci-dessus vous servira utilement de point de départ pour travailler ce levier." }, { "type": "heading", "level": 3, "id": "2-instaurez-des-rituels-avec-vos-parties-prenantes", "text": "2. Instaurez des rituels avec vos parties prenantes" }, { "type": "paragraph", "text": "Connaissez-vous la différence entre un rituel et une habitude ? Le premier est pratiqué de façon « choisie », le second en mode « automatique » et parfois « subie »." }, { "type": "paragraph", "text": "<strong>Soignez vos rituels</strong> avec les parties prenantes. Routines et rituels sont ce qui donnera le rythme !" }, { "type": "paragraph", "text": "Vous voulez sortir du « désalignement » chronique ? Insufflez le rythme dont le projet a besoin. <strong>Banalisez, crantez, « sacralisez » des rituels clairs dans les emplois du temps des parties prenantes.</strong>" }, { "type": "paragraph", "text": "Par exemple :" }, { "type": "list", "ordered": false, "items": ["<strong>Tous les mardis</strong> : un point de synchronisation et de planification du projet d'une demi-heure", "<strong>Tous les vendredis</strong>* : le flash report est envoyé automatiquement à toutes les parties prenantes de suivi du projet"] }, { "type": "paragraph", "text": "* oui, oui, pas une fois tous les mois...!" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62bdfca88290d29985904cb5_report-flash.png", "alt": "Flash rapport AirSaas", "caption": "Le rapport flash automatique est votre meilleur allié vis-à-vis de vos parties prenantes" }, { "type": "paragraph", "text": "Cela prendra du temps, certes - mais le jeu en vaut la chandelle. Quand vous êtes impliqué dans une œuvre, vous ne la critiquez plus de la même manière. Vous basculez dans la co-construction." }, { "type": "paragraph", "text": "Allez au-delà de la simple écoute et répondez aux préoccupations ou aux griefs soulevés par les parties prenantes. <strong>Démontrez que vous êtes disposé à avoir une conversation</strong> et à vous engager dans une discussion significative sur les problèmes rencontrés lors du suivi des projets." }, { "type": "paragraph", "text": "Parce que la transformation c'est avant tout une aventure humaine, avoir une communication transversale est indispensable. Sinon, ça risque de piquer !" }, { "type": "heading", "level": 3, "id": "3-transparence-a-100-percent-engagement-a-100-percent", "text": "3. Transparence à 100 % = engagement à 100 % !" }, { "type": "paragraph", "text": "Cette injonction à la transparence est sans doute la plus difficile à suivre. Et pourtant, elle est un vrai marqueur de respect. Elle renforcera la confiance, et donc l'engagement, des parties prenantes. Elle est l'une des recettes pour sortir du cercle vicieux : silos d'informations → frustration → désengagement. Finis, les reportings dans un logiciel de gestion de projet siloté et caché !" }, { "type": "paragraph", "text": "Soyez intransigeants : zéro conversation privée, pas de silos d'informations dans vos méthodes de management de projet. Rappelons-le : <strong>sans transparence pas d'engagement !</strong> Plus on met de barrières plus on essaye de cacher, plus ça se retourne contre nous. Rien de bon ne peut venir du manque de transparence vis-à-vis des parties prenantes." }, { "type": "paragraph", "text": "Bien sûr, les informations sensibles sont des informations sensibles que vous mettez dans votre tiroir et que vous garderez sous clé. Mais <strong>essayez d'éviter les vides d'informations ou de communication où rien n'est dit à cause de la peur</strong>. Sinon, ce qui risque de se passer dans l'esprit des parties prenantes : ils s'inventent des histoires. Vous ne leur parlez pas du programme et de la façon dont il se déroule ? Ils se font leur propre version ! Et elle sera sans doute pire que la réalité. Rappelez-vous la nature a horreur du vide." }, { "type": "paragraph", "text": "Soyez <strong>transparents avec les délais, la gestion des ressources, le tableau de bord, le budget, les outils de suivi, les données</strong> : c'est la seule façon d'établir la confiance." }, { "type": "paragraph", "text": "Si vous échouez faites savoir aux gens que vous échouez. Si vous ne savez pas ce que vous faites, faites savoir aux gens que vous ne savez pas ce que vous faites. C'est facile." }, { "type": "quote", "text": "Il n'y a aucun projet qui se passe comme prévu ! Les directions générales apprécient la transparence. Ce qu'elles n'apprécient pas, c'est quand vous cachez quelque chose et que, trois ans plus tard, elles découvrent qu'il y a eu un écart dans la trajectoire.", "author": "Thomas Vrignaud — CIO - CDO, extrait de l'épisode 14 du Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "Bonne nouvelle : à l'opposé des anciens outils de gestion des tâches et de projets « silotés », avec AirSaas, vous pourrez assurer une transparence totale sur l'avancement des projets, les décisions, les objectifs, les moyens, les résultats !" }, { "type": "paragraph", "text": "Objectif : 100% de visibilité sur l'état de santé et le déroulement du projet." }, { "type": "heading", "level": 3, "id": "4-une-direction-claire-ou-tout-le-monde-sera-perdu", "text": "4. Une direction claire, ou tout le monde sera perdu" }, { "type": "paragraph", "text": "Donnez et <strong>rappelez le sens du projet dans la stratégie mise en place par l'entreprise.</strong>" }, { "type": "paragraph", "text": "Repartagez fréquemment au-delà de l'évolution du projet, la « grande image », le sens global de ce à quoi chacun contribue." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62714920747026c0d398526b_transformation.jpeg", "alt": "programme versus projet", "caption": "Une vision claire qui fera « sens » pour tous" }, { "type": "paragraph", "text": "On l'a déjà dit au kick-off ? Oui, et de l'eau a coulé sous les ponts. Dans une époque de sur-information chronique, c'est plus que probable que beaucoup de vos parties prenantes aient oublié la moitié des informations clés sur le sens et la portée du projet." }, { "type": "paragraph", "text": "Quels sont les objectifs stratégiques auxquels le projet participe ? Dans quel programme de transformation s'insère-t-il ? Quelle est la valeur métier créée pour l'entreprise, ses clients ?" }, { "type": "paragraph", "text": "Bref : sortons la tête du guidon !" }, { "type": "paragraph", "text": "Confucius (encore lui !) le soulignait « <em>Si vous ne savez pas où vous allez, n'importe quel chemin vous y mènera.</em> » De la même manière, dans un programme de transformation, si vous n'avez pas de plan, vous allez suivre le plan de quelqu'un d'autre à la place !" }, { "type": "paragraph", "text": "La <a href=\"https://www.airsaas.io/fr/gestion-de-projet/trois-innovations-et-tendances-qui-bousculent-la-gestion-de-portefeuille-de-projets\" target=\"_blank\">gestion de portefeuille de projets</a>, ou bien le <em>project management</em> seul, nécessitent des feuilles de routes collaboratives." }, { "type": "paragraph", "text": "L'objectif reste d'y voir clair dans la gestion de projets pour des décisions, priorisations par la valeur, par le collaboratif et en continu !" }, { "type": "paragraph", "text": "Et rappelons-le : un écart dans la trajectoire, ça arrive tout le temps. Dans un monde mouvant, ce qui est important, c'est d'ajuster ! Les schémas directeurs à trois ans sont morts : vive les <em>rolling roadmaps</em> collaboratives qui s'actualisent tout en gardant le cap des objectifs." }, { "type": "heading", "level": 3, "id": "5-ajoutez-du-fun-surprenez-vos-parties-prenantes", "text": "5. Ajoutez du fun, surprenez vos parties prenantes" }, { "type": "paragraph", "text": "Un projet de transformation bouscule les organisations les process, les habitudes... en dehors de vos réunions de suivi de projet, <strong>prenez soin de vos parties prenantes</strong> dans cette phase de transition." }, { "type": "paragraph", "text": "À force de focaliser sur la gestion des risques, les objectifs, la valeur, on finit par oublier que nous avons tous en commun un grand besoin de variété, de plaisir, de créativité...Bref : variez les plaisirs ! Soyez authentiques et fun." }, { "type": "list", "ordered": false, "items": ["<strong>Utilisez des outils visuels</strong> : des GIF et tous les « artefacts » légers", "<strong>Renouvelez vos processus</strong> en puisant dans la panoplie des jeux agiles « qui font le travail »", "<strong>Remercier chacune des parties prenantes</strong> du projet avec un cadeau à l'issue d'un grand jalon ou d'échéances importantes", "<strong>Dépaysez le lieu du comité projet</strong>, son heure, son format...", "<strong>Invitez des personnalités extérieures</strong> à l'entreprise*"] }, { "type": "paragraph", "text": "* Tips de DSI :" }, { "type": "paragraph", "text": "On peut parfois <strong>faire appel à des personnalités extérieures à l'entreprise</strong> afin de redonner du peps à la vision ou à l'exécution du projet, ou encore faire appel à des experts qui permettront de clarifier certains sujets et/ou à éliminer certains biais cognitifs potentiellement bloquants de certaines parties prenantes." }, { "type": "paragraph", "text": "Astuce à double tranchant cependant. Car l'« invité surprise » ponctuel peut arriver comme un « cheveu sur la soupe », c'est un élément perturbateur dont la valeur ajoutée est toute relative. Si c'est un expert, alors pourquoi ne pas lui demander de rédiger une note de recommandation sur un sujet précis et l'envoyer aux personnes concernées en amont de la réunion ? Bref : <strong>surprenez, innovez toujours avec modération et discernement !</strong>" }, { "type": "heading", "level": 2, "id": "a-retenir", "text": "À retenir" }, { "type": "insight-callout", "label": "À retenir", "html": "<p>Au-delà donc du prérequis d'une cartographie dynamique des parties prenantes et des premiers leviers présentés, gardons bien en tête <strong>le côté humain et donc complexe, d'un projet de transformation.</strong> C'est ce qui en fait la saveur !</p><p>Vous avez toutes les clés pour vous appuyer sur vos parties prenantes ? Vous savez comment mettre en place une méthode pragmatique. Pour finir le geste, l'équipe Pro. de la Transfo. vous propose de découvrir un article spécial sur le <a href=\"/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">Plan de communication projet : comment éviter l'échec ?</a></p>" }], "toc": [{ "label": "Rappel : qu'est-ce qu'un suivi de projet ?", "href": "#rappel-quest-ce-quun-suivi-de-projet", "level": 2 }, { "label": "Le suivi de projet traditionnel s'occupe peu (ou mal) des parties prenantes", "href": "#le-suivi-de-projet-traditionnel-soccupe-peu-ou-mal-des-parties-prenantes", "level": 2 }, { "label": "5 leviers (modernes) pour maintenir l'alignement des parties prenantes avec efficacité", "href": "#5-leviers-modernes-pour-maintenir-lalignement-des-parties-prenantes-avec-efficacite", "level": 2 }, { "label": "À retenir", "href": "#a-retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "lean-portfolio-management", "skip": false, "meta": { "title": "Le Lean Portfolio Management pour aligner en continu la direction générale, l'IT et les métiers", "h1": "Le Lean Portfolio Management pour aligner en continu la direction générale, l'IT et les métiers", "description": "Le Lean Portfolio Management pour aligner en continu la direction générale, l'IT et les métiers", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/637282ddbdb2ae01ff017954_lean-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "14/11/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "14/11/2022" }, "blocks": [{ "type": "paragraph", "text": "Les questions de priorisation<strong> </strong>et de recherche d'efficacité opérationnelle de la transformation sont des sujets qui préoccupent de nombreux dirigeants. \"Tout le monde se gratte la tête\" résumait avec humour un membre de la communauté AirSaas Pro de la Transfo, DSI expérimenté, lors d'une interview." }, { "type": "paragraph", "text": "Et avouons-le, les<strong> </strong>directions générales et métiers<strong> </strong>sont parfois difficiles à embarquer dans une <strong>culture Lean-agile </strong>de gestion des portefeuilles projets, vue souvent comme un sujet purement IT<strong>.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6372777e36584e69b2eebab4_image-asset-min.jpeg", "alt": "Dessin hmour alignement business / IT", "caption": "L'art d'aligner l'IT et les métiers dans les organisations" }, { "type": "paragraph", "text": "Dans cet article nous allons nous intéresser à l'exécution<strong> </strong>de votre stratégie d'entreprise en continu<strong>, e</strong>t à l'exécution de votre stratégie commerciale sur l'angle de la gestion de portefeuille Lean<strong>.</strong> Au dialogue et à la coopération entre les silos, à votre flux de valeur, à la répartition budgétaire. On cherchera à en savoir plus sur des approches promettant d'améliorer votre processus agile et de renforcer la valeur ajoutée de vos projets. En un mot : on cherchera à <strong>muscler l'efficacité de votre </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/portfolio-management-pourquoi-il-faut-en-finir-avec-excel\" target=\"_blank\"><strong>portfolio management</strong></a><strong>.</strong>" }, { "type": "paragraph", "text": "On parlera de Kanban, de value stream mapping, de frameworks agiles à l'échelle, &nbsp;de management visuel et peut-être même d'un agile release trains !" }, { "type": "paragraph", "text": "Disclaimer ! Ces sujets sont complexes. Attention, si vous cherchiez un article no brainer... restez un peu !<br>Ici nous avons ici l'objectif de traiter ces thèmes, en partageant des convictions, et en restant le plus pragmatique possible - le tout, avec un<strong> </strong>filtre \"anti langue de bois\" activé<strong>.</strong>" }, { "type": "paragraph", "text": "Du reste, on saupoudrera cet article de quelques pincées d'historique et de sémantique sur le Lean, notamment quand il s'agira de comprendre l'origine et le sens des concepts clés. Parce que revenir aux sens des mots permet d'avoir une approche basée sur le principe et la démarche versus une approche simpliste, type boîte à outils !" }, { "type": "heading", "level": 2, "id": "les-3-problemes-lies-a-la-gestion-actuelle-de-portefeuille-projets", "text": "Les 3 problèmes liés à la gestion actuelle de portefeuille projets" }, { "type": "heading", "level": 3, "id": "la-gestion-actuelle-de-portefeuille-est-trop-statique", "text": "La gestion actuelle de portefeuille est trop statique" }, { "type": "paragraph", "text": "Planifier un an à l'avance n'est plus réaliste<strong>.</strong> Dans ce fameux monde VICA (volatile incertain complexe et ambigu), lorsque le marché, le management, ou le scope connaissent des changements rapides et des perturbations,<strong> les méthodes traditionnelles de gestion de portefeuille de produits ne permettent plus de gérer efficacement</strong>." }, { "type": "paragraph", "text": "Un exemple parmi tant d'autres. Les équipes agiles livrent sur des sprints de 2 à 3 semaines alors que, dans bien des cas, les portefeuilles sont figés sur l'année !" }, { "type": "paragraph", "text": "Cette <strong>contradiction temporelle</strong> s'applique également à la<strong> </strong>prise de décision<strong>. </strong>Celle-ci est souvent jugée par les opérationnels comme étant trop longue, et impliquant trop de gens." }, { "type": "paragraph", "text": "De même, sur des échelles de temps<strong> </strong>à 18 mois, les estimations budgétaires sont imaginaires ! Et finalement, peu importe le fond : ce qui est important, c'est de convaincre la finance pour obtenir les budgets." }, { "type": "heading", "level": 3, "id": "la-valeur-livree-est-inversement-proportionnelle-au-temps-passe", "text": "La valeur livrée est inversement proportionnelle au temps passé" }, { "type": "paragraph", "text": "Il faut le rappeler encore : la valeur livrée n'est pas la quantité livrée !" }, { "type": "paragraph", "text": "La philosophie agile met l'accent sur la livraison de fonctionnalités à valeur ajoutée, dans un délai réduit, comme l'un des indicateurs de réussite pour l'équipe." }, { "type": "paragraph", "text": "Le schéma ci-dessous illustre cette tendance, et nous invite à lutter contre le syndrome du \"toujours plus\" déconnecté de la valeur livrée." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6372769ad3fafa7dae1df7ae_9582760d-8d4b-4255-93d8-c7509761df38.png", "alt": "Pas besoin d'une formation de trois jours...Une image vaut mille mots", "caption": "Pas besoin d'une formation de trois jours...Une image vaut mille mots" }, { "type": "heading", "level": 3, "id": "on-ne-voit-pas-assez-la-big-picture-de-la-transformation", "text": "On ne voit pas assez la \"big picture\" de la transformation" }, { "type": "paragraph", "text": "Pour mieux prioriser et aligner en continu,<strong> on a besoin de voir une \"grande image\" ! </strong>" }, { "type": "paragraph", "text": "D'une façon générale, on peut le dire : les directions générales, IT, métiers, et les chefs de projets ont trop de sujets à adresser. Sans des regroupements synthétiques, il est très difficile de vraiment travailler ensemble, de coopérer." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d865ac5b58cf4e7ed4990f_62714920747026c0d398526b_transformation.jpeg", "alt": "Une vision claire qui fera \"sens\" pour tous !", "caption": "Une vision claire qui fera sens pour tous !" }, { "type": "paragraph", "text": "À partir d'une \"big picture\" les différentes parties prenantes pourront mieux<strong> évaluer l'importance individuelle&nbsp;relative de chacun des projets</strong> soumis." }, { "type": "paragraph", "text": "Et plus encore : grâce à cette vision globale, nous pourrons regrouper certaines demandes et pourrons peut-être voir des synergies et regrouper ces différentes idées de projets pour<strong> </strong>créer un programme<strong> </strong>! Un programme et / ou un plan de transformation qui fera du<strong> </strong>sens pour les collaborateurs." }, { "type": "heading", "level": 2, "id": "lapproche-lean-agile", "text": "L'approche Lean agile" }, { "type": "heading", "level": 3, "id": "lean-story-origines-et-utilite-du-concept", "text": "Lean story : origines et utilité du concept" }, { "type": "paragraph", "text": "Lean thinking, startup, Lean entreprise, manufacturing, Lean budgeting, Lean management, gouvernance, Lean office, Lean <a href=\"https://www.airsaas.io/fr/gestion-de-projet/etre-pmo-en-2023-les-mutations-dun-metier\" target=\"_blank\">PMO</a>, Lean Portfolio Management..." }, { "type": "paragraph", "text": "Au secours : le Lean a été mis à toutes les sauces ! Alors, avant de nous focaliser sur la gestion de portefeuille Lean, un retour aux sources s'impose." }, { "type": "paragraph", "text": "La traduction littérale de Lean est \"maigre\". Parmi les acceptions courantes, on retiendra celle de «&nbsp;au plus juste<strong>&nbsp;</strong>»." }, { "type": "paragraph", "text": "L'objectif est de <strong>tendre vers la performance</strong> (en matière de productivité, de qualité, de délais et de coûts) grâce à l<strong>'amélioration continue </strong>et à l'élimination des gaspillages, tout ceci dans le but de créer de la valeur pour satisfaire le client. <strong>L'idée centrale du Lean, c'est donc la création de valeur.</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/637289dd9695438c9d5bd631_airsaas-lean-min.jpg", "alt": "Pilotage par la valeur - et chasse au gaspillage" }, { "type": "paragraph", "text": "C'est autour des années 1990 que l'expression \"Lean production\" est apparue et que ses principes ont été formalisés dans l'ouvrage <a href=\"#\"><em>The machine that changed the world</em></a> écrit par James Womack, Daniel T. Jones et Daniel Roos. Puis dans <em>Lean thinking</em> publié en 1996 par les mêmes auteurs." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/637279539b9143e3e165f56f_The-Machine-That-Changed-the-World.jpeg", "alt": "The Machine That Changed the World", "caption": "Le livre The Machine That Changed the World" }, { "type": "heading", "level": 3, "id": "lagilite-a-lechelle", "text": "L'agilité à l'échelle" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/637287a74f6cff2866a3d764_Capture%20d%E2%80%99e%CC%81cran%202022-11-11%20a%CC%80%2010.33.27.png", "alt": "agilité humour", "caption": "Source : geek & poke" }, { "type": "paragraph", "text": "Les <strong>modèles de déploiement de l'agilité à grande échelle </strong>(«&nbsp;<em>scale up</em>&nbsp;» en anglais) sont autant adulés que décriés ! Usine à gaz de la transformation pour certains, cadre d'organisation génial pour les autres... ce qui est sûr, c'est qu'on ne peut pas généraliser. Les frameworks sont nombreux. SAFe, Nexus, Spotify, Scum at Scale, LeSS ou encore DAD... et en prime, ils évoluent rapidement." }, { "type": "paragraph", "text": "Ces différents cadres proposent<strong> </strong>des démarches plus ou moins ambitieuses et surtout à géométrie variable. Avec le Lean Portfolio Management, SaFE, on entre dans<strong> l'organisation quasi industrielle des flux de travail</strong>. Dans des interdépendances à l'échelle d'une entreprise." }, { "type": "paragraph", "text": "Les enjeux sont en tous les cas&nbsp;de réussir à obtenir la valeur ciblée par l'agilité tout en l'adaptant à plusieurs équipes digitales - parfois des dizaines !" }, { "type": "paragraph", "text": "La mise en place de ces frameworks de Lean Portfolio Management à l'échelle<strong> </strong>impliquera<strong> </strong>une compréhension des mécanismes de définition stratégique, des cycles budgétaires, du contrôle de gestion, et l'implication du top management ! Complexe à implémenter dans les organisations, cela peut se révéler extrêmement puissant<strong> </strong>dans les effets qu'ils peuvent produire." }, { "type": "paragraph", "text": "Attention donc à bien prendre en compte la taille, le secteur et la structure d'activité de votre organisation avant de vous lancer. De nombreux retours d'expériences confirment la pertinence de ce système dans des organisations orientées full produit comme dans le secteur de la banque-assurance, qui ne font que du développement logiciel." }, { "type": "paragraph", "text": "Si on ne tient pas compte de l'ensemble des paramètres et des critères clés, dans des organisations qui ne sont pas \"full produit\" on risque d'arriver avec une grosse massue pour planter une punaise !<strong> </strong>" }, { "type": "paragraph", "text": "Un DSI, Pro de la Transfo., interrogé au sujet de SAFe nous le confirme :" }, { "type": "quote", "text": "Avec SAFe, il y a des concepts bien. Il faut prendre les trucs intéressants et sortir du dogme. Tu peux organiser en SAFE un département... mais toute l'entreprise sur du vertical, aïe, aïe, aïe !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63728752e4fbfbdf900b8bc7_safe-Portfolio_airsaas.jpg", "alt": "Framework safe", "caption": "Source : SAFe for Lean Enterprises" }, { "type": "paragraph", "text": "Ne nous laissons pas impressionner par ce schéma et restons sur <strong>la philosophie générale de SAFe </strong>qui repose sur neuf principes :" }, { "type": "list", "ordered": true, "items": ["Adopter une <strong>vision économique</strong>", "Appliquer la<strong> pensée systémique</strong>", "<strong>Prendre en compte la variabilité</strong>, préserver les options", "Construire progressivement avec des <strong>cycles d'apprentissage rapides</strong> et intégrés", "Poser des jalons sur l'<strong>évaluation objective des systèmes de travail</strong>", "<strong>Visualiser et limiter les <em>Work in Progress</em></strong>, réduire les tailles de lots et gérer les longueurs de file d'attente", "<strong>Appliquer une cadence et se synchroniser</strong> avec la planification<strong> </strong>inter-domaine", "<strong>Libérer la motivation intrinsèque </strong>des collaborateurs", "<strong>Décentraliser la prise de décision</strong>"] }, { "type": "paragraph", "text": "En résumé, même si vous ne travaillez pas avec une armée de coachs Lean-agiles au sein d'une grande banque du CAC40, ces principes sont autant de bonnes pratiques et opportunités de changements." }, { "type": "paragraph", "text": "Inspirez-vous de cette culture pour créer et faire vivre votre démarche de Lean portfolio \"ad'hoc\" - c'est-à-dire, vraiment adaptée à votre organisation." }, { "type": "heading", "level": 3, "id": "lean-portfolio-management-le-decoupage-des-projets-en-mode-light", "text": "Lean Portfolio Management : le découpage des projets en mode light !" }, { "type": "quote", "text": "Ceux qui maîtrisent la livraison de logiciels à grande échelle définiront le paysage économique du 21ème &nbsp;siècle.", "author": "Mik Kersten, du projet au produit." }, { "type": "paragraph", "text": "La gestion de projet<strong> </strong>vise à répondre à des exigences spécifiques et à terminer un projet donné dans les délais et le budget convenus." }, { "type": "paragraph", "text": "L'un de ses points forts est d'apporter une concentration d'attention et de moyens avec une \"juste\" tension<strong>. </strong>Une mobilisation qui permet en théorie de faire mieux coopérer temporairement des départements transverses de l'entreprise, hors silos." }, { "type": "paragraph", "text": "L'un de ses points faibles est que, lorsqu'ils sont mal découpés les portefeuilles ne sont plus agiles ! Ils deviennent \"obèses\" !" }, { "type": "paragraph", "text": "Les revues de portefeuille n'ont alors plus d'enjeu, ni de bande passante pour le <strong>ré</strong>-ordonnancement des priorités... Avec pour conséquence une potentielle forte démobilisation dans les équipes." }, { "type": "paragraph", "text": "<strong>L'apport clé du Lean Portfolio Management sera</strong> <strong>de changer l'horizon de temps</strong>. De fonctionner par exemple au \"quarter\" - même pour un projet ERP/CRM ! Nous y reviendrons &nbsp;plus bas dans l'article." }, { "type": "paragraph", "text": "Enfin, nous attirons votre attention sur un point complexe du processus : l'idée n'est pas de basculer en mode full produit, mais bien de faire cohabiter le côté produit et projet.<strong> </strong>" }, { "type": "paragraph", "text": "Car oui : même si le fonctionnement en «&nbsp;mode produit&nbsp;» est l'un des apports intéressants des approches de Lean Portfolio Management, celui-ci n'est pas du tout adapté à une grande majorité d'organisations type ETI&nbsp;et PME." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6373c2909e475d58110aba46_airsaas-prouct-project-min.png", "alt": "Approche combinant projet et produit pour réussir votre transfo.", "caption": "Faire cohabiter le côté produit et projet : les deux démarches ne sont pas opposées, bien au contraire - elles interagissent !" }, { "type": "paragraph", "text": "C'est un peu le paradoxe des modèles de delivery modernes. Nous sommes de plus en plus amenés à<strong> </strong>créer une culture de livraison \"hybride\". <strong>Le bon mix entre culture projet approche produit</strong>." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6372769b4a2f743527fd7bc8_e2bea265-c809-44be-8603-295dfcfa2414.png", "alt": "La nécessité de changer la façon de développer les systèmes numériques", "caption": "La nécessité de changer la façon de développer les systèmes numériques" }, { "type": "paragraph", "text": "Un des leviers à activer pour suivre le rythme des évolutions est d'appliquer une approche Lean-agile dans la gestion de portefeuille vers plus de «&nbsp;Business Agility&nbsp;» pour votre transformation digitale." }, { "type": "paragraph", "text": "L'approche Lean-agile s'appuie sur le principe Lean de <strong>décentralisation de la décision</strong> et de transfert des responsabilités aux personnes les plus au contact du terrain." }, { "type": "paragraph", "text": "De façon académique,voire parfois indigeste, la définition du Lean Portfolio Management est la suivante :" }, { "type": "quote", "text": "La gestion de portefeuille Lean (LPM) est une démarche qui vise à aligner la stratégie et l'exécution. En appliquant des approches de pensée systémiques au financement de la stratégie et des investissements, aux opérations de portefeuille Agile et à la gouvernance en donnant la priorité aux initiatives de développement de produits et d'applications." }, { "type": "paragraph", "text": "De façon schématique,voire plus explicite, le processus de LPM est le suivant<strong> :</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/637284cd0097463fdb9b50eb_lpm.jpg", "alt": "Lean portfolio management" }, { "type": "paragraph", "text": "Le processus de Lean Portfolio Management se décompose en <strong>deux étapes :</strong> <strong>l'instruction des demandes</strong> en amont et le<strong> pilotage opérationnel </strong>des initiatives retenues en aval." }, { "type": "paragraph", "text": "S'il est exécuté correctement, le LPM augmente votre agilité. Cela se produit lorsque la planification, les processus de financement et la stratégie commerciale de l'entreprise s'alignent sur les résultats commerciaux souhaités par l'entreprise. Derrière ces termes, il y a bien des hommes et des femmes de l'IT, de la direction générale et des métiers qui cherchent à s'aligner !" }, { "type": "heading", "level": 2, "id": "lean-portfolio-management-comment-limplementer", "text": "Lean Portfolio management : comment l'implémenter ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6372841f129dd4bd8eec3bb1_airsaas-lean-start-min.jpg", "alt": "Think lean", "caption": "Gestion de portefeuille Lean - mise à jour en cours" }, { "type": "heading", "level": 3, "id": "decouper-en-quarter-pour-saligner-sur-la-roadmap-de-lentreprise", "text": "Découper en \"quarter\" pour s'aligner sur la roadmap de l'entreprise" }, { "type": "paragraph", "text": "Le passage au mode produit change l'horizon de temps<strong>.&nbsp;</strong>Nous l'avons vu plus haut : l'un des problèmes de la gestion de projet actuelle réside dans la temporalité trop éloignée des rythmes entreprise et clients<strong>. </strong>Reformater son portefeuille pour une <strong>meilleure adéquation avec le timing de l'organisation</strong> est un conseil simple, efficace et rentable pour votre feuille de route !" }, { "type": "paragraph", "text": "L'exemple ci-dessous présente un modèle de découpage annuel Lean agile." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63752154f2da816c5281eb98_Examen%20du%20portefeuille%20strate%CC%81gique%20Synchronisation%20du%20portefeuille%20Budge%CC%81tisation%20participative.jpg", "alt": "Lean portfolio management", "caption": "Lean portfolio management : s'adapter en permanence !" }, { "type": "paragraph", "text": "Une méthodologie avec des livraisons rapides de ce qui a été priorisé contribuera à un rythme de travail plus naturel que l'effet tunnel." }, { "type": "paragraph", "text": "Toujours pour renforcer ces nouveaux rituels de gouvernance projet, nous partageons avec plaisir ici, le tips d'un CIO expérimenté :" }, { "type": "quote", "text": "\"Lors de chaque \"review\" de bilan, j'invite les chefs de projets / PMO au restaurant pour leur dire merci !\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/637540f146bfef93df3bd388_merci.jpg", "alt": "Invitation à un moment festif à chaque grand jalon !", "caption": "Une invitation à un moment festif à chaque grand jalon !" }, { "type": "paragraph", "text": "Rappelez-vous, c'est<strong> l'esprit d'équipe qu'il faut développer</strong> !" }, { "type": "paragraph", "text": "N'oublions pas de célébrer les étapes clés de ces rituels comme il se doit." }, { "type": "quote", "text": "Le fait d'expliquer aux métiers qu'on a pris le temps de choisir leur projet prioritaire, qu'on a réussi à l'inclure dans le capacitaire, si tout cela est bien rodé, ça facilite immédiatement la relation entre DSI et métiers, même dans les moments plus compliqués.", "author": "Sylvain Bourdette — CIO Indexia Groupe, Invité épisode 59 Podcast CIO Révolution by AirSaas Saison 3" }, { "type": "heading", "level": 3, "id": "miser-sur-le-management-visuel-et-lux-de-vos-outils", "text": "Miser sur le management visuel et l'UX de vos outils" }, { "type": "paragraph", "text": "Les approches Lean et agile ont en commun de <strong>rendre visible le travail à faire</strong>, les opérations, le portefeuille projet. Que ce soit au sein d'une obeya room, d'un <a href=\"http://www.airsaas.io/fr/gestion-de-projet/kanban-gestion-de-projet\" target=\"_blank\">Kanban</a>, d'un mind mapping, l'idée est bien de donner à voir de la façon la plus claire et engageante possible." }, { "type": "paragraph", "text": "Si l'on souhaite impliquer les collaborateurs d'une entreprise sur des sujets aussi techniques que ceux traités par la DSI, mieux vaut le faire sur une interface qui leur plaira." }, { "type": "paragraph", "text": "Les outils PPM qui misent sur l'UX<strong> </strong>ont donc généralement une interface suffisamment intuitive pour faciliter l'alignement en continu de la direction générale, de l'IT et de chaque direction métier." }, { "type": "heading", "level": 3, "id": "utiliser-un-outil-de-lean-portfolio-managment", "text": "Utiliser un outil de Lean Portfolio Managment" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6372769b978c6da6e3c04dde_62615a9763962fbaf216b064_mobile_workflow-min-min.png", "alt": "La solution pour aligner en continu la direction générale, l'IT et les directions business - Airsaas", "caption": "Airsaas : la solution pour aligner en continu la direction générale, l'IT et les directions business" }, { "type": "paragraph", "text": "La<strong> </strong>solution de gestion de portefeuille d'AirSaas<strong> </strong>aide les entreprises à adopter un état d'esprit Lean et agile<strong>. </strong>Celle-ci maximise la coopération en continu<strong> </strong>entre clients fournisseurs, directions métiers, IT et générales en connectant leurs équipes, produits et portefeuilles à leurs buts et objectifs à travers divers cadres. Tout cela pour aider les entreprises à atteindre l'agilité dans toute l'entreprise." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6372769c66dff924993bab7b_609552290d93fd22170f0e67_pilotage-min.svg", "alt": "Lean Portfolio Dashboard", "caption": "Lean Portfolio Dashboard" }, { "type": "paragraph", "text": "Donnez à votre organe de gouvernance projet <strong>un dispositif de prise de décision. </strong>Le portefeuille de projets AirSaas permet de rassembler dans une vue synthétique la combinaison des indicateurs nécessaires à une prise de décision orientée par la valeur." }, { "type": "heading", "level": 2, "id": "a-retenir-lalignement-en-continu-est-la-cle", "text": "À retenir : l'alignement en continu est la clé !" }, { "type": "list", "ordered": false, "items": ["Le passage au mode Lean Portfolio change l'horizon de temps.", "Le Lean Portfolio Management est une démarche systémique tournée vers l'adaptation continue.", "L'alignement et la confiance &nbsp;ne se décrètent pas !...Cela se construit pas à pas dans la sincérité et le respect mutuel."] }, { "type": "paragraph", "text": "Prenez en considération le Lean Portfolio Management dès maintenant pour une transformation d'entreprise réussie !" }], "toc": [{ "label": "Les 3 problèmes liés à la gestion actuelle de portefeuille projets", "href": "#les-3-problemes-lies-a-la-gestion-actuelle-de-portefeuille-projets", "level": 2 }, { "label": "L'approche Lean agile", "href": "#lapproche-lean-agile", "level": 2 }, { "label": "Lean Portfolio management : comment l'implémenter ?", "href": "#lean-portfolio-management-comment-limplementer", "level": 2 }, { "label": "À retenir : l'alignement en continu est la clé !", "href": "#a-retenir-lalignement-en-continu-est-la-cle", "level": 2 }], "faq": [], "related": [] }, { "slug": "les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet", "skip": false, "meta": { "title": "Les 10 erreurs à (ne pas) commettre dans la mise en place d'un portefeuille projet ?", "h1": "Les 10 erreurs à (ne pas) commettre dans la mise en place d'un portefeuille projet ?", "description": "Les 10 erreurs à (ne pas) commettre dans la mise en place d'un portefeuille projet ?", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647a0f99f251445a8e175f20_TOP10%20error-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "3/6/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "3/6/2023" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647a113d3334542e6a69a174_ppm-10error-min.jpg", "alt": "Sélection de 10 erreurs du PPM", "caption": "Chef de projet / DG /DSI /PMO réalisant qu'il a coché les 10 erreurs du TOP 10 d'AirSaas" }, { "type": "paragraph", "html": "Parfois on maîtrise \"the\" dernier framework agile ultra sophistiqué à la mode, mais, <strong>les fondamentaux les plus basiques</strong> de la gestion de portefeuille projet, du management, de la stratégie, ou des relations humaines <strong>sont négligés.</strong> Des erreurs de débutants pourraient être évitées avec une <strong>checklist</strong> à parcourir avant votre décollage !" }, { "type": "paragraph", "html": "Absence de processus de sélection des projets et de priorisation, méprise sur le concept, non-sanction des hors-jeu, ratés de communications, négligence dans le suivi et le contrôle...." }, { "type": "paragraph", "html": "D'après vous, <strong>quelle sera l'erreur la plus préjudiciable</strong> lorsqu'on se lance dans la mise en place d'une démarche de gestion de portefeuille projets ?" }, { "type": "paragraph", "html": "Vous allez être surpris !" }, { "type": "paragraph", "html": "On vous propose de le découvrir avec ce \"top 10\" qui<strong> avance des pistes de réflexions et retours d'expériences de DSI/PMO/DG et experts pragmatiques du domaine. Objectif ne pas tomber dans (tous) les pièges de la transfo d'organisation.</strong>" }, { "type": "paragraph", "html": "Pratique : Les erreurs sont classées des plus mineures et acceptables 10, 9, 8 aux plus bloquantes et néfastes (1, 2, 3) pour la transfo. de votre organisation..." }, { "type": "paragraph", "html": "Si vous vous reconnaissez certains signaux faibles, symptômes ou syndromes dans plus de 5 erreurs, consultez-nous ...on a des services d'accompagnement qui vous éviteront le \"faux départ\" ^^ et même un <a href=\"/gestion-de-projet/portfolio-project-management-le-top-10-des-bonnes-pratiques\" target=\"_blank\">guide des 10 bonnes pratiques</a> !" }, { "type": "heading", "level": 2, "id": "10-communiquer-sur-tous-les-projets-a-tous-de-la-meme-facon", "text": "10 - Communiquer sur tous les projets à tous, de la même façon !" }, { "type": "paragraph", "html": "<em>🎙\"Un point indispensable dans la transfo, ce sont les aspects de communication. On ne communique jamais assez. En tout cas de façon assez ciblée et efficace. La transformation c'est quelque chose qui peut faire peur aux personnes. Si on ne communique pas, les projets peuvent être perçus comme un risque.\" Alexia Schmitt </em>Directrice de la Transformation et des Systèmes d'Information Centrimex invitée de l'épisode 22 du Podcast CIO Révolution by AirSaas." }, { "type": "paragraph", "html": "Les parties prenantes doivent être correctement informées et tenues au courant de l'avancement des projets. Des réunions régulières, des rapports de suivi et des outils de communication appropriés peuvent clairement contribuer à améliorer la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">communication</a>." }, { "type": "paragraph", "html": "Problème : Teams, Email, Coproj, Copils, Codir...<strong>trop d'instances, trop d'audiences</strong>, trop de canaux et outils, vous avez oublié ou négligé une des cibles clés dans les parties prenantes. <strong>Personne n'aime découvrir qu'un projet se tient sans lui !</strong>" }, { "type": "paragraph", "html": "Oui <strong>ça prend du temps de bien communiquer,</strong> et de le faire en continu...c'est pour ça qu'on suggère de soulager les chefs de projet, d'automatiser une partie non stratégique de ce processus avec une plateforme. Oubliez le facteur humain ! Faites-vous aider par les plateformes, on est au XXIe siècle !" }, { "type": "paragraph", "html": "On vous remet en tête juste ci-dessous la \"<strong>stake holder</strong> <strong>map</strong>\", <strong>matrice des parties prenantes</strong>, qui permet une première approche de ce processus. Une <strong>base de réflexion</strong> pour formaliser votre <strong>stratégie</strong> et n'oublier aucunes parties prenantes, car <strong>il y en a toujours plus qu'on ne le pense !</strong>" }, { "type": "paragraph", "html": "Bonus : À partir de cette cartographie, établissez le \"pourquoi\"&nbsp;<strong>clair</strong>&nbsp;de chacun des acteurs pourra contribuer à éviter \"la cata\" de la com interne. ^^" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea63e4dc7075f6681ede9d_15acb6f3-77e2-429c-b54a-459a7ef33c96-min.png", "alt": "stake holder map\", matrice des parties prenantes", "caption": "Matrice impact parties prenantes pour chefs de projet" }, { "type": "heading", "level": 2, "id": "9-vous-navez-pas-une-vraie-visibilite-sur-la-sante-de-votre-portefeuille", "text": "9 - Vous n'avez pas une (vraie) visibilité sur la santé de votre portefeuille" }, { "type": "paragraph", "html": "<strong>Personne n'aime apporter une mauvaise nouvelle sur la santé d'un programme de projets</strong>, d'un chantier particulier..." }, { "type": "paragraph", "html": "Outre le reporting, l'enjeu est dans la collecte de ces infos. On cherchera donc à faciliter la libération de la parole des personnes impliquées pour qu'elles communiquent <strong>en transparence et en continu</strong>, pour qu'elles aient envie de <strong>rendre lisible l'état de santé des projets</strong> avec les <strong>informations</strong> clés à connaître derrière les différents changements de statuts..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647adcf75b10f70a2b372df0_sante-projet-min.png", "alt": "Santé projet", "caption": "Portfolio projets AirSaas et vue météo - Et si vous pouviez lire la dernière mise à jour de l'état de santé depuis votre portfolio projet ?" }, { "type": "heading", "level": 2, "id": "8-choisir-excel-pour-porter-votre-transfo", "text": "8 - Choisir Excel pour porter votre transfo." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647adac83530d3a8d4fdb68b_excel-is-not-a-database-bart-simpson-writing-on-a-blackboard.jpg", "alt": "Excel n'est pas un PPM ^^" }, { "type": "paragraph", "html": "<strong>Parler de stratégie devant un tableur</strong> ? Vraiment ?" }, { "type": "paragraph", "html": "Si, vous avez bien lu ! Certains <a href=\"https://www.airsaas.io/fr/gestion-de-projet/metier-pmo\" target=\"_blank\">PMO</a>/DG/DSI continuent à digitaliser leurs fiches projets et portefeuilles de projets stratégiques avec un tableur. Où l'<strong>art de perdre son audience sa productivité</strong> et ses priorités au sein de plusieurs projets de transfos." }, { "type": "paragraph", "html": "On va se le redire cher lecteurs :" }, { "type": "list", "ordered": false, "items": ["Excel est <strong>vulnérable aux fraudes et aux erreurs humaines</strong>", "Excel <strong>ne favorise pas</strong> le travail<strong> collaboratif</strong>", "Excel est <strong>limitant dans la prise de décisions</strong>", "Excel est <strong>inadapté à la continuité du business</strong>", "Excel est assez <strong>peu compréhensif</strong> pour la personne qui n'a pas créé le fichier..."] }, { "type": "paragraph", "html": "Le portefeuille de projets sert (aussi) à valoriser votre activité et à convaincre votre Codir/comex, vos investisseurs ! Car oui, la notion de marketing de la DSI ça compte." }, { "type": "heading", "level": 2, "id": "7-ne-pas-se-baser-sur-votre-capacitaire-et-partir-dun-besoin-irrealiste", "text": "7 - Ne pas se baser sur votre capacitaire et partir d'un besoin irréaliste" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647add835e30d5b8923a3b30_30projets-min.png", "alt": "Capacitaire projets", "caption": "Attention, Chef de projet et PMO en plein entretien de débrief sur le capacitaire" }, { "type": "paragraph", "html": "L'importance de développer une <strong>culture du make it simple et du MVP !</strong>" }, { "type": "paragraph", "html": "Appelons la culture agile, lean startup, product company, méthodes efficaces..peu importe au fond!" }, { "type": "paragraph", "html": "L'enjeu est de ne pas \"sur spécifier\", sur promettre, sur développer...pour <strong>ne pas surconsommer vos ressources humaines</strong> en premier lieu." }, { "type": "paragraph", "html": "Mais au contraire d'apprendre à se satisfaire de choses imparfaites, de rester focalisé sur la valeur et les clients de <strong>ne pas créer de \"sur complexité\" artificielle, ce fameux gras des orgas !</strong>" }, { "type": "paragraph", "html": "Bref à l'inverse de la prolifération de projets... prônons une forme de sobriété dans la transfo !" }, { "type": "paragraph", "html": "Le fait de dépolluer vos chefs de projets avec moins de chantiers toxiques et plus de coopérations vous facilitera la vie et contribuera à la <strong>continuité de l'équipe, facteur clé en agilité.</strong>" }, { "type": "paragraph", "html": "Retour d'expérience d'un DSI dans le cadre du podcast CIO Révolution by AirSaas : \"<em>Ayez un dialogue avec votre DG sur le capacitaire, levez ce tabou.</em>\"" }, { "type": "heading", "level": 2, "id": "6-choisir-un-outil-ppm-trop-gros-deconnecte-de-la-gp-avec-jira-monday-asana", "text": "6 - Choisir un outil PPM trop gros\", déconnecté de la GP avec jira, monday, asana ..." }, { "type": "paragraph", "html": "Bravo, vos équipes delivery sont super efficaces sur Jira ? 👏" }, { "type": "paragraph", "html": "Mais vous avez du mal à suivre l'avancée des projets ? Et il arrive que le périmètre ne soit pas bien compris ? Que certains projets dérapent ?" }, { "type": "paragraph", "html": "Pour dépasser ce problème d'alignement \"Gouvernance projet / Delivery projet\"...nous vous conseillons de connecter vos outils." }, { "type": "paragraph", "html": "Par exemple, AirSaas est intégré avec Jira. Cadrez le projet sur AirSaas, et une fois validé, connectez-le à votre projet sur cette plateforme." }, { "type": "paragraph", "html": "Les jalons seront synchronisés et l'avancement sera remonté directement sur AirSaas. <br>Chaque audience bénéficiera d'une vue adaptée. Le codir et les opérationnels partageront une vision." }, { "type": "paragraph", "html": "Sans tous les citer voici quelques-uns de ces logiciels phares sur lesquels travaillent vos chefs de projets et auxquels vous pourrez vous connecter avec AirSaas : Gestion de projet et tâches : Wrike, Jira, ..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647addf37b33b4da68093725_hub-gpp.png", "alt": "AirSaas connecté avec Wrike, Asana, Jira, Monday, Teams", "caption": "Une autre stratégie de gestion de projet et pilotage de transfo pour vos chefs de projet / PMO / Codir est possible" }, { "type": "heading", "level": 2, "id": "5-ne-pas-decouper-les-projets-obeses-en-projets-digestes", "text": "5 - Ne pas découper les projets \"obèses\" en projets digestes" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647adf11d384367f998b87fd_jalons-min-min.jpg", "alt": "pilotage par les jalons", "caption": "Jalons - l'art de la gestion de projet moderne pour votre portefeuille projets" }, { "type": "paragraph", "html": "Les très grands projets sont complexes, difficiles à gérer. Les gestionnaires de portefeuille doivent <strong>diviser une grande initiative en un ensemble de petits sous-projets</strong>. Mettre en place des équipes par petit projet, leur donner plus de clarté, d'autonomie, de confort fonctionne mieux que de gérer un grand projet complexe avec des membres d'équipe débordés." }, { "type": "paragraph", "html": "<strong>Inversement, v</strong>ous ne voulez pas exécuter trop de projets et beaucoup d'entre eux restent incomplets dans le portefeuille. Cela entraîne non seulement le portefeuille en termes de coûts, de ressources et de délais, mais également des compromis sur la valeur fournie à l'entreprise. La dernière chose que vous voulez avoir des projets dans vos portefeuilles qui deviennent hors de propos." }, { "type": "paragraph", "html": "Pour sortir de cette façon de faire, adoptez un découpage fin et une <strong>priorisation au trimestre.</strong> En vous calant sur les trimestres vous inscrivez les projets dans une temporalité d'entreprise, ce qui donnera du rythme et facilitera l'engagement." }, { "type": "heading", "level": 2, "id": "4-permettre-aux-projets-peu-prioritaires-ou-de-faible-valeur-dentrer-et-ou-de-rester-dans-votre-portefeuille", "text": "4 - Permettre aux projets peu prioritaires ou de faible valeur d'entrer et ou de rester dans votre portefeuille" }, { "type": "paragraph", "html": "Un portefeuille projet sert à y voir plus clair et à opérer des choix tactiques !" }, { "type": "paragraph", "html": "Généralement, dans les grandes organisations, les projets sont sélectionnés et financés par des sponsors de projet et à leur tour gérés dans le cadre d'un <a href=\"http://www.airsaas.io/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme\" target=\"_blank\">portefeuille de projets</a>. Une fois qu'ils sont pris en charge pour la planification et l'exécution, il existe plusieurs projets en cours dans un portefeuille. C'est une <strong>erreur typique que nous rencontrons chez AirSaas sur la hiérarchisation des projets au sein d'un portefeuille</strong> : il n'y a pas de priorités spécifiques assignées aux projets ! Les équipes continuent de travailler sur des projets moyens alors que des <strong>projets cruciaux sont repoussés et commencent à dérailler</strong>." }, { "type": "paragraph", "html": "<strong>Savoir arrêter un projet au bon moment !</strong> Tout un art pour les DSI, chefs de projets et PMO." }, { "type": "paragraph", "html": "Autre erreur fréquente dans ce même registre, lorsque la<strong> direction ajoute de nouveaux projets au portefeuille sans examen initial.</strong> Le fameux \"fait du prince\", autrement appelée l'effet \"décision du patron\"." }, { "type": "paragraph", "html": "Oui, <strong>ce mode \"autoritaire\" a encore de beaux jours devant lui</strong>...parfois les processus les plus raffinés sont contournés !" }, { "type": "paragraph", "html": "Dans ces cas-là...le <strong>courage managérial est de mise</strong> et si aucune raison centrée sur la valeur n'est réellement avancée...changez d'entreprise !" }, { "type": "heading", "level": 2, "id": "3-envoyer-des-reporting-projets-de-forme-et-frequences-aleatoires", "text": "3 - Envoyer des reporting projets de forme et fréquences aléatoires" }, { "type": "paragraph", "html": "Une des erreurs les plus courantes de la fonction de PMO/Chef de projet. Le côté <strong>hétérogène du point de reporting, de ses contenus, à sa forme, en passant par sa fréquence.</strong><br><br>Perdre 4 jours par mois à faire un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\">reporting</a> pour le Copil dont la forme change à chaque fois ET à une fréquence + ou - aléatoire.<br><br>Du coup, les décideurs :<br><br>- Ont du <strong>mal à suivre l'état d'avancement,</strong> la fameuse question mais on en est ou ?<br>- <strong>Passent plus de temps à essayer de comprendre</strong> les slides du ppt que <strong>le fond des sujets</strong> ...<br>- Ne les lisent pas ..<br><br><strong>Facilitez la prise de décision</strong> ! Un tout petit changement plein de bon sens, qui à de grands impacts. Avec AirSaas vous n'avez <strong>plus d'excuse pour ne pas envoyer un bon et beau rapport flash</strong>." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62bdfca88290d29985904cb5_report-flash.png", "alt": "Rapport Flash", "caption": "Rapport Flash AirSaas-tout pour facilitez la prise de décisions" }, { "type": "heading", "level": 2, "id": "2-negliger-le-pilotage-par-les-jalons-et-decisions", "text": "2 - Négliger le pilotage par les jalons et décisions" }, { "type": "paragraph", "html": "Un peu comme dans une réunion de copropriété, <strong>votre comité de pilotage mérite un protocole décisionnel clair !</strong>" }, { "type": "paragraph", "html": "Pourtant, il est clairement <strong>difficile d'avoir une vision d'ensemble des décisions à prendre et du contexte</strong> synthétique de celles-ci.<br>Et à postériori sans contenu, il est difficile d'avoir l'historique des décisions importantes (prises ou non) sur tel ou tel projet. Difficile pour comprendre comment on en est arrivé là...&nbsp;" }, { "type": "paragraph", "html": "L'usage d'une <strong>plateforme vous simplifiera la gouvernance</strong> (listing des décisions à prendre, vue CoPil, etc.). Vous ne serez plus pris de court parce que vous n'avez pas la bonne information." }, { "type": "paragraph", "html": "Oui, cela paraît évident...mais <strong>parfois, les fondamentaux sont oubliés.</strong> Se focaliser sur les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/jalon-projet\" target=\"_blank\">jalons</a>, les décisions et points d'attentions versus un micromanagement à la tâche mettra le <strong>juste niveau de hauteur dans votre pilotage</strong>.<br><br>Les décisions tout le monde en parle... Mais elles sont ou ? --&gt; Et si vous aviez accès à toutes les décisions à prendre et historique clé pendant le copil ? \"Un kanban des décisions ça change la vie d'une entreprise\"" }, { "type": "heading", "level": 2, "id": "1-ne-pas-mettre-a-jour-los-de-votre-entreprise-sa-gouvernance-et-ses-rituels", "text": "1 - Ne pas mettre à jour l'OS de votre entreprise : sa gouvernance et ses rituels !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/647ae0ec24979a4ed79e0906_update-min.jpg", "alt": "Gouvernance et pilotage transfo", "caption": "Update de l'OS de votre entreprise en cours" }, { "type": "paragraph", "html": "Oui, c'est là où il y <strong>le plus de gains potentiels</strong> !" }, { "type": "paragraph", "html": "Autour de l'outil, <strong>investissez dans la réflexion sur les thématiques clés de la gouvernance</strong> : rituels, rôles, coopération, pilotage par les jalons et décisions, transparence \"by design\",&nbsp;dépassement des silos verticaux et horizontaux, nouveaux rôles du management. Bref sur tous les axes de mise en œuvre d'un nouveau modèle culturel." }, { "type": "paragraph", "html": "Et, pour accompagner dans la durée cette nouvelle structuration des rôles, la formation,&nbsp;l'accompagnement et le coaching sont des \"must have.\"" }, { "type": "paragraph", "html": "Car lorsqu'on pense avoir compris<strong> le concept de PPM</strong> et qu'on évite, pour aller plus vite, un accompagnement, même light, les<strong> risques de méprises</strong> ou de précipitations sont trop nombreux ! Pour n'en citer qu'une, la plus classique.... Penser que l'outil est magique et qu'il fera avancer les choses à lui tout seul !" }, { "type": "paragraph", "html": "Premièrement, l'outil PPM n'est qu'un outil (pléonasme !) il ne consiste <strong>pas en une démarche</strong> !" }, { "type": "paragraph", "html": "Pour bien faire comprendre ce point autour de vous, utilisez la métaphore du couteau (l'outil) et la démarche (La façon de s'en servir pour couper un aliment ou un doigt ! )." }, { "type": "paragraph", "html": "Un <strong>outil donc ne peut pas résoudre les problèmes inhérents à l'organisation</strong> tels que des processus de projet peu clairs, une manière floue de formaliser les exigences d'un projet, un management indécis voire absent, l'absence d'évaluation des risques et de planification de la réponse, etc. Vous le savez, la liste des dysfonctionnements peut être longue !" }, { "type": "paragraph", "html": "Au mieux, l'outil PPM peut être un <strong>excellent catalyseur pour les membres de l'équipe,</strong> pour la gestion de portefeuille de projets, il peut rassembler les parties prenantes du portefeuille de projets, leur permettre de collaborer, apporter plus de transparence avec une <strong>communication automatisée,</strong> fournir des informations sur le portefeuille de projets de manière plus significative, mettre en évidence des indicateurs d'alerte précoce, etc." }, { "type": "paragraph", "html": "On souhaite à vous et votre équipe un plein succès dans cette transformation culturelle." }, { "type": "heading", "level": 2, "id": "conclusion", "text": "Conclusion" }, { "type": "paragraph", "html": "On espère que la lecture de cet article et de sa sélection de 10 erreurs vous a intéressés." }, { "type": "paragraph", "html": "Mettre en place un portefeuille projet est une <strong>étape</strong> <strong>critique</strong> pour les entreprises souhaitant se transformer et moderniser leur gouvernance et gestion de projet. Cependant, les erreurs sont normales, on ne fait pas ça tous les jours ! Et rassurez-vous, une fois en place...on ne le refait pas tous les ans !" }, { "type": "paragraph", "html": "La mise en place d'un portefeuille projet dans une entreprise est certes un investissement et peut être complexe si certains paramètres sont négligés, et si trop d'erreurs sont commises par les membres de l'équipe. En évitant dès le début ces 10 erreurs, vous pourrez <strong>assurer une mise en place efficace</strong> et réussie de votre nouvelle gouvernance, vers une dynamique plus efficace !&nbsp; Pour vous aider à déterminer le bon moment pour vous lancer, on vous a préparé un article pour savoir quand implémenter une démarche de portefeuille projets ? Découvrez le retours d'expérience d'une PMO sur ce processus : <a href=\"/gestion-de-projet/le-portefeuille-projets-pour-faire-grandir-les-collaborateurs-et-lorganisation\">Le portefeuille projets pour faire grandir les collaborateurs et l'organisation.</a>" }], "toc": [{ "label": "10 - Communiquer sur tous les projets à tous, de la même façon !", "href": "#10-communiquer-sur-tous-les-projets-a-tous-de-la-meme-facon", "level": 2 }, { "label": "9 - Vous n'avez pas une (vraie) visibilité sur la santé de votre portefeuille", "href": "#9-vous-navez-pas-une-vraie-visibilite-sur-la-sante-de-votre-portefeuille", "level": 2 }, { "label": "8 - Choisir Excel pour porter votre transfo.", "href": "#8-choisir-excel-pour-porter-votre-transfo", "level": 2 }, { "label": "7 - Ne pas se baser sur votre capacitaire et partir d'un besoin irréaliste", "href": "#7-ne-pas-se-baser-sur-votre-capacitaire-et-partir-dun-besoin-irrealiste", "level": 2 }, { "label": "6 - Choisir un outil PPM trop gros\", déconnecté de la GP avec jira, monday, asana ...", "href": "#6-choisir-un-outil-ppm-trop-gros-deconnecte-de-la-gp-avec-jira-monday-asana", "level": 2 }, { "label": "5 - Ne pas découper les projets \"obèses\" en projets digestes", "href": "#5-ne-pas-decouper-les-projets-obeses-en-projets-digestes", "level": 2 }, { "label": "4 - Permettre aux projets peu prioritaires ou de faible valeur d'entrer et ou de rester dans votre portefeuille", "href": "#4-permettre-aux-projets-peu-prioritaires-ou-de-faible-valeur-dentrer-et-ou-de-rester-dans-votre-portefeuille", "level": 2 }, { "label": "3 - Envoyer des reporting projets de forme et fréquences aléatoires", "href": "#3-envoyer-des-reporting-projets-de-forme-et-frequences-aleatoires", "level": 2 }, { "label": "2 - Négliger le pilotage par les jalons et décisions", "href": "#2-negliger-le-pilotage-par-les-jalons-et-decisions", "level": 2 }, { "label": "1 - Ne pas mettre à jour l'OS de votre entreprise : sa gouvernance et ses rituels !", "href": "#1-ne-pas-mettre-a-jour-los-de-votre-entreprise-sa-gouvernance-et-ses-rituels", "level": 2 }, { "label": "Conclusion", "href": "#conclusion", "level": 2 }], "faq": [], "related": [] }, { "slug": "macro-planning", "skip": false, "meta": { "title": "Le macro planning : Pourquoi et comment s'en servir !", "h1": "Le macro planning : Pourquoi et comment s'en servir !", "description": "Le macro planning est un outil de communication idéal pour votre comité de pilotage. Découvrez pourquoi et comment l'utiliser dans votre gestion de projet.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37eaf0d180f5c6a129c92_6.jpg", "alt": "" }, "author": { "name": "Simon Vacher", "category": "Gestion de projets", "publishedDate": "8/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e038501c4256317123910b_SV-min.jpg" }, "publishedDate": "8/10/2021" }, "blocks": [{ "type": "paragraph", "html": "Le cadrage projet est une phase essentielle de la <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\">conduite de projet</a> pour définir efficacement le plan que l'on prévoit d'exécuter pour mener à bien son exécution. Le macro planning lui, est ou outil parfait pour communiquer ce qui a été pensé lors de la phase de cadrage : en un coup d'œil, l'ensemble des parties concernées peuvent avoir une idée des prochaines étapes à réaliser ainsi que des délais qui y sont assignés. C'est le support de communication idéal pour votre comité de pilotage qui sera intégré dans votre <a href=\"/fr/solution/rapport-flash\">rapport flash</a> !" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-macro-planning", "text": "Qu'est-ce qu'un macro planning ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d8620e6f1e642cdb163164_644bac69154c15992130e296_macroplanning-min.jpeg", "alt": "Qu'est-ce qu'un macro planning et comment créer le vôtre", "caption": "Chronologie des grandes étapes et jalons, Gantt, tâches - Un article sur l'art de la planification" }, { "type": "paragraph", "html": "Dans une <strong>phase d'initialisation du projet,</strong> la constitution de plannings est l'une des premières choses que l'on apprend en gestion de projet. C'est un élément indispensable à quiconque veut garantir la réalisation d'un projet d'une certaine qualité, sans exploser les coûts et en respectant les délais." }, { "type": "paragraph", "html": "Cette tâche incombe généralement au <a href=\"https://www.airsaas.io/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\">chef de projet</a> : le planning sera un outil de travail primordial pour lui et son équipe. Un planning doit donc être suffisamment détaillé pour contenir les informations principales au bon déroulement du projet." }, { "type": "paragraph", "html": "Mais si le chef de projet se sert de la planification pour communiquer avec son équipe, il aura aussi besoin d'en parler avec d'autres acteurs : son supérieur, le commanditaire du projet, des prestataires externes, ou encore les futurs utilisateurs du produit créé !" }, { "type": "paragraph", "html": "<strong>Et c'est ici qu'intervient le macro planning !</strong><br>Si le planning classique très détaillé est souvent trop complexe pour une personne ne travaillant pas sur le projet de manière permanente, le macro planning lui est idéal comme support de communication avec tous ces types d'acteurs !" }, { "type": "paragraph", "html": "Ces derniers auront besoin d'une vision synthétique des points principaux du projet, d'une \"vue hélicoptère\" qui balaye les grandes étapes et les jalons principaux." }, { "type": "paragraph", "html": "La définition d'un macro planning est donc : un planning simplifié qui doit être agréable et facile à lire : idéalement il tient en une seule page !" }, { "type": "paragraph", "html": "Pour toutes ces raisons, le macro planning est considéré comme l'un des supports de communication les plus utiles lors des comités de pilotage ou des comités de directions. Chacun des participants peut alors prendre conscience des aspects principaux du projet en un coup d'œil, ce qui facilite les débats." }, { "type": "paragraph", "html": "Ce macro planning sera créé lors du début du projet et permettra d'assurer la communication avec toutes les parties externes au projet tout au long de son exécution. Tout comme un planning classique, il devra lui aussi être mis à jour continuellement !" }, { "type": "heading", "level": 2, "id": "macro-planning-et-micro-planning-quelles-differences", "text": "Macro planning et micro planning : quelles différences ?" }, { "type": "paragraph", "html": "Pour symboliser le macro planning, nous avons utilisé l'image d'une \"vue hélicoptère\" qui permet de prendre de la hauteur et d'avoir une visibilité globale sur les grandes étapes du projet en quelques secondes." }, { "type": "paragraph", "html": "S'il fallait symboliser le micro planning de la même manière, alors ce dernier serait plutôt une \"vue au microscope\" de la planification du projet !" }, { "type": "paragraph", "html": "Contrairement au macro planning, le micro planning est centré autour d'un périmètre bien plus petit au sein du projet (souvent une tâche, ou même une des phases d'une tâche), mais rentre aussi davantage en profondeur." }, { "type": "paragraph", "html": "Comme le microplanning est extrêmement détaillé, il prend beaucoup de temps à être mis en place : il n'est pas rare qu'un micro planning soit à la minute près !" }, { "type": "paragraph", "html": "Si le micro planning est pratique lorsqu'il faut passer au peigne fin un process ou une tâche à faire, il souffre évidemment d'un défaut le rendant inutile dans de nombreuses situations : il est vulnérable à tout évènement imprévu et demande une actualisation permanente, dépendante de l'avancement du projet réel." }, { "type": "paragraph", "html": "La macro planning et le micro planning du projet dont donc deux outils très différents qui sont à votre disposition : servez-vous-en intelligemment en fonction de vos besoins !" }, { "type": "heading", "level": 2, "id": "pourquoi-utiliser-un-macroplanning-dans-sa-gestion-de-projet", "text": "Pourquoi utiliser un macroplanning dans sa gestion de projet ?" }, { "type": "paragraph", "html": "Comme le micro planning, le macro planning comporte son lot d'avantages et d'inconvénients. Voici une liste des principaux d'entre eux." }, { "type": "heading", "level": 3, "id": "les-avantages-dun-macro-planning", "text": "Les avantages d'un macro planning" }, { "type": "list", "ordered": false, "items": ["Puisqu'il est synthétique, le macro planning est très rapide à réaliser", "Toutes les grandes phases du projet sont résumées en un coup d'œil", "Un document compréhensible par tous, y compris des personnes externes au projet", "Le macro planning n'a pas à être sans cesse actualisé"] }, { "type": "heading", "level": 3, "id": "les-inconvenients-dun-macro-planning", "text": "Les inconvénients d'un macro planning" }, { "type": "list", "ordered": false, "items": ["Offre un degré de précision trop faible pour suffire à l'équipe interne du projet", "Le macro planning n'est pas assez détaillé pour permettre la répartition de la liste de différentes tâches et de la charge de travail."] }, { "type": "heading", "level": 2, "id": "comment-creer-un-macro-planning", "text": "Comment créer un macro planning ?" }, { "type": "paragraph", "html": "Comme précisé, le macro planning se fait dès la phase d'initialisation du projet. Il s'intégrera à votre <a target=\"_blank\" href=\"https://airsaas.io/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\">note de cadrage</a>" }, { "type": "paragraph", "html": "Cependant, à ce stade du projet, il n'existe pas encore de cahier des charges qui détaille de l'ensemble des tâches à réaliser." }, { "type": "heading", "level": 3, "id": "les-differentes-etapes-de-creation-dun-macro-planning", "text": "Les différentes étapes de création d'un macro planning" }, { "type": "paragraph", "html": "Ainsi, pour créer votre macro planning, il vous faudra passer par plusieurs étapes-clés :" }, { "type": "list", "ordered": true, "items": ["<strong>Estimer quelles sont les phases principales</strong> qui constitueront le projet <strong>et leurs échéances</strong>", "<strong>Rattacher les <a href=\"https://www.airsaas.io/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\">jalons-clés</a> principaux</strong> (soit les grandes échéances) à chacune de ces phases principales", "<strong>Etablir des dépendances</strong> entre les différentes phases si elles existents", "<strong>Définir le temps prévisionnel nécessaire</strong> pour accomplir chacune de ces phases"] }, { "type": "paragraph", "html": "L'idéal est d'arriver à réunir autour de la table chacun des responsables des macro-tâches qui devront être exécutée. De cette manière, vous aurez une estimation de la durée des tâches qui ne sera pas parfaite, mais qui aura le mérite d'être réaliste.<br><br>De plus, en réunissant les bonnes personnes pour la confection du macro planning, l'exercice devrait être vite bouclé : si toutes les personnes compétentes sont autour de la table, votre macro planning sera rédigé en moins d'une heure !" }, { "type": "heading", "level": 3, "id": "les-outils-cles-pour-creer-votre-macro-planning", "text": "Les outils-clés pour créer votre macro planning" }, { "type": "paragraph", "html": "Vous disposez déjà probablement d'un outil qui vous permet de créer et de gérer votre macro planning au quotidien." }, { "type": "paragraph", "html": "Par exemple, un macro planning peut prendre la forme de :" }, { "type": "list", "ordered": false, "items": ["Un tableur Excel tout ce qu'il y a de plus simple", "Une slide PowerPoint bien ficelée", "Un outil de calendrier projet collaboratif", "Votre logiciel de gestion de projet ou de gestion des tâches traditionnel, comme Trello ou Asana"] }, { "type": "paragraph", "html": "Le plus important est que cet outil vous permette de visualiser aisément les phases principales du projet, ses jalons-clés, ainsi que ses dépendances. Plus il sera lisible, plus il sera bien intégré par les équipes qui en ont besoin." }, { "type": "heading", "level": 2, "id": "peut-on-se-passer-dun-diagramme-de-gantt-pour-un-macro-planning", "text": "Peut on se passer d'un diagramme de Gantt pour un macro planning ?" }, { "type": "paragraph", "html": "Le <a href=\"https://www.manager-go.com/gestion-de-projet/dossiers-methodes/construction-gantt\" target=\"_blank\">diagramme de Gantt</a> est un peu le \"must-have\" de tous les chefs de projet débutants en gestion de projets cherchant à rassurer les parties prenantes. Sa lecture est pourtant un véritable tue-l'amour ! Un peu comme lorsqu'on invitait des collaborateurs sur des logiciels comme Excel ou MS Project ! L'avantage du macro planning est justement de parler à tout le monde. On a besoin d'y voir clair dans les jalons et délais pas dans les tâches." }, { "type": "paragraph", "html": "La gestion de projet efficace ne se limite pas en effet à l'utilisation de logiciels - c'est un acte de management. C'est un ensemble de processus qu'une organisation macro permettra de rendre plus visible." }, { "type": "paragraph", "html": "Le macro planning et le diagramme de Gantt sont deux outils de planification souvent utilisés par une équipe dans le domaine de la gestion de projet. Le macro planning est un plan global et stratégique qui permet d'identifier les grandes étapes et les objectifs à atteindre, tandis que le diagramme de Gantt est un outil plus détaillé et opérationnel qui permet de planifier les tâches à effectuer et leur durée." }, { "type": "paragraph", "html": "Le macro planning est donc un outil de gestion de projet plus adapté lors de la phase de planification globale d'un projet, tandis que les diagrammes de Gantt sont plus adaptés pour la planification opérationnelle et le suivi des tâches. Il est donc recommandé d'utiliser les deux outils en complémentarité, pour une planification efficace et complète." }, { "type": "heading", "level": 2, "id": "lagilite-comme-alternative-dans-la-planification", "text": "L'agilité comme alternative dans la planification" }, { "type": "paragraph", "html": "Un rappel sur l'origine. En février 2001, aux États-Unis, 17 spécialistes du développement de logiciels proposent un changement d'approche dans la conduite de projet. Plus empirique, moins prédictive, cette alternative pose l'hypothèse que les cycles de développement logiciel classiques ne correspondent plus aux contraintes et aux exigences d'<strong>organisations en constante évolution</strong>. Le Manifeste agile était né ! 4 valeurs et 12 principes clés." }, { "type": "paragraph", "html": "L'utilisation d'un Macro planning en agilité est un moyen efficace de visualiser les grandes phases et les jalons importants d'un p<strong>rojet tout en restant flexible pour répondre aux changements</strong> de la réalité. Il permet de donner une vision globale du projet, d'identifier les dépendances et les risques potentiels. Cela peut aider à mieux planifier les ressources nécessaires, les délais et les coûts." }, { "type": "paragraph", "html": "Voici comment utiliser un macro planning en agilité :" }, { "type": "list", "ordered": true, "items": ["<strong>Identifiez les grandes phases du projet :</strong> En agilité, les grandes phases du projet sont souvent définies en fonction des livrables. Par exemple, dans un projet de développement logiciel, les phases peuvent inclure la planification, l'analyse, la conception, le développement, les tests et le déploiement. Il est important d'impliquer toutes les parties prenantes pour identifier ces grandes phases et s'assurer que tous sont d'accord sur leur ordre et leur contenu.", "<strong>Définissez les jalons importants :</strong> Une fois que les grandes phases ont été identifiées, il est important de définir les jalons importants qui vont aider à suivre la progression du projet. Les jalons doivent être spécifiques, mesurables, atteignables, pertinents et temporels (SMART). Les jalons peuvent inclure des livrables tels que des documents, des versions logicielles, des tests réussis, des formations, des déploiements, etc.", "<strong>Créez un (macro) diagramme de Gantt</strong> : Un diagramme de Gantt est un outil de visualisation qui permet de représenter les grandes phases du projet et les jalons importants dans le temps. Il est important de mettre à jour régulièrement le diagramme de Gantt pour refléter la progression réelle du projet. Le diagramme de Gantt peut être partagé avec toutes les parties prenantes pour faciliter la communication et la collaboration.", "<strong>Restez flexible</strong> : En agilité, il est important de rester flexible et de s'adapter aux changements de la réalité. Le macro planning doit être utilisé comme une feuille de route globale et non comme un plan strict. Il est important de mettre à jour régulièrement le Macro planning en fonction de l'évolution du projet. Chaque jalon peut être révisé, ajouté ou supprimé en fonction des changements de priorités et des obstacles rencontrés."] }, { "type": "paragraph", "html": "L'utilisation d'un macro planning en agilité est un des moyens efficace de visualiser les grandes phases et les jalons importants d'un projet tout en restant flexible pour répondre aux changements de la réalité. Il permet à la fois de mieux planifier les ressources nécessaires, les délais et les coûts et également de mieux communiquer. Cependant, il est important de rester vraiment flexible et d'être prêt à s'adapter aux changements de la réalité de ce fameux monde VICA (volatile, incertain, complexe et ambigu)." }, { "type": "heading", "level": 2, "id": "le-no-estimate-une-approche-radicale-et-honnete-du-macro-planning", "text": "Le no estimate : une approche radicale et honnête du macro planning ?" }, { "type": "paragraph", "html": "Vous connaissez le courant du <a href=\"https://www.bearstudio.fr/blog/developpement/no-estimate\" target=\"_blank\">no estimate</a> ? Il est popularisé en France par le coach agile Frédéric Le Guedois dont les conférences font salle comble !" }, { "type": "paragraph", "html": "Il s'agit d'un fonctionnement basé sur la confiance mutuelle, la priorisation, et l'agilité. Il repose en quelque sorte sur le mode de la régie avec une facturation au temps passé. Si le <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">budget</a> est variable pour plus de souplesse, le temps de mission et les équipes dédiées au projet peuvent être fixées par avance." }, { "type": "heading", "level": 3, "id": "5-arguments-en-faveur-du-no-estimate", "text": "5 arguments en faveur du \"no estimate\" :" }, { "type": "list", "ordered": true, "items": ["Gain de temps : L'estimation de projet peut prendre beaucoup de temps et ne garantit pas la précision des résultats. Le \"no estimate\" permet de se concentrer sur les tâches importantes plutôt que de passer du temps à essayer de prédire l'avenir.", "Évite les biais : L'estimation peut être influencée par des biais cognitifs, tels que l'effet de halo ou l'effet de confirmation, qui peuvent fausser les résultats. En évitant l'estimation, on peut éviter ces biais et obtenir des résultats plus justes.", "Encourage l'adaptabilité : Lorsque les estimations sont prises comme des engagements fermes, cela peut entraîner une résistance au changement et une inflexibilité. Le \"no estimate\" encourage une approche plus adaptative en permettant une plus grande flexibilité pour répondre aux changements de priorités et aux imprévus.", "Réduit le stress : Les estimations peuvent causer du stress aux membres de l'équipe car elles peuvent être perçues comme des engagements stricts et difficiles à respecter. Le \"no estimate\" permet de réduire ce stress en permettant à l'équipe de se concentrer sur la qualité et la livraison plutôt que sur les délais stricts.", "Améliore la transparence : Les estimations peuvent être perçues comme subjectives et peuvent être mal interprétées par les parties prenantes. Le \"no estimate\" permet de rendre le processus plus transparent en mettant l'accent sur la collaboration et"] }, { "type": "heading", "level": 2, "id": "conclusions-a-retenir", "text": "Conclusions - à retenir" }, { "type": "paragraph", "html": "Le macro planning est complémentaire au micro planning, qui offre une vue plus détaillée des tâches et des ressources nécessaires à la réalisation du projet. Le macroplanning s'avère être un must-have, notamment si vous devez piloter un portefeuille de projets assez conséquent." }, { "type": "paragraph", "html": "Découvrez parmi nos autres articles celui consacré à un autre enjeu clé : <a href=\"/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\">Le suivi de projet pour garder aligné les parties prenantes</a>" }], "toc": [{ "label": "Qu'est-ce qu'un macro planning ?", "href": "#quest-ce-quun-macro-planning", "level": 2 }, { "label": "Macro planning et micro planning : quelles différences ?", "href": "#macro-planning-et-micro-planning-quelles-differences", "level": 2 }, { "label": "Pourquoi utiliser un macroplanning dans sa gestion de projet ?", "href": "#pourquoi-utiliser-un-macroplanning-dans-sa-gestion-de-projet", "level": 2 }, { "label": "Comment créer un macro planning ?", "href": "#comment-creer-un-macro-planning", "level": 2 }, { "label": "Peut on se passer d'un diagramme de Gantt pour un macro planning ?", "href": "#peut-on-se-passer-dun-diagramme-de-gantt-pour-un-macro-planning", "level": 2 }, { "label": "L'agilité comme alternative dans la planification", "href": "#lagilite-comme-alternative-dans-la-planification", "level": 2 }, { "label": "Le no estimate : une approche radicale et honnête du macro planning ?", "href": "#le-no-estimate-une-approche-radicale-et-honnete-du-macro-planning", "level": 2 }, { "label": "Conclusions - à retenir", "href": "#conclusions-a-retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "management-de-portefeuille-de-projet", "skip": false, "meta": { "title": "Management de portefeuille de projet : définition, méthodes et outils", "h1": "Management de portefeuille de projet : définition, méthodes et outils", "description": "Gestion de portefeuille de projets (PPM) : définition, méthodes de priorisation, KPIs essentiels et outils pour piloter efficacement vos projets.", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "1/2/2026", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6995db9e00db2afd8d4d5013_Gestion%20de%20portefeuille%20de%20projets.jpg", "alt": "" }, "publishedDate": "1/2/2026" }, "blocks": [{ "type": "heading", "level": 2, "id": "quest-ce-que-la-gestion-de-portefeuille-de-projets", "text": "Qu'est-ce que la gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "La <strong>gestion de portefeuille de projets</strong> (GPP), aussi appelée <strong>Project Portfolio Management</strong> (PPM), est une discipline stratégique qui consiste à sélectionner, prioriser et piloter l'ensemble des projets d'une organisation pour maximiser la création de valeur." }, { "type": "paragraph", "html": "Contrairement à la gestion de projet, qui vise à \"<strong>bien faire les projets</strong>\" (domaine opérationnel), la gestion de portefeuille de projets cherche à \"<strong>faire les bons projets</strong>\" (domaine décisionnel)." }, { "type": "paragraph", "html": "Le Project Management Institute (PMI) la définit comme <em>la gestion centralisée des processus, méthodes et technologies d'un ensemble de projets, permettant d'optimiser les arbitrages et leur planification, tout en évaluant le niveau de risque et la viabilité financière des projets</em>." }, { "type": "paragraph", "html": "Concrètement, un <strong>portefeuille de projets</strong> regroupe l'ensemble des projets, programmes et opérations d'une entreprise. À l'image d'un portefeuille boursier, il s'agit de décider où investir son budget, ses ressources et son temps pour obtenir le meilleur retour sur investissement." }, { "type": "paragraph", "html": "Le PPM fonctionne comme un <strong>entonnoir stratégique</strong> : à l'entrée, un flux massif d'idées provenant de la stratégie, des clients ou de la réglementation ; à la sortie, une sélection rigoureuse d'initiatives coordonnées et exécutables. Sans ce filtre, l'organisation s'épuise à tout mener de front et condamne ses projets à des résultats médiocres." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699732d4dfc0c2f0d4d8feb0_Entonnoir%20strate%CC%81gique%20PPM%20FR.jpg", "alt": "Entonnoir stratégique de la gestion de portefeuille de projets — de l'idée à l'exécution" }, { "type": "paragraph", "html": "Ce que la gestion de portefeuille de projets permet" }, { "type": "list", "ordered": false, "items": ["Assurer l'<strong>alignement stratégique</strong> entre les projets et la vision de l'entreprise", "<strong>Prioriser</strong> les initiatives à plus forte valeur ajoutée", "<strong>Optimiser l'allocation des ressources</strong> (humaines, financières, matérielles) entre les projets", "<strong>Anticiper les risques</strong> de déséquilibre entre capacité et demande", "Offrir une <strong>visibilité consolidée</strong> aux instances de décision (Comité de pilotage, Direction Générale)", "<strong>Arrêter ou reporter</strong> les projets qui n'apportent plus de valeur"] }, { "type": "heading", "level": 3, "id": "la-capacite-par-equipe-la-contrainte-au-coeur-du-portefeuille", "text": "La capacité par équipe : la contrainte au cœur du portefeuille" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets repose sur une vérité que beaucoup d'organisations refusent de regarder en face : <strong>la capacité des équipes est finie</strong>. Et c'est cette contrainte — pas les matrices de scoring, pas les pourcentages d'avancement — qui doit structurer toutes les décisions." }, { "type": "paragraph", "html": "Concrètement, la capacité se mesure <strong>par équipe</strong> et <strong>au trimestre</strong>. C'est l'échelle du <strong>Quarter Plan</strong> : chaque équipe (infra, développement, data, sécurité…) dispose d'un nombre de jours-homme réels sur le trimestre à venir, une fois déduites les absences, la maintenance, le run et les imprévus. Cette capacité trimestrielle est le vrai budget de votre portefeuille — bien plus structurant que le budget financier." }, { "type": "table", "headers": ["", "Gestion des ressources", "Planification de la capacité"], "rows": [["Horizon", "Court terme (semaine/sprint)", "Trimestriel (Quarter Plan)"], ["Maille", "Individu par individu", "Équipe par équipe"], ["Question clé", "\"Qui travaille sur quoi cette semaine ?\"", "\"Cette équipe peut-elle absorber ce projet ce trimestre ?\""], ["Usage", "Optimiser l'affectation au quotidien", "Décider quels projets entrent dans le portefeuille — et lesquels attendent"]] }, { "type": "insight-callout", "html": "⚠️ <strong>Méfions-nous des mots creux.</strong> Les termes \"prioriser\" et \"piloter\" sont parmi les plus galvaudés du vocabulaire projet. Dire qu'un portefeuille est \"priorisé\", c'est souvent ne rien dire du tout si aucune contrainte de capacité n'a été confrontée aux engagements. De même, \"piloter\" un portefeuille via un <strong>pourcentage d'avancement</strong> est trompeur : un projet peut afficher 70 % d'avancement et être à des mois de livrer le moindre délivrable exploitable. Le pourcentage d'avancement mesure la consommation de charge, rarement la proximité d'un résultat tangible. La vraie question n'est jamais \"où en est-on ?\", mais <strong>\"qu'est-ce qu'on va livrer ce trimestre, et est-ce que l'équipe a la bande passante pour le faire ?\"</strong>", "label": "Attention" }, { "type": "paragraph", "html": "La planification de la capacité est le garde-fou stratégique de votre portefeuille : sans elle, vous validez des projets que vos équipes ne pourront jamais absorber." }, { "type": "insight-callout", "html": "💡 <strong>Le saviez-vous ?</strong> Selon une étude du PMI, 70 % des projets ont tendance à échouer. La première cause ? Un changement dans les priorisations de l'entreprise (39 %), suivi d'une modification des objectifs du projet (37 %). La gestion de portefeuille de projets existe précisément pour anticiper et piloter ces arbitrages plutôt que de les subir.", "label": "Le saviez-vous" }, { "type": "heading", "level": 2, "id": "portefeuille-de-projets-vs-programme-vs-projet-quelles-differences", "text": "Portefeuille de projets vs programme vs projet : quelles différences ?" }, { "type": "paragraph", "html": "La confusion entre ces trois concepts est fréquente. Voici ce qui les distingue." }, { "type": "heading", "level": 3, "id": "le-projet", "text": "Le projet" }, { "type": "paragraph", "html": "Un <strong>projet</strong> est une initiative temporaire visant à produire un livrable unique. Il a un début, une fin, un budget et des objectifs SMART (Spécifiques, Mesurables, Atteignables, Réalistes, Temporels). La gestion de projet se concentre sur la livraison réussie de cette initiative." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> Déployer un nouvel outil CRM pour l'équipe commerciale." }, { "type": "heading", "level": 3, "id": "le-programme", "text": "Le programme" }, { "type": "paragraph", "html": "Un <strong>programme</strong> est un ensemble de projets interdépendants qui partagent des objectifs communs. Les projets au sein d'un programme sont liés : ils contribuent collectivement à un résultat stratégique." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> Le programme \"Transformation digitale de la relation client\" qui regroupe le projet CRM, le projet refonte du site web et le projet mise en place d'un chatbot." }, { "type": "heading", "level": 3, "id": "le-portefeuille-de-projets", "text": "Le portefeuille de projets" }, { "type": "paragraph", "html": "Un <strong>portefeuille de projets</strong> n'est pas un niveau hiérarchique au-dessus du programme. C'est une <strong>lentille</strong> — une façon de regarder un groupement de projets sous un angle donné, pour prendre des décisions adaptées à ce périmètre." }, { "type": "paragraph", "html": "En pratique, une même organisation manipule plusieurs portefeuilles simultanément : le portefeuille de l'<strong>équipe IT infrastructure</strong>, celui de l'<strong>équipe applicative métier</strong>, le portefeuille des <strong>projets vitaux</strong>, celui des projets de <strong>conformité réglementaire</strong>, ou encore le portefeuille global vu par la Direction Générale. Chaque vue répond à une question différente : \"Mon équipe est-elle en surcharge ?\", \"Nos projets vitaux avancent-ils ?\", \"Sommes-nous alignés avec la stratégie ?\"." }, { "type": "paragraph", "html": "C'est ce qui rend la gestion de portefeuille de projets si puissante : elle n'impose pas un cadre unique, mais offre la possibilité de <strong>filtrer, regrouper et comparer les projets</strong> selon les besoins de chaque partie prenante — équipe, direction métier, DSI ou Comité de direction." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> La DSI pilote un portefeuille global, mais chaque équipe (infra, dev, data) dispose de sa propre vue portefeuille avec ses contraintes de capacité. Le Comité de direction, lui, regarde le portefeuille par axe stratégique." }, { "type": "heading", "level": 3, "id": "tableau-comparatif", "text": "Tableau comparatif" }, { "type": "table", "headers": ["Critère", "Projet", "Programme", "Portefeuille"], "rows": [["Nature", "Une initiative temporaire avec un livrable", "Un ensemble de projets liés par un objectif commun", "Une vue sur un groupement de projets, filtrée par équipe, thématique ou axe stratégique"], ["Objectif", "Livrer un résultat concret dans les délais", "Atteindre un bénéfice stratégique commun", "Décider quoi faire, quoi arrêter, quoi reporter — en fonction de la capacité réelle"], ["Niveau de décision", "Opérationnel", "Tactique", "Stratégique"], ["Contrainte centrale", "Le triangle coût/délai/périmètre", "La coordination entre projets interdépendants", "La capacité des équipes — le nombre de projets sera toujours supérieur à ce qu'on peut absorber"], ["Pilote", "Chef de projet", "Directeur de programme", "PMO / DSI / Direction Générale"], ["Question clé", "\"Le livrable sera-t-il prêt ?\"", "\"Les projets produisent-ils le bénéfice attendu ?\"", "\"Les bonnes équipes travaillent-elles sur les bons sujets, au bon moment ?\""]] }, { "type": "insight-callout", "html": "📌 <strong>À retenir :</strong> Le portefeuille n'est pas \"au-dessus\" du projet et du programme dans une pyramide. C'est une <strong>grille de lecture</strong> qui permet de comparer, arbitrer et allouer les ressources entre des projets qui se disputent la même capacité. Il peut exister autant de vues portefeuille que de besoins de décision dans l'organisation.", "label": "À retenir" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699733200e76e85e0aaa049e_Le%20portefeuille%20comme%20lentille%20%E2%80%94%20vues%20multiples%20FR.jpg", "alt": "Le portefeuille de projets comme lentille — vues multiples par équipe, stratégie et priorité" }, { "type": "heading", "level": 2, "id": "pourquoi-mettre-en-place-une-gestion-de-portefeuille-de-projets", "text": "Pourquoi mettre en place une gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "Dans la plupart des entreprises, le nombre de projets dépasse largement la capacité à les réaliser. C'est une loi universelle de la transformation : la demande sera toujours supérieure à l'offre de ressources disponibles." }, { "type": "paragraph", "html": "Les chiffres le confirment : selon l'IBM Institute for Business Value, les organisations leaders en gestion de portefeuille de projets affichent une <strong>performance de revenus 46 % plus prévisible</strong> que leurs concurrentes moins matures. L'excellence en PPM n'est pas un luxe organisationnel — c'est un avantage concurrentiel mesurable." }, { "type": "paragraph", "html": "Sans gestion de portefeuille de projets, les organisations subissent un phénomène bien connu : <strong>l'urgence chasse l'urgence</strong>. Les équipes fonctionnent en \"best effort\", les arbitrages se font au fil de l'eau (ou au \"fait du prince\"), et personne n'a de visibilité sur ce qui est réellement prioritaire." }, { "type": "heading", "level": 3, "id": "les-6-benefices-concrets-dune-demarche-de-gestion-de-portefeuille-de-projets", "text": "Les 6 bénéfices concrets d'une démarche de gestion de portefeuille de projets" }, { "type": "paragraph", "html": "<strong>1. Alignement stratégique</strong>" }, { "type": "paragraph", "html": "La GPP garantit que chaque projet contribue à la stratégie de l'entreprise. Fini les projets \"orphelins\" qui consomment des ressources sans créer de valeur mesurable. Chaque euro investi est tracé jusqu'à un objectif stratégique. Une vérité trop souvent ignorée : <strong>succès technique ≠ succès business</strong>. Une exécution parfaite d'un projet sans alignement stratégique reste un gaspillage de ressources." }, { "type": "paragraph", "html": "<strong>2. Priorisation objective et transparente</strong>" }, { "type": "paragraph", "html": "En rendant visible la règle du jeu et l'ensemble des sujets en revue de portefeuille, la démarche instaure une relation de confiance et de transparence entre la DSI, les métiers et la direction générale. Les décisions de priorisation sont fondées sur des <strong>données probantes</strong>, pas sur le rapport de force politique ou la voix la plus forte en comité de direction." }, { "type": "paragraph", "html": "<strong>3. Optimisation de la capacité — la vraie valeur ajoutée</strong>" }, { "type": "paragraph", "html": "C'est ici que la gestion de portefeuille de projets prend tout son sens. La capacité ne se mesure pas à l'échelle de l'organisation entière — elle se mesure <strong>équipe par équipe, trimestre par trimestre</strong>. L'approche du <strong>Quarter Plan</strong> consiste à confronter, chaque trimestre, les engagements projet à la bande passante réelle de chaque équipe. Les organisations qui maîtrisent cette planification augmentent de <strong>68 % leurs chances de livrer leurs projets à temps</strong>. Le secret : identifier les goulots sur les compétences critiques (architectes IT, experts métiers, ingénieurs spécialisés) et accepter de reporter ce qui ne rentre pas dans le trimestre. Résultat : moins de surcharge, moins de retards en cascade, des engagements crédibles." }, { "type": "paragraph", "html": "<strong>4. Gestion proactive des risques</strong>" }, { "type": "paragraph", "html": "En ayant une vue consolidée du portefeuille, les risques sont identifiés à l'échelle de l'organisation, pas uniquement projet par projet. Un risque sur un projet structurant peut impacter tout le portefeuille : la GPP permet de l'anticiper." }, { "type": "paragraph", "html": "<strong>5. Meilleure communication avec les parties prenantes</strong>" }, { "type": "paragraph", "html": "Le reporting consolidé du portefeuille (tableau de bord, rapport flash, revue de portefeuille) offre aux dirigeants les données nécessaires pour prendre des décisions éclairées, sans avoir à plonger dans le détail de chaque projet." }, { "type": "paragraph", "html": "<strong>6. Agilité décisionnelle</strong>" }, { "type": "paragraph", "html": "Les roadmaps de SI à 3-5 ans figées appartiennent au passé. Avec une GPP moderne, la priorisation se fait en continu, à un rythme adapté aux changements de contexte de l'entreprise. Les données terrain remontent en temps réel, permettant des réajustements rapides." }, { "type": "quote", "text": "🏢 <strong>Idée reçue :</strong> \"La gestion de portefeuille de projets est réservée aux grandes entreprises.\" <strong>Faux.</strong> Les PME et ETI peuvent parfois en tirer encore plus de bénéfices, car elles ont plus d'agilité et la capacité de mettre en œuvre la démarche plus rapidement. L'enjeu est d'adapter le niveau de formalisme à la taille de l'organisation." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6997336f720e4b07874d2db7_6%20be%CC%81ne%CC%81fices%20du%20PPM%20en%20chiffres%20FR.jpg", "alt": "Statistiques clés de la gestion de portefeuille de projets — IBM, PMI" }, { "type": "heading", "level": 2, "id": "les-7-etapes-pour-deployer-une-gestion-de-portefeuille-de-projets-efficace", "text": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699733e0185a65bc475aebde_Les%207%20e%CC%81tapes%20du%20de%CC%81ploiement%20PPM%20FR.jpg", "alt": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace" }, { "type": "heading", "level": 3, "id": "etape-1-definir-les-objectifs-strategiques", "text": "Étape 1 — Définir les objectifs stratégiques" }, { "type": "paragraph", "html": "Tout commence par la boussole. Sans clarté sur la stratégie, votre portefeuille ne sera qu'un inventaire de projets sans cohérence." }, { "type": "paragraph", "html": "Trois actions concrètes pour cette étape :" }, { "type": "list", "ordered": false, "items": ["Formaliser la vision à 2-3 ans avec la Direction Générale", "Identifier les axes stratégiques prioritaires (croissance, efficacité, conformité, innovation...)", "Traduire ces axes en <strong>critères de sélection mesurables</strong> pour les projets"] }, { "type": "heading", "level": 3, "id": "etape-2-recenser-et-categoriser-tous-les-projets-intake", "text": "Étape 2 — Recenser et catégoriser tous les projets (Intake)" }, { "type": "paragraph", "html": "Créez un inventaire exhaustif de toutes les initiatives en cours et à venir : projets validés, projets en attente, idées en gestation. Centralisez toutes les demandes — qu'elles soient stratégiques, réglementaires, issues des métiers ou des clients — dans un processus unique d'<strong>intake</strong> (capture). C'est le meilleur moyen d'éliminer les redondances et d'identifier les opportunités de mutualisation." }, { "type": "paragraph", "html": "Chaque projet doit être documenté avec une fiche standardisée comprenant au minimum : objectif, sponsor, budget estimé, ressources nécessaires, échéance et contribution stratégique." }, { "type": "paragraph", "html": "Catégorisez ensuite vos projets par type (transformation, run, réglementaire, innovation...) et par programme si applicable." }, { "type": "heading", "level": 3, "id": "etape-3-evaluer-et-prioriser-les-projets", "text": "Étape 3 — Évaluer et prioriser les projets" }, { "type": "paragraph", "html": "C'est le cœur de la démarche. Appliquez vos critères de sélection pour noter et classer chaque projet. Les méthodes de priorisation sont détaillées dans la section suivante, mais l'essentiel est d'avoir une approche <strong>multicritère</strong> qui combine valeur business, faisabilité, risques et alignement stratégique." }, { "type": "heading", "level": 3, "id": "etape-4-aligner-la-capacite-avec-la-demande-quarter-plan", "text": "Étape 4 — Aligner la capacité avec la demande (Quarter Plan)" }, { "type": "paragraph", "html": "C'est l'étape la plus décisive — et la plus souvent bâclée. Pour chaque <strong>équipe</strong>, évaluez sa capacité réelle sur le <strong>trimestre à venir</strong> : jours-homme disponibles, une fois déduites les absences, le run, la maintenance et la marge d'imprévu. Puis confrontez cette capacité aux engagements projet." }, { "type": "paragraph", "html": "C'est souvent le moment de vérité : ce qui semblait prioritaire peut se révéler irréaliste si l'équipe concernée est déjà saturée. L'exercice doit être concret : non pas \"a-t-on les moyens au global ?\", mais <strong>\"l'équipe Data peut-elle absorber ce projet en Q2, ou faut-il le décaler en Q3 ?\"</strong>" }, { "type": "paragraph", "html": "L'objectif n'est pas de tout planifier au jour près. C'est de s'assurer que les engagements sont crédibles. Mieux vaut 5 projets livrés ce trimestre que 15 projets \"en cours\" dont aucun ne délivre de résultat tangible. Attention au piège du pourcentage d'avancement : un projet à \"60 %\" ne signifie pas qu'il est proche de livrer quoi que ce soit d'exploitable — c'est souvent juste un ratio de charge consommée." }, { "type": "heading", "level": 3, "id": "etape-5-definir-la-gouvernance-et-les-rituels", "text": "Étape 5 — Définir la gouvernance et les rituels" }, { "type": "paragraph", "html": "Mettez en place les instances de décision et les rituels récurrents qui feront vivre votre portefeuille :" }, { "type": "list", "ordered": false, "items": ["<strong>Revue de portefeuille mensuelle</strong> : arbitrages, décisions Go/No-Go, réallocation de ressources", "<strong>Comité de pilotage</strong> : validation des orientations stratégiques et des investissements majeurs", "<strong>Reporting hebdomadaire</strong> (rapport flash) : état d'avancement consolidé envoyé aux parties prenantes", "<strong>Point projet hebdomadaire</strong> : 5 minutes par projet entre chef de projet et référent métier"] }, { "type": "paragraph", "html": "Le PMI distingue trois types de PMO (Bureau de Gestion de Projets), selon le niveau de contrôle exercé :" }, { "type": "table", "headers": ["Type de PMO", "Rôle", "Niveau de contrôle"], "rows": [["Support", "Fournit modèles, outils et bonnes pratiques", "Faible — les équipes restent autonomes"], ["Contrôle", "Exige la conformité aux méthodologies via des audits", "Modéré — cadre structurant"], ["Directif", "Gère directement les projets et affecte les chefs de projet", "Élevé — pilotage centralisé"]] }, { "type": "paragraph", "html": "Le choix du type de PMO dépend de la maturité de votre organisation et de votre culture managériale. La tendance actuelle est au PMO \"facilitateur\" (entre Support et Contrôle), qui structure sans bureaucratiser. Plus largement, le succès en 2026 exige une <strong>métamorphose du PMO</strong> : il doit évoluer d'un rôle de support administratif vers celui de <strong>partenaire stratégique</strong>. Le pilotage stratégique ne consiste pas à surveiller des calendriers, mais à garantir que chaque euro et chaque heure investis servent la croissance de l'entreprise." }, { "type": "paragraph", "html": "Sans rituels réguliers, votre portefeuille deviendra vite obsolète. C'est la fréquence et la discipline de ces rituels qui créent la valeur." }, { "type": "heading", "level": 3, "id": "etape-6-outiller-la-demarche", "text": "Étape 6 — Outiller la démarche" }, { "type": "paragraph", "html": "Suivre un portefeuille de projets dans Excel n'est plus viable au-delà de 10 projets. Un <strong>outil PPM</strong> (Project Portfolio Management) dédié permet de centraliser les informations, automatiser le reporting et offrir une visibilité en temps réel à toutes les parties prenantes." }, { "type": "paragraph", "html": "Les critères clés pour choisir votre outil PPM sont détaillés dans la section dédiée ci-dessous." }, { "type": "heading", "level": 3, "id": "etape-7-piloter-en-continu-et-ameliorer", "text": "Étape 7 — Piloter en continu et améliorer" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets n'est pas un exercice ponctuel, c'est un processus continu. À chaque revue de portefeuille, posez-vous trois questions :" }, { "type": "list", "ordered": true, "items": ["Les projets en cours sont-ils toujours alignés avec la stratégie ?", "Faut-il ajouter, reporter ou arrêter des projets ?", "La capacité est-elle toujours suffisante pour tenir les engagements ?"] }, { "type": "quote", "text": "🎯 <strong>Conseil pragmatique :</strong> Ne cherchez pas la perfection au démarrage. Commencez avec un périmètre restreint (10-15 projets clés), des rituels simples et un outil adapté. Faites \"tache d'huile\" ensuite. La maturité se construit progressivement, comme un sachet de thé qui infuse." }, { "type": "heading", "level": 2, "id": "les-methodes-de-priorisation-dun-portefeuille-de-projets", "text": "Les méthodes de priorisation d'un portefeuille de projets" }, { "type": "paragraph", "html": "La priorisation est l'exercice le plus complexe et le plus politique de la gestion de portefeuille de projets. Voici les méthodes les plus utilisées." }, { "type": "heading", "level": 3, "id": "le-scoring-multicritere", "text": "Le scoring multicritère" }, { "type": "paragraph", "html": "Chaque projet est évalué sur une grille de critères pondérés. Les critères se répartissent généralement en trois familles :" }, { "type": "list", "ordered": false, "items": ["<strong>Critères financiers</strong> : Valeur Actuelle Nette (VAN), Retour sur Investissement (ROI), période de remboursement (payback)", "<strong>Critères stratégiques</strong> : Alignement avec les objectifs annuels, impact client, différenciation concurrentielle", "<strong>Critères opérationnels</strong> : Faisabilité technique, probabilité de réussite, urgence réglementaire, disponibilité des ressources"] }, { "type": "paragraph", "html": "Chaque critère reçoit un score (par exemple de 1 à 5) et un poids relatif. Le score pondéré total permet de classer les projets objectivement et d'établir une <strong>ligne de démarcation</strong> (cut-line) : les projets au-dessus passent, ceux en dessous sont reportés ou abandonnés. L'application de la cut-line est l'acte de management ultime : une fois que les ressources sont consommées par les projets les mieux notés, tout ce qui se trouve en dessous de la ligne doit être reporté ou annulé, sans exception. C'est la seule méthode pour garantir que les initiatives à fort impact reçoivent l'oxygène nécessaire à leur réussite — et pour protéger le portefeuille des \"projets de cœur\" (pet projects) dépourvus de valeur réelle." }, { "type": "paragraph", "html": "<strong>Avantage :</strong> Transparence, reproductibilité, facilité d'explication aux parties prenantes. <strong>Limite :</strong> La qualité du scoring dépend de la qualité des données d'entrée. Comme le souligne Robert Cooper, expert en gestion de portefeuille : <em>« La sophistication des méthodes financières dépasse souvent la qualité des données. Les méthodes purement comptables produisent parfois les résultats les plus médiocres si elles ne sont pas complétées par un jugement stratégique. »</em>" }, { "type": "heading", "level": 3, "id": "la-matrice-valeur-effort-et-risque-rendement", "text": "La matrice valeur / effort (et risque / rendement)" }, { "type": "paragraph", "html": "Cette approche simple et visuelle positionne chaque projet sur deux axes : la valeur attendue (impact business) et l'effort nécessaire (coût, complexité, durée). Les projets à forte valeur et faible effort (les \"quick wins\") sont prioritaires." }, { "type": "paragraph", "html": "Une variante couramment utilisée est la <strong>matrice risque-rendement</strong>, qui permet d'équilibrer le portefeuille entre quatre quadrants : les \"Quick Wins\" (faible risque, haut rendement), les projets stratégiques (haut risque, haut rendement), les projets d'optimisation (faible risque, faible rendement) et les projets à éviter (haut risque, faible rendement)." }, { "type": "paragraph", "html": "<strong>Avantage :</strong> Visuel, rapide à mettre en place, excellent pour les ateliers de priorisation. <strong>Limite :</strong> Réducteur pour les projets complexes à impact long terme" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/69975dc546f627807d618489_Matrice%20Valeur%20-Effort%20FR.png", "alt": "Matrice de priorisation valeur-effort pour le portefeuille de projets" }, { "type": "heading", "level": 3, "id": "la-methode-moscow", "text": "La méthode MoSCoW" }, { "type": "paragraph", "html": "Classez les projets en quatre catégories : <strong>Must have</strong> (vital), <strong>Should have</strong> (important), <strong>Could have</strong> (souhaitable), <strong>Won't have</strong> (pas maintenant). Cette méthode issue du monde agile est particulièrement adaptée quand il faut trancher rapidement." }, { "type": "heading", "level": 3, "id": "le-modele-wsjf-weighted-shortest-job-first", "text": "Le modèle WSJF (Weighted Shortest Job First)" }, { "type": "paragraph", "html": "Issu du framework SAFe, le WSJF priorise en divisant la valeur (<strong>coût du retard</strong> — Cost of Delay) par la taille de l'effort. Le coût du retard combine trois composantes : la valeur business/utilisateur, la criticité temporelle (fenêtre d'opportunité) et la réduction de risque ou l'opportunité d'apprentissage. Les projets à fort coût du retard et de petite taille passent en premier. C'est la méthode la plus utilisée dans les organisations ayant adopté l'agilité à l'échelle." }, { "type": "heading", "level": 3, "id": "la-methode-rice", "text": "La méthode RICE" }, { "type": "paragraph", "html": "RICE est un modèle de scoring rapide qui évalue chaque projet selon 4 dimensions : <strong>Reach</strong> (portée/nombre de personnes impactées), <strong>Impact</strong> (degré d'impact par personne), <strong>Confidence</strong> (niveau de confiance dans les estimations) et <strong>Effort</strong> (charge de travail nécessaire). Le score RICE = (Reach × Impact × Confidence) / Effort. Les projets avec le score le plus élevé sont priorisés." }, { "type": "heading", "level": 3, "id": "la-priorisation-par-le-lean-portfolio-management", "text": "La priorisation par le Lean Portfolio Management" }, { "type": "paragraph", "html": "Le <strong>Lean Portfolio Management</strong> (LPM) va plus loin en intégrant la priorisation dans un flux continu, aligné sur les objectifs stratégiques (OKR ou Epics stratégiques). La capacité est allouée par \"flux de valeur\" plutôt que par projet, ce qui permet une plus grande agilité dans les arbitrages." }, { "type": "table", "headers": ["Caractéristique", "PPM traditionnelle", "Lean Portfolio Management"], "rows": [["Financement", "Basé sur des projets spécifiques", "Basé sur les chaînes de valeur (Value Streams)"], ["Planification", "Cycle annuel rigide", "Glissante, itérative, ajustée chaque trimestre"], ["Gouvernance", "Contrôle centralisé (Top-down)", "Décisions décentralisées avec garde-fous"], ["Focus", "Administration de projets individuels", "Performance économique globale du portefeuille"]] }, { "type": "paragraph", "html": "Le passage au LPM marque la fin de la planification annuelle rigide, souvent obsolète dès le premier trimestre. On ne finance plus des projets isolés (approche \"Fire and Forget\"), mais des chaînes de valeur continues. Cette agilité est sécurisée par trois <strong>garde-fous</strong> (Guardrails) :" }, { "type": "list", "ordered": true, "items": ["<strong>Investissement par horizon</strong> : Équilibre entre maintenance du patrimoine existant, gains immédiats (quick wins) et innovation de rupture.", "<strong>Allocation de capacité</strong> : Arbitrage strict entre le développement de nouvelles fonctionnalités et la réduction de la dette technique.", "<strong>Indicateurs basés sur les résultats</strong> : Utilisation de KPIs liés aux résultats réels (Outcomes) plutôt qu'au simple avancement des tâches (Outputs)."] }, { "type": "heading", "level": 3, "id": "lanalyse-de-simulation-what-if", "text": "L'analyse de simulation « What-If »" }, { "type": "paragraph", "html": "L'analyse de scénarios est un levier puissant pour s'extraire de la gestion de crise permanente et troquer l'intuition contre l'<strong>analyse d'impact prédictive</strong>. Une simulation rigoureuse repose sur trois étapes :" }, { "type": "list", "ordered": true, "items": ["<strong>Identification des variables</strong> : Isoler les leviers critiques — budgets, disponibilité des compétences clés, <strong>coût du retard</strong> (Cost of Delay), dépendances inter-projets.", "<strong>Modélisation de scénarios</strong> : Construire des trajectoires optimiste, pessimiste et \"plus probable\" pour tester la résilience du portefeuille.", "<strong>Évaluation de l'impact</strong> : Mesurer précisément la dérive potentielle sur les délais, les coûts et la charge de travail globale."] }, { "type": "paragraph", "html": "Par exemple : simuler l'ajout d'un projet urgent pour mesurer le décalage sur les dates de livraison des initiatives en cours, ou évaluer l'impact d'une réduction budgétaire de 15 % sur la composition du portefeuille. Les outils PPM modernes intègrent ces capacités de simulation pour éclairer les décisions d'arbitrage en comité de pilotage — mettant fin au règne de \"la voix la plus forte\" en comité de direction." }, { "type": "quote", "text": "⚡ <strong>Bonne pratique AirSaaS :</strong> Les portefeuilles priorisés à 2-3 ans figés, c'était avant. Aujourd'hui, la priorisation en continu est la pratique courante. Un sondage AirSaas (2022) montre que la majorité des DSI repriorisent leur portefeuille au minimum chaque trimestre, et souvent chaque mois." }, { "type": "heading", "level": 2, "id": "les-kpis-essentiels-du-pilotage-de-portefeuille", "text": "Les KPIs essentiels du pilotage de portefeuille" }, { "type": "paragraph", "html": "Piloter un portefeuille de projets sans indicateurs, c'est conduire sans tableau de bord. Voici les KPIs incontournables, organisés en 4 catégories." }, { "type": "heading", "level": 3, "id": "kpis-dalignement-strategique", "text": "KPIs d'alignement stratégique" }, { "type": "list", "ordered": false, "items": ["<strong>% de projets alignés avec les axes stratégiques</strong> : Chaque projet doit être rattaché à un objectif. Un portefeuille sain affiche 80 à 100 % d'alignement.", "<strong>Répartition budgétaire par axe stratégique</strong> : Visualiser si les investissements sont cohérents avec les priorités déclarées.", "<strong>Bénéfices réalisés</strong> : Valeur réelle constatée post-clôture, comparée aux bénéfices attendus lors de la sélection."] }, { "type": "heading", "level": 3, "id": "kpis-de-capacite-et-ressources", "text": "KPIs de capacité et ressources" }, { "type": "list", "ordered": false, "items": ["<strong>Taux d'utilisation des ressources</strong> : Temps productif vs temps total disponible. Au-delà de 80 %, le risque de surcharge est élevé.", "<strong>Ratio demande vs capacité</strong> : Combien de projets sont en attente faute de bande passante ?", "<strong>Productivité par ressource</strong> : Tâches ou jalons accomplis par période, pour identifier les écarts de performance.", "<strong>Churn de l'équipe</strong> : Rotation du personnel en cours de projet — un indicateur avancé de problèmes de management ou de surcharge."] }, { "type": "heading", "level": 3, "id": "kpis-de-performance-operationnelle", "text": "KPIs de performance opérationnelle" }, { "type": "list", "ordered": false, "items": ["<strong>% de projets \"au vert\" / \"à risque\" / \"en alerte\"</strong> : Le triptyque météo classique, indispensable pour une revue de portefeuille efficace.", "<strong>Taux de respect des jalons</strong> : Les jalons clés sont-ils atteints dans les délais ?", "<strong>Variance budgétaire</strong> : Écart entre coûts prévus et coûts réels — un signal d'alerte précoce.", "<strong>Nombre de demandes de changement</strong> : Indicateur de la stabilité du périmètre. Un nombre élevé signale un cadrage initial insuffisant.", "<strong>Indice de santé du projet</strong> : Score composite combinant coût, délai et risque en un seul indicateur.", "<strong>Conformité</strong> : Adhérence aux processus, méthodologies et réglementations en vigueur."] }, { "type": "heading", "level": 3, "id": "kpis-de-valeur-et-resultats", "text": "KPIs de valeur et résultats" }, { "type": "list", "ordered": false, "items": ["<strong>ROI des projets livrés</strong> : Le portefeuille crée-t-il réellement la valeur financière attendue ?", "<strong>Délai de livraison (Time to Market)</strong> : Combien de temps entre la décision de lancer un projet et la première livraison de valeur ?", "<strong>Taux d'annulation</strong> : Capacité de l'organisation à arrêter les projets non rentables — un signe de maturité, pas d'échec.", "<strong>Satisfaction des parties prenantes</strong> : Enquêtes de satisfaction auprès des sponsors, métiers et équipes projet.", "<strong>Gestion des risques</strong> : Ratio risques mitigés vs risques identifiés — mesure l'efficacité de l'anticipation."] }, { "type": "quote", "text": "📊 <strong>Conseil :</strong> Ne multipliez pas les indicateurs. 5 à 8 KPIs bien choisis et mis à jour régulièrement valent mieux que 18 indicateurs jamais consultés. Sélectionnez ceux qui correspondent à votre niveau de maturité et enrichissez progressivement. L'enjeu est que votre tableau de bord de portefeuille raconte une histoire claire en 30 secondes." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699734d9e8f99e6b413126ef_Page%20Portfolio%20FR.png", "alt": "Tableau de bord de gestion de portefeuille de projets — interface AirSaas" }, { "type": "heading", "level": 2, "id": "comment-choisir-son-outil-ppm", "text": "Comment choisir son outil PPM ?" }, { "type": "paragraph", "html": "Le marché des outils de gestion de portefeuille de projets a considérablement évolué. Fini les usines à gaz ERP/PPM des années 2010. Les solutions modernes misent sur la simplicité, la collaboration et l'automatisation." }, { "type": "heading", "level": 3, "id": "les-criteres-essentiels-dun-bon-outil-ppm", "text": "Les critères essentiels d'un bon outil PPM" }, { "type": "paragraph", "html": "<strong>Simplicité d'adoption</strong> : L'outil doit être utilisable par les chefs de projet, les métiers ET la direction, sans formation complexe. Si personne ne l'utilise, il ne sert à rien." }, { "type": "paragraph", "html": "<strong>Vue portefeuille consolidée</strong> : Tableaux de bord visuels avec filtres (par programme, par axe stratégique, par météo projet, par responsable). La vue macro est la raison d'être de l'outil." }, { "type": "paragraph", "html": "<strong>Reporting automatisé</strong> : Génération automatique de rapports flash (PPT, PDF, URL) pour le Comité de pilotage, sans passer 4 jours à compiler des données manuellement." }, { "type": "paragraph", "html": "<strong>Gestion des rituels</strong> : L'outil doit structurer vos revues de portefeuille, vos points projet et vos Copil avec des workflows adaptés." }, { "type": "paragraph", "html": "<strong>Intégration avec l'écosystème existant</strong> : Connexion native avec les outils de gestion de tâches (Jira, Asana, Monday, Azure DevOps) pour faire remonter les données opérationnelles sans double saisie." }, { "type": "paragraph", "html": "<strong>Collaboration temps réel</strong> : Toutes les parties prenantes (DSI, métiers, direction) contribuent sur la même plateforme. Plus de \"je ne savais pas\"." }, { "type": "heading", "level": 3, "id": "ce-quun-outil-ppm-ne-resout-pas", "text": "Ce qu'un outil PPM ne résout pas" }, { "type": "paragraph", "html": "Un outil, aussi bon soit-il, ne peut pas compenser une gouvernance floue, des objectifs stratégiques non définis ou un management indécis. L'outil est un catalyseur : il amplifie les bonnes pratiques, mais ne les crée pas." }, { "type": "quote", "text": "🚀 <strong>AirSaaS</strong> est l'outil de gestion de portefeuille de projets conçu pour les DSI, PMO et directeurs de transformation qui veulent allier simplicité et efficacité. Tableau de bord visuel, rapport flash automatique, intégrations natives et collaboration temps réel. <a href=\"/fr/solution/management-de-portefeuille-projet\">Découvrir AirSaas→</a>" }, { "type": "heading", "level": 2, "id": "les-erreurs-a-eviter-en-gestion-de-portefeuille-de-projets", "text": "Les erreurs à éviter en gestion de portefeuille de projets" }, { "type": "paragraph", "html": "Après des centaines d'échanges avec des DSI, PMO et directeurs de transformation, voici les erreurs les plus fréquentes que nous observons." }, { "type": "heading", "level": 3, "id": "erreur-n1-confondre-gestion-de-portefeuille-et-gestion-de-projet", "text": "Erreur n°1 — Confondre gestion de portefeuille et gestion de projet" }, { "type": "paragraph", "html": "Le portefeuille ne sert pas à micro-manager les tâches de chaque projet. Il sert à prendre des décisions stratégiques : quels projets lancer, arrêter, accélérer ou reporter. Mélanger les niveaux crée de la confusion et alourdit la gouvernance." }, { "type": "heading", "level": 3, "id": "erreur-n2-ne-pas-oser-arreter-un-projet", "text": "Erreur n°2 — Ne pas oser arrêter un projet" }, { "type": "paragraph", "html": "Un portefeuille qui ne \"tue\" jamais de projet est un portefeuille malade. Si un projet ne crée plus de valeur, a vu son contexte changer ou mobilise des ressources critiques, il faut savoir le stopper. C'est un signe de maturité, pas d'échec." }, { "type": "heading", "level": 3, "id": "erreur-n3-sous-estimer-la-gestion-de-la-capacite", "text": "Erreur n°3 — Sous-estimer la gestion de la capacité" }, { "type": "paragraph", "html": "Valider 20 projets quand on a la capacité d'en mener 8 correctement, c'est la recette de l'échec collectif. Et la capacité ne se gère pas \"au global\" — elle se gère <strong>équipe par équipe, trimestre par trimestre</strong>. Une organisation peut avoir du budget disponible et des ressources \"sur le papier\", mais si l'équipe Data est saturée au Q2, aucun projet Data ne délivrera. L'incapacité chronique à dire \"non\" est le symptôme le plus répandu des organisations immatures en PPM. La gestion de portefeuille de projets impose de confronter la demande à la réalité de la capacité de chaque équipe — et d'assumer les arbitrages qui en découlent." }, { "type": "heading", "level": 3, "id": "erreur-n4-se-fier-au-pourcentage-davancement", "text": "Erreur n°4 — Se fier au pourcentage d'avancement" }, { "type": "paragraph", "html": "Le % d'avancement est l'un des indicateurs les plus trompeurs du pilotage de portefeuille. Un projet affiché à 70 % peut être à des mois de livrer le moindre délivrable exploitable. Ce chiffre mesure le plus souvent la <strong>consommation de charge</strong> (combien de jours ont été passés) et non la <strong>proximité d'un résultat tangible</strong>. Les organisations matures en PPM remplacent le % d'avancement par des indicateurs concrets : jalons atteints, délivrables acceptés, fonctionnalités livrées en production. La question à poser en revue de portefeuille n'est jamais \"à combien de % en est-on ?\", mais <strong>\"qu'est-ce qui sera livré et utilisable à la fin du trimestre ?\"</strong>" }, { "type": "heading", "level": 3, "id": "erreur-n5-un-reporting-heterogene-et-chronophage", "text": "Erreur n°5 — Un reporting hétérogène et chronophage" }, { "type": "paragraph", "html": "Si chaque chef de projet produit son reporting dans un format différent, à une fréquence aléatoire, le Comité de pilotage ne pourra jamais avoir une vision claire du portefeuille. Standardisez le format, automatisez la collecte, fixez un rythme régulier." }, { "type": "heading", "level": 3, "id": "erreur-n6-lancer-la-demarche-sans-sponsorship", "text": "Erreur n°6 — Lancer la démarche sans sponsorship" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets touche aux budgets, aux priorités et parfois aux jeux de pouvoir. Sans sponsor au niveau Direction Générale ou DSI, la démarche s'essouffle dès les premiers arbitrages difficiles." }, { "type": "heading", "level": 3, "id": "erreur-n7-vouloir-tout-faire-dun-coup", "text": "Erreur n°7 — Vouloir tout faire d'un coup" }, { "type": "paragraph", "html": "Privilégiez une approche progressive : démarrez sur un périmètre limité, avec des rituels simples et un petit nombre de projets pilotes. Montrez les premiers résultats, puis étendez. L'adoption se fait par la preuve, pas par le décret." }, { "type": "heading", "level": 2, "id": "faq-gestion-de-portefeuille-de-projets", "text": "FAQ — Gestion de portefeuille de projets" }, { "type": "heading", "level": 3, "id": "quest-ce-quun-portefeuille-de-projets", "text": "Qu'est-ce qu'un portefeuille de projets ?" }, { "type": "paragraph", "html": "Un portefeuille de projets est l'ensemble des projets, programmes et opérations d'une organisation, gérés collectivement pour atteindre les objectifs stratégiques. Wikipédia le définit comme <em>\"la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage\"</em> (Fernez-Walch, 2004)." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-gestion-de-portefeuille-de-projets-et-gestion-multi-projets", "text": "Quelle est la différence entre gestion de portefeuille de projets et gestion multi-projets ?" }, { "type": "paragraph", "html": "La <strong>gestion multi-projets</strong> est opérationnelle : elle vise à gérer efficacement plusieurs projets en parallèle (planning, ressources, dépendances). La <strong>gestion de portefeuille</strong> est stratégique : elle décide quels projets lancer et dans quel ordre, en fonction de leur contribution à la stratégie. En résumé, le multi-projet s'occupe du \"comment\", le portefeuille s'occupe du \"quoi\"." }, { "type": "heading", "level": 3, "id": "qui-est-responsable-de-la-gestion-du-portefeuille-de-projets", "text": "Qui est responsable de la gestion du portefeuille de projets ?" }, { "type": "paragraph", "html": "En général, c'est le <strong>PMO</strong> (Project Management Office), le <strong>DSI</strong> ou le <strong>Directeur de transformation</strong> qui pilote la gestion de portefeuille. Mais les décisions d'arbitrage impliquent la Direction Générale et les directions métiers. La gestion de portefeuille de projets est par nature transverse et collaborative." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-un-outil-ppm-et-un-outil-de-gestion-de-projet", "text": "Quelle est la différence entre un outil PPM et un outil de gestion de projet ?" }, { "type": "paragraph", "html": "Un <strong>outil de gestion de projet</strong> (Jira, Asana, Monday, Trello) permet de gérer les tâches, le planning et les ressources d'un projet individuel. Un <strong>outil PPM</strong> permet de piloter l'ensemble du portefeuille : vue consolidée, arbitrages, reporting stratégique, alignement avec les objectifs. Les deux sont complémentaires et doivent idéalement être connectés." }, { "type": "heading", "level": 3, "id": "la-gestion-de-portefeuille-de-projets-est-elle-adaptee-aux-pme", "text": "La gestion de portefeuille de projets est-elle adaptée aux PME ?" }, { "type": "paragraph", "html": "Absolument. La taille de l'entreprise ne détermine pas le besoin, c'est le nombre de projets en concurrence pour les mêmes ressources qui compte. Dès qu'une PME gère plus de 5-10 projets transverses en parallèle, une démarche de portefeuille — même légère — apporte une valeur considérable. Les PME ont d'ailleurs souvent plus d'agilité pour la mettre en œuvre." }, { "type": "heading", "level": 3, "id": "a-quelle-frequence-faut-il-reprioriser-son-portefeuille-de-projets", "text": "À quelle fréquence faut-il reprioriser son portefeuille de projets ?" }, { "type": "paragraph", "html": "La priorisation en continu est devenue la pratique dominante. La plupart des organisations matures réalisent une revue de portefeuille formelle chaque mois, avec des points d'arbitrage ponctuels si le contexte l'exige. Les roadmaps figées à 2-3 ans ont laissé place à un pilotage agile et adaptatif." }, { "type": "heading", "level": 3, "id": "quels-sont-les-principaux-frameworks-pour-la-gestion-de-portefeuille-de-projets", "text": "Quels sont les principaux frameworks pour la gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "Les frameworks les plus reconnus sont : le <strong>Standard for Portfolio Management du PMI</strong>, <strong>MoP (Management of Portfolios)</strong> de AXELOS, le <strong>Lean Portfolio Management (LPM)</strong> du framework SAFe, et les approches inspirées du <strong>OKR</strong> (Objectives and Key Results). Le choix dépend de la culture et de la maturité de votre organisation." }, { "type": "heading", "level": 2, "id": "pour-aller-plus-loin", "text": "Pour aller plus loin" }, { "type": "list", "ordered": false, "items": ["<a href=\"/fr/gestion-de-projet/lean-portfolio-management\">Lean Portfolio Management : aligner direction générale, IT et métiers</a>", "<a href=\"/fr/solution/revue-de-portefeuille\">Revue de portefeuille : bonnes pratiques et guide complet</a>", "<a href=\"/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet\">Les 10 erreurs à ne pas commettre dans la mise en place d'un portefeuille projet</a>", "<a href=\"/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme\">Gestion de portefeuille de projets en PME : bénéfices et bonnes pratiques</a>", "<a href=\"/fr/guide/cahier-des-charges-logiciel-ppm\">Outil PPM : le cahier des charges pour bien choisir</a>", "<a href=\"/fr/solution/management-de-portefeuille-projet\">Découvrir AirSaaS, l'outil PPM des DSI et PMO</a>"] }, { "type": "insight-callout", "label": "À retenir", "html": "📌 <strong>À retenir :</strong> Le portefeuille n'est pas \"au-dessus\" du projet et du programme dans une pyramide. C'est une <strong>grille de lecture</strong> qui permet de comparer, arbitrer et allouer les ressources entre des projets qui se disputent la même capacité. Il peut exister autant de vues portefeuille que de besoins de décision dans l'organisation." }, { "type": "insight-callout", "label": "Idée reçue", "html": "🏢 <strong>Idée reçue :</strong> \"La gestion de portefeuille de projets est réservée aux grandes entreprises.\" <strong>Faux.</strong> Les PME et ETI peuvent parfois en tirer encore plus de bénéfices, car elles ont plus d'agilité et la capacité de mettre en œuvre la démarche plus rapidement. L'enjeu est d'adapter le niveau de formalisme à la taille de l'organisation." }], "toc": [{ "href": "#pour-aller-plus-loin", "label": "Pour aller plus loin", "level": 2 }, { "href": "#portefeuille-de-projets-vs-programme-vs-projet-quelles-differences", "label": "Portefeuille de projets vs programme vs projet : quelles différences ?", "level": 2 }, { "href": "#pourquoi-mettre-en-place-une-gestion-de-portefeuille-de-projets", "label": "Pourquoi mettre en place une gestion de portefeuille de projets ?", "level": 2 }, { "href": "#les-7-etapes-pour-deployer-une-gestion-de-portefeuille-de-projets-efficace", "label": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace", "level": 2 }, { "href": "#les-methodes-de-priorisation-dun-portefeuille-de-projets", "label": "Les méthodes de priorisation d'un portefeuille de projets", "level": 2 }, { "href": "#les-kpis-essentiels-du-pilotage-de-portefeuille", "label": "Les KPIs essentiels du pilotage de portefeuille", "level": 2 }, { "href": "#comment-choisir-son-outil-ppm", "label": "Comment choisir son outil PPM ?", "level": 2 }, { "href": "#les-erreurs-a-eviter-en-gestion-de-portefeuille-de-projets", "label": "Les erreurs à éviter en gestion de portefeuille de projets", "level": 2 }, { "href": "#faq-gestion-de-portefeuille-de-projets", "label": "FAQ — Gestion de portefeuille de projets", "level": 2 }], "faq": [{ "question": "Qu'est-ce qu'un portefeuille de projets ?", "answer": "Un portefeuille de projets est l'ensemble des projets, programmes et opérations d'une organisation, gérés collectivement pour atteindre les objectifs stratégiques. Wikipédia le définit comme \"la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage\" (Fernez-Walch, 2004)." }, { "question": "Quelle est la différence entre gestion de portefeuille de projets et gestion multi-projets ?", "answer": "La gestion multi-projets est opérationnelle : elle vise à gérer efficacement plusieurs projets en parallèle (planning, ressources, dépendances). La gestion de portefeuille est stratégique : elle décide quels projets lancer et dans quel ordre, en fonction de leur contribution à la stratégie. En résumé, le multi-projet s'occupe du \"comment\", le portefeuille s'occupe du \"quoi\"." }, { "question": "Qui est responsable de la gestion du portefeuille de projets ?", "answer": "En général, c'est le PMO (Project Management Office), le DSI ou le Directeur de transformation qui pilote la gestion de portefeuille. Mais les décisions d'arbitrage impliquent la Direction Générale et les directions métiers. La gestion de portefeuille de projets est par nature transverse et collaborative." }, { "question": "Quelle est la différence entre un outil PPM et un outil de gestion de projet ?", "answer": "Un outil de gestion de projet (Jira, Asana, Monday, Trello) permet de gérer les tâches, le planning et les ressources d'un projet individuel. Un outil PPM permet de piloter l'ensemble du portefeuille : vue consolidée, arbitrages, reporting stratégique, alignement avec les objectifs. Les deux sont complémentaires et doivent idéalement être connectés." }, { "question": "La gestion de portefeuille de projets est-elle adaptée aux PME ?", "answer": "Absolument. La taille de l'entreprise ne détermine pas le besoin, c'est le nombre de projets en concurrence pour les mêmes ressources qui compte. Dès qu'une PME gère plus de 5-10 projets transverses en parallèle, une démarche de portefeuille — même légère — apporte une valeur considérable. Les PME ont d'ailleurs souvent plus d'agilité pour la mettre en œuvre." }, { "question": "À quelle fréquence faut-il reprioriser son portefeuille de projets ?", "answer": "La priorisation en continu est devenue la pratique dominante. La plupart des organisations matures réalisent une revue de portefeuille formelle chaque mois, avec des points d'arbitrage ponctuels si le contexte l'exige. Les roadmaps figées à 2-3 ans ont laissé place à un pilotage agile et adaptatif." }, { "question": "Quels sont les principaux frameworks pour la gestion de portefeuille de projets ?", "answer": "Les frameworks les plus reconnus sont : le Standard for Portfolio Management du PMI, MoP (Management of Portfolios) de AXELOS, le Lean Portfolio Management (LPM) du framework SAFe, et les approches inspirées du OKR (Objectives and Key Results). Le choix dépend de la culture et de la maturité de votre organisation." }], "related": [{ "href": "/fr/gestion-de-projet/lean-portfolio-management", "label": "Lean Portfolio Management : aligner direction générale, IT et métiers" }, { "href": "/fr/solution/revue-de-portefeuille", "label": "Revue de portefeuille : bonnes pratiques et guide complet" }, { "href": "/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet", "label": "Les 10 erreurs à ne pas commettre dans la mise en place d'un portefeuille projet" }, { "href": "/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme", "label": "Gestion de portefeuille de projets en PME : bénéfices et bonnes pratiques" }, { "href": "/fr/guide/cahier-des-charges-logiciel-ppm", "label": "Outil PPM : le cahier des charges pour bien choisir" }, { "href": "/fr/solution/management-de-portefeuille-projet", "label": "Découvrir AirSaaS, l'outil PPM des DSI et PMO" }] }, { "slug": "metier-pmo", "skip": false, "meta": { "title": "PMO (Project Management Office) : le guide complet pour comprendre et mettre en place ce rôle clé", "h1": "PMO (Project Management Office) : le guide complet pour comprendre et mettre en place ce rôle clé", "description": "Le PMO est devenu incontournable dans les organisations qui gèrent plusieurs projets en parallèle. Ce guide te donne les clés pour comprendre ce rôle, son positionnement, et comment le mettre en place efficacement.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/69a00523cadcb7d104aaae86_PMO.jpg", "alt": "" }, "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "25/2/2026", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "publishedDate": "25/2/2026" }, "blocks": [{ "type": "paragraph", "text": "Le PMO est devenu incontournable dans les organisations qui gèrent plusieurs projets en parallèle. Pourtant, c'est un métier souvent mal compris : ni chef de projet, ni contrôleur, ni secrétaire de direction. Alors c'est quoi, concrètement, un PMO ? Ce guide te donne les clés pour comprendre ce rôle, son positionnement, et comment le mettre en place efficacement." }, { "type": "heading", "level": 2, "id": "pmo-definition-et-signification", "text": "PMO : définition et signification" }, { "type": "paragraph", "text": "<strong>PMO</strong> signifie <strong>Project Management Office</strong>, soit « Bureau de gestion de projets » en français. C'est une fonction (ou une équipe) qui structure la gouvernance du portefeuille de projets d'une organisation." }, { "type": "quote", "text": "<strong>En une phrase : </strong>le PMO est la personne (ou l'équipe) qui s'assure que les bons projets sont lancés, avec les bonnes méthodes, et que la direction a une visibilité claire sur l'avancement global." }, { "type": "paragraph", "text": "Contrairement à ce que le terme « bureau » suggère, le PMO n'est pas un lieu physique. C'est une fonction rattachée à la direction — DSI, direction de la transformation, ou direction générale — qui orchestre la gestion de projets à l'échelle de l'entreprise." }, { "type": "paragraph", "text": "Le PMO intervient sur trois niveaux :" }, { "type": "heading", "level": 3, "id": "1-la-methode", "text": "1 • La méthode" }, { "type": "paragraph", "text": "Harmoniser les pratiques de gestion de projet entre les équipes. Tout le monde parle le même langage." }, { "type": "heading", "level": 3, "id": "2-la-gouvernance", "text": "2 • La gouvernance" }, { "type": "paragraph", "text": "Structurer les instances de décision (comités de pilotage, revues de portefeuille) pour que le Comex puisse arbitrer avec des données fiables." }, { "type": "heading", "level": 3, "id": "3-laccompagnement", "text": "3 • L'accompagnement" }, { "type": "paragraph", "text": "Faire monter les équipes en compétences projet. Le PMO forme, outille et facilite — il n'exécute pas à la place des équipes." }, { "type": "paragraph", "text": "En France, environ 70% des projets de transformation échouent ou dérapent significativement. Le PMO est la réponse structurelle à ce problème : plutôt que d'empiler des projets en espérant que ça passe, tu mets en place une gouvernance qui garantit l'alignement stratégique et l'allocation optimale des ressources." }, { "type": "paragraph", "text": "C'est aussi un métier en pleine expansion. La multiplication des projets transverses, la transformation digitale et le besoin de piloter par la valeur rendent le PMO indispensable — que ce soit en ETI, grand compte ou secteur public." }, { "type": "heading", "level": 2, "id": "lexplosion-du-nombre-de-projets-transverses", "text": "L'explosion du nombre de projets transverses" }, { "type": "paragraph", "text": "L'accélération de l'innovation a créé une prolifération de projets transverses et de transformation digitale. Les entreprises font face à des défis structurels et culturels pour gérer ces initiatives tout en maintenant les priorités opérationnelles." }, { "type": "quote", "text": "<em>\"90% des projets sont transverses. La transformation, structurellement nécessaire à l'avenir de l'entreprise, déstabilise l'organisation à court terme.\"</em>", "author": "Bertran Ruiz, CEO AirSaas" }, { "type": "paragraph", "text": "Les impacts sont concrets : les collaborateurs clés jonglent entre plusieurs projets en « best effort », les profils exigeants sont difficiles à recruter, l'adoption technologique pêche, et la collaboration inter-services dysfonctionne." }, { "type": "heading", "level": 3, "id": "la-techno-accessible", "text": "La techno accessible" }, { "type": "paragraph", "text": "Les technologies modernes ont atteint la maturité et l'accessibilité. La pression concurrentielle ne porte plus sur le « est-ce que la techno marche ? » mais sur le « comment l'adopter efficacement ? ». Cette profusion de solutions génère mécaniquement un nombre croissant de projets potentiels." }, { "type": "heading", "level": 3, "id": "les-collaborateurs-veulent-la-meme-techno-au-bureau-que-dans-leur-vie-perso", "text": "Les collaborateurs veulent la même techno au bureau que dans leur vie perso" }, { "type": "paragraph", "text": "Les collaborateurs, de plus en plus « tech-savvy » dans leur vie personnelle, attendent des outils professionnels à la hauteur. Si cette familiarité devrait faciliter l'adoption, la vraie barrière reste la conduite du changement, pas la technologie elle-même." }, { "type": "heading", "level": 3, "id": "lechec-des-projets-en-silos", "text": "L'échec des projets en silos" }, { "type": "paragraph", "text": "Un département seul ne peut pas transformer l'entreprise. 90% des projets de transformation ont une dimension digitale. L'exécution isolée crée du gaspillage de ressources, des doublons, et l'absence de partage de connaissances inter-services. Les projets sont abandonnés en phase d'industrialisation faute d'avoir consulté les parties prenantes suffisamment tôt." }, { "type": "heading", "level": 2, "id": "lechec-du-pmo-controle", "text": "L'échec du PMO contrôle" }, { "type": "heading", "level": 3, "id": "lopposition-des-chefs-de-projets", "text": "L'opposition des chefs de projets" }, { "type": "paragraph", "text": "Les PMO positionnés comme des entités de contrôle et d'inspection génèrent de la résistance. Sans autorité hiérarchique sur les chefs de projet, cette approche top-down décourage l'engagement plutôt qu'elle ne le stimule." }, { "type": "heading", "level": 3, "id": "le-cout-dun-passe-plats", "text": "Le coût d'un passe-plats" }, { "type": "paragraph", "text": "Les PMO traditionnels consomment des budgets significatifs (surtout en consultants externes) sur des activités à faible valeur ajoutée : relance des tâches, collecte d'informations, mise en forme de reportings. Cette surcharge administrative ne tire pas parti de la connaissance du PMO pour faire progresser les équipes." }, { "type": "heading", "level": 3, "id": "controle-vs-aider-a-faire", "text": "Contrôle vs aider à faire" }, { "type": "paragraph", "text": "Ajouter des mécanismes de contrôle contredit les objectifs d'engagement pour des contributeurs en « best effort ». Plutôt que de surveiller chaque tâche, le PMO doit simplifier le reporting et le formalisme, permettre aux équipes de se concentrer sur le fond du projet, et motiver la participation en réduisant les contraintes." }, { "type": "quote", "text": "<em>\"La plupart des participants à la transformation sont en mode « best effort ». Exiger plus de contrôle est contre-productif. La solution : maximiser l'engagement des collaborateurs autour de la transformation. « Les diagrammes de Gantt rassurent, mais ce sont les équipes qui livrent. » Sans engagement, pas de transformation.\"</em>", "author": "Bertran Ruiz, CEO AirSaas" }, { "type": "heading", "level": 2, "id": "le-nouveau-role-du-metier-de-pmo", "text": "Le nouveau rôle du métier de PMO" }, { "type": "paragraph", "text": "Le rôle du PMO a évolué du contrôle d'exécution vers l'instauration d'une <strong>culture projet alignée sur les besoins de l'entreprise</strong>, créant une vision transverse au-delà des silos." }, { "type": "quote", "text": "<em>\"Le rôle a évolué de l'assurance projet et des fonctions de secrétariat vers l'accompagnement méthodologique et le support à la vision d'avenir au niveau des directions.\"</em>", "author": "Alexandre Franchino, PMO, Efi Automotive" }, { "type": "heading", "level": 3, "id": "benefices-attendus", "text": "Bénéfices attendus" }, { "type": "list", "ordered": false, "items": ["✅ Développement continu des capacités", "✅ Efficacité opérationnelle accrue", "✅ Capacité de transformation renforcée", "✅ Harmonisation des processus et optimisation des ressources"] }, { "type": "heading", "level": 3, "id": "la-posture", "text": "La posture" }, { "type": "heading", "level": 4, "id": "leadership", "text": "Leadership" }, { "type": "paragraph", "text": "Fort de sa visibilité sur le portefeuille, le PMO doit accompagner proactivement les collaborateurs — pas uniquement reporter vers le haut. Le rôle du PMO : faire grandir l'organisation." }, { "type": "heading", "level": 4, "id": "se-positionner-efficacement", "text": "Se positionner efficacement" }, { "type": "paragraph", "text": "Le positionnement idéal du PMO se fait au sein de l'entité projet transverse la plus mature de l'entreprise. Cela garantit crédibilité et rapidité fonctionnelle sans nécessiter de restructuration majeure." }, { "type": "heading", "level": 4, "id": "eviter-les-conflits-dego", "text": "Éviter les conflits d'ego" }, { "type": "paragraph", "text": "Le PMO qui réussit fait preuve d'empathie, d'anticipation, de pédagogie et de diplomatie. Il navigue entre les services avec respect et sait cadrer les désaccords de manière inclusive." }, { "type": "heading", "level": 4, "id": "ne-pas-se-positionner-en-expert", "text": "Ne pas se positionner en « expert »" }, { "type": "paragraph", "text": "Évite la posture du « je vais t'expliquer ton métier ». Le PMO fonctionne comme un <strong>facilitateur de solutions</strong>, pas une barrière. Adopte une culture produit : les utilisateurs (tes partenaires métier) détiennent la vérité." }, { "type": "heading", "level": 4, "id": "devenir-un-enabler", "text": "Devenir un « enabler »" }, { "type": "paragraph", "text": "Réduis les processus lourds tout en maintenant le contrôle stratégique. Soutiens les projets transverses avec des environnements procéduraux légers, des approches agiles inspirées des startups, et un modèle de partenariat métier." }, { "type": "heading", "level": 3, "id": "ses-methodologies", "text": "Ses méthodologies" }, { "type": "heading", "level": 4, "id": "optimiser-le-best-effort", "text": "Optimiser le best effort" }, { "type": "paragraph", "text": "L'enjeu central : organiser du temps dédié pour les contributeurs transverses tout en mettant en place des workflows asynchrones qui réduisent les réunions en cascade et les barrières d'accès à l'information. Crée de l'engagement positif en valorisant l'impact, en réduisant les charges de reporting sans valeur, et en célébrant les succès." }, { "type": "heading", "level": 4, "id": "penser-ppm-ppt-et-srr", "text": "Penser PPM, PPT et SRR" }, { "type": "paragraph", "text": "<strong>PPM (Portfolio Project Management)</strong> : Orchestrer et prioriser les projets en examinant risque/retour, budgets, délais et bénéfices attendus. Les groupes de gouvernance évaluent le ROI et l'alignement stratégique." }, { "type": "paragraph", "text": "<strong>PPT (People-Process-Tools)</strong> : Le « triangle d'or » qui optimise les relations collaborateur-processus-outil. L'équilibre entre capacité humaine, efficacité des workflows et technologie habilitante." }, { "type": "paragraph", "text": "<strong>SRR (Sense-Role-Ritual)</strong> : <em>Sense</em> — les collaborateurs trouvent du sens en comprenant l'impact et l'importance stratégique. <em>Role</em> — des définitions claires de responsabilités standardisées entre les projets. <em>Ritual</em> — une communication soutenue horizontalement et verticalement tout au long du cycle de vie des projets." }, { "type": "heading", "level": 3, "id": "les-outils-et-ressources-cles", "text": "Les outils et ressources clés" }, { "type": "heading", "level": 4, "id": "gestion-de-projet", "text": "Gestion de projet" }, { "type": "paragraph", "text": "Évite d'imposer un outil unique de gestion de projet à toute l'entreprise. Les fonctions différentes nécessitent des outils différents (marketing vs développement). Les équipes transverses bénéficient d'outils collaboratifs adaptés à leurs besoins spécifiques." }, { "type": "heading", "level": 4, "id": "gestion-de-portefeuille", "text": "Gestion de portefeuille" }, { "type": "paragraph", "text": "La standardisation s'applique au niveau de la gouvernance du portefeuille. La prise de décision rapide exige une accessibilité cohérente de l'information et une fréquence de présentation régulière. L'automatisation alimente les outils projet individuels vers des interfaces macro de <a href=\"/fr/gestion-de-projet/management-de-portefeuille-de-projet\"><strong>gestion de portefeuille</strong></a> axées sur l'information décisionnelle." }, { "type": "heading", "level": 4, "id": "ressources", "text": "Ressources" }, { "type": "paragraph", "text": "La stratégie combine l'allocation de temps pour les talents clés (10-20% d'implication initiale), l'automatisation des processus libérant de la capacité, le staffing d'experts, la diffusion culturelle progressive, et l'engagement de l'exécutif sur la priorité stratégique." }, { "type": "heading", "level": 3, "id": "les-perspectives-du-metier", "text": "Les perspectives du métier" }, { "type": "paragraph", "text": "Les PMO influencent de plus en plus la transformation et la culture projet à travers le contact multi-directions et la participation aux décisions stratégiques. Les leaders PMO démontrant des capacités de management transverse et d'impact sur le changement accèdent fréquemment à des postes de management et de direction." }, { "type": "heading", "level": 2, "id": "quelles-differences-entre-chef-de-projet-et-pmo", "text": "Quelles différences entre chef de projet et PMO ?" }, { "type": "paragraph", "text": "La confusion est fréquente, et pourtant les deux rôles sont fondamentalement différents. Le chef de projet est dans l'exécution d'un projet spécifique. Le PMO prend de la hauteur pour orchestrer le portefeuille dans son ensemble." }, { "type": "table", "headers": ["Critère", "Chef de projet", "PMO"], "rows": [["Périmètre", "1 projet (du cadrage au bilan)", "Le portefeuille de projets (tous les projets)"], ["Focus", "Livrer dans le temps, le budget, le périmètre", "Aligner les projets sur la stratégie de l'entreprise"], ["Rattachement", "Direction métier ou technique", "Direction générale, DSI ou direction de la transformation"], ["Livrables", "Planning, suivi d'avancement, bilan", "Méthodes, reporting portefeuille, gouvernance"], ["Posture", "Exécution et coordination", "Orchestration et facilitation"], ["Compétences clés", "Technique, gestion d'équipe, rigueur", "Vision transverse, diplomatie, conduite du changement"]] }, { "type": "paragraph", "text": "Les deux rôles ne sont pas en compétition : ils sont complémentaires. Les organisations qui réussissent ont des chefs de projet solides ET un PMO qui les aide à travailler de manière harmonisée. Le PMO ne prend pas la place du chef de projet — il le rend meilleur." }, { "type": "quote", "text": "<strong>L'essentiel : le chef de projet gère le « comment » d'un projet. Le PMO gère le « quoi » et le « pourquoi » du portefeuille. Les deux sont nécessaires.</strong>" }, { "type": "paragraph", "text": "<a href=\"/fr/gestion-de-projet/chef-de-projet-pmo\">Lire le guide complet : différences entre chef de projet et PMO →</a>" }, { "type": "heading", "level": 2, "id": "quel-est-le-role-du-pmo-vis-a-vis-du-codir", "text": "Quel est le rôle du PMO vis-à-vis du Codir ?" }, { "type": "paragraph", "text": "Le PMO est l'interface entre la réalité opérationnelle des projets et le besoin de décision du Codir. C'est un positionnement délicat : trop proche de la direction, il passe pour un contrôleur déconnecté du terrain. Trop proche des équipes, il ne remonte plus l'information stratégique." }, { "type": "paragraph", "text": "Trois postures à éviter absolument :" }, { "type": "list", "ordered": false, "items": ["❌ <strong>Le passe-plats</strong> <br>Le PMO relaie l'information sans l'analyser. Valeur ajoutée minimale. Le Codir ne sait pas quoi décider.", "❌ <strong>Le Codir-focused</strong> <br>Le PMO ne regarde que vers le haut. Les équipes le perçoivent comme un micro-manager déconnecté du terrain.", "❌ <strong>Le projet-focused</strong> <br>Le PMO reste dans l'opérationnel. La direction manque d'information consolidée pour arbitrer."] }, { "type": "paragraph", "text": "La bonne posture ? Le PMO comme <strong>facilitateur neutre et de confiance</strong>. Il traduit la réalité terrain en indicateurs actionnables pour le Codir, et il traduit les décisions stratégiques en cadre opérationnel pour les équipes." }, { "type": "paragraph", "text": "La métrique clé du PMO vis-à-vis du Codir : la <strong>vélocité de décision</strong>. À quelle vitesse le Codir peut-il agir sur la base des informations que le PMO fournit ? Si le reporting arrive trop tard, trop complexe ou trop vague, le PMO a raté sa cible." }, { "type": "quote", "text": "<strong>La relation avec le sponsor (membre du Codir) est déterminante. Un PMO sans sponsor influent est un PMO sans impact. Assure-toi d'avoir une communication solide, des responsabilités claires et une collaboration active avec ton sponsor.</strong>" }, { "type": "paragraph", "text": "<a href=\"/fr/gestion-de-projet/role-du-pmo\">Lire le guide complet : rôle du PMO vis-à-vis du Codir →</a>" }, { "type": "heading", "level": 2, "id": "pourquoi-mettre-en-place-un-pmo", "text": "Pourquoi mettre en place un PMO ?" }, { "type": "paragraph", "text": "La question n'est pas « faut-il un PMO ? » mais « à partir de quand ça devient indispensable ? ». La réponse est simple : dès que ton organisation gère plus de <strong>400 à 500K€ de projets transverses ou de transformation</strong>." }, { "type": "paragraph", "text": "À ce stade, les symptômes sont généralement les mêmes :" }, { "type": "list", "ordered": true, "items": ["Les projets se multiplient mais personne n'a la vision consolidée", "Les ressources sont disputées entre services sans arbitrage clair", "Les collaborateurs sont en « best effort » et commencent à craquer", "Le Comex n'a pas de visibilité fiable sur l'avancement réel", "Chaque département a sa propre méthode de gestion de projet"] }, { "type": "paragraph", "text": "Le retour sur investissement d'un PMO représente typiquement <strong>10 à 20% de la valeur du portefeuille</strong> — récupéré via les gains de temps, la réduction des échecs de projets et la meilleure allocation des ressources. Sans PMO, tu continues de dépenser plus pour livrer moins." }, { "type": "quote", "text": "<strong>Insight clé : les organisations plus petites bénéficient souvent davantage d'un PMO, car la culture s'enracine plus vite avant que les mauvaises habitudes ne se cristallisent.</strong>" }, { "type": "paragraph", "text": "<a href=\"/fr/gestion-de-projet/pourquoi-mettre-en-place-un-pmo\">Lire le guide complet : pourquoi mettre en place un PMO →</a>" }, { "type": "heading", "level": 2, "id": "comment-mettre-en-place-un-pmo-les-etapes-cles", "text": "Comment mettre en place un PMO : les étapes clés" }, { "type": "paragraph", "text": "Mettre en place un PMO, ce n'est pas recruter quelqu'un et lui donner un titre. C'est un projet stratégique en soi, qui nécessite un positionnement réfléchi et un sponsor solide." }, { "type": "heading", "level": 3, "id": "1-evalue-les-besoins", "text": "1 • Évalue les besoins" }, { "type": "paragraph", "text": "Quelle est la maturité projet de ton organisation ? Combien de projets transverses sont en cours ? Quels sont les principaux points de douleur (visibilité, priorisation, méthode) ?" }, { "type": "heading", "level": 3, "id": "2-trouve-un-sponsor-influent", "text": "2 • Trouve un sponsor influent" }, { "type": "paragraph", "text": "Le PMO a besoin d'un sponsor au Codir qui porte le sujet et lui donne la légitimité d'agir. Sans ce sponsor, le PMO sera perçu comme une initiative isolée sans poids politique." }, { "type": "heading", "level": 3, "id": "3-positionne-le-au-bon-endroit", "text": "3 • Positionne-le au bon endroit" }, { "type": "paragraph", "text": "Rattache le PMO à la direction la plus mature en transverse (souvent la DSI). Il doit avoir la proximité avec le comité exécutif et l'autorité pour challenger les parties prenantes quand nécessaire." }, { "type": "heading", "level": 3, "id": "4-recrute-le-bon-profil", "text": "4 • Recrute le bon profil" }, { "type": "paragraph", "text": "Cherche un profil avec de l'expérience en transformation transverse, des compétences de communication et de collaboration, un esprit de pédagogue. Le PMO idéal inspire plutôt qu'il n'impose." }, { "type": "heading", "level": 3, "id": "5-delivre-des-quick-wins", "text": "5 • Délivre des quick wins" }, { "type": "paragraph", "text": "Avant de restructurer la gouvernance complète, prouve ta valeur avec des victoires rapides et visibles : un tableau de bord consolidé, un premier cycle de priorisation, une simplification du reporting. La crédibilité se construit sur les résultats concrets, pas sur les processus." }, { "type": "quote", "text": "<strong>Le piège classique : vouloir tout structurer d'entrée. Un PMO qui démarre par un framework de 200 pages sera rejeté avant d'avoir fait quoi que ce soit. Commence léger, livre vite, itère.</strong>" }, { "type": "paragraph", "text": "<a href=\"/fr/gestion-de-projet/comment-mettre-en-place-un-pmo\">Lire le guide complet : étapes pour mettre en place un PMO →</a>" }, { "type": "heading", "level": 2, "id": "le-reporting-pmo-comment-le-reussir", "text": "Le reporting PMO : comment le réussir" }, { "type": "paragraph", "text": "Le reporting est souvent le premier sujet sur lequel le PMO est jugé — et le premier sur lequel il peut se planter. Le piège : transformer le reporting en exercice bureaucratique que personne ne lit. L'objectif : en faire un <strong>outil de décision</strong> que le Codir attend avec impatience." }, { "type": "paragraph", "text": "Trois principes pour un reporting PMO efficace :" }, { "type": "heading", "level": 3, "id": "1-hebdo-greater-mensuel", "text": "1 • Hebdo > Mensuel" }, { "type": "paragraph", "text": "Un reporting hebdomadaire léger (5 min par chef de projet) est infiniment plus utile qu'un reporting mensuel lourd (2-3 jours de collecte). La donnée fraîche permet de réagir, la donnée périmée sert de décoration." }, { "type": "heading", "level": 3, "id": "2-semi-automatise", "text": "2 • Semi-automatisé" }, { "type": "paragraph", "text": "Si le PMO passe ses journées à collecter des données, il ne fait pas son vrai métier. L'outil doit capturer les données à la source et les consolider automatiquement." }, { "type": "heading", "level": 3, "id": "3-adapte-a-laudience", "text": "3 • Adapté à l'audience" }, { "type": "paragraph", "text": "Le Codir n'a pas besoin du même niveau de détail que les chefs de projet. Segmente tes reportings par audience : synthèse exécutive pour le Codir, détail opérationnel pour les équipes." }, { "type": "quote", "text": "<strong>La règle AirSaas : « Si c'est plus complexe qu'Instagram, on a perdu. » Le reporting doit être lisible, exportable (PPT, PDF), et filtrable. Pare les données d'un contexte narratif pour faciliter l'interprétation.</strong>" }, { "type": "paragraph", "text": "<a href=\"/fr/gestion-de-projet/reporting-pmo\">Lire le guide complet : reporting PMO →</a>" }, { "type": "heading", "level": 2, "id": "faq-les-questions-frequentes-sur-le-pmo", "text": "FAQ : les questions fréquentes sur le PMO" }, { "type": "heading", "level": 3, "id": "pmo-cest-quoi", "text": "PMO, c'est quoi ?" }, { "type": "paragraph", "text": "Le PMO (Project Management Office) est une fonction qui structure et accompagne la gestion de portefeuille de projets dans une organisation. Il apporte méthodes, outils et gouvernance pour aider les équipes à livrer leurs projets. Ce n'est pas un contrôleur : c'est un facilitateur qui fait monter tout le monde en compétences." }, { "type": "heading", "level": 3, "id": "que-signifie-pmo", "text": "Que signifie PMO ?" }, { "type": "paragraph", "text": "PMO signifie Project Management Office, littéralement « Bureau de gestion de projets ». En France, on parle parfois de « bureau de projet » ou « direction de projet ». Mais le terme PMO s'est imposé car il décrit mieux la fonction : une entité dédiée à la gouvernance du portefeuille projets, pas juste un bureau physique." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-un-pmo-et-un-chef-de-projet", "text": "Quelle est la différence entre un PMO et un chef de projet ?" }, { "type": "paragraph", "text": "Le chef de projet gère un projet de A à Z (planning, budget, équipe, livrables). Le PMO prend de la hauteur : il pilote le portefeuille dans son ensemble, harmonise les méthodes, et aide les chefs de projet à réussir. Le chef de projet est dans l'exécution, le PMO est dans l'orchestration." }, { "type": "heading", "level": 3, "id": "quand-faut-il-mettre-en-place-un-pmo", "text": "Quand faut-il mettre en place un PMO ?" }, { "type": "paragraph", "text": "Dès que tu gères plus de 400-500K€ de projets transverses ou de transformation. Autres signaux : les projets s'enlisent au-delà de 18 mois, les ressources sont disputées entre services, ou le Comex n'a pas de visibilité consolidée. Si tu constates 2 de ces signaux, le PMO devient rentable." }, { "type": "heading", "level": 3, "id": "quel-est-le-salaire-dun-pmo-en-france", "text": "Quel est le salaire d'un PMO en France ?" }, { "type": "paragraph", "text": "En 2026, un PMO junior démarre entre 40 000 et 50 000€ brut annuel. Un PMO confirmé (5-10 ans) se situe entre 55 000 et 75 000€. Un Directeur PMO en ETI ou grand compte peut atteindre 80 000 à 120 000€. Les profils avec expérience transformation digitale sont les plus recherchés." }, { "type": "heading", "level": 3, "id": "le-pmo-est-il-un-metier-davenir", "text": "Le PMO est-il un métier d'avenir ?" }, { "type": "paragraph", "text": "Oui, et de plus en plus. La multiplication des projets transverses, la transformation digitale, et le besoin de piloter par la valeur rendent le PMO indispensable. Les organisations qui réussissent leur transformation ont toutes un PMO structuré. C'est aussi un tremplin vers des postes de direction." }], "toc": [{ "label": "L'explosion du nombre de projets transverses", "href": "#lexplosion-du-nombre-de-projets-transverses", "level": 2 }, { "label": "L'échec du PMO contrôle", "href": "#lechec-du-pmo-controle", "level": 2 }, { "label": "Le nouveau rôle du métier de PMO", "href": "#le-nouveau-role-du-metier-de-pmo", "level": 2 }, { "label": "Quelles différences entre chef de projet et PMO ?", "href": "#quelles-differences-entre-chef-de-projet-et-pmo", "level": 2 }, { "label": "Quel est le rôle du PMO vis-à-vis du Codir ?", "href": "#quel-est-le-role-du-pmo-vis-a-vis-du-codir", "level": 2 }, { "label": "Pourquoi mettre en place un PMO ?", "href": "#pourquoi-mettre-en-place-un-pmo", "level": 2 }, { "label": "Comment mettre en place un PMO : les étapes clés", "href": "#comment-mettre-en-place-un-pmo-les-etapes-cles", "level": 2 }, { "label": "Le reporting PMO : comment le réussir", "href": "#le-reporting-pmo-comment-le-reussir", "level": 2 }, { "label": "FAQ : les questions fréquentes sur le PMO", "href": "#faq-les-questions-frequentes-sur-le-pmo", "level": 2 }], "faq": [{ "question": "PMO, c'est quoi ?", "answer": "Le PMO (Project Management Office) est une fonction qui structure et accompagne la gestion de portefeuille de projets dans une organisation. Il apporte méthodes, outils et gouvernance pour aider les équipes à livrer leurs projets. Ce n'est pas un contrôleur : c'est un facilitateur qui fait monter tout le monde en compétences." }, { "question": "Que signifie PMO ?", "answer": "PMO signifie Project Management Office, littéralement « Bureau de gestion de projets ». En France, on parle parfois de « bureau de projet » ou « direction de projet ». Mais le terme PMO s'est imposé car il décrit mieux la fonction : une entité dédiée à la gouvernance du portefeuille projets, pas juste un bureau physique." }, { "question": "Quelle est la différence entre un PMO et un chef de projet ?", "answer": "Le chef de projet gère un projet de A à Z (planning, budget, équipe, livrables). Le PMO prend de la hauteur : il pilote le portefeuille dans son ensemble, harmonise les méthodes, et aide les chefs de projet à réussir. Le chef de projet est dans l'exécution, le PMO est dans l'orchestration." }, { "question": "Quand faut-il mettre en place un PMO ?", "answer": "Dès que tu gères plus de 400-500K€ de projets transverses ou de transformation. Autres signaux : les projets s'enlisent au-delà de 18 mois, les ressources sont disputées entre services, ou le Comex n'a pas de visibilité consolidée. Si tu constates 2 de ces signaux, le PMO devient rentable." }, { "question": "Quel est le salaire d'un PMO en France ?", "answer": "En 2026, un PMO junior démarre entre 40 000 et 50 000€ brut annuel. Un PMO confirmé (5-10 ans) se situe entre 55 000 et 75 000€. Un Directeur PMO en ETI ou grand compte peut atteindre 80 000 à 120 000€. Les profils avec expérience transformation digitale sont les plus recherchés." }, { "question": "Le PMO est-il un métier d'avenir ?", "answer": "Oui, et de plus en plus. La multiplication des projets transverses, la transformation digitale, et le besoin de piloter par la valeur rendent le PMO indispensable. Les organisations qui réussissent leur transformation ont toutes un PMO structuré. C'est aussi un tremplin vers des postes de direction." }], "related": [{ "label": "Chef de projet vs PMO : rôles et différences clés", "href": "/fr/gestion-de-projet/chef-de-projet-pmo" }, { "label": "Le rôle du PMO vis-à-vis du Codir et de la chefferie de projets", "href": "/fr/gestion-de-projet/role-du-pmo" }, { "label": "Pourquoi mettre en place un PMO dans votre organisation", "href": "/fr/gestion-de-projet/pourquoi-mettre-en-place-un-pmo" }, { "label": "Comment mettre en place un PMO : le guide étape par étape", "href": "/fr/gestion-de-projet/comment-mettre-en-place-un-pmo" }, { "label": "Reporting PMO : les clés d'un reporting projet efficace", "href": "/fr/gestion-de-projet/reporting-pmo" }] }, { "slug": "pi-planning", "skip": false, "meta": { "title": "PI Planning : le guide complet pour aligner vos équipes IT et métiers", "h1": "PI Planning : le guide complet pour aligner vos équipes IT et métiers", "description": "Découvrez comment réussir votre PI Planning : définition, bénéfices, préparation, déroulement et outils pour aligner vos équipes IT et métiers.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae3b8ff9507e294d9f896_PI%20Planning.jpg", "alt": "PI Planning" }, "author": { "name": "", "category": "Gestion de projets", "publishedDate": "19/2/2026" }, "publishedDate": "19/2/2026" }, "blocks": [{ "type": "paragraph", "text": "Aligner les équipes IT et métiers, c'est souvent un casse-tête. Entre les priorités business qui évoluent sans cesse, les équipes tech qui jonglent avec les contraintes techniques, et des silos qui compliquent la communication, on se retrouve vite avec des projets qui avancent… mais pas forcément dans la bonne direction." }, { "type": "paragraph", "text": "Résultat ? Des frustrations des deux côtés, des retards, et une perte de valeur pour l'entreprise." }, { "type": "paragraph", "text": "C'est là que le <strong>PI Planning</strong> entre en jeu. Pilier du framework SAFe (Scaled Agile Framework), cet événement trimestriel rassemble toutes les équipes impliquées dans un Agile Release Train (ART) pour synchroniser leurs efforts autour d'un plan clair et réaliste. Pendant deux jours, IT et métiers travaillent ensemble pour définir les priorités, lever les dépendances et s'assurer que chacun avance dans le même sens." }, { "type": "paragraph", "text": "En bref : c'est le moment où tout le monde se met d'accord sur ce qu'on fait, pourquoi on le fait et comment on va y arriver." }, { "type": "paragraph", "text": "Mais attention : une session mal préparée peut vite devenir une réunion interminable qui manque d'impact. Pour qu'il soit efficace, il faut <strong>une bonne préparation, une forte implication des parties prenantes et une vraie dynamique de collaboration</strong>. Sinon, on risque de repartir avec un plan flou et une fausse impression d'alignement." }, { "type": "paragraph", "text": "Alors, comment transformer cet exercice en un levier de performance et d'engagement pour vos équipes ? Quels sont les pièges à éviter ? Et surtout, comment faire en sorte que cet événement soit un moteur de création de valeur et pas juste une contrainte de plus ?" }, { "type": "paragraph", "text": "Dans cet article, on va décortiquer <strong>les clés d'un PI Planning réussi, avec des retours d'expérience concrets et des conseils actionnables</strong>. Parce que bien fait, cet événement peut changer la dynamique de vos projets et enfin aligner IT et Métiers sur un objectif commun." }, { "type": "insight-callout", "label": "À retenir", "html": "<ul><li>Pour enrichir nos connaissances et aller au-delà de la littérature, nous avons demandé à des experts de nous partager leurs convictions. Ils apportent aussi leurs bonnes pratiques concrètes pour s'engager dans la mise en place d'un PI Planning. Nous remercions Elodie Clémentine Grasset et <a href=\"https://www.linkedin.com/in/michel-levaslot/\">Michel Levaslot</a> pour leurs contributions.</li></ul>" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-pi-planning", "text": "Qu'est-ce qu'un PI Planning ?" }, { "type": "paragraph", "text": "Focus d'abord sur la définition du PI Planning, et quelques concepts-clés à connaître pour bien vous lancer." }, { "type": "paragraph", "text": "Il s'agit d'une réunion d'équipe à grande échelle, visant à organiser les tâches pour une durée définie, appelée Program Increment ou PI (et Planning Interval depuis la version 6 de SAFe). Cette séance collaborative permet d'aligner les objectifs et de <strong>coordonner les actions de toutes les parties prenantes d'un projet</strong>, garantissant une planification claire et concertée pour la période concernée." }, { "type": "quote", "text": "Le PI Planning, c'est un processus partagé. La notion de \"partagé\" est importante parce que, tout l'intérêt de ce process, c'est que les gens qui y participent sont ceux qui y mettent l'argent - donc ceux qui attendent des bénéfices du livrable. Le PI Planning les oblige à se poser les bonnes questions sur la valeur associée au projet. Ça met les responsabilités au bon endroit.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "paragraph", "text": "On utilise souvent cette pratique dans le cadre d'un développement de produit informatique. Cependant, il peut tout aussi bien être mis en œuvre dans des projets plus traditionnels et structurés, tels que la gestion des changements organisationnels, la création hardware ou encore la réalisation de projets documentaires." }, { "type": "paragraph", "text": "À l'échelle, cette approche peut permettre de structurer tout le build d'une organisation, tous les projets et les évolutions produits en cours." }, { "type": "paragraph", "text": "Grâce à ce processus de planification, vous pouvez :" }, { "type": "list", "ordered": false, "items": ["<strong>Définir et redéfinir régulièrement des objectifs communs</strong> à toutes vos parties prenantes, autour de priorités partagées", "<strong>Planifier les livrables de chaque équipe</strong>, notamment dans le cadre de projets transverses, tout en limitant l'impact des dépendances", "<strong>Déployer et challenger régulièrement et collaborativement un plan d'action</strong>, que chaque équipe s'engage à respecter pour atteindre les objectifs communs via des engagements clairs sur les livrables"] }, { "type": "paragraph", "text": "La session dure généralement une à deux journées, segmentées de manière à aborder tous les sujets du PI à venir : jalons clés, fonctionnalités à développer, priorités, risques…" }, { "type": "heading", "level": 3, "id": "pi-planning-et-framework-safe", "text": "PI Planning et framework SAFe" }, { "type": "paragraph", "text": "Le Program Increment (PI), et par extension le PI Planning, s'inscrit dans le cadre méthodologique du SAFe (Scaled Agile Framework). Dans cette approche agile, les équipes collaborant sur un PI sont appelées \"Agile Release Train\" (ART)." }, { "type": "paragraph", "text": "Pour aller plus loin sur les bonnes pratiques SAFe, consultez <a href=\"/fr/gestion-de-projet/pi-safe\">nos 8 essentiels pour réussir votre PI SAFe</a>." }, { "type": "paragraph", "text": "Traditionnellement, selon les principes du SAFe, un PI s'étend sur une période de 8 à 12 semaines. Toutefois, si vous n'adoptez pas à la lettre ce framework, vous pouvez ajuster cette durée en fonction des besoins de votre organisation, par exemple en choisissant un cycle trimestriel." }, { "type": "quote", "text": "Le framework SAFe considère qu'un Program Increment a une durée spécifique, mais il est possible d'adapter cette temporalité. Les valeurs temporelles comme le trimestre sont très ancrées dans la culture humaine, ce qui peut permettre de rendre les échéances du PI Planning plus aisément compréhensibles par tous. Sans oublier qu'en France, la temporalité trimestrielle permet d'éviter de positionner le prochain PI Planning pendant une période de vacances.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Cette flexibilité n'exclut pas la possibilité de maintenir des sprints plus courts et des livraisons régulières, assurant ainsi un rythme itératif pour l'équipe de développement." }, { "type": "paragraph", "text": "En passant à l'échelle, pour aligner une entreprise sur ses projets stratégiques ou vitaux, on recommande fortement de choisir le rythme du trimestre. Le soleil nous propose un rythme trimestriel pour les saisons, les financiers nous proposent un rythme trimestriel pour les publications financières, pourquoi ne pas s'inscrire dans un rythme naturel pour le build, pour les projets ?" }, { "type": "quote", "text": "Pour les équipes qui sont habituées au contexte SAFe, on peut utiliser le terme de Program Increment Planning. Mais, dans un contexte de gestion de portefeuille de projets, il peut être déroutant d'utiliser le terme \"PI Planning\" — car les parties prenantes vont vouloir se raccrocher à la méthodologie SAFe. Donc autant ne garder que les principes intéressants du PI Planning, et utiliser un terme moins jargonnant, qui correspond à la culture de l'organisation : par exemple, Quarter Plan.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 3, "id": "quels-sont-les-benefices-dun-pi-planning", "text": "Quels sont les bénéfices d'un PI Planning ?" }, { "type": "paragraph", "text": "La pratique de gestion de projets à large échelle qu'est le PI Planning recèle bien des avantages — et ce, que ce soit pour des équipes qui suivent le manifeste agile à la lettre ou non." }, { "type": "paragraph", "text": "Grâce à un PI Planning bien huilé, vous pouvez notamment :" }, { "type": "list", "ordered": false, "items": ["<strong>Aligner toutes vos parties prenantes</strong> autour de priorités stratégiques communes et claires et régulièrement redéfinies", "<strong>Avoir une vision réaliste des projets</strong> et des évolutions produits, pour éviter l'effet tunnel", "<strong>Favoriser la collaboration et l'engagement des acteurs de vos projets</strong> : les owners de programme, de projets ou de produits et les sponsors (Business Owners &amp; dirigeants C-Levels) ou encore les responsables de sujets transverses (contrôleurs financiers, risks &amp; cyber managers, DPO…)", "<strong>Avoir un coup d'avance sur les blocages potentiels des projets</strong> et leurs risques, grâce à une identification en amont de leurs interdépendances"] }, { "type": "paragraph", "text": "Par conséquent, le PI Planning vous permet également de contrôler le budget de vos projets et produits de plus près." }, { "type": "quote", "text": "Le processus de Program Increment Planning permet de mieux contrôler le budget d'un projet. Grâce à un PI Planning, on voit tout passer : les capacités comme le budget à attribuer à chaque étape. Cela permet de donner de la visibilité à tout le monde (y compris le CFO) sur la manière dont l'enveloppe budgétaire est utilisée, et comment on priorise son utilisation sur la période.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "paragraph", "text": "En somme, le PI Planning est une pratique de développement itératif pour accélérer la livraison de valeur de vos projets, et rentrer dans une démarche d'amélioration continue." }, { "type": "paragraph", "text": "Mais pour bénéficier de ces avantages, vous devez comprendre comment mettre en place un PI Planning at scale bien ficelé. Bonne nouvelle : c'est exactement ce que cet article vous dévoile !" }, { "type": "heading", "level": 2, "id": "a-quoi-ressemble-un-pi-planning-reussi-avec-des-benefices-concrets", "text": "À quoi ressemble un PI Planning réussi avec des bénéfices concrets ?" }, { "type": "paragraph", "text": "Découvrez ici à quoi ressemblent deux journées-types de PI Planning." }, { "type": "heading", "level": 3, "id": "le-prerequis-et-le-challenge-permanent-un-climat-dechange-serein-et-transparent", "text": "Le prérequis et le challenge permanent : un climat d'échange serein et transparent" }, { "type": "paragraph", "text": "L'une des clés du succès d'un PI Planning est de réussir à instaurer un environnement où chacun se sent libre de partager ses contraintes, pour planifier collectivement l'avenir du projet sur la période à venir." }, { "type": "paragraph", "text": "Simple sur le papier. Véritable challenge pour les organisateurs qui doivent \"sentir\" les moods de l'entreprise et veiller à distribuer la parole tout en relançant en permanence pour rechercher les compromis." }, { "type": "paragraph", "text": "Ne pas se mentir lors de ces moments est essentiel. Baser les réflexions sur les data objectives disponibles n'empêche pas de faire des paris raisonnables aussi." }, { "type": "paragraph", "text": "Le point de vue du verre à moitié plein sera un allié pour toujours avancer dans la résolution des complexités du portefeuille." }, { "type": "paragraph", "text": "Pour ce faire, utilisez pendant le PI Planning <strong>des outils collaboratifs</strong>, qui permettent de structurer les échanges et de montrer que la parole de chacun est prise en compte." }, { "type": "paragraph", "text": "Utilisez :" }, { "type": "list", "ordered": false, "items": ["Des tableaux d'équipes", "Un tableau des dépendances", "Un tableau des risques"] }, { "type": "paragraph", "text": "Veillez également à <strong>rappeler les règles du PI Planning</strong> dès que vous lancez la réunion. Rentrez dans le détail, en mettant par exemple en avant les couleurs des différents post-its à utiliser sur les tableaux (selon qu'il s'agit de risques, de jalons clés, de features, de user stories…)." }, { "type": "paragraph", "text": "Ces règles seront transmises en amont des prises de parole, auprès de chaque équipe, qui pourront également préparer le terrain habilement." }, { "type": "paragraph", "text": "Et c'est le rôle de l'animateur du PI Planning, le Release Train Engineer (RTE), que de réussir à distribuer la parole équitablement, pour assurer des échanges sereins." }, { "type": "quote", "text": "Le RTE, est quelqu'un que l'on choisit pour sa capacité d'animation. Il doit être bon orateur, savoir gérer sa fatigue (car un PI Planning, c'est fatigant !). Il doit avoir dans sa botte des techniques qui permettent de demander le silence, de couper les personnes trop bavardes, de maîtriser le timing… Souvent, les RTE assistent à d'autres PI Plannings pour se préparer.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 3, "id": "un-lancement-ultra-pragmatique-du-pi-planning-pour-donner-du-sens", "text": "Un lancement ultra pragmatique du PI Planning pour donner du sens" }, { "type": "paragraph", "text": "L'équilibre précaire, notamment dans les premières expérimentations, entre des objectifs raisonnables et un impact total ne doit pas décourager. Un PI Planning c'est un process qui est apprenant pour toutes les parties. Veiller à cibler l'objectif qui résout un des maux les plus partagés par les équipes." }, { "type": "paragraph", "text": "En tout début de PI Planning, c'est le Release Train Engineer qui prend la parole pour introduire la réunion. Il présente l'agenda des journées à venir, et met en avant les objectifs à atteindre." }, { "type": "paragraph", "text": "<em>\"Voici tous les enjeux que le PI nous permet d'adresser, mais pour ces premières mises en œuvre, nous allons focaliser sur …\"</em>" }, { "type": "paragraph", "text": "Puis il <strong>présente la vision du PI à venir</strong>, en se basant sur les priorités stratégiques qu'il a collectées en amont de la réunion." }, { "type": "paragraph", "text": "Les parties prenantes clés — Product Manager, responsables des différents domaines — présentent les objectifs du PI, sa vision, la feuille de route et les priorités stratégiques. L'intervention de top sponsors de l'organisation peut être requise et préparée afin qu'ils portent eux-mêmes les grands changements stratégiques. Invitez les business owners, les directeurs métiers, même des big boss s'il le faut. Donnez le poids nécessaire à ces interventions, qui sont la raison d'être de votre événement." }, { "type": "quote", "text": "La vision du projet est ce qui permet d'exprimer, à court ou à plus long terme, là où on veut collectivement aller. Le but final de la vision du PI est d'embarquer toutes les parties prenantes dans la durée, de les faire tous aller dans le sens de l'entreprise.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Enfin, l'introduction se termine par un rappel <strong>des enjeux stratégiques et des inflexions à prendre en compte dans la période à venir</strong>, une présentation détaillée du backlog et des fonctionnalités ou livrables prioritaires à planifier pour la période à venir." }, { "type": "heading", "level": 3, "id": "des-ateliers-de-planification-par-equipe", "text": "Des ateliers de planification par équipe" }, { "type": "paragraph", "text": "Lors de la deuxième demi-journée du PI Planning, chaque équipe lance son workshop de planification. L'idée : <strong>planifier les livraisons des différentes fonctionnalités pour le PI à venir</strong>, en détaillant chaque user story, et en donnant une estimation des efforts à fournir." }, { "type": "paragraph", "text": "Chaque équipe analyse également <strong>les dépendances</strong> qu'elle pourrait rencontrer avec d'autres équipes, et planifie les itérations en fonction de sa capacité et des priorités des features à sortir." }, { "type": "paragraph", "text": "Lors de cette étape, le Scrum Master aide chaque équipe à prioriser, à organiser le travail. C'est bien de constituer une équipe de référents ultra-engagés dans la réussite de l'événement et multi-équipe pour contrer le côté gourou illuminé qui colle trop souvent aux basques d'un Scrum Master…" }, { "type": "paragraph", "text": "Veillez à la présence d'un représentant des sponsors business dans toutes les phases du PI. Les big boss au début et à la fin, les \"sachants\" experts métiers au cœur des échanges." }, { "type": "quote", "text": "La grande difficulté, surtout pour les métiers, est de réussir à segmenter le produit en features plus fines, pour que le livrable tienne dans la période du Program Increment. Pour cela, il faut amener un changement de culture. Chacun doit comprendre qu'on ne fabrique pas un monolithe, qu'il faut découper le produit pour tenir les échéances de production. Il existe quelques tactiques pour ça : Découper par géolocalisation, en démarrant par une région concernée en premier. Découper le produit en plus petit produit (les pneus de la voiture avant l'habitacle). Découper par population, par exemple en faisant une segmentation 80/20 façon Pareto sur la population concernée…", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 4, "id": "le-tableau-de-suivi-du-rte-garder-le-cap-pendant-les-ateliers", "text": "Le tableau de suivi du RTE : garder le cap pendant les ateliers" }, { "type": "paragraph", "text": "Pendant que les équipes planchent sur leur planification, le RTE ne reste pas les bras croisés. Son rôle est de suivre l'avancement de chaque équipe au fil de l'eau, en s'appuyant sur un tableau de \"Scrum de Scrum\" qui pose les bonnes questions :" }, { "type": "list", "ordered": false, "items": ["Avez-vous identifié la Capacité à Faire (CAF) par sprint ?", "Avez-vous identifié la charge totale de vos features ? Est-elle inférieure à 80% de votre CAF ?", "Combien de dépendances restent à négocier ?", "Avez-vous identifié des actions d'atténuation des risques ?", "Avez-vous rédigé vos objectifs de PI ?"] }, { "type": "quote", "text": "Cette checklist permet de s'assurer de la qualité des échanges entre les participants, et de guider ceux qui sont un peu perdus pendant le Program Increment Planning.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Ce tableau est un outil de pilotage simple mais redoutablement efficace. Il rend visible l'état de préparation de chaque équipe et permet au RTE d'intervenir au bon moment, avant qu'un blocage ne s'installe." }, { "type": "heading", "level": 3, "id": "lidentification-des-dependances-un-livrable-cle-dun-pi-reussi", "text": "L'identification des dépendances, un livrable clé d'un PI réussi" }, { "type": "paragraph", "text": "Lorsque les ateliers de planification sont terminés, chaque équipe présente son plan à tout le train agile. Collectivement, <strong>les dépendances sont validées, et les plans de chaque équipe sont ajustés</strong> pour éviter que ces dépendances ne créent des goulots d'étranglement." }, { "type": "paragraph", "text": "Veiller à ce que ces dépendances ne restent pas sur le paper board jusqu'au prochain PI, mais intégrez-les directement dans vos outils de suivi des projets et des produits." }, { "type": "heading", "level": 3, "id": "le-risk-management-au-coeur-des-enjeux-du-pi-planning", "text": "Le risk management au cœur des enjeux du PI Planning" }, { "type": "paragraph", "text": "Pendant la troisième demi-journée, les participants du PI Planning analysent les risques que les projets vont probablement rencontrer, et qui mettraient potentiellement à mal les livraisons. Ces risques sont généralement classés par ordre de priorité. Puis le collectif met en place <strong>des actions pour atténuer ces risques</strong>." }, { "type": "paragraph", "text": "Une nouvelle fois une attention particulière sera mise sur l'usage de cette matière riche (les risques) qui émerge lors des PI Planning. Choisissez une solution qui rend visible ces risques au cœur même de votre gestion des portefeuilles, programmes, projets et produits." }, { "type": "heading", "level": 3, "id": "une-validation-collective-du-plan-final-du-pi", "text": "Une validation collective du plan final du PI" }, { "type": "paragraph", "text": "Pendant la dernière demi-journée de PI Planning, <strong>les plans d'équipes sont finalisés</strong>. Les représentants des métiers font part de leur feedback sur ces plans, et des ajustements finaux sont apportés si besoin." }, { "type": "paragraph", "text": "Puis tout le monde participe à <strong>un vote de confiance</strong> : les équipes s'engagent ainsi à s'aligner sur le plan qu'elles ont défini. Dans des cas très rares, si le vote de confiance est très bas, il peut être décidé de retravailler les plans. Mais généralement, les ateliers de planification et l'étude des interdépendances a permis d'obtenir un plan carré, adopté par tous." }, { "type": "heading", "level": 3, "id": "collecter-du-feedback-montrer-quon-veut-faire-mieux-la-fois-dapres", "text": "Collecter du feedback : montrer qu'on veut faire mieux la fois d'après" }, { "type": "paragraph", "text": "Un PI Planning ne se termine pas au vote de confiance. L'ultime étape de la réunion, c'est la rétrospective — un moment dédié pour que les participants partagent ce qui a bien fonctionné et ce qui doit être amélioré pour les prochaines sessions." }, { "type": "paragraph", "text": "Deux formats fonctionnent particulièrement bien dans ce contexte :" }, { "type": "paragraph", "text": "Le <strong>ROTI</strong> (Return On Time Invested) permet à chaque participant de noter rapidement l'utilité perçue du temps investi. C'est un indicateur flash, parfait pour prendre le pouls collectif en fin de journée." }, { "type": "paragraph", "text": "Le <strong>DAKI</strong> (Drop, Add, Keep, Improve) va plus loin : chaque participant identifie ce qu'il faut abandonner, ajouter, conserver ou améliorer dans le processus. C'est un format structurant qui alimente directement les évolutions du prochain PI Planning." }, { "type": "paragraph", "text": "Ne sous-estimez pas cette étape. Un PI Planning qui s'améliore d'un trimestre à l'autre, c'est un PI Planning qui s'ancre durablement dans la culture de l'organisation. Et c'est précisément cette logique d'amélioration continue qui distingue les équipes qui \"font du PI Planning\" de celles qui en tirent réellement de la valeur." }, { "type": "heading", "level": 2, "id": "des-sa-preparation-faites-de-votre-pi-planning-un-atout-pour-transformer", "text": "Dès sa préparation, faites de votre PI Planning un atout pour transformer" }, { "type": "paragraph", "text": "Vous l'aurez peut-être déjà compris : un PI Planning réussi, c'est une réunion qui ne laisse rien au hasard, et qui est bien planifiée en amont. Voici quelques étapes-clés par lesquelles passer pour un Program Increment Planning sans accroc." }, { "type": "heading", "level": 3, "id": "miser-sur-les-bonnes-personnes-pour-provoquer-lalignement", "text": "Miser sur les bonnes personnes pour provoquer l'alignement" }, { "type": "paragraph", "text": "Tout d'abord, vous devez établir une liste des participants à votre PI Planning. Toutes les parties prenantes de votre projet doivent être présentes — mais attention : il s'agit de réunir aussi les personnes qui sont réellement décisionnaires." }, { "type": "paragraph", "text": "Sinon, vous prenez le risque d'aligner les équipes qui font et celles qui organisent sans impliquer celles et ceux qui décident. Gros warning : vous partez mal et allez créer des attentes fortes. Pas de sponsor, pas de PI." }, { "type": "quote", "text": "Un PI Planning est une séance de planification. Toutes les personnes nécessaires à la planification et aux arbitrages doivent être présentes. Par contre, attention à ne pas considérer cette réunion comme du \"tourisme industriel\". Si des personnes ne sont pas nécessaires, autant ne pas les inviter. Leur présence risque de polluer le PI Planning.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Doivent être présents à votre séance de planification :" }, { "type": "list", "ordered": false, "items": ["<strong>Le Product Management</strong>, dont les Product Owners", "<strong>Les Scrum Masters</strong>", "<strong>Les Business Owners</strong>, et le management impliqué dans le projet", "<strong>Les architectes</strong>", "<strong>Les sponsors</strong> des projets"] }, { "type": "heading", "level": 4, "id": "clarifier-le-role-de-chacun-avant-le-jour-j", "text": "Clarifier le rôle de chacun avant le jour J" }, { "type": "paragraph", "text": "Avoir les bonnes personnes dans la salle ne suffit pas : chacune doit savoir ce qu'on attend d'elle. Prenez le temps d'expliciter les responsabilités de chaque profil en amont du PI Planning :" }, { "type": "paragraph", "text": "Le <strong>Release Train Engineer (RTE)</strong> coordonne et facilite l'ensemble du PI Planning. C'est lui qui distribue la parole, gère le timing, et s'assure que chaque atelier produit les livrables attendus." }, { "type": "paragraph", "text": "Le <strong>Product Management</strong> (dont les Product Owners) définit les priorités et les features à développer. C'est la voix du \"quoi\" et du \"pourquoi\"." }, { "type": "paragraph", "text": "Les <strong>Scrum Masters</strong> aident les équipes agiles à préparer leurs plans, à estimer leur capacité et à lever les blocages opérationnels." }, { "type": "paragraph", "text": "Les <strong>Business Owners</strong> fournissent les orientations stratégiques et valident les objectifs proposés par les équipes. Leur présence est non négociable pour les arbitrages." }, { "type": "heading", "level": 4, "id": "desamorcer-les-resistances-en-amont", "text": "Désamorcer les résistances en amont" }, { "type": "paragraph", "text": "L'état d'esprit des participants est aussi important que leur présence. Prenez du temps en amont avec les profils sceptiques : levez leurs peurs, identifiez leurs contraintes. Si certaines personnalités risquent de freiner la dynamique collective, préparez le terrain avec leur manager direct. Un deal simple fonctionne souvent : un enjeu personnel adressé en échange d'une attitude constructive pendant la réunion." }, { "type": "paragraph", "text": "Ne soyez pas naïf sur ce point : une seule personne mal embarquée peut abîmer l'impact d'un PI Planning, surtout lors des premières mises en œuvre." }, { "type": "quote", "text": "Ce qui peut faire qu'un PI Planning ne fonctionne pas, c'est de réunir des gens qui ont des objectifs vraiment antinomiques, qui les empêchent d'avoir envie de travailler les uns avec les autres. Mais sachez qu'il est même possible de faire des trains multi-organismes, avec des partenaires business. Un signe que la réussite du PI Planning tient surtout au fait que le projet soit bien sponsorisé des deux côtés. Le PI Planning n'est pas un outil magique : tout le monde doit comprendre qu'on cherche une victoire collective, un processus gagnant/gagnant, malgré les éventuelles inadhérences politiques.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 3, "id": "avoir-une-vision-claire-des-priorites-strategiques", "text": "Avoir une vision claire des priorités stratégiques" }, { "type": "paragraph", "text": "En préparant votre PI Planning, vous devez déterminer quelle est la vision qui va guider la période que vous devez planifier. L'idée : <strong>aligner tout le monde autour de la transformation que votre entreprise va vivre à l'avenir</strong>." }, { "type": "paragraph", "text": "Prenez en compte l'environnement dans lequel votre entreprise évolue et va évoluer dans les temps à venir. Votre vision peut être basée sur des éléments positifs (comme des projets innovants que l'entreprise va mener), négatifs (comme l'arrivée de nouveaux concurrents sur votre marché), ou encore sur des contraintes (comme une nouvelle réglementation)." }, { "type": "paragraph", "text": "Allez également parler avec les directeurs métiers impliqués, et demandez-leur quelles sont leurs priorités stratégiques, et les points de friction qu'ils auront besoin d'aborder pendant le PI Planning." }, { "type": "paragraph", "text": "Notez que la vision que vous allez communiquer aux participants de votre PI Planning n'impacte pas forcément la période à venir. Il s'agit surtout d'une grande ligne directrice qui doit guider la priorisation des actions à venir." }, { "type": "paragraph", "text": "Pensez aussi à préparer votre <strong>roadmap produit</strong> et votre backlog. Veillez à ce que les features soient matures, compréhensibles, faisables, découpées pour tenir dans le PI, et chargées. Des features trop floues ou trop grosses feront perdre un temps précieux pendant les ateliers de planification." }, { "type": "heading", "level": 3, "id": "anticiper-les-blocages-potentiels", "text": "Anticiper les blocages potentiels" }, { "type": "paragraph", "text": "Même si le PI Planning a pour but d'identifier les blocages qui pourraient interférer dans votre projet, prenez le temps si possible d'anticiper ces blocages lors de votre préparation." }, { "type": "paragraph", "text": "Pour cela :" }, { "type": "list", "ordered": false, "items": ["<strong>Préparez une matrice des risques</strong> du projet", "<strong>Repérez les goulots d'étranglement potentiels</strong>, au vu des interdépendances des équipes.", "<strong>Anticipez les contraintes externes au projet</strong>, ainsi que les questions techniques que les participants pourraient vous poser."] }, { "type": "quote", "text": "Le support de travail en amont d'un PI Planning, c'est essentiellement un backlog des projets, un portefeuille de projets, pré-trié avec une macro-priorisation, et une estimation \"à la louche\" de l'effort. Et quand on a un sujet de capacité, il peut être intéressant d'essayer d'identifier, en amont, quel goulot d'étranglement pourrait émerger.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 3, "id": "organiser-la-logistique", "text": "Organiser la logistique" }, { "type": "paragraph", "text": "Vous le savez : la gestion de projet à grande échelle demande une logistique considérable. Et c'est également le cas pour l'organisation d'un PI Planning !" }, { "type": "paragraph", "text": "Prenez le temps de :" }, { "type": "list", "ordered": false, "items": ["<strong>Réserver les jours du planning dans l'agenda des participants</strong>, et anticiper les besoins de réservations d'hôtel si des intervenants ont besoin de se déplacer. Réservez au moins deux mois en avance. Vérifiez aussi si les dates fixées permettent à vos invités de planifier des team meetings sur les jours précédents ou suivants — un deal avec l'hôtel du coin, c'est toujours ça en moins sur le budget.", "<strong>Planifier la réunion dans une salle adaptée au PI Planning</strong>, ou bien mettre en place un outil de visioconférence si votre réunion se passe à distance. Vos salles (physiques ou digitales) doivent pouvoir contenir tous les participants, et leur permettre de travailler en plus petits groupes. Prévoyez des salles annexes pour traiter les problèmes qui peuvent apparaître en séance. Réfléchissez à un plan de table qui facilite la communication par équipes et inter-équipes.", "<strong>Préparer un agenda détaillé du PI Planning</strong>. Prévoyez minutieusement la durée de chaque session. Puis partagez cet agenda à tous."] }, { "type": "paragraph", "text": "Vous optez pour le PI Planning en ligne ? Ne sous-estimez pas la complexité de la logistique. Qualité des visios, outils collaboratifs pour les workshops, salles virtuelles dédiées… Des tests et une répétition générale le jour précédent paraissent indispensables. Nous déconseillons personnellement de mener vos PI Plannings intégralement à distance !" }, { "type": "heading", "level": 3, "id": "communiquer-pour-changer-la-culture-projet", "text": "Communiquer pour changer la culture projet" }, { "type": "paragraph", "text": "Lancer la démarche itérative du PI Planning dans une entreprise est un véritable acte de communication. Vous devez faire en sorte que vos participants soient prêts à s'y engager fermement, dans la durée, et qu'ils comprennent les bénéfices qu'ils pourront en tirer." }, { "type": "quote", "text": "En amont du PI Planning, il faut vendre ce processus comme une arme de guerre. Tout le monde doit être prêt à \"brûler les vaisseaux\" : chacun doit s'engager dans la démarche, sans faire marche arrière. Pour ça, il faut créer de l'engagement via un acte de communication fort, en publiant des posts sur l'Intranet, par exemple. Pour lancer un PI Planning, nous avons même un jour lancé un article sur un média externe référent pour détailler le processus : idéal pour créer de l'engagement.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "En effet, les développeurs sont souvent habitués à travailler de manière incrémentale, grâce à des méthodes agiles. Mais les métiers, eux, ont souvent plus de mal à mettre en place une méthode de planification aussi fine et détaillée. Le processus de PI Planning demande de mener une véritable conduite du changement : communication sur les bénéfices, levage des freins de chacun, et mise en place de techniques concrètes pour mieux planifier ensemble." }, { "type": "paragraph", "text": "D'où le fait que vous devez <strong>mener une conduite du changement assidue</strong>, en communiquant de manière motivante. Levez les freins de chacun en amont de la réunion, et rappelez à tous les avantages de ce mode de fonctionnement." }, { "type": "quote", "text": "Le PI Planning pousse toutes les parties prenantes à se poser les bonnes questions sur la valeur associée au projet. Lors des discussions, on se focalise sur pourquoi on fait ce projet, quelles sont les priorités, et comment identifier et gérer les dépendances. Ce processus permet à tout le monde de se rendre compte que la gestion du projet est transparente, non arbitraire, et remet les responsabilités au bon endroit.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 2, "id": "quels-outils-pour-un-pi-planning-qui-se-deroule-parfaitement", "text": "Quels outils pour un PI Planning qui se déroule parfaitement ?" }, { "type": "paragraph", "text": "Un PI Planning efficace ne repose pas uniquement sur la méthodologie : les bons outils font toute la différence. Sans une préparation rigoureuse et un suivi structuré, cet exercice peut vite devenir une perte de temps, avec des engagements flous et des dépendances mal gérées." }, { "type": "paragraph", "text": "C'est là qu'un outil comme <strong>Airsaas</strong> prend tout son sens. Avant même le PI Planning, il permet de <strong>préparer en amont la capacité des équipes, de prioriser les features clés et d'anticiper les dépendances</strong>. En donnant une vision claire des objectifs et des ressources disponibles, Airsaas facilite la revue des initiatives et aligne les parties prenantes sur ce qui est vraiment faisable sur le trimestre à venir." }, { "type": "paragraph", "text": "Pendant l'événement, Airsaas structure la planification en <strong>rendant visibles les arbitrages et les engagements pris</strong>. Plus besoin de jongler avec des dizaines de tableaux : tout est centralisé, lisible et actionnable. Et après le PI Planning, il assure un suivi en continu des engagements et de l'exécution des projets, pour éviter les dérives et ajuster les priorités en fonction des réalités terrain." }, { "type": "paragraph", "text": "Un PI Planning réussi, c'est une préparation solide, une exécution fluide et un suivi rigoureux. Avec Airsaas, vous donnez aux équipes IT et métiers un cadre clair et pragmatique pour que leurs efforts soient réellement alignés sur la stratégie de l'entreprise." }, { "type": "paragraph", "text": "Intéressé ? <a href=\"https://www.airsaas.io/fr\">Découvrez Airsaas, et demandez votre démo dès maintenant</a>." }, { "type": "heading", "level": 2, "id": "apres-le-pi-planning-assurer-le-suivi-pour-ne-pas-perdre-la-valeur-creee", "text": "Après le PI Planning : assurer le suivi pour ne pas perdre la valeur créée" }, { "type": "paragraph", "text": "Le PI Planning est terminé. Deux jours intenses, des dizaines de décisions prises, des engagements formalisés. Mais tout cela ne vaut rien si la dynamique retombe le lundi suivant. Voici comment capitaliser sur l'énergie du PI." }, { "type": "heading", "level": 3, "id": "communiquer-les-objectifs-et-les-rendre-accessibles-a-tous", "text": "Communiquer les objectifs et les rendre accessibles à tous" }, { "type": "paragraph", "text": "Premier réflexe : rassemblez tous les objectifs du Program Increment et les plans d'équipes, et diffusez-les largement. Chaque participant doit pouvoir retrouver facilement ce qui a été décidé, les engagements de chacun, et les échéances associées." }, { "type": "paragraph", "text": "Votre plan dans un Sharepoint caché ou un PowerPoint envoyé par email, ça ne suffira pas. Optez pour des solutions qui rendent vos plans compréhensibles et accessibles en permanence — pour les équipes comme pour les sponsors." }, { "type": "paragraph", "text": "Vous n'avez pas déployé toute cette énergie, mobilisé autant de cerveaux, pour que les décisions prises restent confidentielles." }, { "type": "heading", "level": 3, "id": "mettre-en-place-les-rituels-de-suivi", "text": "Mettre en place les rituels de suivi" }, { "type": "paragraph", "text": "Tout au long du PI, un suivi régulier est indispensable pour s'assurer que le plan est respecté et que les obstacles sont levés rapidement. Trois niveaux de rituels sont à mettre en place :" }, { "type": "paragraph", "text": "Les <strong>réunions quotidiennes</strong> (Daily Stand-ups) et les réunions de gestion des risques permettent aux équipes de traiter les irritants au fil de l'eau." }, { "type": "paragraph", "text": "Les <strong>Scrum of Scrums</strong> et les <strong>PI Reviews</strong> assurent la synchronisation entre les équipes à intervalles réguliers. C'est le moment de vérifier que les dépendances identifiées sont bien gérées." }, { "type": "paragraph", "text": "Les <strong>System Demo</strong> (ou a minima des démos d'équipes) offrent une mesure objective et régulière de l'avancement, avec la possibilité de recevoir du feedback." }, { "type": "paragraph", "text": "L'écueil que rencontrent beaucoup d'organisations : les informations du PI Planning restent sur des post-its dans Miro ou sur un paperboard pris en photo… et six mois plus tard, on recommence à identifier des dépendances et des risques qu'on avait déjà levés. Intégrez la data produite lors du PI dans vos outils de suivi projet, et exploitez-la en continu." }, { "type": "heading", "level": 3, "id": "linspect-and-adapt-boucler-la-boucle-avant-le-prochain-pi", "text": "L'Inspect & Adapt : boucler la boucle avant le prochain PI" }, { "type": "paragraph", "text": "Juste avant le prochain PI Planning, prenez le temps de faire une revue de la réalisation effective du PI — en termes de valeur atteinte, plus qu'en termes de features livrées. C'est la cérémonie d'<strong>Inspect &amp; Adapt</strong> : un moment clé pour identifier ce qui a fonctionné, ce qui a dévié, et ce qui doit changer." }, { "type": "quote", "text": "Si les équipes font du Scrum, on conserve toutes les cérémonies Scrum, ce qui permet de traiter les dérives qui ont pu apparaître entre la planification en PI Planning et le déroulement effectif. Et, juste avant le prochain PI Planning, on fait une séance de revue de la réalisation effective du PI (en termes de valeur atteinte plus qu'en termes de features) et d'amélioration, cérémonie appelée Inspect & Adapt.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "C'est cette boucle complète — planifier, exécuter, suivre, ajuster — qui fait passer le PI Planning d'un événement ponctuel à un véritable moteur de transformation continue." }, { "type": "paragraph", "text": "Vous êtes désormais prêt pour lancer ou optimiser votre prochain Program Increment Planning !" }, { "type": "insight-callout", "label": "À retenir", "html": "<p>Découvrez Airsaas pour structurer votre PI Planning de bout en bout : préparation, exécution et suivi des engagements.</p>" }], "toc": [{ "href": "#quest-ce-quun-pi-planning", "label": "Qu'est-ce qu'un PI Planning ?", "level": 2 }, { "href": "#a-quoi-ressemble-un-pi-planning-reussi-avec-des-benefices-concrets", "label": "À quoi ressemble un PI Planning réussi avec des bénéfices concrets ?", "level": 2 }, { "href": "#des-sa-preparation-faites-de-votre-pi-planning-un-atout-pour-transformer", "label": "Dès sa préparation, faites de votre PI Planning un atout pour transformer", "level": 2 }, { "href": "#quels-outils-pour-un-pi-planning-qui-se-deroule-parfaitement", "label": "Quels outils pour un PI Planning qui se déroule parfaitement ?", "level": 2 }, { "href": "#apres-le-pi-planning-assurer-le-suivi-pour-ne-pas-perdre-la-valeur-creee", "label": "Après le PI Planning : assurer le suivi pour ne pas perdre la valeur créée", "level": 2 }], "faq": [], "related": [] }, { "slug": "pi-safe", "skip": false, "meta": { "title": "PI SAFe : 8 bonnes pratiques pour réussir votre planning", "h1": "PI SAFe : 8 bonnes pratiques pour réussir votre planning", "description": "Découvrez ce qu'est un PI SAFe et les 8 clés de succès pour mettre en place votre prochain PI Planning sans peine.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae3a6e54962b16695b2f3_PI%20SAFe.jpg", "alt": "PI SAFe" }, "author": { "category": "Gestion de projets" } }, "blocks": [{ "type": "paragraph", "text": "Vous gérez un portefeuille de projets, et vous rencontrez toujours les mêmes problèmes : vous planifiez en amont chaque étape, mais vos projets bloquent faute de ressources disponibles ou à cause de dépendances qu'il était difficile d'anticiper." }, { "type": "paragraph", "text": "Ce n'est pas une fatalité ! Et si vous vous inspiriez de <strong>la démarche agile appelée \"PI SAFe\" </strong>pour régler ces soucis ?" }, { "type": "paragraph", "text": "Découvrez ici ce qu'est un PI, et les clés de succès pour mettre en place votre prochain PI Planning sans peine." }, { "type": "heading", "level": 2, "id": "quappelle-t-on-pi-safe", "text": "Qu'appelle-t-on PI SAFe ?" }, { "type": "paragraph", "text": "Pour commencer, quelques rappels sur ce qu'est un PI SAFe sont de bon ton." }, { "type": "heading", "level": 3, "id": "pi-safe-and-pi-planning-de-quoi-parle-t-on", "text": "PI SAFe & PI Planning : de quoi parle-t-on ?" }, { "type": "paragraph", "text": "On appelle PI ou Program Increment (et Planning Interval depuis la version 6 de SAFe) un espace de temps donné, lors duquel des équipes (aussi appelées \"Agile Release Train\", ou ART, dans la méthode agile) planifient, développent, testent et obtiennent du feedback sur une solution qu'elles développent. On parle de \"PI SAFe\" car le concept de Program Increment fait partie du framework agile dit SAFe (Scaled Agile Framework)." }, { "type": "paragraph", "text": "Pendant l'espace de temps qu'est le PI SAFe, <strong>le train planifie, met en œuvre, évalue et ajuste la solution développée</strong>, sous forme d'itérations." }, { "type": "paragraph", "text": "Si l'on s'en tient à la méthodologie SAFe, un PI dure entre 8 et 12 semaines. Cependant, si vous n'appliquez pas directement ce framework, vous pouvez tout à fait adapter cette temporalité à celle de votre entreprise - par exemple, en déterminant qu'un PI dure un trimestre. Cela n'empêche pas le principe des sprints par itérations plus courtes, et de livraisons plus fréquentes, de continuer pour l'équipe de développement." }, { "type": "paragraph", "text": "L'un des moments-clés d'un Program Increment est le PI Planning. Il s'agit d'une <strong>cérémonie collective, qui vise à planifier à l'avance tout le PI</strong> et ce, collaborativement, avec toutes les parties prenantes impliquées dans le développement de la solution." }, { "type": "paragraph", "text": "Un PI Planning rassemble ainsi tous les acteurs majeurs du Agile Release Train, à savoir :" }, { "type": "list", "ordered": false, "items": ["<strong>Le Product Management </strong>(dont les Product Owners)", "<strong>Les Scrum Masters </strong>", "<strong>Les représentants des métiers</strong>", "<strong>Le sponsor du projet</strong>"] }, { "type": "paragraph", "text": "Le PI Planning peut être appliqué au développement informatique, mais aussi à tout type de portefeuille projet." }, { "type": "inline-cta", "label": "Réservez votre démo de 30 min", "href": "/fr/meetings-pages" }, { "type": "heading", "level": 3, "id": "les-avantages-dun-bon-pi-planning", "text": "Les avantages d'un bon PI Planning" }, { "type": "paragraph", "text": "Que vous suiviez la méthodologie agile SAFe \"from the book\", ou que vous cherchiez simplement une pratique de gestion de projets plus efficace, le PI Planning peut vous apporter de grands bénéfices." }, { "type": "paragraph", "text": "Un PI SAFe bien organisé vous permet notamment de :" }, { "type": "list", "ordered": false, "items": ["<strong>Bien définir vos priorités stratégiques</strong>, en alignant toutes les parties prenantes de vos projets", "<strong>Favoriser la collaboration</strong>, notamment sur des projets transversaux", "<strong>Obtenir une vision claire et réaliste des projets</strong>, en mettant en place des objectifs mesurables : de quoi éviter l'effet tunnel", "<strong>Booster l'engagement de toutes les parties prenantes</strong>, ce qui favorise l'avancement de votre transformation d'entreprise", "<strong>Anticiper les risques et les blocages</strong>, en identifiant les interdépendances des projets : idéal pour répondre au manque d'agilité que la plupart des entreprises rencontre", "<strong>Rentrer dans un processus d'amélioration continue</strong>, grâce à de précieux feedbacks des différentes équipes", "<strong>Accélérer la livraison de valeur</strong> - conséquence de tous les bénéfices précédents !"] }, { "type": "quote", "text": "Le PI Planning pousse toutes les parties prenantes à se poser les bonnes questions sur la valeur associée au projet. Lors des discussions, on se focalise sur pourquoi on fait ce projet, quelles sont les priorités, et comment identifier et gérer les dépendances. Ce processus permet à tout le monde de se rendre compte que la gestion du projet est transparente, non arbitraire, et remet les responsabilités au bon endroit.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 2, "id": "8-essentiels-pour-reussir-votre-pi-planning", "text": "8 essentiels pour réussir votre PI Planning" }, { "type": "paragraph", "text": "Pas besoin de lire le manifeste agile pour lancer votre propre démarche de PI SAFe ! Grâce aux conseils suivants, vous pouvez adapter la méthodologie SAFe à votre organisation." }, { "type": "heading", "level": 3, "id": "avoir-une-vision-claire-des-priorites-strategiques", "text": "Avoir une vision claire des priorités stratégiques" }, { "type": "paragraph", "text": "Avant même que votre PI Planning ne commence, vous devez avoir une vision précise des priorités stratégiques de votre projet - et, à plus large échelle, de l'environnement dans lequel il est déployé." }, { "type": "paragraph", "text": "La direction ou les Business Owners doivent définir et communiquer les objectifs du PI SAFe. C'est le rôle du responsable de l'organisation du PI Planning d'aller demander à tous les directeurs des métiers impliqués quelles sont leurs priorités stratégiques, et quels sont leurs points de tension qu'ils voudront aborder pendant la réunion." }, { "type": "quote", "text": "La vision du projet est ce qui permet d'exprimer, à court ou à plus long terme, là où on veut collectivement aller. Il peut s'agir d'une nouvelle réglementation à suivre, de projets vers lesquels l'entreprise se dirige, de concurrents qui arrivent sur le marché… Il peut s'agir d'éléments qui ne vont pas forcément impacter le PI SAFe à venir, et d'éléments aussi bien positifs que négatifs. Le but final de la vision du PI est d'embarquer toutes les parties prenantes dans la durée, de les faire tous aller dans le sens de l'entreprise.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Prenez aussi le temps de vous pencher sur votre <strong>roadmap produit</strong>. Les priorités à moyen terme doivent être établies pour guider les équipes dans leur planification. Vous devez avoir en tête les features, et les avoir priorisées. Attention cependant à ce qu'elles soient matures, faisables, compréhensibles et chargées." }, { "type": "heading", "level": 3, "id": "anticiper-les-blocages-potentiels", "text": "Anticiper les blocages potentiels" }, { "type": "paragraph", "text": "Si possible, avant votre PI Planning, commencez à identifier les blocages qui pourraient avoir lieu lors des discussions." }, { "type": "list", "ordered": false, "items": ["<strong>Analysez les risques</strong>, en préparant une matrice des risques du projet.", "<strong>Anticipez les goulots d'étranglement</strong>, en identifiant les dépendances potentielles entre les équipes. Ces interdépendances seront discutées pendant le PI Planning.", "<strong>Préparez les réponses aux questions techniques</strong>, et anticipez les contraintes externes du projet."] }, { "type": "quote", "text": "Le support de travail en amont d'un PI Planning, c'est essentiellement un backlog des projets, un portefeuille de projets, pré-trié avec une macro-priorisation, et une estimation \"à la louche\" de l'effort. Et quand on a un sujet de capacité, il peut être intéressant d'essayer d'identifier, en amont, quel goulot d'étranglement pourrait émerger.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 3, "id": "organiser-une-logistique-sans-faille", "text": "Organiser une logistique sans faille" }, { "type": "paragraph", "text": "La logistique est essentielle au bon déroulement d'un PI Planning. L'idée : mettre tout le monde dans les meilleures conditions pour pouvoir se projeter sur la période du PI SAFe à venir." }, { "type": "paragraph", "text": "Pour cela :" }, { "type": "list", "ordered": false, "items": ["<strong>Choisissez une date</strong> où toutes les parties prenantes sont bien disponibles.", "<strong>Planifier l'agenda détaillé de la réunion</strong>, en dédiant assez de temps à chaque session, et partagez cet agenda en amont.", "<strong>Choisissez un espace approprié</strong>, permettant de travailler en grand groupe et en plus petites équipes. Si votre PI Planning a lieu à distance, organisez les outils de visioconférence appropriés. S'il est en présentiel, préparez un plan de de table propice aux échanges constructifs."] }, { "type": "heading", "level": 3, "id": "clarifier-les-roles-et-les-responsabilites-de-chacun", "text": "Clarifier les rôles et les responsabilités de chacun" }, { "type": "paragraph", "text": "Qui dit séance de planification collective, dit nécessité de mettre chacun au diapason de son rôle en amont." }, { "type": "paragraph", "text": "Pensez à expliciter à toutes les parties prenantes leurs responsabilités en amont du PI Planning :" }, { "type": "list", "ordered": false, "items": ["<strong>Le Release Train Engineer (RTE)</strong> coordonne et facilite le PI Planning, en accompagnant les échanges des participants.", "<strong>Le Product Management</strong> définit les priorités et les features à développer.", "<strong>Le Scrum Master</strong> aide les équipes agiles à préparer leurs plans et à lever les blocages.", "<strong>Les Business Owners </strong>fournissent des orientations stratégiques et valident les objectifs des équipes."] }, { "type": "heading", "level": 3, "id": "communiquer-sur-le-pi-planning-en-amont", "text": "Communiquer sur le PI Planning en amont" }, { "type": "paragraph", "text": "En amont, veillez à expliciter les règles du PI Planning - mais surtout, à faire comprendre à tous quel est son intérêt et ses bénéfices !" }, { "type": "quote", "text": "En amont du PI Planning, il faut vendre ce processus comme une arme de guerre. Tout le monde doit être prêt à \"brûler les vaisseaux\" : chacun doit s'engager dans la démarche, sans faire marche arrière. Pour ça, il faut créer de l'engagement via un acte de communication fort, en publiant des posts sur l'Intranet, par exemple. Pour lancer un PI Planning, nous avons même un jour lancé un article sur un média externe référent pour détailler le processus : idéal pour créer de l'engagement.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Appuyez-vous sur les bénéfices vus en première partie de cet article pour développer votre argumentaire. Et n'hésitez pas non plus à faire un focus sur les bénéfices budgétaires de ce type de gestion de projet." }, { "type": "quote", "text": "Le processus de PI SAFe permet de mieux contrôler le budget d'un projet. Grâce à un PI Planning, on voit tout passer : les capacités comme le budget à attribuer à chaque étape. Cela permet de donner de la visibilité à tout le monde (y compris le CFO) sur la manière dont l'enveloppe budgétaire est utilisée, et comment on priorise son utilisation sur la période.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 3, "id": "accompagner-le-changement-de-la-culture-projet", "text": "Accompagner le changement de la culture projet" }, { "type": "paragraph", "text": "Si les équipes de développement sont souvent déjà habituées à travailler avec l'approche agile du PI SAFe, ou encore à réfléchir en termes de fonctionnalités, les métiers, eux, sont moins souvent aguerris à une planification aussi fine." }, { "type": "paragraph", "text": "Le processus de PI Planning demande donc de mener une véritable conduite du changement, avec tout ce qu'elle implique : communication sur les bénéfices du processus, levage des freins de chacun, et surtout, mise en place de techniques pour mieux planifier…" }, { "type": "quote", "text": "La grande difficulté, surtout pour les métiers, est de réussir à segmenter le produit en features plus fines, pour que le livrable tienne dans la période du Program Increment. Pour cela, il faut amener un changement de culture. Chacun doit comprendre qu'on ne fabrique pas un monolithe, qu'il faut découper le produit pour tenir les échéances de production. Il existe quelques tactiques pour ça : découper par géolocalisation, en démarrant par une région concernée en premier. Découper le produit en plus petit produit (les pneus de la voiture avant l'habitacle). Découper par population, par exemple en faisant une segmentation 80/20 façon Pareto sur la population concernée…", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 3, "id": "favoriser-un-climat-dechange-en-toute-transparence", "text": "Favoriser un climat d'échange en toute transparence" }, { "type": "paragraph", "text": "Être plus agile, c'est avant tout opérer dans un climat où les équipes se sentent libres de partager leurs contraintes et préoccupations, pour mieux avancer ensemble. Et cela s'applique également pendant le PI Planning !" }, { "type": "paragraph", "text": "L'une des clés du succès : <strong>utiliser des outils collaboratifs</strong>, qui permettent à chacun de planifier en équipe. Tableaux d'équipes, tableau des dépendances, et tableau des risques, doivent être mis en place pour aligner tout le monde au cours des échanges." }, { "type": "paragraph", "text": "Et attention à <strong>bien expliciter les règles du PI Planning</strong> dès le début de la réunion. N'hésitez pas à aller jusqu'à expliquer les couleurs des post-its à utiliser sur chacun des tableaux, selon qu'on parle de features, de user stories, de risques…" }, { "type": "quote", "text": "L'animateur de PI Planning, le RTE, est quelqu'un que l'on choisit pour sa capacité d'animation. Il doit être bon orateur, savoir gérer sa fatigue (car un PI Planning, c'est fatigant !). Il doit avoir dans sa botte des techniques qui permettent de demander le silence, de couper les personnes trop bavardes, de maîtriser le timing… Souvent, les RTE assistent à d'autres PI Plannings pour se préparer.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 3, "id": "utiliser-les-outils-appropries", "text": "Utiliser les outils appropriés" }, { "type": "paragraph", "text": "Le succès d'un PI Planning ne dépend pas uniquement de la méthode employée. <strong>Les outils choisis jouent également un rôle déterminant</strong>. Sans une préparation minutieuse et un suivi structuré, cette étape cruciale peut rapidement perdre en efficacité : les dépendances sont mal gérées, les engagements manquent de clarté, et les équipes s'égarent." }, { "type": "paragraph", "text": "C'est là qu'intervient Airsaas. En amont de la session, la solution facilite <strong>l'évaluation des capacités des équipes, la priorisation des fonctionnalités essentielles et l'identification des dépendances critiques</strong>. Cette anticipation offre une vision d'ensemble précise, permettant de cadrer les objectifs et de mobiliser efficacement toutes les parties prenantes sur ce qui est réalisable au cours du trimestre." }, { "type": "paragraph", "text": "Lors du PI Planning, Airsaas simplifie la planification. Les décisions stratégiques sont rendues visibles instantanément, les engagements sont formalisés, et les arbitrages sont facilités. Plus besoin de jongler entre plusieurs outils ou feuilles de calcul : tout est centralisé sur une plateforme intuitive, rendant l'information accessible et exploitable en temps réel." }, { "type": "paragraph", "text": "Et une fois le PI Planning terminé, Airsaas assure un suivi continu. Les engagements pris sont monitorés, l'avancement des projets est suivi avec précision, et les ajustements nécessaires peuvent être effectués rapidement, en fonction des évolutions du contexte ou des imprévus." }, { "type": "paragraph", "text": "Avec Airsaas, vous offrez à vos équipes métiers et IT un cadre clair et structurant, favorisant une meilleure coordination et garantissant un alignement permanent avec la stratégie de l'entreprise." }, { "type": "paragraph", "text": "Grâce à ces conseils pour bien organiser votre PI Planning, vous êtes prêt à mettre en place un processus itératif de gestion de projets !" }, { "type": "paragraph", "text": "À la recherche d'une plateforme de gouvernance projet qui vous aide à préparer et animer votre prochain PI SAFe ? <a href=\"https://airsaas.io/fr/\" target=\"_blank\">Découvrez Airsaas, l'outil préféré des PMO et DSI</a>, qui les aide à visualiser en temps réel leur roadmap macro et leur capacité par équipe." }], "toc": [{ "label": "Qu'appelle-t-on PI SAFe ?", "href": "#quappelle-t-on-pi-safe", "level": 2 }, { "label": "8 essentiels pour réussir votre PI Planning", "href": "#8-essentiels-pour-reussir-votre-pi-planning", "level": 2 }], "faq": [], "related": [] }, { "slug": "pilotage-de-projet", "skip": false, "meta": { "title": "À quoi ressemble le pilotage de projet moderne ?", "h1": "À quoi ressemble le pilotage de projet moderne ?", "description": "Pandémie, guerre des talents IT et explosion des projets transverses ont créé un contexte de sables mouvants pour les organisations souhaitant un pilotage de projet plus efficace.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f7c31438b271d7e45c638a_pilotage-projet.jpg", "alt": "Gestion de Projets" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "4/8/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "4/8/2022" }, "blocks": [{ "type": "paragraph", "text": "Pandémie, guerre des talents IT et explosion des projets transverses ont créé&nbsp;<strong>un contexte de sables mouvants</strong> pour les organisations&nbsp;souhaitant un pilotage de projet plus efficace avec des méthodes agiles, traditionnelles ou hybrides." }, { "type": "paragraph", "text": "Ce fameux monde VICA (Volatile, Incertain, Complexe et Ambigu) est bien là ! Ajoutez-y une pincée d'intelligence artificielle, une&nbsp;vague de Grande Démission,&nbsp;et une&nbsp;culture projet super hétérogène&nbsp;: vous obtiendrez un contexte de travail complexe, ou, pour rester positif, passionnant !" }, { "type": "paragraph", "text": "Dans ces conditions, avant même de penser à s'adapter au mieux, l'art de bien piloter un projet nécessitera une compétence clé : le discernement. Cet article porte cette intention : vous&nbsp;aider à vous orienter. Contribuer à une meilleure lecture de ce qui se joue, pour ne verser ni dans le \"positivisme\" ni dans la défiance facile." }, { "type": "paragraph", "text": "Oui : <strong>le&nbsp;pilotage de projet aussi est une activité en transition qui nécessite des mises à jour de nos approches et compétences ainsi que des partages d'expériences</strong>." }, { "type": "paragraph", "text": "Quelles croyances doit-on revisiter pour moins subir et échouer à délivrer des projets ? Qu'est-ce qu'il faut ajouter pour garder du plaisir et de l'efficience dans la démarche ? Quelles sont les tendances intéressantes à surveiller pour suivre et anticiper les évolutions du pilotage de projet ? Et enfin quelles sont les 7 étapes clés pour faire progresser la culture projet de l'entreprise ?" }, { "type": "paragraph", "text": "L'article à lire pour enlever le frein à main de votre <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet</a> et le limiteur de vitesse de transformation de l'entreprise !" }, { "type": "heading", "level": 2, "id": "partage-des-taches-et-mythe-du-chef-de-projet-heros-solitaire-deux-croyances-a-revisiter", "text": "Partage des tâches et mythe du chef de projet héros solitaire : deux croyances à revisiter" }, { "type": "heading", "level": 3, "id": "sortir-du-partage-des-taches-en-silos-moa-amoa-moe", "text": "Sortir du partage des tâches en silos MOA-AMOA-MOE" }, { "type": "paragraph", "text": "En gestion de projet, l'héritage d'années de MOA/MOE et de pratique avec des référentiels d'outils de gestion de projets type \"à la tâche\" ont conditionnés notre vision de la réalisation en liste des tâches, planning et ressources." }, { "type": "paragraph", "text": "On a longtemps cru qu'en se répartissant des tâches dans un planning, \"ça passerait\".&nbsp;On a aussi misé sur LE super Project Manager pour la réussite. Le Top Gun rassurant pour piloter un projet, mais fonctionnant en mode silo entre MOA/MOE..." }, { "type": "paragraph", "text": "Et, à la fin, le projet ne correspondait même pas au besoin réel. L'adoption des outils et le ROI étant le plus souvent négligeables. Un comble quand on connaît l'énergie et le talent déployés." }, { "type": "paragraph", "text": "Dans la vraie vie,&nbsp;on réussit une gestion de projet grâce à l'engagement individuel et collectif,<strong>&nbsp;</strong>versus une approche centrée sur le suivi et contrôle des tâches. 80 % des projets n'ont pas besoin d'une planification type Gantt&nbsp;aujourd'hui. Une équipe engagée suffira !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62eae08ccb335202a139b71a_gantt-rassure-equipe-assure.png", "alt": "Citation Ludovic Lajoie - Gantt Project", "caption": "Merci Ludovic. Cette citation cadeau est à mettre en page de garde de vos supports Coproj/Copil" }, { "type": "paragraph", "text": "Préparer un énième planning de Gantt ne vous protégera pas contre une livraison, en retard, hors budget, d'un projet sans adoption des utilisateurs." }, { "type": "quote", "text": "Quand on a vécu depuis plusieurs dizaines années avec MOA-AMOA-MOE, il a fallu faire sauter aussi les barrières historiques des silos qui existaient.&nbsp; Nous avons mis en place des formations sur l'efficience des développements pour les membres de la DSI et pour les métiers. Pour expliquer les rôles, les attendus et les engagements de chacun.", "author": "Benito Diz — CIO - DSI, Invité épisode 9 Podcast CIO Révolution by AirSaas" }, { "type": "heading", "level": 3, "id": "la-fin-du-mythe-du-chef-de-projet-heros-solitaire", "text": "La fin du mythe du chef de projet héros solitaire" }, { "type": "paragraph", "text": "Cette responsabilité est trop lourde pour qu'une seule personne puisse tout faire et mener des travaux de plus en plus complexes et de résoudre des problèmes difficiles presque quotidiennement." }, { "type": "insight-callout", "label": "À retenir", "html": "<blockquote><p>Je crois beaucoup à la dualité du pilotage, car avoir une direction qui n'est ni métier, ni DSI, permet de rester neutre et d'avoir un regard critique. Tout doit être dans l'explicite, les rôles doivent concrètement être définis à l'avance et la confiance doit régner.</p></blockquote><p><strong>Frédéric Riou</strong> — CIO Biogaran, Invité épisode 29 Podcast CIO Révolution by AirSaas</p>" }, { "type": "paragraph", "text": "Aujourd'hui, le rôle du chef de projet s'est&nbsp;éloigné de quelqu'un qui peut cocher les actions et tâches comme terminées&nbsp;sur un diagramme de Gantt pour aller vers <strong>une</strong>&nbsp;<strong>position de leadership stratégique&nbsp;</strong>permettant d'effectuer des changements dans une organisation." }, { "type": "paragraph", "text": "Pour se résumer, nous partageons ici&nbsp;trois convictions&nbsp;:" }, { "type": "list", "ordered": false, "items": ["<strong>Un projet = une équipe.&nbsp;</strong>On réussit un projet grâce à l'engagement individuel et collectif sur des objectifs, pas sur le contrôle des tâches et de l'avancement de phases.", "<strong>La</strong>&nbsp;<strong>chefferie de projet</strong>&nbsp;<strong>= un co-pilotage métier/Tech/sponsor</strong>.", "Idéalement, un projet clé se réalise dans&nbsp;<strong>un espace-temps qui reste humain :</strong> des délais de 9 mois par exemple<strong> - </strong>comme une gestation !"] }, { "type": "heading", "level": 2, "id": "pilotage-hybride-et-outils-ppm-des-ingredients-cles-pour-reussir-le-pilotage-de-projet-transverse-aujourdhui", "text": "Pilotage hybride et outils PPM : des ingrédients clés pour réussir le pilotage de projet transverse aujourd'hui" }, { "type": "heading", "level": 3, "id": "les-methodes-hybrides-pour-faciliter-le-pilotage-projet", "text": "Les méthodes hybrides pour faciliter le pilotage projet" }, { "type": "paragraph", "text": "Le&nbsp;manifeste agile à déjà 20 ans !<strong>&nbsp;</strong>L'une des tendances de gestion de projet que nous constatons de plus en plus est l'acceptation que les approches de gestion hybrides sont la voie à suivre pour une meilleure exécution." }, { "type": "paragraph", "text": "Le \"full agile\" véritable peine à sortir du cadre des équipes IT/digitales.&nbsp;Dans ce contexte,&nbsp;<strong>le semi agile est une hybridation intéressante</strong>&nbsp;pour les entreprises recherchant une mise à jour méthodologique de leurs méthodes de livraison." }, { "type": "quote", "text": "Je ne parle pas d'agile mais d'efficience. Parce que je veux pas me reporter à des carcans, y compris le manifeste de 2001 : c'est pas le but de dire \"on fait de l'agile pour de l'agile, on fait du modèle en V pour du modèle en V, de l'API management pour de l'API management, du cloud pour du cloud\"… On fait quelque chose qui est compris par tout le monde et qui apporte une valeur ajoutée !", "author": "Benito Diz — CIO - DSI, Invité épisode 9 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "On visera toujours des itérations continues pour le développement avec une implication significative des clients dans les livrables à toutes les phases, mais gérées dans le cadre d'une structure de gouvernance et de décisions avec le comité de pilotage d'un projet." }, { "type": "paragraph", "text": "L'essor de la gestion de projet hybride est une bonne nouvelle parce que&nbsp; :" }, { "type": "list", "ordered": false, "items": ["La plupart des grandes organisations ne sont pas équipées pour gérer l'ensemble de leurs opérations dans un framework agile cohérent", "Les projets sont plus complexes que jamais. Ils impliquent beaucoup plus d'individus et expertise : plus que ce qui pourrait composer une équipe Scrum au sens strict&nbsp;!"] }, { "type": "heading", "level": 3, "id": "logiciel-de-gestion-de-portefeuille-projet-ppm-la-nouvelle-generation-est-la", "text": "Logiciel de gestion de portefeuille projet (PPM) : la nouvelle génération est là" }, { "type": "paragraph", "text": "Fini le pilotage avec&nbsp;un logiciel dédié, isolé de l'écosystème de l'entreprise ! Au fur et à mesure que notre environnement devient plus complexe, incertain - et disons-le, parfois&nbsp;politique&nbsp;– nous avons besoin de plus en plus d'outils nouvelle génération pour aider à réaliser des projets transverses dans ce type d'environnement et contraintes." }, { "type": "paragraph", "text": "L'usage d'une plateforme moderne permettra d'<strong>uniformiser les </strong><a href=\"https://www.airsaas.io/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\"><strong>cadrages</strong></a><strong>, le </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-suivi-de-projet-pour-garder-aligne-les-parties-prenantes\" target=\"_blank\"><strong>suivi des projets</strong></a><strong>, le reporting et la gouvernance.</strong>" }, { "type": "paragraph", "text": "(Note du rédacteur : Je vous propose de relire la phrase ci-dessus une seconde fois ! :-)" }, { "type": "paragraph", "text": "Oui&nbsp;: plus l'entreprise grandit&nbsp;et son volume de projet avec,&nbsp;plus la capacité de garder un niveau de communication clair, cohérent, simple d'accès pour tout le monde est clé. L'augmentation du nombre d'initiatives et de projets en cours, venant des métiers, rend la gestion de portefeuille utile voire indispensable pour de plus en plus d'organisation de toutes tailles." }, { "type": "paragraph", "text": "Les développeurs utilisent Jira, le marketing est fan de Trello, la direction de l'innovation est sur Wrike, la qualité est fan de ZenDesk, les RH utilisent Monday, la DSI est sur Teams.... Au secours<strong>&nbsp;: </strong>les silos sont de retour<strong>&nbsp;</strong>! L'enjeu est bien de<strong>&nbsp;proposer un outil macro, partagé&nbsp;ET&nbsp;qui se synchronise&nbsp;</strong>avec les autres plateformes utilisées au quotidien." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62eae1b4ab965deaa837fd03_synchro-outils-min.png", "alt": "AirSaas outil macro, partagé ET qui se synchronise avec les autres plateformes : idéal pour votre pilotage de projet", "caption": "AirSaas est un outil macro, partagé ET qui se synchronise avec les autres plateformes" }, { "type": "paragraph", "text": "Pour un vrai impact sur la réalisation de la transformation de l'entreprise, on cherchera à inclure et collaborer avec les différents métiers et parties prenantes dans un même espace-temps. L'objectif poursuivi étant d'y voir clair dans le périmètre pour faciliter la prise de décision,&nbsp;prioriser par la valeur,&nbsp;collaborativement&nbsp;et&nbsp;en continu. Tout un programme sans une plateforme adaptée !" }, { "type": "paragraph", "text": "Bonne nouvelle pour la fonction de pilote.&nbsp;<strong>L'automatisation et l'uniformisation du reporting</strong> sont accessibles et constituent désormais une vraie assistance au pilotage de projet. Une aide simple pour automatiser et simplifier les tâches répétitives à faible valeur ajoutée (par exemple la collecte des données, l'envoi d'un reporting flash, <a href=\"https://www.airsaas.io/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">l'identification des risques</a> et les ressaisies de données...)." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/616fd320191fb9e48982f69c_Export-flash.jpg", "alt": "Rapport flash - flash report - reporting projet", "caption": "Le pouvoir d'un reporting projet homogène et automatisé" }, { "type": "paragraph", "text": "Uniformiser la forme<strong>,</strong>&nbsp;c'est dire : on va se faciliter la vie pour piloter un projet, pour se comprendre quel que soit l'enjeu que nous affrontons. De quoi, en passant, réduire aussi la fatigue cognitive de tout le monde." }, { "type": "heading", "level": 3, "id": "la-matrice-de-knoster-la-recette-dun-changement-global-efficace", "text": "La matrice de Knoster : la recette d'un changement global efficace" }, { "type": "paragraph", "text": "Gardons bien en tête le côté complexe, humain et donc multifactoriel du pilotage d'un projet de transformation. C'est ce qui en fait la saveur !&nbsp;La <a href=\"https://agilityportal.io/blog/knoster-model-for-change\" target=\"_blank\">matrice de Knoster</a><strong> </strong>(cf tableau ci-dessous)<strong> </strong>propose une grille de lecture très pertinente, des modèles<strong>,&nbsp;</strong>pour faire un check des éléments et indicateurs indispensables d'un pilotage moderne." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62714b94e7e643ce851a39a2_matrice-knoster-projet-airsaas.jpg", "alt": "Matrice de Knoster conduite de changement", "caption": "Matrice de Knoster pour limiter faux départ, pagaille ou confusion dans le pilotage des projets" }, { "type": "list", "ordered": false, "items": ["<strong>Sans vision</strong>, on crée de la&nbsp;confusion&nbsp;au sein des parties prenantes d'un projet", "<strong>Sans savoir-faire</strong>, on engendre la<strong>&nbsp;</strong>peur", "<strong>Sans bénéfice au changement</strong>, on renforce la<strong>&nbsp;</strong>résistance", "<strong>Sans ressources humaines et financières</strong>, on génère de la<strong>&nbsp;</strong>frustration", "<strong>Sans plan d'actions</strong>&nbsp;projet structuré et suivi, on génère de la&nbsp;pagaille"] }, { "type": "heading", "level": 2, "id": "7-etapes-pour-faire-progresser-la-culture-projet-dans-son-entreprise-sans-y-laisser-3-ans-de-vie", "text": "7 étapes pour faire progresser la culture projet dans son entreprise (sans y laisser 3 ans de vie !)" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62eae4d2e5f84506331a2168_culture%20projet%20%20entreprise.jpeg", "alt": "Carte Mind map 7 étapes pour faire progresser la culture projet dans son entreprise", "caption": "Aide mémoire sur la culture projet" }, { "type": "heading", "level": 3, "id": "1-partager-le-diagnostic", "text": "1 - Partager le diagnostic" }, { "type": "paragraph", "text": "Il faut arriver à&nbsp;<strong>partager un même constat avec les équipes</strong>&nbsp;(projet, métier, direction) : il y a&nbsp;trop de sujets, tout le monde est sous l'eau, les gens demandent tout le temps \"où vous en êtes\". On est dans un RUN permanent. Ça rame..." }, { "type": "paragraph", "text": "🙍🏻‍♂️Si le constat n'est pas partagé, ça sera compliqué de dire \"on va changer nos méthodes de travail\". Ici l'enjeu est de créer les conditions et choisir un moment clé notamment pour libérer la parole sur le diagnostic." }, { "type": "heading", "level": 3, "id": "2-etablir-une-vision-commune-des-priorites", "text": "2 - Établir une vision commune des priorités" }, { "type": "paragraph", "text": "Définir avec le Codir / Copil ce qui est vital et ce qui ne l'est pas." }, { "type": "paragraph", "text": "🙍🏻♂️ Sinon vous allez encore vous retrouver avec une liste de 70 projets tous super importants, et une équipe de trois personnes pour les porter." }, { "type": "heading", "level": 3, "id": "3-avoir-un-bon-storytelling-des-programmes-de-transformation-axes-strategiques", "text": "3 - Avoir un bon storytelling des programmes de transformation / axes stratégiques" }, { "type": "paragraph", "text": "Par exemple : \"le programme d'excellence commerciale (projet CRM, projet analyse comportementale, projet analyse prédictive...) doit nous amener à rentrer dans le top 3 Européen\"." }, { "type": "paragraph", "text": "🙍🏻♂️ Sinon, au bout de quelques mois, les projets n'auront plus de sens, et le manque de motivation des équipes peut vite se faire ressentir." }, { "type": "heading", "level": 3, "id": "4-adopter-une-plateforme-pour-uniformiser-le-management-de-projets", "text": "4 - Adopter une plateforme pour uniformiser le management de projets" }, { "type": "paragraph", "text": "Commencez par mettre en place une plateforme comme AirSaas pour uniformiser le cahier des charges, les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-faire-un-bon-cadrage-projet-avec-les-metiers\" target=\"_blank\">cadrages projets</a>, le suivi des projets, le reporting et la gouvernance." }, { "type": "paragraph", "text": "🙍🏻♂️ Si les équipes ne sont pas toutes matures en gestion de projet, alors les mettre sur Jira sera l'échec assuré, tout comme essayer de leur faire faire un Gantt, essayer d'avoir des fiches de cadrage compréhensibles et bien pensées sur PowerPoint." }, { "type": "heading", "level": 3, "id": "5-definir-les-roles-la-comitologie-commune-les-regles-du-jeu", "text": "5 - Définir les rôles, la comitologie commune, les règles du jeu" }, { "type": "paragraph", "text": "C'est quoi un sponsor ? Un chef de projet ? Un référent métier ? Droits et devoirs de chacun ?" }, { "type": "paragraph", "text": "🙍🏻♂️Sans ça, personne ne sera responsable de rien." }, { "type": "heading", "level": 3, "id": "6-mettre-en-place-les-rituels", "text": "6 - Mettre en place les rituels." }, { "type": "paragraph", "text": "🙍🏻♂️Tous les mardis, réunion chef de projet + référent métier de cinq minutes par projet : décisions à prendre, point d'attention." }, { "type": "paragraph", "text": "Tous les&nbsp;vendredis, envoi du rapport flash<strong>&nbsp;</strong>à l'ensemble des parties prenantes" }, { "type": "paragraph", "text": "Tous les mois, Copil&nbsp;sur les&nbsp;enjeux du mois prochain&nbsp;et&nbsp;alignement&nbsp;sur le&nbsp;temps métiers disponible." }, { "type": "heading", "level": 3, "id": "7-parler-du-positif", "text": "7 - Parler du positif" }, { "type": "paragraph", "text": "🙍🏻♂️ OK il faut résoudre les problèmes, mais il faut surtout embarquer en continu les équipes. Alors&nbsp;parlez des succès, <a href=\"https://www.airsaas.io/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">communiquez-les</a><strong>.</strong>&nbsp;Donnez&nbsp;envie. Connaître et travailler sur les points forts des talents de l'équipe, c'est le secret !" }, { "type": "paragraph", "text": "Vous avez maintenant une vision mise à jour de ce qui se joue aujourd'hui dans le pilotage du projet. Prochaine étape proposée : zoomer sur un ingrédient clé - <a href=\"/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\"><strong>le jalon projet : une technique pour séquencer vos projets intelligemment.</strong></a>" }], "toc": [{ "label": "Partage des tâches et mythe du chef de projet héros solitaire : deux croyances à revisiter", "href": "#partage-des-taches-et-mythe-du-chef-de-projet-heros-solitaire-deux-croyances-a-revisiter", "level": 2 }, { "label": "Pilotage hybride et outils PPM : des ingrédients clés pour réussir le pilotage de projet transverse aujourd'hui", "href": "#pilotage-hybride-et-outils-ppm-des-ingredients-cles-pour-reussir-le-pilotage-de-projet-transverse-aujourdhui", "level": 2 }, { "label": "7 étapes pour faire progresser la culture projet dans son entreprise (sans y laisser 3 ans de vie !)", "href": "#7-etapes-pour-faire-progresser-la-culture-projet-dans-son-entreprise-sans-y-laisser-3-ans-de-vie", "level": 2 }], "faq": [], "related": [] }, { "slug": "plan-capacitaire", "skip": false, "meta": { "title": "7 étapes pour créer votre plan capacitaire sans vous arracher les cheveux", "h1": "7 étapes pour créer votre plan capacitaire sans vous arracher les cheveux", "description": "Découvrez les 7 étapes pour créer un plan capacitaire efficace : définition, méthodes, outils et bonnes pratiques pour optimiser vos ressources et réussir vos projets.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae3dd336808907b763784_7%20etapes.jpg", "alt": "" }, "author": { "category": "Gestion de projets" } }, "blocks": [{ "type": "paragraph", "text": "Imaginez votre portefeuille de projets comme un orchestre symphonique. Chaque projet est un instrument, et vous en êtes le chef d'orchestre. Pour créer une harmonie parfaite, vous devez connaître chaque instrument, sa portée, ses limites, et savoir comment les faire jouer ensemble." }, { "type": "paragraph", "text": "C'est là qu'intervient le plan capacitaire." }, { "type": "paragraph", "text": "Cet outil essentiel vous permet d'optimiser l'allocation de vos ressources, d'anticiper les goulots d'étranglement et de garantir le succès de vos projets." }, { "type": "paragraph", "text": "Prêt à devenir le maestro de votre propre orchestre de projets ? Plongez dans cet article et ses <strong>sept étapes pour créer votre propre plan capacitaire sans accroc</strong>." }, { "type": "heading", "level": 2, "id": "quest-ce-quun-plan-capacitaire", "text": "Qu'est-ce qu'un plan capacitaire ?" }, { "type": "paragraph", "text": "Le terme \"plan capacitaire\" est la traduction littérale de \"Capacity Planning\". Il s'agit d'une méthode dont l'objectif est d'<strong>aligner la capacité disponible dans l'entreprise</strong> (en termes de ressources humaines et matérielles) <strong>avec la demande</strong>." }, { "type": "paragraph", "text": "Cette méthode permet ainsi d'évaluer, de planifier, et de gérer toutes les ressources pour répondre à l'intégralité des besoins de votre portefeuille de projets." }, { "type": "paragraph", "text": "Pour le dire autrement : il s'agit de vérifier si la charge de travail que vous demandez à vos équipes pour mener vos projets passe ou non auprès des équipes, en fonction des tâches déjà prévues à leur planning." }, { "type": "paragraph", "text": "Si de nombreux DSI ou PMO utilisent le Capacity Planning, c'est parce qu'il permet notamment de :" }, { "type": "list", "ordered": false, "items": ["<strong>Augmenter les chances de réussir les projets</strong>. En limitant les goulots d'étranglement, vous évitez d'avoir affaire à des projets qui bloquent ou qui sont en retard.", "<strong>Optimiser les ressources à disposition </strong>pour mieux planifier les projets à venir, notamment les projets transverses.", "<strong>Améliorer la productivité</strong> des équipes au quotidien.", "<strong>Aligner l'utilisation des ressources avec la stratégie de l'entreprise </strong>et donc, accélérer la livraison de valeur.", "<strong>Se préparer à la variation de la demande </strong>dans le temps.", "<strong>Diminuer la frustration entre les équipes</strong>, et plus principalement dans le Codir", "<strong>Améliorer les relations entre les différents pôles</strong>. Vous pouvez enfin lancer les projets que tel métier demande depuis des mois sans relâche, sans pour autant surcharger les équipes. De quoi assainir plus d'une relation dans l'entreprise !"] }, { "type": "paragraph", "text": "<a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning-definition\" target=\"_blank\">Pour creuser la définition du plan capacitaire, rendez-vous sur notre article sur le sujet</a>." }, { "type": "heading", "level": 2, "id": "les-7-etapes-pour-creer-un-plan-capacitaire-efficace", "text": "Les 7 étapes pour créer un plan capacitaire efficace" }, { "type": "paragraph", "text": "À la recherche d'une méthode concrète pour créer votre Capacity Planning ? Vous êtes au bon endroit : voici les sept étapes par lesquelles passer pour obtenir un plan capacitaire efficace et aussi exact que possible !" }, { "type": "heading", "level": 3, "id": "etape-1-definir-vos-besoins-prioritaires", "text": "Étape 1 : Définir vos besoins prioritaires" }, { "type": "paragraph", "text": "Toute bonne gestion de la capacité de production doit commencer par <strong>s'appuyer sur la vision stratégique de l'entreprise</strong>. L'idée est de vous demander quelles sont les priorités, les projets qui permettront d'apporter le plus de valeur à l'entreprise sur la période à venir. C'est cette direction stratégique qui va vous permettre ensuite d'orchestrer au mieux les ressources à votre disposition." }, { "type": "paragraph", "text": "Pour cela, vous aurez besoin d'aligner l'intégralité de vos parties prenantes (direction et métiers) sur ces priorités. Le but : créer un plan capacitaire qui mette tout le monde d'accord." }, { "type": "paragraph", "text": "Facile, sur le papier… mais, dans les faits, avoir un plan stratégique s'avère très compliqué ! Tout bouge tellement vite, que vous peinez à poser un cadre. Alors comment faire ?" }, { "type": "list", "ordered": false, "items": ["Commencez par demander à votre Direction Générale de <strong>définir ce qu'est un \"projet vital pour l'organisation\"</strong>. Cette définition servira de cadre premier.", "Puis, <strong>demandez à chaque direction métier de définir ses priorités</strong>. Attention : chacune des directions doit comprendre qu'il ne peut pas y avoir 10 P0 (priorités zéro) ! Demandez-leur clairement de définir une P0, une P1, une P2, et ainsi de suite.", "Enfin, vous pourrez revenir vers la Direction avec ces priorités par métiers, pour lui demander de définir <strong>les priorités à l'échelle de l'organisation</strong>."] }, { "type": "paragraph", "text": "Ce faisant, vous aurez un bon cadre pour commencer, sans avoir besoin de créer une usine à gaz pleine d'équations !" }, { "type": "paragraph", "text": "Gardez en tête que prioriser, c'est forcément renoncer (ou, tout du moins, reporter à plus tard). Ainsi, un plan capacitaire est nécessairement politique, et demande une véritable stratégie d'alignement des différentes parties prenantes !" }, { "type": "paragraph", "text": "À l'issue de cette étape, vous avez en tête les lignes directrices que doit suivre votre plan capacitaire." }, { "type": "heading", "level": 3, "id": "etape-2-analyser-la-capacite-actuelle", "text": "Étape 2 : Analyser la capacité actuelle" }, { "type": "paragraph", "text": "Dans un deuxième temps, faites un <strong>inventaire des ressources disponibles </strong>dans votre entreprise. Pensez ici à la fois en termes de ressources humaines et financières." }, { "type": "paragraph", "text": "Pour vos projets transverses, demandez à chacune des équipes impliquées de déclarer leur capacité sur la période à venir. Vous pouvez leur proposer de déclarer cette capacité sous forme de temps/homme, ou bien sous forme de t-shirt sizing, si les responsables ont du mal à estimer précisément la capacité de leurs équipes." }, { "type": "paragraph", "text": "À cette étape, vous devez veiller à bien identifier le temps de run et le temps de build - le run étant toujours incompressible." }, { "type": "paragraph", "text": "La clé pour réussir cette étape ? Penser à la maille de l'équipe, et non de l'individu. Cela vous permettra de définir un capacitaire à l'échelle de votre organisation, sans vous arracher les cheveux à rentrer dans le détail micro." }, { "type": "paragraph", "text": "Considérez qu'on entend ici par \"équipe\" un rassemblement de compétences homogènes. En ce sens, dans le pôle IT, une équipe peut être par exemple l'équipe IT Sécurité, l'équipe IT Data, ou l'IT Intégration. Dans le service marketing, on différenciera l'équipe marketing Content, l'équipe marketing CRM, et les autres membres du pôle, rassemblés dans une équipe \"marketing Autres\"." }, { "type": "paragraph", "text": "L'objectif de cette étape : vous permettre d'<strong>avoir une idée aussi précise que possible de la manière dont les compétences sont utilisées actuellement</strong>, et du temps qui leur reste à déployer sur d'autres projets." }, { "type": "heading", "level": 4, "id": "comment-aider-les-equipes-a-calculer-le-temps-de-run-et-de-build", "text": "Comment aider les équipes à calculer le temps de run et de build ?" }, { "type": "paragraph", "text": "Pour de nombreux pôles, il sera sans doute complexe de vous annoncer leur temps de run et leur temps de build. Mais bonne nouvelle : nous avons une technique pour que vous les aidiez !" }, { "type": "paragraph", "text": "Commencez par leur demander d'observer toutes les tâches que l'équipe fait au quotidien, et d'essayer de les bloquer dans des demi-journées de la semaine. Plutôt que de tout traiter instantanément, il s'agit pour ces équipes de fonctionner par \"batch\"." }, { "type": "paragraph", "text": "Chaque semaine, les équipes essayent de s'améliorer sur chacun de leurs batchs. Et, au bout de quatre semaines, elles peuvent constater combien de demi-journées elles doivent immobiliser pour gérer le run quotidien - et donc, combien de temps elles peuvent dégager pour le build." }, { "type": "heading", "level": 3, "id": "etape-3-gerer-la-demande-soit-structurer-pour-eviter-la-dispersion", "text": "Étape 3 : Gérer la demande - soit structurer pour éviter la dispersion" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67d14814ad46b55ee85c5eed_gestion-de-la-demande.png", "alt": "" }, { "type": "paragraph", "text": "La gestion de la demande repose sur un principe simple : <strong>créer les conditions pour exprimer les besoins de manière efficace</strong>, sans perdre de temps dans des processus inutiles. Trop souvent, les équipes métiers inondent l'IT de demandes mal cadrées, via des emails, des tickets ou des discussions informelles, ce qui entraîne une perte de temps et une frustration généralisée. Structurer cette gestion permet de clarifier les priorités, d'éviter le gaspillage d'énergie et de concentrer les efforts sur les projets réellement utiles." }, { "type": "heading", "level": 4, "id": "le-duo-it-domaine-metier-ou-it-responsable-solution", "text": "Le duo IT - Domaine Métier ou IT - Responsable Solution" }, { "type": "paragraph", "text": "La première étape consiste à organiser la gestion des demandes autour de <strong>duos structurés</strong>." }, { "type": "paragraph", "text": "Selon les domaines, il peut s'agir :" }, { "type": "list", "ordered": false, "items": ["<strong>D'un binôme IT - Domaine Métier</strong> (exemple : IT RH et Responsable RH, IT Finance et Responsable Finance).", "<strong>D'un binôme IT - Responsable Solution</strong> (exemple : IT CRM et Responsable Solution CRM, IT WMS et Responsable WMS)."] }, { "type": "paragraph", "text": "Ce duo joue un rôle clé en tant que filtre et point d'entrée unique pour toutes les demandes de leur périmètre." }, { "type": "paragraph", "text": "Il se réunit toutes les deux semaines pour :" }, { "type": "list", "ordered": false, "items": ["<strong>Centraliser</strong> les demandes et éviter qu'elles soient disséminées un peu partout.", "<strong>Filtrer et disqualifier</strong> celles qui ne sont pas alignées avec les priorités stratégiques.", "<strong>Structurer</strong> les demandes avant qu'elles ne soient étudiées plus en détail."] }, { "type": "paragraph", "text": "Ce mode de fonctionnement oblige les métiers à <strong>prendre leurs responsabilités</strong> en ne lançant que des demandes réellement pertinentes. L'IT ne devient plus un simple exécutant mais un véritable partenaire, capable d'apporter de la valeur en aidant à structurer les besoins dès le départ." }, { "type": "heading", "level": 4, "id": "un-pre-sizing-rapide-et-pragmatique", "text": "Un pré-sizing rapide et pragmatique" }, { "type": "paragraph", "text": "Une fois une demande validée par le duo, elle passe dans une phase de<strong> pré-sizing macro</strong>, qui permet d'obtenir une estimation rapide de son impact." }, { "type": "paragraph", "text": "Ce travail n'est pas réalisé par une seule personne mais par un <strong>groupe de quelques experts</strong> ayant une bonne vision des capacités et du fonctionnement des équipes." }, { "type": "paragraph", "text": "Leur mission est de :" }, { "type": "list", "ordered": false, "items": ["<strong>Définir quelles équipes</strong> doivent être impliquées.", "<strong>Estimer le volume d'effort global</strong> (sans entrer dans le détail des tâches).", "<strong>Vérifier la faisabilité</strong> en fonction des contraintes existantes"] }, { "type": "paragraph", "text": "L'objectif ici est d<strong>'aller vite</strong>. Pas question de lancer une étude approfondie à ce stade. L'idée est de donner une première évaluation permettant aux métiers de <strong>se confronter à la réalité</strong>. Un directeur de domaine a souvent tendance à penser que tout est simple et rapide. En lui donnant une estimation macro, il peut mieux prioriser ses demandes en fonction des efforts nécessaires. Cette étape permet également d'<strong>écarter rapidement </strong>les projets qui n'ont aucun sens ou qui ne sont pas faisables dans un horizon raisonnable." }, { "type": "heading", "level": 4, "id": "lintegration-et-larbitrage-dans-la-roadmap", "text": "L'intégration et l'arbitrage dans la roadmap" }, { "type": "paragraph", "text": "Une fois une demande qualifiée et estimée, elle doit être <strong>intégrée dans la roadmap globale</strong>. L'objectif est d'éviter l'effet \"pile infinie\" où des projets sont validés mais jamais réalisés faute de place dans le planning." }, { "type": "paragraph", "text": "Cette étape repose sur plusieurs principes :" }, { "type": "list", "ordered": false, "items": ["<strong>Découper le projet</strong> en phases claires pour faciliter son absorption.", "<strong>Intégrer une logique capacitaire</strong> : vérifier si les équipes ont réellement la bande passante pour mener le projet.", "<strong>Arbitrer face aux autres priorités</strong> : un projet peut être techniquement faisable, mais s'il n'a pas de place dans le plan d'exécution, il ne sert à rien de le garder en suspens."] }, { "type": "paragraph", "text": "Cette phase permet de transformer une simple demande en un projet cadré et réalisable, avec une vision claire sur son impact et son échéance." }, { "type": "heading", "level": 4, "id": "en-somme-un-processus-clair-et-efficace", "text": "En somme : un processus clair et efficace" }, { "type": "list", "ordered": false, "items": ["<strong>Le duo IT - Domaine Métier ou IT - Responsable Solution </strong>centralise et filtre les demandes.", "<strong>Le pré-sizing rapide</strong> par un groupe d'experts donne une estimation macro et élimine les demandes non viables.", "<strong>L'intégration dans la roadmap</strong> priorise et assure que les projets sont réellement exécutables."] }, { "type": "paragraph", "text": "Avec cette approche, la gestion de la demande devient plus fluide, plus transparente et plus efficace. L'IT cesse d'être un simple réceptacle de demandes et devient un acteur stratégique dans la sélection et la structuration des projets.<br>Qui plus est, le fait de planifier votre portfolio de projets sur une période longue comme le trimestre, le semestre ou le Program Increment, crée une pression positive dans toute l'organisation. Chaque équipe va faire en sorte de finir son projet avant la prochaine réunion, et fera l'effort de bien cadrer en amont ses besoins spécifiques pour la période à venir. Que du bon !" }, { "type": "heading", "level": 3, "id": "etape-4-identifier-les-ecarts-entre-capacite-et-demande", "text": "Étape 4 : Identifier les écarts entre capacité et demande" }, { "type": "paragraph", "text": "Ici, l'objectif est de <strong>comparer la capacité actuelle des équipes avec la demande prévue</strong>." }, { "type": "paragraph", "text": "Pour ce faire, mettez en évidence les goulots d'étranglement et les zones où les ressources sont en surplus, pour les équilibrer ensuite au vu des projets à mener." }, { "type": "paragraph", "text": "Notez que cette étape peut également être réalisée collectivement, pendant votre Quarter Plan ou <a href=\"http://www.airsaas.io/fr/gestion-de-projet/pi-planning\" target=\"_blank\">PI Planning</a>. Au vu des priorités de chaque parties prenantes, vous déterminez pendant cette réunion ce qui est ou non faisable à l'échelle du trimestre." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02619d9ea0f26bb542e01_capacitaire-equipes.png", "alt": "" }, { "type": "inline-cta", "label": "Réservez votre démo de 30 min", "href": "/fr/meetings-pages" }, { "type": "heading", "level": 3, "id": "etape-5-implementer-votre-plan-capacitaire", "text": "Étape 5 : Implémenter votre plan capacitaire" }, { "type": "paragraph", "text": "Voici venue l'étape où vous formalisez réellement votre plan capacitaire." }, { "type": "paragraph", "text": "Pour bien équilibrer la capacité et la demande, plusieurs options s'offrent à vous. Vous pouvez :" }, { "type": "list", "ordered": false, "items": ["<strong>Ajuster la capacité</strong>, en recrutant des ressources humaines en plus, en formant certains collaborateurs à des compétences dont vous manquez, en externalisant la production de certains livrables, ou encore en déployant de nouvelles technologies.", "<strong>Moduler la demande</strong>, en priorisant certains projets dans le temps ou en reportant certains livrables à une période ultérieure. Là encore, si vous fonctionnez selon la méthode du PI Planning ou du Quarter Plan, cette stratégie aura été mise en place collectivement pendant le rassemblement de toutes vos parties prenantes."] }, { "type": "paragraph", "text": "Souvent, la création d'un plan capacitaire mélange les deux options. Ainsi, vous concevez un plan capacitaire sur-mesure, où vous ajoutez des ressources ici et enlevez des compétences là, pour faire passer en priorité les projets qui apportent le plus de valeur ajoutée à l'entreprise entière." }, { "type": "paragraph", "text": "Une fois votre plan capacitaire bien équilibré, <strong>déployez les actions identifiées pour réduire les écarts entre capacité et demande</strong>. Selon les stratégies décidées, cela peut demander de mettre en place un plan de recrutement ou de formation, trouver les ressources externes nécessaires, mettre à jour la roadmap du portefeuille de projet…" }, { "type": "paragraph", "text": "N'hésitez pas à mettre en place des outils pour suivre la mise en œuvre de votre plan capacitaire. Bonne nouvelle : on vous donne plus d'informations sur le sujet dans la dernière partie de cet article." }, { "type": "heading", "level": 3, "id": "etape-6-suivre-et-ajuster-en-continu", "text": "Étape 6 : Suivre et ajuster en continu" }, { "type": "paragraph", "text": "Un plan capacitaire est un document nécessairement mouvant, au fil des changements dans la demande et dans les ressources humaines ou matérielles." }, { "type": "paragraph", "text": "Mettez donc en place des KPIs pour évaluer l'efficacité de votre Capacity Planning, comme :" }, { "type": "list", "ordered": false, "items": ["<strong>Le taux d'avancement du Quarter plan </strong>", "<strong>Le taux d'achèvement des projets</strong> selon les budgets et les deadlines prévus", "<strong>Le taux d'interruption ou de retard</strong> sur les projets qui serait lié à une mauvaise planification de la capacité", "<strong>Le niveau de satisfaction</strong> de vos parties prenantes (collaborateurs et clients) vis-à-vis de votre plan"] }, { "type": "paragraph", "text": "Puis, en suivant ces KPIs, repérez en continu des pistes d'optimisation de votre plan capacitaire. Ajustez-le régulièrement en fonction des changements dans la demande ou les ressources, et en mettant en place des points de contrôle avec les différentes parties prenantes." }, { "type": "heading", "level": 3, "id": "etape-7-lancer-votre-journee-capacitaire", "text": "Étape 7 : Lancer votre journée Capacitaire" }, { "type": "paragraph", "text": "Et peut-être le plus important : la <strong>journée Quarter Plan </strong>est un moment de <strong>resynchronisation collective </strong>sur ce qui est réellement faisable ou non pour le prochain trimestre. Trop souvent, les équipes avancent avec des priorités mal alignées, des contraintes mal comprises et des décisions prises en silos. Cet événement interne vise justement à <strong>casser ces silos</strong> en permettant aux collaborateurs de se revoir, d'échanger librement et d'ajuster ensemble leurs engagements." }, { "type": "paragraph", "text": "Au-delà de la planification, cette journée offre un <strong>temps précieux pour se rencontrer</strong>, partager les réalités du terrain et résoudre des problématiques opérationnelles qui ne trouvent pas toujours leur place dans le flot quotidien des réunions en visio ou des discussions asynchrones. C'est aussi un moment où l'on prend <strong>conscience des capacités réelles </strong>des équipes, en confrontant les ambitions aux ressources disponibles." }, { "type": "paragraph", "text": "Le format physique est clé : il crée un lien humain fort, facilite les discussions franches et ancre les décisions dans une dynamique collective. À l'ère du travail hybride et de l'isolement digital, ce type d'événement devient indispensable pour recréer de la cohésion, <strong>donner du sens aux priorités</strong> et s'assurer que le plan du prochain trimestre repose sur un engagement partagé et réaliste." }, { "type": "paragraph", "text": "Bravo : vous avez mis en place un process de Capacity Planning bien huilé !" }, { "type": "heading", "level": 2, "id": "quels-outils-pour-creer-votre-capacity-planning", "text": "Quels outils pour créer votre Capacity Planning ?" }, { "type": "paragraph", "text": "Vous l'avez lu plus haut : votre plan capacitaire demande à être revu régulièrement, à l'aune de la variation de la demande et des ressources disponibles. Cet outil si utile peut alors devenir rapidement un casse-tête, si vous ne disposez pas d'un outil collaboratif, où vous pouvez regrouper à la fois le suivi de vos projets au niveau macro et la fluctuation de la capacité disponible." }, { "type": "paragraph", "text": "Chez Airsaas, nous avons un parti pris : celui de <strong>préférer un capacitaire approximativement juste plutôt que précisément faux</strong>." }, { "type": "paragraph", "text": "D'où la création de notre logiciel de gestion de portefeuille de projet, qui vous permet de créer un plan capacitaire par équipe, sur un temps plutôt long (trimestre, semestre, ou PI). Votre Capacity Planning devient alors plus simple à maîtriser, et se focalise sur le build plutôt que sur la capacité de chaque individu." }, { "type": "paragraph", "text": "Comment ça fonctionne ? Chaque équipe déclare sa capacité dans Airsaas, et le DSI ou PMO récolte toute la demande à l'échelle de l'entreprise. Par la suite, la vue Capacitaire de l'outil permet de savoir précisément quels livrables mettent à mal l'avancement de vos projets, quelle capacité vous avez dans chaque équipe, et quels sont vos besoins en ressources humaines supplémentaires." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02737c3f7b9a4eb992582_capacitaire-airsaas.png", "alt": "" }, { "type": "paragraph", "text": "Airsaas devient ainsi votre outil de capacitaire macro - ce qui ne vous empêche pas ensuite, si vous le souhaitez, de décliner votre Capacity Planning à l'échelle de la personne sur deux à trois mois maximum." }, { "type": "paragraph", "text": "En somme : Airsaas est l'outil collaboratif qui vous aide à assurer une gestion de la capacité de production, en alignant toutes les parties prenantes sur les priorités stratégiques de l'entreprise." }, { "type": "paragraph", "text": "Envie de tester la solution ? <a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">Découvrez la fonctionnalité \"plan capacitaire\" d'Airsaas, et demandez une démo à l'un de nos experts !</a>" }], "toc": [{ "label": "Qu'est-ce qu'un plan capacitaire ?", "href": "#quest-ce-quun-plan-capacitaire", "level": 2 }, { "label": "Les 7 étapes pour créer un plan capacitaire efficace", "href": "#les-7-etapes-pour-creer-un-plan-capacitaire-efficace", "level": 2 }, { "label": "Quels outils pour créer votre Capacity Planning ?", "href": "#quels-outils-pour-creer-votre-capacity-planning", "level": 2 }], "faq": [], "related": [] }, { "slug": "plan-de-communication-projet", "skip": false, "meta": { "title": "Plan de communication projet : comment éviter l'échec ?", "h1": "Plan de communication projet : comment éviter l'échec ?", "description": "Découvrez comment concevoir un plan de communication projet efficace : principes fondamentaux, usages avancés, meilleures stratégies, pratiques et erreurs courantes.", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "6/4/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3739f88c0c35815049633_Project%20image-min.jpg", "alt": "" }, "publishedDate": "6/4/2022" }, "blocks": [{ "type": "paragraph", "html": "<strong>99 % des échecs projets sont liés à un mauvais plan de communication !</strong>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62456551174d9fb320898d56_dsi-com-projet.png", "alt": "Illustration d'un DSI sans plan de communication projet ... découvrant l'existence d'AirSaas trop tard :)", "caption": "DSI après un bad buzz de com... découvrant qu'AirSaas existait ;-)" }, { "type": "paragraph", "html": "Cette statistique du \"Totally Subjective Institute\" est certes invérifiable. Néanmoins les DSI expérimentés nous le disent, les actions de communication efficaces constituent un aspect central de la gestion de projet. Car oui, selon l'adage, \"Si c'est flou… il y a un loup\" !" }, { "type": "paragraph", "html": "La <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet,</a> c'est avant tout conduire un groupe d'hommes et de femmes. Pour réussir cette mission <strong>le chef de projet doit être écouté et être à l'écoute</strong>. Et faire en sorte qu'à chaque étape ses messages clés soient entendus ! Tout cela en évitant le \"bad buzz\" autour du projet." }, { "type": "paragraph", "html": "Bienvenue dans un article pragmatique et stratégique sur l'art de concevoir un plan de communication projet adapté à votre contexte et à vos objectifs. Nous allons passer en revue les <strong>principes fondamentaux, les usages avancés, les meilleures stratégies de communication, les pratiques,</strong> <strong>et les erreurs courantes </strong>en la matière." }, { "type": "paragraph", "html": "Comme d'habitude, vous ne trouverez pas ici de recette magique pour réussir à tous les coups ! Vous y découvrirez <strong>des convictions fortes, des principes clés et quelques modèles éprouvés</strong> pour réfléchir à votre plan de communication projet générique, prêt à être customisé pour votre contexte." }, { "type": "heading", "level": 2, "id": "pourquoi-communiquer-autour-de-votre-projet", "text": "Pourquoi communiquer autour de votre projet ?" }, { "type": "paragraph", "html": "Selon l'étymologie, le terme « <em>communication</em> » provient du latin « communicare » qui signifie « mettre en commun »." }, { "type": "paragraph", "html": "En pratique, mettre en commun des charges, des difficultés 😱 , ça ne va pas motiver les équipes ! Et pourtant <strong>bien cadré, puis bien exécuté, un plan de communication interne efficace</strong> <strong>est un \"change manager\"</strong> à lui tout seul, qui vous aide à mieux piloter vos projets." }, { "type": "heading", "level": 3, "id": "communiquer-a-bon-escient-fait-baisser-la-pression-et-motive-les-parties-prenantes", "text": "Communiquer (à bon escient) fait baisser la pression et motive les parties prenantes" }, { "type": "paragraph", "html": "🥊 99 % des frictions proviennent du manque de compréhension du jeu de contrainte de la DSI et de la prise en compte des attentes des métiers." }, { "type": "paragraph", "html": "Pourtant, communiquer à intervalle régulier sur l'avancée, les problèmes rencontrés et les succès d'étape aide à diminuer les frustrations et l'impatience des personnes en demande." }, { "type": "paragraph", "html": "Moins de friction permet à votre équipe de projet d'avancer plus sereinement !" }, { "type": "paragraph", "html": "C'est le cercle vertueux : <strong>Confiance + Respect = Engagement !</strong>" }, { "type": "heading", "level": 2, "id": "par-ou-on-commence-comment-on-sy-prend", "text": "Par où on commence ? Comment on s'y prend ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6245d465d39322070c1c7ec3_plan-communication-projet.png", "alt": "Strat et Plan de communication projet", "caption": "Vous avez besoin d'une stratégie de communication projet !" }, { "type": "paragraph", "html": "Avant de vouloir jouer les \"ceintures noires\" de la communication d'entreprise, il vous faut maîtriser les fondamentaux de la planification !" }, { "type": "paragraph", "html": "De façon générale, l'approche méthodologique consiste à cadrer votre plan d'action sous tous ses angles : \"<strong>Sui dit quoi, à qui, pourquoi, quand, où ? Par quel moyen et avec quel effet ?</strong>\"." }, { "type": "paragraph", "html": "Cette approche est inspirée de la <a href=\"https://www.e-marketing.fr/Definitions-Glossaire/Modele-Lasswell-242443.htm\" target=\"_blank\">matrice de Lasswell;</a> du nom d'un politologue américain du XXe siècle qui a travaillé sur la communication de masse." }, { "type": "heading", "level": 3, "id": "la-matrice-cqqcoqp-pour-construire-des-plans-de-communication-tout-terrain", "text": "La matrice \"CQQCOQP\" : pour construire des plans de communication \"tout terrain\"" }, { "type": "heading", "level": 4, "id": "qui", "text": "Qui ?" }, { "type": "paragraph", "html": "Vous n'êtes pas seul à être responsable de la communication autour de votre projet !" }, { "type": "paragraph", "html": "<strong>Faites vous aider dans cette tâche par tous les contributeurs.</strong> Annoncée dès la phase de <a href=\"https://www.airsaas.io/gestion-de-projet/tout-savoir-sur-la-note-de-cadrage-projet\" target=\"_blank\">cadrage,</a> cette \"charge\" de communication sera partagée au sein du groupe. Un cercle/comité de communication peut être créé." }, { "type": "paragraph", "html": "Attention cependant à bien définir le processus de relecture et la personne qui aura le \"final cut\" sur les messages collectifs. A l'image d'une rédaction, où les journalistes dépendent d'un rédacteur en chef garant de la ligne éditoriale." }, { "type": "heading", "level": 4, "id": "quoi", "text": "Quoi ?" }, { "type": "paragraph", "html": "Définir selon vos objectifs de communication des formats \"types\" dans votre <a href=\"https://www.manager-go.com/gestion-de-projet/dossiers-methodes/plan-de-comm-projet\" target=\"_blank\">plan de communication projet</a>, pour créer des repères" }, { "type": "list", "ordered": false, "items": ["Un <strong>reporting général</strong> : planning prévisionnel, livrables, avancement du projet, retards, <a href=\"https://www.airsaas.io/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">risques</a>, décisions, <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">budget</a>", "Une <strong>reporting décisionnel</strong> automatique avec un email au format court et précis, une fois par semaine pour ne pas noyer sous les informations.", "Une <strong>communication plus \"légère\"</strong> sur les coulisses, les anecdotes..."] }, { "type": "heading", "level": 4, "id": "a-qui", "text": "A qui ? :" }, { "type": "paragraph", "html": "Un message, plusieurs variantes selon votre public-cible" }, { "type": "paragraph", "html": "<strong>Listez les parties prenantes</strong> au projet, voir quels sont leurs enjeux et leurs attentes." }, { "type": "paragraph", "html": "<strong>Tous les groupes ciblés sont-ils homogènes ?</strong> ou un groupe ciblé particulier doit-il être subdivisé (par importance, par implication vis-à-vis du projet, par aptitudes en informatique, par localisation,...) ?" }, { "type": "heading", "level": 4, "id": "pourquoi", "text": "Pourquoi ?" }, { "type": "paragraph", "html": "Servir vos objectifs directs et indirects dans chaque campagne de communication" }, { "type": "list", "ordered": false, "items": ["<strong>Renforcer les décisions</strong> prises", "<strong>Alerter sur des difficultés</strong>", "<strong>Informer de l'avancée</strong> d'un projet", "<strong>Obtenir un support</strong> et des moyens supplémentaires"] }, { "type": "heading", "level": 4, "id": "quand", "text": "Quand ?" }, { "type": "paragraph", "html": "La communication interne suit le rythme du projet, s'adapte et évolue au gré des étapes" }, { "type": "list", "ordered": false, "items": ["<strong>Au début, milieu et à la fin du projet :</strong> on prépare un dossier plus \"éditorialisé\", avec interviews, infographie, dans la newsletter, dans Teams...", "<strong>à chaque jalon,</strong> aux utilisateurs et parties prenantes : un article, un post simple, une communication générale dans Teams...", "<strong>Toutes les semaines, aux parties prenantes :</strong> un reporting décisionnel automatique avec un email au format court et précis, pour ne pas noyer vos lecteurs sous les informations."] }, { "type": "heading", "level": 4, "id": "comment-par-quel-moyen", "text": "Comment ? Par quel moyen ?" }, { "type": "paragraph", "html": "Trois critères sont à retenir pour créer votre contenu à communiquer : utilité, clarté et concision." }, { "type": "list", "ordered": false, "items": ["<strong>Utilité</strong> ? Centrez votre communication sur la valeur ! Parlez des gains attendus de ce qui va changer au quotidien pour chacun.", "<strong>Clarté</strong> ? On n'oublie très souvent de rappeler, outre ce que le projet va \"délivrer\", il est fondamental de souligner clairement ce qu'il ne vas pas livrer. Agir par le \"détour\" est souvent un levier très impactant en communication. Les équipes apprécient la communication authentique !", "<strong>Concision</strong> ? Less is more ! Et une image vaut mille mots !"] }, { "type": "heading", "level": 4, "id": "ou", "text": "Où ?" }, { "type": "paragraph", "html": "Un canal = un usage" }, { "type": "paragraph", "html": "Avec la multiplication des canaux de communication, il est plus que jamais intéressant de s'accorder et choisir vos meilleurs \"médias\", moyens de communication, en fonction de l'impact souhaité, et de \"charter\" vos échanges." }, { "type": "heading", "level": 2, "id": "au-dela-des-basiques-les-cinq-hacks-pour-construire-un-plan-de-communication-projet-moderne", "text": "Au delà des basiques : les cinq hacks🔥 pour construire un plan de communication projet moderne" }, { "type": "heading", "level": 3, "id": "1-le-rapport-flash-hebdomadaire-ou-lart-de-la-communication-continue", "text": "1. Le rapport flash hebdomadaire : ou l'art de la communication continue" }, { "type": "figure", "src": "https://www.youtube.com/embed/DJHyOpzt61I", "alt": "AirSaas.io - Uniformisez le reporting projet", "caption": "AirSaas.io - Uniformisez le reporting projet" }, { "type": "paragraph", "html": "Supports de communication idéaux, <strong>les \"rapports flash\"</strong> sont cruciaux pour une meilleure implication des parties prenantes de l'entreprise et par conséquent pour la réussite de vos projets. Ils viennent <strong>compléter un bon </strong><a href=\"https://www.airsaas.io/gestion-de-projet/le-pilotage-de-projet-en-2023\" target=\"_blank\"><strong>pilotage</strong></a><strong> et suivi de planning.</strong>" }, { "type": "paragraph", "html": "L'envoi d'un rapport flash hebdomadaire permet de <strong>répondre à trois enjeux</strong> :" }, { "type": "list", "ordered": true, "items": ["<strong>Partager des informations de façon structurée</strong> auprès des parties prenantes.", "Un enjeu \"masqué\": <strong>se prémunir du fait d'entendre \"Ah ? je ne savais pas !\"</strong>", "Et enfin le fait d'avoir une fréquence fixe, <strong>donne le \"tempo\" et permet conserver la mobilisation</strong> des équipes."] }, { "type": "paragraph", "html": "👩‍🍳 Astuce du chef : Au bout de quelques itérations de cette \"routine\", revenir vers les parties prenantes pour valider que la communication projet leur convient. A l'aide d'une simple question ouverte : \"Est ce que la manière de communiquer correspond a ton besoin d'informations ?\"" }, { "type": "paragraph", "html": "🕵️♂️ Cette notion de communication continue a été évoquée dans notre article sur le comité de pilotage : \"Le meilleur moyen de ne pas prendre les acteurs du <a href=\"https://www.airsaas.io/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">COPIL</a> au dépourvu, c'est de communiquer en continu sur l'avancée du projet\"." }, { "type": "heading", "level": 3, "id": "2-avoir-des-canaux-cibles-et-frequences-bien-identifiees", "text": "2. Avoir des canaux, cibles et fréquences bien identifiées" }, { "type": "paragraph", "html": "Pour <strong>éviter le piège du groupe de key user trop restreint,</strong> n'oubliez pas de vous adresser, outre ceux qui sont dans le projet, à tous les futurs utilisateurs qui vont être impactés. En remontant par exemple sur votre plateforme Teams ou autre, tous les 15 jours, les informations clés. Pour être certains qu'on touche vraiment la cible. ✅" }, { "type": "paragraph", "html": "On peut par exemple découper son plan de communication avec :" }, { "type": "list", "ordered": false, "items": ["<strong>Sur Teams, une communication des informations \"larges\"</strong> auprès de l'ensemble des personnes qui seront concernées par les résultats du projets.", "Et <strong>pour l'équipe projet l'envoi de façon régulière à l'ensemble des parties prenantes</strong> d'un <a href=\"https://www.airsaas.io/fr/solution/flash-report\" target=\"_blank\">rapport flash</a> au format PowerPoint <strong>grâce à un un outil dédié comme AirSaas</strong>."] }, { "type": "paragraph", "html": "☝️ Attention à charter vos canaux et annoncer vos conditions d'utilisation pour éviter une dérive des conversations." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f3717143f25951912a43b2_3a770361-98b1-473c-999a-c38414ef659a.jpg", "alt": "Photo du Bistrot du coin pour illustrer les dérives de la communication via Teams entre autres", "caption": "Non \"charté\" votre plateforme Teams peut se transformer en bistrot du coin !" }, { "type": "paragraph", "html": "☝️ Et attention à varier les plaisirs : affiche projet, flyer d'info, e-mails de teasing, vidéo \"Loom\" démo, encart dans la newsletter d'entreprise, goodies au nom du projet, webinaire d'info collective, messages dans slack/teams, event de lancement... A chaque outil de communication projet ses avantages et inconvénients." }, { "type": "heading", "level": 3, "id": "3-propagez-les-bonnes-nouvelles-avec-une-communication-attractive", "text": "3. Propagez les bonnes nouvelles avec une communication attractive" }, { "type": "quote", "text": "\"La forme, c'est le fond qui remonte à la surface\".", "author": "Victor Hugo" }, { "type": "paragraph", "html": "La forme compte autant que le contenu. Rappelez vous les emballages de cartons de jouet à Noël, qui plaisent parfois plus que le cadeau lui même ! Soignez la forme, utilisez des images et infographies simples comme outils de communication." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f371c137dc7374b9618c93_4e191b37-561e-4fec-a1ca-ad8d2729082b.jpg", "alt": "usage teams et gif communication projet", "caption": "Valoriser ce qui marche, ce qui a fonctionné, c'est un axe clé de votre plan de communication projet. Cela passe aussi par les chefs de projets qui postent, des sponsors qui \"likent\" et commentent." }, { "type": "paragraph", "html": "Partager un succès avec une image c'est bien, <strong>valoriser un point de succès dans un message qui sera vu</strong> c'est mieux ! Pour cela, rien de tel que d'utiliser à bon escient un simple GIF animé par exemple. Pour que votre message soit vu et apprécié, un GIF, ça attire l'oeil !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62ea8fd3925c8b03320edd60_airsaas-partage-gif.jpg", "alt": "Usage point succès projet", "caption": "Une fonctionnalité AirSaas qui plaît beaucoup :-)" }, { "type": "paragraph", "html": "Dans le fil de discussion des projets sur AirSaas, vous pouvez ajouter un GIF pour partager un succès, féliciter un collègue... ça fait toute la différence !" }, { "type": "paragraph", "html": "Une communication variée voire \"décalée\" permettra de surprendre pour contribuer à éviter la démobilisation de tout le monde." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f372d750d8017a5a59a6ac_catadelacom-airsaas.jpg", "alt": "Photo d'illustration d'une voiture avec deux pioches plantées dans le capot", "caption": "Mélanger sérieux et humour : oui, et toujours avec modération et discernement" }, { "type": "heading", "level": 3, "id": "4-utiliser-chaque-jalon-projet-comme-un-point-succes", "text": "4. Utiliser chaque jalon projet comme un point succès" }, { "type": "paragraph", "html": "Les <a href=\"https://www.airsaas.io/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\"><strong>jalons</strong></a><strong> sont ce qui rythme les projets</strong>, ils permettent d'aligner les équipes sur les objectifs et découper les projets en plusieurs étapes clés." }, { "type": "paragraph", "html": "C'est donc l'opportunité de communication idéale pour donner des repères. N'oubliez pas qu'<strong>on est tous plus ou moins noyé par le flot d'informations</strong>. Cela va même dans certains cas jusqu'à l'\"infoxication\" !" }, { "type": "paragraph", "html": "Bref <strong>communiquer sur les jalons va contribuer à orienter vos \"lecteurs\"</strong>. C'est le fameux 📍 \"Vous êtes ici !\" qui rassure et donne une vue d'ensemble des projets." }, { "type": "heading", "level": 3, "id": "5-conservez-une-communication-authentique-et-transparente", "text": "5. Conservez une communication authentique et transparente" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37332e3e5061aaecd0dd1_a4f3a7d0-91e3-41bb-a047-0cc694e3414c.jpg", "alt": "dessin de presse com projet", "caption": "Extrait du livre \"Communication ? je me marre!\" Ed. Eyrolles." }, { "type": "paragraph", "html": "Dernier enjeu pour bien élaborer un plan de communication projet : la <strong>transparence</strong>. En effet, pendant les rendez-vous de synchronisation de l'équipe projet, de nombreuses micros décisions sont prises." }, { "type": "paragraph", "html": "<strong>L'équipe projet doit se responsabiliser pour communiquer</strong> sur celles-ci. Car elle sortent parfois du périmètre de responsabilité. Il est donc important de bien organiser la remontée de toutes les informations, points d'attention et décisions prises." }, { "type": "paragraph", "html": "Car oui chacun de nous en a fait l'expérience :" }, { "type": "quote", "text": "Il y a aucun projet qui se passe comme prévu !. Les directions générales apprécient la transparence. Ce qu'elles n'apprécient pas, c'est quand vous cachez quelque chose et que 3 ans plus tard elles découvrent qu'il y a eu un écart dans la trajectoire.", "author": "Thomas Vrignaud — CIO-CDO, Extrait de l'épisode 14 du Podcast CIO Révolution by AirSaas" }, { "type": "heading", "level": 2, "id": "les-dos-and-donts-dun-plan-de-communication-projet", "text": "Les Do's & Don'ts d'un plan de communication projet" }, { "type": "heading", "level": 3, "id": "les-7-ingredients-dune-communication-projet-qui-impacte", "text": "Les 7 ingrédients d'une communication projet qui impacte !" }, { "type": "list", "ordered": true, "items": ["<strong>Authentique</strong> : pour qu'on vous suive, il faut que ça sonne juste !", "<strong>Semi automatique</strong> : faites travailler les robots, le flash report est là pour ça :-)", "<strong>Collaborative</strong> : tous communicants ! c'est une charge à partager.", "<strong>Continue</strong> : itérations courtes et fréquentes... ça vous rappelle quelque chose ?", "<strong>Variée</strong> : même au sein d'un format type, l'idée, c'est de surprendre.", "<strong>Utile :</strong> Centrez votre communication sur la valeur. Parlez des gains attendus de ce qui va changer au quotidien pour chacun. Une règle : parlez-moi de moi, il n'y a que ça qui m'intéresse !", "<strong>Respectueuse</strong> : Mettez vous à la place du lecteur. C'est parfois dur de comprendre la technologie, son jargon ! Si vous ne faites pas attention, ne vous plaignez pas de travailler seul..."] }, { "type": "heading", "level": 3, "id": "les-7-erreurs-courantes-du-plan-de-communication-projet", "text": "Les 7 erreurs courantes du plan de communication projet" }, { "type": "list", "ordered": true, "items": ["Le piège du groupe de key user trop restreint !", "L'objectif du plan de communication projet doit être clarifié avant d'entreprendre la démarche", "Le rédacteur doit être interne au projet", "Le rédacteur n'est pas forcément le validateur", "Le plan de com ne peut s'élaborer dans l'urgence", "Le fait de rédiger un plan doit opérer dans un esprit de transparence et d'ouverture", "Oublier de dire ce que le projet ne vas pas délivrer !"] }, { "type": "insight-callout", "label": "À retenir", "html": "Concevoir et exécuter un plan de communication et de conduite du changement est un <b>investissement</b> ! Celui qui contribuera à <b>développer en continu l'engagement collectif des utilisateurs</b>, parties prenantes, sponsors et clients...qui apprécieront d'être tenus au courant régulièrement. Elle ne garantira pas votre réussite, mais vous aurez fait votre part du travail en luttant notamment contre les risques liés aux non dits et les \"je ne savais pas\" !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f373627d043066aefb0e77_Matrice%20%20communication%20projet%20AirSaas.jpg", "alt": "Aide mémoire Plan de communication projet", "caption": "Une \"carte mémoire\" du plan de communication projet à emporter" }, { "type": "paragraph", "html": "L'outil le plus simple pour communiquer sur l'état de santé de vos projets est la météo ! On vous dit tout sur <a href=\"http://gestion-de-projet/comment-mettre-une-bonne-meteo-projet\" target=\"_blank\">Comment faire une météo projet claire et compréhensible ?</a>" }], "toc": [{ "href": "#pourquoi-communiquer-autour-de-votre-projet", "label": "Pourquoi communiquer autour de votre projet ?", "level": 2 }, { "href": "#par-ou-on-commence-comment-on-sy-prend", "label": "Par où on commence ? Comment on s'y prend ?", "level": 2 }, { "href": "#au-dela-des-basiques-les-cinq-hacks-pour-construire-un-plan-de-communication-projet-moderne", "label": "Au delà des basiques : les cinq hacks🔥 pour construire un plan de communication projet moderne", "level": 2 }, { "href": "#les-dos-and-donts-dun-plan-de-communication-projet", "label": "Les Do's & Don'ts d'un plan de communication projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "planification-de-la-capacite", "skip": false, "meta": { "title": "8 bonnes pratiques pour réussir votre planification de la capacité", "h1": "8 bonnes pratiques pour réussir votre planification de la capacité", "description": "Découvrez 8 conseils pragmatiques pour réussir votre planification de la capacité et faire avancer vos projets plus vite et mieux.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae498a9e9ecfe92f151b1_8%20bonnes.jpg", "alt": "" }, "author": { "category": "Gestion de projets" } }, "blocks": [{ "type": "paragraph", "text": "Dans un monde où les ressources sont de plus en plus rares et la pression des délais ne cesse de croître, la planification de la capacité est plus cruciale que jamais. Et chaque retard ou malentendu dans cette planification peut compromettre l'ensemble de votre portfolio." }, { "type": "paragraph", "text": "Dans notre article précédent, nous vous avions dévoilé notre méthode pour mettre en place un Capacity Planning efficace. <a href=\"http://www.airsaas.io/fr/gestion-de-projet/plan-capacitaire\" target=\"_blank\">Rendez-vous ici si c'est ce que vous recherchez</a>." }, { "type": "paragraph", "text": "Mais si vous cherchez à aller plus loin, nous vous proposons ici huit conseils pragmatiques de planification de la capacité, pour faire avancer plus vite et mieux vos projets. À vous une transfo. d'entreprise accélérée, et bien alignée sur vos objectifs stratégiques !" }, { "type": "heading", "level": 2, "id": "planification-de-la-capacite-de-quoi-parle-t-on", "text": "Planification de la capacité : de quoi parle-t-on ?" }, { "type": "paragraph", "text": "Commençons par définir concrètement ce qu'est la planification de la capacité, et pourquoi cette méthode vous aide dans l'optimisation de votre portefeuille de projets." }, { "type": "heading", "level": 3, "id": "une-breve-definition-de-la-planification-de-la-capacite", "text": "Une brève définition de la planification de la capacité" }, { "type": "paragraph", "text": "On appelle \"planification de la capacité\", \"Capacity Planning\" ou encore \"plan capacitaire\" une méthode faite pour <strong>évaluer, planifier et gérer les ressources nécessaires pour répondre aux besoins</strong> d'une organisation." }, { "type": "paragraph", "text": "Il s'agit d'un processus de planification pour créer un plan de production qui aligne la demande en projets de l'entreprise avec ses ressources réelles." }, { "type": "paragraph", "text": "En planification de la capacité, on organise plusieurs types de ressources dans le temps :" }, { "type": "list", "ordered": false, "items": ["Les ressources financières", "Les ressources humaines"] }, { "type": "paragraph", "text": "C'est souvent ce dernier point qui constitue la source des goulots d'étranglement dans l'avancement des projets - d'où les bénéfices issus d'une planification de la capacité au cordeau." }, { "type": "heading", "level": 2, "id": "pourquoi-votre-entreprise-a-besoin-dun-capacity-planning", "text": "Pourquoi votre entreprise a besoin d'un Capacity Planning" }, { "type": "paragraph", "text": "La planification de la capacité est utilisée par des entreprises de tous les secteurs d'activité. Et pour cause : elle présente bien des bénéfices !" }, { "type": "paragraph", "text": "Grâce à un Capacity Planning bien ficelé, vous pouvez :" }, { "type": "list", "ordered": false, "items": ["<strong>Optimiser vos ressources</strong> pour mieux planifier les projets à venir, grâce à des prévisions plus fiables", "<strong>Aligner l'utilisation de vos ressources et votre stratégie d'entreprise</strong>, pour accélérer la livraison de valeur", "<strong>Booster la productivité de vos équipes</strong> et leur engagement dans vos projets", "<strong>Réduire les risques de retard</strong> sur tout votre portefeuille de projets", "<strong>Être prêt à accueillir une variation de la demande </strong>sur une période donnée", "<strong>Optimiser votre rentabilité</strong> et maîtriser vos coûts", "<strong>Améliorer la satisfaction collaborateur</strong>, en maîtrisant notamment la charge de travail des équipes", "<strong>Doper la satisfaction de vos clients</strong>, internes ou externes, grâce à un delivery fiable et de qualité"] }, { "type": "paragraph", "text": "En somme, un plan capacitaire vous donne toutes les clés pour lancer des projets… et les réussir ! Tout le monde est aligné autour des priorités stratégiques, sans que les ressources soient sur- ou sous-utilisées. De quoi assainir les relations entre les différents métiers, et accélérer la transfo. de votre organisation." }, { "type": "paragraph", "text": "Envie de creuser la définition de cette méthode de planification stratégique ? <a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning-definition\" target=\"_blank\">Rendez-vous sur notre article \"Capacity Planning : définition et principes de base\"</a>." }, { "type": "heading", "level": 2, "id": "8-bonnes-pratiques-pour-reussir-votre-planification-de-la-capacite", "text": "8 bonnes pratiques pour réussir votre planification de la capacité" }, { "type": "paragraph", "text": "Aligner votre capacité de production et la demande stratégique de votre organisation demande méthodologie et vision. Voici les huit clés de succès pour réussir la planification de la capacité de votre entreprise sur la période à venir." }, { "type": "heading", "level": 3, "id": "avoir-une-vision-claire-des-besoins-prioritaires", "text": "Avoir une vision claire des besoins prioritaires" }, { "type": "paragraph", "text": "La vision stratégique de votre entreprise est le prérequis pour faire une planification de la capacité vraiment efficace. Car, après tout, l'idée d'un Capacity Planning est bien de faire en sorte que l'utilisation des ressources transcrive les objectifs stratégiques de l'entreprise." }, { "type": "paragraph", "text": "Votre objectif est donc que votre planning traduise en actions opérationnelles la stratégie de l'organisation toute entière." }, { "type": "paragraph", "text": "Pour ça, commencez par <strong>vous pencher sur les projets qui ont le plus de valeur dans la roadmap</strong> de la période à venir, et priorisez-les en termes d'allocation de ressources." }, { "type": "heading", "level": 3, "id": "creer-un-momentum-pour-encourager-la-collaboration-inter-equipes", "text": "Créer un momentum pour encourager la collaboration inter-équipes" }, { "type": "paragraph", "text": "Pour être sûr que votre Capacity Planning traduise tous les enjeux stratégiques de l'organisation, vous devez vous assurer que toutes vos parties prenantes sont au diapason en termes de priorités." }, { "type": "paragraph", "text": "Car n'oubliez pas : prioriser, c'est forcément renoncer - ou, tout du moins, repousser dans le temps des projets. D'où l'intérêt de <strong>passer par un moment collectif où la direction et les métiers peuvent discuter de ces priorités.</strong>" }, { "type": "paragraph", "text": "C'est là où des méthodologies comme celles du <a href=\"https://www.airsaas.io/fr/quarter-plan\" target=\"_blank\">Quarter Plan</a> ou du <a href=\"http://www.airsaas.io/fr/gestion-de-projet/pi-planning\" target=\"_blank\">PI Planning</a> prennent tout leur sens. L'idée ici : mettre en place des moments de planification collective pour aligner tout le monde, lors desquelles chaque équipe s'engage sur le temps qu'elles peuvent allouer à chaque projet." }, { "type": "paragraph", "text": "Ces réunions permettent également de repérer en amont les risques et les dépendances de chaque projet, ainsi que les goulots d'étranglement potentiels. Elles vous évitent aussi les longues heures passées entre les différents services, en réunions one-to-one, à récolter les besoins et attentes de chacun." }, { "type": "paragraph", "text": "Quelle que soit la méthode que vous choisissez, rappelez-vous que votre capacité à planifier et à déployer un plan de charge ne peut pas uniquement reposer sur vos équipes. Jouez collectif : vous verrez la différence !" }, { "type": "inline-cta", "label": "Réservez votre démo de 30 min", "href": "/fr/meetings-pages" }, { "type": "heading", "level": 3, "id": "mettre-en-place-un-capacitaire-par-trimestre", "text": "Mettre en place un capacitaire par trimestre" }, { "type": "paragraph", "text": "Souvent, on observe les entreprises mettre en place un plan capacitaire sur une échelle de temps très courte - généralement, une semaine. Or, cette temporalité courte rend très fastidieuse la mise à jour du Capacity Planning… qui, de toute façon, est voué à évoluer au fil des changements dans la demande et dans les ressources !" }, { "type": "paragraph", "text": "Notre parti pris, chez Airsaas ? <strong>Privilégiez un capacitaire approximativement juste plutôt que précisément faux</strong>." }, { "type": "paragraph", "text": "Pour ce faire, vous devez passer votre planification de la capacité sur une autre échelle de temps, plus longue. Mettre en place un capacitaire au trimestre - ou bien au semestre, ou au PI - fait plus de sens par rapport à la réalité du travail que les équipes doivent fournir." }, { "type": "paragraph", "text": "L'avantage en plus ? Cette planification sur un temps long crée une pression positive sur les équipes, qui font en sorte de finir leurs projets avant la fin de la période, et de bien cadrer leurs besoins en amont de la période suivante." }, { "type": "paragraph", "text": "Bien entendu, cela n'empêche pas les équipes de développement, habituées aux sprints plus courts, de continuer à planifier leurs tâches sur des périodes plus courtes. Mais votre planning, lui, prévoit les livrables plutôt sur du moyen-terme." }, { "type": "heading", "level": 3, "id": "estimer-le-temps-necessaire-au-livrable-et-non-a-la-tache", "text": "Estimer le temps nécessaire au livrable, et non à la tâche" }, { "type": "paragraph", "text": "Traditionnellement, la planification de la capacité se fait à la tâche. Et c'est l'un des éléments qui peut rapidement transformer ce planning en un véritable casse-tête !" }, { "type": "paragraph", "text": "Nous vous conseillons plutôt d'adopter une approche plus pragmatique, qui consiste à <strong>estimer le temps nécessaire au livrable plutôt qu'à la tâche</strong>. Ainsi, vous évitez de rentrer dans le détail micro, et de vous y perdre." }, { "type": "paragraph", "text": "Encore une fois, rien ne vous empêche par la suite de créer des plannings à la tâche en fonction de l'allocation des ressources décidées sur chaque livrable." }, { "type": "heading", "level": 3, "id": "penser-a-la-maille-de-lequipe-et-non-de-la-personne", "text": "Penser à la maille de l'équipe, et non de la personne" }, { "type": "paragraph", "text": "Lorsque que vous allez configurer votre plan capacitaire, il est essentiel de <strong>vous projeter sur le temps disponible pour vos projets</strong> (c'est-à-dire le build)." }, { "type": "paragraph", "text": "Or, vous l'avez peut-être testé : créer un capacitaire à l'échelle des individus peut rapidement devenir un casse-tête si vous devez le faire pour une organisation toute entière !" }, { "type": "paragraph", "text": "Alors, plutôt que de faire votre planification de la capacité à l'échelle de la personne, nous vous conseillons de le faire à l'échelle de l'équipe. Ce faisant, vous rendez votre capacitaire plus souple, et augmentez vos chances de faire matcher la capacité et la demande." }, { "type": "paragraph", "text": "Notez que chaque équipe n'a pas forcément besoin d'être un pôle distinct de l'entreprise. Il faut plutôt considérer chacune de vos équipes comme un \"rassemblement de compétences homogènes\"." }, { "type": "paragraph", "text": "Il peut par exemple s'agir, pour le pôle IT, de l'équipe IT Sécurité, de l'équipe IT Data, et de l'équipe IT Intégration. Autre exemple : pour le service marketing, segmentez-le en équipe marketing CRM, marketing Content, plus une autre équipe regroupant le reste des marketeurs." }, { "type": "heading", "level": 3, "id": "etablir-des-scenarios-pour-combler-les-ecarts", "text": "Établir des scénarios pour combler les écarts" }, { "type": "paragraph", "text": "Pour établir un Capacity Planning qui soit aussi réaliste que possible, <strong>utilisez des scénarios qui permettent de combler l'écart </strong>entre la capacité actuelle et la demande prévue." }, { "type": "paragraph", "text": "Par exemple, vous pouvez vous poser les questions suivantes :" }, { "type": "list", "ordered": false, "items": ["Si on rajoute de la charge à une équipe sur un nouveau projet, ça passe ou pas ?", "Et si on recrute un nouveau collaborateur ou que l'on fait appel à un prestataire externe ?", "Si l'on met en place un plan de montée en compétences pour une équipe ?"] }, { "type": "paragraph", "text": "Estimez à chaque scénario le budget à déployer, ainsi que le ROI en à tirer au vu de la valeur attendue stratégiquement par votre organisation. Résultat : vous obtenez la projection la plus avantageuse pour les équipes et pour l'entreprise." }, { "type": "heading", "level": 3, "id": "adopter-un-outil-adapte", "text": "Adopter un outil adapté" }, { "type": "paragraph", "text": "Ne vous y détrompez pas : quelles que soient les mesures d'alignement entre les équipes que vous avez mises en place, au fil du temps qui passe, la demande dans votre entreprise et ses ressources vont fluctuer. Vous devrez donc régulièrement revoir votre planification de la capacité. De quoi rapidement s'arracher les cheveux… si vous ne disposez pas du bon outil !" }, { "type": "paragraph", "text": "C'est pour simplifier la vie des DSI, PMO et chefs de projet que nous avons conçu <strong>Airsaas : un logiciel de gestion de portefeuille projet, qui vous permet de concevoir un capacitaire par équipe</strong> sur le temps long. Idéal pour vous focaliser sur le build." }, { "type": "paragraph", "text": "L'outil est fondamentalement collaboratif. Chaque équipe déclare la bande passante dont elle dispose sur l'outil, pour que vous puissiez savoir précisément où attribuer vos ressources selon votre vision stratégique." }, { "type": "paragraph", "text": "Grâce à la vue Capacitaire, vous visualisez la capacité de chaque équipe, quels livrables vous empêchent d'avancer, ou encore de quelles ressources humaines en plus vous pourriez avoir besoin." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02737c3f7b9a4eb992582_capacitaire-airsaas.png", "alt": "" }, { "type": "paragraph", "text": "Grâce à ce capacitaire macro, finies les heures perdues à mettre à jour un Capacity Planning à la tâche et à la personne… qui finit à la poubelle deux jours plus tard." }, { "type": "paragraph", "text": "Intéressé par la solution ? <a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">Découvrez la fonctionnalité de planification de la capacité d'Airsaas dès maintenant</a>." }, { "type": "heading", "level": 3, "id": "prioriser-la-flexibilite", "text": "Prioriser la flexibilité" }, { "type": "paragraph", "text": "Vous le savez mieux que quiconque : un projet se déroule rarement comme on le prévoit. L'entreprise est une matière vivante, où les compétences internes sont mouvantes et où la priorité des demandes peut changer en fonction des tendances du marché et les résultats de l'organisation." }, { "type": "paragraph", "text": "D'où la nécessité de prévoir des marges pour faire face aux imprévus." }, { "type": "paragraph", "text": "Adoptez donc <strong>une approche itérative et ajustable dans votre planification de la capacité</strong>. Vous pouvez notamment le faire grâce à une approche au temps plus long, sous forme de Quarter Plan ou de PI Planning, qui permet de revoir la planification de la capacité à échéances fixes, en fonctionnant de manière collaborative." }, { "type": "heading", "level": 3, "id": "suivre-et-analyser-les-performances", "text": "Suivre et analyser les performances" }, { "type": "paragraph", "text": "Dernier conseil, et non des moindres : le fait de mettre en place les KPIs adaptés pour suivre l'efficacité du Capacity Planning." }, { "type": "paragraph", "text": "Vous pouvez notamment inclure dans vos tableaux de bord :" }, { "type": "list", "ordered": false, "items": ["<strong>Le taux de réalisation des livrables à la fin du trimestre</strong>", "<strong>Le taux d'utilisation de la capacité</strong>", "<strong>Le taux d'achèvement des projets</strong> dans les délais et budgets prévus", "<strong>Le taux d'interruption ou de retard</strong> sur les projets dû à une planification de la capacité incorrecte"] }, { "type": "paragraph", "text": "Pensez également à organiser des revues périodiques mensuelles pour évaluer l'efficacité et affiner votre planning." }, { "type": "paragraph", "text": "Vous êtes désormais fin prêt à mettre (enfin) en place un Capacity Planning qui équilibre demande et ressources disponibles !" }, { "type": "paragraph", "text": "Besoin d'un outil pour vous simplifier la tâche ? <a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">Demandez une démo d'Airsaas</a>, et constatez combien sa fonctionnalité de Capacity Planning peut vous aider à mieux aligner vos projets avec votre vision stratégique." }], "toc": [{ "label": "Planification de la capacité : de quoi parle-t-on ?", "href": "#planification-de-la-capacite-de-quoi-parle-t-on", "level": 2 }, { "label": "Pourquoi votre entreprise a besoin d'un Capacity Planning", "href": "#pourquoi-votre-entreprise-a-besoin-dun-capacity-planning", "level": 2 }, { "label": "8 bonnes pratiques pour réussir votre planification de la capacité", "href": "#8-bonnes-pratiques-pour-reussir-votre-planification-de-la-capacite", "level": 2 }], "faq": [], "related": [] }, { "slug": "planification-de-la-demande-capacity-planning", "skip": false, "meta": { "title": "Planification de la demande et Capacity Planning : quelles différences ?", "h1": "Planification de la demande et Capacity Planning : quelles différences ?", "description": "Planification de la demande vs Capacity Planning : découvrez les différences clés, leur complémentarité et les outils pour équilibrer besoins et ressources dans vos projets.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae3cc625434050c28f97f_Planification%20de%20la%20demande.jpg", "alt": "Planification de la demande" }, "author": { "category": "Gestion de projets" } }, "blocks": [{ "type": "paragraph", "text": "Si vous gérez des projets IT ou métiers, vous avez forcément entendu parler de planification de la demande et de capacity planning. Deux concepts souvent confondus, alors qu'ils répondent à des enjeux bien distincts." }, { "type": "paragraph", "text": "D'un côté, <strong>la planification de la demande</strong> consiste à lister et prioriser tout ce que l'entreprise veut faire : nouvelles fonctionnalités, évolutions, projets stratégiques..." }, { "type": "paragraph", "text": "De l'autre, <strong>le Capacity Planning</strong> vise à s'assurer qu'on a les ressources nécessaires (humaines, techniques, budgétaires) pour les réaliser." }, { "type": "paragraph", "text": "Et c'est là que ça coince souvent." }, { "type": "paragraph", "text": "Beaucoup d'entreprises passent du temps à définir leurs demandes, mais sans vérifier si elles sont réalistes en fonction des capacités disponibles. Résultat : des roadmaps intenables, des équipes en surcharge et des arbitrages faits dans l'urgence. À l'inverse, certaines sociétés sont focalisées sur leurs contraintes de ressources sans avoir une vision claire des besoins métiers, ce qui mène à une sous-exploitation des équipes et un manque de valeur créée." }, { "type": "paragraph", "text": "L'enjeu est donc d'équilibrer ces deux approches : faire coïncider ce que l'on veut faire avec ce que l'on peut réellement faire. C'est ici qu'intervient un bon cadre de gouvernance, avec des outils adaptés pour piloter à la fois la demande et la capacité." }, { "type": "paragraph", "text": "Dans cet article, on va voir <strong>les différences fondamentales entre planification de la demande et Capacity Planning</strong>, pourquoi elles sont indissociables, et surtout comment les intégrer intelligemment pour éviter de tomber dans le piège des projets irréalisables ou des équipes surchargées." }, { "type": "heading", "level": 2, "id": "quest-ce-que-la-planification-de-la-demande", "text": "Qu'est-ce que la planification de la demande ?" }, { "type": "paragraph", "text": "On appelle \"planification de la demande\" (ou parfois \"gestion de la demande\") un processus qui vise à <strong>prévoir la demande future de l'entreprise en projets</strong>. Ses objectifs principaux : répondre à la demande des clients (externes comme internes), et favoriser la transformation et l'innovation au sein de l'organisation." }, { "type": "paragraph", "text": "En somme, la planification de la demande consiste à récolter les besoins futurs de l'entreprise en termes de produits, de services ou de features. Elle vous permet de canaliser les projets entrants, pour être sûr de ne vous lancer que dans les initiatives qui ont de réelles chances d'aboutir." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67d14a18d038eb3653397ab8_gestion-de-la-demande-airsaas.png", "alt": "Gestion de la demande - AirSaas" }, { "type": "heading", "level": 2, "id": "quest-ce-que-le-capacity-planning", "text": "Qu'est-ce que le Capacity Planning ?" }, { "type": "paragraph", "text": "On appelle Capacity Planning, ou plan capacitaire, le processus de <strong>planification des ressources nécessaires pour répondre à des besoins déjà identifiés</strong>. L'objectif de la planification de la capacité est de s'assurer que la capacité disponible est suffisante pour répondre à la demande." }, { "type": "paragraph", "text": "En somme, un Capacity Planning consiste à évaluer et optimiser les ressources disponibles (humaines et financières) pour répondre efficacement à la demande existante ou prévue." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67d14a39b4b35c1d21be0f8f_suivi-capacitaire.png", "alt": "Suivi capacitaire - AirSaas" }, { "type": "paragraph", "text": "Pour creuser le sujet, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning-definition\" target=\"_blank\">rendez-vous sur notre article \"Capacity Planning : définition et principes de base\"</a>." }, { "type": "heading", "level": 2, "id": "les-differences-cles-entre-planification-de-la-demande-et-capacity-planning", "text": "Les différences clés entre planification de la demande et capacity planning" }, { "type": "heading", "level": 3, "id": "des-objectifs-differents", "text": "Des objectifs différents" }, { "type": "paragraph", "text": "Tout d'abord, on n'utilise pas ces deux méthodologies pour les mêmes raisons." }, { "type": "paragraph", "text": "D'un côté, la planification de la demande vise à <strong>anticiper les besoins</strong> des différentes parties prenantes de l'entreprise. L'accent est donc mis sur la prévision de ces besoins, grâce à une analyse des tendances historiques et des comportements des clients, mais aussi une récolte des attentes des différents acteurs de l'organisation." }, { "type": "paragraph", "text": "De l'autre, le Capacity Planning se concentre sur <strong>l'allocation et la gestion des ressources pour répondre à ces besoins</strong>. Cette approche se concentre donc sur l'adaptation des ressources disponibles aux besoins prévisionnels. Elle s'assure que l'entreprise dispose de suffisamment de ressources, que ce soit en termes de capacité de production ou de main-d'œuvre, pour satisfaire la demande." }, { "type": "heading", "level": 3, "id": "des-donnees-utilisees-differentes", "text": "Des données utilisées différentes" }, { "type": "paragraph", "text": "Qui dit méthodes différentes, dit data différente à utiliser." }, { "type": "paragraph", "text": "D'un côté, la planification de la demande va se baser sur <strong>les données historiques de l'entreprise</strong>, ses prévisions ou ses tendances, ainsi que sur les demandes remontées par les métiers.<br>De l'autre, le Capacity Planning va se focaliser sur <strong>la capacité actuelle</strong>, ses contraintes et ses projections en termes de charge de travail." }, { "type": "paragraph", "text": "D'où la nécessité d'adopter des outils différents pour mener à bien ces deux méthodes." }, { "type": "paragraph", "text": "On vous en dit plus à la fin de cet article sur les outils pour concevoir votre Capacity Planning - mais si vous êtes impatient, vous pouvez d'ores et déjà <a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">découvrir la solution Airsaas et ses fonctionnalités de capacitaire macro</a>." }, { "type": "heading", "level": 2, "id": "la-complementarite-entre-planification-de-la-demande-et-capacity-planning", "text": "La complémentarité entre planification de la demande et Capacity Planning" }, { "type": "paragraph", "text": "Si ces deux méthodes ont un intérêt pour la gestion de projet dans l'entreprise, elles n'ont pas les mêmes liens avec votre portefeuille de projets." }, { "type": "paragraph", "text": "La planification de la demande peut influencer vos projets, car elle vous permet d'identifier des périodes de forte demande, des pics de charge de travail, ou encore des livrables à développer rapidement pour vous assurer que l'entreprise garde son avantage concurrentiel." }, { "type": "paragraph", "text": "Le Capacity Planning vous permet de vous assurer que vous pouvez exécuter vos projets de manière fluide, sans être freiné par un manque de ressources." }, { "type": "paragraph", "text": "En somme, quand la planification de la demande répond à la question \"Que devons-nous faire comme projets ?\", le Capacity Planning permet de se poser la question \"Pouvons-nous faire ces projets ?\"." }, { "type": "paragraph", "text": "C'est pourquoi plan capacitaire et planification de la demande sont aussi complémentaires ! Les deux méthodes forment <strong>les deux faces d'une même pièce : l'équilibre entre besoins et ressources</strong>." }, { "type": "paragraph", "text": "En combinant ces deux approches, vous pouvez <strong>maximiser l'efficacité opérationnelle de votre organisation</strong>. Une planification de la demande fiable permet à votre Capacity Planning de fonctionner sur des bases solides, tandis qu'un Capacity Planning bien géré assure que les prévisions de la demande peuvent être réalisées sans rupture ou retard." }, { "type": "paragraph", "text": "<strong>Ensemble, ils créent une stratégie intégrée</strong>, où la demande guide les priorités et les ressources garantissent leur exécution." }, { "type": "paragraph", "text": "L'idée : planifier des réunions de la gestion de la demande (ou request reviews) toutes les deux semaines avec des duos IT - Métier, vous permettant de récolter la demande des différentes parties prenantes. Par la suite, les éléments récoltés vous permettent d'organiser votre Capacity Planning sur un temps plus long - quarter, semestre ou PI, selon la temporalité de votre organisation." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c0254d7662945f0bda0459_culture-capacity-planning.png", "alt": "Culture Capacity Planning - AirSaas" }, { "type": "inline-cta", "label": "Réservez votre démo de 30 min", "href": "/fr/meetings-pages" }, { "type": "heading", "level": 2, "id": "quels-outils-pour-un-capacity-planning-maitrise", "text": "Quels outils pour un Capacity Planning maîtrisé ?" }, { "type": "paragraph", "text": "Concevoir un Capacity Planning vous demande de récolter toute la demande actuelle et planifiée de votre entreprise, puis l'aligner avec les ressources disponibles sur la période." }, { "type": "paragraph", "text": "Si la méthode vous est totalement inconnue, n'hésitez pas à consulter <a href=\"http://www.airsaas.io/fr/gestion-de-projet/plan-capacitaire\" target=\"_blank\">notre guide en sept étapes pour concevoir votre plan capacitaire</a>." }, { "type": "paragraph", "text": "Mais, si vous avez déjà créé un Capacity Planning, vous le savez : fonctionner sur un seul tableau Excel peut vite devenir un casse-tête sans nom. En effet, votre planning doit être collaboratif, et aisément mis à jour en fonction de la fluctuation de la demande et des ressources." }, { "type": "paragraph", "text": "C'est pour aider les DSI, PMO et chefs de projet à mieux gérer la capacité de production de leur entreprise que nous avons conçu la fonctionnalité Capacity Planning d'Airsaas." }, { "type": "paragraph", "text": "C'est simple : sur Airsaas, vous concevez un capacitaire par équipe pour la période que vous souhaitez : trimestre, semestre, ou PI. Ainsi, vous vous focalisez sur le build réel de l'entreprise.<br>Chaque équipe remonte dans Airsaas les ressources qu'elle peut mettre à disposition pour vos projets." }, { "type": "paragraph", "text": "Il vous suffit ensuite simplement de faire des scénarios pour évaluer où attribuer vos ressources en fonction des priorités. Une étape simple, grâce à la vue Capacitaire, qui permet de voir en un clin d'œil où vos projets bloquent, et quelles sont les ressources supplémentaires dont vous avez besoin." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67c02737c3f7b9a4eb992582_capacitaire-airsaas.png", "alt": "Capacitaire AirSaas" }, { "type": "paragraph", "text": "Ne perdez plus votre temps (précieux) sur des capacitaires à la personne et à la tâche : optez pour un Capacity Planning pragmatique avec Airsaas !" }, { "type": "paragraph", "text": "Et maintenant que vous avez bien saisi les différences majeures entre planification de la demande et Capacity Planning, vous êtes prêt à vous lancer dans votre plan capacitaire." }, { "type": "paragraph", "text": "<a href=\"https://www.airsaas.io/fr/produit/capacity-planning\" target=\"_blank\">Demandez une démo Airsaas</a>, et laissez notre plateforme de gestion de portefeuille projet rationaliser la transformation de votre entreprise." }], "toc": [{ "href": "#quest-ce-que-la-planification-de-la-demande", "label": "Qu'est-ce que la planification de la demande ?", "level": 2 }, { "href": "#quest-ce-que-le-capacity-planning", "label": "Qu'est-ce que le Capacity Planning ?", "level": 2 }, { "href": "#les-differences-cles-entre-planification-de-la-demande-et-capacity-planning", "label": "Les différences clés entre planification de la demande et capacity planning", "level": 2 }, { "href": "#la-complementarite-entre-planification-de-la-demande-et-capacity-planning", "label": "La complémentarité entre planification de la demande et Capacity Planning", "level": 2 }, { "href": "#quels-outils-pour-un-capacity-planning-maitrise", "label": "Quels outils pour un Capacity Planning maîtrisé ?", "level": 2 }], "related": [{ "href": "/fr/gestion-de-projet/metier-pmo", "label": "PMO (Project Management Office) : le guide complet pour comprendre et mettre en place ce rôle clé" }, { "href": "/fr/gestion-de-projet/pi-planning", "label": "PI Planning : le guide complet pour aligner vos équipes IT et métiers" }, { "href": "/fr/gestion-de-projet/management-de-portefeuille-de-projet", "label": "Management de portefeuille de projet : définition, méthodes et outils" }], "faq": [] }, { "slug": "portefeuille-projet", "skip": false, "meta": { "title": "Management de portefeuille de projet : définition, méthodes et outils", "h1": "Management de portefeuille de projet : définition, méthodes et outils", "description": "Gestion de portefeuille de projets (PPM) : définition, méthodes de priorisation, KPIs essentiels et outils pour piloter efficacement vos projets.", "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "1/2/2026", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6995db9e00db2afd8d4d5013_Gestion%20de%20portefeuille%20de%20projets.jpg", "alt": "" }, "publishedDate": "1/2/2026" }, "blocks": [{ "type": "heading", "level": 2, "id": "quest-ce-que-la-gestion-de-portefeuille-de-projets", "text": "Qu'est-ce que la gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "La <strong>gestion de portefeuille de projets</strong> (GPP), aussi appelée <strong>Project Portfolio Management</strong> (PPM), est une discipline stratégique qui consiste à sélectionner, prioriser et piloter l'ensemble des projets d'une organisation pour maximiser la création de valeur." }, { "type": "paragraph", "html": "Contrairement à la gestion de projet, qui vise à \"<strong>bien faire les projets</strong>\" (domaine opérationnel), la gestion de portefeuille de projets cherche à \"<strong>faire les bons projets</strong>\" (domaine décisionnel)." }, { "type": "paragraph", "html": "Le Project Management Institute (PMI) la définit comme <em>la gestion centralisée des processus, méthodes et technologies d'un ensemble de projets, permettant d'optimiser les arbitrages et leur planification, tout en évaluant le niveau de risque et la viabilité financière des projets</em>." }, { "type": "paragraph", "html": "Concrètement, un <strong>portefeuille de projets</strong> regroupe l'ensemble des projets, programmes et opérations d'une entreprise. À l'image d'un portefeuille boursier, il s'agit de décider où investir son budget, ses ressources et son temps pour obtenir le meilleur retour sur investissement." }, { "type": "paragraph", "html": "Le PPM fonctionne comme un <strong>entonnoir stratégique</strong> : à l'entrée, un flux massif d'idées provenant de la stratégie, des clients ou de la réglementation ; à la sortie, une sélection rigoureuse d'initiatives coordonnées et exécutables. Sans ce filtre, l'organisation s'épuise à tout mener de front et condamne ses projets à des résultats médiocres." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699732d4dfc0c2f0d4d8feb0_Entonnoir%20strate%CC%81gique%20PPM%20FR.jpg", "alt": "Entonnoir stratégique de la gestion de portefeuille de projets — de l'idée à l'exécution" }, { "type": "paragraph", "html": "Ce que la gestion de portefeuille de projets permet" }, { "type": "list", "ordered": false, "items": ["Assurer l'<strong>alignement stratégique</strong> entre les projets et la vision de l'entreprise", "<strong>Prioriser</strong> les initiatives à plus forte valeur ajoutée", "<strong>Optimiser l'allocation des ressources</strong> (humaines, financières, matérielles) entre les projets", "<strong>Anticiper les risques</strong> de déséquilibre entre capacité et demande", "Offrir une <strong>visibilité consolidée</strong> aux instances de décision (Comité de pilotage, Direction Générale)", "<strong>Arrêter ou reporter</strong> les projets qui n'apportent plus de valeur"] }, { "type": "heading", "level": 3, "id": "la-capacite-par-equipe-la-contrainte-au-coeur-du-portefeuille", "text": "La capacité par équipe : la contrainte au cœur du portefeuille" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets repose sur une vérité que beaucoup d'organisations refusent de regarder en face : <strong>la capacité des équipes est finie</strong>. Et c'est cette contrainte — pas les matrices de scoring, pas les pourcentages d'avancement — qui doit structurer toutes les décisions." }, { "type": "paragraph", "html": "Concrètement, la capacité se mesure <strong>par équipe</strong> et <strong>au trimestre</strong>. C'est l'échelle du <strong>Quarter Plan</strong> : chaque équipe (infra, développement, data, sécurité…) dispose d'un nombre de jours-homme réels sur le trimestre à venir, une fois déduites les absences, la maintenance, le run et les imprévus. Cette capacité trimestrielle est le vrai budget de votre portefeuille — bien plus structurant que le budget financier." }, { "type": "table", "headers": ["", "Gestion des ressources", "Planification de la capacité"], "rows": [["Horizon", "Court terme (semaine/sprint)", "Trimestriel (Quarter Plan)"], ["Maille", "Individu par individu", "Équipe par équipe"], ["Question clé", "\"Qui travaille sur quoi cette semaine ?\"", "\"Cette équipe peut-elle absorber ce projet ce trimestre ?\""], ["Usage", "Optimiser l'affectation au quotidien", "Décider quels projets entrent dans le portefeuille — et lesquels attendent"]] }, { "type": "insight-callout", "html": "⚠️ <strong>Méfions-nous des mots creux.</strong> Les termes \"prioriser\" et \"piloter\" sont parmi les plus galvaudés du vocabulaire projet. Dire qu'un portefeuille est \"priorisé\", c'est souvent ne rien dire du tout si aucune contrainte de capacité n'a été confrontée aux engagements. De même, \"piloter\" un portefeuille via un <strong>pourcentage d'avancement</strong> est trompeur : un projet peut afficher 70 % d'avancement et être à des mois de livrer le moindre délivrable exploitable. Le pourcentage d'avancement mesure la consommation de charge, rarement la proximité d'un résultat tangible. La vraie question n'est jamais \"où en est-on ?\", mais <strong>\"qu'est-ce qu'on va livrer ce trimestre, et est-ce que l'équipe a la bande passante pour le faire ?\"</strong>", "label": "Attention" }, { "type": "paragraph", "html": "La planification de la capacité est le garde-fou stratégique de votre portefeuille : sans elle, vous validez des projets que vos équipes ne pourront jamais absorber." }, { "type": "insight-callout", "html": "💡 <strong>Le saviez-vous ?</strong> Selon une étude du PMI, 70 % des projets ont tendance à échouer. La première cause ? Un changement dans les priorisations de l'entreprise (39 %), suivi d'une modification des objectifs du projet (37 %). La gestion de portefeuille de projets existe précisément pour anticiper et piloter ces arbitrages plutôt que de les subir.", "label": "Le saviez-vous" }, { "type": "heading", "level": 2, "id": "portefeuille-de-projets-vs-programme-vs-projet-quelles-differences", "text": "Portefeuille de projets vs programme vs projet : quelles différences ?" }, { "type": "paragraph", "html": "La confusion entre ces trois concepts est fréquente. Voici ce qui les distingue." }, { "type": "heading", "level": 3, "id": "le-projet", "text": "Le projet" }, { "type": "paragraph", "html": "Un <strong>projet</strong> est une initiative temporaire visant à produire un livrable unique. Il a un début, une fin, un budget et des objectifs SMART (Spécifiques, Mesurables, Atteignables, Réalistes, Temporels). La gestion de projet se concentre sur la livraison réussie de cette initiative." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> Déployer un nouvel outil CRM pour l'équipe commerciale." }, { "type": "heading", "level": 3, "id": "le-programme", "text": "Le programme" }, { "type": "paragraph", "html": "Un <strong>programme</strong> est un ensemble de projets interdépendants qui partagent des objectifs communs. Les projets au sein d'un programme sont liés : ils contribuent collectivement à un résultat stratégique." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> Le programme \"Transformation digitale de la relation client\" qui regroupe le projet CRM, le projet refonte du site web et le projet mise en place d'un chatbot." }, { "type": "heading", "level": 3, "id": "le-portefeuille-de-projets", "text": "Le portefeuille de projets" }, { "type": "paragraph", "html": "Un <strong>portefeuille de projets</strong> n'est pas un niveau hiérarchique au-dessus du programme. C'est une <strong>lentille</strong> — une façon de regarder un groupement de projets sous un angle donné, pour prendre des décisions adaptées à ce périmètre." }, { "type": "paragraph", "html": "En pratique, une même organisation manipule plusieurs portefeuilles simultanément : le portefeuille de l'<strong>équipe IT infrastructure</strong>, celui de l'<strong>équipe applicative métier</strong>, le portefeuille des <strong>projets vitaux</strong>, celui des projets de <strong>conformité réglementaire</strong>, ou encore le portefeuille global vu par la Direction Générale. Chaque vue répond à une question différente : \"Mon équipe est-elle en surcharge ?\", \"Nos projets vitaux avancent-ils ?\", \"Sommes-nous alignés avec la stratégie ?\"." }, { "type": "paragraph", "html": "C'est ce qui rend la gestion de portefeuille de projets si puissante : elle n'impose pas un cadre unique, mais offre la possibilité de <strong>filtrer, regrouper et comparer les projets</strong> selon les besoins de chaque partie prenante — équipe, direction métier, DSI ou Comité de direction." }, { "type": "paragraph", "html": "<strong>Exemple :</strong> La DSI pilote un portefeuille global, mais chaque équipe (infra, dev, data) dispose de sa propre vue portefeuille avec ses contraintes de capacité. Le Comité de direction, lui, regarde le portefeuille par axe stratégique." }, { "type": "heading", "level": 3, "id": "tableau-comparatif", "text": "Tableau comparatif" }, { "type": "table", "headers": ["Critère", "Projet", "Programme", "Portefeuille"], "rows": [["Nature", "Une initiative temporaire avec un livrable", "Un ensemble de projets liés par un objectif commun", "Une vue sur un groupement de projets, filtrée par équipe, thématique ou axe stratégique"], ["Objectif", "Livrer un résultat concret dans les délais", "Atteindre un bénéfice stratégique commun", "Décider quoi faire, quoi arrêter, quoi reporter — en fonction de la capacité réelle"], ["Niveau de décision", "Opérationnel", "Tactique", "Stratégique"], ["Contrainte centrale", "Le triangle coût/délai/périmètre", "La coordination entre projets interdépendants", "La capacité des équipes — le nombre de projets sera toujours supérieur à ce qu'on peut absorber"], ["Pilote", "Chef de projet", "Directeur de programme", "PMO / DSI / Direction Générale"], ["Question clé", "\"Le livrable sera-t-il prêt ?\"", "\"Les projets produisent-ils le bénéfice attendu ?\"", "\"Les bonnes équipes travaillent-elles sur les bons sujets, au bon moment ?\""]] }, { "type": "insight-callout", "html": "📌 <strong>À retenir :</strong> Le portefeuille n'est pas \"au-dessus\" du projet et du programme dans une pyramide. C'est une <strong>grille de lecture</strong> qui permet de comparer, arbitrer et allouer les ressources entre des projets qui se disputent la même capacité. Il peut exister autant de vues portefeuille que de besoins de décision dans l'organisation.", "label": "À retenir" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699733200e76e85e0aaa049e_Le%20portefeuille%20comme%20lentille%20%E2%80%94%20vues%20multiples%20FR.jpg", "alt": "Le portefeuille de projets comme lentille — vues multiples par équipe, stratégie et priorité" }, { "type": "heading", "level": 2, "id": "pourquoi-mettre-en-place-une-gestion-de-portefeuille-de-projets", "text": "Pourquoi mettre en place une gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "Dans la plupart des entreprises, le nombre de projets dépasse largement la capacité à les réaliser. C'est une loi universelle de la transformation : la demande sera toujours supérieure à l'offre de ressources disponibles." }, { "type": "paragraph", "html": "Les chiffres le confirment : selon l'IBM Institute for Business Value, les organisations leaders en gestion de portefeuille de projets affichent une <strong>performance de revenus 46 % plus prévisible</strong> que leurs concurrentes moins matures. L'excellence en PPM n'est pas un luxe organisationnel — c'est un avantage concurrentiel mesurable." }, { "type": "paragraph", "html": "Sans gestion de portefeuille de projets, les organisations subissent un phénomène bien connu : <strong>l'urgence chasse l'urgence</strong>. Les équipes fonctionnent en \"best effort\", les arbitrages se font au fil de l'eau (ou au \"fait du prince\"), et personne n'a de visibilité sur ce qui est réellement prioritaire." }, { "type": "heading", "level": 3, "id": "les-6-benefices-concrets-dune-demarche-de-gestion-de-portefeuille-de-projets", "text": "Les 6 bénéfices concrets d'une démarche de gestion de portefeuille de projets" }, { "type": "paragraph", "html": "<strong>1. Alignement stratégique</strong>" }, { "type": "paragraph", "html": "La GPP garantit que chaque projet contribue à la stratégie de l'entreprise. Fini les projets \"orphelins\" qui consomment des ressources sans créer de valeur mesurable. Chaque euro investi est tracé jusqu'à un objectif stratégique. Une vérité trop souvent ignorée : <strong>succès technique ≠ succès business</strong>. Une exécution parfaite d'un projet sans alignement stratégique reste un gaspillage de ressources." }, { "type": "paragraph", "html": "<strong>2. Priorisation objective et transparente</strong>" }, { "type": "paragraph", "html": "En rendant visible la règle du jeu et l'ensemble des sujets en revue de portefeuille, la démarche instaure une relation de confiance et de transparence entre la DSI, les métiers et la direction générale. Les décisions de priorisation sont fondées sur des <strong>données probantes</strong>, pas sur le rapport de force politique ou la voix la plus forte en comité de direction." }, { "type": "paragraph", "html": "<strong>3. Optimisation de la capacité — la vraie valeur ajoutée</strong>" }, { "type": "paragraph", "html": "C'est ici que la gestion de portefeuille de projets prend tout son sens. La capacité ne se mesure pas à l'échelle de l'organisation entière — elle se mesure <strong>équipe par équipe, trimestre par trimestre</strong>. L'approche du <strong>Quarter Plan</strong> consiste à confronter, chaque trimestre, les engagements projet à la bande passante réelle de chaque équipe. Les organisations qui maîtrisent cette planification augmentent de <strong>68 % leurs chances de livrer leurs projets à temps</strong>. Le secret : identifier les goulots sur les compétences critiques (architectes IT, experts métiers, ingénieurs spécialisés) et accepter de reporter ce qui ne rentre pas dans le trimestre. Résultat : moins de surcharge, moins de retards en cascade, des engagements crédibles." }, { "type": "paragraph", "html": "<strong>4. Gestion proactive des risques</strong>" }, { "type": "paragraph", "html": "En ayant une vue consolidée du portefeuille, les risques sont identifiés à l'échelle de l'organisation, pas uniquement projet par projet. Un risque sur un projet structurant peut impacter tout le portefeuille : la GPP permet de l'anticiper." }, { "type": "paragraph", "html": "<strong>5. Meilleure communication avec les parties prenantes</strong>" }, { "type": "paragraph", "html": "Le reporting consolidé du portefeuille (tableau de bord, rapport flash, revue de portefeuille) offre aux dirigeants les données nécessaires pour prendre des décisions éclairées, sans avoir à plonger dans le détail de chaque projet." }, { "type": "paragraph", "html": "<strong>6. Agilité décisionnelle</strong>" }, { "type": "paragraph", "html": "Les roadmaps de SI à 3-5 ans figées appartiennent au passé. Avec une GPP moderne, la priorisation se fait en continu, à un rythme adapté aux changements de contexte de l'entreprise. Les données terrain remontent en temps réel, permettant des réajustements rapides." }, { "type": "quote", "text": "🏢 <strong>Idée reçue :</strong> \"La gestion de portefeuille de projets est réservée aux grandes entreprises.\" <strong>Faux.</strong> Les PME et ETI peuvent parfois en tirer encore plus de bénéfices, car elles ont plus d'agilité et la capacité de mettre en œuvre la démarche plus rapidement. L'enjeu est d'adapter le niveau de formalisme à la taille de l'organisation." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6997336f720e4b07874d2db7_6%20be%CC%81ne%CC%81fices%20du%20PPM%20en%20chiffres%20FR.jpg", "alt": "Statistiques clés de la gestion de portefeuille de projets — IBM, PMI" }, { "type": "heading", "level": 2, "id": "les-7-etapes-pour-deployer-une-gestion-de-portefeuille-de-projets-efficace", "text": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699733e0185a65bc475aebde_Les%207%20e%CC%81tapes%20du%20de%CC%81ploiement%20PPM%20FR.jpg", "alt": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace" }, { "type": "heading", "level": 3, "id": "etape-1-definir-les-objectifs-strategiques", "text": "Étape 1 — Définir les objectifs stratégiques" }, { "type": "paragraph", "html": "Tout commence par la boussole. Sans clarté sur la stratégie, votre portefeuille ne sera qu'un inventaire de projets sans cohérence." }, { "type": "paragraph", "html": "Trois actions concrètes pour cette étape :" }, { "type": "list", "ordered": false, "items": ["Formaliser la vision à 2-3 ans avec la Direction Générale", "Identifier les axes stratégiques prioritaires (croissance, efficacité, conformité, innovation...)", "Traduire ces axes en <strong>critères de sélection mesurables</strong> pour les projets"] }, { "type": "heading", "level": 3, "id": "etape-2-recenser-et-categoriser-tous-les-projets-intake", "text": "Étape 2 — Recenser et catégoriser tous les projets (Intake)" }, { "type": "paragraph", "html": "Créez un inventaire exhaustif de toutes les initiatives en cours et à venir : projets validés, projets en attente, idées en gestation. Centralisez toutes les demandes — qu'elles soient stratégiques, réglementaires, issues des métiers ou des clients — dans un processus unique d'<strong>intake</strong> (capture). C'est le meilleur moyen d'éliminer les redondances et d'identifier les opportunités de mutualisation." }, { "type": "paragraph", "html": "Chaque projet doit être documenté avec une fiche standardisée comprenant au minimum : objectif, sponsor, budget estimé, ressources nécessaires, échéance et contribution stratégique." }, { "type": "paragraph", "html": "Catégorisez ensuite vos projets par type (transformation, run, réglementaire, innovation...) et par programme si applicable." }, { "type": "heading", "level": 3, "id": "etape-3-evaluer-et-prioriser-les-projets", "text": "Étape 3 — Évaluer et prioriser les projets" }, { "type": "paragraph", "html": "C'est le cœur de la démarche. Appliquez vos critères de sélection pour noter et classer chaque projet. Les méthodes de priorisation sont détaillées dans la section suivante, mais l'essentiel est d'avoir une approche <strong>multicritère</strong> qui combine valeur business, faisabilité, risques et alignement stratégique." }, { "type": "heading", "level": 3, "id": "etape-4-aligner-la-capacite-avec-la-demande-quarter-plan", "text": "Étape 4 — Aligner la capacité avec la demande (Quarter Plan)" }, { "type": "paragraph", "html": "C'est l'étape la plus décisive — et la plus souvent bâclée. Pour chaque <strong>équipe</strong>, évaluez sa capacité réelle sur le <strong>trimestre à venir</strong> : jours-homme disponibles, une fois déduites les absences, le run, la maintenance et la marge d'imprévu. Puis confrontez cette capacité aux engagements projet." }, { "type": "paragraph", "html": "C'est souvent le moment de vérité : ce qui semblait prioritaire peut se révéler irréaliste si l'équipe concernée est déjà saturée. L'exercice doit être concret : non pas \"a-t-on les moyens au global ?\", mais <strong>\"l'équipe Data peut-elle absorber ce projet en Q2, ou faut-il le décaler en Q3 ?\"</strong>" }, { "type": "paragraph", "html": "L'objectif n'est pas de tout planifier au jour près. C'est de s'assurer que les engagements sont crédibles. Mieux vaut 5 projets livrés ce trimestre que 15 projets \"en cours\" dont aucun ne délivre de résultat tangible. Attention au piège du pourcentage d'avancement : un projet à \"60 %\" ne signifie pas qu'il est proche de livrer quoi que ce soit d'exploitable — c'est souvent juste un ratio de charge consommée." }, { "type": "heading", "level": 3, "id": "etape-5-definir-la-gouvernance-et-les-rituels", "text": "Étape 5 — Définir la gouvernance et les rituels" }, { "type": "paragraph", "html": "Mettez en place les instances de décision et les rituels récurrents qui feront vivre votre portefeuille :" }, { "type": "list", "ordered": false, "items": ["<strong>Revue de portefeuille mensuelle</strong> : arbitrages, décisions Go/No-Go, réallocation de ressources", "<strong>Comité de pilotage</strong> : validation des orientations stratégiques et des investissements majeurs", "<strong>Reporting hebdomadaire</strong> (rapport flash) : état d'avancement consolidé envoyé aux parties prenantes", "<strong>Point projet hebdomadaire</strong> : 5 minutes par projet entre chef de projet et référent métier"] }, { "type": "paragraph", "html": "Le PMI distingue trois types de PMO (Bureau de Gestion de Projets), selon le niveau de contrôle exercé :" }, { "type": "table", "headers": ["Type de PMO", "Rôle", "Niveau de contrôle"], "rows": [["Support", "Fournit modèles, outils et bonnes pratiques", "Faible — les équipes restent autonomes"], ["Contrôle", "Exige la conformité aux méthodologies via des audits", "Modéré — cadre structurant"], ["Directif", "Gère directement les projets et affecte les chefs de projet", "Élevé — pilotage centralisé"]] }, { "type": "paragraph", "html": "Le choix du type de PMO dépend de la maturité de votre organisation et de votre culture managériale. La tendance actuelle est au PMO \"facilitateur\" (entre Support et Contrôle), qui structure sans bureaucratiser. Plus largement, le succès en 2026 exige une <strong>métamorphose du PMO</strong> : il doit évoluer d'un rôle de support administratif vers celui de <strong>partenaire stratégique</strong>. Le pilotage stratégique ne consiste pas à surveiller des calendriers, mais à garantir que chaque euro et chaque heure investis servent la croissance de l'entreprise." }, { "type": "paragraph", "html": "Sans rituels réguliers, votre portefeuille deviendra vite obsolète. C'est la fréquence et la discipline de ces rituels qui créent la valeur." }, { "type": "heading", "level": 3, "id": "etape-6-outiller-la-demarche", "text": "Étape 6 — Outiller la démarche" }, { "type": "paragraph", "html": "Suivre un portefeuille de projets dans Excel n'est plus viable au-delà de 10 projets. Un <strong>outil PPM</strong> (Project Portfolio Management) dédié permet de centraliser les informations, automatiser le reporting et offrir une visibilité en temps réel à toutes les parties prenantes." }, { "type": "paragraph", "html": "Les critères clés pour choisir votre outil PPM sont détaillés dans la section dédiée ci-dessous." }, { "type": "heading", "level": 3, "id": "etape-7-piloter-en-continu-et-ameliorer", "text": "Étape 7 — Piloter en continu et améliorer" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets n'est pas un exercice ponctuel, c'est un processus continu. À chaque revue de portefeuille, posez-vous trois questions :" }, { "type": "list", "ordered": true, "items": ["Les projets en cours sont-ils toujours alignés avec la stratégie ?", "Faut-il ajouter, reporter ou arrêter des projets ?", "La capacité est-elle toujours suffisante pour tenir les engagements ?"] }, { "type": "quote", "text": "🎯 <strong>Conseil pragmatique :</strong> Ne cherchez pas la perfection au démarrage. Commencez avec un périmètre restreint (10-15 projets clés), des rituels simples et un outil adapté. Faites \"tache d'huile\" ensuite. La maturité se construit progressivement, comme un sachet de thé qui infuse." }, { "type": "heading", "level": 2, "id": "les-methodes-de-priorisation-dun-portefeuille-de-projets", "text": "Les méthodes de priorisation d'un portefeuille de projets" }, { "type": "paragraph", "html": "La priorisation est l'exercice le plus complexe et le plus politique de la gestion de portefeuille de projets. Voici les méthodes les plus utilisées." }, { "type": "heading", "level": 3, "id": "le-scoring-multicritere", "text": "Le scoring multicritère" }, { "type": "paragraph", "html": "Chaque projet est évalué sur une grille de critères pondérés. Les critères se répartissent généralement en trois familles :" }, { "type": "list", "ordered": false, "items": ["<strong>Critères financiers</strong> : Valeur Actuelle Nette (VAN), Retour sur Investissement (ROI), période de remboursement (payback)", "<strong>Critères stratégiques</strong> : Alignement avec les objectifs annuels, impact client, différenciation concurrentielle", "<strong>Critères opérationnels</strong> : Faisabilité technique, probabilité de réussite, urgence réglementaire, disponibilité des ressources"] }, { "type": "paragraph", "html": "Chaque critère reçoit un score (par exemple de 1 à 5) et un poids relatif. Le score pondéré total permet de classer les projets objectivement et d'établir une <strong>ligne de démarcation</strong> (cut-line) : les projets au-dessus passent, ceux en dessous sont reportés ou abandonnés. L'application de la cut-line est l'acte de management ultime : une fois que les ressources sont consommées par les projets les mieux notés, tout ce qui se trouve en dessous de la ligne doit être reporté ou annulé, sans exception. C'est la seule méthode pour garantir que les initiatives à fort impact reçoivent l'oxygène nécessaire à leur réussite — et pour protéger le portefeuille des \"projets de cœur\" (pet projects) dépourvus de valeur réelle." }, { "type": "paragraph", "html": "<strong>Avantage :</strong> Transparence, reproductibilité, facilité d'explication aux parties prenantes. <strong>Limite :</strong> La qualité du scoring dépend de la qualité des données d'entrée. Comme le souligne Robert Cooper, expert en gestion de portefeuille : <em>« La sophistication des méthodes financières dépasse souvent la qualité des données. Les méthodes purement comptables produisent parfois les résultats les plus médiocres si elles ne sont pas complétées par un jugement stratégique. »</em>" }, { "type": "heading", "level": 3, "id": "la-matrice-valeur-effort-et-risque-rendement", "text": "La matrice valeur / effort (et risque / rendement)" }, { "type": "paragraph", "html": "Cette approche simple et visuelle positionne chaque projet sur deux axes : la valeur attendue (impact business) et l'effort nécessaire (coût, complexité, durée). Les projets à forte valeur et faible effort (les \"quick wins\") sont prioritaires." }, { "type": "paragraph", "html": "Une variante couramment utilisée est la <strong>matrice risque-rendement</strong>, qui permet d'équilibrer le portefeuille entre quatre quadrants : les \"Quick Wins\" (faible risque, haut rendement), les projets stratégiques (haut risque, haut rendement), les projets d'optimisation (faible risque, faible rendement) et les projets à éviter (haut risque, faible rendement)." }, { "type": "paragraph", "html": "<strong>Avantage :</strong> Visuel, rapide à mettre en place, excellent pour les ateliers de priorisation. <strong>Limite :</strong> Réducteur pour les projets complexes à impact long terme" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/69975dc546f627807d618489_Matrice%20Valeur%20-Effort%20FR.png", "alt": "Matrice de priorisation valeur-effort pour le portefeuille de projets" }, { "type": "heading", "level": 3, "id": "la-methode-moscow", "text": "La méthode MoSCoW" }, { "type": "paragraph", "html": "Classez les projets en quatre catégories : <strong>Must have</strong> (vital), <strong>Should have</strong> (important), <strong>Could have</strong> (souhaitable), <strong>Won't have</strong> (pas maintenant). Cette méthode issue du monde agile est particulièrement adaptée quand il faut trancher rapidement." }, { "type": "heading", "level": 3, "id": "le-modele-wsjf-weighted-shortest-job-first", "text": "Le modèle WSJF (Weighted Shortest Job First)" }, { "type": "paragraph", "html": "Issu du framework SAFe, le WSJF priorise en divisant la valeur (<strong>coût du retard</strong> — Cost of Delay) par la taille de l'effort. Le coût du retard combine trois composantes : la valeur business/utilisateur, la criticité temporelle (fenêtre d'opportunité) et la réduction de risque ou l'opportunité d'apprentissage. Les projets à fort coût du retard et de petite taille passent en premier. C'est la méthode la plus utilisée dans les organisations ayant adopté l'agilité à l'échelle." }, { "type": "heading", "level": 3, "id": "la-methode-rice", "text": "La méthode RICE" }, { "type": "paragraph", "html": "RICE est un modèle de scoring rapide qui évalue chaque projet selon 4 dimensions : <strong>Reach</strong> (portée/nombre de personnes impactées), <strong>Impact</strong> (degré d'impact par personne), <strong>Confidence</strong> (niveau de confiance dans les estimations) et <strong>Effort</strong> (charge de travail nécessaire). Le score RICE = (Reach × Impact × Confidence) / Effort. Les projets avec le score le plus élevé sont priorisés." }, { "type": "heading", "level": 3, "id": "la-priorisation-par-le-lean-portfolio-management", "text": "La priorisation par le Lean Portfolio Management" }, { "type": "paragraph", "html": "Le <strong>Lean Portfolio Management</strong> (LPM) va plus loin en intégrant la priorisation dans un flux continu, aligné sur les objectifs stratégiques (OKR ou Epics stratégiques). La capacité est allouée par \"flux de valeur\" plutôt que par projet, ce qui permet une plus grande agilité dans les arbitrages." }, { "type": "table", "headers": ["Caractéristique", "PPM traditionnelle", "Lean Portfolio Management"], "rows": [["Financement", "Basé sur des projets spécifiques", "Basé sur les chaînes de valeur (Value Streams)"], ["Planification", "Cycle annuel rigide", "Glissante, itérative, ajustée chaque trimestre"], ["Gouvernance", "Contrôle centralisé (Top-down)", "Décisions décentralisées avec garde-fous"], ["Focus", "Administration de projets individuels", "Performance économique globale du portefeuille"]] }, { "type": "paragraph", "html": "Le passage au LPM marque la fin de la planification annuelle rigide, souvent obsolète dès le premier trimestre. On ne finance plus des projets isolés (approche \"Fire and Forget\"), mais des chaînes de valeur continues. Cette agilité est sécurisée par trois <strong>garde-fous</strong> (Guardrails) :" }, { "type": "list", "ordered": true, "items": ["<strong>Investissement par horizon</strong> : Équilibre entre maintenance du patrimoine existant, gains immédiats (quick wins) et innovation de rupture.", "<strong>Allocation de capacité</strong> : Arbitrage strict entre le développement de nouvelles fonctionnalités et la réduction de la dette technique.", "<strong>Indicateurs basés sur les résultats</strong> : Utilisation de KPIs liés aux résultats réels (Outcomes) plutôt qu'au simple avancement des tâches (Outputs)."] }, { "type": "heading", "level": 3, "id": "lanalyse-de-simulation-what-if", "text": "L'analyse de simulation « What-If »" }, { "type": "paragraph", "html": "L'analyse de scénarios est un levier puissant pour s'extraire de la gestion de crise permanente et troquer l'intuition contre l'<strong>analyse d'impact prédictive</strong>. Une simulation rigoureuse repose sur trois étapes :" }, { "type": "list", "ordered": true, "items": ["<strong>Identification des variables</strong> : Isoler les leviers critiques — budgets, disponibilité des compétences clés, <strong>coût du retard</strong> (Cost of Delay), dépendances inter-projets.", "<strong>Modélisation de scénarios</strong> : Construire des trajectoires optimiste, pessimiste et \"plus probable\" pour tester la résilience du portefeuille.", "<strong>Évaluation de l'impact</strong> : Mesurer précisément la dérive potentielle sur les délais, les coûts et la charge de travail globale."] }, { "type": "paragraph", "html": "Par exemple : simuler l'ajout d'un projet urgent pour mesurer le décalage sur les dates de livraison des initiatives en cours, ou évaluer l'impact d'une réduction budgétaire de 15 % sur la composition du portefeuille. Les outils PPM modernes intègrent ces capacités de simulation pour éclairer les décisions d'arbitrage en comité de pilotage — mettant fin au règne de \"la voix la plus forte\" en comité de direction." }, { "type": "quote", "text": "⚡ <strong>Bonne pratique AirSaaS :</strong> Les portefeuilles priorisés à 2-3 ans figés, c'était avant. Aujourd'hui, la priorisation en continu est la pratique courante. Un sondage AirSaas (2022) montre que la majorité des DSI repriorisent leur portefeuille au minimum chaque trimestre, et souvent chaque mois." }, { "type": "heading", "level": 2, "id": "les-kpis-essentiels-du-pilotage-de-portefeuille", "text": "Les KPIs essentiels du pilotage de portefeuille" }, { "type": "paragraph", "html": "Piloter un portefeuille de projets sans indicateurs, c'est conduire sans tableau de bord. Voici les KPIs incontournables, organisés en 4 catégories." }, { "type": "heading", "level": 3, "id": "kpis-dalignement-strategique", "text": "KPIs d'alignement stratégique" }, { "type": "list", "ordered": false, "items": ["<strong>% de projets alignés avec les axes stratégiques</strong> : Chaque projet doit être rattaché à un objectif. Un portefeuille sain affiche 80 à 100 % d'alignement.", "<strong>Répartition budgétaire par axe stratégique</strong> : Visualiser si les investissements sont cohérents avec les priorités déclarées.", "<strong>Bénéfices réalisés</strong> : Valeur réelle constatée post-clôture, comparée aux bénéfices attendus lors de la sélection."] }, { "type": "heading", "level": 3, "id": "kpis-de-capacite-et-ressources", "text": "KPIs de capacité et ressources" }, { "type": "list", "ordered": false, "items": ["<strong>Taux d'utilisation des ressources</strong> : Temps productif vs temps total disponible. Au-delà de 80 %, le risque de surcharge est élevé.", "<strong>Ratio demande vs capacité</strong> : Combien de projets sont en attente faute de bande passante ?", "<strong>Productivité par ressource</strong> : Tâches ou jalons accomplis par période, pour identifier les écarts de performance.", "<strong>Churn de l'équipe</strong> : Rotation du personnel en cours de projet — un indicateur avancé de problèmes de management ou de surcharge."] }, { "type": "heading", "level": 3, "id": "kpis-de-performance-operationnelle", "text": "KPIs de performance opérationnelle" }, { "type": "list", "ordered": false, "items": ["<strong>% de projets \"au vert\" / \"à risque\" / \"en alerte\"</strong> : Le triptyque météo classique, indispensable pour une revue de portefeuille efficace.", "<strong>Taux de respect des jalons</strong> : Les jalons clés sont-ils atteints dans les délais ?", "<strong>Variance budgétaire</strong> : Écart entre coûts prévus et coûts réels — un signal d'alerte précoce.", "<strong>Nombre de demandes de changement</strong> : Indicateur de la stabilité du périmètre. Un nombre élevé signale un cadrage initial insuffisant.", "<strong>Indice de santé du projet</strong> : Score composite combinant coût, délai et risque en un seul indicateur.", "<strong>Conformité</strong> : Adhérence aux processus, méthodologies et réglementations en vigueur."] }, { "type": "heading", "level": 3, "id": "kpis-de-valeur-et-resultats", "text": "KPIs de valeur et résultats" }, { "type": "list", "ordered": false, "items": ["<strong>ROI des projets livrés</strong> : Le portefeuille crée-t-il réellement la valeur financière attendue ?", "<strong>Délai de livraison (Time to Market)</strong> : Combien de temps entre la décision de lancer un projet et la première livraison de valeur ?", "<strong>Taux d'annulation</strong> : Capacité de l'organisation à arrêter les projets non rentables — un signe de maturité, pas d'échec.", "<strong>Satisfaction des parties prenantes</strong> : Enquêtes de satisfaction auprès des sponsors, métiers et équipes projet.", "<strong>Gestion des risques</strong> : Ratio risques mitigés vs risques identifiés — mesure l'efficacité de l'anticipation."] }, { "type": "quote", "text": "📊 <strong>Conseil :</strong> Ne multipliez pas les indicateurs. 5 à 8 KPIs bien choisis et mis à jour régulièrement valent mieux que 18 indicateurs jamais consultés. Sélectionnez ceux qui correspondent à votre niveau de maturité et enrichissez progressivement. L'enjeu est que votre tableau de bord de portefeuille raconte une histoire claire en 30 secondes." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/699734d9e8f99e6b413126ef_Page%20Portfolio%20FR.png", "alt": "Tableau de bord de gestion de portefeuille de projets — interface AirSaas" }, { "type": "heading", "level": 2, "id": "comment-choisir-son-outil-ppm", "text": "Comment choisir son outil PPM ?" }, { "type": "paragraph", "html": "Le marché des outils de gestion de portefeuille de projets a considérablement évolué. Fini les usines à gaz ERP/PPM des années 2010. Les solutions modernes misent sur la simplicité, la collaboration et l'automatisation." }, { "type": "heading", "level": 3, "id": "les-criteres-essentiels-dun-bon-outil-ppm", "text": "Les critères essentiels d'un bon outil PPM" }, { "type": "paragraph", "html": "<strong>Simplicité d'adoption</strong> : L'outil doit être utilisable par les chefs de projet, les métiers ET la direction, sans formation complexe. Si personne ne l'utilise, il ne sert à rien." }, { "type": "paragraph", "html": "<strong>Vue portefeuille consolidée</strong> : Tableaux de bord visuels avec filtres (par programme, par axe stratégique, par météo projet, par responsable). La vue macro est la raison d'être de l'outil." }, { "type": "paragraph", "html": "<strong>Reporting automatisé</strong> : Génération automatique de rapports flash (PPT, PDF, URL) pour le Comité de pilotage, sans passer 4 jours à compiler des données manuellement." }, { "type": "paragraph", "html": "<strong>Gestion des rituels</strong> : L'outil doit structurer vos revues de portefeuille, vos points projet et vos Copil avec des workflows adaptés." }, { "type": "paragraph", "html": "<strong>Intégration avec l'écosystème existant</strong> : Connexion native avec les outils de gestion de tâches (Jira, Asana, Monday, Azure DevOps) pour faire remonter les données opérationnelles sans double saisie." }, { "type": "paragraph", "html": "<strong>Collaboration temps réel</strong> : Toutes les parties prenantes (DSI, métiers, direction) contribuent sur la même plateforme. Plus de \"je ne savais pas\"." }, { "type": "heading", "level": 3, "id": "ce-quun-outil-ppm-ne-resout-pas", "text": "Ce qu'un outil PPM ne résout pas" }, { "type": "paragraph", "html": "Un outil, aussi bon soit-il, ne peut pas compenser une gouvernance floue, des objectifs stratégiques non définis ou un management indécis. L'outil est un catalyseur : il amplifie les bonnes pratiques, mais ne les crée pas." }, { "type": "quote", "text": "🚀 <strong>AirSaaS</strong> est l'outil de gestion de portefeuille de projets conçu pour les DSI, PMO et directeurs de transformation qui veulent allier simplicité et efficacité. Tableau de bord visuel, rapport flash automatique, intégrations natives et collaboration temps réel. <a href=\"/fr/solution/management-de-portefeuille-projet\">Découvrir AirSaas→</a>" }, { "type": "heading", "level": 2, "id": "les-erreurs-a-eviter-en-gestion-de-portefeuille-de-projets", "text": "Les erreurs à éviter en gestion de portefeuille de projets" }, { "type": "paragraph", "html": "Après des centaines d'échanges avec des DSI, PMO et directeurs de transformation, voici les erreurs les plus fréquentes que nous observons." }, { "type": "heading", "level": 3, "id": "erreur-n1-confondre-gestion-de-portefeuille-et-gestion-de-projet", "text": "Erreur n°1 — Confondre gestion de portefeuille et gestion de projet" }, { "type": "paragraph", "html": "Le portefeuille ne sert pas à micro-manager les tâches de chaque projet. Il sert à prendre des décisions stratégiques : quels projets lancer, arrêter, accélérer ou reporter. Mélanger les niveaux crée de la confusion et alourdit la gouvernance." }, { "type": "heading", "level": 3, "id": "erreur-n2-ne-pas-oser-arreter-un-projet", "text": "Erreur n°2 — Ne pas oser arrêter un projet" }, { "type": "paragraph", "html": "Un portefeuille qui ne \"tue\" jamais de projet est un portefeuille malade. Si un projet ne crée plus de valeur, a vu son contexte changer ou mobilise des ressources critiques, il faut savoir le stopper. C'est un signe de maturité, pas d'échec." }, { "type": "heading", "level": 3, "id": "erreur-n3-sous-estimer-la-gestion-de-la-capacite", "text": "Erreur n°3 — Sous-estimer la gestion de la capacité" }, { "type": "paragraph", "html": "Valider 20 projets quand on a la capacité d'en mener 8 correctement, c'est la recette de l'échec collectif. Et la capacité ne se gère pas \"au global\" — elle se gère <strong>équipe par équipe, trimestre par trimestre</strong>. Une organisation peut avoir du budget disponible et des ressources \"sur le papier\", mais si l'équipe Data est saturée au Q2, aucun projet Data ne délivrera. L'incapacité chronique à dire \"non\" est le symptôme le plus répandu des organisations immatures en PPM. La gestion de portefeuille de projets impose de confronter la demande à la réalité de la capacité de chaque équipe — et d'assumer les arbitrages qui en découlent." }, { "type": "heading", "level": 3, "id": "erreur-n4-se-fier-au-pourcentage-davancement", "text": "Erreur n°4 — Se fier au pourcentage d'avancement" }, { "type": "paragraph", "html": "Le % d'avancement est l'un des indicateurs les plus trompeurs du pilotage de portefeuille. Un projet affiché à 70 % peut être à des mois de livrer le moindre délivrable exploitable. Ce chiffre mesure le plus souvent la <strong>consommation de charge</strong> (combien de jours ont été passés) et non la <strong>proximité d'un résultat tangible</strong>. Les organisations matures en PPM remplacent le % d'avancement par des indicateurs concrets : jalons atteints, délivrables acceptés, fonctionnalités livrées en production. La question à poser en revue de portefeuille n'est jamais \"à combien de % en est-on ?\", mais <strong>\"qu'est-ce qui sera livré et utilisable à la fin du trimestre ?\"</strong>" }, { "type": "heading", "level": 3, "id": "erreur-n5-un-reporting-heterogene-et-chronophage", "text": "Erreur n°5 — Un reporting hétérogène et chronophage" }, { "type": "paragraph", "html": "Si chaque chef de projet produit son reporting dans un format différent, à une fréquence aléatoire, le Comité de pilotage ne pourra jamais avoir une vision claire du portefeuille. Standardisez le format, automatisez la collecte, fixez un rythme régulier." }, { "type": "heading", "level": 3, "id": "erreur-n6-lancer-la-demarche-sans-sponsorship", "text": "Erreur n°6 — Lancer la démarche sans sponsorship" }, { "type": "paragraph", "html": "La gestion de portefeuille de projets touche aux budgets, aux priorités et parfois aux jeux de pouvoir. Sans sponsor au niveau Direction Générale ou DSI, la démarche s'essouffle dès les premiers arbitrages difficiles." }, { "type": "heading", "level": 3, "id": "erreur-n7-vouloir-tout-faire-dun-coup", "text": "Erreur n°7 — Vouloir tout faire d'un coup" }, { "type": "paragraph", "html": "Privilégiez une approche progressive : démarrez sur un périmètre limité, avec des rituels simples et un petit nombre de projets pilotes. Montrez les premiers résultats, puis étendez. L'adoption se fait par la preuve, pas par le décret." }, { "type": "heading", "level": 2, "id": "faq-gestion-de-portefeuille-de-projets", "text": "FAQ — Gestion de portefeuille de projets" }, { "type": "heading", "level": 3, "id": "quest-ce-quun-portefeuille-de-projets", "text": "Qu'est-ce qu'un portefeuille de projets ?" }, { "type": "paragraph", "html": "Un portefeuille de projets est l'ensemble des projets, programmes et opérations d'une organisation, gérés collectivement pour atteindre les objectifs stratégiques. Wikipédia le définit comme <em>\"la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage\"</em> (Fernez-Walch, 2004)." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-gestion-de-portefeuille-de-projets-et-gestion-multi-projets", "text": "Quelle est la différence entre gestion de portefeuille de projets et gestion multi-projets ?" }, { "type": "paragraph", "html": "La <strong>gestion multi-projets</strong> est opérationnelle : elle vise à gérer efficacement plusieurs projets en parallèle (planning, ressources, dépendances). La <strong>gestion de portefeuille</strong> est stratégique : elle décide quels projets lancer et dans quel ordre, en fonction de leur contribution à la stratégie. En résumé, le multi-projet s'occupe du \"comment\", le portefeuille s'occupe du \"quoi\"." }, { "type": "heading", "level": 3, "id": "qui-est-responsable-de-la-gestion-du-portefeuille-de-projets", "text": "Qui est responsable de la gestion du portefeuille de projets ?" }, { "type": "paragraph", "html": "En général, c'est le <strong>PMO</strong> (Project Management Office), le <strong>DSI</strong> ou le <strong>Directeur de transformation</strong> qui pilote la gestion de portefeuille. Mais les décisions d'arbitrage impliquent la Direction Générale et les directions métiers. La gestion de portefeuille de projets est par nature transverse et collaborative." }, { "type": "heading", "level": 3, "id": "quelle-est-la-difference-entre-un-outil-ppm-et-un-outil-de-gestion-de-projet", "text": "Quelle est la différence entre un outil PPM et un outil de gestion de projet ?" }, { "type": "paragraph", "html": "Un <strong>outil de gestion de projet</strong> (Jira, Asana, Monday, Trello) permet de gérer les tâches, le planning et les ressources d'un projet individuel. Un <strong>outil PPM</strong> permet de piloter l'ensemble du portefeuille : vue consolidée, arbitrages, reporting stratégique, alignement avec les objectifs. Les deux sont complémentaires et doivent idéalement être connectés." }, { "type": "heading", "level": 3, "id": "la-gestion-de-portefeuille-de-projets-est-elle-adaptee-aux-pme", "text": "La gestion de portefeuille de projets est-elle adaptée aux PME ?" }, { "type": "paragraph", "html": "Absolument. La taille de l'entreprise ne détermine pas le besoin, c'est le nombre de projets en concurrence pour les mêmes ressources qui compte. Dès qu'une PME gère plus de 5-10 projets transverses en parallèle, une démarche de portefeuille — même légère — apporte une valeur considérable. Les PME ont d'ailleurs souvent plus d'agilité pour la mettre en œuvre." }, { "type": "heading", "level": 3, "id": "a-quelle-frequence-faut-il-reprioriser-son-portefeuille-de-projets", "text": "À quelle fréquence faut-il reprioriser son portefeuille de projets ?" }, { "type": "paragraph", "html": "La priorisation en continu est devenue la pratique dominante. La plupart des organisations matures réalisent une revue de portefeuille formelle chaque mois, avec des points d'arbitrage ponctuels si le contexte l'exige. Les roadmaps figées à 2-3 ans ont laissé place à un pilotage agile et adaptatif." }, { "type": "heading", "level": 3, "id": "quels-sont-les-principaux-frameworks-pour-la-gestion-de-portefeuille-de-projets", "text": "Quels sont les principaux frameworks pour la gestion de portefeuille de projets ?" }, { "type": "paragraph", "html": "Les frameworks les plus reconnus sont : le <strong>Standard for Portfolio Management du PMI</strong>, <strong>MoP (Management of Portfolios)</strong> de AXELOS, le <strong>Lean Portfolio Management (LPM)</strong> du framework SAFe, et les approches inspirées du <strong>OKR</strong> (Objectives and Key Results). Le choix dépend de la culture et de la maturité de votre organisation." }, { "type": "heading", "level": 2, "id": "pour-aller-plus-loin", "text": "Pour aller plus loin" }, { "type": "list", "ordered": false, "items": ["<a href=\"/fr/gestion-de-projet/lean-portfolio-management\">Lean Portfolio Management : aligner direction générale, IT et métiers</a>", "<a href=\"/fr/solution/revue-de-portefeuille\">Revue de portefeuille : bonnes pratiques et guide complet</a>", "<a href=\"/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet\">Les 10 erreurs à ne pas commettre dans la mise en place d'un portefeuille projet</a>", "<a href=\"/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme\">Gestion de portefeuille de projets en PME : bénéfices et bonnes pratiques</a>", "<a href=\"/fr/guide/cahier-des-charges-logiciel-ppm\">Outil PPM : le cahier des charges pour bien choisir</a>", "<a href=\"/fr/solution/management-de-portefeuille-projet\">Découvrir AirSaaS, l'outil PPM des DSI et PMO</a>"] }], "toc": [{ "href": "#pour-aller-plus-loin", "label": "Pour aller plus loin", "level": 2 }, { "href": "#portefeuille-de-projets-vs-programme-vs-projet-quelles-differences", "label": "Portefeuille de projets vs programme vs projet : quelles différences ?", "level": 2 }, { "href": "#pourquoi-mettre-en-place-une-gestion-de-portefeuille-de-projets", "label": "Pourquoi mettre en place une gestion de portefeuille de projets ?", "level": 2 }, { "href": "#les-7-etapes-pour-deployer-une-gestion-de-portefeuille-de-projets-efficace", "label": "Les 7 étapes pour déployer une gestion de portefeuille de projets efficace", "level": 2 }, { "href": "#les-methodes-de-priorisation-dun-portefeuille-de-projets", "label": "Les méthodes de priorisation d'un portefeuille de projets", "level": 2 }, { "href": "#les-kpis-essentiels-du-pilotage-de-portefeuille", "label": "Les KPIs essentiels du pilotage de portefeuille", "level": 2 }, { "href": "#comment-choisir-son-outil-ppm", "label": "Comment choisir son outil PPM ?", "level": 2 }, { "href": "#les-erreurs-a-eviter-en-gestion-de-portefeuille-de-projets", "label": "Les erreurs à éviter en gestion de portefeuille de projets", "level": 2 }, { "href": "#faq-gestion-de-portefeuille-de-projets", "label": "FAQ — Gestion de portefeuille de projets", "level": 2 }], "faq": [{ "question": "Qu'est-ce qu'un portefeuille de projets ?", "answer": "Un portefeuille de projets est l'ensemble des projets, programmes et opérations d'une organisation, gérés collectivement pour atteindre les objectifs stratégiques. Wikipédia le définit comme \"la discipline traitant des projets pris d'un point de vue global dans un but de sélection et d'arbitrage\" (Fernez-Walch, 2004)." }, { "question": "Quelle est la différence entre gestion de portefeuille de projets et gestion multi-projets ?", "answer": "La gestion multi-projets est opérationnelle : elle vise à gérer efficacement plusieurs projets en parallèle (planning, ressources, dépendances). La gestion de portefeuille est stratégique : elle décide quels projets lancer et dans quel ordre, en fonction de leur contribution à la stratégie. En résumé, le multi-projet s'occupe du \"comment\", le portefeuille s'occupe du \"quoi\"." }, { "question": "Qui est responsable de la gestion du portefeuille de projets ?", "answer": "En général, c'est le PMO (Project Management Office), le DSI ou le Directeur de transformation qui pilote la gestion de portefeuille. Mais les décisions d'arbitrage impliquent la Direction Générale et les directions métiers. La gestion de portefeuille de projets est par nature transverse et collaborative." }, { "question": "Quelle est la différence entre un outil PPM et un outil de gestion de projet ?", "answer": "Un outil de gestion de projet (Jira, Asana, Monday, Trello) permet de gérer les tâches, le planning et les ressources d'un projet individuel. Un outil PPM permet de piloter l'ensemble du portefeuille : vue consolidée, arbitrages, reporting stratégique, alignement avec les objectifs. Les deux sont complémentaires et doivent idéalement être connectés." }, { "question": "La gestion de portefeuille de projets est-elle adaptée aux PME ?", "answer": "Absolument. La taille de l'entreprise ne détermine pas le besoin, c'est le nombre de projets en concurrence pour les mêmes ressources qui compte. Dès qu'une PME gère plus de 5-10 projets transverses en parallèle, une démarche de portefeuille — même légère — apporte une valeur considérable. Les PME ont d'ailleurs souvent plus d'agilité pour la mettre en œuvre." }, { "question": "À quelle fréquence faut-il reprioriser son portefeuille de projets ?", "answer": "La priorisation en continu est devenue la pratique dominante. La plupart des organisations matures réalisent une revue de portefeuille formelle chaque mois, avec des points d'arbitrage ponctuels si le contexte l'exige. Les roadmaps figées à 2-3 ans ont laissé place à un pilotage agile et adaptatif." }, { "question": "Quels sont les principaux frameworks pour la gestion de portefeuille de projets ?", "answer": "Les frameworks les plus reconnus sont : le Standard for Portfolio Management du PMI, MoP (Management of Portfolios) de AXELOS, le Lean Portfolio Management (LPM) du framework SAFe, et les approches inspirées du OKR (Objectives and Key Results). Le choix dépend de la culture et de la maturité de votre organisation." }], "related": [{ "href": "/fr/gestion-de-projet/lean-portfolio-management", "label": "Lean Portfolio Management : aligner direction générale, IT et métiers" }, { "href": "/fr/solution/revue-de-portefeuille", "label": "Revue de portefeuille : bonnes pratiques et guide complet" }, { "href": "/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet", "label": "Les 10 erreurs à ne pas commettre dans la mise en place d'un portefeuille projet" }, { "href": "/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme", "label": "Gestion de portefeuille de projets en PME : bénéfices et bonnes pratiques" }, { "href": "/fr/guide/cahier-des-charges-logiciel-ppm", "label": "Outil PPM : le cahier des charges pour bien choisir" }, { "href": "/fr/solution/management-de-portefeuille-projet", "label": "Découvrir AirSaaS, l'outil PPM des DSI et PMO" }] }, { "slug": "pourquoi-mettre-en-place-un-pmo", "skip": false, "meta": { "title": "Pourquoi mettre en place un PMO ?", "h1": "Pourquoi mettre en place un PMO ?", "description": "Pourquoi mettre en place un PMO ? Découvrez les raisons clés qui poussent les entreprises à créer un Project Management Office pour structurer leurs projets transverses.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63f9aca975301ae018a7bf06_why%20pmo-min.jpg", "alt": "" }, "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "26/2/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "publishedDate": "26/2/2023" }, "blocks": [{ "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3e69ce2ca4c58ebea1c4_PMO-1-min.png", "alt": "PMO Bureau des projets", "caption": "project management office - terme anglo saxon pour bureau des projets" }, { "type": "heading", "level": 2, "id": "lenvolee-des-projets-transverses", "text": "L'envolée des projets transverses" }, { "type": "paragraph", "html": "L'accélération digitale génère des <strong>enjeux forts d'adaptation et de transformation</strong> pour les entreprises qui se traduisent par une explosion du nombre de projets transverses et des projets de transformations, notamment digitaux." }, { "type": "paragraph", "html": "Cette prolifération de projets a <strong>multiplié</strong> les <strong>obstacles structurels et culturels</strong> pour les organisations. Elles ont pourtant un<strong> besoin quasi vital d'innover</strong> avec efficience pour mener à bien tous ces projets transverses <strong>sans </strong>pour autant<strong> déstabiliser ce qui fonctionne </strong>dans les verticales métiers." }, { "type": "paragraph", "html": "De nombreux exemples ont démontré que ces projets de transformation sont indispensables pour la survie même de l'entreprise. Cependant ils génèrent beaucoup de nouvelles problématiques, parmi lesquelles le syndrome du projet raté : environ 70% des projets échouent (études Mc Kinsey, IBM et Project Management Institute)." }, { "type": "heading", "level": 2, "id": "projets-silos-et-transformation-le-parfait-oxymore", "text": "Projets silos et transformation, le parfait oxymore" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3e9b96fb86ebcf881f11_PMO-2-min.png", "alt": "Les paradoxes de la mission de PMO", "caption": "project management office vs silos" }, { "type": "paragraph", "html": "Les projets de transformation sont à la très grande majorité transverses et possèdent un aspect digital, avec des services ayant des appétences plus ou moins importantes pour cet aspect-là." }, { "type": "paragraph", "html": "Quand ils sont menés de manière isolée dans chaque service, on se rend compte d'u<strong>n gaspillage de ressources </strong>avec des <strong>projets menés en doublon </strong>par plusieurs services parfois en simultané." }, { "type": "paragraph", "html": "Dans la conduite des projets en silos,<strong> la pédagogie par l'erreur coûte cher à l'entreprise.</strong> Le <strong>manque d'ouverture à l'extérieur et aux autres services</strong> ne permet pas d'accéder aux retours d'expériences nécessaires pour <strong>rendre la conduite de projets plus simple</strong> et plus <strong>efficace</strong>." }, { "type": "paragraph", "html": "Ensuite dans le cas d'une gouvernance mono-service des projets de transformation on abandonne souvent beaucoup de projets en phase d'implémentation, ceci est lié notamment aux non-conformités avec les process de l'entreprise et à la mauvaise implication des autres services en amont." }, { "type": "paragraph", "html": "De plus, avec cette gouvernance mono-service, on rentre dans une dynamique de <strong>\"techno push\"</strong> induite souvent par une incompréhension des besoins métiers (ou un besoin relégué au second plan par rapport aux desseins du service en question), générant un climat pesant autour de ces projets, une dynamique de clients/fournisseurs qui s'installe entre les métiers et le service en charge, avec dans le pire des cas, des guerres d'ego et jeux politiques renforçant la résistance aux changements." }, { "type": "paragraph", "html": "Plutôt que de rassembler autour d'objectifs d'entreprise, les projets menés \"en silos\" finissent généralement en relatif échec, générant frustrations et sentiment de pertes de temps. Cela diffuse par la même occasion une dynamique toxique pour la poursuite de la transformation dans l'entreprise et surtout ne favorise pas l'engagement des collaborateurs \"fatigués\" par ce type de projet en mode échec systématique." }, { "type": "paragraph", "html": "Rappelons-le : <strong>un seul service métier ne peut transformer à lui seul toute l'entreprise.</strong> Il s'agit d'un enjeu collectif qui nécessite à tous de pouvoir se <strong>repérer, s'adapter et se projeter</strong>. Une transition où les silos sont alors un véritable problème structurel." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3eea4311849ae9aef307_silos-min.jpeg", "alt": "Les silos d'une entreprise", "caption": "Organisation classique d'une entreprise - départements sales, marketing, etc" }, { "type": "paragraph", "html": "Plus loin nous verrons également un autre échec des projets en silos : l'incapacité des différents services à collaborer." }, { "type": "heading", "level": 2, "id": "limpact-rh-des-projets-transverses", "text": "L'impact RH des projets transverses" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3f182b794fe40158cf5a_impact-pmo-min.png", "alt": "Impact d'un PMO dans votre organisation", "caption": "pmo project management office - portefeuille de projets" }, { "type": "paragraph", "html": "<strong>Les équipes sont sous l'eau ? Et si on leur ajoutait une casquette de chef de projet transverse en plus ?</strong>" }, { "type": "paragraph", "html": "Avec cette flambée de nouveaux projets, il faut bien évidemment des nouveaux rôles et collaborateurs pour les mener à bien. On a dans ces projets, souvent besoin de connaissances métier en ne pouvant justifier que rarement l'immobilisation d'un ETP." }, { "type": "paragraph", "html": "On en demande de plus en plus aux collaborateurs clés, souvent déjà bien chargés par leurs activités principales de travailler sur toujours plus de projets et ce, en mode best effort." }, { "type": "paragraph", "html": "La <strong>gestion de projet transverse </strong>n'est en réalité <strong>pas aussi évidente qu'il y paraît</strong> et a besoin, avec la multiplication des projets, de se structurer ainsi que de<strong> s'appuyer sur une culture forte</strong>." }, { "type": "paragraph", "html": "À cause de la<strong> multiplication de la charge de travail</strong> et des tâches, de la <strong>charge mentale</strong>, ou de la dépriorisation des projets et du <strong>manque de sens pour les équipes,</strong> on constate très souvent un <strong>manque d'engagement des collaborateurs</strong> dans les projets, moteur nécessaire et essentiel de leurs réussites." }, { "type": "paragraph", "html": "On constate également souvent, une très <strong>mauvaise adoption des solutions </strong>et des technologies, qui contribue un peu plus a<strong>u désengagement et à l'échec des projets.</strong>" }, { "type": "paragraph", "html": "Ceci peut aussi s'expliquer par une nécessité des projets pour être menés à bien, d'un <strong>nombre de compétences</strong> à avoir qui est <strong>grandissant</strong> et qui, sans formations et sans ressources supplémentaires, contribuent à la mise en échec des équipes." }, { "type": "paragraph", "html": "Il arrive que pour certains projets on puisse justifier l'embauche de compétences spécifiques face à ces nouveaux besoins, particulièrement pour les aspects digitaux, cependant ces profils sont en tension sur le marché et de plus en plus difficiles à recruter car de plus en plus demandés. De plus, si le digital n'est pas cœur de métier ou n'est pas très imprégné dans l'entreprise, les<strong> probabilités de faire des erreurs de recrutement augmentent.</strong>" }, { "type": "paragraph", "html": "Enfin, même en passant par l'externe et la sous-traitance il faut un<strong> minimum de ces connaissances en interne </strong>pour arriver à<strong> suivre et à challenger ces nouvelles prestations.</strong>" }, { "type": "paragraph", "html": "Ici <strong>le </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/metier-pmo\" target=\"_blank\"><strong>PMO</strong></a><strong> a un rôle fort à jouer</strong>, il va pouvoir<strong> aider les collaborateurs à mieux adapter leur gestion de projets </strong>pour <strong>rendre leur temps limité plus efficace</strong> ainsi que les aider sur les bonnes pratiques et les réalités du marché du digital." }, { "type": "heading", "level": 2, "id": "difficultes-pour-les-differents-services-a-collaborer", "text": "Difficultés pour les différents services à collaborer" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3f2896fb86b4c188a67d_coop-pmo-min.png", "alt": "coopration PMO", "caption": "project management vs project management office" }, { "type": "paragraph", "html": "Nous pouvons citer ici quelques barrières connues qui empêchent la collaboration :" }, { "type": "list", "ordered": false, "items": ["<strong>Temps et ressources</strong> à allouer pour les projets <strong>en conflit avec les activités </strong>principales", "<strong>Façons de travailler différentes</strong> selon les <strong>services</strong>", "<strong>Difficulté</strong> à identifier qui pourrait<strong> aider</strong> dans les autres services, de <strong>demander</strong> de l'aide, ne <strong>pas arriver à travailler ensemble</strong>.", "Guerre d'ego", "<strong>Réticence</strong> <strong>à donner du temps</strong> en best effort", "<strong>Communication</strong> et <strong>suivi difficile</strong>", "<strong>Incapacité à fonctionner efficacement en mode projet</strong>, avec les bonnes méthodes et outils"] }, { "type": "paragraph", "html": "Un PMO ici pourra agir dans la résolution ou l'anticipation des problèmes ci-dessus. Son rôle consiste à mettre en place et à adapter des outils et une culture ayant pour but de participer à solder ces points." }, { "type": "heading", "level": 2, "id": "la-gestion-de-projet-si-on-demande-tout-le-monde-sait-faire", "text": "La gestion de projet, si on demande, tout le monde sait faire" }, { "type": "paragraph", "html": "Si on considère la gestion de projet, comme un processus de gestion et d'exécution d'un ensemble de tâches défini, alors la majorité des collaborateurs, peu importe leur rôle, font de la gestion de projet. Le<strong> biais cognitif </strong>fréquemment rencontré est le suivant : Si un collaborateur a été capable de mener à bien un ou plusieurs projets dans son service, alors il mènera à bien un projet transverse, car qu'il soit transverse ou métier, ça reste un projet." }, { "type": "paragraph", "html": "Cependant, vos chefs de projet feront face à de nombreuses difficultés supplémentaires, et parfois nouvelles et très peu documentées, qu'il s'agisse de soft skills (ex : comment influencer/manager les parties prenantes sans liens hiérarchiques et sans déclencher de guerres d'ego) ou de hard skills (ex : méthodes de gestion de projets en open innovation et interservices, gestion de portefeuille intégrée et efficace, etc.)." }, { "type": "paragraph", "html": "Un PMO sera plus expérimenté dans la gestion de ce type de projets et opérations. Il aura l'habitude de ces nouveaux types de relations interpersonnelles. Un des avantages du PMO est son ouverture à l'extérieur, par la nature de son rôle mais également par son appétence pour la recherche de REX et de bonnes pratiques, il pourra plus facilement les diffuser dans l'entreprise de par sa position et le nouveau canal de communication ouvert." }, { "type": "heading", "level": 2, "id": "diffuser-la-bonne-culture-projet-pour-donner-de-lair-aux-equipes", "text": "Diffuser la bonne culture projet pour donner de l'air aux équipes" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3f352b794f6a3f58da49_pmo4-min.png", "alt": "rôle du pmo chef d'orchestre", "caption": "rôle du pmo chef d'orchestre ?" }, { "type": "paragraph", "html": "L'enjeu est de prendre un<strong> virage managérial \"radical\".</strong> De passer d'une culture du contrôle de l'exécution des tâches, de la relance des collaborateurs voire de chasse aux reportings <strong>à une posture de \"cultivateur\" d'une culture projet adaptée à l'entreprise</strong>. Une culture ouverte permettant de clarifier et<strong> créer une vision désilotée.</strong>" }, { "type": "paragraph", "html": "Les actions du PMO devraient permettre <strong>un nivellement par le haut au sein des équipes</strong> en termes de compétences et de connaissance métiers." }, { "type": "paragraph", "html": "S'il est assorti d'une réelle exemplarité du Codir, ce contexte nouveau peut contribuer à une vraie efficacité opérationnelle accrue et augmenter la capacité de l'entreprise et de son management à se <strong>transformer</strong> plus rapidement <strong>et surtout, en continu</strong>." }, { "type": "paragraph", "html": "L'enjeu premier sera de se donner de nouvelles règles du jeu. De créer des repères stables et motivants, pour permettre à chacun de mieux <strong>s'adapter aux évolutions technologiques et organisationnelles </strong>qui bousculent ses missions. D'inscrire les projets dans des programmes. Cela peut entre autres permettre d'empêcher le statu quo de s'installer, vrai poison face à l'accélération de l'innovation." }, { "type": "paragraph", "html": "En résumé le rôle du PMO contribue donc <strong>à harmoniser les </strong><a href=\"https://www.airsaas.io/fr/gestion-de-projet/demarche-de-projet\" target=\"_blank\"><strong>démarches projets</strong></a>,<strong> à optimiser les efforts, apporter des outils adaptés</strong> ce qui amène à <strong>une gestion de portefeuille projet plus performante et pragmatique</strong>. Avec des nouveaux outils et process et comportements, la solution résidera en grande partie dans l'implication et l'<strong>engagement de tous</strong>." }, { "type": "paragraph", "html": "Au niveau des équipes, cela passe par la<strong> création d'un langage commun</strong>, d'une coordination de projet interservices, d'une clarification du sens des projets pour les collaborateurs ainsi que de la définition d'un rôle clair pour chacun, leur évitant ainsi de perdre du temps sur \"comment\" mener le projet et de se concentrer plus efficacement sur le fond." }, { "type": "paragraph", "html": "Cette efficacité gagnée, permettra de réduire l'impact de l'engagement en best effort et de réduire la charge mentale liée à ces projets, rendant les collaborateurs plus performants dans la conduite de projet mais surtout plus sereins." }, { "type": "heading", "level": 2, "id": "communication-clarte-projet-et-meilleures-decisions", "text": "Communication, clarté projet et meilleures décisions" }, { "type": "paragraph", "html": "Dans un article précédent on abordait les prises de décisions souvent trop longues ou partielles, identifiées parmi les causes importantes d'échecs des projets de transformation." }, { "type": "paragraph", "html": "Échecs, que l'on pouvait imputer aux manques d'informations, d'accès facile à l'information et de clarté sur les projets qui induisent les ½ ou non-décisions en <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-decider-en-copil\" target=\"_blank\">Copil</a>." }, { "type": "paragraph", "html": "Grâce à ses actions sur la culture projet et sa connexion avec les services et les collaborateurs le PMO pourra apporter une vision transverse désilottée et avec les bons outils. Cela permettra de jouer un rôle déterminant dans le traitement cognitif de l'information pour le top management, <strong>apportant une clarté dans tous les projets jusqu'ici difficiles </strong>et in fine, <strong>permettra de prendre de meilleures décisions </strong>et surtout,<strong> bien plus rapidement</strong>." }, { "type": "heading", "level": 2, "id": "investissez-dans-vos-equipes-a-travers-un-pmo", "text": "Investissez dans vos équipes à travers un PMO" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3f3f7d4e52400e0f6c5f_why-PMO-invest-min.png", "alt": "Investir pour accompagner votre croissance", "caption": "Vers une nouvelle feuille de route" }, { "type": "paragraph", "html": "Quand un projet prend de l'ampleur ou qu'il est soit plus complexe ou plus ambitieux, on pense souvent à l'embauche d'un chef de projet, la plupart des entreprises ne peuvent pas embaucher un chef de projet par projet transverses à mener, et ce même si on donne plusieurs projets à un ETP." }, { "type": "paragraph", "html": "<strong>Tous les collaborateurs ont un aspect de chefferie de projet dans leurs activités</strong>, plus ou moins simples. Les problématiques de conduite de projets sont souvent plus liées à des problèmes d'engagement, de collaboration, d'efficacité et de gestion du best effort que d'un nombre de chefs de projets disponibles. <strong>On peut faire mieux avec moins,</strong> si on adopte une <strong>culture projet adaptée</strong> et qu'on investit dans la montée en compétences des collaborateurs de l'entreprise." }, { "type": "paragraph", "html": "Faites monter en compétences vos effectifs et investissez dans l'humain pour que tout le monde travaille mieux ensemble au sein d'une plateforme et que l'entreprise devienne efficace dans la mise en œuvre de la feuille de route de transformation digitale. Embauchez moins et formez mieux et <strong>l'arrivée d'un PMO sera le moyen le plus pragmatique pour y arriver.</strong>" }, { "type": "heading", "level": 2, "id": "quel-est-le-bon-moment-quelle-est-la-bonne-taille-dentreprise-pour-mettre-en-place-un-pmo", "text": "Quel est le bon moment, quelle est la bonne taille d'entreprise pour mettre en place un PMO ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fb3f4b4311849367af063c_pmo-now-min.png", "alt": "Timing de mise en place du rôle de PMO", "caption": "Votre pmo doit arriver au bon moment et avec les bons \"logiciels\" dans les organisations" }, { "type": "paragraph", "html": "Parmi toutes les questions c'est celle qui <strong>revient le plus souvent</strong> : quand est-ce qu'une entreprise est assez grande ou mature pour mettre en place un PMO ? Pour avoir souvent entendu \"<strong><em>Mais on est trop petit pour prendre un PMO</em></strong>\" ou encore \"<strong><em>On n'est pas assez structuré pour ouvrir un poste de PMO</em></strong>\".<br>Et bien justement, avant de répondre à la question, commentons les deux derniers points récurrents :" }, { "type": "list", "ordered": false, "items": ["<strong>Ce n'est pas la taille de l'entreprise qui importe, mais le nombre de projets et l'investissement</strong> qu'ils représentent. Plus l'entreprise a un effectif réduit et s'apprête à absorber une forte croissance, plus c'est pertinent. Il y aura moins de personnes à embarquer dans la nouvelle culture projet et une fois adoptée, elle se diffusera plus facilement pour chaque nouvel arrivant dans l'entreprise. Disons qu'il y aura moins d'efforts à fournir et moins de résistance aux changements.", "Le fait que l'entreprise ne soit pas encore bien structurée ou qu'elle soit en train de le faire n'est pas un problème mais au contraire une réelle opportunité, <strong>le travail du PMO est justement d'aider à structurer une démarche permettant d'absorber plus de projets transverses</strong> et <strong>d'augmenter</strong> <strong>les chances de leurs réussites</strong>. De plus, cette démarche et culture faisant augmenter l'efficacité des équipes, cela permettra d'absorber encore mieux la montée en charge pour laquelle l'entreprise est en train de se structurer."] }, { "type": "paragraph", "html": "Un bon indicateur pour mettre en place un PMO est quand la somme des projets transverses ou de transformation atteint 400K€ à 500K€. Provisionner 10% à 20% de la valeur de son portefeuille dans la mise en place d'un PMO semble être une bonne pratique pour sécuriser ces investissements actuels mais aussi améliorer l'investissement projets futurs. Il permettra également de <strong>faire des gains sur le temps passé par les collaborateurs sur les projets.</strong>" }, { "type": "paragraph", "html": "Un dernier mot ...au-delà des meilleurs indicateurs rationnels, ROIsables...il y a un troisième critère que vous pouvez prendre en compte pour envisager de créer ce rôle...Quand votre projet CRM/ERP glisse depuis 18 mois et que votre DG<strong> à l'impression que vous ramez</strong>. ! OK on entre en pleine subjectivité ...mais peut être le signe qu'il va falloir gouverner votre transformation autrement." }, { "type": "paragraph", "html": "Pour aller plus loin, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-mettre-en-place-un-pmo\" target=\"_blank\">consultez notre article sur comment mettre en place un PMO</a>." }, { "type": "paragraph", "html": "Pour approfondir, découvrez <a href=\"/fr/gestion-de-projet/role-du-pmo\">comment le PMO doit se positionner face au Codir</a>." }], "toc": [{ "href": "#lenvolee-des-projets-transverses", "label": "L'envolée des projets transverses", "level": 2 }, { "href": "#projets-silos-et-transformation-le-parfait-oxymore", "label": "Projets silos et transformation, le parfait oxymore", "level": 2 }, { "href": "#limpact-rh-des-projets-transverses", "label": "L'impact RH des projets transverses", "level": 2 }, { "href": "#difficultes-pour-les-differents-services-a-collaborer", "label": "Difficultés pour les différents services à collaborer", "level": 2 }, { "href": "#la-gestion-de-projet-si-on-demande-tout-le-monde-sait-faire", "label": "La gestion de projet, si on demande, tout le monde sait faire", "level": 2 }, { "href": "#diffuser-la-bonne-culture-projet-pour-donner-de-lair-aux-equipes", "label": "Diffuser la bonne culture projet pour donner de l'air aux équipes", "level": 2 }, { "href": "#communication-clarte-projet-et-meilleures-decisions", "label": "Communication, clarté projet et meilleures décisions", "level": 2 }, { "href": "#investissez-dans-vos-equipes-a-travers-un-pmo", "label": "Investissez dans vos équipes à travers un PMO", "level": 2 }, { "href": "#quel-est-le-bon-moment-quelle-est-la-bonne-taille-dentreprise-pour-mettre-en-place-un-pmo", "label": "Quel est le bon moment, quelle est la bonne taille d'entreprise pour mettre en place un PMO ?", "level": 2 }], "faq": [], "related": [] }, { "slug": "pourquoi-vos-18-millions", "skip": false, "meta": { "title": "Pourquoi vos millions de transformation s'évaporent : le vrai pouvoir est dans le tempo", "h1": "Pourquoi vos millions de transformation s'évaporent : le vrai pouvoir est dans le tempo", "description": "Pourquoi vos 18 millions d'investissements de transformation ne produisent que 30% des résultats attendus ? Le vrai problème est le rythme organisationnel.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68d2911114f69523913f12f5_Pourquoi%20vos%2018%20millions.jpg", "alt": "Pourquoi vos 18 millions" }, "author": { "category": "Gestion de projets", "publishedDate": "17/9/2025" }, "publishedDate": "17/9/2025" }, "blocks": [{ "type": "heading", "level": 2, "id": "pourquoi-vos-18-millions-dinvestissements-de-transformation-ne-produisent-que-30percent-des-resultats-attendus", "text": "Pourquoi vos 18 millions d'investissements de transformation ne produisent que 30% des résultats attendus" }, { "type": "paragraph", "html": "Septembre 2025. Vous sortez de votre revue budgétaire annuelle avec un constat qui vous glace le sang." }, { "type": "paragraph", "html": "18 millions d'euros investis dans la transformation business, l'optimisation des processus, la modernisation du SI. Trois ans de projets stratégiques. Des équipes mobilisées. Des consultants payés au prix fort." }, { "type": "paragraph", "html": "Le résultat ? 30% des objectifs atteints. 70% de gaspillage organisé." }, { "type": "paragraph", "html": "Vous n'êtes pas seuls. Dans les couloirs des ETI françaises, le même aveu circule en off : \"Nos transformations n'aboutissent jamais vraiment.\"" }, { "type": "paragraph", "html": "Pourtant, ce n'est pas faute de vision. Ni de budget. Ni même de talents." }, { "type": "paragraph", "html": "Le problème est ailleurs. Plus profond. Plus structurel." }, { "type": "paragraph", "html": "Il se niche dans cette incapacité collective à synchroniser l'ambition stratégique avec la réalité opérationnelle. Dans cette désynchronisation chronique entre ce que le COMEX décide en janvier et ce que les équipes peuvent vraiment livrer en décembre." }, { "type": "quote", "text": "On pilote nos projets stratégiques comme si on dirigeait encore une PME de 50 personnes. Avec les mêmes outils, les mêmes réflexes, le même tempo. Sauf qu'on fait 500 millions de CA et qu'on a 3000 salariés.", "author": "DG, groupe serviciel" }, { "type": "paragraph", "html": "Les entreprises de taille intermédiaire naviguent aujourd'hui dans un monde que même les meilleurs dashboards n'avaient pas anticipé. Un monde où les marges se réduisent plus vite que les arbitrages, où les transitions numériques et environnementales convergent sans coordination, où les cycles politiques raccourcissent et les réglementations se multiplient." }, { "type": "paragraph", "html": "Cette tribune n'est pas un plaidoyer pour un outil de plus. C'est un constat partagé par des dirigeants lucides : le problème n'est pas la vision, c'est le rythme." }, { "type": "heading", "level": 2, "id": "lillusion-du-pilotage-strategique", "text": "L'illusion du pilotage stratégique" }, { "type": "paragraph", "html": "Dans de nombreuses ETI, la gouvernance repose sur une conviction rassurante mais dangereuse : suivre six projets stratégiques, c'est piloter l'organisation." }, { "type": "paragraph", "html": "Le DG présente sa matrice. Le DAF détaille ses points mensuels. Le DSI expose son backlog. Le Chief of Staff fait la synthèse. Tout semble maîtrisé." }, { "type": "quote", "text": "Je croyais avoir la main sur nos transformations. En réalité, je ne gérais qu'une vitrine, pas la réalité opérationnelle.", "author": "DG, groupe technologique, 1 400 salariés" }, { "type": "paragraph", "html": "Car derrière ces quelques projets \"visibles\", se cache une tout autre réalité :" }, { "type": "list", "ordered": false, "items": ["40 à 80 initiatives réellement actives dans l'organisation", "Des interdépendances entre directions totalement invisibles au COMEX", "Des arbitrages systématiquement reportés ou contournés", "Une incapacité collective à évaluer le coût réel du portefeuille"] }, { "type": "quote", "text": "Quand j'ai voulu connaître le nombre exact de projets en cours, il a fallu 3 semaines pour établir une liste fiable. Trois semaines dans une organisation de 2 100 personnes.", "author": "Chief Transformation Officer" }, { "type": "insight-callout", "label": "À retenir", "html": "<p><strong>🧠 Insight #1</strong> 👉 Se concentrer sur les seuls projets \"phares\" sans vision globale, c'est piloter en regardant uniquement le rétroviseur.</p><p><strong>🧠 Insight #2</strong> 👉 Le vrai risque stratégique ne vient jamais de ce qu'on surveille, mais de ce qu'on a cessé de regarder.</p>" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68caf865243ab3a0272c602a_Pourquoi%20vos%2018%20millions-image%201-min.jpg", "alt": "L'illusion du pilotage stratégique" }, { "type": "heading", "level": 2, "id": "crm-finance-data-pourquoi-la-gouvernance-projet-est-restee-a-lage-des-powerpoint", "text": "CRM, finance, data… pourquoi la gouvernance projet est restée à l'âge des PowerPoint" }, { "type": "paragraph", "html": "Prenez du recul sur vos outils de pilotage." }, { "type": "paragraph", "html": "Pour vos ventes, vous disposez d'un CRM moderne : pipelines en temps réel, taux de conversion, forecasts actualisés quotidiennement." }, { "type": "paragraph", "html": "Pour vos finances, vous pilotez avec des BI consolidées, des reportings automatisés, des KPI fiables qui donnent le pouls de l'entreprise." }, { "type": "paragraph", "html": "Et pour vos projets de transformation – ceux qui déterminent votre compétitivité future ? Vous avez des PowerPoint et des tableaux Excel partagés." }, { "type": "quote", "text": "Nous gérons nos projets stratégiques avec les mêmes méthodes qu'en 2004. PowerPoint pour présenter, Excel pour calculer, réunions pour arbitrer. C'est aberrant.", "author": "COO, ETI de services, 1 900 salariés" }, { "type": "paragraph", "html": "Pendant que toutes les fonctions support ont opéré leur révolution digitale, la gouvernance projet est restée artisanale :" }, { "type": "list", "ordered": false, "items": ["Aucune vision centralisée du portefeuille réel", "Pas de suivi partagé des capacités ou de la charge", "Des estimations de livrables approximatives, souvent déconnectées des réalités terrain"] }, { "type": "paragraph", "html": "Le contraste est saisissant : ces mêmes entreprises qui traquent chaque euro de CA et analysent chaque conversion client naviguent à vue sur leurs investissements les plus structurants." }, { "type": "paragraph", "html": "<strong>🧠 Insight #3</strong> 👉 La maturité projet des ETI accuse 15 ans de retard sur leur maturité commerciale. Paradoxal quand l'avenir se joue sur leur capacité à se transformer." }, { "type": "paragraph", "html": "<strong>🧠 Insight #4</strong> 👉 Piloter sans visibilité sur les dérives de planning et de ressources, c'est programmer ses échecs en silence." }, { "type": "heading", "level": 2, "id": "le-mal-invisible-des-comex-quand-chacun-vit-dans-sa-propre-temporalite", "text": "Le mal invisible des COMEX : quand chacun vit dans sa propre temporalité" }, { "type": "paragraph", "html": "Un autre fléau ronge les directions d'ETI : l'asynchronisme décisionnel." }, { "type": "paragraph", "html": "Autour de la même table, quatre univers temporels coexistent sans jamais se rencontrer :" }, { "type": "list", "ordered": false, "items": ["Le DG projette sa vision à horizon 2028 : marchés, capitaux, disruptions", "Le DAF raisonne au trimestre : marges, budgets, arbitrages financiers", "L'IT oscille entre l'urgence hebdomadaire : incidents, bugs, maintenance", "Le terrain vit l'immédiateté quotidienne : clients, commandes, réclamations"] }, { "type": "quote", "text": "Nous partageons la même stratégie, mais nous ne vivons pas au même rythme. Résultat : nous n'avançons jamais vraiment ensemble.", "author": "CIO, industrie, 2 200 salariés" }, { "type": "paragraph", "html": "Face aux blocages, les réflexes sont prévisibles :" }, { "type": "list", "ordered": false, "items": ["Formation d'une task force \"projet critique\"", "Mise en place d'un \"pilotage renforcé\"", "Attente passive que la prochaine crise force les décisions"] }, { "type": "paragraph", "html": "Cette cacophonie temporelle explique pourquoi tant de transformations s'enlisent. Pas par manque de vision ou de moyens, mais par incapacité à créer un tempo commun d'exécution." }, { "type": "paragraph", "html": "Les équipes courent dans des directions alignées, mais à des vitesses incompatibles." }, { "type": "paragraph", "html": "<strong>🧠 Insight #5</strong> 👉 Dans les COMEX d'ETI, le vrai problème n'est pas le désaccord stratégique, mais le décalage temporel structurel." }, { "type": "paragraph", "html": "<strong>🧠 Insight #6</strong> 👉 Sans rythme d'exécution partagé, la meilleure stratégie se transforme en catalogue de bonnes intentions." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68caf8c6e6ba82688dd64848_Pourquoi%20vos%2018%20millions-image%202-min.jpg", "alt": "Le mal invisible des COMEX" }, { "type": "heading", "level": 2, "id": "le-quarter-plan-la-solution-qui-reconcilie-vision-et-execution", "text": "Le quarter plan : la solution qui réconcilie vision et exécution" }, { "type": "paragraph", "html": "Face à cette désynchronisation chronique, une pratique gagne du terrain dans les COMEX les plus matures : le quarter plan." }, { "type": "paragraph", "html": "Attention : il ne s'agit pas d'un énième comité de pilotage trimestriel. La différence est fondamentale." }, { "type": "paragraph", "html": "Un COPIL classique regarde dans le rétroviseur : \"Où en sommes-nous ? Pourquoi ce retard ?\"" }, { "type": "paragraph", "html": "Le quarter plan regarde l'horizon : \"Que pouvons-nous réellement accomplir dans les 90 prochains jours avec nos ressources actuelles ?\"" }, { "type": "paragraph", "html": "C'est une discipline de gouvernance qui impose un nouveau rythme organisationnel, centré sur deux piliers :" }, { "type": "list", "ordered": false, "items": ["Vision capacitaire : évaluation honnête de ce que chaque direction peut absorber comme charge de travail", "Arbitrage prospectif : choix assumés sur ce qui entre dans le trimestre et ce qui en sort"] }, { "type": "paragraph", "html": "Le principe : tous les 90 jours, trois exercices non négociables : ✅ Revue exhaustive du portefeuille réel de projets ✅ Évaluation des capacités disponibles par direction ✅ Arbitrages assumés : ce qui avance, ce qui ralentit, ce qui s'arrête" }, { "type": "quote", "text": "Notre premier quarter plan a été un électrochoc. 30% de nos projets ont été abandonnés séance tenante. Des projets que personne n'osait remettre en question depuis des mois.", "author": "DAF, BTP, 2 400 salariés" }, { "type": "quote", "text": "Nous ne nous alignons plus seulement sur ce qu'il faut faire, mais sur ce que nous pouvons réellement accomplir dans les 90 jours qui viennent.", "author": "Chief of Staff, retail, 1 800 salariés" }, { "type": "paragraph", "html": "<strong>🧠 Insight #7</strong> 👉 Dans le contexte économique actuel, réduire le gaspillage des ressources internes est devenu un impératif de survie." }, { "type": "paragraph", "html": "<strong>🧠 Insight #8</strong> 👉 Le quarter plan ne contraint pas la stratégie : il la rend enfin exécutable." }, { "type": "heading", "level": 2, "id": "ce-que-changent-les-comex-qui-passent-a-90-jours", "text": "Ce que changent les COMEX qui passent à 90 jours" }, { "type": "paragraph", "html": "Les directions générales qui ont basculé en quarter plan observent trois mutations profondes dans leur mode de fonctionnement :" }, { "type": "paragraph", "html": "<strong>Révolution dans la priorisation</strong> : fini les débats interminables sur les projets \"moyennement prioritaires\". La contrainte temporelle force les décisions. Un projet est soit dans le trimestre, soit il ne l'est pas." }, { "type": "paragraph", "html": "<strong>Transformation des arbitrages</strong> : le périmètre des projets s'adapte désormais aux ressources disponibles, et non l'inverse. Le scope creep – cette dérive naturelle qui fait grossir les projets – devient enfin maîtrisable." }, { "type": "paragraph", "html": "<strong>Synchronisation organisationnelle</strong> : toutes les directions fonctionnent sur la même cadence. Un calendrier unique remplace la cacophonie des plannings individuels." }, { "type": "quote", "text": "Nous n'avons pas supprimé nos comités de pilotage. Nous les avons rendus enfin utiles : ils servent à décider, plus seulement à constater.", "author": "COO, ETI logistique, 1 600 salariés" }, { "type": "quote", "text": "Depuis l'adoption de ce rythme trimestriel, nos projets souffrent moins de dérives de périmètre et génèrent plus d'impact business. Nos directions métiers le reconnaissent.", "author": "CIO, santé, 2 900 salariés" }, { "type": "paragraph", "html": "Le quarter plan révèle une vérité managériale : la contrainte temporelle libère la décision." }, { "type": "paragraph", "html": "<strong>🧠 Insight #9</strong> 👉 Le quarter plan n'améliore pas mécaniquement vos projets. Il transforme votre COMEX en véritable instance de pilotage." }, { "type": "paragraph", "html": "<strong>🧠 Insight #10</strong> 👉 Savoir dire \"non\" au bon moment vaut toutes les roadmaps du monde." }, { "type": "heading", "level": 2, "id": "le-vrai-pouvoir-des-comex-en-2026-le-tempo", "text": "Le vrai pouvoir des COMEX en 2026 ? Le tempo." }, { "type": "paragraph", "html": "L'époque de la gouvernance d'apparat est révolue." }, { "type": "paragraph", "html": "Les plans stratégiques triennaux, les roadmaps ambitieuses et les six projets phares du DG ne suffisent plus à naviguer dans la complexité actuelle." }, { "type": "paragraph", "html": "Ce qui séparera demain les ETI performantes de celles qui stagnent ne sera ni leur capacité d'investissement, ni leur sophistication technologique, mais leur maîtrise du rythme organisationnel." }, { "type": "paragraph", "html": "La différence se joue dans cette capacité collective à synchroniser vision stratégique et exécution opérationnelle, à ajuster en continu sans perdre le cap." }, { "type": "quote", "text": "Un COMEX qui ne maîtrise pas son tempo, c'est comme un orchestre symphonique où chaque musicien jouerait dans sa propre partition. Individuellement, chacun excelle. Collectivement, c'est la cacophonie.", "author": "CIO, groupe industriel, 1 700 salariés" }, { "type": "paragraph", "html": "Les ETI qui s'imposeront dans les années à venir seront celles qui auront compris cette évidence : dans un environnement volatil, la vraie compétence stratégique n'est pas de prévoir l'imprévisible, mais de s'adapter rapidement quand l'imprévu survient." }, { "type": "paragraph", "html": "<strong>🧠 Insight final</strong> 👉 Dans un monde en perpétuelle mutation, le véritable luxe managérial n'est plus d'avoir une stratégie parfaite. 👉 C'est d'avoir une stratégie que l'on peut réajuster intelligemment tous les 90 jours." }], "toc": [{ "label": "Pourquoi vos 18 millions d'investissements de transformation ne produisent que 30% des résultats attendus", "href": "#pourquoi-vos-18-millions-dinvestissements-de-transformation-ne-produisent-que-30percent-des-resultats-attendus", "level": 2 }, { "label": "L'illusion du pilotage stratégique", "href": "#lillusion-du-pilotage-strategique", "level": 2 }, { "label": "CRM, finance, data… pourquoi la gouvernance projet est restée à l'âge des PowerPoint", "href": "#crm-finance-data-pourquoi-la-gouvernance-projet-est-restee-a-lage-des-powerpoint", "level": 2 }, { "label": "Le mal invisible des COMEX : quand chacun vit dans sa propre temporalité", "href": "#le-mal-invisible-des-comex-quand-chacun-vit-dans-sa-propre-temporalite", "level": 2 }, { "label": "Le quarter plan : la solution qui réconcilie vision et exécution", "href": "#le-quarter-plan-la-solution-qui-reconcilie-vision-et-execution", "level": 2 }, { "label": "Ce que changent les COMEX qui passent à 90 jours", "href": "#ce-que-changent-les-comex-qui-passent-a-90-jours", "level": 2 }, { "label": "Le vrai pouvoir des COMEX en 2026 ? Le tempo.", "href": "#le-vrai-pouvoir-des-comex-en-2026-le-tempo", "level": 2 }], "faq": [], "related": [] }, { "slug": "preparer-comite-de-pilotage-d-un-projet", "skip": false, "meta": { "title": "Comment bien préparer le comité de pilotage d'un projet ?", "h1": "Comment bien préparer le comité de pilotage d'un projet ?", "description": "Vous préparez votre prochain comité de pilotage d'un projet ? Découvrez les clés pour muscler votre préparation et être prêt à toutes les éventualités lors de votre Copil.", "publishedDate": "4/7/2022", "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "4/7/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2a70c692292515dbb828a_prepa-copil-min.jpg", "alt": "Prépa copil" } }, "blocks": [{ "type": "paragraph", "text": "Vous préparez votre prochain comité de pilotage d'un projet, et vous ne savez pas réellement à quoi vous attendre ? Alors c'est que vous devez passer plus de temps sur sa préparation !" }, { "type": "paragraph", "text": "L'objectif de cet article : vous aider à muscler cette préparation et être prêt à toutes les éventualités lors de votre Copil à venir !" }, { "type": "paragraph", "text": "Cet article fait partie de la série <a href=\"/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\" target=\"_blank\">Comité de pilotage ou Copil : Les bases</a> qui recense l'essentiel des éléments simples et pragmatiques&nbsp;à connaitre sur le comité de pilotage projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e620_62c2a421759161de6022b1a7_f0ef116c-0e8a-450b-86c9-806f909eaa63-min.jpeg", "alt": "Prépa copil" }, { "type": "heading", "level": 2, "id": "identifier-et-determiner-les-objectifs-du-comite-de-pilotage-dun-projet", "text": "Identifier et déterminer les objectifs du comité de pilotage d'un projet" }, { "type": "paragraph", "text": "Un Copil ne doit pas être votre énième réunion de la semaine ou du mois. Un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comite-de-pilotage-definitions-et-incomprehensions\" target=\"_blank\">comité de pilotage</a> n'est pas non plus un groupe de travail vu comme un atelier collaboratif pour co-construire le projet, il ne doit pas permettre de répondre à des questions opérationnelles ou métiers que vous auriez pu glaner par ailleurs pendant les phases précédentes de la conduite du projet." }, { "type": "paragraph", "text": "Tout ceci doit avoir été réalisé en amont, dans des sessions de travail en plus petit groupe (Task Force). Et le chef de projet, ainsi que le sponsor, doivent avoir une idée très claire de ce qu'ils attendent de chaque session de comité de pilotage d'un projet." }, { "type": "heading", "level": 3, "id": "no-pain-no-gain", "text": "\"No Pain, No Gain\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e629_62c2a46880979dc90d055c19_6919e1a5-cdf7-43e2-87d5-3cb7c4697ad0-min.png", "alt": "no pain no gain" }, { "type": "paragraph", "text": "Les objectifs d'un comité ne peuvent pas se réduire à un but informatif ou à garder tout le monde informé et valorisé." }, { "type": "paragraph", "text": "Si il n'y a pas de problème à résoudre ou à anticiper, alors l'objet même de tenir un comité de pilotage d'un projet est strictement inutile. Les comités de pilotage se tiennent en général tous les 45 à 60 jours environ, pendant la durée du projet, aussi l'idée est de se concentrer sur ce qui peut être problématique immédiatement ou d'ici le/les prochains Copil." }, { "type": "paragraph", "text": "Le comité de pilotage doit servir au chef de projet pour <strong>mobiliser et activer des ressources ou des actions nécessaires au projet</strong> et qui nécessitent le soutien du sponsor et des Top Managers de l'entreprise. Il doit pouvoir s'appuyer sur le sponsor pour obtenir ce dont il a besoin pour mener à bien le projet." }, { "type": "heading", "level": 3, "id": "il-ny-a-pas-de-vent-favorable-pour-celui-qui-ne-sait-pas-ou-il-va", "text": "\"Il n'y a pas de vent favorable pour celui qui ne sait pas où il va\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e62c_62c2a4806078ed14044b2f36_f42688e1-5dd0-4418-a538-8d18c14ff316-min.jpeg", "alt": "Citation projet - vent favorable" }, { "type": "paragraph", "text": "Votre capacité à bien définir les objectifs dépendra du travail de préparation fait par le chef de projet en amont, mais aussi de sa capacité à écouter, à évaluer et anticiper les risques et les facteurs bloquants qu'il aura identifiés tout au long de la mise en place du projet." }, { "type": "paragraph", "text": "Ces rendez-vous auront beaucoup plus d'impact s'ils servent au manager de projet à débloquer des aspects en aval du projet, à en dérisquer d'autres, ou à amener à prendre des décisions clés que le chef de projet n'est pas en position de réaliser par ailleurs." }, { "type": "paragraph", "text": "De ce fait, il est important de rassembler en amont tous les éléments nécessaire à la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-decider-en-copil\" target=\"_blank\">prise de décision en Copil</a>, et d'avoir proposé une stratégie à suivre au sponsor, ainsi que des recommandations quant au différentes options possibles et leurs impacts avant le jour du Copil. Le chef de projet doit connaître le positionnement de chacun des acteurs du projet plus ou moins précisément, afin qu'il n'y ait pas de surprise pendant le comité de pilotage." }, { "type": "heading", "level": 3, "id": "le-sponsor-ne-doit-rien-decouvrir-pendant-le-comite-de-pilotage", "text": "Le sponsor ne doit rien découvrir pendant le comité de pilotage" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e623_62ea82304a84154f23c1ddc4_82b121c6-ebaa-48b0-9b18-604028180897-min.jpeg", "alt": "sponsor copil projet" }, { "type": "paragraph", "text": "Que ce soit le chef de projet ou le sponsor, aucun d'eux ne doit découvrir d'éléments dimensionnant, d'informations ou de positionnements de membres pouvant remettre en cause la capacité d'arbitrage et de décision pendant le Copil, au risque de le rendre inefficace et de devoir le reporter. Voire, dans certains cas, remettre le projet lui-même en question" }, { "type": "paragraph", "text": "Le rôle du chef de projet est donc d'investiguer pour rassembler ce type d'informations, afin d'en faire des synthèses au sponsor, au fil de l'eau et tout au long du projet. Il est nécessaire de lui faire part des potentiels facteurs bloquants, risques et problèmes, de manière à ce qu'il puisse jouer pleinement son rôle de sponsor." }, { "type": "paragraph", "text": "Contrairement à ce que l'on peut entendre d'habitude, ne faites pas remonter ces points clés au sponsor seulement deux ou trois jours avant le comité de pilotage d'un projet. L'idée est de pouvoir lui laisser le temps d'évaluer les situations et de prendre les bonnes décisions. Pour cela, vous pouvez lui soumettre une stratégie à adopter, mais garder en tête qu'il doit avoir du temps devant lui." }, { "type": "heading", "level": 3, "id": "placer-le-projet-au-dessus-des-interets-personnels", "text": "Placer le projet au dessus des intérêts personnels" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e642_62ea8289df96d8705cc802f8_dca91451-d3a7-42c3-b59a-c36e0802c3c7-min-min.jpeg", "alt": "Montagne projet" }, { "type": "paragraph", "text": "Le projet et le Copil ne doivent pas être une tribune permettant à des personnalités de faire passer leurs priorités ou intérêts personnels. Le rassemblement d'autant de personnes clés de l'entreprise autour de la table pourrait être tentant pour certains de dériver du plan de la réunion." }, { "type": "paragraph", "text": "Avoir un ordre du jour carré et une bonne gestion des personnalités fait bien évidemment partie de la solution. Mais il est bon d'ajouter à ça un bon plan de communication pour valoriser l'implication de chacun. C'est aussi là où le chef de projet doit mettre son égo de côté. Si le projet réussit, ce n'est pas grâce à lui, mais grâce à la participation de tous. Et s'il donne assez de raisons aux personnalités ambitieuses de briller à travers le projet dans l'intérêt global de l'entreprise, alors il aura rempli une partie, parfois difficile, de sa mission." }, { "type": "heading", "level": 3, "id": "rester-proche-du-terrain-et-des-membres-du-comite-de-pilotage", "text": "Rester proche du terrain et des membres du comité de pilotage" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e62f_62ea82d11d124a688760b2b0_69bcfe0a-a84a-454c-816a-394e9d19d80e-min.jpeg", "alt": "proximité terrain copil" }, { "type": "paragraph", "text": "Récolter des informations sur la réalité terrain et les bloquants associés et augmenter le leadership du <a href=\"https://www.airsaas.io/fr/gestion-de-projet/chef-de-projet-transverse\" target=\"_blank\">chef de projet transverse</a> : voilà l'un de vos rôles. On peut également citer le fait de faire preuve d'écoute et de considération de tous les avis des parties prenantes. Et de récolter les positionnements de certains par rapport au projet, et sonder ceux qui faciliteront les opérations, ainsi que ceux qui le feront ralentir." }, { "type": "paragraph", "text": "L'important ici est de pouvoir anticiper les risques ou points facilitateurs pour le projet, et bien écouter les retours métiers. Cela permettra également de relever et identifier toute tension, frustration ou non-dit qui doivent être traités avant et à la marge du comité de pilotage du projet. La première approche consiste à essayer de comprendre, de trouver des solutions ou de le désamorcer pour le chef de projet - et, dans un second temps, si cela ne fonctionne pas ou représente un trop gros risque, de s'appuyer sur le sponsor sur la bonne stratégie à adopter." }, { "type": "heading", "level": 3, "id": "rappel-des-objectifs-cles-dun-comite-de-pilotage-projet", "text": "Rappel des objectifs clés d'un comité de pilotage projet" }, { "type": "list", "ordered": false, "items": ["<strong>Prendre des décisions et faire des arbitrages.</strong>", "<strong>Veiller au bon déroulement du projet</strong> et s'assurer qu'il est <strong>en accord avec les stratégies globales de l'entreprise.</strong>", "<strong>Évaluer la qualité et la santé du projet à chaque réunion</strong>. Si certains problèmes&nbsp; doivent être améliorés, les principaux intervenants peuvent les soulever pour les résoudre.", "<strong>Donner au chef de projet le pouvoir d'agir</strong> et d'utiliser les ressources de l'entreprise pour mener l'exécution, l'avancement du projet.", "<strong>Résoudre les conflits entre départements</strong>, les problèmes liés au coût, au temps, au risque, aux ressources, à la qualité et à la portée.", "<strong>Surveiller les progrès du projet par rapport aux objectifs convenus</strong> et <strong>résoudre les problèmes</strong> qui ne permettent pas au projet de progresser à temps."] }, { "type": "paragraph", "text": "Toute la préparation doit s'articuler autour de ces points, et permettre de répondre à ces objectifs" }, { "type": "heading", "level": 2, "id": "les-cles-pour-bien-preparer-votre-prochain-comite-de-pilotage-dun-projet", "text": "Les clés pour bien préparer votre prochain comité de pilotage d'un projet" }, { "type": "paragraph", "text": "Piloter un Copil n'est pas chose aisée - donc autant faire preuve d'une planification au cordeau pour y arriver serein !" }, { "type": "heading", "level": 3, "id": "avoir-rassemble-toutes-les-informations-necessaires-a-la-prises-de-decision-et-aux-arbitrages", "text": "Avoir rassemblé toutes les informations nécessaires à la prises de décision et aux arbitrages" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e658_62ea831544e58a4cd2ffb7cf_02ef1429-4e1e-43fa-b594-d980d06f44f1-min.jpeg", "alt": "bibliothèque" }, { "type": "paragraph", "text": "Le comité de pilotage d'un projet est le moment d'aborder tous les aspects du projet qui nécessitent une prise de position tranchée ou des choix/décisions stratégiques. Pour cela tout le monde doit pouvoir s'exprimer, donner son avis ou encore lever des points d'attention, et repartir à la fin de ce comité avec toutes ces décisions actées pour faire avancer correctement le projet." }, { "type": "paragraph", "text": "Il faut avoir identifié, recensé et préparé avec le sponsor, à l'avance et au fil de l'eau, tous les éléments du projet qui nécessitent de telles décisions ou actions correctives dans le prochain Copil." }, { "type": "paragraph", "text": "Les membres du comité de pilotage d'un projet doivent savoir à l'avance quelles sont les décisions clés du prochain Copil, afin que tout le monde puisse avoir le temps de réfléchir et évaluer l'impact des décisions. Tous les documents, ordre du jour et annexes, doivent être transmis, au moins une semaine, et idéalement 15 jours, avant le jour du comité de pilotage." }, { "type": "paragraph", "text": "Il est donc primordial pour tout cela, que les objectifs et livrables attendus soient clairs et d'avoir établi les règles du jeu quant à la façon de prendre des décisions et instaurer les principes de gouvernance<strong>. </strong>Cette grille de lecture commune permettra d'instaurer un cadre connu et compris de tous - ce qui accélère les prises de décisions." }, { "type": "heading", "level": 3, "id": "instaurer-le-feedback-pour-anticiper-les-facteurs-bloquants", "text": "Instaurer le feedback pour anticiper les facteurs bloquants" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e632_62ea8362dbd70f379da8ad1d_84d32479-7203-4080-a63a-939a6f530321-min.jpeg", "alt": "Copil Feedback" }, { "type": "paragraph", "text": "Si vous passez suffisamment de temps et d'écoute avec les membres du Copil projet, vous récolterez la vision des membres, et vous aurez la possibilité de bien comprendre où le projet se situe pour eux. Cela vous permet, par la même occasion, d'identifier les problématiques techniques, politiques et financières qui ne seraient pas exprimées en comité de pilotage du projet." }, { "type": "paragraph", "text": "Particulièrement quand il y'a des prise de positions tranchées non-partagées ou des désaccords importants entre parties prenantes qui parfois n'ont pas le même pouvoir/influence dans l'entreprise, on peut passer à côté d'élément clés si cela génère des non-dits et des frustrations." }, { "type": "paragraph", "text": "Mettez en place les bons outils<strong> </strong>pour récolter les informations. Dans beaucoup de cas, certaines des informations ne sont pas communiquées car il n'y a pas d'instance ou de rendez-vous adaptés :" }, { "type": "heading", "level": 4, "id": "des-formulaires-de-feedback-rapides-a-remplir-et-anonyme", "text": "Des formulaires de feedback rapides à remplir et anonyme" }, { "type": "paragraph", "text": "Peu importe le support du moment. Il doit être anonyme et rapide à remplir - car l'important, c'est que tout le monde le remplisse. Utilisez-le avec parcimonie afin de conserver la participation. Un outil type Typeform fera très bien l'affaire, et donnera au chef de projet et au sponsor une très bonne idée de la position des membres sur la conduite de projet. De temps temps en temps, il permettra également de faire ressortir des informations qui restent autrement des non-dits." }, { "type": "heading", "level": 4, "id": "des-rendez-vous-a-la-marge-des-copil-ou-des-sessions-de-travail-projet", "text": "Des rendez-vous à la marge des Copil ou des sessions de travail projet" }, { "type": "paragraph", "text": "Afin de fluidifier les étapes du projets, le project manager, selon les besoins à venir, fera en sorte d'intégrer à la réflexion, l'action ou par anticipation, les métiers pertinents pour l'exécution du projet en cours ou à avenir et les managers des services concernés quand il y'a un besoin en ressources. Le sponsor pourra prendre le relais avec les Tops Managers pour les besoins en ressources. L'idée est ici que tout le monde connaisse avant le comité de pilotage d'un projet les besoins, afin de faciliter l'arbitrage le jour du Copil." }, { "type": "heading", "level": 3, "id": "planifier-le-copil-longtemps-a-lavance", "text": "Planifier le Copil longtemps à l'avance" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e63c_62ea83e4130ed4f8f849be36_5bf2173d-fbfe-470a-af2c-0bd0d5ebd42a-min.jpeg", "alt": "Agenda copil" }, { "type": "heading", "level": 4, "id": "sassurer-de-la-presence-de-toutes-les-parties-prenantes", "text": "S'assurer de la présence de toutes les parties prenantes" }, { "type": "paragraph", "text": "Plus les membres du comité de pilotage ont un rôle important ou de l'influence dans l'entreprise, plus il y aura de difficultés à trouver un créneau libre pour tout le monde. Et qui dit non-présence de toutes les parties prenantes, dit risques supplémentaires de non-décisions ou décisions partielles pour le management de projet." }, { "type": "paragraph", "text": "Pour cela, prévoyez votre comité de pilotage du projet 45 ou 60 jours à l'avance. Cela devrait suffire - mais pensez à vous adapter à votre organisation et prendre plus de marge si nécessaire." }, { "type": "heading", "level": 4, "id": "sassurer-que-toutes-les-parties-prenantes-aient-assez-de-temps-de-preparation", "text": "S'assurer que toutes les parties prenantes aient assez de temps de préparation" }, { "type": "paragraph", "text": "Si le projet abesoin de ressources, de réponses métiers ou tiers ainsi que de réflexion quant à des prises de décisions à venir, le chef de projet doit laisser assez de temps à chacun pour pouvoir faire ce qui est attendu de lui avant le comité de pilotage d'un projet. Et comme vu précédemment : leur communiquer l'ordre du jour au moins 15 jours à l'avance." }, { "type": "heading", "level": 3, "id": "une-presentation-synthetique-et-un-ordre-du-jour-qui-va-droit-au-but", "text": "Une présentation synthétique et un ordre du jour qui va droit au but" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e639_62ea844656d69a85eb435d37_e30e3bfb-a44d-45cd-89bb-335cfd1c5d57-min-min.jpeg", "alt": "sprint" }, { "type": "list", "ordered": false, "items": ["Liste des participants", "Décisions du derniers comité de pilotage", "Performance : roadmap prévue -vs- avancement réel / budget prévu -vs- dépenses à date", "Les prochains gros jalons et enjeux", "Tableau de bord (vue d'ensemble), suivi de l'avancement du projet et des KPIs", "Décisions à prendre", "Questions", "Prochaines étapes", "Dates et jalons du prochain comité de pilotage du projet"] }, { "type": "paragraph", "text": "Faites attention à ne pas utiliser de support de présentation qui rentre trop dans le détail comme les outils de gestion de projet. Le risque ? Perdre bon nombre de collaborateurs pendant la réunion. Si vous souhaitez gagner du temps sans passer des heures à refaire un PowerPoint pour chaque comité de pilotage et donner de la visibilité sur les éléments essentiels pour un Copil l L'outil AirSaas a spécialement été conçu pour résoudre ces problèmes-là." }, { "type": "paragraph", "text": "Pour aller plus loin sur le sujet, <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-modele-de-presentation-pour-votre-comite-de-pilotage\" target=\"_blank\">découvrez notre modèle de présentation pour votre comité de pilotage</a>." }, { "type": "heading", "level": 3, "id": "presenter-des-nouvelles-positives-cest-aussi-anticiper-des-facteurs-bloquants", "text": "Présenter des nouvelles positives, c'est aussi anticiper des facteurs bloquants" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d864c195c1ae278463e63f_62ea84914a8415747dc1f6ce_4f2bd82a-9c98-48ef-b2a6-88f490053563-min.jpeg", "alt": "Positif copil" }, { "type": "paragraph", "text": "Que ce soit pour valoriser le travail accompli ou partager de bons résultats, évitez l'inertie dans un projet, le désengagement et le sentiment que le projet n'avance pas, ou pas comme prévu." }, { "type": "paragraph", "text": "C'est aussi le moment de canaliser les personnalités plus ambitieuses en mettant en avant le travail réalisé qui va dans le sens et l'intérêt du projet avec de récompenser les bons comportements et de faciliter le management transverse de ces ressources." }, { "type": "paragraph", "text": "Le chef de projet et le sponsor ne doivent pas négliger la perception que le projet donne aux parties prenantes. Le projet doit être un moteur de changements positifs et un bon plan de communication consiste à s'assurer de conserver une bonne dynamique pour la suite du projet. Une véritable conduite du changement doit donc opérer !" }, { "type": "heading", "level": 3, "id": "connaitre-et-anticiper-les-objections-avant-le-comite-de-pilotage", "text": "Connaître et anticiper les objections avant le comité de pilotage" }, { "type": "paragraph", "text": "Vous l'aurez compris dans cet article : l'accent est mis sur l'humain et les relations humaines. Elles sont tellement souvent à l'origine de défaillances projets qu'elles représentent des points d'attention majeurs dans la gestion de projet. Avec tout le travail de préparation énoncé en amont, le chef de projet doit maintenant connaître toutes les objections des membres et préparer avec le sponsor le bon plan d'action." }, { "type": "paragraph", "text": "Pour toutes les objections pendant le comité de pilotage qui n'auraient pas été anticipées ou qu'il a été décidé d'écarter vous pouvez toujours \"être vague, précisément...\", utilisez l'astuce du frigo/parking développé dans notre autre article : <a href=\"/gestion-de-projet/copil-projet-5-astuces-pour-que-tout-se-passe-bien\" target=\"_blank\">Copil projet : 5 astuces pour que tout se passe bien</a>." }], "toc": [{ "label": "Identifier et déterminer les objectifs du comité de pilotage d'un projet", "href": "#identifier-et-determiner-les-objectifs-du-comite-de-pilotage-dun-projet", "level": 2 }, { "label": "Les clés pour bien préparer votre prochain comité de pilotage d'un projet", "href": "#les-cles-pour-bien-preparer-votre-prochain-comite-de-pilotage-dun-projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "program-increment-planning", "skip": false, "meta": { "title": "PI Planning : le guide complet pour aligner vos équipes IT et métiers", "h1": "PI Planning : le guide complet pour aligner vos équipes IT et métiers", "description": "Découvrez comment réussir votre PI Planning : définition, bénéfices, préparation, déroulement et outils pour aligner vos équipes IT et métiers.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/68cae3b8ff9507e294d9f896_PI%20Planning.jpg", "alt": "PI Planning" }, "author": { "name": "", "category": "Gestion de projets", "publishedDate": "19/2/2026" }, "publishedDate": "19/2/2026" }, "blocks": [{ "type": "paragraph", "text": "Aligner les équipes IT et métiers, c'est souvent un casse-tête. Entre les priorités business qui évoluent sans cesse, les équipes tech qui jonglent avec les contraintes techniques, et des silos qui compliquent la communication, on se retrouve vite avec des projets qui avancent… mais pas forcément dans la bonne direction." }, { "type": "paragraph", "text": "Résultat ? Des frustrations des deux côtés, des retards, et une perte de valeur pour l'entreprise." }, { "type": "paragraph", "text": "C'est là que le <strong>PI Planning</strong> entre en jeu. Pilier du framework SAFe (Scaled Agile Framework), cet événement trimestriel rassemble toutes les équipes impliquées dans un Agile Release Train (ART) pour synchroniser leurs efforts autour d'un plan clair et réaliste. Pendant deux jours, IT et métiers travaillent ensemble pour définir les priorités, lever les dépendances et s'assurer que chacun avance dans le même sens." }, { "type": "paragraph", "text": "En bref : c'est le moment où tout le monde se met d'accord sur ce qu'on fait, pourquoi on le fait et comment on va y arriver." }, { "type": "paragraph", "text": "Mais attention : une session mal préparée peut vite devenir une réunion interminable qui manque d'impact. Pour qu'il soit efficace, il faut <strong>une bonne préparation, une forte implication des parties prenantes et une vraie dynamique de collaboration</strong>. Sinon, on risque de repartir avec un plan flou et une fausse impression d'alignement." }, { "type": "paragraph", "text": "Alors, comment transformer cet exercice en un levier de performance et d'engagement pour vos équipes ? Quels sont les pièges à éviter ? Et surtout, comment faire en sorte que cet événement soit un moteur de création de valeur et pas juste une contrainte de plus ?" }, { "type": "paragraph", "text": "Dans cet article, on va décortiquer <strong>les clés d'un PI Planning réussi, avec des retours d'expérience concrets et des conseils actionnables</strong>. Parce que bien fait, cet événement peut changer la dynamique de vos projets et enfin aligner IT et Métiers sur un objectif commun." }, { "type": "insight-callout", "label": "À retenir", "html": "<ul><li>Pour enrichir nos connaissances et aller au-delà de la littérature, nous avons demandé à des experts de nous partager leurs convictions. Ils apportent aussi leurs bonnes pratiques concrètes pour s'engager dans la mise en place d'un PI Planning. Nous remercions Elodie Clémentine Grasset et <a href=\"https://www.linkedin.com/in/michel-levaslot/\">Michel Levaslot</a> pour leurs contributions.</li></ul>" }, { "type": "heading", "level": 2, "id": "quest-ce-quun-pi-planning", "text": "Qu'est-ce qu'un PI Planning ?" }, { "type": "paragraph", "text": "Focus d'abord sur la définition du PI Planning, et quelques concepts-clés à connaître pour bien vous lancer." }, { "type": "paragraph", "text": "Il s'agit d'une réunion d'équipe à grande échelle, visant à organiser les tâches pour une durée définie, appelée Program Increment ou PI (et Planning Interval depuis la version 6 de SAFe). Cette séance collaborative permet d'aligner les objectifs et de <strong>coordonner les actions de toutes les parties prenantes d'un projet</strong>, garantissant une planification claire et concertée pour la période concernée." }, { "type": "quote", "text": "Le PI Planning, c'est un processus partagé. La notion de \"partagé\" est importante parce que, tout l'intérêt de ce process, c'est que les gens qui y participent sont ceux qui y mettent l'argent - donc ceux qui attendent des bénéfices du livrable. Le PI Planning les oblige à se poser les bonnes questions sur la valeur associée au projet. Ça met les responsabilités au bon endroit.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "paragraph", "text": "On utilise souvent cette pratique dans le cadre d'un développement de produit informatique. Cependant, il peut tout aussi bien être mis en œuvre dans des projets plus traditionnels et structurés, tels que la gestion des changements organisationnels, la création hardware ou encore la réalisation de projets documentaires." }, { "type": "paragraph", "text": "À l'échelle, cette approche peut permettre de structurer tout le build d'une organisation, tous les projets et les évolutions produits en cours." }, { "type": "paragraph", "text": "Grâce à ce processus de planification, vous pouvez :" }, { "type": "list", "ordered": false, "items": ["<strong>Définir et redéfinir régulièrement des objectifs communs</strong> à toutes vos parties prenantes, autour de priorités partagées", "<strong>Planifier les livrables de chaque équipe</strong>, notamment dans le cadre de projets transverses, tout en limitant l'impact des dépendances", "<strong>Déployer et challenger régulièrement et collaborativement un plan d'action</strong>, que chaque équipe s'engage à respecter pour atteindre les objectifs communs via des engagements clairs sur les livrables"] }, { "type": "paragraph", "text": "La session dure généralement une à deux journées, segmentées de manière à aborder tous les sujets du PI à venir : jalons clés, fonctionnalités à développer, priorités, risques…" }, { "type": "heading", "level": 3, "id": "pi-planning-et-framework-safe", "text": "PI Planning et framework SAFe" }, { "type": "paragraph", "text": "Le Program Increment (PI), et par extension le PI Planning, s'inscrit dans le cadre méthodologique du SAFe (Scaled Agile Framework). Dans cette approche agile, les équipes collaborant sur un PI sont appelées \"Agile Release Train\" (ART)." }, { "type": "paragraph", "text": "Pour aller plus loin sur les bonnes pratiques SAFe, consultez <a href=\"/fr/gestion-de-projet/pi-safe\">nos 8 essentiels pour réussir votre PI SAFe</a>." }, { "type": "paragraph", "text": "Traditionnellement, selon les principes du SAFe, un PI s'étend sur une période de 8 à 12 semaines. Toutefois, si vous n'adoptez pas à la lettre ce framework, vous pouvez ajuster cette durée en fonction des besoins de votre organisation, par exemple en choisissant un cycle trimestriel." }, { "type": "quote", "text": "Le framework SAFe considère qu'un Program Increment a une durée spécifique, mais il est possible d'adapter cette temporalité. Les valeurs temporelles comme le trimestre sont très ancrées dans la culture humaine, ce qui peut permettre de rendre les échéances du PI Planning plus aisément compréhensibles par tous. Sans oublier qu'en France, la temporalité trimestrielle permet d'éviter de positionner le prochain PI Planning pendant une période de vacances.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Cette flexibilité n'exclut pas la possibilité de maintenir des sprints plus courts et des livraisons régulières, assurant ainsi un rythme itératif pour l'équipe de développement." }, { "type": "paragraph", "text": "En passant à l'échelle, pour aligner une entreprise sur ses projets stratégiques ou vitaux, on recommande fortement de choisir le rythme du trimestre. Le soleil nous propose un rythme trimestriel pour les saisons, les financiers nous proposent un rythme trimestriel pour les publications financières, pourquoi ne pas s'inscrire dans un rythme naturel pour le build, pour les projets ?" }, { "type": "quote", "text": "Pour les équipes qui sont habituées au contexte SAFe, on peut utiliser le terme de Program Increment Planning. Mais, dans un contexte de gestion de portefeuille de projets, il peut être déroutant d'utiliser le terme \"PI Planning\" — car les parties prenantes vont vouloir se raccrocher à la méthodologie SAFe. Donc autant ne garder que les principes intéressants du PI Planning, et utiliser un terme moins jargonnant, qui correspond à la culture de l'organisation : par exemple, Quarter Plan.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 3, "id": "quels-sont-les-benefices-dun-pi-planning", "text": "Quels sont les bénéfices d'un PI Planning ?" }, { "type": "paragraph", "text": "La pratique de gestion de projets à large échelle qu'est le PI Planning recèle bien des avantages — et ce, que ce soit pour des équipes qui suivent le manifeste agile à la lettre ou non." }, { "type": "paragraph", "text": "Grâce à un PI Planning bien huilé, vous pouvez notamment :" }, { "type": "list", "ordered": false, "items": ["<strong>Aligner toutes vos parties prenantes</strong> autour de priorités stratégiques communes et claires et régulièrement redéfinies", "<strong>Avoir une vision réaliste des projets</strong> et des évolutions produits, pour éviter l'effet tunnel", "<strong>Favoriser la collaboration et l'engagement des acteurs de vos projets</strong> : les owners de programme, de projets ou de produits et les sponsors (Business Owners &amp; dirigeants C-Levels) ou encore les responsables de sujets transverses (contrôleurs financiers, risks &amp; cyber managers, DPO…)", "<strong>Avoir un coup d'avance sur les blocages potentiels des projets</strong> et leurs risques, grâce à une identification en amont de leurs interdépendances"] }, { "type": "paragraph", "text": "Par conséquent, le PI Planning vous permet également de contrôler le budget de vos projets et produits de plus près." }, { "type": "quote", "text": "Le processus de Program Increment Planning permet de mieux contrôler le budget d'un projet. Grâce à un PI Planning, on voit tout passer : les capacités comme le budget à attribuer à chaque étape. Cela permet de donner de la visibilité à tout le monde (y compris le CFO) sur la manière dont l'enveloppe budgétaire est utilisée, et comment on priorise son utilisation sur la période.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "paragraph", "text": "En somme, le PI Planning est une pratique de développement itératif pour accélérer la livraison de valeur de vos projets, et rentrer dans une démarche d'amélioration continue." }, { "type": "paragraph", "text": "Mais pour bénéficier de ces avantages, vous devez comprendre comment mettre en place un PI Planning at scale bien ficelé. Bonne nouvelle : c'est exactement ce que cet article vous dévoile !" }, { "type": "heading", "level": 2, "id": "a-quoi-ressemble-un-pi-planning-reussi-avec-des-benefices-concrets", "text": "À quoi ressemble un PI Planning réussi avec des bénéfices concrets ?" }, { "type": "paragraph", "text": "Découvrez ici à quoi ressemblent deux journées-types de PI Planning." }, { "type": "heading", "level": 3, "id": "le-prerequis-et-le-challenge-permanent-un-climat-dechange-serein-et-transparent", "text": "Le prérequis et le challenge permanent : un climat d'échange serein et transparent" }, { "type": "paragraph", "text": "L'une des clés du succès d'un PI Planning est de réussir à instaurer un environnement où chacun se sent libre de partager ses contraintes, pour planifier collectivement l'avenir du projet sur la période à venir." }, { "type": "paragraph", "text": "Simple sur le papier. Véritable challenge pour les organisateurs qui doivent \"sentir\" les moods de l'entreprise et veiller à distribuer la parole tout en relançant en permanence pour rechercher les compromis." }, { "type": "paragraph", "text": "Ne pas se mentir lors de ces moments est essentiel. Baser les réflexions sur les data objectives disponibles n'empêche pas de faire des paris raisonnables aussi." }, { "type": "paragraph", "text": "Le point de vue du verre à moitié plein sera un allié pour toujours avancer dans la résolution des complexités du portefeuille." }, { "type": "paragraph", "text": "Pour ce faire, utilisez pendant le PI Planning <strong>des outils collaboratifs</strong>, qui permettent de structurer les échanges et de montrer que la parole de chacun est prise en compte." }, { "type": "paragraph", "text": "Utilisez :" }, { "type": "list", "ordered": false, "items": ["Des tableaux d'équipes", "Un tableau des dépendances", "Un tableau des risques"] }, { "type": "paragraph", "text": "Veillez également à <strong>rappeler les règles du PI Planning</strong> dès que vous lancez la réunion. Rentrez dans le détail, en mettant par exemple en avant les couleurs des différents post-its à utiliser sur les tableaux (selon qu'il s'agit de risques, de jalons clés, de features, de user stories…)." }, { "type": "paragraph", "text": "Ces règles seront transmises en amont des prises de parole, auprès de chaque équipe, qui pourront également préparer le terrain habilement." }, { "type": "paragraph", "text": "Et c'est le rôle de l'animateur du PI Planning, le Release Train Engineer (RTE), que de réussir à distribuer la parole équitablement, pour assurer des échanges sereins." }, { "type": "quote", "text": "Le RTE, est quelqu'un que l'on choisit pour sa capacité d'animation. Il doit être bon orateur, savoir gérer sa fatigue (car un PI Planning, c'est fatigant !). Il doit avoir dans sa botte des techniques qui permettent de demander le silence, de couper les personnes trop bavardes, de maîtriser le timing… Souvent, les RTE assistent à d'autres PI Plannings pour se préparer.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 3, "id": "un-lancement-ultra-pragmatique-du-pi-planning-pour-donner-du-sens", "text": "Un lancement ultra pragmatique du PI Planning pour donner du sens" }, { "type": "paragraph", "text": "L'équilibre précaire, notamment dans les premières expérimentations, entre des objectifs raisonnables et un impact total ne doit pas décourager. Un PI Planning c'est un process qui est apprenant pour toutes les parties. Veiller à cibler l'objectif qui résout un des maux les plus partagés par les équipes." }, { "type": "paragraph", "text": "En tout début de PI Planning, c'est le Release Train Engineer qui prend la parole pour introduire la réunion. Il présente l'agenda des journées à venir, et met en avant les objectifs à atteindre." }, { "type": "paragraph", "text": "<em>\"Voici tous les enjeux que le PI nous permet d'adresser, mais pour ces premières mises en œuvre, nous allons focaliser sur …\"</em>" }, { "type": "paragraph", "text": "Puis il <strong>présente la vision du PI à venir</strong>, en se basant sur les priorités stratégiques qu'il a collectées en amont de la réunion." }, { "type": "paragraph", "text": "Les parties prenantes clés — Product Manager, responsables des différents domaines — présentent les objectifs du PI, sa vision, la feuille de route et les priorités stratégiques. L'intervention de top sponsors de l'organisation peut être requise et préparée afin qu'ils portent eux-mêmes les grands changements stratégiques. Invitez les business owners, les directeurs métiers, même des big boss s'il le faut. Donnez le poids nécessaire à ces interventions, qui sont la raison d'être de votre événement." }, { "type": "quote", "text": "La vision du projet est ce qui permet d'exprimer, à court ou à plus long terme, là où on veut collectivement aller. Le but final de la vision du PI est d'embarquer toutes les parties prenantes dans la durée, de les faire tous aller dans le sens de l'entreprise.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Enfin, l'introduction se termine par un rappel <strong>des enjeux stratégiques et des inflexions à prendre en compte dans la période à venir</strong>, une présentation détaillée du backlog et des fonctionnalités ou livrables prioritaires à planifier pour la période à venir." }, { "type": "heading", "level": 3, "id": "des-ateliers-de-planification-par-equipe", "text": "Des ateliers de planification par équipe" }, { "type": "paragraph", "text": "Lors de la deuxième demi-journée du PI Planning, chaque équipe lance son workshop de planification. L'idée : <strong>planifier les livraisons des différentes fonctionnalités pour le PI à venir</strong>, en détaillant chaque user story, et en donnant une estimation des efforts à fournir." }, { "type": "paragraph", "text": "Chaque équipe analyse également <strong>les dépendances</strong> qu'elle pourrait rencontrer avec d'autres équipes, et planifie les itérations en fonction de sa capacité et des priorités des features à sortir." }, { "type": "paragraph", "text": "Lors de cette étape, le Scrum Master aide chaque équipe à prioriser, à organiser le travail. C'est bien de constituer une équipe de référents ultra-engagés dans la réussite de l'événement et multi-équipe pour contrer le côté gourou illuminé qui colle trop souvent aux basques d'un Scrum Master…" }, { "type": "paragraph", "text": "Veillez à la présence d'un représentant des sponsors business dans toutes les phases du PI. Les big boss au début et à la fin, les \"sachants\" experts métiers au cœur des échanges." }, { "type": "quote", "text": "La grande difficulté, surtout pour les métiers, est de réussir à segmenter le produit en features plus fines, pour que le livrable tienne dans la période du Program Increment. Pour cela, il faut amener un changement de culture. Chacun doit comprendre qu'on ne fabrique pas un monolithe, qu'il faut découper le produit pour tenir les échéances de production. Il existe quelques tactiques pour ça : Découper par géolocalisation, en démarrant par une région concernée en premier. Découper le produit en plus petit produit (les pneus de la voiture avant l'habitacle). Découper par population, par exemple en faisant une segmentation 80/20 façon Pareto sur la population concernée…", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 4, "id": "le-tableau-de-suivi-du-rte-garder-le-cap-pendant-les-ateliers", "text": "Le tableau de suivi du RTE : garder le cap pendant les ateliers" }, { "type": "paragraph", "text": "Pendant que les équipes planchent sur leur planification, le RTE ne reste pas les bras croisés. Son rôle est de suivre l'avancement de chaque équipe au fil de l'eau, en s'appuyant sur un tableau de \"Scrum de Scrum\" qui pose les bonnes questions :" }, { "type": "list", "ordered": false, "items": ["Avez-vous identifié la Capacité à Faire (CAF) par sprint ?", "Avez-vous identifié la charge totale de vos features ? Est-elle inférieure à 80% de votre CAF ?", "Combien de dépendances restent à négocier ?", "Avez-vous identifié des actions d'atténuation des risques ?", "Avez-vous rédigé vos objectifs de PI ?"] }, { "type": "quote", "text": "Cette checklist permet de s'assurer de la qualité des échanges entre les participants, et de guider ceux qui sont un peu perdus pendant le Program Increment Planning.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Ce tableau est un outil de pilotage simple mais redoutablement efficace. Il rend visible l'état de préparation de chaque équipe et permet au RTE d'intervenir au bon moment, avant qu'un blocage ne s'installe." }, { "type": "heading", "level": 3, "id": "lidentification-des-dependances-un-livrable-cle-dun-pi-reussi", "text": "L'identification des dépendances, un livrable clé d'un PI réussi" }, { "type": "paragraph", "text": "Lorsque les ateliers de planification sont terminés, chaque équipe présente son plan à tout le train agile. Collectivement, <strong>les dépendances sont validées, et les plans de chaque équipe sont ajustés</strong> pour éviter que ces dépendances ne créent des goulots d'étranglement." }, { "type": "paragraph", "text": "Veiller à ce que ces dépendances ne restent pas sur le paper board jusqu'au prochain PI, mais intégrez-les directement dans vos outils de suivi des projets et des produits." }, { "type": "heading", "level": 3, "id": "le-risk-management-au-coeur-des-enjeux-du-pi-planning", "text": "Le risk management au cœur des enjeux du PI Planning" }, { "type": "paragraph", "text": "Pendant la troisième demi-journée, les participants du PI Planning analysent les risques que les projets vont probablement rencontrer, et qui mettraient potentiellement à mal les livraisons. Ces risques sont généralement classés par ordre de priorité. Puis le collectif met en place <strong>des actions pour atténuer ces risques</strong>." }, { "type": "paragraph", "text": "Une nouvelle fois une attention particulière sera mise sur l'usage de cette matière riche (les risques) qui émerge lors des PI Planning. Choisissez une solution qui rend visible ces risques au cœur même de votre gestion des portefeuilles, programmes, projets et produits." }, { "type": "heading", "level": 3, "id": "une-validation-collective-du-plan-final-du-pi", "text": "Une validation collective du plan final du PI" }, { "type": "paragraph", "text": "Pendant la dernière demi-journée de PI Planning, <strong>les plans d'équipes sont finalisés</strong>. Les représentants des métiers font part de leur feedback sur ces plans, et des ajustements finaux sont apportés si besoin." }, { "type": "paragraph", "text": "Puis tout le monde participe à <strong>un vote de confiance</strong> : les équipes s'engagent ainsi à s'aligner sur le plan qu'elles ont défini. Dans des cas très rares, si le vote de confiance est très bas, il peut être décidé de retravailler les plans. Mais généralement, les ateliers de planification et l'étude des interdépendances a permis d'obtenir un plan carré, adopté par tous." }, { "type": "heading", "level": 3, "id": "collecter-du-feedback-montrer-quon-veut-faire-mieux-la-fois-dapres", "text": "Collecter du feedback : montrer qu'on veut faire mieux la fois d'après" }, { "type": "paragraph", "text": "Un PI Planning ne se termine pas au vote de confiance. L'ultime étape de la réunion, c'est la rétrospective — un moment dédié pour que les participants partagent ce qui a bien fonctionné et ce qui doit être amélioré pour les prochaines sessions." }, { "type": "paragraph", "text": "Deux formats fonctionnent particulièrement bien dans ce contexte :" }, { "type": "paragraph", "text": "Le <strong>ROTI</strong> (Return On Time Invested) permet à chaque participant de noter rapidement l'utilité perçue du temps investi. C'est un indicateur flash, parfait pour prendre le pouls collectif en fin de journée." }, { "type": "paragraph", "text": "Le <strong>DAKI</strong> (Drop, Add, Keep, Improve) va plus loin : chaque participant identifie ce qu'il faut abandonner, ajouter, conserver ou améliorer dans le processus. C'est un format structurant qui alimente directement les évolutions du prochain PI Planning." }, { "type": "paragraph", "text": "Ne sous-estimez pas cette étape. Un PI Planning qui s'améliore d'un trimestre à l'autre, c'est un PI Planning qui s'ancre durablement dans la culture de l'organisation. Et c'est précisément cette logique d'amélioration continue qui distingue les équipes qui \"font du PI Planning\" de celles qui en tirent réellement de la valeur." }, { "type": "heading", "level": 2, "id": "des-sa-preparation-faites-de-votre-pi-planning-un-atout-pour-transformer", "text": "Dès sa préparation, faites de votre PI Planning un atout pour transformer" }, { "type": "paragraph", "text": "Vous l'aurez peut-être déjà compris : un PI Planning réussi, c'est une réunion qui ne laisse rien au hasard, et qui est bien planifiée en amont. Voici quelques étapes-clés par lesquelles passer pour un Program Increment Planning sans accroc." }, { "type": "heading", "level": 3, "id": "miser-sur-les-bonnes-personnes-pour-provoquer-lalignement", "text": "Miser sur les bonnes personnes pour provoquer l'alignement" }, { "type": "paragraph", "text": "Tout d'abord, vous devez établir une liste des participants à votre PI Planning. Toutes les parties prenantes de votre projet doivent être présentes — mais attention : il s'agit de réunir aussi les personnes qui sont réellement décisionnaires." }, { "type": "paragraph", "text": "Sinon, vous prenez le risque d'aligner les équipes qui font et celles qui organisent sans impliquer celles et ceux qui décident. Gros warning : vous partez mal et allez créer des attentes fortes. Pas de sponsor, pas de PI." }, { "type": "quote", "text": "Un PI Planning est une séance de planification. Toutes les personnes nécessaires à la planification et aux arbitrages doivent être présentes. Par contre, attention à ne pas considérer cette réunion comme du \"tourisme industriel\". Si des personnes ne sont pas nécessaires, autant ne pas les inviter. Leur présence risque de polluer le PI Planning.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "Doivent être présents à votre séance de planification :" }, { "type": "list", "ordered": false, "items": ["<strong>Le Product Management</strong>, dont les Product Owners", "<strong>Les Scrum Masters</strong>", "<strong>Les Business Owners</strong>, et le management impliqué dans le projet", "<strong>Les architectes</strong>", "<strong>Les sponsors</strong> des projets"] }, { "type": "heading", "level": 4, "id": "clarifier-le-role-de-chacun-avant-le-jour-j", "text": "Clarifier le rôle de chacun avant le jour J" }, { "type": "paragraph", "text": "Avoir les bonnes personnes dans la salle ne suffit pas : chacune doit savoir ce qu'on attend d'elle. Prenez le temps d'expliciter les responsabilités de chaque profil en amont du PI Planning :" }, { "type": "paragraph", "text": "Le <strong>Release Train Engineer (RTE)</strong> coordonne et facilite l'ensemble du PI Planning. C'est lui qui distribue la parole, gère le timing, et s'assure que chaque atelier produit les livrables attendus." }, { "type": "paragraph", "text": "Le <strong>Product Management</strong> (dont les Product Owners) définit les priorités et les features à développer. C'est la voix du \"quoi\" et du \"pourquoi\"." }, { "type": "paragraph", "text": "Les <strong>Scrum Masters</strong> aident les équipes agiles à préparer leurs plans, à estimer leur capacité et à lever les blocages opérationnels." }, { "type": "paragraph", "text": "Les <strong>Business Owners</strong> fournissent les orientations stratégiques et valident les objectifs proposés par les équipes. Leur présence est non négociable pour les arbitrages." }, { "type": "heading", "level": 4, "id": "desamorcer-les-resistances-en-amont", "text": "Désamorcer les résistances en amont" }, { "type": "paragraph", "text": "L'état d'esprit des participants est aussi important que leur présence. Prenez du temps en amont avec les profils sceptiques : levez leurs peurs, identifiez leurs contraintes. Si certaines personnalités risquent de freiner la dynamique collective, préparez le terrain avec leur manager direct. Un deal simple fonctionne souvent : un enjeu personnel adressé en échange d'une attitude constructive pendant la réunion." }, { "type": "paragraph", "text": "Ne soyez pas naïf sur ce point : une seule personne mal embarquée peut abîmer l'impact d'un PI Planning, surtout lors des premières mises en œuvre." }, { "type": "quote", "text": "Ce qui peut faire qu'un PI Planning ne fonctionne pas, c'est de réunir des gens qui ont des objectifs vraiment antinomiques, qui les empêchent d'avoir envie de travailler les uns avec les autres. Mais sachez qu'il est même possible de faire des trains multi-organismes, avec des partenaires business. Un signe que la réussite du PI Planning tient surtout au fait que le projet soit bien sponsorisé des deux côtés. Le PI Planning n'est pas un outil magique : tout le monde doit comprendre qu'on cherche une victoire collective, un processus gagnant/gagnant, malgré les éventuelles inadhérences politiques.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "heading", "level": 3, "id": "avoir-une-vision-claire-des-priorites-strategiques", "text": "Avoir une vision claire des priorités stratégiques" }, { "type": "paragraph", "text": "En préparant votre PI Planning, vous devez déterminer quelle est la vision qui va guider la période que vous devez planifier. L'idée : <strong>aligner tout le monde autour de la transformation que votre entreprise va vivre à l'avenir</strong>." }, { "type": "paragraph", "text": "Prenez en compte l'environnement dans lequel votre entreprise évolue et va évoluer dans les temps à venir. Votre vision peut être basée sur des éléments positifs (comme des projets innovants que l'entreprise va mener), négatifs (comme l'arrivée de nouveaux concurrents sur votre marché), ou encore sur des contraintes (comme une nouvelle réglementation)." }, { "type": "paragraph", "text": "Allez également parler avec les directeurs métiers impliqués, et demandez-leur quelles sont leurs priorités stratégiques, et les points de friction qu'ils auront besoin d'aborder pendant le PI Planning." }, { "type": "paragraph", "text": "Notez que la vision que vous allez communiquer aux participants de votre PI Planning n'impacte pas forcément la période à venir. Il s'agit surtout d'une grande ligne directrice qui doit guider la priorisation des actions à venir." }, { "type": "paragraph", "text": "Pensez aussi à préparer votre <strong>roadmap produit</strong> et votre backlog. Veillez à ce que les features soient matures, compréhensibles, faisables, découpées pour tenir dans le PI, et chargées. Des features trop floues ou trop grosses feront perdre un temps précieux pendant les ateliers de planification." }, { "type": "heading", "level": 3, "id": "anticiper-les-blocages-potentiels", "text": "Anticiper les blocages potentiels" }, { "type": "paragraph", "text": "Même si le PI Planning a pour but d'identifier les blocages qui pourraient interférer dans votre projet, prenez le temps si possible d'anticiper ces blocages lors de votre préparation." }, { "type": "paragraph", "text": "Pour cela :" }, { "type": "list", "ordered": false, "items": ["<strong>Préparez une matrice des risques</strong> du projet", "<strong>Repérez les goulots d'étranglement potentiels</strong>, au vu des interdépendances des équipes.", "<strong>Anticipez les contraintes externes au projet</strong>, ainsi que les questions techniques que les participants pourraient vous poser."] }, { "type": "quote", "text": "Le support de travail en amont d'un PI Planning, c'est essentiellement un backlog des projets, un portefeuille de projets, pré-trié avec une macro-priorisation, et une estimation \"à la louche\" de l'effort. Et quand on a un sujet de capacité, il peut être intéressant d'essayer d'identifier, en amont, quel goulot d'étranglement pourrait émerger.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 3, "id": "organiser-la-logistique", "text": "Organiser la logistique" }, { "type": "paragraph", "text": "Vous le savez : la gestion de projet à grande échelle demande une logistique considérable. Et c'est également le cas pour l'organisation d'un PI Planning !" }, { "type": "paragraph", "text": "Prenez le temps de :" }, { "type": "list", "ordered": false, "items": ["<strong>Réserver les jours du planning dans l'agenda des participants</strong>, et anticiper les besoins de réservations d'hôtel si des intervenants ont besoin de se déplacer. Réservez au moins deux mois en avance. Vérifiez aussi si les dates fixées permettent à vos invités de planifier des team meetings sur les jours précédents ou suivants — un deal avec l'hôtel du coin, c'est toujours ça en moins sur le budget.", "<strong>Planifier la réunion dans une salle adaptée au PI Planning</strong>, ou bien mettre en place un outil de visioconférence si votre réunion se passe à distance. Vos salles (physiques ou digitales) doivent pouvoir contenir tous les participants, et leur permettre de travailler en plus petits groupes. Prévoyez des salles annexes pour traiter les problèmes qui peuvent apparaître en séance. Réfléchissez à un plan de table qui facilite la communication par équipes et inter-équipes.", "<strong>Préparer un agenda détaillé du PI Planning</strong>. Prévoyez minutieusement la durée de chaque session. Puis partagez cet agenda à tous."] }, { "type": "paragraph", "text": "Vous optez pour le PI Planning en ligne ? Ne sous-estimez pas la complexité de la logistique. Qualité des visios, outils collaboratifs pour les workshops, salles virtuelles dédiées… Des tests et une répétition générale le jour précédent paraissent indispensables. Nous déconseillons personnellement de mener vos PI Plannings intégralement à distance !" }, { "type": "heading", "level": 3, "id": "communiquer-pour-changer-la-culture-projet", "text": "Communiquer pour changer la culture projet" }, { "type": "paragraph", "text": "Lancer la démarche itérative du PI Planning dans une entreprise est un véritable acte de communication. Vous devez faire en sorte que vos participants soient prêts à s'y engager fermement, dans la durée, et qu'ils comprennent les bénéfices qu'ils pourront en tirer." }, { "type": "quote", "text": "En amont du PI Planning, il faut vendre ce processus comme une arme de guerre. Tout le monde doit être prêt à \"brûler les vaisseaux\" : chacun doit s'engager dans la démarche, sans faire marche arrière. Pour ça, il faut créer de l'engagement via un acte de communication fort, en publiant des posts sur l'Intranet, par exemple. Pour lancer un PI Planning, nous avons même un jour lancé un article sur un média externe référent pour détailler le processus : idéal pour créer de l'engagement.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "En effet, les développeurs sont souvent habitués à travailler de manière incrémentale, grâce à des méthodes agiles. Mais les métiers, eux, ont souvent plus de mal à mettre en place une méthode de planification aussi fine et détaillée. Le processus de PI Planning demande de mener une véritable conduite du changement : communication sur les bénéfices, levage des freins de chacun, et mise en place de techniques concrètes pour mieux planifier ensemble." }, { "type": "paragraph", "text": "D'où le fait que vous devez <strong>mener une conduite du changement assidue</strong>, en communiquant de manière motivante. Levez les freins de chacun en amont de la réunion, et rappelez à tous les avantages de ce mode de fonctionnement." }, { "type": "quote", "text": "Le PI Planning pousse toutes les parties prenantes à se poser les bonnes questions sur la valeur associée au projet. Lors des discussions, on se focalise sur pourquoi on fait ce projet, quelles sont les priorités, et comment identifier et gérer les dépendances. Ce processus permet à tout le monde de se rendre compte que la gestion du projet est transparente, non arbitraire, et remet les responsabilités au bon endroit.", "author": "Elodie Clémentine Grasset — Consultante et formatrice indépendante et ex-CDO Groupe Air Liquide" }, { "type": "heading", "level": 2, "id": "quels-outils-pour-un-pi-planning-qui-se-deroule-parfaitement", "text": "Quels outils pour un PI Planning qui se déroule parfaitement ?" }, { "type": "paragraph", "text": "Un PI Planning efficace ne repose pas uniquement sur la méthodologie : les bons outils font toute la différence. Sans une préparation rigoureuse et un suivi structuré, cet exercice peut vite devenir une perte de temps, avec des engagements flous et des dépendances mal gérées." }, { "type": "paragraph", "text": "C'est là qu'un outil comme <strong>Airsaas</strong> prend tout son sens. Avant même le PI Planning, il permet de <strong>préparer en amont la capacité des équipes, de prioriser les features clés et d'anticiper les dépendances</strong>. En donnant une vision claire des objectifs et des ressources disponibles, Airsaas facilite la revue des initiatives et aligne les parties prenantes sur ce qui est vraiment faisable sur le trimestre à venir." }, { "type": "paragraph", "text": "Pendant l'événement, Airsaas structure la planification en <strong>rendant visibles les arbitrages et les engagements pris</strong>. Plus besoin de jongler avec des dizaines de tableaux : tout est centralisé, lisible et actionnable. Et après le PI Planning, il assure un suivi en continu des engagements et de l'exécution des projets, pour éviter les dérives et ajuster les priorités en fonction des réalités terrain." }, { "type": "paragraph", "text": "Un PI Planning réussi, c'est une préparation solide, une exécution fluide et un suivi rigoureux. Avec Airsaas, vous donnez aux équipes IT et métiers un cadre clair et pragmatique pour que leurs efforts soient réellement alignés sur la stratégie de l'entreprise." }, { "type": "paragraph", "text": "Intéressé ? <a href=\"https://www.airsaas.io/fr\">Découvrez Airsaas, et demandez votre démo dès maintenant</a>." }, { "type": "heading", "level": 2, "id": "apres-le-pi-planning-assurer-le-suivi-pour-ne-pas-perdre-la-valeur-creee", "text": "Après le PI Planning : assurer le suivi pour ne pas perdre la valeur créée" }, { "type": "paragraph", "text": "Le PI Planning est terminé. Deux jours intenses, des dizaines de décisions prises, des engagements formalisés. Mais tout cela ne vaut rien si la dynamique retombe le lundi suivant. Voici comment capitaliser sur l'énergie du PI." }, { "type": "heading", "level": 3, "id": "communiquer-les-objectifs-et-les-rendre-accessibles-a-tous", "text": "Communiquer les objectifs et les rendre accessibles à tous" }, { "type": "paragraph", "text": "Premier réflexe : rassemblez tous les objectifs du Program Increment et les plans d'équipes, et diffusez-les largement. Chaque participant doit pouvoir retrouver facilement ce qui a été décidé, les engagements de chacun, et les échéances associées." }, { "type": "paragraph", "text": "Votre plan dans un Sharepoint caché ou un PowerPoint envoyé par email, ça ne suffira pas. Optez pour des solutions qui rendent vos plans compréhensibles et accessibles en permanence — pour les équipes comme pour les sponsors." }, { "type": "paragraph", "text": "Vous n'avez pas déployé toute cette énergie, mobilisé autant de cerveaux, pour que les décisions prises restent confidentielles." }, { "type": "heading", "level": 3, "id": "mettre-en-place-les-rituels-de-suivi", "text": "Mettre en place les rituels de suivi" }, { "type": "paragraph", "text": "Tout au long du PI, un suivi régulier est indispensable pour s'assurer que le plan est respecté et que les obstacles sont levés rapidement. Trois niveaux de rituels sont à mettre en place :" }, { "type": "paragraph", "text": "Les <strong>réunions quotidiennes</strong> (Daily Stand-ups) et les réunions de gestion des risques permettent aux équipes de traiter les irritants au fil de l'eau." }, { "type": "paragraph", "text": "Les <strong>Scrum of Scrums</strong> et les <strong>PI Reviews</strong> assurent la synchronisation entre les équipes à intervalles réguliers. C'est le moment de vérifier que les dépendances identifiées sont bien gérées." }, { "type": "paragraph", "text": "Les <strong>System Demo</strong> (ou a minima des démos d'équipes) offrent une mesure objective et régulière de l'avancement, avec la possibilité de recevoir du feedback." }, { "type": "paragraph", "text": "L'écueil que rencontrent beaucoup d'organisations : les informations du PI Planning restent sur des post-its dans Miro ou sur un paperboard pris en photo… et six mois plus tard, on recommence à identifier des dépendances et des risques qu'on avait déjà levés. Intégrez la data produite lors du PI dans vos outils de suivi projet, et exploitez-la en continu." }, { "type": "heading", "level": 3, "id": "linspect-and-adapt-boucler-la-boucle-avant-le-prochain-pi", "text": "L'Inspect & Adapt : boucler la boucle avant le prochain PI" }, { "type": "paragraph", "text": "Juste avant le prochain PI Planning, prenez le temps de faire une revue de la réalisation effective du PI — en termes de valeur atteinte, plus qu'en termes de features livrées. C'est la cérémonie d'<strong>Inspect &amp; Adapt</strong> : un moment clé pour identifier ce qui a fonctionné, ce qui a dévié, et ce qui doit changer." }, { "type": "quote", "text": "Si les équipes font du Scrum, on conserve toutes les cérémonies Scrum, ce qui permet de traiter les dérives qui ont pu apparaître entre la planification en PI Planning et le déroulement effectif. Et, juste avant le prochain PI Planning, on fait une séance de revue de la réalisation effective du PI (en termes de valeur atteinte plus qu'en termes de features) et d'amélioration, cérémonie appelée Inspect & Adapt.", "author": "Michel Levaslot — Adjoint de Direction - Transformation de la DSI et animateur d'un club SAFe" }, { "type": "paragraph", "text": "C'est cette boucle complète — planifier, exécuter, suivre, ajuster — qui fait passer le PI Planning d'un événement ponctuel à un véritable moteur de transformation continue." }, { "type": "paragraph", "text": "Vous êtes désormais prêt pour lancer ou optimiser votre prochain Program Increment Planning !" }, { "type": "insight-callout", "label": "À retenir", "html": "<p>Découvrez Airsaas pour structurer votre PI Planning de bout en bout : préparation, exécution et suivi des engagements.</p>" }], "toc": [{ "label": "Qu'est-ce qu'un PI Planning ?", "href": "#quest-ce-quun-pi-planning", "level": 2 }, { "label": "À quoi ressemble un PI Planning réussi avec des bénéfices concrets ?", "href": "#a-quoi-ressemble-un-pi-planning-reussi-avec-des-benefices-concrets", "level": 2 }, { "label": "Dès sa préparation, faites de votre PI Planning un atout pour transformer", "href": "#des-sa-preparation-faites-de-votre-pi-planning-un-atout-pour-transformer", "level": 2 }, { "label": "Quels outils pour un PI Planning qui se déroule parfaitement ?", "href": "#quels-outils-pour-un-pi-planning-qui-se-deroule-parfaitement", "level": 2 }, { "label": "Après le PI Planning : assurer le suivi pour ne pas perdre la valeur créée", "href": "#apres-le-pi-planning-assurer-le-suivi-pour-ne-pas-perdre-la-valeur-creee", "level": 2 }], "faq": [], "related": [] }, { "slug": "project-portfolio-management", "skip": false, "meta": { "title": "Project portfolio management : le top 10 des bonnes pratiques", "h1": "Project portfolio management : le top 10 des bonnes pratiques", "description": "Découvrez le top 10 des bonnes pratiques en project portfolio management : sens, rituels, priorisation, transparence et culture de transformation.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63977013ce0aa527482b769b_ppm-top1-bestpracice.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "1/3/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "1/3/2023" }, "blocks": [{ "type": "paragraph", "text": "Et si on se l'avouait franchement : <strong>parfois, les organisations n'arrivent plus à gérer leurs priorités</strong>. Parfois, les directions générales ont <strong>une vision partielle de l'utilisation des ressources</strong> et de la performance des projets, parfois les <strong>nouvelles demandes de projet sont validées sans même savoir si la capacité à délivrer est réaliste</strong>...et enfin parfois...<strong>le lien entre le business plan de l'IT et celui de l'entreprise</strong> est clairement <strong>déconnecté !</strong>" }, { "type": "paragraph", "text": "Est-ce que ça vous parle ?" }, { "type": "paragraph", "text": "Oui, les <strong>organisations</strong> d'aujourd'hui ont un <strong>besoin</strong> vital, à la fois d'<strong>outils modernes ET d'une approche différente</strong> pour gérer leurs <strong>plans de transformation et portefeuilles de projets</strong> associés !" }, { "type": "paragraph", "text": "Wikipédia nous le rappelle : <em>La gestion de portefeuille de projets est la discipline traitant des </em><strong><em>projets d'un point de vue général dans un but de sélection et d'arbitrage</em></strong><em>. Alors que la gestion de projet s'attache à « bien faire les projets » - domaine de l'opérationnel -,</em><strong><em> la gestion de portefeuille de projets vise à « faire les bons projets </em></strong><em>» - domaine du décisionnel.</em>" }, { "type": "paragraph", "text": "Une <strong>gestion plus simple et efficace</strong> du portefeuille projet est essentielle <strong>au succès de toute organisation</strong>, car elle <strong>aide</strong> à <strong>décider ce qui est financé et ce qui ne l'est pas</strong>. Elle aide à voir ce qui est réaliste et ce qui ne l'est pas. Elle aide à distinguer ce qui va à l'encontre de l'alignement stratégique et des priorités et ce qui le favorise. Bref, ce qui est efficace et ce qui ne l'est pas..." }, { "type": "paragraph", "text": "En effet, les entreprises doivent trouver des moyens d'atteindre un équilibre entre investir dans les opérations quotidiennes et prendre des initiatives stratégiques pour se transformer." }, { "type": "paragraph", "text": "Oui, mais comment <strong>mettre l'accent sur la sélection d'initiatives qui maximisent (vraiment) la valeur</strong> apportée à l'ensemble d'une entreprise ?" }, { "type": "paragraph", "text": "<strong>De nouvelles démarches de Portfolio Management</strong> - Gestion de portefeuille projet existent justement pour <strong>faciliter et développer les capacités de décisions</strong>, <strong>d'exécution et de coopération</strong> de nos organisations, les rendre plus <strong>efficaces</strong> !" }, { "type": "list", "ordered": false, "items": ["en arbitrant entre les différentes priorités,", "en centralisant l'ensemble des données des divers projets et ressources,", "en s'alignant mieux avec la stratégie globale."] }, { "type": "paragraph", "text": "Problème...ce sont de nouvelles démarches justement. L'ancrage d'années de micromanagement de projet \"à la tâche\" est très fort. Vous installez un outil macro...et on vous ramène au suivi des actions ! ....<strong>Ce dossier est justement là pour vous aider</strong> à user de pédagogie et de patience pour non pas vous lancer dans la politique mais embarquer au juste niveau de compréhension toutes vos parties prenantes." }, { "type": "paragraph", "text": "À l'image d'un portefeuille boursier...<strong>choisir où investir votre budget et votre temps n'est pas une mince affaire</strong>. Nous avons recueilli les <strong>témoignages et retours d'expérience de DSI</strong>, chefs de projet, PMO et Directions générales. Découvrez leurs <strong>approches innovantes et pragmatiques dans ce grand guide du portfolio management qui vous conduira en prime vers la découverte d'articles thématiques pour approfondir chacune des pratiques présentées.</strong>" }, { "type": "paragraph", "text": "<strong>Bonne lecture.</strong>" }, { "type": "heading", "level": 2, "id": "1-redonner-du-sens-aux-grands-programmes-de-transfo-dans-votre-project-portfolio-management", "text": "1. Redonner du sens aux grands programmes de transfo dans votre Project Portfolio Management" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe171e759265fce10a4c85_sens-min.jpeg", "alt": "Le sens de la transformation doit être partagé !", "caption": "Appuyez sur le bouton pour lancer le portfolio management system de votre activité" }, { "type": "paragraph", "text": "Un programme = un groupe de projets dont le nom doit parler à tous." }, { "type": "paragraph", "text": "Le programme ERP, SI Finance, ERP ne fera jamais rêver !" }, { "type": "paragraph", "text": "Un outil de portfolio management adapté à la transformation des organisations vous permettra de publier votre programme, d'y <strong>\"ranger\" vos chantiers et projets afin qu'ils contribuent à un ensemble clair pour tous. Un sens commun disponible \"à la demande\" pas seulement lors des projections de powerpoint en copil.</strong>" }, { "type": "paragraph", "text": "Il faut en effet <strong>que les collaborateurs sachent où trouver, quand ils en ont besoin, en self-service presque, un sens commun dans leurs actions, des repères</strong>. Avant de s'adapter et se transformer il faut déjà se repérer. Ce sont bien eux, les collaborateurs qui auront un impact significatif dans le projet, qui lui-même à un impact significatif dans l'évolution de l'entreprise." }, { "type": "paragraph", "text": "Au delà de l'effet \"marketing\", on retrouve ici <strong>l'allégorie du tailleur de pierre</strong>, ce <strong>conte qui traite de la relation au désir et au plaisir</strong> ! Selon le sens qu'on y met, deux rapports au travail s'opposent : «Je fabrique juste un mur. ». VS « Je suis en train de construire une cathédrale »." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe177a1d5135336a3c9841_2%20ppm-min.png", "alt": "Vue programme AirSaas", "caption": "Exemple de vue programme qui affiche tous les projets en vue macro" }, { "type": "paragraph", "text": "<strong>La communication continue des enjeux stratégiques</strong> joue donc un rôle de <strong>levier</strong> et les collaborateurs doivent trouver du sens dans les nouvelles actions au regard de leur mission principale, ils participent souvent à un projet qui égale ou dépasse en importance pour l'entreprise les enjeux de leur mission principale. <strong>C'est du sens que naît l'engagement,</strong> et chaque partie joue un rôle déterminant." }, { "type": "paragraph", "text": "Pour aligner le métier, la direction générale et l'IT autour d'une vision commune appuyez-vous sur : <a href=\"/fr/solution/outil-ppm\" target=\"_blank\">AirSaas : un outil PPM nouvelle génération - Logiciel ppm</a>" }, { "type": "heading", "level": 2, "id": "2-reduire-les-durees-des-projets-de-votre-portefeuille", "text": "2. Réduire les durées des projets de votre portefeuille" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe17be440cc6dd369bafc4_3%20de%CC%81lai%20ppm-min.jpeg", "alt": "PPM - durée des projets portefeuille projets", "caption": "Tendre vers une réduction de la durée des projets de votre portefeuille projets - PPM" }, { "type": "paragraph", "text": "Tendre vers une (vraie) réduction des <strong>délais de développement, générera plus de potentiel de progrès que les autres approches.</strong>" }, { "type": "paragraph", "text": "Agilité, accélération digitale, \"ubérisation\", les rythmes d'innovations sont désormais plus rapides ! Oui on assiste lentement mais sûrement à la <strong>fin</strong> des <strong>schémas directeurs</strong> / roadmap des systèmes d'information <strong>à 3 voire 5 ans que nous connaissions.</strong>" }, { "type": "paragraph", "text": "Car oui, le rythme des projets de votre roadmap, ça compte !" }, { "type": "paragraph", "text": "Dans une organisation optimale, <strong>un projet ne devrait pas dépasser 3 mois</strong>. C'est un <strong>challenge !</strong>" }, { "type": "paragraph", "text": "<strong>Les sceptiques</strong> vous diront :" }, { "type": "list", "ordered": false, "items": ["Impossible, je n'ai que des projets de 18 mois", "On ne peut pas découper un projet ERP en projet de 3 mois !", "Je ne vois pas à quoi ça sert ^^"] }, { "type": "paragraph", "text": "<strong>Les \"précurseurs\" rétorqueront :</strong>" }, { "type": "list", "ordered": false, "items": ["Sur les projets « longs » on le découpe déjà en phase donc ça ne nous rajoute pas de travail", "C'est top, grâce à ça on se met sur une dynamique d'entreprise", "En faisant un événement par trimestre, ça nous aide à faire converger les énergies avec les métiers et les sponsors", "Avec ça on arrive beaucoup plus facilement à dynamiser la roadmap avec toutes les parties prenantes."] }, { "type": "paragraph", "text": "À vous de trouver votre nouveau découpage et rythme cible pour les durées \"recommandées\" de projets de votre portefeuille projets." }, { "type": "paragraph", "text": "Pour aller plus loin et moderniser votre gouvernance découvrez l'article : <a href=\"/gestion-de-projet/trois-innovations-et-tendances-qui-bousculent-la-gestion-de-portefeuille-de-projets\" target=\"_blank\">Trois innovations et tendances qui bousculent la gestion de portefeuille de projets</a>." }, { "type": "heading", "level": 2, "id": "3-redefinir-les-roles-de-chaque-membre", "text": "3. Redéfinir les rôles de chaque membre" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe180f3a6e9a784b3ccaaf_%204%20re%CC%80gles%20PPM-min.jpeg", "alt": "PPM définition des règles et prérogatives", "caption": "Conseils de PMO avisé" }, { "type": "paragraph", "text": "Ça veut dire quoi exactement être \"key user\", \"chef de projet\", \"référent métier\", project managers ou \"sponsor\" ? Dans le contexte de votre organisation ?" }, { "type": "paragraph", "text": "<strong>Quels sont les pouvoirs et les devoirs</strong> de chacun dans la gouvernance et la gestion de projets au sein de votre entreprise ? <strong>Sans règle du jeu, personne ne sera responsable de rien</strong> !" }, { "type": "paragraph", "text": "Alan Zucker, directeur fondateur de Project Management Essentials, déclare que la définition des rôles pour les individus et les groupes est une première étape importante. \"<em>De nombreuses organisations ne parviennent pas à établir des attentes au début, ce qui conduit à la confusion et aux conflits sur toute la ligne.</em>\"" }, { "type": "paragraph", "text": "Il appelle trois questions clés à poser :" }, { "type": "list", "ordered": true, "items": ["Quel est le <strong>rôle du project management office</strong> - PMO / bureau des projets ?", "<strong>Qui joue quels rôles</strong> dans l'<strong>établissement des priorités stratégiques de l'organisation</strong> et <strong>approuve les projets qui s'alignent sur la stratégie</strong> ?", "<strong>Qui « possède » les projets</strong> et est responsable du fait que ceux-ci, respectent leur portée, leur calendrier et leurs objectifs de coût ?"] }, { "type": "paragraph", "text": "À l'image de Scrum, la culture \"lean-agile pose des rôles clés. À un niveau supérieur, dans les portefeuilles projets on a également à adresser <strong>ce travail de définition des redevabilités associées aux rôles.</strong>" }, { "type": "paragraph", "text": "Expliquer les prérogatives de chaque membre du projet c'est la base mais c'est parfois invisible dans les outils du quotidien !" }, { "type": "paragraph", "text": "Pour <strong>simplifier la définition et la tenue des rôles de chacun</strong> dans un projet on a amélioré cette fonction dans AirSaas. Vous allez pouvoir à la fois définir qui fait quoi et aligner tous les intervenants sur ce qui est attendu de chacun." }, { "type": "paragraph", "text": "Lors du cadrage ou de la vie du projet, vous pouvez ajouter :" }, { "type": "paragraph", "text": "✔️Soit des personnes et ensuite leur assigner un rôle" }, { "type": "paragraph", "text": "✔️Soit des rôles dans lesquels vous allez ajouter des personnes" }, { "type": "paragraph", "text": "Au-delà du fait d'assigner un rôle type à quelqu'un...<strong>une phrase donnera du contexte sur chacun des rôles dans le projet.</strong> Elle permet d'<strong>aligner tous les intervenants sur ce qui est attendu de chacun</strong>. Cette définition est bien sûr paramétrable dans AirSaas, en fonction de la culture de votre organisation." }, { "type": "paragraph", "text": "Pour <strong>tester autre chose qu'une matrice RACI qui sera oubliée</strong> dans les diapos d'un kick off....j'essaie AirSaas, l'outil de gestion de portefeuille qui modernisera votre gouvernance !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fc784be5cad04293441368_qfq-projets-min.jpeg", "alt": "Poser les droits, devoirs et règles du jeu à chaque membre du projet avec l'aide d'un outil", "caption": "Poser les droits, devoirs et règles du jeu à chaque membre du projet avec l'aide d'un outil" }, { "type": "paragraph", "text": "Pour poursuivre et approfondir votre approche nous vous recommandons la lecture de l'article suivant : <a href=\"/gestion-de-projet/le-lean-portfolio-management-pour-aligner-en-continu-la-direction-generale-lit-et-les-metiers\">Le Lean Portfolio Management pour aligner en continu la direction générale, l'IT et les métiers</a>" }, { "type": "heading", "level": 2, "id": "4-creer-des-rituels-pas-des-reunions", "text": "4. Créer des rituels pas des réunions !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe18f41c8f2fdbafa96539_7%20routines%20ppm-min.jpeg", "alt": "Routines et rituels projet", "caption": "L'importance fondamentale des rituels dans le portfolio management" }, { "type": "paragraph", "text": "Vous connaissez les rituels SCRUM, des rituels des repas de Noël, des anniversaires, d'Halloween, de la cérémonie du thé…Il est temps de <strong>s'intéresser de plus près à vos rituels de gouvernance projet.</strong>" }, { "type": "paragraph", "text": "Rappel : <strong>un rituel</strong> est un ensemble des règles et habitudes fixées. <strong>À ne pas confondre avec une routine</strong> qui est une habitude mécanique, irréfléchie, et qui résulte d'une succession d'actions répétées sans cesse." }, { "type": "paragraph", "text": "On pense en particulier aux réunions routinières !" }, { "type": "paragraph", "text": "En gestion de portfolio management la mise en place de nouveaux rituels sera l'une clé de votre transformation culturelle réussie (avec les rôles et le programme)." }, { "type": "paragraph", "text": "À vous PMO, DSI,….de vous accorder avec vos équipes concernées pour « <strong>dessiner</strong> » <strong>et nommer ce nouveau flux</strong> de travail particulier qui embarquera vos nouveaux rituels de gouvernance et facilitera la transformation de votre entreprise." }, { "type": "paragraph", "text": "<strong>L'enjeu sous-jacent est bien de développer de nouvelles habitudes de décisions, communication et coopération</strong>, de la journée à l'année !" }, { "type": "paragraph", "text": "Ce qui compte ensuite, c'est la <strong>régularité</strong>. De <strong>donner et tenir le rythme de ces routines.</strong>" }, { "type": "paragraph", "text": "À titre d'illustration, nous vous proposons ci-dessous une série de pratiques de management, mise en place dans un contexte particulier à une organisation." }, { "type": "heading", "level": 3, "id": "exemple-de-rituels-en-project-portfolio-management", "text": "Exemple de rituels en Project Portfolio Management" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63752154f2da816c5281eb98_Examen%20du%20portefeuille%20strate%CC%81gique%20Synchronisation%20du%20portefeuille%20Budge%CC%81tisation%20participative.jpg", "alt": "Lean PPM - vue rituels annuels", "caption": "Exemple 1 : rituels de lean PPM annuel" }, { "type": "heading", "level": 4, "id": "la-map-meteo-avancement-projet", "text": "La M.A.P. —> Météo Avancement Projet" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6247101b95f4a4562cfa3fd0_27379b47-3c96-4060-b561-4b071f5ad3db.png", "alt": "Météo avancement projet" }, { "type": "list", "ordered": false, "items": ["Rythme <strong>hebdo</strong> ou tous les 15 jours en fonction des Copils projets"] }, { "type": "list", "ordered": false, "items": ["1 CDP IT avec métier"] }, { "type": "list", "ordered": false, "items": ["Revue du projet avec la présentation copil de AirSaas —> ce qui permet un management visuel interactif facilitant la coopération entre les parties prenantes. Fixer un jour (mardi 9h) pour ce rituel ou tous projets seront à jour : décision / point d'attention, jalon) ⟶ Avec les métiers"] }, { "type": "list", "ordered": false, "items": ["Rituel lors des mises à jour des avancées —> systématiquement chercher et poster un point de succès."] }, { "type": "heading", "level": 4, "id": "la-rsp-revue-synchro-portfolio", "text": "La R.S.P. —> Revue Synchro Portfolio" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/641fede013b8de305da47f2c_ppm-statut-min.png", "alt": "PPM - Timeline portefeuille projet", "caption": "Vue timeline AirSaas" }, { "type": "list", "ordered": false, "items": ["Rituel de gouvernance interne à la DSI avec PMO / CDP", "Flash report envoyé avant", "On fait le tour directement dans AirSaas des points de vigilance, succès et décisions à prendre sur les projets"] }, { "type": "heading", "level": 4, "id": "la-pod-prio-or-die", "text": "La P.O.D —> Prio or die :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/641febb7fa824343e880ec18_flash-report-min.png", "alt": "Flash report PPM", "caption": "Le rapport flash ou la vue aérienne des projets" }, { "type": "list", "ordered": false, "items": ["Tous les trimestres un Copil orienté revue de portefeuille stratégique, de 2h est fait pour évaluer.", "Niveau CODIR, intégrant les directions métiers.", "Objectifs : Requestionner l'état des ressources et des priorités. En profiter pour récupérer des insight via le métier. Faire le retour d'expérience des projets exécutés. Le bilan budgétaire. Une re-priorisation de la roadmap", "Le rituel est <strong>géré avec l'appui de la plateforme</strong>. (Sur la base du COPIL view d'AirSaas par exemple) Tout ce qui n'est pas à jour dans AirSaas ne peut pas passer en comité POD."] }, { "type": "heading", "level": 4, "id": "le-fdm-flash-design-metier", "text": "Le F.D.M. —> Flash Design métier" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/641ff3f93614ae981da8c55e_FD-min.jpg", "alt": "Cadrage métier Flash design", "caption": "Bonne pratique de la DSI de Ouigo via Podcast CIO Révolution by AirSaas" }, { "type": "list", "ordered": false, "items": ["Toutes les semaines 2h de flash design pour bosser avec les métiers sur les insights / problèmes remontés.", "Plutôt que de commencer à réfléchir au cadrage d'un besoin métier quand on a le temps de le traiter, on organise <strong>des sessions flash design de 2h dès que le métier émet son \"ticket\". 2h de brainstorming réunissant le métier et l'IT pour dégrossir le besoin</strong>, étudier les solutions Saas \"miracles\" qui pourraient y répondre et finalement se laisser du temps pour mûrir le besoin. Tout ça intervenant bien en amont de la phase de cadrage."] }, { "type": "heading", "level": 4, "id": "le-fra-flash-report-automatise", "text": "Le F.R.A. —> Flash Report automatisé" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/641fef21ce466642859184c2_alerte-min.png", "alt": "Flash report automatisé PPM" }, { "type": "list", "ordered": false, "items": ["La newsletter automatisée de vos projets", "<strong>Rituel automatisé</strong> <strong>—></strong> via l'envoi de notifications d'AirSaas <strong>—></strong> toutes les semaines le vendredi soir 19 h vous recevez une synthèse (État d'avancée / Météo des projets contextualisée, Point d'attention, décision urgente et importante de la semaine prochaine)."] }, { "type": "heading", "level": 4, "id": "le-qtc-quarter-transfo-celebration", "text": "Le Q.T.C. —> Quarter Transfo célébration !" }, { "type": "list", "ordered": false, "items": ["À chaque fin de quarter : invitation des chefs de projets à un repas. !", "Utiliser chaque jalon projet comme un point succès sur lequel communiquer. De plus, cela <strong>contribuera à passer des messages de rappels sur ce que vous faites. Car oui il y a beaucoup (trop !) de sujets en concurrence dans le portefeuille</strong>"] }, { "type": "paragraph", "text": "Pour créer vos propres rituels et réussir à ancrer ces nouveaux comportements, faites vous aider par une plateforme !" }, { "type": "paragraph", "text": "Bye bye Email, Excel ! L'assistance au pilotage de portefeuille est à votre portée : <a href=\"/gestion-de-projet/portfolio-management-pourquoi-il-faut-en-finir-avec-excel\">Portfolio management : Pourquoi il faut en finir avec excel !</a>" }, { "type": "heading", "level": 2, "id": "5-definissez-ce-qui-est-vital-puis-lordre-dexecution", "text": "5. Définissez ce qui est vital ! Puis l'ordre d'exécution" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63989258ea3259ccbaffddb1_123-airsaas-min.jpg", "alt": "Classement des projets dans le portefeuille", "caption": "Projet type 1, 2 ou 3 de votre PPM ?" }, { "type": "paragraph", "text": "Une fois le sens, les responsabilités et rituels clarifiés... il restera à <strong>s'accorder sur l'ordre</strong> des choses... À <strong>prendre le temps de vous accorder pour définir ce qui est vital</strong> (et ce qui ne l'est pas). Même si ça vous prend des mois à faire avancer cette notion avec tous les membres du codir ça vaut la peine d'investir votre énergie et d'être pédagogue ! De toute façon, d'une façon générale, rien qu'avec les projets vitaux les capacités de travail des équipes sont déjà surchargées !" }, { "type": "heading", "level": 3, "id": "ordonnez-les-projets-vitaux-par-ordre-dexecution", "text": "Ordonnez les projets vitaux par ordre d'exécution" }, { "type": "paragraph", "text": "La hiérarchisation des projets - en les désignant comme ayant une <strong>importance élevée, moyenne ou faible</strong> - est une pratique courante au sein des organisations. Cependant, Alan Zucker, directeur fondateur de Project Management Essentials, nous rappelle avec humour que la direction a tendance à classer la plupart (voire tous) les projets comme hautement prioritaires. \"<em>Ce type de système à lui seul ne permet pas d'allouer de manière appropriée les ressources financières et humaines rares.</em>\"" }, { "type": "paragraph", "text": "Il recommande une étape supplémentaire de <em>classement ordinal</em>, dans laquelle <strong>les chantiers sont répertoriés dans l'ordre de leur exécution</strong> : premier, deuxième, troisième, etc. \"Cela <strong>oblige les dirigeants à réfléchir à des compromis</strong> et <strong>à prendre des décisions difficiles</strong> sur les projets (vraiment) les plus importants pour l'organisation.\"" }, { "type": "heading", "level": 3, "id": "evitez-le-favoritisme", "text": "Évitez le favoritisme" }, { "type": "paragraph", "text": "Vous connaissez le <strong>syndrome du HIPPO ? Acronyme anglais signifiant Highest Paid Person's Opinion.</strong> Autrement dit les opinions de la personne la plus hautement placée hiérarchiquement dans les membres du comité ont une tendance naturelle à être retenues." }, { "type": "paragraph", "text": "Une des <strong>astuces basiques</strong> pour tenter d'éviter ce biais en project portfolio management peut consister à demander au chef présent au comité de pilotage de parler en dernier à chaque tour de table..." }, { "type": "paragraph", "text": "De nombreux gestionnaires de portefeuilles de projets tombent en effet souvent dans le piège de favoriser certains sujets, ce qui peut fausser la réussite perçue de votre project portfolio management. Ces travaux sont généralement ceux dans lesquels le manager s'investit personnellement, et, hasard incroyable, le manager leur accordera probablement plus de temps et d'attention." }, { "type": "paragraph", "text": "Le résultat : les projets favorisés sont moins susceptibles de rencontrer des problèmes ou de souffrir de négligence. Cependant, être trop myope à propos des thèmes favorisés peut entraîner la souffrance d'autres projets du portefeuille et faire face à des défis qui, autrement, pourraient être évités s'ils recevaient la même attention." }, { "type": "heading", "level": 2, "id": "6-rendez-bien-visible-tous-les-projets-du-portefeuille", "text": "6. Rendez bien visible tous les projets du portefeuille" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/640f2b7109e63c264f8dd0e4_visible-min2.jpg", "alt": "Visibilité des projets dans le PPM", "caption": "La portée du portefeuille projets ne se limite pas au grands projets !" }, { "type": "paragraph", "text": "Pourquoi ajouter ce projet au portefeuille alors qu'il est à 10 jours et que tout se passe bien ? On entend encore trop souvent les DSI/PMO et chefs de projets dire ça." }, { "type": "paragraph", "text": "Au total, <strong>le volume de jours hommes cumulé de ces petits projets invisibles</strong>, sorte de shadow project management, est sans doute <strong>égal ou supérieur à celui des projets dits moyens!</strong>" }, { "type": "paragraph", "text": "L'idée derrière est de valoriser ce qui fonctionne. De valoriser les trains qui arrivent à l'heure. Les pilotes qui savent faire vs ceux qui font savoir." }, { "type": "heading", "level": 3, "id": "less-is-more", "text": "Less is more" }, { "type": "paragraph", "text": "Autre rappel de bon sens : <strong>Travailler sur de nombreux projets hautement prioritaires en même temps peut entraîner des problèmes importants</strong> en project portfolio management et en particulier : l'inefficacité !" }, { "type": "paragraph", "text": "Cela signifie que <strong>vous ne pouvez pas terminer ce que vous n'avez pas commencé</strong> et que vous ne <strong>devriez jamais commencer ce que vous ne vous êtes pas engagé à terminer.</strong> CQFD !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe196ae6d77cf7b76d613b_less%20is%20more-min.jpeg", "alt": "Less is more PPM", "caption": "Le tableau préféré des PMO" }, { "type": "paragraph", "text": "De nombreuses organisations se concentrent en effet davantage sur « faire décoller des avions » que sur leur atterrissage », explique Alan Zucker, directeur du Project Management Essentials (encore lui). En d'autres termes, ils se concentrent sur le démarrage des projets mais ne prêtent pas autant d'attention à leur suivi, jusqu'à leur achèvement." }, { "type": "paragraph", "text": "Plutôt que de démarrer un grand nombre de projets qui pourraient ne pas atteindre la ligne d'arrivée, Zucker note que <strong>se concentrer sur l'achèvement se traduit par de meilleurs résultats pour l'organisation</strong>. \"Minimiser le nombre de projets simultanés permettra d'accélérer le travail, ce qui signifie que vous pourrez <strong>voir plus rapidement la valeur générée par ces projets</strong>.\"" }, { "type": "paragraph", "text": "<strong>Mieux décider de \"faire les bons projets\"</strong>...voici la promesse de cette catégorie d'outils et de pratiques en project portfolio management ! Oui, on entre ici en pleine subjectivité ! C'est pour cela que nous vous proposons de prendre connaissance de l'article : <a href=\"/gestion-de-projet/gestion-de-portefeuille-projets-comment-selectionner-les-bons-projets\" target=\"_blank\">Gestion de portefeuille de projets : Comment sélectionner les bons projets ?</a>" }, { "type": "heading", "level": 2, "id": "7-nattendez-pas-detre-mature-en-gestion-de-projet-pour-moderniser-votre-gouvernance", "text": "7. N'attendez pas d'être \"mature\" en gestion de projet pour moderniser votre gouvernance !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe1cbafaef315fb7189929_innovation%20ppm-min.jpg", "alt": "Innovation Source image : Fx Dessinateur", "caption": "L'art de l'innovation en gouvernance de projet (Source dessin : FX Dessinateur)" }, { "type": "paragraph", "text": "Vous avez modernisé votre gestion de projet...c'est un super début ! Remontez maintenant d'un niveau pour améliorer la gouvernance de vos programmes de transformation." }, { "type": "paragraph", "text": "Centralisation des données, décisions, cadrage et suivi de l'exécution, les outils peuvent vous assister dans le pilotage du portefeuille projet. Avec une plateforme de project portfolio management comme AirSaas au sein de votre entreprise vous disposerez de cinq bénéfices :" }, { "type": "list", "ordered": true, "items": ["<strong>Cadrages projets collaboratifs</strong> et uniformes", "<strong>Reporting</strong> décisionnels <strong>automatiques</strong>", "<strong>Focalisation</strong> sur la <strong>prise de décision</strong>, les points d'attentions", "<strong>Pilotage</strong> par les <strong>jalons</strong>", "<strong>Bilan projet</strong> dans une seule plateforme."] }, { "type": "paragraph", "text": "Pour \"déboulonner\" les préjugés sur les seuils de maturité nécessaires pour aborder les démarches de gestion de portefeuille projet, nous vous proposons de découvrir :" }, { "type": "paragraph", "text": "👉 Les cinq niveaux de maturité en gestion de projet pour une entreprise. Du niveau de base à 🥋l'avantage concurrentiel." }, { "type": "paragraph", "text": "👉 Les 7 arguments contre/pour mettre en place une démarche de portefeuilles de projets dans une organisation pas assez \"mature\" en gestion de projets.<br>🚨 Spoiler : n'attendez pas que votre entreprise soit \"mature\" en gestion de projet pour lancer une démarche de gestion de portefeuille, sinon elle ne le sera jamais !<br><br>👉 En prime, on a demandé à une PMO membre de la communauté Pro de la Transfo. son retour d'expérience sur la mise en œuvre de la fonction Bureau des projets dans une structure à faible maturité projet. (Merci 🫶 Constance)💡 <br><em>\" À la manière d'un sachet de thé dans de l'eau chaude, vous infusez progressivement dans l'entreprise la culture projet, de la gestion de projet au PPM, vers l'excellence opérationnelle.\"</em>" }, { "type": "paragraph", "text": "Pour approfondir ces trois points, je découvre l'article <a href=\"/gestion-de-projet/le-portefeuille-projets-pour-faire-grandir-les-collaborateurs-et-lorganisation\">: Le portefeuille projets pour faire grandir les collaborateurs et l'organisation</a>" }, { "type": "heading", "level": 2, "id": "8-le-changement-cest-maintenant-ou-pas", "text": "8. Le changement c'est maintenant, ou pas !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/642037521efce649da6416f1_visual%20management%20(1)-min.jpg", "alt": "Diffusion culture projet et best practice de gouvernance sans effort", "caption": "Investissez dans l'accompagnement !" }, { "type": "paragraph", "text": "Un outil de project portfolio management aussi simple soit il nécessite un <strong>minimum d'accompagnement dans l'animation</strong> de la démarche. C'est bien sûr en partie le rôle du management de partager le sens, les attendus, les limites et la portée des outils. Ceci étant en vous appuyant sur des ressources type PMO/Facilitateur/ project portfolio manager ayant déjà mené ce type de missions vous <strong>mettrez vraiment plus de chances de votre côté.</strong>" }, { "type": "paragraph", "text": "Investissez dans l'accompagnement <strong>pour que vos collaborateurs gagnent en confiance</strong> et <strong>déjouent d'emblée les pièges</strong> classiques d'une <strong>démarche PPM/program management.</strong>" }, { "type": "paragraph", "text": "Plus vos collaborateurs seront sensibilisés à cette démarche, plus vous allez bénéficier de votre PPM." }, { "type": "paragraph", "text": "De la même manière que pour un projet métier…vous devez prendre en compte l'implémentation de la solution PPM dans sa globalité. Idéation, cadrage, exécution, transfert, rôles, rituels, conduite du changement…AirSaas est un outil métier pour la transformation !" }, { "type": "paragraph", "text": "En résumé, assurez-vous que les collaborateurs comprennent bien les tenants et aboutissants de la démarche au-delà de l'outil. Pour cela, pas de secrets, il faut communiquer, former, coacher, accompagner." }, { "type": "paragraph", "text": "Si vous n'avez pas envie de prendre le temps de vous faire accompagner, une solution « bis » sera de faire monter en compétences des facilitateurs internes. De les sensibiliser à cette culture grâce aux contenus et échanges au sein de communautés de pratiques. On ne saurait que trop vous recommander la nôtre :) Le <strong>club Pro de la Transfo.</strong> Cela peut vous être d'une aide précieuse pour conduire votre transformation !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63944acd39cc5c1a9ad2ebfe_e1580ee7-7ef1-4543-97cb-f8887a9ed704.png", "alt": "Pro de la transfo.", "href": "https://www.airsaas.io/fr/lesprodelatransfo" }, { "type": "paragraph", "text": "Pour découvrir le club \"Les Pro. de La Transfo\", ça se passe ici : <a href=\"https://www.airsaas.io/fr/lesprodelatransfo\" target=\"_blank\">lesprodelatransfo</a>" }, { "type": "heading", "level": 2, "id": "9-cultivez-la-transparence-pour-permettre-a-chacun-de-sinformer-efficacement-sur-le-portefeuille-projet", "text": "9. Cultivez la transparence pour permettre à chacun de s'informer (efficacement) sur le portefeuille projet" }, { "type": "paragraph", "text": "Efficacement signifie ici en continu...sans attendre un CODIR / COPIL / COPROJ...et surtout...se baser sur des données fiables. Pas \"maquillées\" dans un reporting powerpoint. Des données authentiques donc. Car rappelons-le : « <strong>Sans transparence, pas d'engagement.</strong> »" }, { "type": "paragraph", "text": "Même si, rassurez-vous, c'est toujours le rôle des pilotes tech. &amp; Métier de contribuer activement à la saisie des infos clés de compte rendu, etc." }, { "type": "paragraph", "text": "Néanmoins, nous sommes passés à l'ère de la coopération. Faciliter l'accès du sponsor, des métiers et/ou directions générales aux infos clés sur les jalons et décisions est un acte de transparence très fort et indispensable. Cela constitue un <strong>levier d'alignement et d'engagement.</strong>" }, { "type": "paragraph", "text": "Sylvain Bourdette, DSI de Proxiserve et utilisateur d'AirSaas nous le confiait :" }, { "type": "quote", "text": "Il est essentiel que les directions métiers puissent savoir où trouver l'information sur le suivi des demandes. De savoir qu'elles sont à leur disposition peut contribuer au renforcement du lien de confiance. Et ce, peu importe qu'elles aillent le voir ou pas. Ils savent qu'en cas de besoin…l'info est là !", "author": "Sylvain Bourdette, DSI Proxiserve - Invité de Bertran Ruiz CEO AirSaas - Podcast CIO Révolution" }, { "type": "paragraph", "text": "Sur cette accessibilité nouvelle des données de reporting, attention. Face au volume croissant d'information on est vite dans le <strong>syndrome du sapin de noël</strong> du portfolio. Dans un reporting surchargé, joli mais peu efficace pour décider !" }, { "type": "paragraph", "text": "Dans AirSaas, avec les smart view vous avez la possibilité de <strong>personnaliser la vue projet</strong> pour montrer exactement ce que vous souhaitez voir en un clin d'œil. De faire \"tourner le cube\"." }, { "type": "paragraph", "text": "Le portefeuille projet ayant 1000 facettes, AirSaas permet de créer des vues publiques ou privées adaptées au contexte et à l'audience : quickwins marketing, projet en retard, RH, priorisation par programme…" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/639892f9eb9c8923f9ef79bf_view-rubiks-min.jpg", "alt": "Les vues AirSaas pour faire \"tourner le cube\" et présenter un angle du portefeuille en fonction du contexte et de l'audience cible", "caption": "Les vues AirSaas pour faire \"tourner le cube\" et présenter un angle du portefeuille en fonction du contexte et de l'audience cible" }, { "type": "paragraph", "text": "L'important c'est de proposer non pas une vue du portefeuille, mais un nombre de vues et donc de <strong>critère de choix de priorisation quasi illimité</strong> ! En <strong>permettant à chaque audience de voir ce dont elle a (vraiment) besoin dans le portfolio.</strong>" }, { "type": "paragraph", "text": "Par exemple une vue Kanban des décisions à prendre. Une vue liste des chantiers des équipes dont la météo est dans un statut « compliqué » et sur des projets d'une certaine taille…" }, { "type": "paragraph", "text": "La seule limite, c'est votre besoin. ;-)" }, { "type": "paragraph", "text": "Découvrez un exemple de Copil View AirSaas ci-dessous :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe1a3d9220c849c59202f3_copil%20view-min.png", "alt": "Capture d'écran AirSaas -Smart views", "caption": "Capture d'écran AirSaas -Smart views" }, { "type": "paragraph", "text": "Pour finir sur cette 9e bonne pratique sur 10, rappelons-le, tous les outils ne se valent pas ! Ils sont <strong>plus ou moins simples</strong>, gage d'une <strong>adoption potentielle plus large. Ils sont plus ou moins innovants</strong>, gage d'un meilleur gain de temps potentiel." }, { "type": "paragraph", "text": "Pour découvrir ce qui se profile dans les nouveaux usages du portfolio management moderne découvrez cet article consacré à ces questions : <a href=\"https://www.airsaas.io/fr/solution/outil-ppm\">AirSaas : un outil PPM nouvelle génération.</a>" }, { "type": "heading", "level": 2, "id": "10-renforcez-durablement-la-culture-de-transformation-dans-votre-organisation", "text": "10. Renforcez (durablement) la culture de transformation dans votre organisation" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe1a628bb934026b9b149f_transfo%20iceberg-min.png", "alt": "Iceberg transformation modèle", "caption": "Iceberg transformation model inspiré du iceberg model of corporate culture by Edward Twitchell Hall (1989)." }, { "type": "paragraph", "text": "La démarche de PPM pragmatique implique un <strong>état d'esprit</strong> nouveau. On <strong>\"switche\" entre ancienne et nouvelle approches</strong> : Command &amp; Contrôle VS confiance &amp; engagement !" }, { "type": "heading", "level": 3, "id": "obtenir-lengagement-du-management-et-des-collaborateurs-sur-la-duree", "text": "Obtenir l'engagement du management et des collaborateurs sur la durée" }, { "type": "paragraph", "text": "La gestion actuelle majoritaire de portefeuille focalise trop souvent sur le côté rationnel du processus. Gestion des tâches, aspects techniques, budgétaires, processus, objectifs.... <strong>Dans un contexte de grande démission et de discontinuité des équipes</strong>...le <strong>renforcement de la culture</strong> de votre organisation est un des <strong>fondements de la réussite</strong> de votre transformation avec le lean portfolio management !" }, { "type": "paragraph", "text": "La clé = <strong>Les enjeux d'alignement, de comportement, d'engagement de leadership</strong> sont à <strong>activer</strong>, et à <strong>cultiver</strong>." }, { "type": "paragraph", "text": "Concernant la <strong>définition de la culture</strong>...on partage ici une citation entendue en conférence agile et dont l'auteur est inconnu. <em>\"La culture c'est ce que l'on fait quand personne nous dit quoi faire\".</em> \"C'est <em>\"</em>ce qui est commun à un groupe d'individus, ce qui le soude<em>\"</em>." }, { "type": "heading", "level": 3, "id": "une-approche-du-portfolio-fondee-sur-des-principes", "text": "Une approche du portfolio fondée sur des principes" }, { "type": "paragraph", "text": "Tout changement qui se limiterait à faire un effort sur une attitude et un comportement s'avère souvent contreproductif. Pour plus d'efficacité, le focus doit être porté sur les perceptions et croyances plus profondes. En allant rechercher les croyances \"cachées\", le non-dits." }, { "type": "paragraph", "text": "Et attention à la <strong>confusion entre principes et valeurs</strong>. Les principes ne sont pas, non plus, des valeurs. Les membres d'une mafia pourraient partager des valeurs d'amitié, de compassion et de respect, mais en violation des principes les plus humainement reconnus comme fondements de la morale et l'éthique." }, { "type": "paragraph", "text": "Exposez vos <strong>grands principes d'actions</strong>. Trois minimums, sept maximums ! En voici quelques-uns qui peuvent vous inspirer." }, { "type": "paragraph", "text": "La sincérité, l'empathie et la confiance, l'auto-organisation, la transparence, la coopération gagnant + gagnant par exemple. À vous de composer votre mix de principes qui sonnera juste dans votre contexte. Un \"mindset\" authentique et original est primordial pour réussir à copiloter votre portfolio !" }, { "type": "paragraph", "text": "Un dernier point, sur la portée de la gestion de portefeuille de projets dans les entreprises. Ce <strong>n'est surtout pas un processus réservé aux ETI et grands comptes !</strong> Au contraire, c'est là ou le manque de ressources en pilotage et PMO est le plus critique qu'une plateforme type PMO as a service peut faire toute la différence. Comment commencer simplement ? Retrouvez des retours d'expériences et conseils clés dans notre publication suivante : <a href=\"/gestion-de-projet/pourquoi-developper-une-gestion-de-portefeuille-projets-dans-une-pme\" target=\"_blank\">Pourquoi développer une gestion de portefeuille projets dans une PME ?</a>" }], "faq": [], "related": [], "toc": [] }, { "slug": "reporting-pmo", "skip": false, "meta": { "title": "Tout savoir sur le reporting PMO", "h1": "Tout savoir sur le reporting PMO", "description": "La question du reporting PMO n'est pas à prendre à la légère : partager une compréhension commune de l'état de santé et des enjeux du portefeuille projet avec l'ensemble des parties prenantes peut changer la dynamique d'une organisation !", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/658087d8f4d5e6bdb6f54cb4_Reporting%20PMO-min.jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "30/11/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "30/11/2023" }, "blocks": [{ "type": "paragraph", "html": "La question du reporting <a href=\"/fr/gestion-de-projet/metier-pmo\">PMO</a> n'est pas à prendre à la légère : partager une compréhension commune de l'état de santé et des enjeux du portefeuille projet avec l'ensemble des parties prenantes peut changer la dynamique d'une organisation ! L'importance des tableaux de bord projets et indicateurs de performance au sein des organisations n'est plus à démontrer." }, { "type": "paragraph", "html": "Problème : dans le management de projet, la perception <strong>du reporting est parfois vue comme négative</strong> par les chefs de projets et PMO !" }, { "type": "paragraph", "html": "Et vous, vous le voyez plus comme un outil choisi d'aide à la décision ou bien comme un instrument de contrôle managérial \"subi\" ?" }, { "type": "paragraph", "html": "Si vous pensez que cet outil de communication et les démarches qui lui sont associées sont parfois mal comprises, vous êtes au bon endroit pour <strong>mieux comprendre l'intérêt, repérer les meilleures pratiques en PPM</strong> et tout simplement améliorer votre usage actuel du reporting." }, { "type": "paragraph", "html": "Après une définition (toujours utile !), cet article traitera du rôle des données dans la prise de décision, raison d'être, usages, pièges à éviter, process et façon de faire des PMO, rythme, personnes concernées et parties prenantes.... Tout pour relever les grands défis liés à la mise en œuvre de cette pratique et réussir vos pilotages de portefeuilles." }, { "type": "heading", "level": 2, "id": "quest-ce-quun-reporting-projet-et-pourquoi-est-ce-important-de-bien-le-faire", "text": "Qu'est-ce qu'un reporting projet, et pourquoi est-ce important de (bien) le faire ?" }, { "type": "heading", "level": 3, "id": "definition-du-reporting-projet", "text": "Définition du reporting projet" }, { "type": "paragraph", "html": "Notre <a href=\"https://fr.wikipedia.org/wiki/Communication_de_donn%C3%A9es\" target=\"_blank\">encyclopédie en ligne préférée</a> le rappelle : \"La <strong>communication de données</strong> (en anglais reporting) est l'action consistant à faire un rapport de ses activités.\"" }, { "type": "paragraph", "html": "Outil de communication, le reporting permet essentiellement de matérialiser des données de votre portefeuille de projets. Il fait partie des outils de gestion clés du PMO." }, { "type": "paragraph", "html": "Et en prime, un reporting PMO efficace = <strong>la clé du leadership en </strong><a href=\"http://www.airsaas.io/fr/gestion-de-projet/role-du-pmo\" target=\"_blank\"><strong>Codir</strong></a><strong>.</strong>" }, { "type": "heading", "level": 3, "id": "exemple-de-flash-report-airsaas", "text": "Exemple de flash Report AirSaas" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f1a76cf5f64ee9e5d9c_37215105-a478-40b4-ada5-66c78ace95dc.png", "alt": "Exemple de flash Report AirSaas" }, { "type": "heading", "level": 3, "id": "un-reporting-pmo-pour-quoi-faire", "text": "Un reporting PMO : pour quoi faire ?" }, { "type": "paragraph", "html": "Ce rappel est fondamental. Le reporting a deux fonctions principales :" }, { "type": "list", "ordered": true, "items": ["être analysé afin <strong>d'orienter les décisions stratégiques ;</strong>", "<strong>guider les managers</strong> et leurs équipes vers l'atteinte des objectifs préalablement fixés."] }, { "type": "paragraph", "html": "Les rapports sont vitaux pour toutes les organisations, ils nous permettent de transmettre des informations, d'identifier un problème et d'aider à élaborer des prévisions futures." }, { "type": "paragraph", "html": "Surtout dans un contexte d'explosion du nombre de projets transverses et de projets de transformations !" }, { "type": "paragraph", "html": "En s'appuyant sur des indicateurs de pilotage opérationnel de la performance (appelés aussi KPIs pour Key Performance Indicators), on peut mesurer et piloter la trajectoire d'un \"chantier\" de manière efficace, ou à l'inverse se rendre compte de certains points de blocage." }, { "type": "paragraph", "html": "Un bon reporting PMO doit permettre à chacun de <strong>discerner rapidement l'état actuel de l'environnement de</strong> chaque projet du portfolio.&nbsp;Les décideurs en particulier doivent voir à première vue ce qui doit être décidé. Cela parait tomber sous le sens...mais on peut vite se prendre les pieds dans le tapis de l'excès d'information mal présentés qui plus est." }, { "type": "paragraph", "html": "Car le reporting est <strong>avant tout un outil d'aide à la décision</strong> vs un outil de contrôle comme on le pense souvent. Il doit <strong>amener les parties prenantes à se poser des questions</strong> : \"Quelle suite à donner au projet?\" ; \"De quelles compétences avons-nous besoin&nbsp;?\", &nbsp;\"Pourquoi avons-nous pris du retard sur le planning de ce point précis ?\". \"Pourquoi le rythme de delivery est-il en train de baisser&nbsp;?" }, { "type": "heading", "level": 2, "id": "comment-reussir-votre-reporting-pmo", "text": "Comment réussir votre reporting PMO ?" }, { "type": "heading", "level": 3, "id": "les-7-questions-initiales-a-vous-poser", "text": "Les 7 questions initiales à vous poser" }, { "type": "heading", "level": 4, "id": "question-1-quel-est-mon-objectif-avec-ces-rapports", "text": "Question 1 : Quel est mon objectif avec ces rapports ?" }, { "type": "paragraph", "html": "Qu'est-ce que je veux suivre et contrôler ? Dans tous les cas, un reporting de projet a pour finalité l'action, la planification des tâches et la prise de décision. Pour ce faire, les meilleurs reporting de projets ont tous un point en commun, ils permettent au lecteur de visualiser l'information en un clin d'œil pour que chacun à son niveau dans l'entreprise puisse faire les bons choix." }, { "type": "paragraph", "html": "Le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/etre-pmo-en-2023-les-mutations-dun-metier\" target=\"_blank\">PMO</a> doit garantir la qualité des reportings en s'assurant que les données sont à jour et qu'elles sont correctes et fiables." }, { "type": "heading", "level": 4, "id": "question-2-qui-va-etre-amene-a-prendre-une-decision-avec-ces-reportings", "text": "Question 2 : Qui va être amené à prendre une décision avec ces reportings ?" }, { "type": "paragraph", "html": "Vos rapports sont destinés à être lus ! Cartographier les lecteurs est un investissement utile. Il y aura en effet X formats cibles, X vues du portefeuille différentes." }, { "type": "paragraph", "html": "Cette seconde question implique d'<strong>identifier les niveaux de confidentialité</strong> : diffusion restreinte, élargie ou tout public." }, { "type": "heading", "level": 4, "id": "question-3-les-futurs-lecteurs-ont-il-ete-associes-a-la-construction-du-reporting", "text": "Question 3 : Les futurs lecteurs ont il été associés à la construction du reporting ?" }, { "type": "paragraph", "html": "Pour eux, ce reporting est il vu comme un flicage du management ou bien un outil d'aide au pilotage ?" }, { "type": "paragraph", "html": "Leur a-t-on demandé après le premier reporting s'ils étaient satisfaits du format, du rythme, de la visibilité ?" }, { "type": "paragraph", "html": "Pourront-ils interagir, éditer ou commenter le contenu ?" }, { "type": "heading", "level": 4, "id": "question-4-de-quelles-donnees-ai-je-besoin-pour-cela", "text": "Question 4 : De quelles données ai-je besoin pour cela ?" }, { "type": "paragraph", "html": "En fonction de vos grands personas, de vos lecteurs vous aurez autant de niveaux de lecture de rythmes de reporting potentiels. En exemple voici un : Contenu type de reporting pour C Level" }, { "type": "list", "ordered": false, "items": ["Backlog", "Risques", "Ressources", "Charges", "Décisions"] }, { "type": "paragraph", "html": "Plutôt que d'inventer l'eau chaude sur ce point, appuyez-vous sur les smart frameworks proposés par les outils avec des tableaux de bord de gestion de projet pré établis comme AirSaas." }, { "type": "paragraph", "html": "Autre point : la data c'est bien, mais le contexte avec, c'est quand même mieux !" }, { "type": "paragraph", "html": "Autre point clé sur la forme et le design d'information au delà d'une donnée brute : la compréhension du message passe aussi par la contextualisation - ajout de commentaire, légende... Derrière chaque changement de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-mettre-une-bonne-meteo-projet\" target=\"_blank\">météo du projet</a>, par exemple, on doit accéder facilement au détail." }, { "type": "heading", "level": 4, "id": "question-5-quel-niveau-de-detail-est-le-plus-adapte", "text": "Question 5 : Quel niveau de détail est le plus adapté ?" }, { "type": "paragraph", "html": "«&nbsp;Tout est poison, rien n'est poison, c'est la dose qui fait le poison » (Paracelse, médecin et alchimiste Russe)" }, { "type": "paragraph", "html": "Oui, à l'opposé des démarches data driven excessives, le reporting minimaliste a le vent en poupe." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f1968269ce9bf4901b7_18e9193e-101b-4763-9101-36d9a1f10280.png", "alt": "L'importance d'une bonne analyse ^^" }, { "type": "heading", "level": 3, "id": "quatre-exemples-de-vues-pour-votre-reporting", "text": "Quatre exemples de vues pour votre reporting" }, { "type": "paragraph", "html": "<em>\"La forme c'est le fond qui remonte à la surface\" - </em><strong><em>Victor Hugo.</em></strong>" }, { "type": "paragraph", "html": "L'importance du design n'est plus à démonter, autant pour faciliter la collecter que pour développer la compréhension." }, { "type": "paragraph", "html": "\"Si c'est plus compliqué qu'Instagram, on a perdu !\", confie Simon Vacher CPO d'AirSaas. En effet, l'outil doit être adopté par le chef de projet, le PMO, les métiers, les dirigeants..." }, { "type": "paragraph", "html": "Chez AirSaas nous proposons quatre types de vues." }, { "type": "heading", "level": 4, "id": "la-vue-tableau-ou-vue-spreadsheet", "text": "La vue tableau, ou vue Spreadsheet" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f19a66b827a9749fd42_08c18b94-1c56-4d7d-8909-b673cab25265.png", "alt": "Toutes les catégories sur une seule page !" }, { "type": "paragraph", "html": "Cette vue est utile pour:" }, { "type": "list", "ordered": false, "items": ["voir un maximum sur votre page courante", "agencer l'ordre des colonnes les unes par rapport aux autres", "classer l'ordre des projets manuellement en cliqué/déposé (drag and drop pour les english)", "choisir les colonnes que vous souhaitez afficher"] }, { "type": "heading", "level": 4, "id": "la-vue-timeline-pour-voir-la-repartition-dans-le-temps", "text": "La vue Timeline, pour voir la répartition dans le temps" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f196e3b38e1280f5cc6_4112c387-b2c0-4d25-8a40-a4d0b0c5a42d.png", "alt": "vue timeline" }, { "type": "paragraph", "html": "Bien plus qu'un simple diagramme de Gantt. La vue chronologique vous offrent une grande flexibilité pour définir l'étendue de vos projets, ajuster les échéances et personnaliser vos processus." }, { "type": "heading", "level": 4, "id": "la-vue-kanban-pour-montrer-un-passage-detapes", "text": "La vue Kanban, pour montrer un passage d'étapes" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f19268856cbb5a4a46d_6919a2e9-ef91-406e-882e-3c45150ecdda.png", "alt": "Management visuel" }, { "type": "paragraph", "html": "Utilisé dans ce contexte, le <a href=\"http://www.airsaas.io/fr/gestion-de-projet/kanban-gestion-de-projet\" target=\"_blank\">Kanban</a> de votre portfolio sert à vous faciliter une gestion visuelle des projets et de ses différentes phases." }, { "type": "heading", "level": 4, "id": "la-vue-liste", "text": "La vue liste" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f19787cfbf628969762_6fcd52f7-f56b-46d8-b108-fdfdad52795d.png", "alt": "Tout pour un suivi projets" }, { "type": "paragraph", "html": "Dans le contexte du portfolio la vue liste est utile pour faire un focus sur un ensemble d'éléments dans un groupe" }, { "type": "heading", "level": 2, "id": "9-criteres-cles-pour-un-reporting-pmo-efficace", "text": "9 critères-clés pour un reporting PMO efficace" }, { "type": "list", "ordered": true, "items": ["<strong>Semi-Automatisé</strong> avec des features de reporting projet automatisées.", "<strong>Vision</strong> <strong>adaptable</strong> du smartphone au grand écran.", "<strong>Donnée</strong> <strong>exportable</strong> (XLS, PPT..)", "<strong>Imprimable</strong> : parfois l'analyse est plus aisée avec le format papier", "<strong>Filtrable</strong>, triable : votre outil doit permettre de trier toutes vos données en fonction de vos audiences", "<strong>Agréable</strong> : non ce n'est pas le cas de tous les outils et oui c'est un détail clé pour l'adoption", "<strong>Authentique</strong> / <strong>Transparent</strong> : si les données sont maquillées, on n'ira pas loin !", "<strong>Synthétique</strong> et accès au détails contexte des saisies de données (c'est la clé)", "<strong>Un reporting moderne</strong> doit capter l'attention de son lecteur : pertinence, bonne présentation, standardisation de la mise en forme.. tout pour permettre d'en tirer des conclusions."] }, { "type": "heading", "level": 2, "id": "quand-quelle-frequence-adopter-quel-temps-de-production", "text": "Quand ? Quelle fréquence adopter ? Quel temps de production ?" }, { "type": "paragraph", "html": "Horaire, quotidienne, hebdo, mensuelle aucune réponse universelle à cette question n'existe... mais il y a des bonnes pratiques en fonction des types de projet de votre portfolio." }, { "type": "paragraph", "html": "Longtemps, la pratique des PMO au sein des entreprises a été de proposer un reporting mensuel au format PowerPoint." }, { "type": "paragraph", "html": "Problème : le reporting projet que vous recevez tous les deux mois ne permet de faire des arbitrages rapides et de lever les risques rapidement." }, { "type": "paragraph", "html": "Aujourd'hui retenez que les organisations qui \"sur-performent\" proposent un reporting \"on demand\". Sur les projets du chemin critique la fréquence hebdomadaire tend à s'imposer a minima." }, { "type": "paragraph", "html": "Les équipes qui utilisent AirSaas envoient le rapport flash aux différentes parties prenantes une fois par semaine. (Oui oui - pas une fois tous les mois...)" }, { "type": "paragraph", "html": "<em>\" La clé c'est de fournir de l'information pertinente et d'avoir les moyens de la faire vivre au fil de l'eau, car on n'a pas besoin d'attendre qu'un CODIR ou un Comité projet se réunisse pour communiquer sur ce qui se passe.\"</em> - Stéphan Boisson - Chief Digital &amp; Information Officer, Digital Whirl Catalyser chez SCC, Utilisateur AirSaas" }, { "type": "paragraph", "html": "Et comme chaque projet ne nécessite pas forcement une mise à jour à la semaine, voici notre conseil pour mettre en place un suivi encore plus fin : accordez-vous avec votre chef de projet sur une fréquence de mise à jour de la santé du projet grâce à l'option rappel de mise à jour depuis la page projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f195710cf5a1d6a38dc_91a5bfb9-3962-4038-8f31-75fd30e1d9c5.png", "alt": "Avec AirSaas votre organisation peut activer le rappel auto. des informations" }, { "type": "heading", "level": 3, "id": "quel-temps-de-production-du-rapport", "text": "Quel temps de production du rapport ?" }, { "type": "paragraph", "html": "Avant l'apparition d'un outil \"ad hoc\", la bureaucratie se glissait dans chaque tableau de bord !" }, { "type": "paragraph", "html": "Un DSI client témoignait du fait \"qu'un PMO externe lui prenait <strong>2 à 3 jours par mois</strong> pour consolider le fichier du portfolio Excel et rendre compte de l'état des lieux de l'exécution des projets dans un PowerPoint, au risque d'oublier les décisions importantes à prendre\"." }, { "type": "paragraph", "html": "Problème secondaire, pour le lecteur : l'outil impose une relecture versus une \"vue\" sur le delta sur ce qui a changé et nécéssite une attention et ou une décision." }, { "type": "paragraph", "html": "Avec&nbsp;AirSaas le reporting projet pour la direction se fait un en clic avec une synthèse de l'état d'avancement, les décisions à prendre, les risques et cela ne prendra pas plus de 5 minutes par semaine à vos chefs de projet de faire remonter ces informations." }, { "type": "paragraph", "html": "Pour le PMO auteur du reporting, comme pour ses destinataires, le temps est précieux." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/65681f19f098583e3a19fe36_a5c14d16-7a92-4a63-a51b-e428e477fa23.png", "alt": "Qualité vs temps passé à formaliser" }, { "type": "heading", "level": 2, "id": "ce-quil-faut-retenir", "text": "Ce qu'il faut retenir" }, { "type": "paragraph", "html": "\"On ne peut changer que ce que l'on voit\"." }, { "type": "paragraph", "html": "Vous l'avez compris il est fondamental de disposer d'un bureau de gestion de projets transverse, ou d'un PMO, axé sur le processus de reporting projets de (toute) l' entreprise versus une seule direction." }, { "type": "paragraph", "html": "L'impact des rapports données et indicateurs dans le process de décision est connu, en prime le fait de lui adjoindre des infos de contexte, (pourquoi la météo est en orange ?) est un puissant levier pour faciliter la prise de décision à partir de vos données." }, { "type": "paragraph", "html": "Au delà de toute les bonnes pratiques en création de rapports listées ici, on ne saurait que trop souligner l'importance d'une assistance au reporting pour limiter les erreurs. Utiliser une plateforme est aujourd'hui un \"must have\" au sein d'une organisation." }, { "type": "paragraph", "html": "Et n'oubliez pas un <strong>reporting PMO efficace = la clé du leadership en</strong> <strong>CODIR.</strong>" }, { "type": "paragraph", "html": "Si le reporting est essentiel au bon pilotage du projet, il ne faut <strong>jamais oublier qu'il y a des femmes et des hommes derrière.</strong> Et que nos reporting ne sont pas une excuse pour oublier le bon sens, l'humanité et l'importance du management." }, { "type": "paragraph", "html": "Vous êtes prêts pour creuser pleinement ce thème ? On vous conseille (vraiment) la lecture de cet article qui va zoome sur les \"howto\" : \"<a href=\"/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">Comment élaborer un reporting projet efficace ?</a>\"" }], "toc": [{ "label": "Qu'est-ce qu'un reporting projet, et pourquoi est-ce important de (bien) le faire ?", "href": "#quest-ce-quun-reporting-projet-et-pourquoi-est-ce-important-de-bien-le-faire", "level": 2 }, { "label": "Comment réussir votre reporting PMO ?", "href": "#comment-reussir-votre-reporting-pmo", "level": 2 }, { "label": "9 critères-clés pour un reporting PMO efficace", "href": "#9-criteres-cles-pour-un-reporting-pmo-efficace", "level": 2 }, { "label": "Quand ? Quelle fréquence adopter ? Quel temps de production ?", "href": "#quand-quelle-frequence-adopter-quel-temps-de-production", "level": 2 }, { "label": "Ce qu'il faut retenir", "href": "#ce-quil-faut-retenir", "level": 2 }], "faq": [], "related": [] }, { "slug": "retour-sur-agile-en-seine-2023", "skip": false, "meta": { "title": "Retour sur Agile en Seine 2023", "h1": "Retour sur Agile en Seine 2023", "description": "Retour sur Agile en Seine 2023 : keynotes, REX RATP, PMU, Renault, La Poste/Thiga et ENGIE. Sélection des meilleurs take away pour la communauté #Pro2latransfo.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da8943270feabd66ddd23_AES-min%20(1).jpg", "alt": "" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "22/9/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "22/9/2023" }, "blocks": [{ "type": "paragraph", "html": "Merci à toute l'équipe <a href=\"https://www.linkedin.com/company/agile-en-seine/\">Agile en Seine</a> pour l'organisation : Amina Bourguiba, Franck Beulé, Farida Mellouk, Arnault Etouman, Caroline Castillo, Soun Banh, Couthaïer Farfra, Chrystelle Cogneville, Alain Sallon, Janro Pons, Mélina Cowsy, Badr Zeroual et un merci spécial à 🙏 <a href=\"https://www.linkedin.com/in/ACoAAAUinb0ByhtaIDmkR6yoTsWv1lFPacEnu2s\">Couthaïer FARFRA 🙏</a> pour avoir rendu possible notre participation au nom des Pro de la Transfo / CIO Révolution." }, { "type": "paragraph", "html": "7e édition, 940 participants, 125 conférenciers !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/651151bbecd71a70965e1873_aes23-min.jpg", "alt": "Agile en seine", "caption": "Crédit photo Equipe orga AES" }, { "type": "paragraph", "html": "On y a beaucoup entendu parlé de business agility, Lean portfolio management, OKR, agilité à l'échelle, d'approche produit à l'échelle, des framework, de SaFe bien sûr... sur toutes les lèvres, en bien ou en mal… ^^<br>Bref des supers retours d'expériences pour les #Pro2latransfo." }, { "type": "paragraph", "html": "4 thématiques étaient au programme :<br><strong>• SCALE :</strong> autour de la transformation à l'échelle.<br><strong>• THINK :</strong> vers de nouvelles idées !<br><strong>• PRODUCT :</strong> pour continuer à faire vivre et évoluer l'essentiel.<br><strong>• BEYOND-IT :</strong> pour considérer les secteurs d'activités non IT où l'agilité s'invite." }, { "type": "paragraph", "html": "Voici notre sélection (forcément subjective) de \"take away\" des conférences auxquelles on a pu assister pour la communauté #Pro2latransfo d'AirSaas et le Podcast CIO Révolution." }, { "type": "heading", "level": 2, "id": "keynote-douverture-julia-de-funes-sur-le-theme-sens-et-responsabilite-en-temps-de-crise", "text": "Keynote d'ouverture Julia de Funès sur le thème \"sens et responsabilité en temps de crise\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da20862ecda20374eb461_JDF1-min%20(1).jpeg", "alt": "Julia de Funès sur le thème \"sens et responsabilité en temps de crise\"", "caption": "Julia de Funès #AES23 sur le thème \"sens et responsabilité en temps de crise\"" }, { "type": "paragraph", "html": "« Il y a un amalgame entre confiance et transparence, au contraire la confiance s'oppose à la transparence, registre de la connaissance »" }, { "type": "paragraph", "html": "« La confiance est rentable ! »" }, { "type": "paragraph", "html": "« Avoir une « Posture du manager » est une antidote au charisme »" }, { "type": "paragraph", "html": "« On est réhaussé par la confiance reçue »" }, { "type": "paragraph", "html": "« Process ? Le poison est dans la dose ! » « Attention au surdosage procédural »" }, { "type": "paragraph", "html": "« Les entreprises se sont engouffrées dans le bien-être avec des « gadgets bonheuristes bonbon, baby-foot, … mais ça ne fonctionne pas ! »" }, { "type": "paragraph", "html": "« La bienveillance : il n'y a rien de plus violent que de ne pas se confronter avec les autres (à ne pas confondre avec le conflit) »." }, { "type": "paragraph", "html": "« Le travail n'est pas une finalité, mais un moyen, car c'est toujours autre chose qui justifie le travail. Tout ce qui a un prix n'est pas une valeur morale. »" }, { "type": "paragraph", "html": "« La peur est signe désormais de maturité »" }, { "type": "paragraph", "html": "« Posture/impostures du manager » = antidote au charisme »" }, { "type": "paragraph", "html": "« Leadership est une histoire d'authenticité plus que de technique »" }, { "type": "paragraph", "html": "« La valeur clé c'est le courage »" }, { "type": "paragraph", "html": "« Il est important d'avoir un bon équilibrage des processus. Il faut bien sûr des processus mais il faut éviter le surdosage et de mettre en œuvre des processus dans des domaines où ils n'apportent pas de valeur (par exemple le bien être procéduré ?). »" }, { "type": "paragraph", "html": "« Parfois il faut aussi savoir prendre des risques (Intelligence d'action au sens d'Aristote). »" }, { "type": "paragraph", "html": "« Il faut aussi bien sûr donner du sens dans une entreprise. La technique n'étant que le moyen. »" }, { "type": "heading", "level": 2, "id": "transformation-agile-choisissez-vos-combats-grace-aux-okr-rex-ratp", "text": "Transformation agile : choisissez vos combats grâce aux OKR (REX RATP)" }, { "type": "paragraph", "html": "Anne Gabrillagues (coach) et Florence Lyon (Dir. Transfo) ont racontées les coulisses de leur transformation...dans un contexte ou l'équipe croule sous les sollicitations directes et indirectes !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da471e3c770cfd04a8919_flyon-ratp-min.jpg", "alt": "Florence Lyon (Dir. Transfo) et Anne Gabrillagues (Coach Agile)", "caption": "Florence Lyon (Dir. Transfo) et Anne Gabrillagues (Coach Agile)" }, { "type": "heading", "level": 3, "id": "lessentiel-de-leur-rex-prioriser-et-piloter-cest-la-cle", "text": "L'essentiel de leur REX : prioriser et piloter c'est la clé !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da343163554f2ec69a71a_ratp-saison1-min.jpg", "alt": "" }, { "type": "paragraph", "html": "« Notre manifeste de la transfo, co écrit avec les sponsors, a servi de boussole »" }, { "type": "paragraph", "html": "« Nous avons mené un travail de fond sur la notion de responsabilité vs culture du prestataire externe »" }, { "type": "paragraph", "html": "« Il ne faut pas oublier que les activités de transfo ça vient en plus du travail des équipes. »" }, { "type": "paragraph", "html": "« Notre but a été de trouver le bon degré de process pour sécuriser avec un cadre et libérer. »" }, { "type": "paragraph", "html": "« Prioriser par la valeur c'est la clé ! »" }, { "type": "paragraph", "html": "« Parmi les apprentissages nous nous sommes heurtés au manque de données que nous n'avions pas assez pris en compte. Nous avons développé l'obsession de la mesure régulière ^^ »" }, { "type": "paragraph", "html": "« Trop d'outils tue l'outil, les coachs agiles ont toujours plein d'outils ! »" }, { "type": "heading", "level": 2, "id": "le-pmu-raconte-son-long-chemin-vers-la-tech-company", "text": "Le PMU raconte son (long) chemin vers la Tech Company !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da51ebd3898282ed9bf29_pmu%20-%20copie-min.jpg", "alt": "Nelson Dufossé, Release Train Engineer PMU", "caption": "Nelson Dufossé, Release Train Engineer" }, { "type": "paragraph", "html": "Alors que beaucoup ne voient que le tiercé et les bars PMU... la face cachée et les exigences vis-à-vis du SI sont colossales ! 2000 transactions/seconde, un recalcul des cotes toutes les 5 secondes, des MEPs tous les jours…une DSI de 400 personnes sur les 1200 collaborateurs." }, { "type": "paragraph", "html": "Nelson Dufossé, Release Train Engineer a présenté un focus sur les 4 dernières années... la vie d'une Tech Company, sa multitude d'ambitions en parallèle (Recrutement, Structuration du management, migration AWS, création de nouveaux produits, refonte des hardwares…) et comment il s'y prennent pour le rendre possible avec les trains SAFe." }, { "type": "paragraph", "html": "\"Depuis 20 ans, toutes les boîtes tech affrontent un peu les mêmes difficultés, réussir à scaler, travailler la robustesse, la qualité, des problèmes de people...\"" }, { "type": "heading", "level": 3, "id": "lorganisation-de-lagilite-a-lechelle", "text": "L'organisation de l'agilité à l'échelle" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da599b46a6196c3310db8_pmu-orga-agilite-echelle-min.jpg", "alt": "L'organisation de l'agilité à l'échelle au PMU", "caption": "PMU : L'organisation de l'agilité à l'échelle" }, { "type": "paragraph", "html": "\"Pour lancer l'Agilité à l'échelle on a créé deux trains transverses aux départements avec 125 personnes...10 à 15 équipes et 7 solutions par train !\"." }, { "type": "paragraph", "html": "<strong>Côté obstacles :</strong>" }, { "type": "list", "ordered": false, "items": ["Hétérogénéité des pratiques", "Pas suffisamment de communautés", "Peu de coopérations"] }, { "type": "paragraph", "html": "Leur approche globale repose notamment sur le fait d'intégrer l'inspection à leur culture en s'appuyant sur les \"feedbacks authentiques + tentatives\"." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da5ff34a739a538f30245_pmu-approche%20globale%20-%20copie-min.jpg", "alt": "Innovation au PMU", "caption": "Approche innovation @ PMU" }, { "type": "paragraph", "html": "\"Il parait que la première étape de la transfo c'est de jeter les gens dans la piscine.\"" }, { "type": "paragraph", "html": "\"Le PMU a au contraire posé un système d'innovation d'un point de vue tech orga et fonctionnel qui permet de tenter en sécurité, de dérisquer les choix. Un système à base d'essai erreur réajustements...\"" }, { "type": "paragraph", "html": "\"Les succès amènent la confiance. La confiance favorise l'autonomie et la transparence. La transparence permet l'alignement\"" }, { "type": "paragraph", "html": "\"Aujourd'hui on maîtrise notre delivery de bout en bout de l'idée de démarrage avec le business jusqu'à la mise en prod.\"" }, { "type": "paragraph", "html": "\"Nous avons transformé le PI planning...notre vrai sujet est de sécuriser les sujets les plus importants !\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da6613cd8c053c16df521_quote-pmu.jpg", "alt": "Transfo PMU" }, { "type": "heading", "level": 3, "id": "cote-competences-et-alignement", "text": "Côté compétences et alignement" }, { "type": "paragraph", "html": "\"Dès lors que nous appartenons à un système, il faut un minimum d'alignement pour réellement progresser\"" }, { "type": "paragraph", "html": "\"La formation est intégrée au plan stratégique avec un budget &gt; 100K.\"" }, { "type": "paragraph", "html": "\"Le PMU a également mis en axe stratégique le maintien des compétences avec notamment la mise en place des communautés.\" Il y a eu la création de 6 communautés : Scrum, Produit, QA, Opes, Back, Front." }, { "type": "paragraph", "html": "\"En rapprochant les gens ....on va voir que naturellement tous les problèmes vont se simplifier....quand il y a par exemple des problèmes de dépendances ça marche mieux parce que les gens se parlent !" }, { "type": "paragraph", "html": "À noter que contribuer fait partie des objectifs individuels et que les communautés représentent environ 20 heures / mois dans les emplois du temps." }, { "type": "heading", "level": 3, "id": "un-process-de-recrutement-plus-long", "text": "Un process de recrutement plus long" }, { "type": "paragraph", "html": "Le PMU a des objectifs de recrutement ambitieux pour la DOSI de l'ordre de 70 personnes." }, { "type": "paragraph", "html": "\"Côté recrutement on s'est rendus compte que la compétence était majoritairement externe\". La bonne solution c'est la mixité conseil externe/équipe interne." }, { "type": "paragraph", "html": "Et si on veut être une tech company, il nous faut les meilleurs ! À contrepied des processus rapides...Pour avoir les meilleurs, on leur fait passer un process assez long avec un exercice de code a faire chez eux, une revue par quelqu'un de chez nous, des entretiens avec les RH les opérationnels. Tout ça pour évaluer si au delà d'être un bon développeur il sera un bon élément dans un système. Car aujourd'hui les hards skill sans soft ça ne sert à rien »" }, { "type": "paragraph", "html": "(Ils évaluent à 10 h le temps de recrutement.)" }, { "type": "heading", "level": 3, "id": "perspectives", "text": "Perspectives" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650da6fe0c6336fb3c5ab160_pmu-tech%20-%20copie-min.jpg", "alt": "", "caption": "Le long chemin de transfo du PMU" }, { "type": "paragraph", "html": "\"Aujourd'hui on a démarré un département produit, un département data pour mettre la data au centre, rallier l'IT et le produit pour qu'on arrive à prendre des décisions au niveau CODIR sur des thèmes vraiment stratégiques et pas partir dans tous les sens. Il y a un vrai besoin à ce niveau là on va se renforcer sur la partie SECOPS et autres.\"" }, { "type": "heading", "level": 2, "id": "le-lean-portfolio-agile-au-sein-du-groupe-renault", "text": "Le Lean Portfolio Agile au sein du Groupe Renault" }, { "type": "paragraph", "html": "Les équipes IS/IT &amp; digital sont revenues sur la mise en place le Lean Portfolio management (inspiré de SAFe.)" }, { "type": "paragraph", "html": "Ils ont partagé leur gouvernance du Portfolio Digital vue comme un levier de renforcement du plan stratégique du groupe." }, { "type": "paragraph", "html": "aka \"La gestion de la transversalité dans un portfolio d'entreprise\"." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650dafe28b937cae79ef4f2d_renault-digital-min.jpg", "alt": "", "caption": "Esra Soner - Aurelie Sale et Mehdi Balza" }, { "type": "paragraph", "html": "Les équipes de déploiement composées du Performance Office, du Pole Agile, des PMO et des Entreprise Architectes déploient une gouvernance et des outils qui maximisent les opportunités de création de valeur et de croissance depuis les OKR du Groupe jusqu'au niveau opérationnel." }, { "type": "paragraph", "html": "\"Le LPM Renault répond aux enjeux du pilotage transverse aux Value Stream. Notamment comment il aide les Executives et les Directeurs à s'aligner sur la gestion des programmes transverses, au calcul de la valeur et au pilotage budgétaire.\"" }, { "type": "paragraph", "html": "Aidé par un déploiement des OKR au niveau du groupe, le déploiement du LPM des produits vers toute la stratégie est en cours." }, { "type": "heading", "level": 3, "id": "vers-une-autre-gouvernance", "text": "Vers une autre gouvernance ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db196e1ce5d43209b0869_change-gov.jpg", "alt": "gouvernance flow", "caption": "Vers une autre gouvernance" }, { "type": "paragraph", "html": "\"Côté gouvernance le dispositif était basé sur une gouvernance pilotée par métiers\"" }, { "type": "paragraph", "html": "\"Les équipes agiles étaient tellement orientées métier …qu'il était difficile de connaître la contribution strat globale entreprise.\"" }, { "type": "paragraph", "html": "\"Le challenge : Une nouvelle gouvernance pour apporter de la transversalité.\"" }, { "type": "paragraph", "html": "\"La décision a été prise de mettre en place une gouvernance drivée par les chaînes de valeur du groupe. Une digital value stream\"" }, { "type": "paragraph", "html": "\"Cette gouvernance nous a permis de gérer cette complexité du métier\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db2b0d485fa4d7c70ac91_gouv%20flow-min.png", "alt": "Gouvernance flow Renault", "caption": "Le flux de gouvernance" }, { "type": "paragraph", "html": "\"C'est la gouvernance authority qui est owner sur le quoi et le comment\"" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db312e1ce5d43209c0d8b_lifecycle.jpg", "alt": "", "caption": "Cycle de vie des initiatives et de la gouvernance" }, { "type": "heading", "level": 3, "id": "value-driven-une-matrice-de-priorisation", "text": "\"Value driven\" : une matrice de priorisation" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db44f37bce8e3f1bade5e_valuedriven.jpg", "alt": "", "caption": "Les critères de priorisation du LPM" }, { "type": "heading", "level": 4, "id": "les-differents-criteres-de-la-matrice-ont-ete-presentes", "text": "Les différents critères de la matrice ont été présentés :" }, { "type": "list", "ordered": false, "items": ["Critères financiers", "Critères / Valeur utilisateur (basée sur le framework Heart de Google)", "Alignement stratégique", "Continuité business", "Compliance", "Business value, continuity..."] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db36a364a87059cbdc75d_IMG_9131%20-%20Grande-min.jpeg", "alt": "cross value stream strategic portfolio", "caption": "Aurélie Sale" }, { "type": "heading", "level": 2, "id": "la-poste-thiga-le-product-portfolio-management-au-dela-du-produit-numerique", "text": "La Poste / Thiga : Le Product Portfolio Management au-delà du Produit Numérique" }, { "type": "paragraph", "html": "Renaud CHEVALIER Conseil en Organisation Produit Thiga/Groupe La Poste a revalorisé la notion d'architecture d'entreprise plus précisément de Business architecture !" }, { "type": "paragraph", "html": "Pour lui le Product Management a dépassé les frontières des pure players du digital." }, { "type": "paragraph", "html": "Il repense nos approches de gestion de portefeuille. Explorez les défis spécifiques auxquels les entreprises sont confrontées lorsqu'elles doivent développer de nouvelles capacités et faire évoluer leurs chaînes de valeur. Découvrez comment la Business Architecture et la conduite du changement jouent un rôle essentiel dans la gestion du portefeuille de produits, en pilotant des initiatives stratégiques bien au delà de l'IT." }, { "type": "paragraph", "html": "Cependant il souligne que malgré le passage à l'échelle, deux modes de fonctionnement continuent de cohabiter autour du produit marketing. Un géré en mode projet \"côté métier\" et un géré en mode produit \"côté IT\"." }, { "type": "paragraph", "html": "Il a présenté une représentation de ce que l'entreprise doit être capable de faire pour rendre un service complexe :" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db796750792506e1b8d8c_IMG_9150.jpg", "alt": "", "caption": "Exemple de flux sur un produit marketing complexe (Renaud CHEVALIER / Crédit Thiga)" }, { "type": "paragraph", "html": "Pour lui :" }, { "type": "paragraph", "html": "\"Le Product Management passe à l'échelle\"" }, { "type": "paragraph", "html": "\"Le mode Produit se généralise sur les produits Techs\"" }, { "type": "paragraph", "html": "\"Attention au mot « produit » et à l'application de pratiques au mauvais niveau\"" }, { "type": "paragraph", "html": "\"Appliqué sur le Produit Marketing complexe, le Mode Produit facilite l'exécution de la stratégie\"" }, { "type": "paragraph", "html": "\"5 enablers sont nécessaires dont la Business Architecture\" *" }, { "type": "paragraph", "html": "\"Le Business Capability Management permet de sortir de L'IT en rendant le Mode Produit holistique\"" }, { "type": "heading", "level": 3, "id": "les-5-enablers-sont", "text": "Les 5 enablers sont :" }, { "type": "list", "ordered": false, "items": ["La business architecture", "Le business train tribe. &gt; embarquer le flux de valeur open", "Le combined portfolio &gt; aka 1 seul budget", "La team topologie &gt; plateformisation", "L'entreprise portfolio &gt; cohérence stratégique à gérer un portfolio de portfolio lean startup cycle"] }, { "type": "heading", "level": 3, "id": "et-en-resume-la-business-architecture-cest", "text": "Et en résumé, la business architecture c'est..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650db821ee68292f2e2f4a0e_Business%20Architecture-min.png", "alt": "", "caption": "La business architecture (Crédit Thiga)" }, { "type": "heading", "level": 2, "id": "deux-exemples-dimplementation-lpm-au-sein-dengie", "text": "Deux exemples d'implémentation LPM au sein d'ENGIE" }, { "type": "paragraph", "html": "Les retours d'expériences sur deux entités d'ENGIE ont été animés par Sophie Montet Coach Agile au sein de l'Agile Center, la practice au service du Groupe ENGIE et Laurence Bago, Responsable Transformation Agile qui a notamment pour mission l'implémentation du LPM et l'animation du train SAFe." }, { "type": "paragraph", "html": "L'enjeu clé présenté : renforcer la capacité à livrer plus de valeur." }, { "type": "paragraph", "html": "En effet au sein du groupe ENGIE, de plus en plus d'entités souhaitent mettre en place du LPM pour optimiser les investissements, absorber les aléas et en tirer le meilleur parti grâce au delivery agile." }, { "type": "paragraph", "html": "En creux comment contribuer à accélérer l'adoption du LPM ? Laurence et Sophie Montet ont présenté un retour d'expérience complet sur les étapes de mise en place, les difficultés rencontrées et les résultats à date." }, { "type": "insight-callout", "label": "À retenir", "html": "Une des conférences les plus enrichissantes !" }, { "type": "heading", "level": 3, "id": "engie-pro-en-2020avant-lagilite", "text": "Engie Pro en 2020...avant l'agilité" }, { "type": "paragraph", "html": "Trop de sujets en parallèle et non priorisés" }, { "type": "paragraph", "html": "Des ambitions au delà du budget disponible" }, { "type": "paragraph", "html": "Un manque de partage de la vision roadmap" }, { "type": "paragraph", "html": "Des équipes surchargées et non alignées" }, { "type": "paragraph", "html": "Peu de projets délivrés ..." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650dc89746bdb8bb6ab39264_xls%20engie-min.png", "alt": "Le portfolio Excel Engie avant 2020", "caption": "Avant ^^" }, { "type": "heading", "level": 3, "id": "une-adoption-progressive-au-sein-du-groupe", "text": "Une adoption progressive au sein du groupe" }, { "type": "paragraph", "html": "Les entités choisissent la façon de passer à l'échelle (ou non)" }, { "type": "paragraph", "html": "Aujourd'hui SAFe pour 6 entités" }, { "type": "paragraph", "html": "Modèle spotity pour 1 entité" }, { "type": "paragraph", "html": "Modèle hybride pour 1 entité" }, { "type": "paragraph", "html": "<strong>8 trains SAFe lancés en 4 ans</strong> dans le groupe" }, { "type": "paragraph", "html": "Le LACE (Lean-Agile Center of Excellence) en support" }, { "type": "paragraph", "html": "Activateur de communautés de pratique" }, { "type": "paragraph", "html": "Plus de 45 sessions de formations certifiantes Leading SAFe" }, { "type": "paragraph", "html": "Accompagnement des transformations agiles (trains, LPM, ateliers spécifiques comme pitch, MVP, priorisation ou encore chaînes de valeur)" }, { "type": "heading", "level": 3, "id": "vers-un-autre-fonctionnement-articulant-plusieurs-dispositifs-okr-valeur-lpm-et-pi", "text": "Vers un autre fonctionnement articulant plusieurs dispositifs : OKR / Valeur / LPM et PI" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/650dcea6ba4cdc4285daa0c7_Engie-LPMOKREPIC1600-min.jpg", "alt": "OKR LPM PI EPIC", "caption": "L'EPIC au centre et le Lean Portfolio Management en amont" }, { "type": "heading", "level": 3, "id": "priorisation-comment-fait-on-quand-on-a-que-100-patates", "text": "Priorisation comment fait-on quand on a que \"100 patates\" ?" }, { "type": "paragraph", "html": "Plus de 45 projets dans l'entité, équipe surchargée....Le premier truc a été d'aligner tout le monde avec une séance OKR." }, { "type": "paragraph", "html": "Ensuite commencer à mettre en place du LPM avec EPIC et priorisation." }, { "type": "paragraph", "html": "Puis mettre en œuvre des horizons pour être sur de garder de la capacité pour de l'avenir" }, { "type": "paragraph", "html": "PI planning \"on a mis tt le monde dans un train\" !" }, { "type": "heading", "level": 3, "id": "quatre-etapes-pour-contribuer-a-accelerer-ladoption-du-lpm-dans-le-groupe-engie", "text": "Quatre étapes pour contribuer à accélérer l'adoption du LPM dans le Groupe Engie" }, { "type": "paragraph", "html": "La première marche a acquérir a été le vocabulaire..." }, { "type": "paragraph", "html": "La seconde a été la mise en place de rôle et un mindset qui change entre l'IT et le métier" }, { "type": "paragraph", "html": "Troisième point pour tout ce qui est gouvernance &gt; revue strat trim + revue de dotations &gt;" }, { "type": "paragraph", "html": "Enfin quatrième étape : l'amélioration continue travailler sur la valeur mesurée" }, { "type": "heading", "level": 3, "id": "la-priorisation-des-initiatives", "text": "La priorisation des initiatives" }, { "type": "paragraph", "html": "Chaque initiative obtient une note. Sur la suite de fibonacci sur la valeur." }, { "type": "paragraph", "html": "1h 30 pour faire les notations : 10 min / sujet" }, { "type": "paragraph", "html": "3 min pour pitcher bénéfices et la façon de répondre / contribuer aux axes stratégiques par le porteur." }, { "type": "heading", "level": 3, "id": "benefices-constates-de-limplementation-du-lean-portfolio-management-chez-engie-home-service", "text": "Bénéfices constatés de l'implémentation du Lean Portfolio Management chez Engie Home Service" }, { "type": "list", "ordered": false, "items": ["Connaissance et appropriation des sujets par tous", "Meilleure implication des équipes métiers et business owners", "Meilleur alignement stratégique", "Amélioration du delivery"] }, { "type": "heading", "level": 3, "id": "les-nouveaux-defis", "text": "Les nouveaux défis" }, { "type": "list", "ordered": false, "items": ["Fluidification du flux / Identification des WIP limits", "Quantifier les bénéfices attendus et mieux mesurer le ROI", "Piloter par les résultats attendus"] }], "toc": [{ "label": "Keynote d'ouverture Julia de Funès sur le thème \"sens et responsabilité en temps de crise\"", "href": "#keynote-douverture-julia-de-funes-sur-le-theme-sens-et-responsabilite-en-temps-de-crise", "level": 2 }, { "label": "Transformation agile : choisissez vos combats grâce aux OKR (REX RATP)", "href": "#transformation-agile-choisissez-vos-combats-grace-aux-okr-rex-ratp", "level": 2 }, { "label": "Le PMU raconte son (long) chemin vers la Tech Company !", "href": "#le-pmu-raconte-son-long-chemin-vers-la-tech-company", "level": 2 }, { "label": "Le Lean Portfolio Agile au sein du Groupe Renault", "href": "#le-lean-portfolio-agile-au-sein-du-groupe-renault", "level": 2 }, { "label": "La Poste / Thiga : Le Product Portfolio Management au-delà du Produit Numérique", "href": "#la-poste-thiga-le-product-portfolio-management-au-dela-du-produit-numerique", "level": 2 }, { "label": "Deux exemples d'implémentation LPM au sein d'ENGIE", "href": "#deux-exemples-dimplementation-lpm-au-sein-dengie", "level": 2 }], "faq": [], "related": [] }, { "slug": "role-du-pmo", "skip": false, "meta": { "title": "PMO et Codir : comment trouver la juste posture avec la direction ?", "h1": "PMO et Codir : comment trouver la juste posture avec la direction ?", "description": "Le positionnement du PMO face au Codir et aux chefs de projet conditionne tout : la qualité des décisions, la vitesse d'exécution, et au final la réussite ou l'échec des projets.", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe2572bfe3ed203f17a5c5_ro%CC%82le%20pmo-min.jpg", "alt": "" }, "author": { "name": "Jonas Roman", "category": "Gestion de projets", "publishedDate": "1/3/2023", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62c2f39c78a60c6233a66aa7_1543845869071.jpeg" }, "publishedDate": "1/3/2023" }, "blocks": [{ "type": "paragraph", "html": "Le <a href=\"/fr/gestion-de-projet/metier-pmo\">PMO</a> a beau être la colonne vertébrale de la gouvernance projet, sa relation avec le Codir reste souvent un exercice d'équilibriste. Trop dans le contrôle, il se fait rejeter par les équipes. Trop dans le service, il devient invisible pour la direction." }, { "type": "paragraph", "html": "Le positionnement du PMO face au Codir et aux chefs de projet conditionne tout : la qualité des décisions, la vitesse d'exécution, et au final la réussite ou l'échec des projets. Pourtant, peu de PMO identifient clairement ce levier. Le résultat ? Le PMO finit par jouer le rôle de fusible en cas de dysfonctionnement." }, { "type": "paragraph", "html": "Deux profils se retrouvent souvent en difficulté :" }, { "type": "paragraph", "html": "- Le PMO issu de la chefferie de projet : il reste trop proche du terrain, fait \"du projet\", et ne sait pas comment faire évoluer sa posture. On peut être un très bon chef de projet et un très mauvais PMO — et inversement." }, { "type": "paragraph", "html": "- Le PMO qui ne vient pas du terrain : il gravite autour du Codir, se met à dos les équipes projets, et finit par relayer des informations déconnectées de la réalité opérationnelle." }, { "type": "paragraph", "html": "Cet article détaille les symptômes d'un positionnement dysfonctionnel, et propose un cadre pour trouver la juste posture entre direction et équipes." }, { "type": "heading", "level": 2, "id": "les-symptomes-dun-pmo-dysfonctionnel", "text": "Les symptômes d'un PMO dysfonctionnel" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d8652edced0ea565de1199_63fe2e3a119889aeaead9d10_pmo2-min.jpeg", "alt": "Board", "caption": "Directeurs in progress" }, { "type": "heading", "level": 3, "id": "incomprehensions-et-frustrations", "text": "Incompréhensions et frustrations" }, { "type": "paragraph", "html": "On ne peut pas aborder l'historique des relations sans expliquer d'abord les raisons qui font que ce sujet mérite d'être abordé.&nbsp;" }, { "type": "paragraph", "html": "Il&nbsp;y a souvent des dysfonctionnements ou des imprévus dans un projet. Mais quand ces dysfonctionnements touchent une majorité de projets dans un programme, voire dans l'ensemble d'un processus projet, alors il est important de rechercher les éléments communs à ces dysfonctionnements pour pouvoir les adresser." }, { "type": "paragraph", "html": "Parmi les signaux qui peuvent indiquer des dysfonctionnements au niveau de la gestion des programmes projets et des relations entre les parties prenantes du processus, on retrouve bien souvent des latences dans les projets et des frustrations.&nbsp;" }, { "type": "paragraph", "html": "Résultat : incompréhension et frustrations pour la chefferie de projet quand des décisions non-prises ou des changements de décisions déstabilisent la gestion de projet ou encore, quand des projets sont dépriorisés ou abandonnés.&nbsp;Incompréhension et frustrations également des décisionnaires quand la chefferie de projet s'engage dans la complétion d'un jalon ou de livrables et qu'au final ils ne sont pas tenus.&nbsp;" }, { "type": "paragraph", "html": "Nous pouvons dire avec confiance aujourd'hui que le PMO a un rôle à jouer dans la résolution de ces problématiques - voire, qu'il en vient en grande partie du rôle du PMO.&nbsp;" }, { "type": "paragraph", "html": "Son incapacité à faire partie de la solution réside souvent dans son positionnement face aux parties prenantes. On a identifié plusieurs positionnements qui pose problème dans l'historique de ces relations :&nbsp;le PMO \"passe-plats\", le PMO trop focalisé sur&nbsp; le Codir, ou vers les chefs de projets... Focus ici sur les symptômes à surveiller." }, { "type": "paragraph", "html": "Pour comprendre quand et pourquoi ce rôle devient indispensable, lire <a href=\"/fr/gestion-de-projet/pourquoi-mettre-en-place-un-pmo\">pourquoi mettre en place un PMO</a>.<br>" }, { "type": "heading", "level": 3, "id": "le-pmo-passe-plats", "text": "Le PMO passe-plats" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d8652edced0ea565de118f_63fe2ca69358f8c8cb70aa4a_PMO%2520passe%2520plat-min.jpeg", "alt": "PMO project management office Passe-plats en entreprise", "caption": "Project Management Office \"passe-plats\" en entreprise ?" }, { "type": "paragraph", "html": "C'est la position que le PMO adopte quand il joue un rôle essentiellement de reporting aux parties prenantes. Il n'apporte que peu ou pas de valeur dans le processus, son action est bridée (souvent à la définition de son rôle par l'entreprise) et il reporte les actions et informations du terrain vers le Codir - et inversement les informations et directives données par le Codir à la chefferie /gestion de projet.&nbsp;" }, { "type": "paragraph", "html": "Un PMO passe-plat, c'est un peu comme passer au travers de sa vie en n'y étant qu'un simple spectateur. Il n'y a absolument aucun intérêt à créer un rôle de PMO pour qu'il soit endossé de cette manière.&nbsp;" }, { "type": "paragraph", "html": "Il participe à creuser le fossé entre le Codir et la chefferie de projet où la communication est faible, les échanges peu constructifs - et encore, quand ils existent ! On reste souvent dans une dynamique très top down avec des décisions décorrélées de la réalité terrain.&nbsp;<br>" }, { "type": "heading", "level": 3, "id": "le-pmo-trop-focalise-sur-le-codir", "text": "Le PMO trop focalisé sur le Codir" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d8652edced0ea565de119e_63fe2d3d8556b03270d32a2c_pmo4-min.jpeg", "alt": "PMO au Codir", "caption": "Un Project Management Office trop Codir" }, { "type": "paragraph", "html": "Les PMO étaient habituellement plus tournés dans leur relation au Codir, faisant une priorité pour apporter les informations et éléments voulus par le Codir. Avec une relation de \"grand petit chef\" avec les chefs de projets, et une relation entre PMO et Codir en \"front commun\" face aux chefs de projets." }, { "type": "paragraph", "html": "Il fait de son rôle une priorité quand il s'agit de fournir beaucoup de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/reporting-pmo\" target=\"_blank\">reporting</a>, et les équipes projets vont avoir un sentiment de contrôle et de micromanagement. Mais, dans les faits, les équipes n'auront pas de décisions ou le support du Codir, ni un PMO permettant une gestion fluide du projet." }, { "type": "paragraph", "html": "Petit à petit, le PMO va se mettre à dos les équipes projets et assister à l'effondrement de l'engagement des équipes." }, { "type": "paragraph", "html": "Au final, on se retrouve avec des Codir qui prennent des décisions sur de la fausse donnée, car on demande trop de reportings aux équipes - ce qui ne leur facilite pas la vie, surtout en mode \"best effort\". Et on finit par donner des informations pour donner des informations, et on multiplie les informations \"bullshit\" servant souvent à se couvrir plutôt que d'avoir du temps qualitatif à passer pour faire avancer les projets stratégiques.&nbsp;" }, { "type": "paragraph", "html": "En conséquence, cela génère une méfiance et défiance vis-à-vis du PMO de la part des chefs de projets, ce qui l'amène lui-même à obtenir des données fausses issues du management de projet sur lequel faire son pilotage de portefeuille de projets. Et donc, en conséquence, une direction qui pilote sur des données fausses également. Du coup la direction pense que ça avance - et quand elle se rend compte que ce n'est pas le cas, le PMO \"saute\" en attendant le prochain fusible.&nbsp;" }, { "type": "heading", "level": 3, "id": "le-pmo-trop-focalise-vers-les-chefs-de-projets", "text": "Le PMO (trop) focalisé vers les chefs de projets" }, { "type": "paragraph", "html": "D'un autre côté, un PMO qui vient de la chefferie de projet aura souvent du mal à se positionner et dysfonctionnera aussi. Car il va \"faire du projet\", s'impliquer beaucoup avec les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/chef-de-projet-pmo\" target=\"_blank\">chefs de projet</a>, et ne va pas faire avancer les décisions avec le Codir. La raison : les décideurs n'auront pas compris l'état des lieux des différentes situations sur lesquelles on leur demande de statuer." }, { "type": "paragraph", "html": "Le PMO n'arrivera donc pas à obtenir ces décisions rapides pour la gestion de projet, car les membres du Codir auront perdu de vue les éléments des projets et n'auront pas assez d'infos ou un niveau de compréhension suffisamment clair pour distiller les bonnes décisions ou les bons insights aux équipes projets." }, { "type": "heading", "level": 2, "id": "la-juste-posture-du-pmo-avec-son-codir", "text": "La \"juste\" posture du PMO avec son Codir" }, { "type": "paragraph", "html": "Les décisionnaires ont besoin de comprendre l'état des lieux, une réalité terrain, afin d'être en mesure de fournir les bonnes décisions et actions correctives." }, { "type": "paragraph", "html": "Pour ce faire, le rôle du PMO est de donner une image claire de la réalité terrain, sur l'avancement et l'évolution de la gestion de projet. Il doit être en mesure de communiquer au bon niveau, afin de synthétiser les informations clés, pour toujours remettre les évènements dans le cadre cognitif des objectifs du projet et des objectifs stratégiques d'entreprise. Les informations doivent être communiquées au Codir sous forme d'actionnables, permettant au Codir de prendre des décisions rapides, implémentables facilement.&nbsp;<br>" }, { "type": "heading", "level": 2, "id": "la-juste-posture-entre-pmo-et-chefs-de-projets", "text": "La \"juste\" posture entre PMO et chefs de projets" }, { "type": "paragraph", "html": "Il doit être assez proche des collaborateurs, pour comprendre leurs problématiques, les aider dans le processus opérationnel, la démarche, et la gestion de projet en leur rendant la vie plus facile. Mais surtout, il doit être en mesure d'obtenir pour la chefferie de projet des décisions rapides sur les éléments clés dont elle a besoin pour faire avancer leurs actions.&nbsp;" }, { "type": "paragraph", "html": "Il doit être un soutien à la chefferie de projet, leur permettant d'identifier et d'anticiper les difficultés ainsi que les ressources nécessaires à la complétion des objectifs." }, { "type": "paragraph", "html": "Dans le cas de chefs de projets en mode \"best effort\", le PMO joue un rôle de formation et de coaching aux services et équipes, afin de les aider à monter en compétence et d'atteindre une autonomie suffisante dans la gestion de ces projets - mais également en favorisant l'engagement des collaborateurs dans la gestion de projet.&nbsp;" }, { "type": "heading", "level": 2, "id": "le-role-souhaite-du-pmo-dans-le-processus-global", "text": "Le rôle souhaité du PMO dans le processus global" }, { "type": "paragraph", "html": "Le rôle du PMO idéal, c'est ce juste milieu à trouver entre \"ne pas faire les projets\" et \"aider les collaborateurs en essayant de leur faciliter la vie dans la gestion de projet\"." }, { "type": "paragraph", "html": "En même temps, le PMO a un bon accès aux informations. Par conséquent, il peut bien faire remonter les bons actionnables, en les communiquant au bon niveau de discours au Codir, ce qui permet d'obtenir des décisions et actions correctives rapides.&nbsp;" }, { "type": "paragraph", "html": "Le PMO doit apporter clarté et anticipation afin de faciliter la communication et la compréhension entre les parties prenantes des projets, et ainsi fluidifier le suivi et l'avancement.<br>" }, { "type": "heading", "level": 2, "id": "comment-bien-se-positionner-en-tant-que-pmo", "text": "Comment bien se positionner en tant que PMO ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d8652edced0ea565de1189_63fe2d8d005215b2ef91458c_pmo5-min.jpeg", "alt": "PMO", "caption": "Repères pour une mise en œuvre" }, { "type": "heading", "level": 3, "id": "un-facilitateur-le-tiers-de-confiance", "text": "Un facilitateur, le tiers de confiance" }, { "type": "paragraph", "html": "Le PMO doit partager son temps entre ces deux parties prenantes, il doit être un allié des deux parties, et jouer ce rôle de facilitateur pour fluidifier la communication et l'accès aux informations nécessaires, afin de faire avancer les projets." }, { "type": "paragraph", "html": "Pour qu'il puisse mettre de l'huile dans les rouages, il ne doit pas se positionner dans une relation de clients à fournisseurs. Il doit créer une relation partenariale avec les deux parties, comme le ferait un tiers de confiance afin de s'assurer de pouvoir créer des situations win-win entre toutes les parties.&nbsp;&nbsp;" }, { "type": "paragraph", "html": "Cela permettra également de rappeler à l'ensemble des collaborateurs et instances leurs droits et leurs devoirs. D'où l'importance dans la démarche projet pour le PMO de bien définir et communiquer sur les rôles et responsabilités de chaque partie prenante, afin de pouvoir garantir le bon fonctionnement du processus dans la réussite des objectifs relatifs aux projets.&nbsp;<br>" }, { "type": "heading", "level": 3, "id": "entre-le-marteau-et-lenclume-pas-de-soucis", "text": "Entre le marteau et l'enclume, pas de soucis !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d8652edced0ea565de118c_63fe2dd5c119d8111002a8b3_pmo6-min.png", "alt": "PMO entre le marteau et l'enclume", "caption": "Attention aux processus métiers du PMO !" }, { "type": "paragraph", "html": "Le PMO peut parfois se retrouver dans cette situation délicate - ou en cas de dysfonctionnements il se retrouve face à une forte concentration de frustrations des différentes parties.&nbsp;" }, { "type": "paragraph", "html": "Ici pour bien gérer ces situations et garder la tête froide, il est important de rester dans le factuel, ne pas rentrer dans le registre des émotions et adopter la casquette de \"problem solver\". Être en mesure de bien fluidifier la communication et trouver les situations de win-win permettra au PMO de passer ces étapes délicates, certes inconfortables, mais souvent inévitables dans la gestion de projets à l'échelle d'une entreprise." }, { "type": "heading", "level": 3, "id": "structurer-une-demarche-projet-basee-sur-le-srr-pour-bien-positionner-les-acteurs", "text": "Structurer une démarche projet basée sur le SRR pour bien positionner les acteurs" }, { "type": "paragraph", "html": "L'un des outils du PMO pour fluidifier la conduite des projets et la communication, menant vers des décisions rapides, est la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/demarche-de-projet\" target=\"_blank\">démarche projet</a> mise en place.&nbsp;" }, { "type": "paragraph", "html": "L'une des méthodologies qui se montre très efficace est une démarche drivée par l'engagement, les jalons, les décisions et qui est centrée autour du SRR (pour Sens, Rôle, Rituel)." }, { "type": "paragraph", "html": "Le concept SRR permet de bien définir et communiquer les rôles et responsabilités de chacun, tout en y donnant du sens pour tout le monde, et en mettant en place des rituels qui permettent de bien adopter les concepts et la culture projet pour tous.&nbsp;" }, { "type": "heading", "level": 2, "id": "lenjeu-de-la-relation-entre-le-pmo-et-le-sponsor-dans-le-processus", "text": "L'enjeu de la relation entre le PMO et le sponsor dans le processus" }, { "type": "paragraph", "html": "Le sponsor du projet est le collaborateur ou l'organisation qui a initié le projet et qui en assume la responsabilité finale. On a coutume de dire que c'est \"celui qui paye\"." }, { "type": "paragraph", "html": "Il est important que le PMO et le sponsor du projet entretiennent une relation de travail solide et efficace pour garantir le succès du projet. Voici quelques éléments clés qui peuvent aider à définir les relations entre un PMO et un sponsor :" }, { "type": "list", "ordered": true, "items": ["<strong>Communication</strong> : il est essentiel que le PMO et le sponsor du projet communiquent de manière régulière et efficace afin de s'assurer que tous les aspects du projet sont gérés de manière appropriée.", "<strong>Responsabilités</strong> : le PMO est responsable de la gestion du projet, tandis que le sponsor du projet est responsable de la décision finale et de l'approbation des changements. Il est important que ces responsabilités soient clairement définies et que chacun comprenne son propre rôle dans le projet.", "<strong>Collaboration</strong> : le PMO et le sponsor du projet doivent travailler ensemble de manière collaborative pour atteindre les objectifs du projet. Cela peut inclure la définition des priorités, la résolution de problèmes et la prise de décision qui ne nécessite pas le Codir."] }, { "type": "paragraph", "html": "En résumé, il est important que le PMO et le sponsor du projet entretiennent une relation de travail solide et efficace pour garantir le succès du projet. Cela implique une communication claire et régulière, des responsabilités bien définies et une collaboration active." }, { "type": "heading", "level": 2, "id": "quelle-est-la-bonne-metrique-pour-un-pmo-dans-lentreprise", "text": "Quelle est la bonne métrique pour un PMO dans l'entreprise ?" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/63fe2581ce62313f927c048e_a4d2800c-9cc1-4ded-b03e-698f24155d6b.png", "alt": "Dashboard", "caption": "Tout pour aider direction générale et PMO à tourner les \"boutons\" au bon niveau" }, { "type": "paragraph", "html": "Vous l'aurez peut-être déjà deviné à ce stade : une des missions et indicateur qui serait parfaitement adaptée au rôle du PMO de nos jours serait donc plutôt la capacité à faire décider et la rapidité avec laquelle il aide à faire prendre des décisions<strong> </strong>aux Codir permettant d'améliorer la gestion de projet." }, { "type": "paragraph", "html": "Sa capacité à faire prendre ces décisions rapides viendra&nbsp;de sa capacité à communiquer au bon niveau avec le Codir, de fluidifier les échanges d'informations entre le Codir et les collaborateurs projet, tout en facilitant le travail de ces derniers afin de garantir l'intégrité des informations et aider dans la conduite opérationnelle des projets." }, { "type": "paragraph", "html": "Si le Codir à peu de décisions à prendre, c'est peut-être qu'il n'y a pas assez d'informations qui remontent des collaborateurs projets. A contrario, s'il y a beaucoup de décisions à prendre qui remontent en Codir mais que peu de décisions sont prises, ça ne fonctionnera pas non plus. C'est un équilibre subtil que de trouver le juste rôle du PMO - mais un équilibre atteignable !" }], "toc": [{ "label": "Les symptômes d'un PMO dysfonctionnel", "href": "#les-symptomes-dun-pmo-dysfonctionnel", "level": 2 }, { "label": "La \"juste\" posture du PMO avec son Codir", "href": "#la-juste-posture-du-pmo-avec-son-codir", "level": 2 }, { "label": "La \"juste\" posture entre PMO et chefs de projets", "href": "#la-juste-posture-entre-pmo-et-chefs-de-projets", "level": 2 }, { "label": "Le rôle souhaité du PMO dans le processus global", "href": "#le-role-souhaite-du-pmo-dans-le-processus-global", "level": 2 }, { "label": "Comment bien se positionner en tant que PMO ?", "href": "#comment-bien-se-positionner-en-tant-que-pmo", "level": 2 }, { "label": "L'enjeu de la relation entre le PMO et le sponsor dans le processus", "href": "#lenjeu-de-la-relation-entre-le-pmo-et-le-sponsor-dans-le-processus", "level": 2 }, { "label": "Quelle est la bonne métrique pour un PMO dans l'entreprise ?", "href": "#quelle-est-la-bonne-metrique-pour-un-pmo-dans-lentreprise", "level": 2 }], "faq": [], "related": [] }, { "slug": "tout-savoir-sur-la-note-de-cadrage-projet", "skip": false, "meta": { "title": "Tout savoir sur la note de cadrage projet", "h1": "Tout savoir sur la note de cadrage projet", "description": "Tout savoir sur la note de cadrage projet : définition, utilité, contenu, formats et gestion des ressources. Guide complet pour bien cadrer vos projets.", "author": { "name": "Simon Vacher", "category": "Gestion de projets", "publishedDate": "9/10/2021", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/61e038501c4256317123910b_SV-min.jpg" }, "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/62f37d0ce3e506569bcd5ba1_5.jpg", "alt": "" }, "publishedDate": "9/10/2021" }, "blocks": [{ "type": "paragraph", "text": "Lorsqu'on entreprend une phase de cadrage de projet, l'une des <strong>étapes indispensables </strong>est de réaliser une note de cadrage de projet. La note de cadrage projet sera le <strong>document synthétique</strong> qui permettra à chacun d'<strong>identifier en un coup d'œil</strong> les points principaux du cadrage de votre projet. Elle est partie intégrante du <a href=\"/fr/solution/rapport-flash\" target=\"_blank\">rapport flash</a> que vous pouvez envoyer aux différentes parties prenantes. <strong>Sans elle pas de bon début</strong> pour votre <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\" target=\"_blank\">conduite de projet.</a>" }, { "type": "inline-cta", "label": "Télécharger notre note de cadrage projet ⇣", "href": "https://hubs.ly/Q02NlZ8Q0" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d6d473e7b12e9bc4e00fa4_62f37bb514709396276b8070_Project-page-setup%252Bcreation.jpeg", "alt": "Création d'un projet", "caption": "Créer un projet" }, { "type": "heading", "level": 2, "id": "quest-ce-quune-note-de-cadrage", "text": "Qu'est-ce qu'une note de cadrage ?" }, { "type": "paragraph", "text": "La note de cadrage est un <strong>document</strong> qui permet de <strong>délimiter l'étendue </strong>d'un projet et d'en définir les objectifs." }, { "type": "paragraph", "text": "La note de cadrage est l'une des étapes principales qui permet de donner naissance formellement à un projet : on le fait ainsi <strong>passer du stade de la simple idée</strong> <strong>à celui d'un projet assorti d'un cadre</strong> directeur." }, { "type": "paragraph", "text": "La note de cadre doit être <strong>synthétique</strong> : elle concentre toutes les caractéristiques essentielles du projet : les moyens à disposition, les différentes étapes, les éléments à surveiller, etc..." }, { "type": "paragraph", "text": "Un des principaux intérêts de la note de cadrage est de <strong>permettre à toutes les parties prenantes de</strong> <strong>s'accorder </strong>sur un même projet, clairement défini. Elle est <strong>partie intégrante du plan de communication.</strong>" }, { "type": "paragraph", "text": "Ainsi, la fiche de cadrage est une étape importante de la phase de cadrage : elle <strong>fixe </strong>à l'écrit <strong>les points principaux </strong>du projet et permet de <strong>vérifier</strong> que le client comme l'équipe projet sont bien d'<strong>accord </strong>sur la totalité du projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d0796d34dc540fa20b13b9_62f3767188c0c35f4604ba8a_Project-info.jpeg", "alt": "note de cadrage projet", "caption": "Note de cadrage projet" }, { "type": "heading", "level": 2, "id": "a-quoi-sert-une-note-de-cadrage", "text": "À quoi sert une note de cadrage ?" }, { "type": "paragraph", "text": "Un des premiers <strong>intérêts </strong>de la note de cadrage est de <strong>graver dans le marbre</strong> les points majeurs d'un projet, le contenu. Quiconque a déjà mené un projet dans une entreprise sait que <strong>tout ce qui n'est pas écrit noir sur blanc n'existe pas</strong> forcément aux yeux de toutes les parties engagées. De plus, si votre client est impliqué, elle lui permet aussi de <strong>s'approprier vraiment les enjeux du projet.</strong>" }, { "type": "paragraph", "text": "Ainsi, il est conseillé de <strong>fixer en amont du projet vos objectifs et vos engagements</strong>, mais aussi d'identifier quelles sont les priorités, le <a href=\"https://www.airsaas.io/gestion-de-projet/budgetiser-un-projet-sans-se-louper\" target=\"_blank\">budget</a> affecté, ainsi que les risques à surveiller." }, { "type": "heading", "level": 3, "id": "pourquoi-devez-vous-faire-une-note-de-cadrage", "text": "Pourquoi devez-vous faire une note de cadrage ?" }, { "type": "list", "ordered": false, "items": ["<strong>Vérifier </strong>en avant projet que toutes les <strong>parties prenantes </strong>sont <strong>en phase avec le projet</strong>, les besoins, ses ressources, son périmètre, les solutions...", "Définir <a href=\"https://www.airsaas.io/gestion-de-projet/le-macro-planning-pourquoi-et-comment-sen-servir\" target=\"_blank\">l'organisation macro</a> du projet", "Identifier les bénéfices qu'apportera le projet", "<a href=\"https://www.airsaas.io/gestion-de-projet/analyse-des-risques-projet\" target=\"_blank\">Définir les risques</a> et les points d'attention à surveiller."] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44c27_62f370f834986741dc2e6b30_Project-metrics.jpeg", "alt": "coût et délai du projet", "caption": "Les coûts et délai du projet" }, { "type": "paragraph", "text": "Si l'on voulait <strong>résumer</strong> le plus rapidement l'intérêt d'une note de cadrage : elle <strong>augmente vos chances de mener à bien votre projet</strong>." }, { "type": "heading", "level": 2, "id": "a-qui-se-destine-t-elle-pour-quelle-utilisation", "text": "À qui se destine-t-elle ? Pour quelle utilisation ?" }, { "type": "paragraph", "text": "La <a href=\"https://www.manager-go.com/gestion-de-projet/dossiers-methodes/realiser-une-note-de-cadrage\" target=\"_blank\">note de cadrage</a> est souvent <strong>préparée en vue d'une réunion </strong>qui <strong>regroupera toutes les parties prenantes</strong> du projet (client, équipe projet, comité de pilotage…)." }, { "type": "paragraph", "text": "C'est un support qui <strong>pose les bases des discussions des parties prenantes </strong>: c'est aussi pour cela qu'elle doit balayer l'ensemble du projet et en contenir tous les points essentiels." }, { "type": "paragraph", "text": "Petit conseil : <strong>ces points doivent être suffisamment synthétiques</strong> pour que chaque acteur puisse en prendre connaissance en un coup d'œil !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d6d473e7b12e9bc4e00f9b_62f37c5c64eac25421043d3d_Copil-play.jpeg", "alt": "Un note de cadrage pour tout type de projet", "caption": "Tous les projets doivent avoir une note de cadrage" }, { "type": "heading", "level": 2, "id": "comment-faire-une-note-de-cadrage", "text": "Comment faire une note de cadrage ?" }, { "type": "paragraph", "text": "Soyons clairs : il n'existe <strong>pas de modèle universel</strong> de note de cadrage." }, { "type": "paragraph", "text": "Votre note de cadrage idéale <strong>dépend de votre entreprise</strong> : quelle est sa taille ? Quelle est votre activité ? Quelle est la problématique du projet ? Quelle est votre méthodologie pour mener vos projets ?<br><br>La <strong>première étape </strong>qui précède la rédaction est donc de <strong>discuter avec chaque partie prenante </strong>du projet : vous pourrez ainsi <strong>cerner</strong> tous les <strong>enjeux</strong> et attentes de vos clients, ainsi que <strong>demander</strong> des informations de <strong>précisions</strong> aux <strong>équipes</strong> en charge du projet." }, { "type": "paragraph", "text": "Cependant, on peut se risquer à citer <strong>plusieurs des points</strong> <strong>que l'on retrouve</strong> souvent dans les <strong>notes de cadrage.</strong>" }, { "type": "paragraph", "text": "Nous vous conseillons donc de vous en inspirer, tout en les <strong>adaptant aux caractéristiques</strong> de vos projets pour sa mise en place." }, { "type": "list", "ordered": false, "items": ["L'<strong>énoncé et les contours </strong>du projet ;", "Le client final du projet et ses attentes", "Les objectifs que l'on souhaite atteindre", "La portée du projet : <strong>périmètre</strong> de ce qu'on fera/ne fera pas", "Les étapes/<a href=\"https://www.airsaas.io/gestion-de-projet/les-jalons-projet-une-technique-pour-sequencer-vos-projets-intelligemment\" target=\"_blank\"><strong>jalons du projet</strong></a>", "Les <strong>contraintes</strong> qu'il faut respecter", "Les <strong>ressources</strong> à disposition, le budget", "Le délai de réalisation."] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d6d473e7b12e9bc4e00f72_62f37c8e6d43f233ee160352_Creation-step1-min.jpeg", "alt": "Description projet", "caption": "Une bonne description est essentielle" }, { "type": "paragraph", "text": "Enfin, gardez en tête que si vous pouvez la <strong>personnaliser</strong> en fonction des <strong>spécificités</strong> de votre projet, une note de cadrage doit respecter <strong>deux points essentiels </strong>:" }, { "type": "list", "ordered": false, "items": ["elle doit donner <strong>une vision globale </strong>de votre projet", "elle doit <strong>comporter tous les éléments </strong>qui vous paraissent essentiels"] }, { "type": "heading", "level": 3, "id": "quest-ce-qui-est-inclus-dans-la-portee-dun-projet", "text": "Qu'est-ce qui est inclus dans la \"portée\" d'un projet ?" }, { "type": "paragraph", "text": "Ces <strong>détails sont essentiels à documenter</strong> dans votre note de cadrage car il y aura des moments où les demandes des parties prenantes (et parfois même de l'équipe) se glisseront et mettront en danger votre calendrier votre budget et votre moral !" }, { "type": "heading", "level": 4, "id": "description-du-projet-et-des-livrables-inclus", "text": "Description du projet et des livrables inclus" }, { "type": "paragraph", "text": "Il s'agit de proposer un <strong>aperçu en langage clair des livrables</strong> du projet. Évitez toute confusion en décrivant clairement <strong>ce qui sera livré</strong> pour approbation <strong>tout au long du projet</strong>, ainsi que <strong>le livrable final</strong>." }, { "type": "paragraph", "text": "Il s'agit d'une simple description de ce que vous travaillez pour livrer, mais il énonce également de <strong>petits détails </strong>comme la <strong>quantité</strong>, la <strong>quantité</strong>, la longueur ou tout autre aspect décrivant avec <strong>précision</strong> le projet." }, { "type": "heading", "level": 4, "id": "exclusions", "text": "Exclusions" }, { "type": "paragraph", "text": "Vous avez déjà répertorié les livrables que vous fournirez, mais il est parfois tout aussi important de <strong>détailler ce que vous ne livrerez PAS</strong>. Cela vous permet dès la mise en place du projet d'éviter les questions ou demandes embarrassantes du type « Mais n'allez-vous pas… ». Vraiment, il s'agit de définir des attentes et <strong>d'éviter tout malentendu autour du travail que vous avez prévu</strong>." }, { "type": "heading", "level": 4, "id": "criteres-dacceptation-du-produit-projet", "text": "Critères d'acceptation du produit/projet" }, { "type": "paragraph", "text": "Dans le même esprit de transparence et de précision....Votre cadrage projet devrait vous aider à vous mettre d'accord au-delà des objectifs généraux sur ce qui sera livré et à ne laisser aucun doute sur la fin du projet. Les <strong>critères d'acceptation</strong> pourront être mesurés, atteints et utilisés pour <strong>prouver que le projet est terminé.</strong>" }, { "type": "paragraph", "text": "Cette notion est très proche de celle de l'exigence fonctionnelle mais pour la note de cadrage on reste \"macro\" !" }, { "type": "paragraph", "text": "Au-delà de l'approbation finale des parties prenantes parfois subjective...ces <strong>critères d'acceptation </strong>vous <strong>permettront</strong> de \"tamponner\" votre <strong>validation du bon fonctionnement</strong> (VABF). À vous la signature du procès-verbal de fin de projet !" }, { "type": "heading", "level": 4, "id": "accord-tacite-ou-explicite", "text": "Accord tacite ou explicite ?" }, { "type": "paragraph", "text": "Les notes de cadrage projet créent un <strong>accord par nature</strong>, mais parfois vous avez besoin de preuves ! Incluez donc un champ de signature dans votre document de cadrage et <strong>demandez à votre intervenant principal </strong>ou à votre sponsor de projet et aux parties prenantes éventuellement de <strong>signer le document !</strong>" }, { "type": "paragraph", "text": "Et pour finir sur ce point, rappelons une chose : <strong>rédiger une fiche de cadrage s'apprend</strong> de manière théorique, mais aussi <strong>sur le terrain</strong>. À force de le faire, le <a href=\"https://www.airsaas.io/gestion-de-projet/comment-etre-un-bon-chef-de-projet-transverse\" target=\"_blank\">chef de projet</a> identifiera les points qui sont indispensables et en retirera des leçons. Avec de la volonté, vous finirez par obtenir le modèle de fiche de cadrage qui vous comblera !" }, { "type": "heading", "level": 2, "id": "note-de-cadrage-projet-variez-les-formats", "text": "Note de cadrage projet : variez les formats !" }, { "type": "paragraph", "text": "Proposer une vision <strong>globale et précise</strong> peut parfois se révéler délicat. L'utilisation d'un des logiciels de cartographie de type mind mapping peut vous permettre de mieux organiser visuellement les données et idées et finalement de <strong>mettre en scène le contenu </strong>de la note de cadrage projet." }, { "type": "paragraph", "text": "L'avantage est de proposer à la fois une <strong>vue globale</strong> et au clic sur une des sous branches, une vue <strong>détaillée</strong> dans le <strong>même support</strong>." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66d6d473e7b12e9bc4e00f86_6326c37dd094701445d4c961_CQQCOQP-Cadrage-projet-AirSaas-min.jpeg", "alt": "Exemple de Mind map de synthèse de la note de cadrage projet", "caption": "Exemple de Mind map de synthèse de la note de cadrage projet" }, { "type": "paragraph", "text": "Cette <strong>synthèse visuelle ne remplace pas le document</strong>, les objectifs poursuivis ne sont simplement pas les mêmes." }, { "type": "paragraph", "text": "Au sein d'une <strong>note de cadrage</strong>, on retrouvera <strong>les développements logiques, </strong>une rédaction avec de la nuance et des détails. Pour la mind map, on cherche à accentuer la vue \"globale\" des informations clés, votre macro planning, etc.. Le tout avec le juste nombre de mots, la <strong>synthèse visuelle. Ici on travaille la conduite du changement, un outil d'aide à la décision en quelque sorte.</strong>" }, { "type": "paragraph", "text": "Pour réaliser cette carte avec des logiciels vous avez le choix ...il en existe des centaines ! Du logiciel desktop le plus simple aux plateformes saas interconnectées aux différents services cloud ....les solutions les plus utilisées sont MindManager, X-Mind, et Mindmeister pour la partie payante. Pour la partie libre Freemind est la référence." }, { "type": "paragraph", "text": "Vous avez tout ce qu'il faut pour intégrer ce nouveau \"média\" de synthèse à <a href=\"https://www.airsaas.io/gestion-de-projet/plan-de-communication-projet\" target=\"_blank\">votre plan de communication projet</a>." }, { "type": "heading", "level": 3, "id": "lexemple-du-cqqcoqp-pour-le-cadrage-projet", "text": "L'exemple du CQQCOQP pour le cadrage projet" }, { "type": "paragraph", "text": "Également appelée méthode des Five W's (pour what, why, who, when et how) la démarche empirique qu'est <a href=\"https://www.appvizer.fr/magazine/operations/gestion-de-projet/methode-qqoqcp\" target=\"_blank\">le CQQCOQP</a> permet un questionnement exhaustif d'un sujet. Associée au mind mapping on obtient la forme combinée à une structuration simple." }, { "type": "paragraph", "text": "Couramment utilisée en <strong>gestion de projet </strong>ainsi qu'en <strong>gestion de la qualité</strong>, comme première approche d'une analyse de causes de problèmes. Cette matrice basique permettra à votre chef de projet d'organiser l'information, contenue dans la note, à l'attention des parties prenantes de votre entreprise." }, { "type": "heading", "level": 4, "id": "declinaison-de-la-matrice-de-lasswell-pour-la-note-de-cadrage-projet", "text": "Déclinaison de la Matrice de Lasswell pour la note de cadrage projet :" }, { "type": "list", "ordered": false, "items": ["<strong>Qui</strong> ? : qui demande ce projet, avec qui pourrions-nous le réaliser, pour le compte de qui…", "<strong>Quoi</strong> ? : L'énoncé et les contours du projet ; situation finale ? Quels sont les résultats attendus ? Avec quoi, en relation avec quoi…", "<strong>Où</strong> ? : localisation du projet, des lieux de travail, des différents services,…", "<strong>Quand</strong> ? : À partir de quand, jusqu'à quand, dans quel délai…Dates, périodicité, durée…pourquoi maintenant ? Les étapes/jalons du projet, le délai de réalisation...", "<strong>Comment</strong> ? De quelle façon, dans quelles conditions, par quel procédé… ? Quelle comitologie ?", "<strong>Combien</strong> ? Les ressources à disposition, le budget ? etc.", "<strong>Pourquoi</strong> ? Les objectifs que l'on souhaite atteindre. Cause, facteur déclenchant, Justification par les causes qui ont amené à… (la « raison » d'être, la croyance)"] }, { "type": "heading", "level": 2, "id": "note-de-cadrage-et-gestion-des-ressources-projet", "text": "Note de cadrage et gestion des ressources projet" }, { "type": "paragraph", "text": "Comme expliqué précédemment, la note de cadrage doit <strong>permettre en un coup d'œil </strong>de se <strong>rendre compte de l'affectation des ressources</strong> sur les différentes tâches de votre projet." }, { "type": "paragraph", "text": "Cependant, <strong>assigner les bonnes ressources</strong>, en bonne quantité, au bon moment, au bon endroit <strong>est un art </strong>: l'art de la <strong>gestion des ressources</strong> ! Nous vous conseillons donc de prendre particulièrement du temps pour penser votre gestion des ressources, si vous voulez vous donner toutes les chances de réussir votre projet." }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66c83647fe48f35c11f44bf4_62f37cc85606d84d53b0f203_People-involve-min.jpeg", "alt": "Equipe projet", "caption": "Mettez en valeur les personnes impliquées !" }, { "type": "heading", "level": 3, "id": "mettez-en-valeur-les-personnes-impliquees", "text": "Mettez en valeur les personnes impliquées !" }, { "type": "paragraph", "text": "Ce dernier point n'est pas anecdotique....dès la note de cadrage projet pensez à nommer les personnes, leur rôles et redevabilités précises. On sait tous que la disponibilité des métiers est trop souvent largement sous estimées. Aux cotés du sponsor et du chef de projet, les rôles de PO et ou de référent digital sont quasiment un mi-temps parfois ! <strong>Dès votre cadrage</strong> nommez et valorisez sincèrement les personnes qui vont être amenées à s'engager et sortir de leur zone de confort." }, { "type": "paragraph", "text": "La liste des <strong>retours d'expériences et conseils </strong>ci-dessus n'est pas exhaustive ....mais bien suffisante pour vous lancer !" }, { "type": "paragraph", "text": "Après avoir <strong>réussi vos objectifs de lancement</strong>, pensez d'emblée à la phase de fin du projet en découvrant dès maintenant la fin de la \"série\" ! Faites <strong>le plein de conseils </strong>avec l'article issu de notre dossier spécial gestion de projet : <a href=\"/gestion-de-projet/comment-animer-un-bilan-projet-efficace\" target=\"_blank\">Comment animer un bilan projet efficace ?</a>" }], "toc": [{ "label": "Qu'est-ce qu'une note de cadrage ?", "href": "#quest-ce-quune-note-de-cadrage", "level": 2 }, { "label": "À quoi sert une note de cadrage ?", "href": "#a-quoi-sert-une-note-de-cadrage", "level": 2 }, { "label": "À qui se destine-t-elle ? Pour quelle utilisation ?", "href": "#a-qui-se-destine-t-elle-pour-quelle-utilisation", "level": 2 }, { "label": "Comment faire une note de cadrage ?", "href": "#comment-faire-une-note-de-cadrage", "level": 2 }, { "label": "Note de cadrage projet : variez les formats !", "href": "#note-de-cadrage-projet-variez-les-formats", "level": 2 }, { "label": "Note de cadrage et gestion des ressources projet", "href": "#note-de-cadrage-et-gestion-des-ressources-projet", "level": 2 }], "faq": [], "related": [] }, { "slug": "trois-innovations-et-tendances-qui-bousculent-la-gestion-de-portefeuille-de-projets", "skip": false, "meta": { "title": "Trois innovations et tendances qui bousculent la gestion de portefeuille de projets", "h1": "Trois innovations et tendances qui bousculent la gestion de portefeuille de projets", "description": "Trois innovations et tendances qui bousculent la gestion de portefeuille de projets", "heroImage": { "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330b49f2ea6e2c24bd35495_innovationPPM-Airsaas.jpg", "alt": "Innovation PPM - AirSaas" }, "author": { "name": "Jérôme Dard", "category": "Gestion de projets", "publishedDate": "26/9/2022", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6253f0a55719365a7a838978_Avatar%20Je%CC%81ro%CC%82me.png" }, "publishedDate": "26/9/2022" }, "blocks": [{ "type": "paragraph", "text": "Dans une étude publiée à l'occasion du <strong>Program &amp; Portfolio Management Summit en juin 2020, l'institut d'études </strong>Gartner annonçait que \"<em>d'ici 2030, 80 % des tâches relatives à la gestion de projet seront éliminées à mesure que l'intelligence artificielle prendra en charge les fonctions traditionnelles de cette discipline, telles que la collecte, le suivi et le reporting des données.</em>\"" }, { "type": "paragraph", "text": "Gartner précisait sa prévision en ajoutant que «<strong>&nbsp;<em>Le marché se concentrera d'abord sur l'offre d'avantages supplémentaires en termes d'expérience utilisateur</em></strong><em> pour les professionnels de la gestion de projet et, plus tard, les aidera à devenir de meilleurs planificateurs et gestionnaires</em>&nbsp;»." }, { "type": "paragraph", "text": "Au-delà d'un effet d'annonce marketing <strong>qu'en est-il concrètement</strong> dans les pratiques en entreprise aujourd'hui ?" }, { "type": "paragraph", "text": "<strong>À quoi rêvent nos algorithmes ?</strong> ;-) Comment le management de l'innovation sera-t-il impacté par la technologie ?" }, { "type": "paragraph", "text": "De plus en plus d'aspects de la gestion de projet seront réalisables par l'IA. Exemples : gestion des ressources et des coûts, tableaux de bord de reporting, détection des dérives dans le budget ou les plans, …" }, { "type": "paragraph", "text": "Dans cet article on va s'intéresser à une dimension concrète, <strong>en zoomant sur trois innovations autour des usages</strong> qui nous semble pertinentes." }, { "type": "list", "ordered": false, "items": ["<strong>Le développement de l'usage des API </strong>pour une<strong> interconnexion </strong>toujours plus forte des outils de gestion de portefeuille de projets avec les écosystèmes applicatifs au sein de votre entreprise.", "<strong>L'importance prise par le design des interfaces</strong> et la mobilité dans la conception des outils de portefeuille de projets", "Et enfin les <strong>avancées technologique autour de l'IA</strong> avec l'automatisation, le data to texte, les analyse prédictive, le big data, les chatbots..."] }, { "type": "paragraph", "text": "Et, spoiler alerte ! &nbsp;On ne parlera<strong> pas que de très haute technologie </strong>mais également de ruptures d'usages. En particulier dans le second axe d'innovation lié au design des solutions de gestion de portefeuilles de projets actuelles." }, { "type": "paragraph", "text": "<strong>Combler le gap entre vision et exécution</strong>. C'est la promesse des outils de gestion du portefeuille projets. ! Regardons de plus près <strong>ce qui peut contribuer à faciliter cette démarche </strong>!" }, { "type": "heading", "level": 2, "id": "ppm-trois-innovations-qui-font-la-difference", "text": "PPM : trois innovations qui font la différence" }, { "type": "heading", "level": 3, "id": "la-tendance-de-fond-linterconnexion-des-outils", "text": "La tendance de fond : l'interconnexion des outils" }, { "type": "paragraph", "text": "<strong>Les PPM innovants ne cherchent plus à tout faire tout seul !</strong>" }, { "type": "paragraph", "text": "Les intégrations et les connexions SaaS se sont développées récemment, et les entreprises veulent un outil de portefeuilles de projets qui fonctionne avec leurs technologies existantes." }, { "type": "paragraph", "text": "En effet les différents métiers de l'entreprise ont leurs outils quotidiens préférés." }, { "type": "paragraph", "text": "Des outils comme Atlassian JIRA, Wrike, Microsoft Azure DevOps, Asana et Trello ont changé la façon dont les chefs de projets planifient, attribuent et partagent les actions." }, { "type": "paragraph", "text": "Des outils d'analyse commerciale comme Power BI et Tableau ont simplifié la création de tableaux de bords." }, { "type": "paragraph", "text": "Enfin des outils comme slack et teams ont contribué à fluidifier une partie de la communication au sein des organisations. En particulier depuis la pandémie." }, { "type": "paragraph", "text": "Rappelons-le, il est inutile de mener une conduite du changement sur tous les fronts.<strong> L'interconnexion des outils à travers les API permettra de renforcer certains usages bien ancrés tout en profitant d'une vue macro</strong> via un outil de pilotage stratégique, comme AirSaas par exemple. :-)" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330adebae9a8fdcececfb9a_hub-airsaas.png", "alt": "Votre hub opérationnel intégré à vos outils - Que ce soit avec vos outils de gestion de projet (Wrike,jira, Asana) ou avec vos outils de communication, Airsaas rassemble vos données projets", "caption": "Votre hub opérationnel intégré à vos outils - Que ce soit avec vos outils de gestion de projet (Wrike,jira, Asana) ou avec vos outils de communication, Airsaas rassemble vos données projets" }, { "type": "paragraph", "text": "Dans ce contexte de<strong> \"best of breed\"</strong> étendu. L'usage d'une <strong>solution macro</strong> interconnectée aux différents outils <strong>vous offrira le meilleur des différents usages</strong>. On parlera dans certains cas de \"logiciel parapluie\" pour décrire ce positionnement méta." }, { "type": "paragraph", "text": "Attention toutefois, avec en quelque sorte une <strong>prolifération de saas disséminés</strong> un peu partout dans l'entreprise, il peut être <strong>utile</strong> de se<strong> poser régulièrement pour formaliser une charte des usages</strong> cibles de votre \"tooling\" saas interne. Pour l'instant le record connu est celui de 224 saas utilisés au sein de Doctolib. Source : Sébastien Louyot - Directeur IT Services - au sein de Doctolib lors de l'épisode 37 du Podcast CIO Révolution produit par AirSaas" }, { "type": "paragraph", "text": "Au niveau du portefeuille. Concrètement cette approche permet la collecte, l'automatisation en temps réel et la synchronisation d'une plateforme avec votre écosystème de données." }, { "type": "paragraph", "text": "Au sein d'AirSaas vous pouvez par exemple :" }, { "type": "list", "ordered": false, "items": ["Récupérer votre<strong> liste des projets </strong>avec leurs attributs", "Ajouter le <strong>temps passé par équipe par projet</strong> sur vos projets AirSaas", "Récupérer la<strong> liste des jalons</strong> d'un projet", "Récupérer et modifier les<strong> budgets</strong> d'un projet", "et d'autres à venir"] }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330af1ca49e6f569eb5ab29_api.png", "alt": "API AirSaas", "caption": "Mise en place API - Plateforme AirSaas" }, { "type": "heading", "level": 4, "id": "derniere-integration-en-date-au-sein-dairsaas-teams", "text": "Dernière intégration en date au sein d'AirSaas : Teams" }, { "type": "paragraph", "text": "<strong>Teams</strong> est devenu l'<strong>outil majeur de la communication interne </strong>au sein des entreprises." }, { "type": "paragraph", "text": "<strong>Tous les collaborateurs </strong>de votre organisation <strong>ne disposent pas d'une licence AirSaas</strong> et vous avez néanmoins <strong>besoin d'embarquer les key user</strong> dans vos projets ?" }, { "type": "paragraph", "text": "Une fois Teams ajoutée à votre espace de travail AirSaas, vous pouvez <strong>connecter un projet au canal Teams de votre choix</strong>." }, { "type": "paragraph", "text": "Concrètement une fois les deux applications \"branchées\", les posts importants de ce projet peuvent être poussés vers Teams (<strong>publication standard, points succès, points d'attention, décisions et comptes rendus</strong>). Les changements de<strong> statuts de décisions</strong>, de points d'attention, de météo et de risque aussi (seulement si un message y est associé)." }, { "type": "paragraph", "text": "Dans le cadre de cette intégration AirSaas/Teams, vous aurez également <strong>la possibilité de récupérer la liste de vos décisions à prendre</strong> et <strong>prendre une décision dans un projet sans sortir de Teams</strong>. CQFD !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330af7fa49e6fb844b5d93b_AirSaas_bot-inte%CC%81gration-Teams-PPM.png", "alt": "AirSaas / Teams screenshot récupération de décisions à prendre", "caption": "Mise en œuvre de l'interconnexion AirSaas / Teams sur la récupération de décisions à prendre" }, { "type": "paragraph", "text": "Les <strong>outils PPM nouvelle génération</strong> permettent donc une meilleure i<strong>ntégration d'applications.</strong>&nbsp;Les applications intégrées ou synchronisées permettront à toutes les parties prenantes de mieux unir leurs forces sur des projets, fusionnant les intérêts et<strong> permettant</strong> que <strong>l'investissement technologique porte ses fruits</strong> en termes de parts de marché." }, { "type": "paragraph", "text": "Les <strong>intégrations</strong> sont essentielles car elles <strong>permettent d'automatiser certaines étapes</strong> et de se <strong>débarrasser de beaucoup d'erreurs </strong>que les gens commettent." }, { "type": "heading", "level": 3, "id": "la-tendance-minimalisme-design-ux-ui-fortes-au-service-de-lexperience-collaborateur", "text": "La tendance minimalisme & design UX et UI fortes au service de l'expérience collaborateur" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330b05ed3c66e1cb85fb535_kiss.png", "alt": "Simplicité", "caption": "L'un des meilleurs conseils prodigués :-)" }, { "type": "paragraph", "text": "<strong>Les PPM innovants donnent envie aux métiers de passer du temps sur l'outil !</strong>" }, { "type": "paragraph", "text": "Inviter les métiers, référents transformations à contribuer dans un ERP, un fichier excel ou gantt..c'est fini. <strong>Les UI au top</strong> sont un must have." }, { "type": "paragraph", "text": "Si vous voulez donner envie... Offrez une solution innovante sur cet axe également. <strong>Placez ce critère en bonne place dans votre grille de choix</strong>. Encore une fois, ce n'est pas la couverture fonctionnelle de l'outil qui compte....c'est son<strong> adoption la plus large !</strong> L'objectif est bien de faciliter la remontée et circulation d'information par différentes tactiques, et notamment en donnant envie aux utilisateurs de \"jardiner\" leurs données régulièrement." }, { "type": "quote", "text": "Quand on bascule dans le digital, on doit forcément faire attention au parcours utilisateur. L'ergonomie est beaucoup plus importante que dans un système SAP. On va s'intéresser en détail sur les méthodes de travail des utilisateurs et essayer de savoir comment l'outil qu'on va lui proposer va être efficace pour que cela améliore son travail au quotidien. Un utilisateur qui n'a plus besoin de faire d'effort pour utiliser ses outils peut se concentrer sur autre chose : il gagne donc forcément en productivité !", "author": "Emmanuelle Courtois — DSI du Siège de Danone - episode 23 Podcast CIO Révolution by AirSaas" }, { "type": "paragraph", "text": "Sur ce thème du minimalisme, n'oublions pas l'importance du mobile !" }, { "type": "paragraph", "text": "CNBC rapporte que 72,6% des personnes utiliseront des téléphones pour accéder à Internet d'ici 2025." }, { "type": "paragraph", "text": "Alors que le digital devient \"mobile first\". Cela soulève des enjeux de conception, comme la création d'interfaces light et responsive adaptées à ces nouveaux usages." }, { "type": "paragraph", "text": "Vous l'avez compris, <strong>le minimalisme </strong>dans la gestion de portefeuille projet<strong> est tendance </strong>!" }, { "type": "paragraph", "text": "Citons par exemple la montée en puissance du <a href=\"https://www.airsaas.io/fr/gestion-de-projet/lean-portfolio-management\" target=\"_blank\">Lean Portfolio management (LPM)</a> qui illustre cette recherche de sobriété...buzzword du moment." }, { "type": "paragraph", "text": "Enfin,<strong> l'innovation</strong> dans le champ de l'expérience utilisateur / collaborateur <strong>passera également par la façon dont l'éditeur opère sa communication vis-à-vis des communautés</strong> d'utilisateurs. Proposer un espace ouvert permettant d'interagir sur les différentes features actuelles ou à venir. Disposer de <strong>courtes vidéos</strong> centrées sur les usages clés...tout cela n'est pas une innovation technologique. Mais apporte une <strong>rupture d'usage</strong> avec une démarche produit ouverte. Pour toujours plus d'appropriation des parties prenantes. Là encore, vous l'aurez compris ce critère discret est à prendre en compte. Oui un PPM peut avoir une UX au top et une communication produits efficiente !" }, { "type": "heading", "level": 3, "id": "linnovation-cest-parfois-simple", "text": "L'innovation c'est parfois simple !" }, { "type": "paragraph", "text": "Un exemple : le jour où une célèbre marque de ketchup a proposé de simplement retourner la bouteille pour la poser sur la table vers le bas...tout le monde à suivi. Mais au-delà de l'anecdote, l'usage de ces bouteilles mieux adaptées au contexte des consommateurs a explosé ! <strong>C'est ce qui est en jeu dans l'innovation en gestion de portefeuille : l'adoption</strong> au-delà de l'IT, par le reste de l'entreprise et de ses métiers !" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330b0f2b1374a72fd673af5_ui%20ux%20.jpeg", "alt": "UI / UX", "caption": "R&D simple pour une innovation dans les pratiques des utilisateurs" }, { "type": "heading", "level": 3, "id": "la-tendance-algo-robots-automatisations-hyperpersonnalisation-et-ia-au-service-du-management-de-portefeuille", "text": "La tendance \"algo & robots\" : automatisations, hyperpersonnalisation et IA au service du management de portefeuille de projets" }, { "type": "figure", "src": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6330b12910aaa100159ee0f6_image.png", "alt": "Dessin d'humour ROBOTS en entreprise", "caption": "Accélération digitale / Transformation et changement sont le quotidien des organisations" }, { "type": "paragraph", "text": "L'intelligence artificielle (IA) renvoie à \"une application capable de traiter des tâches qui sont, pour l'heure, réalisées de manière plus satisfaisante par des êtres humains dans la mesure où elles impliquent des processus mentaux de haut niveau comme l'apprentissage perceptuel, l'organisation de la mémoire et l'esprit critique\". C'est ainsi que le scientifique américain Marvin Lee Minsky, considéré comme le père de l'IA, a défini ce concept en 1956." }, { "type": "paragraph", "text": "Alors que bon nombre de ces fonctionnalités sont disponibles depuis des années (le concept remonte à près de quatre décennies), les avancées technologiques récentes permettent de disposer de meilleurs outils d'assistance au pilotage de transformation." }, { "type": "heading", "level": 4, "id": "exemple-1-lia-en-mode-assistant-avec-les-technologies-de-generation-de-textes", "text": "Exemple 1 : L'IA en mode assistant, avec Les technologies de génération de textes" }, { "type": "paragraph", "text": "La génération de texte est l'<strong>une des tendances actuelles du machine learning</strong>. Les systèmes d'IA qui apprennent en absorbant des milliards de mots extraits d'internet et génèrent du texte en réponse à diverses requêtes." }, { "type": "paragraph", "text": "Concrètement il s'agit ici<strong> d'aider les utilisateurs sur la génération de contenus</strong>. Car oui tout le monde n'aime pas rédiger ou n'a pas toujours envie de prendre le temps." }, { "type": "paragraph", "text": "Les technologies de génération de textes sont entre autres basées sur <strong>GPT 3, l'algorithme d'open AI</strong>." }, { "type": "paragraph", "text": "On est ici sur <strong>une IA qui aidera à grandir dans la compétence</strong>. On peut par exemple citer les fonctions de détection de tonalité dans les messages qui peuvent suggérer d'autres options aux rédacteurs." }, { "type": "heading", "level": 4, "id": "exemple-2-generation-de-reporting-decisionnel-automatique", "text": "Exemple 2 : Génération de reporting décisionnel automatique" }, { "type": "paragraph", "text": "Chez AirSaas nous proposons un<strong> tableau de bord automatisé</strong>, <strong>réduisant</strong> considérablement <strong>les frais</strong> généraux <strong>liés aux reportings manuels</strong>. L'équipe de management et toutes les parties prenantes ont les données à portée de main pour prendre des décisions en temps réel." }, { "type": "paragraph", "text": "Cette approche permet d'<strong>automatiser de manière intelligente</strong> la <strong>collecte</strong> des informations dont vous avez besoin pour <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\" target=\"_blank\">élaborer votre <strong>reporting</strong></a>." }, { "type": "paragraph", "text": "<strong>La collecte, l'analyse et la communication de données</strong> représentent une grande partie de la discipline du PPM.<strong> L'IA améliorera les résultats de ces tâches</strong>, y compris la capacité d'analyser les données plus rapidement que les humains et d'utiliser ces résultats pour améliorer les performances globales." }, { "type": "paragraph", "text": "Les projets reposent sur de grands ensembles de données d'informations structurées. Jusqu'à récemment, les data scientists devaient « connecter les points » manuellement. Pas étonnant que l'intelligence artificielle atteigne la gestion au niveau du portefeuille." }, { "type": "paragraph", "text": "<strong>Citons également le usecase d'alerting</strong> quand quelque chose risque de mal tourner dans le projet. Par exemple <strong>l'alerte des interdépendances automatiques</strong>." }, { "type": "paragraph", "text": "Après la collecte, l'automatisation des envois de reporting est également une fonctionnalité \"nice to have\"." }, { "type": "paragraph", "text": "Bien sûr tout cela ne remplace pas un comité projet ou de direction....Nous ne disons pas cela. Par contre, bien utilisées, ces diverses automatisations <strong>permettent de dégager du temps aux chefs de projets</strong>....Et en prime...plus personne ne pourra dire \" je ne savais pas !\"." }, { "type": "heading", "level": 2, "id": "a-retenir-la-technologie-est-une-aide-precieuse-au-pilotage-du-portefeuille-de-projets", "text": "À retenir : la technologie est une aide précieuse au pilotage du portefeuille de projets" }, { "type": "paragraph", "text": "Nous venons de balayer trois des innovations technologiques et d'usages qui<strong> bousculent la gestion de portefeuille projets</strong>." }, { "type": "paragraph", "text": "Les promesses de l'IA comme assistant au pilotage sont en passe d'être tenues." }, { "type": "list", "ordered": false, "items": ["<strong>Des services d'assistance de haute qualité</strong>&nbsp;tels que des chatbots et d'autres assistants automatisés peuvent alléger votre charge de travail.", "<strong>Le traitement du langage naturel</strong>&nbsp;(NLP) et la commande vocale simplifient les logiciels", "L'équation magique pour réussir votre transformation avec des outils de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/management-de-portefeuille-de-projet\" target=\"_blank\">management de portefeuille de projet</a> est : <strong>Experience utilisateur + Automatisation x Service </strong>!"] }, { "type": "insight-callout", "label": "À retenir", "html": "<p>N'oublions pas néanmoins que <strong>le plus gros changement est humain</strong>. Et c'est une autre histoire que nous vous proposerons dans un prochain article du blog Pro de la Transfo. !</p><p>Ceci étant, en guise de teasing, nous terminons cet article sur <strong>une ouverture vers deux macros tendances</strong> <strong>organisationnelles </strong>à considérer dès aujourd'hui dans le design de votre stratégie de transformation.</p>" }, { "type": "heading", "level": 3, "id": "linformatique-dirigee-par-lentreprise", "text": "L'informatique dirigée par l'entreprise" }, { "type": "paragraph", "text": "La décentralisation de l'informatique est en marche. L'informatique dirigée par l'entreprise - où les employés, et non l'informatique, décident de la technologie à utiliser - promet de rendre les travailleurs plus productifs, de réagir plus rapidement aux conditions du marché et d'augmenter la satisfaction au travail. Les entreprises peuvent se préparer à cette tendance en adoptant des politiques pour gouverner et sécuriser la technologie acquise via un processus d'achat décentralisé plutôt qu'un processus de type command &amp; contrôle ignorant le shadow it et la décentralisation en marche." }, { "type": "heading", "level": 3, "id": "vers-un-modele-de-gestion-de-portefeuille-adaptatif-axe-sur-la-creation-de-valeur", "text": "Vers un modèle de gestion de portefeuille adaptatif axé sur la création de valeur" }, { "type": "paragraph", "text": "L'idée est de se concentrer sur <strong>la transformation de l'organisation de \"Projets\" en \"Produits\"</strong>, car les projets sont toujours en retard, tandis que les produits sont publiés en continu." }, { "type": "paragraph", "text": "De nombreuses organisations ont « flirté » avec le PPM. Ils ont essayé des évaluations numériques ou mesurées formelles pour la sélection et la hiérarchisation des projets, puis les ont rapidement rejetées comme étant rigides, chronophages ou fournissant des résultats erronés." }, { "type": "paragraph", "text": "Le <strong>PPM \"à papa\" cède progressivement la place à un outil PPM nouvelle génération </strong>avec une gestion de portefeuille allégée avec ses flux de valeur qui semblent être le prochain \"big thing\" ou une super tendance dans la gestion au niveau du portefeuille. Les flux de valeur sont de grandes «équipes» - capables de se former, de s'organiser et apparemment de prendre de meilleures décisions au niveau du portefeuille dans une course pour fournir plus de valeur plus rapidement." }], "toc": [{ "label": "PPM : trois innovations qui font la différence", "href": "#ppm-trois-innovations-qui-font-la-difference", "level": 2 }, { "label": "À retenir : la technologie est une aide précieuse au pilotage du portefeuille de projets", "href": "#a-retenir-la-technologie-est-une-aide-precieuse-au-pilotage-du-portefeuille-de-projets", "level": 2 }], "faq": [], "related": [] }] as const;

export const ACTIVE_BLOG_ARTICLES_V2: BlogArticleV2[] = BLOG_ARTICLES_V2.filter(
  (a) => !a.skip,
);

